// fl_all.js — Florida Class E Knowledge Test — Question Database
// Format: { cat, en, it, options:[{en,it},...], correct, explain_en, explain_it }
// Categorie: signs | laws | safety | alcohol | license
// TOTAL: 1505 domande
// =====================================================================

const QUESTIONS = [
  {cat:"signs",en:"A red octagonal sign means:",it:"Un segnale ottagonale rosso significa:",options:[{en:"Slow down",it:"Rallentare"},{en:"Stop completely",it:"Fermarsi completamente"},{en:"Yield to traffic",it:"Dare la precedenza"},{en:"No entry",it:"Divieto di accesso"}],correct:1,explain_en:"The red octagon is universally the STOP sign. You must come to a complete stop before the stop line or crosswalk.",explain_it:"Il segno ottagonale rosso \u00e8 universalmente il segnale di STOP. \u00c8 obbligatorio fermarsi completamente prima della linea di arresto o del passaggio pedonale."},
  {cat:"signs",en:"A yellow diamond-shaped sign indicates:",it:"Un segnale a rombo giallo indica:",options:[{en:"A regulatory requirement",it:"Un obbligo normativo"},{en:"A warning of a potential hazard ahead",it:"Un avvertimento di pericolo potenziale"},{en:"A school zone",it:"Una zona scolastica"},{en:"A construction zone speed limit",it:"Limite di velocit\u00e0 in area di lavori"}],correct:1,explain_en:"Yellow diamond signs are warning signs. They alert drivers to road conditions or hazards ahead such as curves, intersections, or merging traffic.",explain_it:"I segnali a rombo giallo sono segnali di avvertimento. Avvisano i conducenti di condizioni stradali o pericoli, come curve, incroci o traffico in confluenza."},
  {cat:"signs",en:"A white rectangular sign with black lettering typically indicates:",it:"Un segnale rettangolare bianco con lettere nere indica tipicamente:",options:[{en:"A warning",it:"Un avvertimento"},{en:"A regulatory rule you must obey",it:"Una regola normativa da rispettare"},{en:"A guide or informational message",it:"Un messaggio informativo o di orientamento"},{en:"A temporary traffic condition",it:"Una condizione di traffico temporanea"}],correct:1,explain_en:"White rectangular signs with black text are regulatory signs (e.g. speed limits, no turn signs). Drivers must comply with them.",explain_it:"I segnali rettangolari bianchi con testo nero sono segnali normativi (es. limiti di velocit\u00e0, divieti di svolta). I conducenti devono rispettarli."},
  {cat:"signs",en:"A triangular red-bordered sign with a pointed top is a:",it:"Un segnale triangolare con bordo rosso e punta verso l'alto \u00e8 un segnale di:",options:[{en:"STOP sign",it:"STOP"},{en:"YIELD sign",it:"PRECEDENZA (YIELD)"},{en:"Warning sign",it:"Avvertimento"},{en:"No-passing zone sign",it:"Zona di sorpasso vietato"}],correct:1,explain_en:"The inverted red triangle (YIELD sign) means you must slow down and give the right-of-way to vehicles in the intersection or roadway you are entering.",explain_it:"Il triangolo rovesciato rosso (YIELD) significa che devi rallentare e cedere la precedenza ai veicoli nell'incrocio o nella carreggiata che stai per immettere."},
  {cat:"signs",en:"An orange sign in a construction or work zone means:",it:"Un segnale arancione in una zona di lavori stradali significa:",options:[{en:"Speed up to clear the zone quickly",it:"Accelerare per attraversare rapidamente la zona"},{en:"Temporary traffic control is in effect",it:"\u00c8 in vigore un controllo del traffico temporaneo"},{en:"The road is permanently closed",it:"La strada \u00e8 chiusa definitivamente"},{en:"Workers are not present",it:"Gli operai non sono presenti"}],correct:1,explain_en:"Orange signs indicate temporary traffic control measures in construction or work zones. Fines are doubled for violations in these zones.",explain_it:"I segnali arancioni indicano misure temporanee di controllo del traffico in zone di costruzione o lavori. Le multe sono raddoppiate per violazioni in queste zone."},
  {cat:"signs",en:"A green sign on the highway provides:",it:"Un segnale verde in autostrada fornisce:",options:[{en:"Speed limit information",it:"Informazioni sul limite di velocit\u00e0"},{en:"Direction and distance information",it:"Informazioni su direzione e distanza"},{en:"Warning of hazards ahead",it:"Avvertimento di pericoli in avanti"},{en:"Regulatory instructions",it:"Istruzioni normative"}],correct:1,explain_en:"Green signs are guide signs. They provide directional and distance information to help drivers navigate to destinations.",explain_it:"I segnali verdi sono segnali di orientamento. Forniscono informazioni su direzione e distanza per aiutare i conducenti a navigare verso le destinazioni."},
  {cat:"signs",en:"When you see a pennant-shaped (elongated triangle pointing right) yellow sign, it means:",it:"Quando vedi un segnale a forma di pennacchio (triangolo allungato verso destra) giallo, significa:",options:[{en:"No U-turn ahead",it:"Divieto di inversione di marcia"},{en:"No passing zone begins here",it:"Inizia qui una zona di sorpasso vietato"},{en:"Merging traffic ahead",it:"Traffico in confluenza in avanti"},{en:"School zone warning",it:"Avviso di zona scolastica"}],correct:1,explain_en:"The pennant-shaped yellow sign marks the beginning of a no-passing zone. It is placed on the left side of the roadway.",explain_it:"Il segnale a forma di pennacchio giallo segna l'inizio di una zona di sorpasso vietato. \u00c8 posizionato sul lato sinistro della carreggiata."},
  {cat:"laws",en:"What is the speed limit in a school zone when children are present in Florida?",it:"Qual \u00e8 il limite di velocit\u00e0 in una zona scolastica quando ci sono bambini presenti in Florida?",options:[{en:"15 mph",it:"15 miglia orarie"},{en:"20 mph",it:"20 miglia orarie"},{en:"25 mph",it:"25 miglia orarie"},{en:"30 mph",it:"30 miglia orarie"}],correct:1,explain_en:"In Florida, the speed limit in school zones when children are present is 20 mph. Violating school zone speed limits results in doubled fines.",explain_it:"In Florida, il limite di velocit\u00e0 nelle zone scolastiche quando ci sono bambini \u00e8 20 mph (circa 32 km/h). Le violazioni nelle zone scolastiche comportano multe raddoppiate."},
  {cat:"laws",en:"What is the maximum speed limit on most interstate highways in Florida?",it:"Qual \u00e8 il limite di velocit\u00e0 massimo sulla maggior parte delle autostrade interstatali in Florida?",options:[{en:"55 mph",it:"55 miglia orarie"},{en:"65 mph",it:"65 miglia orarie"},{en:"70 mph",it:"70 miglia orarie"},{en:"75 mph",it:"75 miglia orarie"}],correct:2,explain_en:"The maximum speed limit on most Florida interstates is 70 mph. Some rural interstates may have posted limits of 70 mph; urban interstates are typically 65 mph.",explain_it:"Il limite di velocit\u00e0 massimo sulla maggior parte delle autostrade interstatali della Florida \u00e8 70 mph (circa 113 km/h). Le autostrade urbane hanno generalmente un limite di 65 mph."},
  {cat:"laws",en:"When must you turn on your headlights in Florida?",it:"Quando devi accendere i fari in Florida?",options:[{en:"Only at night",it:"Solo di notte"},{en:"From sunset to sunrise and when visibility is less than 1,000 feet",it:"Dal tramonto all'alba e quando la visibilit\u00e0 \u00e8 inferiore a 300 metri"},{en:"Only in rain or fog",it:"Solo in caso di pioggia o nebbia"},{en:"Anytime you are on a highway",it:"Ogni volta che sei in autostrada"}],correct:1,explain_en:"Florida law requires headlights from sunset to sunrise and any time visibility is less than 1,000 feet. This includes rain, fog, smoke, or any other condition reducing visibility.",explain_it:"La legge della Florida richiede i fari dal tramonto all'alba e ogni volta che la visibilit\u00e0 \u00e8 inferiore a 300 metri. Ci\u00f2 include pioggia, nebbia, fumo o qualsiasi altra condizione che riduce la visibilit\u00e0."},
  {cat:"laws",en:"Under Florida's Move Over Law, when approaching a stopped emergency vehicle with flashing lights on a multi-lane road, you must:",it:"In base alla legge Move Over della Florida, quando ti avvicini a un veicolo di emergenza fermo con luci lampeggianti su una strada a pi\u00f9 corsie, devi:",options:[{en:"Maintain your speed and lane",it:"Mantenere velocit\u00e0 e corsia"},{en:"Move over one lane away from the vehicle OR reduce speed by 20 mph below the posted limit",it:"Spostarti di una corsia oppure ridurre la velocit\u00e0 di 20 mph sotto il limite"},{en:"Stop completely until the vehicle moves",it:"Fermarti completamente fino a quando il veicolo non si muove"},{en:"Flash your headlights as a warning",it:"Lampeggiare i fari come segnale"}],correct:1,explain_en:"Florida's Move Over Law requires drivers to move over one lane (if possible) OR slow down 20 mph below the posted limit when passing stationary emergency vehicles, tow trucks, and road maintenance vehicles with flashing lights.",explain_it:"La legge Move Over della Florida richiede di spostarsi di una corsia (se possibile) O ridurre la velocit\u00e0 di 20 mph sotto il limite quando si superano veicoli di emergenza, carroattrezzi e veicoli di manutenzione stradale fermi con luci lampeggianti."},
  {cat:"laws",en:"In Florida, when approaching a school bus with flashing red lights stopped on an undivided road, you must:",it:"In Florida, quando si avvicina uno scuolabus con luci rosse lampeggianti fermo su una strada non divisa, devi:",options:[{en:"Slow to 15 mph and proceed carefully",it:"Rallentare a 15 mph e procedere con cautela"},{en:"Stop at least 30 feet away and wait until the lights stop flashing",it:"Fermarsi a non meno di 9 metri e attendere che le luci smettano di lampeggiare"},{en:"Pass on the right side at reduced speed",it:"Superare sul lato destro a velocit\u00e0 ridotta"},{en:"Honk to alert children and proceed",it:"Suonare il clacson per avvisare i bambini e procedere"}],correct:1,explain_en:"All traffic on undivided roads must stop at least 30 feet from a stopped school bus with flashing red lights. You must wait until the lights stop and the stop arm is withdrawn.",explain_it:"Tutto il traffico su strade non divise deve fermarsi ad almeno 9 metri da uno scuolabus fermo con luci rosse lampeggianti. Devi attendere che le luci si spengano e il braccio di stop venga ritirato."},
  {cat:"laws",en:"At a four-way stop with no traffic signals, the right-of-way goes to:",it:"A un incrocio a quattro vie senza segnali, la precedenza spetta a:",options:[{en:"The vehicle coming from the left",it:"Il veicolo proveniente da sinistra"},{en:"The vehicle that arrived first; if simultaneous, the vehicle on the right",it:"Il veicolo arrivato prima; se simultaneo, al veicolo a destra"},{en:"The vehicle traveling straight ahead",it:"Il veicolo che va dritto"},{en:"The largest vehicle",it:"Il veicolo pi\u00f9 grande"}],correct:1,explain_en:"At a four-way stop, the first vehicle to arrive goes first. If two vehicles arrive at the same time, the vehicle on the left yields to the vehicle on the right.",explain_it:"A un incrocio a quattro vie, il primo veicolo ad arrivare ha la precedenza. Se due veicoli arrivano simultaneamente, il veicolo a sinistra cede la precedenza al veicolo a destra."},
  {cat:"laws",en:"What is the proper following distance rule in Florida for normal driving conditions?",it:"Qual \u00e8 la regola corretta per la distanza di sicurezza in Florida in condizioni normali di guida?",options:[{en:"1-second rule",it:"Regola del secondo"},{en:"3-second rule",it:"Regola dei 3 secondi"},{en:"10-car-length rule",it:"Regola dei 10 lunghezze auto"},{en:"50-foot minimum rule",it:"Regola del minimo 50 piedi"}],correct:1,explain_en:"The Florida Driver Handbook recommends the 3-second rule as a minimum following distance. In poor conditions (rain, fog, night), increase to 4\u20136 seconds.",explain_it:"Il manuale del conducente della Florida raccomanda la regola dei 3 secondi come distanza di sicurezza minima. In condizioni avverse (pioggia, nebbia, notte), aumentare a 4\u20136 secondi."},
  {cat:"laws",en:"When making a left turn at an intersection, you must yield to:",it:"Quando si effettua una svolta a sinistra a un incrocio, devi cedere la precedenza a:",options:[{en:"Vehicles behind you only",it:"Solo ai veicoli dietro di te"},{en:"Oncoming traffic and pedestrians in the crosswalk",it:"Il traffico in senso contrario e i pedoni sul passaggio pedonale"},{en:"Vehicles turning right from the opposite direction",it:"I veicoli che svoltano a destra dalla direzione opposta"},{en:"No one, you have the right-of-way",it:"Nessuno, hai la precedenza"}],correct:1,explain_en:"When turning left, you must yield to all oncoming vehicles and pedestrians crossing the intersection. Left-turning vehicles have the lowest right-of-way priority.",explain_it:"Svoltando a sinistra, devi cedere la precedenza a tutti i veicoli in arrivo e ai pedoni che attraversano l'incrocio. I veicoli che svoltano a sinistra hanno la priorit\u00e0 di precedenza pi\u00f9 bassa."},
  {cat:"laws",en:"In Florida, you must use your turn signal at least how far before turning or changing lanes?",it:"In Florida, devi usare l'indicatore di direzione almeno a quale distanza prima di svoltare o cambiare corsia?",options:[{en:"50 feet (15 m)",it:"50 piedi (15 m)"},{en:"100 feet (30 m)",it:"100 piedi (30 m)"},{en:"200 feet (60 m)",it:"200 piedi (60 m)"},{en:"300 feet (90 m)",it:"300 piedi (90 m)"}],correct:1,explain_en:"Florida law requires drivers to signal at least 100 feet before turning in a residential area, and at least 200 feet before turning on a highway.",explain_it:"La legge della Florida richiede di segnalare almeno 100 piedi (30 m) prima di svoltare in zona residenziale e almeno 200 piedi (60 m) prima di svoltare in autostrada."},
  {cat:"laws",en:"When can you pass a vehicle on the right in Florida?",it:"Quando puoi sorpassare un veicolo a destra in Florida?",options:[{en:"Anytime you want",it:"In qualsiasi momento tu voglia"},{en:"When the vehicle ahead is making a left turn and there is a clear lane",it:"Quando il veicolo davanti sta svoltando a sinistra e c'\u00e8 una corsia libera"},{en:"Only on one-way streets",it:"Solo su strade a senso unico"},{en:"Only when the posted speed is above 55 mph",it:"Solo quando il limite \u00e8 superiore a 55 mph"}],correct:1,explain_en:"You may pass on the right when the vehicle ahead is turning left AND there is a usable lane on the right, or on one-way roads with two or more lanes.",explain_it:"Puoi sorpassare a destra quando il veicolo davanti sta svoltando a sinistra E c'\u00e8 una corsia utilizzabile a destra, o su strade a senso unico con due o pi\u00f9 corsie."},
  {cat:"laws",en:"A solid yellow center line on your side of the road means:",it:"Una linea centrale gialla continua sul tuo lato della strada significa:",options:[{en:"You may pass if it is safe to do so",it:"Puoi sorpassare se \u00e8 sicuro farlo"},{en:"You must not pass (no-passing zone)",it:"Non puoi sorpassare (zona di sorpasso vietato)"},{en:"You may pass only at reduced speed",it:"Puoi sorpassare solo a velocit\u00e0 ridotta"},{en:"The road is one-way",it:"La strada \u00e8 a senso unico"}],correct:1,explain_en:"A solid yellow line on your side means no passing. A broken yellow line means passing is permitted when safe.",explain_it:"Una linea gialla continua sul tuo lato significa divieto di sorpasso. Una linea gialla tratteggiata significa che il sorpasso \u00e8 consentito quando \u00e8 sicuro."},
  {cat:"laws",en:"Under Florida law, pedestrians in a crosswalk have the right-of-way:",it:"Secondo la legge della Florida, i pedoni in un passaggio pedonale hanno la precedenza:",options:[{en:"Only when traffic signals tell vehicles to stop",it:"Solo quando i semafori ordinano ai veicoli di fermarsi"},{en:"At all times, whether or not a traffic signal is present",it:"In qualsiasi momento, con o senza segnale semaforico"},{en:"Only during daylight hours",it:"Solo durante le ore diurne"},{en:"Only at marked crosswalks, not at intersections",it:"Solo ai passaggi pedonali segnalati, non agli incroci"}],correct:1,explain_en:"Florida law requires drivers to yield to pedestrians in any crosswalk, whether marked or unmarked, and whether or not a traffic signal is present.",explain_it:"La legge della Florida richiede ai conducenti di cedere la precedenza ai pedoni in qualsiasi passaggio pedonale, segnalato o meno, con o senza segnale semaforico."},
  {cat:"laws",en:"What should you do when you see a flashing red traffic signal?",it:"Cosa dovresti fare quando vedi un segnale semaforico rosso lampeggiante?",options:[{en:"Slow down and proceed with caution",it:"Rallentare e procedere con cautela"},{en:"Stop completely, then proceed when safe",it:"Fermarsi completamente, poi procedere quando \u00e8 sicuro"},{en:"Yield to cross traffic",it:"Cedere la precedenza al traffico trasversale"},{en:"Treat it like a yield sign",it:"Trattarlo come un segnale di precedenza"}],correct:1,explain_en:"A flashing red light is treated like a STOP sign. Come to a complete stop, yield to traffic and pedestrians, and then proceed when safe.",explain_it:"Una luce rossa lampeggiante va trattata come un segnale di STOP. Fermarsi completamente, cedere la precedenza al traffico e ai pedoni, poi procedere quando \u00e8 sicuro."},
  {cat:"safety",en:"What is the safest thing to do when you become drowsy while driving?",it:"Qual \u00e8 la cosa pi\u00f9 sicura da fare quando ti vengono i colpi di sonno mentre guidi?",options:[{en:"Open a window and turn up the radio",it:"Aprire un finestrino e alzare la radio"},{en:"Drink coffee and keep driving",it:"Bere caff\u00e8 e continuare a guidare"},{en:"Pull off the road safely and rest",it:"Accostare in modo sicuro e riposarsi"},{en:"Drive faster to reach your destination sooner",it:"Guidare pi\u00f9 velocemente per arrivare prima a destinazione"}],correct:2,explain_en:"The only safe solution for drowsy driving is to stop and rest. Other methods provide only a brief, unreliable delay before fatigue returns.",explain_it:"L'unica soluzione sicura per la sonnolenza alla guida \u00e8 fermarsi e riposarsi. Gli altri metodi offrono solo un breve e inaffidabile ritardo prima che la stanchezza ritorni."},
  {cat:"safety",en:"At highway speeds, your minimum following distance should be:",it:"Ad alta velocit\u00e0, la tua distanza di sicurezza minima dovrebbe essere:",options:[{en:"2 seconds",it:"2 secondi"},{en:"3 seconds",it:"3 secondi"},{en:"4\u20136 seconds",it:"4\u20136 secondi"},{en:"1 second per 10 mph",it:"1 secondo per ogni 10 mph"}],correct:2,explain_en:"At highway speeds, or in poor conditions (rain, fog, night), the recommended following distance increases to 4\u20136 seconds to allow adequate stopping time.",explain_it:"Ad alta velocit\u00e0, o in condizioni avverse (pioggia, nebbia, notte), la distanza di sicurezza raccomandata aumenta a 4\u20136 secondi per consentire un tempo di frenata adeguato."},
  {cat:"safety",en:"When driving in fog, you should use:",it:"Quando guidi nella nebbia, devi usare:",options:[{en:"High-beam headlights",it:"Abbaglianti"},{en:"Low-beam headlights or fog lights",it:"Anabbaglianti o fendinebbia"},{en:"Hazard lights only",it:"Solo le luci di pericolo"},{en:"No lights \u2014 they reduce visibility",it:"Nessuna luce \u2014 riducono la visibilit\u00e0"}],correct:1,explain_en:"Use low-beam headlights or fog lights in fog, smoke, or rain. High beams reflect off the water droplets and actually reduce visibility.",explain_it:"Usa gli anabbaglianti o i fendinebbia in caso di nebbia, fumo o pioggia. Gli abbaglianti si riflettono sulle goccioline d'acqua e riducono effettivamente la visibilit\u00e0."},
  {cat:"safety",en:"What is hydroplaning?",it:"Cos'\u00e8 l'aquaplaning (idroplanazione)?",options:[{en:"Driving too fast in a flooded area",it:"Guidare troppo velocemente in una zona allagata"},{en:"When tires lose contact with the road because of water, causing loss of steering control",it:"Quando i pneumatici perdono il contatto con la strada a causa dell'acqua, causando perdita di controllo dello sterzo"},{en:"When your brakes fail on a wet road",it:"Quando i freni cedono su una strada bagnata"},{en:"Excessive windshield fogging in rain",it:"Eccessivo appannamento del parabrezza in caso di pioggia"}],correct:1,explain_en:"Hydroplaning occurs when a layer of water builds up between your tires and the road, causing loss of steering and braking control. Reduce speed in wet conditions.",explain_it:"L'aquaplaning si verifica quando si forma uno strato d'acqua tra i pneumatici e la strada, causando perdita del controllo dello sterzo e dei freni. Ridurre la velocit\u00e0 in condizioni bagnate."},
  {cat:"safety",en:"If your vehicle starts to skid, you should:",it:"Se il tuo veicolo inizia a slittare, dovresti:",options:[{en:"Slam on the brakes immediately",it:"Frenare bruscamente immediatamente"},{en:"Steer in the direction you want the front of the vehicle to go and ease off the gas",it:"Sterzare nella direzione in cui vuoi che vada la parte anteriore del veicolo e togliere il piede dal gas"},{en:"Turn the wheel sharply in the opposite direction",it:"Girare bruscamente il volante nella direzione opposta"},{en:"Accelerate to regain control",it:"Accelerare per riprendere il controllo"}],correct:1,explain_en:"In a skid, steer in the direction you want the front to go (into the skid) and ease off the accelerator. Avoid braking sharply as this worsens the skid.",explain_it:"In caso di slittamento, sterzare nella direzione in cui si vuole andare (verso lo slittamento) e togliere gradualmente il piede dall'acceleratore. Evitare la frenata brusca poich\u00e9 peggiora lo slittamento."},
  {cat:"safety",en:"Which of the following is the most effective safety device in your vehicle?",it:"Quale dei seguenti \u00e8 il dispositivo di sicurezza pi\u00f9 efficace nel tuo veicolo?",options:[{en:"Airbags",it:"Airbag"},{en:"Anti-lock brakes (ABS)",it:"Freni antibloccaggio (ABS)"},{en:"Seat belt",it:"Cintura di sicurezza"},{en:"Electronic stability control",it:"Controllo elettronico della stabilit\u00e0"}],correct:2,explain_en:"The seat belt is the single most effective life-saving device in a vehicle. Florida law requires all front-seat occupants and all passengers under 18 to wear seat belts.",explain_it:"La cintura di sicurezza \u00e8 il singolo dispositivo pi\u00f9 efficace per salvare vite in un veicolo. La legge della Florida richiede che tutti gli occupanti del sedile anteriore e tutti i passeggeri sotto i 18 anni indossino la cintura."},
  {cat:"safety",en:"What should you do when an emergency vehicle with flashing lights and siren approaches from behind?",it:"Cosa dovresti fare quando un veicolo di emergenza con luci lampeggianti e sirena si avvicina da dietro?",options:[{en:"Speed up to stay ahead of it",it:"Accelerare per restare davanti a esso"},{en:"Pull over to the right edge of the road and stop",it:"Accostare al bordo destro della strada e fermarsi"},{en:"Move to the center lane and slow down",it:"Spostarsi nella corsia centrale e rallentare"},{en:"Maintain your speed and watch in the mirror",it:"Mantenere la velocit\u00e0 e guardare nello specchio"}],correct:1,explain_en:"When an emergency vehicle approaches with lights and siren, pull to the right edge of the road and stop. Remain stopped until the vehicle has passed.",explain_it:"Quando si avvicina un veicolo di emergenza con luci e sirena, accostare al bordo destro della strada e fermarsi. Rimanere fermi fino al passaggio del veicolo."},
  {cat:"safety",en:"In Florida, it is illegal to text and drive. What does this mean?",it:"In Florida, \u00e8 illegale scrivere messaggi mentre si guida. Cosa significa questo?",options:[{en:"You may text at red lights only",it:"Puoi mandare messaggi solo ai semafori rossi"},{en:"You may not manually type or read messages on a wireless device while driving",it:"Non puoi digitare o leggere manualmente messaggi su un dispositivo wireless durante la guida"},{en:"You may use voice-to-text at any time",it:"Puoi usare la voce per i messaggi in qualsiasi momento"},{en:"The law only applies to drivers under 18",it:"La legge si applica solo ai conducenti sotto i 18 anni"}],correct:1,explain_en:"Florida's texting while driving law prohibits manually typing, reading, or sending messages on a wireless device while driving. It is a primary offense \u2014 officers can stop you solely for this violation.",explain_it:"La legge della Florida sul messaggistica durante la guida vieta di digitare manualmente, leggere o inviare messaggi su un dispositivo wireless durante la guida. \u00c8 un reato primario: gli agenti possono fermarti solo per questa violazione."},
  {cat:"safety",en:"Before backing up your vehicle, you should:",it:"Prima di fare retromarcia, dovresti:",options:[{en:"Check only the rearview mirror",it:"Controllare solo lo specchietto retrovisore interno"},{en:"Check mirrors and look over both shoulders for pedestrians and obstacles",it:"Controllare gli specchietti e guardare oltre entrambe le spalle per pedoni e ostacoli"},{en:"Tap the horn once and proceed",it:"Suonare il clacson una volta e procedere"},{en:"Turn on hazard lights before reversing",it:"Accendere le luci di pericolo prima di fare retromarcia"}],correct:1,explain_en:"Always check all mirrors and physically turn to look behind you (over both shoulders) before backing. Mirrors have blind spots that can hide children or obstacles.",explain_it:"Controlla sempre tutti gli specchietti e girare fisicamente a guardare dietro di te (oltre entrambe le spalle) prima di fare retromarcia. Gli specchietti hanno punti ciechi che possono nascondere bambini o ostacoli."},
  {cat:"safety",en:"What is the recommended hand position on the steering wheel?",it:"Qual \u00e8 la posizione raccomandata delle mani sul volante?",options:[{en:"10 and 2 o'clock",it:"10 e 2 in punto"},{en:"9 and 3 o'clock",it:"9 e 3 in punto"},{en:"8 and 4 o'clock",it:"8 e 4 in punto"},{en:"One hand at 12 o'clock",it:"Una mano alle 12 in punto"}],correct:1,explain_en:"The current recommendation is 9 and 3 o'clock (or 8 and 4). This position provides better control and keeps hands away from airbag deployment zones compared to the older 10-and-2 position.",explain_it:"La raccomandazione attuale \u00e8 9 e 3 in punto (o 8 e 4). Questa posizione offre un controllo migliore e mantiene le mani lontane dalle zone di attivazione degli airbag rispetto alla vecchia posizione 10-e-2."},
  {cat:"alcohol",en:"What is the legal Blood Alcohol Content (BAC) limit for drivers 21 and older in Florida?",it:"Qual \u00e8 il limite legale di tasso alcolemico (BAC) per i conducenti di 21 anni e oltre in Florida?",options:[{en:"0.05%",it:"0,05%"},{en:"0.08%",it:"0,08%"},{en:"0.10%",it:"0,10%"},{en:"0.12%",it:"0,12%"}],correct:1,explain_en:"In Florida (and all U.S. states), the legal BAC limit for drivers 21 and older is 0.08%. For drivers under 21, the limit is 0.02% under Florida's Zero Tolerance Law.",explain_it:"In Florida (e in tutti gli stati USA), il limite legale di BAC per conducenti di 21 anni e oltre \u00e8 0,08%. Per i conducenti sotto i 21 anni, il limite \u00e8 0,02% ai sensi della legge Zero Tolerance della Florida."},
  {cat:"alcohol",en:"Under Florida's Implied Consent Law, refusing a breath or blood test when lawfully arrested for DUI will result in:",it:"In base alla legge del consenso implicito della Florida, rifiutarsi di sottoporsi a un test del respiro o del sangue quando si \u00e8 legalmente arrestati per guida in stato di ebbrezza comporta:",options:[{en:"No penalty if you are found not guilty of DUI",it:"Nessuna sanzione se si viene ritenuti non colpevoli di DUI"},{en:"Automatic license suspension (1 year for first refusal)",it:"Sospensione automatica della patente (1 anno per il primo rifiuto)"},{en:"A fine only, no license suspension",it:"Solo una multa, nessuna sospensione della patente"},{en:"Community service requirement",it:"Obbligo di servizio alla comunit\u00e0"}],correct:1,explain_en:"Under Florida's Implied Consent Law, refusal to submit to a chemical test results in an automatic 1-year license suspension for the first offense and 18 months for a second refusal.",explain_it:"Ai sensi della legge del consenso implicito della Florida, il rifiuto di sottoporsi a un test chimico comporta una sospensione automatica della patente di 1 anno per la prima infrazione e 18 mesi per un secondo rifiuto."},
  {cat:"alcohol",en:"Which of the following is TRUE about alcohol and driving?",it:"Quale delle seguenti affermazioni \u00e8 VERA sull'alcol e la guida?",options:[{en:"Coffee sobers you up quickly",it:"Il caff\u00e8 ti fa passare l'ubriachezza rapidamente"},{en:"Cold air sobers you up",it:"L'aria fredda ti fa passare l'ubriachezza"},{en:"Only time eliminates alcohol from your body",it:"Solo il tempo elimina l'alcol dal corpo"},{en:"Exercise speeds up alcohol metabolism",it:"L'esercizio fisico accelera il metabolismo dell'alcol"}],correct:2,explain_en:"Only time allows your body to eliminate alcohol. The liver processes approximately one standard drink per hour. Coffee, cold showers, food, and exercise do not speed this up.",explain_it:"Solo il tempo consente al corpo di eliminare l'alcol. Il fegato elabora circa un drink standard all'ora. Caff\u00e8, docce fredde, cibo ed esercizio fisico non accelerano questo processo."},
  {cat:"alcohol",en:"What is the BAC limit for drivers under 21 in Florida?",it:"Qual \u00e8 il limite di BAC per i conducenti sotto i 21 anni in Florida?",options:[{en:"0.00%",it:"0,00%"},{en:"0.02%",it:"0,02%"},{en:"0.05%",it:"0,05%"},{en:"0.08%",it:"0,08%"}],correct:1,explain_en:"Florida has a Zero Tolerance Law for drivers under 21. A BAC of 0.02% or higher (essentially any measurable alcohol) results in license suspension.",explain_it:"La Florida ha una legge di tolleranza zero per i conducenti sotto i 21 anni. Un BAC di 0,02% o superiore (essenzialmente qualsiasi quantit\u00e0 misurabile di alcol) comporta la sospensione della patente."},
  {cat:"alcohol",en:"A first DUI conviction in Florida can result in:",it:"Una prima condanna per DUI in Florida pu\u00f2 comportare:",options:[{en:"Only a fine with no other consequences",it:"Solo una multa senza altre conseguenze"},{en:"Fines, license revocation, possible jail time, and community service",it:"Multe, revoca della patente, eventuale carcere e servizio alla comunit\u00e0"},{en:"A warning and mandatory alcohol education class only",it:"Solo un avviso e una classe obbligatoria di educazione sull'alcol"},{en:"Automatic 10-year license suspension",it:"Sospensione automatica della patente di 10 anni"}],correct:1,explain_en:"A first DUI in Florida can result in fines ($500\u2013$2,000), up to 6 months in jail, up to 1 year license revocation, 50 hours of community service, and probation.",explain_it:"Una prima condanna per DUI in Florida pu\u00f2 comportare multe ($500\u2013$2.000), fino a 6 mesi di carcere, fino a 1 anno di revoca della patente, 50 ore di servizio alla comunit\u00e0 e libert\u00e0 vigilata."},
  {cat:"license",en:"In Florida, you must report a change of address to the FLHSMV within:",it:"In Florida, devi comunicare un cambio di indirizzo al FLHSMV entro:",options:[{en:"10 days",it:"10 giorni"},{en:"30 days",it:"30 giorni"},{en:"60 days",it:"60 giorni"},{en:"90 days",it:"90 giorni"}],correct:1,explain_en:"Florida requires you to notify the FLHSMV of a change of address within 30 days. Failure to do so may result in fines.",explain_it:"La Florida richiede di notificare al FLHSMV un cambio di indirizzo entro 30 giorni. La mancata notifica pu\u00f2 comportare sanzioni."},
  {cat:"license",en:"A Florida driver license must be renewed every:",it:"Una patente di guida della Florida deve essere rinnovata ogni:",options:[{en:"2 years",it:"2 anni"},{en:"4 years",it:"4 anni"},{en:"6 years",it:"6 anni"},{en:"8 years",it:"8 anni"}],correct:3,explain_en:"Standard Florida driver licenses are valid for 8 years. Drivers who are 80 or older must renew every 6 years.",explain_it:"Le patenti di guida standard della Florida sono valide per 8 anni. I conducenti di 80 anni e oltre devono rinnovarle ogni 6 anni."},
  {cat:"license",en:"Florida's point system suspends your license if you accumulate how many points in 12 months?",it:"Il sistema a punti della Florida sospende la tua patente se accumuli quanti punti in 12 mesi?",options:[{en:"8 points",it:"8 punti"},{en:"12 points",it:"12 punti"},{en:"15 points",it:"15 punti"},{en:"18 points",it:"18 punti"}],correct:1,explain_en:"In Florida, 12 points within 12 months = 30-day suspension; 18 points within 18 months = 3-month suspension; 24 points within 36 months = 1-year suspension.",explain_it:"In Florida: 12 punti in 12 mesi = sospensione di 30 giorni; 18 punti in 18 mesi = sospensione di 3 mesi; 24 punti in 36 mesi = sospensione di 1 anno."},
  {cat:"license",en:"If you receive a traffic citation and do not pay or contest it, what happens to your driving privilege?",it:"Se ricevi una multa per infrazione e non la paghi n\u00e9 la contesti, cosa succede alla tua autorizzazione a guidare?",options:[{en:"Nothing until you accumulate 3 unpaid citations",it:"Nulla finch\u00e9 non accumuli 3 infrazioni non pagate"},{en:"Your driver license may be suspended",it:"La tua patente potrebbe essere sospesa"},{en:"You receive a written warning",it:"Ricevi un avviso scritto"},{en:"The citation is automatically dismissed after 90 days",it:"La multa viene automaticamente archiviata dopo 90 giorni"}],correct:1,explain_en:"Failure to pay or contest a traffic citation in Florida results in a license suspension. You must either pay the fine or request a hearing.",explain_it:"La mancata risoluzione di una multa per infrazione in Florida comporta la sospensione della patente. Devi pagare la multa o richiedere un'udienza."},
  {cat:"license",en:"In Florida, who must wear a seat belt?",it:"In Florida, chi deve indossare la cintura di sicurezza?",options:[{en:"Only the driver",it:"Solo il conducente"},{en:"Driver and front-seat passengers only",it:"Solo il conducente e i passeggeri del sedile anteriore"},{en:"All front-seat occupants and all passengers under 18 regardless of seating position",it:"Tutti gli occupanti del sedile anteriore e tutti i passeggeri sotto i 18 anni indipendentemente dalla posizione"},{en:"Everyone in the vehicle regardless of age",it:"Tutti nel veicolo indipendentemente dall'et\u00e0"}],correct:2,explain_en:"Florida's seat belt law requires all front-seat occupants and all passengers under 18 (in any seat) to wear a seat belt. Adults 18+ in back seats are not covered by the primary law but are strongly encouraged.",explain_it:"La legge della Florida sulle cinture di sicurezza richiede che tutti gli occupanti del sedile anteriore e tutti i passeggeri sotto i 18 anni (in qualsiasi sedile) indossino la cintura. Gli adulti di 18+ nei sedili posteriori non sono coperti dalla legge primaria ma sono fortemente incoraggiati."},
  {cat:"license",en:"Florida requires all drivers to carry minimum liability insurance. What are the required minimums?",it:"La Florida richiede a tutti i conducenti una copertura assicurativa minima di responsabilit\u00e0. Quali sono i minimi richiesti?",options:[{en:"$10,000 PIP and $10,000 PDL",it:"$10.000 PIP e $10.000 PDL"},{en:"$25,000 bodily injury per person and $50,000 per accident",it:"$25.000 per lesioni per persona e $50.000 per incidente"},{en:"$100,000 bodily injury coverage only",it:"Solo $100.000 di copertura per lesioni"},{en:"$50,000 comprehensive coverage",it:"$50.000 di copertura completa"}],correct:0,explain_en:"Florida requires a minimum of $10,000 Personal Injury Protection (PIP) and $10,000 Property Damage Liability (PDL). Florida is a no-fault insurance state.",explain_it:"La Florida richiede un minimo di $10.000 di Personal Injury Protection (PIP) e $10.000 di Property Damage Liability (PDL). La Florida \u00e8 uno stato assicurativo 'no-fault'."},
  {cat:"license",en:"A new Florida resident with a valid out-of-state license must obtain a Florida license within:",it:"Un nuovo residente in Florida con una patente valida di un altro stato deve ottenere una patente Florida entro:",options:[{en:"10 days of becoming a resident",it:"10 giorni dall'acquisizione della residenza"},{en:"30 days of becoming a resident",it:"30 giorni dall'acquisizione della residenza"},{en:"60 days of becoming a resident",it:"60 giorni dall'acquisizione della residenza"},{en:"90 days of becoming a resident",it:"90 giorni dall'acquisizione della residenza"}],correct:1,explain_en:"New Florida residents must obtain a Florida driver license within 30 days of establishing residency in the state.",explain_it:"I nuovi residenti in Florida devono ottenere una patente di guida Florida entro 30 giorni dall'acquisizione della residenza nello stato."},
  {cat:"license",en:"What does a 'habitual traffic offender' designation in Florida mean?",it:"Cosa significa la designazione di 'trasgressore abituale del traffico' in Florida?",options:[{en:"You receive 3 extra points per violation",it:"Ricevi 3 punti extra per violazione"},{en:"Your license is revoked for 5 years if you have 3 or more major convictions within 5 years",it:"La tua patente viene revocata per 5 anni se hai 3 o pi\u00f9 condanne gravi entro 5 anni"},{en:"You must retake the driving test every year",it:"Devi sostenere nuovamente l'esame di guida ogni anno"},{en:"You are required to attend defensive driving school",it:"Sei obbligato a frequentare una scuola di guida difensiva"}],correct:1,explain_en:"A habitual traffic offender in Florida faces a mandatory 5-year license revocation for accumulating 3 or more major convictions (DUI, leaving the scene, etc.) within 5 years.",explain_it:"Un trasgressore abituale del traffico in Florida subisce una revoca obbligatoria della patente di 5 anni per aver accumulato 3 o pi\u00f9 condanne gravi (DUI, fuga dalla scena, ecc.) entro 5 anni."},
  {cat:"laws",en:"What is the legal definition of reckless driving in Florida?",it:"Qual \u00e8 la definizione legale di guida spericolata in Florida?",options:[{en:"Driving more than 20 mph over the speed limit",it:"Guidare a pi\u00f9 di 20 mph oltre il limite di velocit\u00e0"},{en:"Driving with willful or wanton disregard for the safety of persons or property",it:"Guidare con deliberata o sconsiderata noncuranza per la sicurezza di persone o propriet\u00e0"},{en:"Running a red light",it:"Passare con il rosso"},{en:"Driving without a license",it:"Guidare senza patente"}],correct:1,explain_en:"Florida law defines reckless driving as driving with willful or wanton disregard for the safety of people or property. It is a criminal traffic offense.",explain_it:"La legge della Florida definisce la guida spericolata come guidare con deliberata o sconsiderata noncuranza per la sicurezza di persone o propriet\u00e0. \u00c8 un reato penale stradale."},
  {cat:"laws",en:"When approaching a roundabout in Florida, you must:",it:"Quando ti avvicini a una rotatoria in Florida, devi:",options:[{en:"Accelerate to merge quickly",it:"Accelerare per immetterti rapidamente"},{en:"Yield to traffic already in the roundabout and enter when safe",it:"Cedere la precedenza al traffico gi\u00e0 nella rotatoria e immetterti quando \u00e8 sicuro"},{en:"Stop completely before entering",it:"Fermarti completamente prima di entrare"},{en:"Sound your horn to alert drivers in the circle",it:"Suonare il clacson per avvisare i conducenti nel cerchio"}],correct:1,explain_en:"At a roundabout, you must yield to vehicles already circulating inside the roundabout. Once it is safe, enter and travel counterclockwise to your exit.",explain_it:"In una rotatoria, devi cedere la precedenza ai veicoli gi\u00e0 in circolazione all'interno. Una volta che \u00e8 sicuro, entra e viaggia in senso antiorario fino alla tua uscita."},
  {cat:"safety",en:"What should you do if your brakes fail while driving?",it:"Cosa dovresti fare se i freni si guastano durante la guida?",options:[{en:"Turn off the ignition immediately",it:"Spegnere immediatamente il motore"},{en:"Pump the brakes (if not ABS), downshift, and steer to a safe area",it:"Pompare i freni (se non ABS), scalare marcia, e sterzare verso un'area sicura"},{en:"Open the door and drag your foot on the road",it:"Aprire la portiera e trascinare il piede sulla strada"},{en:"Swerve into oncoming traffic to slow down",it:"Sterzare verso il traffico in senso contrario per rallentare"}],correct:1,explain_en:"If brakes fail: pump rapidly (for non-ABS), downshift to slow the engine, use the emergency/parking brake gently, and guide the vehicle to a safe stop area.",explain_it:"Se i freni si guastano: pompare rapidamente (per non-ABS), scalare la marcia per rallentare il motore, usare delicatamente il freno di emergenza/parcheggio e guidare il veicolo verso un'area di arresto sicura."},
  {cat:"laws",en:"In Florida, what is the speed limit in a business or residential area unless otherwise posted?",it:"In Florida, qual \u00e8 il limite di velocit\u00e0 in un'area commerciale o residenziale salvo diversa indicazione?",options:[{en:"25 mph",it:"25 mph"},{en:"30 mph",it:"30 mph"},{en:"35 mph",it:"35 mph"},{en:"45 mph",it:"45 mph"}],correct:1,explain_en:"In Florida, the default speed limit in a business or residential district is 30 mph unless otherwise posted by a sign.",explain_it:"In Florida, il limite di velocit\u00e0 predefinito in un quartiere commerciale o residenziale \u00e8 30 mph (circa 48 km/h) salvo diversa indicazione da un cartello."},
  {cat:"laws",en:"What does a flashing yellow traffic signal mean?",it:"Cosa significa un segnale semaforico giallo lampeggiante?",options:[{en:"Stop completely before proceeding",it:"Fermarsi completamente prima di procedere"},{en:"Slow down and proceed with caution",it:"Rallentare e procedere con cautela"},{en:"Prepare to stop \u2014 the light is about to turn red",it:"Prepararsi a fermarsi: il semaforo sta per diventare rosso"},{en:"The signal is out of order \u2014 treat it as a stop sign",it:"Il segnale \u00e8 fuori servizio: trattarlo come un segnale di stop"}],correct:1,explain_en:"A flashing yellow light means slow down and proceed with caution. It does not require a full stop but does require increased alertness.",explain_it:"Una luce gialla lampeggiante significa rallentare e procedere con cautela. Non richiede un arresto completo ma richiede una maggiore attenzione."},
  {cat:"safety",en:"Florida's 'hands-free' law (effective 2020) primarily restricts:",it:"La legge 'hands-free' della Florida (in vigore dal 2020) principalmente limita:",options:[{en:"Using a GPS navigation device while driving",it:"L'uso di un dispositivo GPS durante la guida"},{en:"Holding a wireless device while driving in school or work zones",it:"Tenere in mano un dispositivo wireless mentre si guida nelle zone scolastiche o di lavoro"},{en:"Using Bluetooth headsets while driving",it:"L'uso di auricolari Bluetooth durante la guida"},{en:"Using the radio or music apps while driving",it:"L'uso della radio o di app musicali durante la guida"}],correct:1,explain_en:"Florida's hands-free law prohibits holding a wireless device while driving in designated school zones and active work zones. Violation is a primary offense.",explain_it:"La legge hands-free della Florida vieta di tenere in mano un dispositivo wireless mentre si guida nelle zone scolastiche designate e nelle zone di lavoro attive. La violazione \u00e8 un reato primario."},
  {cat:"laws",en:"When two vehicles arrive at an uncontrolled intersection at the same time, which vehicle has the right of way?",it:"Quando due veicoli arrivano contemporaneamente a un incrocio non controllato, quale ha la precedenza?",options:[{en:"The vehicle on the left",it:"Il veicolo a sinistra"},{en:"The vehicle on the right",it:"Il veicolo a destra"},{en:"The larger vehicle",it:"Il veicolo pi\u00f9 grande"},{en:"The faster-moving vehicle",it:"Il veicolo che si muove pi\u00f9 velocemente"}],correct:1,explain_en:"When two vehicles reach an uncontrolled intersection simultaneously, the vehicle on the left must yield to the vehicle on the right.",explain_it:"Quando due veicoli raggiungono simultaneamente un incrocio non controllato, il veicolo a sinistra deve cedere la precedenza al veicolo a destra."},
  {cat:"safety",en:"What is the first thing you should do at the scene of an accident involving injuries?",it:"Qual \u00e8 la prima cosa da fare sulla scena di un incidente con feriti?",options:[{en:"Exchange insurance information with the other driver",it:"Scambiare le informazioni assicurative con l'altro conducente"},{en:"Call 911 and render reasonable assistance",it:"Chiamare il 911 e prestare ragionevole assistenza"},{en:"Take photos of the scene before anything else",it:"Fare foto della scena prima di qualsiasi altra cosa"},{en:"Move all vehicles off the road immediately",it:"Spostare immediatamente tutti i veicoli dalla strada"}],correct:1,explain_en:"Florida law requires drivers involved in accidents with injuries to immediately call 911 and provide reasonable assistance to injured persons. Failure to do so ('hit and run') is a serious felony.",explain_it:"La legge della Florida richiede ai conducenti coinvolti in incidenti con feriti di chiamare immediatamente il 911 e prestare ragionevole assistenza alle persone ferite. La mancata ottemperanza ('hit and run') \u00e8 un grave reato."},
  {cat:"laws",en:"In Florida, you may park no closer than how many feet from a fire hydrant?",it:"In Florida, non puoi parcheggiare a meno di quanti piedi da un idrante antincendio?",options:[{en:"10 feet (3 m)",it:"10 piedi (3 m)"},{en:"15 feet (4,5 m)",it:"15 piedi (4,5 m)"},{en:"20 feet (6 m)",it:"20 piedi (6 m)"},{en:"30 feet (9 m)",it:"30 piedi (9 m)"}],correct:1,explain_en:"Florida law prohibits parking within 15 feet of a fire hydrant. Violators may be fined and the vehicle towed.",explain_it:"La legge della Florida vieta di parcheggiare entro 15 piedi (circa 4,5 m) da un idrante antincendio. I trasgressori possono essere multati e il veicolo rimosso."},
  {cat:"laws",en:"When entering a highway from an on-ramp, you should:",it:"Quando si entra in autostrada da una rampa di accesso, dovresti:",options:[{en:"Stop at the end of the ramp and wait for a gap",it:"Fermarsi alla fine della rampa e aspettare un'apertura"},{en:"Accelerate to match highway speed and merge smoothly into traffic",it:"Accelerare per raggiungere la velocit\u00e0 dell'autostrada e immetterti fluidamente nel traffico"},{en:"Enter at a slow speed and force traffic to yield",it:"Entrare a bassa velocit\u00e0 e costringere il traffico a cedere la precedenza"},{en:"Flash your headlights to signal your entry",it:"Lampeggiare i fari per segnalare il tuo ingresso"}],correct:1,explain_en:"When entering a highway, use the acceleration lane to reach highway speed and merge smoothly into a gap in traffic. Highway drivers have the right-of-way but must make room if safe.",explain_it:"Quando si entra in autostrada, usare la corsia di accelerazione per raggiungere la velocit\u00e0 dell'autostrada e immettersi fluidamente in uno spazio nel traffico. I conducenti in autostrada hanno la precedenza ma devono fare spazio se sicuro."},
  {cat:"safety",en:"Which is a characteristic of a safe driver?",it:"Qual \u00e8 una caratteristica di un guidatore sicuro?",options:[{en:"Always driving at the maximum posted speed limit",it:"Guidare sempre al massimo del limite di velocit\u00e0"},{en:"Scanning the road ahead and anticipating hazards",it:"Scansionare la strada davanti e anticipare i pericoli"},{en:"Driving aggressively to keep pace with traffic",it:"Guidare in modo aggressivo per stare al passo con il traffico"},{en:"Relying entirely on other drivers to avoid collisions",it:"Affidarsi interamente agli altri conducenti per evitare collisioni"}],correct:1,explain_en:"Safe drivers scan far ahead (12\u201315 seconds), identify potential hazards early, and maintain space to maneuver. Defensive driving is about anticipation, not reaction.",explain_it:"I guidatori sicuri scansionano lontano davanti (12\u201315 secondi), identificano precocemente i pericoli potenziali e mantengono spazio per manovrare. La guida difensiva riguarda l'anticipazione, non la reazione."},
  {cat:"laws",en:"You must stop your vehicle for a blind pedestrian who is:",it:"Devi fermarti per un pedone non vedente che sta:",options:[{en:"Only at a crosswalk with a traffic signal",it:"Solo a un passaggio pedonale con semaforo"},{en:"Using a white cane or guide dog at any crosswalk or intersection",it:"Usando un bastone bianco o cane guida a qualsiasi passaggio pedonale o incrocio"},{en:"Facing you from across the street",it:"Di fronte a te dall'altro lato della strada"},{en:"Only if the pedestrian has a disability card",it:"Solo se il pedone ha una tessera di disabilit\u00e0"}],correct:1,explain_en:"Florida law requires all drivers to stop and yield to visually impaired pedestrians using a white cane or guide dog at any crosswalk or intersection. Failure is a serious offense.",explain_it:"La legge della Florida richiede a tutti i conducenti di fermarsi e cedere la precedenza ai pedoni con disabilit\u00e0 visiva che utilizzano un bastone bianco o cane guida a qualsiasi passaggio pedonale o incrocio."},
  {cat:"signs",en:"A blue highway sign provides information about:",it:"Un segnale autostradale blu fornisce informazioni su:",options:[{en:"Speed limits",it:"Limiti di velocit\u00e0"},{en:"Motorist services (gas, food, lodging, hospitals)",it:"Servizi per automobilisti (carburante, cibo, alloggio, ospedali)"},{en:"Hazards and road conditions",it:"Pericoli e condizioni stradali"},{en:"State and national parks",it:"Parchi statali e nazionali"}],correct:1,explain_en:"Blue signs indicate motorist services, including gas stations, rest areas, restaurants, lodging, and hospitals. These help travelers find services along the route.",explain_it:"I segnali blu indicano servizi per automobilisti, tra cui stazioni di servizio, aree di sosta, ristoranti, alloggi e ospedali. Questi aiutano i viaggiatori a trovare servizi lungo il percorso."},
  {cat:"safety",en:"If you are involved in a crash causing more than $500 in property damage and no police respond, you must:",it:"Se sei coinvolto in un incidente che causa danni materiali superiori a $500 e la polizia non interviene, devi:",options:[{en:"Report it to the insurance company only",it:"Segnalarlo solo alla compagnia assicurativa"},{en:"File a written report (SR-13) with FLHSMV within 10 days",it:"Presentare una relazione scritta (SR-13) al FLHSMV entro 10 giorni"},{en:"No report is required if everyone agrees on blame",it:"Non \u00e8 richiesta alcuna segnalazione se tutti concordano sulla responsabilit\u00e0"},{en:"Report it within 30 days to the FLHSMV",it:"Segnalarlo al FLHSMV entro 30 giorni"}],correct:1,explain_en:"If police do not respond to a crash with $500+ in property damage or injury, the driver must file a written crash report (SR-13) with FLHSMV within 10 days.",explain_it:"Se la polizia non interviene a un incidente con $500+ di danni materiali o feriti, il conducente deve presentare una relazione scritta sull'incidente (SR-13) al FLHSMV entro 10 giorni."},
  {cat:"signs",en:"A green traffic signal means:",it:"Un semaforo verde significa:",options:[{en:"Proceed if the intersection is clear",it:"Procedere se l'incrocio \u00e8 libero"},{en:"Slow down",it:"Rallentare"},{en:"Stop \u2014 prepare to yield",it:"Fermarsi \u2014 prepararsi a cedere la precedenza"},{en:"Emergency vehicles approaching",it:"Veicoli di emergenza in arrivo"}],correct:0,explain_en:"A green light means you may proceed if the intersection is clear and it is safe to do so. Always check for cross-traffic before entering.",explain_it:"Il verde significa che puoi procedere se l'incrocio \u00e8 libero e sicuro. Verifica sempre il traffico trasversale prima di entrare."},
  {cat:"signs",en:"A flashing red traffic signal should be treated as:",it:"Un segnale semaforico rosso lampeggiante va trattato come:",options:[{en:"A yield sign",it:"Un segnale di precedenza YIELD"},{en:"A stop sign \u2014 stop, yield, then proceed when safe",it:"Un segnale STOP \u2014 fermarsi, cedere, poi procedere quando sicuro"},{en:"A green light",it:"Un semaforo verde"},{en:"A caution to slow down only",it:"Solo un invito a rallentare"}],correct:1,explain_en:"A flashing red signal must be treated exactly like a stop sign: come to a full stop, yield to traffic and pedestrians, and proceed when safe.",explain_it:"Un segnale rosso lampeggiante va trattato esattamente come uno stop: arresto completo, cedere la precedenza a traffico e pedoni, procedere quando sicuro."},
  {cat:"signs",en:"A flashing yellow traffic signal means:",it:"Un segnale semaforico giallo lampeggiante significa:",options:[{en:"Stop completely",it:"Fermarsi completamente"},{en:"Slow down and proceed with caution",it:"Rallentare e procedere con cautela"},{en:"The light is about to turn red",it:"Il semaforo sta per diventare rosso"},{en:"Yield to all cross traffic",it:"Cedere a tutto il traffico trasversale"}],correct:1,explain_en:"A flashing yellow means slow down and proceed with caution \u2014 no full stop is required unless traffic demands it.",explain_it:"Il giallo lampeggiante significa rallentare e procedere con cautela \u2014 non \u00e8 richiesto un arresto completo a meno che il traffico lo imponga."},
  {cat:"signs",en:"A green arrow displayed with a red light means:",it:"Una freccia verde mostrata insieme a un semaforo rosso significa:",options:[{en:"Yield and then turn in the direction of the arrow",it:"Cedere e poi svoltare nella direzione della freccia"},{en:"You may move in the direction of the arrow \u2014 oncoming traffic is stopped",it:"Puoi muoverti nella direzione della freccia \u2014 il traffico opposto \u00e8 fermo"},{en:"All traffic may proceed",it:"Tutto il traffico pu\u00f2 procedere"},{en:"Pedestrians have right-of-way in the arrow direction",it:"I pedoni hanno la precedenza nella direzione della freccia"}],correct:1,explain_en:"A green arrow (protected signal) means you may move in that direction \u2014 conflicting traffic is stopped by a red light. It is a protected movement.",explain_it:"Una freccia verde (segnale protetto) indica che puoi muoverti in quella direzione \u2014 il traffico in conflitto \u00e8 fermato dal rosso. \u00c8 un movimento protetto."},
  {cat:"signs",en:"What does a yellow X signal above a traffic lane indicate?",it:"Cosa indica una X gialla sopra una corsia di traffico?",options:[{en:"The lane is open \u2014 proceed normally",it:"La corsia \u00e8 aperta \u2014 procedere normalmente"},{en:"Prepare to leave this lane \u2014 it is about to close",it:"Prepararsi a lasciare questa corsia \u2014 sta per chiudersi"},{en:"The lane is reserved for high-occupancy vehicles",it:"La corsia \u00e8 riservata ai veicoli ad alta occupazione"},{en:"Turning is required from this lane",it:"\u00c8 obbligatorio svoltare da questa corsia"}],correct:1,explain_en:"A yellow X above a lane is a warning that the lane is closing. Drivers should safely move to an adjacent open lane.",explain_it:"Una X gialla sopra una corsia avvisa che la corsia sta per chiudersi. I conducenti devono spostarsi in sicurezza in una corsia adiacente aperta."},
  {cat:"signs",en:"What does a red X signal above a traffic lane mean?",it:"Cosa significa una X rossa sopra una corsia di traffico?",options:[{en:"Emergency vehicles only permitted",it:"Solo veicoli di emergenza consentiti"},{en:"The lane is closed \u2014 do not use it",it:"La corsia \u00e8 chiusa \u2014 non usarla"},{en:"Trucks and buses prohibited",it:"Camion e autobus vietati"},{en:"Speed limit reduction in effect",it:"Riduzione del limite di velocit\u00e0 in vigore"}],correct:1,explain_en:"A red X above a lane means the lane is closed to traffic. Driving in a lane with a red X is illegal and dangerous.",explain_it:"Una X rossa sopra una corsia significa che quella corsia \u00e8 chiusa al traffico. Guidarci \u00e8 illegale e pericoloso."},
  {cat:"signs",en:"A pennant-shaped yellow sign on the LEFT side of the road indicates:",it:"Un segnale a pennant giallo sul lato SINISTRO della strada indica:",options:[{en:"No U-turn",it:"Divieto di inversione di marcia"},{en:"Beginning of a no-passing zone",it:"Inizio di una zona di divieto di sorpasso"},{en:"Slow vehicle turn-out ahead",it:"Piazzola di sosta veicoli lenti in avanti"},{en:"Road narrows from the left",it:"La strada si restringe dal lato sinistro"}],correct:1,explain_en:"The pennant-shaped sign marks the beginning of a no-passing zone. It always appears on the left side of the road.",explain_it:"Il segnale a pennant segna l'inizio di una zona di divieto di sorpasso. Appare sempre sul lato sinistro della strada."},
  {cat:"signs",en:"A 'Do Not Enter' sign means:",it:"Un segnale 'Do Not Enter' (Vietato Accesso) significa:",options:[{en:"Slow down to 15 mph",it:"Rallentare a 15 mph"},{en:"Do not enter this road or area",it:"Non entrare in questa strada o area"},{en:"Yield to oncoming traffic before entering",it:"Cedere al traffico in arrivo prima di entrare"},{en:"One-way street \u2014 enter with caution",it:"Strada a senso unico \u2014 entrare con cautela"}],correct:1,explain_en:"'Do Not Enter' prohibits entry into a roadway or area, usually on one-way streets or exit ramps. Entering is extremely dangerous and illegal.",explain_it:"'Do Not Enter' vieta l'accesso a una strada o area, solitamente su strade a senso unico o rampe di uscita. Entrare \u00e8 estremamente pericoloso e illegale."},
  {cat:"signs",en:"A 'Wrong Way' sign means:",it:"Un segnale 'Wrong Way' (Senso Vietato) significa:",options:[{en:"You are entering a restricted zone",it:"Stai entrando in una zona riservata"},{en:"You are traveling against the flow of traffic \u2014 turn around immediately",it:"Stai viaggiando contromano \u2014 invertire immediatamente la marcia"},{en:"Speed reduction required ahead",it:"Riduzione della velocit\u00e0 richiesta in avanti"},{en:"Road is closed for construction",it:"Strada chiusa per lavori"}],correct:1,explain_en:"A 'Wrong Way' sign means you are headed into oncoming traffic. Stop, turn around safely, and exit the roadway immediately.",explain_it:"Un segnale 'Wrong Way' significa che stai andando contromano. Fermarsi, invertire in sicurezza e uscire immediatamente dalla carreggiata."},
  {cat:"signs",en:"A round yellow sign with an 'X' and the letters 'RR' means:",it:"Un segnale rotondo giallo con una 'X' e le lettere 'RR' significa:",options:[{en:"Railroad crossing ahead \u2014 be prepared to stop",it:"Passaggio a livello in avanti \u2014 prepararsi a fermarsi"},{en:"No passing zone 100 feet ahead",it:"Zona di divieto di sorpasso a 100 piedi"},{en:"Rest area with restrooms",it:"Area di sosta con servizi igienici"},{en:"Road narrows ahead",it:"La strada si restringe in avanti"}],correct:0,explain_en:"A round yellow sign with RR and an X is an advance warning of a railroad crossing ahead. Slow down and be prepared to stop if a train is coming.",explain_it:"Un segnale rotondo giallo con RR e una X \u00e8 un avviso anticipato di un passaggio a livello in avanti. Rallentare e prepararsi a fermarsi se arriva un treno."},
  {cat:"signs",en:"Yellow pavement center-line markings separate:",it:"Le linee centrali gialle sul manto stradale separano:",options:[{en:"Lanes of traffic traveling in the same direction",it:"Corsie di traffico nella stessa direzione"},{en:"Traffic traveling in opposite directions",it:"Il traffico che viaggia in direzioni opposte"},{en:"Bicycle lanes from vehicle lanes",it:"Piste ciclabili dalle corsie per veicoli"},{en:"Parking from travel lanes",it:"Parcheggio dalle corsie di marcia"}],correct:1,explain_en:"Yellow center-line markings always separate traffic moving in opposite directions. White markings separate traffic moving in the same direction.",explain_it:"Le linee centrali gialle separano sempre il traffico che si muove in direzioni opposte. Le bianche separano il traffico nella stessa direzione."},
  {cat:"signs",en:"A solid white line at an intersection stop bar means:",it:"Una linea bianca continua alla linea di arresto di un incrocio significa:",options:[{en:"You may cross it at any time",it:"Puoi attraversarla in qualsiasi momento"},{en:"Stop here \u2014 do not cross the line when required to stop",it:"Fermati qui \u2014 non attraversare la linea quando sei obbligato a fermarti"},{en:"Yield to pedestrians only",it:"Cedere la precedenza solo ai pedoni"},{en:"No-parking zone begins here",it:"Inizia una zona di divieto di sosta"}],correct:1,explain_en:"A solid white stop bar marks where you must stop for a stop sign or red light. Your vehicle must not cross this line when stopping.",explain_it:"Una linea di arresto bianca continua segna dove devi fermarti per uno stop o un semaforo rosso. Il veicolo non deve attraversare questa linea quando si ferma."},
  {cat:"signs",en:"What color are guide signs on interstate highways?",it:"Di che colore sono i segnali informativi sulle autostrade interstatali?",options:[{en:"Blue",it:"Blu"},{en:"Brown",it:"Marrone"},{en:"Green",it:"Verde"},{en:"White",it:"Bianco"}],correct:2,explain_en:"Green signs are guide signs on interstates and highways. They give directional and distance information to exits and destinations.",explain_it:"I segnali verdi sono segnali informativi sulle autostrade interstatali. Forniscono informazioni su direzioni, distanze e destinazioni."},
  {cat:"signs",en:"Brown highway signs indicate:",it:"I segnali autostradali marroni indicano:",options:[{en:"Motorist services (gas, food)",it:"Servizi per automobilisti (carburante, cibo)"},{en:"Recreational areas and points of cultural interest",it:"Aree ricreative e punti di interesse culturale"},{en:"Construction zones",it:"Zone di lavori stradali"},{en:"Regulatory speed zones",it:"Zone di velocit\u00e0 normativa"}],correct:1,explain_en:"Brown signs indicate recreational areas, parks, historical landmarks, and cultural points of interest.",explain_it:"I segnali marroni indicano aree ricreative, parchi, siti storici e punti di interesse culturale."},
  {cat:"signs",en:"A 'Merge' sign warns that:",it:"Un segnale 'Merge' (Confluenza) avverte che:",options:[{en:"The road is splitting into two lanes",it:"La strada si divide in due corsie"},{en:"Two lanes of traffic will soon join into one",it:"Due corsie di traffico si uniranno presto in una"},{en:"You must stop and yield",it:"Devi fermarti e cedere la precedenza"},{en:"A lane is reserved for merging vehicles only",it:"Una corsia \u00e8 riservata solo ai veicoli in confluenza"}],correct:1,explain_en:"A Merge sign warns that two lanes of traffic will soon combine into one. Adjust speed and position to merge safely.",explain_it:"Un segnale Merge avverte che due corsie di traffico si uniranno presto in una. Adeguare velocit\u00e0 e posizione per confluire in sicurezza."},
  {cat:"signs",en:"What shape is a STOP sign?",it:"Che forma ha un segnale STOP?",options:[{en:"Rectangle",it:"Rettangolo"},{en:"Pentagon",it:"Pentagono"},{en:"Octagon",it:"Ottagono"},{en:"Circle",it:"Cerchio"}],correct:2,explain_en:"The STOP sign is an octagon (8 sides). It is always red with white lettering. Its unique shape allows recognition even when obscured by snow or dirt.",explain_it:"Il segnale STOP \u00e8 un ottagono (8 lati). \u00c8 sempre rosso con lettere bianche. La sua forma unica consente il riconoscimento anche quando \u00e8 oscurato."},
  {cat:"signs",en:"What shape is a YIELD sign?",it:"Che forma ha un segnale YIELD (Precedenza)?",options:[{en:"Octagon",it:"Ottagono"},{en:"Inverted triangle (point down)",it:"Triangolo capovolto (punta verso il basso)"},{en:"Diamond",it:"Rombo"},{en:"Pentagon",it:"Pentagono"}],correct:1,explain_en:"The YIELD sign is an inverted triangle with a red border \u2014 unique shape means drivers recognize it even without seeing the text.",explain_it:"Il segnale YIELD \u00e8 un triangolo capovolto con bordo rosso \u2014 la forma unica consente il riconoscimento anche senza leggere il testo."},
  {cat:"signs",en:"A speed limit sign is classified as a:",it:"Un segnale di limite di velocit\u00e0 \u00e8 classificato come:",options:[{en:"Warning sign",it:"Segnale di avvertimento"},{en:"Regulatory sign",it:"Segnale normativo"},{en:"Guide sign",it:"Segnale informativo"},{en:"Temporary sign",it:"Segnale temporaneo"}],correct:1,explain_en:"Speed limit signs are regulatory signs. They establish the maximum legal speed allowed and must be obeyed.",explain_it:"I segnali di limite di velocit\u00e0 sono normativi. Stabiliscono la velocit\u00e0 massima legale consentita e devono essere rispettati."},
  {cat:"signs",en:"A crosswalk marked with white lines means:",it:"Un passaggio pedonale segnato con linee bianche significa:",options:[{en:"Parking is permitted here",it:"Il parcheggio \u00e8 consentito qui"},{en:"Pedestrians may be crossing \u2014 yield to them",it:"I pedoni potrebbero attraversare \u2014 cedergli la precedenza"},{en:"Bicycles only may cross here",it:"Solo le biciclette possono attraversare qui"},{en:"Speed up to clear the crossing",it:"Accelerare per liberare il passaggio"}],correct:1,explain_en:"Marked crosswalks indicate where pedestrians may cross. Florida law requires drivers to yield to any pedestrian in a crosswalk.",explain_it:"I passaggi pedonali segnalati indicano dove i pedoni possono attraversare. La legge della Florida richiede di cedere a qualsiasi pedone in un passaggio pedonale."},
  {cat:"signs",en:"A 'No U-Turn' sign means:",it:"Un segnale 'No U-Turn' (Divieto di Inversione) significa:",options:[{en:"U-turns are permitted with caution",it:"Le inversioni sono consentite con cautela"},{en:"U-turns are prohibited at this location",it:"Le inversioni sono vietate in questo punto"},{en:"U-turns allowed only for trucks",it:"Inversioni consentite solo ai camion"},{en:"Reduce speed before making a U-turn",it:"Ridurre la velocit\u00e0 prima dell'inversione"}],correct:1,explain_en:"A 'No U-Turn' sign prohibits making a U-turn at that intersection or location. Violating it is a moving violation.",explain_it:"Un segnale 'No U-Turn' vieta di eseguire un'inversione di marcia in quell'incrocio o punto. Violarlo \u00e8 un'infrazione in movimento."},
  {cat:"signs",en:"When pavement markings are white and dashed (broken), they mean:",it:"Quando le linee sul manto stradale sono bianche e tratteggiate, significano:",options:[{en:"No lane change permitted",it:"Nessun cambio di corsia consentito"},{en:"Lane changes are permitted when safe",it:"I cambi di corsia sono consentiti quando sicuro"},{en:"Bicycle lane",it:"Corsia ciclabile"},{en:"No passing zone",it:"Zona di divieto di sorpasso"}],correct:1,explain_en:"White dashed lines separate lanes of same-direction traffic. You may change lanes when it is safe to do so.",explain_it:"Le linee bianche tratteggiate separano le corsie dello stesso senso di marcia. Puoi cambiare corsia quando \u00e8 sicuro farlo."},
  {cat:"signs",en:"A 'Lane Ends' sign means:",it:"Un segnale 'Lane Ends' (Fine Corsia) significa:",options:[{en:"The road ends \u2014 no outlet",it:"La strada finisce \u2014 nessuna uscita"},{en:"Your lane is ending \u2014 merge safely into the adjacent lane",it:"La tua corsia sta finendo \u2014 immettiti in sicurezza nella corsia adiacente"},{en:"No passing allowed in this lane",it:"Sorpasso non consentito in questa corsia"},{en:"Reduce speed to 25 mph",it:"Ridurre la velocit\u00e0 a 25 mph"}],correct:1,explain_en:"A 'Lane Ends' sign means your current lane is ending. You must merge into the adjacent lane. Yield to traffic in the lane you are entering.",explain_it:"Un segnale 'Lane Ends' significa che la tua corsia sta finendo. Devi immetterti nella corsia adiacente, cedendo al traffico in quella corsia."},
  {cat:"signs",en:"What does a 'Keep Right' sign mean?",it:"Cosa significa un segnale 'Keep Right' (Tenersi a Destra)?",options:[{en:"Pass only on the right side of other vehicles",it:"Superare solo sul lato destro degli altri veicoli"},{en:"Stay to the right of a divider, island, or obstruction",it:"Tenersi a destra di uno spartitraffico, isola o ostacolo"},{en:"Right turn only at the next intersection",it:"Solo svolta a destra al prossimo incrocio"},{en:"Right lane is the slow lane \u2014 use it if below speed limit",it:"La corsia destra \u00e8 quella lenta \u2014 usarla se sotto il limite"}],correct:1,explain_en:"A 'Keep Right' sign tells drivers to stay to the right side of a divider, median, island, or other obstruction in the roadway.",explain_it:"Un segnale 'Keep Right' indica ai conducenti di tenersi a destra di uno spartitraffico, mediana, isola o altro ostacolo nella carreggiata."},
  {cat:"signs",en:"What does a truck on a slope road sign indicate?",it:"Cosa indica un segnale raffigurante un camion su una strada in pendenza?",options:[{en:"Truck parking area ahead",it:"Area di parcheggio camion in avanti"},{en:"Steep hill ahead \u2014 trucks should use lower gears",it:"Pendenza ripida in avanti \u2014 i camion devono usare marce basse"},{en:"No trucks allowed on this road",it:"Camion non consentiti su questa strada"},{en:"Runaway truck ramp available on the right",it:"Rampa di emergenza per camion disponibile a destra"}],correct:1,explain_en:"A truck-on-slope sign warns of a steep grade ahead. Trucks should downshift and all drivers should increase following distance.",explain_it:"Un segnale con camion in pendenza avverte di una pendenza ripida in avanti. I camion devono scalare marcia e tutti i conducenti devono aumentare la distanza."},
  {cat:"signs",en:"A 'No Left Turn' sign means:",it:"Un segnale 'No Left Turn' (Divieto Svolta a Sinistra) significa:",options:[{en:"Left turns are required here",it:"Le svolte a sinistra sono obbligatorie qui"},{en:"Left turns are prohibited at this location",it:"Le svolte a sinistra sono vietate in questo punto"},{en:"Left turns allowed only when no oncoming traffic",it:"Svolte a sinistra consentite solo senza traffico in arrivo"},{en:"Yield before turning left",it:"Cedere la precedenza prima di svoltare a sinistra"}],correct:1,explain_en:"A 'No Left Turn' sign prohibits left turns at that intersection or location. Obeying it is mandatory.",explain_it:"Un segnale 'No Left Turn' vieta le svolte a sinistra a quell'incrocio o in quel punto. Rispettarlo \u00e8 obbligatorio."},
  {cat:"signs",en:"A school zone sign is typically what color?",it:"Un segnale di zona scolastica \u00e8 tipicamente di che colore?",options:[{en:"Yellow",it:"Giallo"},{en:"Fluorescent yellow-green",it:"Giallo-verde fluorescente"},{en:"Orange",it:"Arancione"},{en:"Red",it:"Rosso"}],correct:1,explain_en:"School zone and pedestrian warning signs use a distinctive fluorescent yellow-green color for maximum visibility.",explain_it:"I segnali di zona scolastica e di avvertimento pedonale usano un colore giallo-verde fluorescente per la massima visibilit\u00e0."},
  {cat:"signs",en:"Double solid yellow center lines mean:",it:"Una doppia linea gialla continua al centro significa:",options:[{en:"Passing is allowed from both directions",it:"Il sorpasso \u00e8 consentito da entrambe le direzioni"},{en:"Passing is prohibited from both directions",it:"Il sorpasso \u00e8 vietato da entrambe le direzioni"},{en:"Passing is allowed only during daylight",it:"Il sorpasso \u00e8 consentito solo di giorno"},{en:"The center lane is for left turns only",it:"La corsia centrale \u00e8 solo per le svolte a sinistra"}],correct:1,explain_en:"Double solid yellow lines mean no passing is allowed from either direction. Neither lane may cross these lines to pass.",explain_it:"Una doppia linea gialla continua significa che il sorpasso \u00e8 vietato da entrambe le direzioni. Nessuna corsia pu\u00f2 attraversare queste linee per sorpassare."},
  {cat:"laws",en:"On a Florida interstate highway, the maximum speed limit is typically:",it:"Su un'autostrada interstatale della Florida, il limite massimo di velocit\u00e0 \u00e8 tipicamente:",options:[{en:"55 mph",it:"55 mph"},{en:"65 mph",it:"65 mph"},{en:"70 mph",it:"70 mph"},{en:"75 mph",it:"75 mph"}],correct:2,explain_en:"Most Florida interstates have a maximum speed of 70 mph. Urban interstates within city limits are typically 65 mph.",explain_it:"La maggior parte delle autostrade interstatali della Florida ha un limite massimo di 70 mph. Le autostrade urbane all'interno dei limiti della citt\u00e0 sono tipicamente 65 mph."},
  {cat:"laws",en:"The speed limit in a Florida school zone when children are present is:",it:"Il limite di velocit\u00e0 in una zona scolastica della Florida con bambini presenti \u00e8:",options:[{en:"15 mph",it:"15 mph"},{en:"20 mph",it:"20 mph"},{en:"25 mph",it:"25 mph"},{en:"30 mph",it:"30 mph"}],correct:1,explain_en:"Florida school zones have a 20 mph speed limit when children are present. Traffic fines are doubled in school zones.",explain_it:"Le zone scolastiche della Florida hanno un limite di 20 mph con bambini presenti. Le multe per infrazioni stradali sono raddoppiate nelle zone scolastiche."},
  {cat:"laws",en:"When must you turn on your headlights in Florida?",it:"Quando devi accendere i fari in Florida?",options:[{en:"Only after dark",it:"Solo dopo il buio"},{en:"From sunset to sunrise and when visibility is less than 1,000 feet",it:"Dal tramonto all'alba e quando la visibilit\u00e0 \u00e8 inferiore a 300 m"},{en:"Only in rain or heavy fog",it:"Solo in caso di pioggia o nebbia fitta"},{en:"Only on roads without streetlights",it:"Solo su strade senza illuminazione pubblica"}],correct:1,explain_en:"Florida requires headlights from sunset to sunrise and whenever visibility is reduced to less than 1,000 feet due to rain, fog, smoke, or other conditions.",explain_it:"La Florida richiede i fari dal tramonto all'alba e ogni volta che la visibilit\u00e0 si riduce a meno di 300 m a causa di pioggia, nebbia, fumo o altre condizioni."},
  {cat:"laws",en:"Florida's Move Over Law requires you, on a multi-lane road, to:",it:"La legge Move Over della Florida richiede su strade a pi\u00f9 corsie di:",options:[{en:"Slow down by 20 mph and keep your lane",it:"Rallentare di 20 mph e mantenere la corsia"},{en:"Move one lane away from a stopped emergency vehicle OR reduce speed 20 mph below the limit",it:"Spostarti di una corsia dal veicolo di emergenza fermo O ridurre la velocit\u00e0 di 20 mph sotto il limite"},{en:"Stop completely until the emergency vehicle leaves",it:"Fermarti completamente finch\u00e9 il veicolo di emergenza non se ne va"},{en:"Flash your lights as a courtesy",it:"Lampeggiare i fari come gesto di cortesia"}],correct:1,explain_en:"Florida's Move Over Law: on multi-lane roads, move over one lane away from stopped emergency/tow/road maintenance vehicles, OR if unable, slow to 20 mph below the posted limit.",explain_it:"Legge Move Over della Florida: su strade a pi\u00f9 corsie, spostarsi di una corsia dal veicolo fermo (emergenza/carro attrezzi/manutenzione), O se impossibile, rallentare a 20 mph sotto il limite."},
  {cat:"laws",en:"Florida's Move Over Law also covers:",it:"La legge Move Over della Florida copre anche:",options:[{en:"Any vehicle stopped on the shoulder",it:"Qualsiasi veicolo fermo sulla corsia di emergenza"},{en:"Tow trucks and road maintenance vehicles with flashing lights",it:"Carroattrezzi e veicoli di manutenzione stradale con luci lampeggianti"},{en:"School buses loading or unloading",it:"Scuolabus in fase di carico o scarico"},{en:"Parked delivery trucks",it:"Camion di consegna parcheggiati"}],correct:1,explain_en:"The Move Over Law covers emergency vehicles, tow trucks, and road maintenance vehicles operating with flashing lights \u2014 not just police and ambulances.",explain_it:"La legge Move Over copre i veicoli di emergenza, i carroattrezzi e i veicoli di manutenzione stradale con luci lampeggianti \u2014 non solo polizia e ambulanze."},
  {cat:"laws",en:"On a divided highway, when a school bus stops with flashing red lights, traffic on the OPPOSITE side of the median must:",it:"Su una strada divisa, quando uno scuolabus si ferma con luci rosse lampeggianti, il traffico sul lato OPPOSTO della mediana deve:",options:[{en:"Also stop and wait",it:"Fermarsi anche e aspettare"},{en:"NOT stop \u2014 only same-side traffic must stop",it:"NON fermarsi \u2014 solo il traffico sullo stesso lato deve fermarsi"},{en:"Slow to 15 mph",it:"Rallentare a 15 mph"},{en:"Stop only if children are visible",it:"Fermarsi solo se i bambini sono visibili"}],correct:1,explain_en:"On divided highways with a raised median, traffic on the opposite side does NOT need to stop for a school bus. Only traffic behind the bus must stop.",explain_it:"Su strade divise con mediana rialzata, il traffico sul lato opposto NON deve fermarsi per uno scuolabus. Solo il traffico dietro lo scuolabus deve fermarsi."},
  {cat:"laws",en:"At a four-way stop, if you arrive at the same time as the driver to your right, you should:",it:"A un incrocio a quattro vie, se arrivi contemporaneamente al conducente alla tua destra, dovresti:",options:[{en:"Proceed first \u2014 you are on the right",it:"Procedere per primo \u2014 sei a destra"},{en:"Yield to the driver on your right",it:"Cedere la precedenza al conducente alla tua destra"},{en:"Both proceed together",it:"Procedere entrambi insieme"},{en:"Honk to establish who goes first",it:"Suonare il clacson per stabilire chi va per primo"}],correct:1,explain_en:"At a 4-way stop with simultaneous arrivals, yield to the driver on your right. They have the right-of-way.",explain_it:"A un incrocio a 4 vie con arrivi simultanei, cedere la precedenza al conducente alla propria destra. Ha la precedenza."},
  {cat:"laws",en:"When turning left at a green light, you must yield to:",it:"Quando svolti a sinistra con semaforo verde, devi cedere la precedenza a:",options:[{en:"No one \u2014 you have a green light",it:"Nessuno \u2014 hai il verde"},{en:"Oncoming vehicles and pedestrians crossing in your path",it:"Veicoli in arrivo e pedoni che attraversano il tuo percorso"},{en:"Only pedestrians in the crosswalk",it:"Solo i pedoni nel passaggio pedonale"},{en:"Emergency vehicles only",it:"Solo i veicoli di emergenza"}],correct:1,explain_en:"A green light for left turns does NOT give you the right-of-way. You must still yield to oncoming traffic and pedestrians crossing in your path.",explain_it:"Un semaforo verde per le svolte a sinistra NON ti d\u00e0 la precedenza. Devi comunque cedere ai veicoli in arrivo e ai pedoni che attraversano il tuo percorso."},
  {cat:"laws",en:"Florida requires you to signal at least how far before turning on a highway?",it:"La Florida richiede di segnalare ad almeno quanta distanza prima di svoltare in autostrada?",options:[{en:"100 feet (30 m)",it:"100 piedi (30 m)"},{en:"150 feet (45 m)",it:"150 piedi (45 m)"},{en:"200 feet (60 m)",it:"200 piedi (60 m)"},{en:"300 feet (90 m)",it:"300 piedi (90 m)"}],correct:2,explain_en:"On a highway, Florida law requires a turn signal at least 200 feet (about 60 m) before the turn. In residential areas, it's at least 100 feet.",explain_it:"In autostrada, la legge della Florida richiede di segnalare la svolta almeno 200 piedi (circa 60 m) prima. Nelle zone residenziali, almeno 100 piedi."},
  {cat:"laws",en:"Pedestrians on Florida roads have the right-of-way:",it:"I pedoni sulle strade della Florida hanno la precedenza:",options:[{en:"Only at marked crosswalks",it:"Solo ai passaggi pedonali segnalati"},{en:"At all crosswalks \u2014 marked or unmarked \u2014 and at intersections",it:"A tutti i passaggi pedonali \u2014 segnalati o meno \u2014 e agli incroci"},{en:"Only when a walk signal is displayed",it:"Solo quando \u00e8 visualizzato il segnale di cammina"},{en:"Only in school and residential zones",it:"Solo nelle zone scolastiche e residenziali"}],correct:1,explain_en:"Florida law requires drivers to yield to pedestrians at any crosswalk \u2014 marked or unmarked \u2014 and at any intersection, at all times.",explain_it:"La legge della Florida richiede di cedere la precedenza ai pedoni a qualsiasi passaggio pedonale \u2014 segnalato o meno \u2014 e a qualsiasi incrocio, in qualsiasi momento."},
  {cat:"laws",en:"How close to a railroad crossing may you park?",it:"A quanti piedi da un passaggio a livello puoi parcheggiare?",options:[{en:"Within 30 feet (9 m) is fine",it:"Entro 30 piedi (9 m) va bene"},{en:"No closer than 50 feet (15 m)",it:"Non pi\u00f9 vicino di 50 piedi (15 m)"},{en:"No closer than 100 feet (30 m)",it:"Non pi\u00f9 vicino di 100 piedi (30 m)"},{en:"No restriction \u2014 park anywhere",it:"Nessuna restrizione \u2014 parcheggiare ovunque"}],correct:1,explain_en:"You may not park within 50 feet of a railroad crossing. This ensures emergency access and visibility for crossing traffic.",explain_it:"Non puoi parcheggiare entro 50 piedi (15 m) da un passaggio a livello. Questo garantisce accesso di emergenza e visibilit\u00e0 per il traffico."},
  {cat:"laws",en:"It is illegal to follow an emergency vehicle (lights/siren active) closer than:",it:"\u00c8 illegale seguire un veicolo di emergenza (luci/sirena attive) a meno di:",options:[{en:"100 feet (30 m)",it:"100 piedi (30 m)"},{en:"300 feet (90 m)",it:"300 piedi (90 m)"},{en:"500 feet (150 m)",it:"500 piedi (150 m)"},{en:"1,000 feet (300 m)",it:"1.000 piedi (300 m)"}],correct:2,explain_en:"You may not follow a fire truck or other emergency vehicle with active lights/siren closer than 500 feet.",explain_it:"Non puoi seguire un'autopompa o altro veicolo di emergenza con luci/sirena attive a meno di 500 piedi (150 m)."},
  {cat:"laws",en:"When parked facing downhill with a curb, turn your front wheels:",it:"Quando parcheggi in discesa con marciapiede, gira le ruote anteriori:",options:[{en:"Away from the curb (left)",it:"Lontano dal marciapiede (a sinistra)"},{en:"Toward the curb (right)",it:"Verso il marciapiede (a destra)"},{en:"Straight \u2014 wheels straight is safest",it:"Dritte \u2014 le ruote dritte sono le pi\u00f9 sicure"},{en:"It does not matter",it:"Non importa"}],correct:1,explain_en:"Facing downhill with a curb: turn wheels toward the curb (right). If brakes fail, the curb stops the car from rolling into traffic.",explain_it:"In discesa con marciapiede: girare le ruote verso il marciapiede (destra). Se i freni cedono, il marciapiede blocca l'auto prima che entri nel traffico."},
  {cat:"laws",en:"When parked facing uphill with a curb, turn your front wheels:",it:"Quando parcheggi in salita con marciapiede, gira le ruote anteriori:",options:[{en:"Toward the curb (right)",it:"Verso il marciapiede (a destra)"},{en:"Away from the curb (left)",it:"Lontano dal marciapiede (a sinistra)"},{en:"Straight ahead",it:"Dritte"},{en:"It does not matter",it:"Non importa"}],correct:1,explain_en:"Facing uphill with a curb: turn wheels away from the curb (left). If brakes fail, the car rolls back and the curb stops it.",explain_it:"In salita con marciapiede: girare le ruote lontano dal marciapiede (sinistra). Se i freni cedono, l'auto torna indietro e il marciapiede la blocca."},
  {cat:"laws",en:"When parked on a hill without a curb, your wheels should be turned:",it:"Quando parcheggi su una collina senza marciapiede, le ruote devono essere girate:",options:[{en:"Toward the road (left)",it:"Verso la strada (a sinistra)"},{en:"Away from the road toward the shoulder (right)",it:"Lontano dalla strada verso la corsia di emergenza (a destra)"},{en:"Straight ahead always",it:"Sempre dritte"},{en:"In the direction of traffic",it:"Nella direzione del traffico"}],correct:1,explain_en:"Without a curb: always turn wheels to the right (away from the road). If brakes fail, the car rolls off the road rather than into traffic.",explain_it:"Senza marciapiede: girare sempre le ruote a destra (lontano dalla strada). Se i freni cedono, l'auto esce dalla strada anzich\u00e9 entrare nel traffico."},
  {cat:"laws",en:"In Florida, a U-turn is illegal when:",it:"In Florida, un'inversione di marcia \u00e8 illegale quando:",options:[{en:"Only in school zones",it:"Solo nelle zone scolastiche"},{en:"Prohibited by a sign, on curves, hills, or where visibility or safety is insufficient",it:"Vietata da un segnale, in curva, in salita, o dove visibilit\u00e0 o sicurezza sono insufficienti"},{en:"Only on interstate highways",it:"Solo sulle autostrade interstatali"},{en:"After 10 PM",it:"Dopo le 22:00"}],correct:1,explain_en:"U-turns are illegal where prohibited by a sign, on curves or hills, or wherever visibility is insufficient to make the maneuver safely.",explain_it:"Le inversioni sono illegali dove vietate da un segnale, in curva o salita, o ovunque la visibilit\u00e0 non sia sufficiente per eseguire la manovra in sicurezza."},
  {cat:"laws",en:"In Florida, you must dim your high beams within how many feet of an oncoming vehicle?",it:"In Florida, devi abbassare gli abbaglianti entro quanti piedi da un veicolo in arrivo?",options:[{en:"200 feet (60 m)",it:"200 piedi (60 m)"},{en:"300 feet (90 m)",it:"300 piedi (90 m)"},{en:"500 feet (150 m)",it:"500 piedi (150 m)"},{en:"1,000 feet (300 m)",it:"1.000 piedi (300 m)"}],correct:2,explain_en:"Dim your high beams within 500 feet of an oncoming vehicle and within 300 feet of a vehicle you are following.",explain_it:"Abbassa gli abbaglianti entro 500 piedi (150 m) da un veicolo in arrivo e entro 300 piedi (90 m) da un veicolo che stai seguendo."},
  {cat:"laws",en:"A right turn on red in Florida is permitted:",it:"Una svolta a destra con il rosso in Florida \u00e8 consentita:",options:[{en:"Never",it:"Mai"},{en:"After a complete stop, yielding to all traffic and pedestrians, unless prohibited by a sign",it:"Dopo un arresto completo, cedendo la precedenza a traffico e pedoni, salvo segnale di divieto"},{en:"Only at intersections with a traffic light",it:"Solo agli incroci con semaforo"},{en:"Only when no pedestrians are present",it:"Solo quando non ci sono pedoni"}],correct:1,explain_en:"Right on red is generally allowed in Florida after a complete stop and yielding, unless a 'No Turn on Red' sign is posted.",explain_it:"La svolta a destra con il rosso \u00e8 generalmente consentita in Florida dopo un arresto completo e la cessione della precedenza, salvo segnale 'No Turn on Red'."},
  {cat:"laws",en:"In Florida, a left turn on red is ONLY permitted when:",it:"In Florida, una svolta a sinistra con il rosso \u00e8 consentita SOLO quando:",options:[{en:"No oncoming traffic is present",it:"Non c'\u00e8 traffico in senso contrario"},{en:"Turning from a one-way street onto another one-way street, after stopping and yielding",it:"Si svolta da una strada a senso unico su un'altra a senso unico, dopo essersi fermati e aver ceduto la precedenza"},{en:"The turn is protected by a green arrow",it:"La svolta \u00e8 protetta da una freccia verde"},{en:"It is always prohibited",it:"\u00c8 sempre vietata"}],correct:1,explain_en:"Left on red is only legal in Florida when turning from a one-way street onto another one-way street, after stopping and yielding to all traffic.",explain_it:"La svolta a sinistra con il rosso \u00e8 legale in Florida solo girando da una strada a senso unico su un'altra a senso unico, dopo essersi fermati e aver ceduto la precedenza."},
  {cat:"laws",en:"When must you report a crash to FLHSMV in writing?",it:"Quando devi segnalare un incidente al FLHSMV per iscritto?",options:[{en:"When damage exceeds $100",it:"Quando i danni superano $100"},{en:"When there are injuries, deaths, or property damage over $500 and police did not investigate",it:"Quando ci sono feriti, morti o danni materiali superiori a $500 e la polizia non ha investigato"},{en:"Only if you were at fault",it:"Solo se sei stato tu a causare l'incidente"},{en:"Only if 3 or more vehicles are involved",it:"Solo se sono coinvolti 3 o pi\u00f9 veicoli"}],correct:1,explain_en:"If police do not investigate a crash with injuries, fatalities, or $500+ in property damage, you must file a written report with FLHSMV within 10 days.",explain_it:"Se la polizia non investiga un incidente con feriti, morti o $500+ di danni materiali, devi presentare una relazione scritta al FLHSMV entro 10 giorni."},
  {cat:"laws",en:"Florida's 'Open Container' law prohibits:",it:"La legge sul 'contenitore aperto' della Florida vieta:",options:[{en:"Drinking only while the vehicle is moving",it:"Bere solo mentre il veicolo \u00e8 in movimento"},{en:"Having any open alcoholic beverage container anywhere in a vehicle on a public roadway",it:"Avere qualsiasi contenitore aperto di bevanda alcolica in qualsiasi punto del veicolo su una strada pubblica"},{en:"Alcohol in the trunk",it:"L'alcol nel bagagliaio"},{en:"Only the driver having an open container",it:"Solo il conducente avere un contenitore aperto"}],correct:1,explain_en:"Florida's open container law prohibits any open alcoholic beverage container anywhere inside the vehicle (including back seat and cup holders) on a public road.",explain_it:"La legge della Florida sui contenitori aperti vieta qualsiasi contenitore aperto di bevanda alcolica in qualsiasi punto del veicolo (inclusi sedile posteriore e portabicchieri) su una strada pubblica."},
  {cat:"laws",en:"In Florida, manually texting or reading messages while driving is:",it:"In Florida, inviare o leggere messaggi manualmente durante la guida \u00e8:",options:[{en:"Legal at red lights",it:"Legale ai semafori rossi"},{en:"A primary offense \u2014 police can stop you for this alone",it:"Un reato primario \u2014 la polizia pu\u00f2 fermarti solo per questo"},{en:"Only prohibited for drivers under 18",it:"Vietato solo per i conducenti under 18"},{en:"A secondary offense \u2014 only ticketed with another violation",it:"Un reato secondario \u2014 multato solo con un'altra violazione"}],correct:1,explain_en:"Florida's texting-while-driving law is a primary offense \u2014 officers may stop and ticket you solely for texting. It applies at all times, including red lights.",explain_it:"La legge della Florida sulla guida con messaggi \u00e8 un reato primario \u2014 gli agenti possono fermarti e multarti esclusivamente per i messaggi. Si applica in qualsiasi momento, inclusi i semafori rossi."},
  {cat:"laws",en:"When backing out of a driveway onto a street, you must yield to:",it:"Quando esci in retromarcia da un vialetto su una strada, devi cedere la precedenza a:",options:[{en:"Nothing \u2014 backing drivers have priority",it:"Niente \u2014 i conducenti in retromarcia hanno la priorit\u00e0"},{en:"All approaching traffic and pedestrians",it:"Tutto il traffico in arrivo e ai pedoni"},{en:"Only vehicles coming from the left",it:"Solo i veicoli proveniente da sinistra"},{en:"Only vehicles coming from the right",it:"Solo i veicoli provenienti da destra"}],correct:1,explain_en:"When backing out of a driveway, you must yield to all approaching vehicles from both directions and to pedestrians on the sidewalk.",explain_it:"Quando si esce in retromarcia da un vialetto, si deve cedere la precedenza a tutti i veicoli in arrivo da entrambe le direzioni e ai pedoni sul marciapiede."},
  {cat:"laws",en:"Passing on the right is legal in Florida when:",it:"Sorpassare a destra \u00e8 legale in Florida quando:",options:[{en:"You are in a hurry",it:"Sei di fretta"},{en:"The vehicle ahead is making a left turn and a paved right lane is available, or on a one-way street",it:"Il veicolo davanti sta svoltando a sinistra e c'\u00e8 una corsia destra asfaltata, o su strade a senso unico"},{en:"Only on roads with 3 or more lanes",it:"Solo su strade con 3 o pi\u00f9 corsie"},{en:"Only when the speed limit is above 45 mph",it:"Solo quando il limite \u00e8 superiore a 45 mph"}],correct:1,explain_en:"Passing on the right is legal when the vehicle ahead is turning left and a usable right lane exists, or when traveling on a one-way street with multiple lanes.",explain_it:"Sorpassare a destra \u00e8 legale quando il veicolo davanti svolta a sinistra ed esiste una corsia destra utilizzabile, o su strade a senso unico con pi\u00f9 corsie."},
  {cat:"laws",en:"After passing a vehicle on a two-lane road, you should return to your lane when:",it:"Dopo aver sorpassato un veicolo su una strada a due corsie, dovresti rientrare quando:",options:[{en:"You are even with the passed vehicle",it:"Sei affiancato al veicolo sorpassato"},{en:"You can see the passed vehicle's headlights in your rearview mirror",it:"Puoi vedere i fari del veicolo sorpassato nel tuo specchietto retrovisore"},{en:"You have gained one car length ahead",it:"Hai guadagnato una lunghezza auto davanti"},{en:"Immediately after the pass is complete",it:"Immediatamente dopo che il sorpasso \u00e8 completato"}],correct:1,explain_en:"Return to your lane only when you can see the passed vehicle's headlights in your rearview mirror \u2014 ensuring enough clearance.",explain_it:"Rientra nella tua corsia solo quando puoi vedere i fari del veicolo sorpassato nel retrovisore \u2014 assicurando una distanza sufficiente."},
  {cat:"laws",en:"Florida's 'Implied Consent' law means:",it:"La legge del 'consenso implicito' della Florida significa:",options:[{en:"You agree to speed checks on state highways",it:"Accetti i controlli di velocit\u00e0 sulle strade statali"},{en:"By driving in Florida you automatically consent to chemical testing if lawfully arrested for DUI",it:"Guidando in Florida acconsenti automaticamente al test chimico se arrestato legalmente per DUI"},{en:"Police can search your car without cause",it:"La polizia pu\u00f2 perquisire la tua auto senza causa"},{en:"You waive the right to a jury trial for traffic violations",it:"Rinunci al diritto a un processo con giuria per le infrazioni stradali"}],correct:1,explain_en:"Implied Consent: operating a vehicle in Florida means you automatically consent to a chemical test (breath, blood, or urine) if lawfully arrested for DUI.",explain_it:"Consenso implicito: guidare in Florida significa che acconsenti automaticamente a un test chimico (respiro, sangue o urine) se arrestato legalmente per DUI."},
  {cat:"laws",en:"You must yield to a blind pedestrian who is using a white cane or guide dog:",it:"Devi cedere la precedenza a un pedone non vedente che usa un bastone bianco o cane guida:",options:[{en:"Only at signalized crosswalks",it:"Solo ai passaggi pedonali semaforizzati"},{en:"At any crosswalk or intersection, regardless of signals",it:"A qualsiasi passaggio pedonale o incrocio, indipendentemente dai segnali"},{en:"Only during school hours",it:"Solo durante le ore scolastiche"},{en:"Only if they look directly at you",it:"Solo se ti guardano direttamente"}],correct:1,explain_en:"Florida law requires ALL drivers to stop and yield to visually impaired pedestrians using a white cane or guide dog at any crosswalk or intersection.",explain_it:"La legge della Florida richiede a TUTTI i conducenti di fermarsi e cedere la precedenza ai pedoni non vedenti con bastone bianco o cane guida a qualsiasi passaggio pedonale o incrocio."},
  {cat:"laws",en:"How far from a stop sign are you prohibited from parking?",it:"A quanti piedi da un segnale di stop \u00e8 vietato parcheggiare?",options:[{en:"10 feet (3 m)",it:"10 piedi (3 m)"},{en:"20 feet (6 m)",it:"20 piedi (6 m)"},{en:"30 feet (9 m)",it:"30 piedi (9 m)"},{en:"50 feet (15 m)",it:"50 piedi (15 m)"}],correct:2,explain_en:"You may not park within 30 feet of a stop sign. This keeps the sign visible to approaching drivers.",explain_it:"Non puoi parcheggiare entro 30 piedi (9 m) da un segnale di stop. Questo mantiene il segnale visibile ai conducenti in avvicinamento."},
  {cat:"laws",en:"Florida law defines 'careless driving' as:",it:"La legge della Florida definisce la 'guida negligente' come:",options:[{en:"The same as reckless driving",it:"Uguale alla guida spericolata"},{en:"Driving without due care and circumspection, creating a hazard to others",it:"Guidare senza la dovuta cura e circospezione, creando un pericolo per gli altri"},{en:"Any moving violation in a school zone",it:"Qualsiasi violazione in movimento in una zona scolastica"},{en:"Exceeding the speed limit by less than 5 mph",it:"Superare il limite di velocit\u00e0 di meno di 5 mph"}],correct:1,explain_en:"Careless driving is a civil (non-criminal) moving violation \u2014 driving without due care, creating a potential hazard. Reckless driving is a criminal offense requiring willful disregard.",explain_it:"La guida negligente \u00e8 un'infrazione in movimento civile (non penale) \u2014 guidare senza la dovuta cura, creando un pericolo potenziale. La guida spericolata \u00e8 un reato penale che richiede deliberata noncuranza."},
  {cat:"laws",en:"When passing a solid yellow line on YOUR side of the road, you may:",it:"Quando c'\u00e8 una linea gialla continua sul TUO lato della strada, puoi:",options:[{en:"Pass if the road ahead is clear",it:"Sorpassare se la strada davanti \u00e8 libera"},{en:"Not pass \u2014 the solid line on your side prohibits passing",it:"Non sorpassare \u2014 la linea continua sul tuo lato vieta il sorpasso"},{en:"Pass only slow vehicles (under 25 mph)",it:"Sorpassare solo veicoli lenti (sotto i 25 mph)"},{en:"Pass only during daylight hours",it:"Sorpassare solo durante le ore diurne"}],correct:1,explain_en:"A solid yellow line on your side of the road prohibits passing. A broken yellow on your side means passing is permitted when safe.",explain_it:"Una linea gialla continua sul tuo lato vieta il sorpasso. Una gialla tratteggiata sul tuo lato significa che il sorpasso \u00e8 consentito quando sicuro."},
  {cat:"laws",en:"When can a vehicle legally drive in a bicycle lane?",it:"Quando un veicolo pu\u00f2 legalmente circolare in una pista ciclabile?",options:[{en:"Never",it:"Mai"},{en:"Only when preparing to turn right \u2014 temporarily, for up to 200 feet",it:"Solo quando ci si prepara a svoltare a destra \u2014 temporaneamente, per un massimo di 60 m"},{en:"When traffic is heavy and the lane is empty",it:"Quando il traffico \u00e8 intenso e la corsia \u00e8 vuota"},{en:"Only motorcycles may use bicycle lanes",it:"Solo le motociclette possono usare le piste ciclabili"}],correct:1,explain_en:"In Florida, motor vehicles may enter a bicycle lane only when preparing to turn right, and only within the last 200 feet before the turn.",explain_it:"In Florida, i veicoli a motore possono entrare in una pista ciclabile solo quando si preparano a svoltare a destra, e solo negli ultimi 60 m prima della svolta."},
  {cat:"laws",en:"In Florida, if you miss your highway exit you should:",it:"In Florida, se perdi la tua uscita autostradale dovresti:",options:[{en:"Reverse on the shoulder to reach the exit",it:"Fare retromarcia sulla corsia di emergenza per raggiungere l'uscita"},{en:"Continue to the next exit and turn around safely",it:"Continuare fino alla prossima uscita e tornare indietro in sicurezza"},{en:"Make a U-turn on the highway",it:"Fare un'inversione sull'autostrada"},{en:"Drive through the gore area between the exit ramp and highway",it:"Attraversare l'area di gore tra la rampa di uscita e l'autostrada"}],correct:1,explain_en:"Never reverse or U-turn on a highway. Continue to the next exit and turn around. Reversing or U-turning on a highway is extremely dangerous and illegal.",explain_it:"Non fare mai retromarcia o inversioni sull'autostrada. Continua fino alla prossima uscita e torna indietro. Fare retromarcia o inversioni \u00e8 estremamente pericoloso e illegale."},
  {cat:"safety",en:"To avoid drowsy driving, the best approach is to:",it:"Per evitare la guida sonnolenta, il miglior approccio \u00e8:",options:[{en:"Drink coffee or energy drinks",it:"Bere caff\u00e8 o bevande energetiche"},{en:"Turn up the radio and open windows",it:"Alzare la radio e aprire i finestrini"},{en:"Pull off safely and rest or sleep",it:"Accostare in sicurezza e riposarsi o dormire"},{en:"Drive faster to get to your destination sooner",it:"Guidare pi\u00f9 veloce per arrivare prima a destinazione"}],correct:2,explain_en:"The only real cure for drowsy driving is stopping and resting. Coffee and other stimulants temporarily mask fatigue but do not restore full alertness.",explain_it:"L'unico vero rimedio alla guida sonnolenta \u00e8 fermarsi e riposarsi. Il caff\u00e8 e altri stimolanti mascherano temporaneamente la stanchezza ma non ripristinano la piena vigilanza."},
  {cat:"safety",en:"At highway speeds the safe following distance increases to at least:",it:"Ad alta velocit\u00e0, la distanza di sicurezza aumenta ad almeno:",options:[{en:"1 second",it:"1 secondo"},{en:"2 seconds",it:"2 secondi"},{en:"4 to 6 seconds",it:"4-6 secondi"},{en:"The same 3-second rule applies always",it:"Si applica sempre la stessa regola dei 3 secondi"}],correct:2,explain_en:"At highway speeds or in poor conditions (rain, fog, night), increase your following distance to 4\u20136 seconds to allow adequate stopping time.",explain_it:"Ad alta velocit\u00e0 o in condizioni avverse (pioggia, nebbia, notte), aumenta la distanza a 4-6 secondi per avere tempo di frenata adeguato."},
  {cat:"safety",en:"In heavy fog or rain you should use:",it:"In caso di nebbia fitta o pioggia intensa dovresti usare:",options:[{en:"High-beam headlights for maximum visibility",it:"Abbaglianti per la massima visibilit\u00e0"},{en:"Low-beam headlights or fog lights",it:"Anabbaglianti o fendinebbia"},{en:"Hazard lights only",it:"Solo luci di pericolo"},{en:"No lights \u2014 visibility is already poor",it:"Nessuna luce \u2014 la visibilit\u00e0 \u00e8 gi\u00e0 scarsa"}],correct:1,explain_en:"In fog or heavy rain, use low beams or fog lights. High beams reflect off water droplets and create glare that reduces visibility further.",explain_it:"In nebbia o pioggia intensa, usa anabbaglianti o fendinebbia. Gli abbaglianti si riflettono sulle goccioline d'acqua e creano un riverbero che riduce ulteriormente la visibilit\u00e0."},
  {cat:"safety",en:"Hydroplaning occurs when:",it:"L'acquaplaning (hydroplaning) si verifica quando:",options:[{en:"You brake too hard and lock the wheels",it:"Freni troppo bruscamente e blocchi le ruote"},{en:"A water layer forms between tires and pavement, causing loss of traction",it:"Uno strato d'acqua si forma tra pneumatici e asfalto, causando perdita di trazione"},{en:"Your engine overheats in hot weather",it:"Il motore si surriscalda con il caldo"},{en:"Your windshield fogs up in rain",it:"Il parabrezza si appanna con la pioggia"}],correct:1,explain_en:"Hydroplaning happens when a layer of water builds between tires and the road, causing the vehicle to 'float' and lose steering/braking control. Reduce speed in wet conditions.",explain_it:"L'aquaplaning avviene quando uno strato d'acqua si accumula tra pneumatici e asfalto, causando la 'galleggiamento' del veicolo e la perdita del controllo. Ridurre la velocit\u00e0."},
  {cat:"safety",en:"If your vehicle begins to hydroplane, you should:",it:"Se il tuo veicolo inizia ad avere aquaplaning, dovresti:",options:[{en:"Brake hard to regain traction",it:"Frenare bruscamente per recuperare la trazione"},{en:"Ease off the gas and steer straight until traction returns",it:"Togliere il piede dal gas e sterzare dritto finch\u00e9 la trazione non torna"},{en:"Sharply turn the wheel in the direction of the skid",it:"Girare bruscamente il volante nella direzione dello slittamento"},{en:"Accelerate slightly to regain grip",it:"Accelerare leggermente per recuperare l'aderenza"}],correct:1,explain_en:"In hydroplaning: ease off the gas, steer straight, and avoid sharp braking or sudden turns until the tires regain contact with the road.",explain_it:"In caso di aquaplaning: togliere il piede dal gas, sterzare dritto ed evitare frenate brusche o svolte improvvise finch\u00e9 i pneumatici non riprendono contatto con la strada."},
  {cat:"safety",en:"If your car starts to skid, you should:",it:"Se l'auto inizia a slittare, dovresti:",options:[{en:"Slam on the brakes immediately",it:"Frenare immediatamente e bruscamente"},{en:"Steer in the direction you want the front of the car to go and ease off the gas",it:"Sterzare nella direzione in cui vuoi che vada la parte anteriore dell'auto e togliere il gas"},{en:"Turn the wheel sharply in the opposite direction of the skid",it:"Girare bruscamente il volante nella direzione opposta allo slittamento"},{en:"Accelerate to power out of the skid",it:"Accelerare per uscire dallo slittamento"}],correct:1,explain_en:"In a skid: steer INTO the skid (toward where you want the front to go) and gently ease off the accelerator. Avoid sharp braking, which worsens the skid.",explain_it:"In caso di slittamento: sterza VERSO lo slittamento (nella direzione in cui vuoi che vada la parte anteriore) e togli delicatamente il gas. Evita frenate brusche."},
  {cat:"safety",en:"The most effective safety device in any vehicle is:",it:"Il dispositivo di sicurezza pi\u00f9 efficace in qualsiasi veicolo \u00e8:",options:[{en:"The airbag",it:"L'airbag"},{en:"Anti-lock brakes (ABS)",it:"I freni ABS"},{en:"The seat belt",it:"La cintura di sicurezza"},{en:"Electronic stability control",it:"Il controllo elettronico della stabilit\u00e0"}],correct:2,explain_en:"The seat belt is the single most effective life-saving device in a vehicle. It prevents ejection and reduces crash injury severity by up to 50%.",explain_it:"La cintura di sicurezza \u00e8 il dispositivo salva-vita pi\u00f9 efficace in un veicolo. Previene l'espulsione e riduce la gravit\u00e0 delle lesioni fino al 50%."},
  {cat:"safety",en:"What should you do when an emergency vehicle with siren and lights approaches from behind?",it:"Cosa dovresti fare quando un veicolo di emergenza con sirena e luci si avvicina da dietro?",options:[{en:"Speed up to get out of its way",it:"Accelerare per togliersi di mezzo"},{en:"Pull to the right edge of the road and stop",it:"Accostare al bordo destro della strada e fermarsi"},{en:"Stay in your lane and reduce speed",it:"Rimanere nella corsia e ridurre la velocit\u00e0"},{en:"Move to the center lane",it:"Spostarsi alla corsia centrale"}],correct:1,explain_en:"Pull to the right edge of the road and stop. Stay stopped until the emergency vehicle has passed. Never block an intersection.",explain_it:"Accostare al bordo destro della strada e fermarsi. Rimanere fermi fino a quando il veicolo di emergenza \u00e8 passato. Non bloccare mai un incrocio."},
  {cat:"safety",en:"Before backing your vehicle, you should:",it:"Prima di fare retromarcia, dovresti:",options:[{en:"Check only the rearview mirror",it:"Controllare solo lo specchietto retrovisore"},{en:"Check all mirrors and look over both shoulders",it:"Controllare tutti gli specchi e guardare oltre entrambe le spalle"},{en:"Sound the horn twice",it:"Suonare il clacson due volte"},{en:"Turn on your hazard lights",it:"Accendere le luci di pericolo"}],correct:1,explain_en:"Always check all mirrors AND look over both shoulders before reversing. Mirrors have blind spots \u2014 a physical check catches what mirrors miss.",explain_it:"Controlla sempre tutti gli specchi E guarda oltre entrambe le spalle prima di fare retromarcia. Gli specchi hanno punti ciechi \u2014 un controllo fisico coglie ci\u00f2 che gli specchi non vedono."},
  {cat:"safety",en:"Current recommended steering wheel hand position is:",it:"La posizione attuale raccomandata delle mani sul volante \u00e8:",options:[{en:"10 and 2 o'clock",it:"10 e 2 in punto"},{en:"9 and 3 o'clock",it:"9 e 3 in punto"},{en:"8 and 4 o'clock",it:"8 e 4 in punto"},{en:"One hand at 12 o'clock",it:"Una mano alle 12 in punto"}],correct:1,explain_en:"9 and 3 is now the recommended position for better vehicle control and improved safety if the airbag deploys (10-and-2 can cause arm/hand injuries with airbag deployment).",explain_it:"9 e 3 \u00e8 ora la posizione raccomandata per un migliore controllo del veicolo e maggiore sicurezza in caso di apertura dell'airbag (10 e 2 pu\u00f2 causare lesioni braccio/mano con l'airbag aperto)."},
  {cat:"safety",en:"How often should you check your mirrors while driving?",it:"Con quale frequenza dovresti controllare gli specchi durante la guida?",options:[{en:"Only when changing lanes",it:"Solo quando cambi corsia"},{en:"Every 5 to 8 seconds",it:"Ogni 5-8 secondi"},{en:"Only when stopping",it:"Solo quando ti fermi"},{en:"Once per minute is sufficient",it:"Una volta al minuto \u00e8 sufficiente"}],correct:1,explain_en:"You should check your mirrors every 5 to 8 seconds to maintain constant awareness of surrounding traffic conditions.",explain_it:"Dovresti controllare gli specchi ogni 5-8 secondi per mantenere una consapevolezza costante delle condizioni del traffico circostante."},
  {cat:"safety",en:"The three types of driver distraction are:",it:"I tre tipi di distrazione del conducente sono:",options:[{en:"Speed, fatigue, and alcohol",it:"Velocit\u00e0, stanchezza e alcol"},{en:"Visual, manual, and cognitive",it:"Visiva, manuale e cognitiva"},{en:"Texting, phone calls, and eating",it:"Messaggi, telefonate e cibo"},{en:"Radio, GPS, and passengers",it:"Radio, GPS e passeggeri"}],correct:1,explain_en:"The 3 types: Visual (eyes off road), Manual (hands off wheel), Cognitive (mind off driving). Texting is dangerous because it involves all three simultaneously.",explain_it:"I 3 tipi: Visiva (occhi fuori strada), Manuale (mani fuori dal volante), Cognitiva (mente fuori dalla guida). I messaggi sono pericolosi perch\u00e9 coinvolgono tutti e tre simultaneamente."},
  {cat:"safety",en:"What is the safest way to deal with a tailgating driver?",it:"Qual \u00e8 il modo pi\u00f9 sicuro di gestire un conducente che ti segue troppo vicino?",options:[{en:"Slam your brakes to warn them",it:"Frenare bruscamente per avvisarli"},{en:"Gradually slow and allow them to pass, or pull over safely",it:"Rallentare gradualmente e lasciarli passare, o accostare in sicurezza"},{en:"Speed up to increase the distance",it:"Accelerare per aumentare la distanza"},{en:"Use your brake lights to signal your irritation",it:"Usare le luci dei freni per segnalare la tua irritazione"}],correct:1,explain_en:"Responding to a tailgater safely means slowing gradually to encourage them to pass, or pulling over to let them by. Never brake-check a tailgater.",explain_it:"Rispondere in sicurezza a chi ti segue troppo vicino significa rallentare gradualmente per incoraggiarli a passare, o accostare per lasciarli passare. Non frenare bruscamente."},
  {cat:"safety",en:"What is 'defensive driving'?",it:"Cos'\u00e8 la 'guida difensiva'?",options:[{en:"Driving very slowly at all times to avoid all risks",it:"Guidare molto lentamente in ogni momento per evitare tutti i rischi"},{en:"Anticipating hazards and the actions of others to avoid collisions proactively",it:"Anticipare i pericoli e le azioni degli altri per evitare collisioni in modo proattivo"},{en:"Driving aggressively to control your space on the road",it:"Guidare in modo aggressivo per controllare il tuo spazio sulla strada"},{en:"Following all traffic laws strictly",it:"Seguire rigorosamente tutte le norme del traffico"}],correct:1,explain_en:"Defensive driving means proactively anticipating hazards, maintaining space, and managing your driving to avoid collisions \u2014 not just reacting to them.",explain_it:"La guida difensiva significa anticipare proattivamente i pericoli, mantenere lo spazio e gestire la guida per evitare collisioni \u2014 non solo reagire ad esse."},
  {cat:"safety",en:"How should you respond to an aggressive driver who is making threatening gestures?",it:"Come dovresti rispondere a un conducente aggressivo che fa gesti minacciosi?",options:[{en:"Match their aggression to show you are not intimidated",it:"Corrispondere alla loro aggressivit\u00e0 per dimostrare che non sei intimidito"},{en:"Avoid eye contact, don't respond, and create distance",it:"Evitare il contatto visivo, non rispondere e creare distanza"},{en:"Stop your car and confront them",it:"Fermare la macchina e affrontarli"},{en:"Honk your horn repeatedly",it:"Suonare ripetutamente il clacson"}],correct:1,explain_en:"When confronted by an aggressive driver: stay calm, avoid eye contact, do not respond to gestures or honking, and put as much distance between you as possible.",explain_it:"Quando affrontato da un conducente aggressivo: rimanere calmo, evitare il contatto visivo, non rispondere a gesti o clacson e mettere pi\u00f9 distanza possibile tra voi."},
  {cat:"safety",en:"When following a large truck, you should:",it:"Quando segui un camion grande, dovresti:",options:[{en:"Follow closely to draft and save fuel",it:"Seguire da vicino per sfruttare la scia e risparmiare carburante"},{en:"Increase following distance and avoid staying in the truck's blind spots",it:"Aumentare la distanza e evitare di restare nei punti ciechi del camion"},{en:"Pass quickly on the left at the first opportunity",it:"Superare rapidamente a sinistra alla prima occasione"},{en:"Honk before passing to alert the driver",it:"Suonare il clacson prima di sorpassare per avvisare il conducente"}],correct:1,explain_en:"Large trucks have massive blind spots (front, rear, and both sides). Increase your following distance and avoid lingering in the truck's blind zones.",explain_it:"I camion grandi hanno enormi punti ciechi (davanti, dietro e su entrambi i lati). Aumenta la distanza e evita di restare nelle zone cieche del camion."},
  {cat:"safety",en:"When sharing the road with motorcycles, you should:",it:"Quando condividi la strada con le motociclette, dovresti:",options:[{en:"Assume they can see you clearly",it:"Presupporre che ti vedano chiaramente"},{en:"Give them a full lane width and increase following distance",it:"Dargli l'intera larghezza della corsia e aumentare la distanza di sicurezza"},{en:"Pass them quickly \u2014 they are slower than cars",it:"Superarli rapidamente \u2014 sono pi\u00f9 lenti delle auto"},{en:"Sound your horn when approaching them from behind",it:"Suonare il clacson quando li si avvicina da dietro"}],correct:1,explain_en:"Motorcycles are entitled to a full lane. They are harder to see and can stop faster than expected. Give extra space and check mirrors/blind spots carefully.",explain_it:"Le motociclette hanno diritto all'intera larghezza della corsia. Sono pi\u00f9 difficili da vedere e possono fermarsi pi\u00f9 velocemente del previsto. Dai spazio extra e controlla attentamente specchi e punti ciechi."},
  {cat:"safety",en:"In a work zone, speed limit violations:",it:"Nelle zone di lavori stradali, le violazioni del limite di velocit\u00e0:",options:[{en:"Are treated the same as anywhere else",it:"Sono trattate come ovunque altro"},{en:"Result in doubled fines",it:"Comportano multe raddoppiate"},{en:"Are only enforced when workers are present",it:"Vengono applicate solo quando gli operai sono presenti"},{en:"Are ignored if below 10 mph over the limit",it:"Vengono ignorate se sotto i 10 mph oltre il limite"}],correct:1,explain_en:"Traffic fines are doubled in Florida work zones, whether workers are present or not. Always obey posted work zone speed limits.",explain_it:"Le multe stradali sono raddoppiate nelle zone di lavori in Florida, sia che gli operai siano presenti o meno. Rispettare sempre i limiti di velocit\u00e0 nelle zone di lavori."},
  {cat:"safety",en:"What does 'overdriving your headlights' mean?",it:"Cosa significa 'guidare oltre i propri fari' (overdriving)?",options:[{en:"Using high beams when low beams are required",it:"Usare gli abbaglianti quando sono richiesti gli anabbaglianti"},{en:"Driving at a speed where you cannot stop within the lit distance",it:"Guidare a una velocit\u00e0 in cui non riesci a fermarti entro la distanza illuminata"},{en:"Using your lights during the day unnecessarily",it:"Usare i fari di giorno inutilmente"},{en:"Driving with one headlight out",it:"Guidare con un faro guasto"}],correct:1,explain_en:"Overdriving headlights means going fast enough that your stopping distance exceeds the distance illuminated by your headlights \u2014 a dangerous situation at night.",explain_it:"Guidare oltre i propri fari significa andare abbastanza veloci da far s\u00ec che la distanza di frenata superi la distanza illuminata dai fari \u2014 situazione pericolosa di notte."},
  {cat:"safety",en:"When should you use hazard (emergency flasher) lights?",it:"Quando dovresti usare le luci di pericolo (emergenza)?",options:[{en:"Whenever driving slowly in traffic",it:"Ogni volta che guidi lentamente nel traffico"},{en:"When your vehicle is disabled, stopped, or is an unusual hazard to others",it:"Quando il tuo veicolo \u00e8 in panne, fermo o costituisce un pericolo insolito per gli altri"},{en:"When driving through rain",it:"Quando guidi sotto la pioggia"},{en:"When driving in a construction zone",it:"Quando guidi in una zona di lavori"}],correct:1,explain_en:"Hazard lights are for when your vehicle is stopped or disabled and poses a hazard. Using them while driving (except in some states' laws) can confuse other drivers.",explain_it:"Le luci di pericolo servono quando il veicolo \u00e8 fermo o in panne e costituisce un pericolo. Usarle mentre si guida pu\u00f2 confondere gli altri conducenti."},
  {cat:"safety",en:"The most dangerous time to drive in rain is:",it:"Il momento pi\u00f9 pericoloso per guidare sotto la pioggia \u00e8:",options:[{en:"During a heavy downpour",it:"Durante un forte acquazzone"},{en:"The first 10\u201315 minutes when oil and water mix on the road surface",it:"I primi 10-15 minuti quando olio e acqua si mescolano sulla superficie stradale"},{en:"After the rain has stopped",it:"Dopo che la pioggia ha smesso"},{en:"Only late at night in rain",it:"Solo tardi di notte con la pioggia"}],correct:1,explain_en:"When rain first starts, oil residue on the road mixes with water to create an extremely slippery surface. Roads become safer once rain washes the oil away.",explain_it:"Quando inizia a piovere, i residui di olio sulla strada si mescolano con l'acqua creando una superficie estremamente scivolosa. Le strade diventano pi\u00f9 sicure dopo che la pioggia lava via l'olio."},
  {cat:"safety",en:"If you have ABS (Anti-lock Brake System) brakes and need to stop quickly, you should:",it:"Se hai freni ABS e devi fermarti rapidamente, dovresti:",options:[{en:"Pump the brakes rapidly",it:"Pompare i freni rapidamente"},{en:"Apply firm, steady pressure \u2014 do NOT pump the pedal",it:"Applicare una pressione ferma e costante \u2014 NON pompare il pedale"},{en:"Press gently to avoid skidding",it:"Premere delicatamente per evitare lo slittamento"},{en:"Apply the parking brake together with foot brake",it:"Applicare il freno di parcheggio insieme al freno a pedale"}],correct:1,explain_en:"With ABS brakes: press firmly and HOLD \u2014 the system pulses automatically to prevent lock-up while maintaining steering control. Pumping the pedal defeats ABS.",explain_it:"Con i freni ABS: premi con fermezza e MANTIENI \u2014 il sistema pulsa automaticamente per prevenire il bloccaggio mantenendo il controllo dello sterzo. Pompare il pedale annulla l'ABS."},
  {cat:"safety",en:"What are rumble strips used for?",it:"A cosa servono le bande sonore (rumble strips)?",options:[{en:"To slow vehicles before intersections",it:"Per rallentare i veicoli prima degli incroci"},{en:"To alert drowsy or inattentive drivers drifting out of their lane",it:"Per avvisare i conducenti assonnati o disattenti che escono dalla loro corsia"},{en:"To provide traction on slippery roads",it:"Per fornire trazione su strade scivolose"},{en:"To mark bicycle lanes",it:"Per segnalare le piste ciclabili"}],correct:1,explain_en:"Rumble strips generate vibrations and noise when a vehicle's tires cross them, alerting inattentive or drowsy drivers before they drift off the road.",explain_it:"Le bande sonore generano vibrazioni e rumore quando i pneumatici le attraversano, avvisando i conducenti disattenti o assonnati prima che escano dalla strada."},
  {cat:"safety",en:"A 'space cushion' in driving means:",it:"Un 'cuscinetto di spazio' nella guida significa:",options:[{en:"The extra padding in your car seat",it:"L'imbottitura extra nel sedile della tua auto"},{en:"Open space maintained around your vehicle on all sides",it:"Spazio aperto mantenuto intorno al tuo veicolo su tutti i lati"},{en:"Distance between your car and the sidewalk when parking",it:"Distanza tra la tua auto e il marciapiede quando parcheggi"},{en:"Minimum distance from other cars when parking",it:"Distanza minima dalle altre auto quando parcheggi"}],correct:1,explain_en:"A space cushion is the open area you intentionally maintain around your vehicle in all directions. It gives you time and space to react to sudden hazards.",explain_it:"Un cuscinetto di spazio \u00e8 l'area aperta che mantieni intenzionalmente intorno al tuo veicolo in tutte le direzioni. Ti d\u00e0 tempo e spazio per reagire ai pericoli improvvisi."},
  {cat:"safety",en:"What is the effect of carbon monoxide on drivers?",it:"Qual \u00e8 l'effetto del monossido di carbonio sui conducenti?",options:[{en:"It improves alertness at low levels",it:"Migliora la vigilanza a bassi livelli"},{en:"It causes drowsiness, confusion, and can lead to unconsciousness or death",it:"Causa sonnolenza, confusione e pu\u00f2 portare a perdita di coscienza o morte"},{en:"It only affects people with pre-existing health conditions",it:"Colpisce solo persone con condizioni di salute preesistenti"},{en:"It has no effect unless levels are very high",it:"Non ha effetti a meno che i livelli siano molto alti"}],correct:1,explain_en:"Carbon monoxide is odorless and colorless. Even low concentrations can cause severe drowsiness and loss of consciousness. Ensure good ventilation and maintain your exhaust system.",explain_it:"Il monossido di carbonio \u00e8 inodore e incolore. Anche basse concentrazioni possono causare grave sonnolenza e perdita di coscienza. Assicurare buona ventilazione e mantenere il sistema di scarico."},
  {cat:"safety",en:"Night driving is more hazardous because:",it:"Guidare di notte \u00e8 pi\u00f9 pericoloso perch\u00e9:",options:[{en:"Traffic is always heavier at night",it:"Il traffico \u00e8 sempre pi\u00f9 intenso di notte"},{en:"Visibility is reduced and glare from oncoming lights impairs vision",it:"La visibilit\u00e0 \u00e8 ridotta e il riverbero dei fari in arrivo compromette la visione"},{en:"Speed limits are lower at night",it:"I limiti di velocit\u00e0 sono pi\u00f9 bassi di notte"},{en:"Animals are never on the road during the day",it:"Gli animali non sono mai sulla strada di giorno"}],correct:1,explain_en:"Night driving is more dangerous due to reduced visibility, glare from oncoming headlights, driver fatigue, and difficulty judging distance and speed.",explain_it:"Guidare di notte \u00e8 pi\u00f9 pericoloso a causa della visibilit\u00e0 ridotta, del riverbero dei fari in arrivo, della stanchezza del conducente e della difficolt\u00e0 nel giudicare distanza e velocit\u00e0."},
  {cat:"safety",en:"The leading cause of traffic crashes is:",it:"La principale causa degli incidenti stradali \u00e8:",options:[{en:"Poor weather",it:"Maltempo"},{en:"Mechanical failure",it:"Guasto meccanico"},{en:"Driver error or inattention",it:"Errore del conducente o disattenzione"},{en:"Aggressive driving by other drivers",it:"Guida aggressiva di altri conducenti"}],correct:2,explain_en:"Driver error or inattention (including distraction, speeding, drowsiness, and impairment) is the leading cause of traffic crashes.",explain_it:"L'errore del conducente o la disattenzione (incluse distrazione, eccesso di velocit\u00e0, sonnolenza e alterazione) \u00e8 la principale causa degli incidenti stradali."},
  {cat:"safety",en:"When backing out of a parking space, you should:",it:"Quando esci in retromarcia da un posto auto, dovresti:",options:[{en:"Back out quickly to avoid holding up traffic",it:"Uscire rapidamente per non bloccare il traffico"},{en:"Check mirrors and look in all directions before and while backing",it:"Controllare gli specchi e guardare in tutte le direzioni prima e durante la retromarcia"},{en:"Sound the horn to warn pedestrians",it:"Suonare il clacson per avvisare i pedoni"},{en:"Only check to the left side",it:"Controllare solo il lato sinistro"}],correct:1,explain_en:"When reversing from a parking space, check all mirrors and look in all directions including over both shoulders to check for pedestrians, cyclists, and other vehicles.",explain_it:"Uscendo in retromarcia da un parcheggio, controlla tutti gli specchi e guarda in tutte le direzioni, incluso oltre entrambe le spalle, per pedoni, ciclisti e altri veicoli."},
  {cat:"safety",en:"Scanning far ahead while driving helps you:",it:"Scansionare lontano davanti durante la guida ti aiuta a:",options:[{en:"Drive faster safely",it:"Guidare pi\u00f9 velocemente in sicurezza"},{en:"Identify hazards early and have more time to react",it:"Identificare i pericoli in anticipo e avere pi\u00f9 tempo per reagire"},{en:"Reduce fuel consumption",it:"Ridurre il consumo di carburante"},{en:"Avoid using your mirrors",it:"Evitare di usare gli specchi"}],correct:1,explain_en:"Scanning 12\u201315 seconds ahead gives you early warning of hazards, allowing you to adjust speed, change lanes, or take other actions before a crisis develops.",explain_it:"Scansionare 12-15 secondi in avanti ti d\u00e0 un avviso precoce dei pericoli, consentendoti di regolare la velocit\u00e0, cambiare corsia o intraprendere altre azioni prima che si sviluppi una crisi."},
  {cat:"safety",en:"What should you do if a tire blows out while driving at highway speed?",it:"Cosa dovresti fare se uno pneumatico si buca durante la guida ad alta velocit\u00e0?",options:[{en:"Brake hard and pull to the right immediately",it:"Frenare bruscamente e spostarsi a destra immediatamente"},{en:"Grip the wheel firmly, ease off the gas, steer straight, and slow gradually",it:"Stringere saldamente il volante, togliere il gas, sterzare dritto e rallentare gradualmente"},{en:"Shift to reverse briefly to slow down",it:"Mettere brevemente la retromarcia per rallentare"},{en:"Steer immediately toward the nearest lane",it:"Sterzare immediatamente verso la corsia pi\u00f9 vicina"}],correct:1,explain_en:"In a blowout: grip the steering wheel firmly, ease off the gas gradually, steer straight, and slow down gently before pulling off the road. Do not brake sharply.",explain_it:"In caso di scoppio: stringi saldamente il volante, togli gradualmente il gas, sterza dritto e rallenta delicatamente prima di accostare. Non frenare bruscamente."},
  {cat:"safety",en:"When driving, you should use your horn:",it:"Durante la guida, dovresti usare il clacson:",options:[{en:"To signal frustration at other drivers",it:"Per segnalare frustrazione verso altri conducenti"},{en:"To warn others of hazards or your presence in dangerous situations",it:"Per avvisare gli altri di pericoli o della tua presenza in situazioni pericolose"},{en:"Whenever you approach an intersection",it:"Ogni volta che ti avvicini a un incrocio"},{en:"To signal pedestrians on the crosswalk to hurry",it:"Per segnalare ai pedoni sul passaggio pedonale di affrettarsi"}],correct:1,explain_en:"The horn is a safety device \u2014 use it to warn others of danger or your presence. Never use it to express anger, frustration, or to rush pedestrians.",explain_it:"Il clacson \u00e8 un dispositivo di sicurezza \u2014 usalo per avvisare gli altri di un pericolo o della tua presenza. Non usarlo mai per esprimere rabbia, frustrazione o per affrettare i pedoni."},
  {cat:"safety",en:"What is the danger of driving in a large truck's blind spot?",it:"Qual \u00e8 il pericolo di guidare nel punto cieco di un camion grande?",options:[{en:"Your radio reception is worse",it:"La ricezione radio \u00e8 peggiore"},{en:"The truck driver cannot see you and may merge or change lanes into you",it:"Il camionista non riesce a vederti e potrebbe spostare nella tua direzione"},{en:"Wind turbulence can blow you off the road",it:"Le turbolenze del vento possono spingerti fuori strada"},{en:"There is no real danger",it:"Non c'\u00e8 un vero pericolo"}],correct:1,explain_en:"Large trucks have massive blind spots on all four sides. If you can't see the truck driver's mirrors, they can't see you \u2014 and may merge or change lanes into your path.",explain_it:"I camion grandi hanno enormi punti ciechi su tutti e quattro i lati. Se non puoi vedere gli specchi del camionista, loro non possono vedere te \u2014 e potrebbero spostarsi nel tuo percorso."},
  {cat:"safety",en:"If a vehicle behind keeps its high beams on, you should:",it:"Se un veicolo dietro mantiene gli abbaglianti accesi, dovresti:",options:[{en:"Turn on your own high beams in retaliation",it:"Accendere i tuoi abbaglianti in risposta"},{en:"Use the night-position of your rearview mirror or adjust it to reduce glare",it:"Usare la posizione notturna del retrovisore o regolarlo per ridurre il riverbero"},{en:"Brake suddenly to warn them",it:"Frenare bruscamente per avvisarli"},{en:"Speed up to get away from them",it:"Accelerare per allontanarti da loro"}],correct:1,explain_en:"Adjust your interior mirror to its night position (anti-glare) to reduce blinding glare from the vehicle behind. Do not retaliate with your own high beams.",explain_it:"Regola il retrovisore interno in posizione notturna (anti-riverbero) per ridurre il riverbero accecante dal veicolo dietro. Non rispondere con i tuoi abbaglianti."},
  {cat:"alcohol",en:"The legal Blood Alcohol Content (BAC) limit for drivers 21+ in Florida is:",it:"Il limite legale di tasso alcolemico (BAC) per conducenti di 21+ anni in Florida \u00e8:",options:[{en:"0.05%",it:"0,05%"},{en:"0.08%",it:"0,08%"},{en:"0.10%",it:"0,10%"},{en:"0.12%",it:"0,12%"}],correct:1,explain_en:"The legal BAC limit for drivers 21+ in Florida (and all U.S. states) is 0.08%. At or above this level you are presumed to be impaired.",explain_it:"Il limite legale di BAC per conducenti di 21+ anni in Florida (e in tutti gli stati USA) \u00e8 0,08%. A questo livello o superiore sei presunto compromesso."},
  {cat:"alcohol",en:"Florida's Zero Tolerance Law sets the BAC limit for drivers under 21 at:",it:"La legge Zero Tolerance della Florida fissa il limite di BAC per conducenti under 21 a:",options:[{en:"0.00% \u2014 any measurable amount triggers consequences",it:"0,00% \u2014 qualsiasi quantit\u00e0 misurabile scatena conseguenze"},{en:"0.02%",it:"0,02%"},{en:"0.05%",it:"0,05%"},{en:"0.08% \u2014 same as adults",it:"0,08% \u2014 come gli adulti"}],correct:1,explain_en:"Florida's Zero Tolerance Law: any measurable BAC (0.02% or higher) for a driver under 21 results in license suspension. The practical limit is 0.02% due to measurement thresholds.",explain_it:"Legge Zero Tolerance della Florida: qualsiasi BAC misurabile (0,02% o superiore) per un conducente under 21 comporta la sospensione della patente."},
  {cat:"alcohol",en:"Refusing a breath test when lawfully arrested for DUI in Florida results in:",it:"Rifiutare un test del respiro quando si \u00e8 arrestati per DUI in Florida comporta:",options:[{en:"No penalty if found not guilty of DUI",it:"Nessuna penalit\u00e0 se si viene ritenuti non colpevoli di DUI"},{en:"Automatic 1-year license suspension for first refusal",it:"Sospensione automatica della patente di 1 anno per il primo rifiuto"},{en:"Only a fine \u2014 no license action",it:"Solo una multa \u2014 nessuna azione sulla patente"},{en:"Immediate arrest for obstruction",it:"Arresto immediato per ostruzione"}],correct:1,explain_en:"Florida Implied Consent: refusing a chemical test = automatic 1-year suspension for first refusal, 18 months for second refusal. Refusal may also be used against you in court.",explain_it:"Consenso implicito in Florida: rifiutare un test chimico = sospensione automatica di 1 anno per il primo rifiuto, 18 mesi per il secondo. Il rifiuto pu\u00f2 anche essere usato contro di te in tribunale."},
  {cat:"alcohol",en:"Which of these methods can effectively sober you up faster?",it:"Quale di questi metodi pu\u00f2 farti smaltire l'alcol pi\u00f9 velocemente?",options:[{en:"Drinking coffee",it:"Bere caff\u00e8"},{en:"Cold shower and fresh air",it:"Doccia fredda e aria fresca"},{en:"Exercise \u2014 walking or jogging",it:"Esercizio fisico \u2014 camminare o fare jogging"},{en:"None \u2014 only time eliminates alcohol from the body",it:"Nessuno \u2014 solo il tempo elimina l'alcol dal corpo"}],correct:3,explain_en:"Only time eliminates alcohol. The liver processes approximately one standard drink per hour, and nothing speeds this up. Coffee makes you alert but still impaired.",explain_it:"Solo il tempo elimina l'alcol. Il fegato elabora circa un drink standard all'ora, e nulla accelera questo processo. Il caff\u00e8 ti rende vigile ma ancora compromesso."},
  {cat:"alcohol",en:"Penalties for a first DUI conviction in Florida include:",it:"Le sanzioni per una prima condanna DUI in Florida includono:",options:[{en:"A written warning and community service only",it:"Solo un avvertimento scritto e servizio alla comunit\u00e0"},{en:"Fines up to $2,000, possible jail time, license revocation, and community service",it:"Multe fino a $2.000, possibile carcere, revoca della patente e servizio alla comunit\u00e0"},{en:"Only a fine of $500",it:"Solo una multa di $500"},{en:"Permanent license revocation",it:"Revoca permanente della patente"}],correct:1,explain_en:"First DUI in FL: fines $500\u2013$2,000, up to 6 months jail, license revocation up to 1 year, 50 hours of community service, and probation up to 1 year.",explain_it:"Primo DUI in Florida: multe $500-$2.000, fino a 6 mesi di carcere, revoca della patente fino a 1 anno, 50 ore di servizio alla comunit\u00e0, libert\u00e0 vigilata fino a 1 anno."},
  {cat:"alcohol",en:"A third DUI conviction in Florida within 10 years is classified as:",it:"Una terza condanna DUI in Florida entro 10 anni \u00e8 classificata come:",options:[{en:"A misdemeanor \u2014 same as first offense",it:"Un'infrazione minore \u2014 come la prima"},{en:"A third-degree felony",it:"Un crimine di terzo grado"},{en:"A civil violation only",it:"Solo una violazione civile"},{en:"An infraction requiring only a fine",it:"Un'infrazione che richiede solo una multa"}],correct:1,explain_en:"A third DUI within 10 years in Florida is a third-degree felony, with fines up to $5,000 and up to 5 years in prison.",explain_it:"Un terzo DUI entro 10 anni in Florida \u00e8 un crimine di terzo grado, con multe fino a $5.000 e fino a 5 anni di prigione."},
  {cat:"alcohol",en:"Alcohol first affects a driver's:",it:"L'alcol colpisce per prima la/il:",options:[{en:"Physical strength",it:"Forza fisica"},{en:"Judgment and decision-making ability",it:"Giudizio e capacit\u00e0 decisionale"},{en:"Muscle coordination",it:"Coordinazione muscolare"},{en:"Vision only",it:"Solo la visione"}],correct:1,explain_en:"Alcohol impairs judgment first \u2014 even before it affects physical coordination. Drivers may feel fine but are already making dangerous decisions.",explain_it:"L'alcol compromette prima il giudizio \u2014 anche prima di influenzare la coordinazione fisica. I conducenti possono sentirsi bene ma stanno gi\u00e0 prendendo decisioni pericolose."},
  {cat:"alcohol",en:"Which factor DOES affect how alcohol impacts a person?",it:"Quale fattore influenza DAVVERO come l'alcol colpisce una persona?",options:[{en:"The type of glass used to drink",it:"Il tipo di bicchiere usato per bere"},{en:"The person's body weight and whether they have eaten",it:"Il peso corporeo della persona e se ha mangiato"},{en:"The color of the alcoholic beverage",it:"Il colore della bevanda alcolica"},{en:"Whether you drink sitting or standing",it:"Se bevi seduto o in piedi"}],correct:1,explain_en:"Body weight, food intake, gender, and metabolism all affect how alcohol impacts a person. A lighter person eating on an empty stomach reaches higher BAC faster.",explain_it:"Peso corporeo, cibo ingerito, genere e metabolismo influenzano come l'alcol colpisce una persona. Una persona pi\u00f9 leggera a stomaco vuoto raggiunge un BAC pi\u00f9 alto pi\u00f9 velocemente."},
  {cat:"alcohol",en:"No one can drink alcohol and drive safely \u2014 this statement is:",it:"Nessuno pu\u00f2 bere alcolici e guidare in sicurezza \u2014 questa affermazione \u00e8:",options:[{en:"False \u2014 experienced drivers handle alcohol better",it:"Falsa \u2014 i conducenti esperti gestiscono meglio l'alcol"},{en:"True \u2014 alcohol affects everyone's driving regardless of experience",it:"Vera \u2014 l'alcol influenza la guida di tutti indipendentemente dall'esperienza"},{en:"True only for inexperienced drivers",it:"Vera solo per i conducenti inesperti"},{en:"False \u2014 only illegal amounts affect driving",it:"Falsa \u2014 solo le quantit\u00e0 illegali influenzano la guida"}],correct:1,explain_en:"The Florida Driver Handbook states: 'No one can drink alcohol and drive safely.' Any amount of alcohol affects driving ability, even amounts below the legal limit.",explain_it:"Il manuale del conducente della Florida afferma: 'Nessuno pu\u00f2 bere alcolici e guidare in sicurezza.' Qualsiasi quantit\u00e0 di alcol influenza la capacit\u00e0 di guida, anche sotto il limite legale."},
  {cat:"alcohol",en:"Florida law requires ignition interlock devices for:",it:"La legge della Florida richiede dispositivi interlock per l'accensione per:",options:[{en:"All first-time DUI offenders",it:"Tutti i trasgressori DUI alla prima offesa"},{en:"Second or subsequent DUI offenders, and first offenders with BAC 0.15%+ or a minor in vehicle",it:"Trasgressori DUI alla seconda o successiva offesa, e alla prima offesa con BAC 0,15%+ o un minore nel veicolo"},{en:"Only DUI manslaughter convictions",it:"Solo le condanne per DUI manslaughter"},{en:"Any driver with a suspended license",it:"Qualsiasi conducente con la patente sospesa"}],correct:1,explain_en:"Florida requires ignition interlock for 2nd+ DUI convictions, and also for first-time DUI if BAC was 0.15%+ or if a minor was in the vehicle.",explain_it:"La Florida richiede l'interlock per 2a+ condanne DUI, e anche per la prima offesa DUI se il BAC era 0,15%+ o se c'era un minore nel veicolo."},
  {cat:"alcohol",en:"In Florida, DUI causing serious bodily injury is classified as:",it:"In Florida, il DUI che causa lesioni fisiche gravi \u00e8 classificato come:",options:[{en:"A misdemeanor",it:"Un'infrazione minore"},{en:"A third-degree felony",it:"Un crimine di terzo grado"},{en:"Only a civil matter",it:"Solo una questione civile"},{en:"The same as a standard DUI",it:"Uguale a un DUI standard"}],correct:1,explain_en:"DUI causing serious bodily injury is a third-degree felony in Florida, with up to 5 years in prison and up to $5,000 in fines.",explain_it:"Il DUI che causa lesioni fisiche gravi \u00e8 un crimine di terzo grado in Florida, con fino a 5 anni di prigione e fino a $5.000 di multa."},
  {cat:"alcohol",en:"Alcohol combined with many prescription drugs:",it:"L'alcol combinato con molti farmaci da prescrizione:",options:[{en:"Has no additional effect on driving",it:"Non ha ulteriori effetti sulla guida"},{en:"Can multiply impairing effects far beyond what either would cause alone",it:"Pu\u00f2 moltiplicare gli effetti compromettenti molto oltre quello che ciascuno causerebbe da solo"},{en:"Only affects people over 65",it:"Colpisce solo le persone over 65"},{en:"Is acceptable if the drug is legally prescribed",it:"\u00c8 accettabile se il farmaco \u00e8 legalmente prescritto"}],correct:1,explain_en:"Many medications combined with alcohol create a dangerous synergy, multiplying impairment far beyond what either substance would cause alone.",explain_it:"Molti farmaci combinati con l'alcol creano una pericolosa sinergia, moltiplicando la compromissione molto oltre quello che ciascuna sostanza causerebbe da sola."},
  {cat:"alcohol",en:"After a DUI arrest in Florida, what happens to your driver's license immediately?",it:"Dopo un arresto DUI in Florida, cosa succede immediatamente alla tua patente?",options:[{en:"Nothing until you are convicted",it:"Nulla fino alla condanna"},{en:"It is administratively suspended immediately \u2014 even before conviction",it:"Viene sospesa amministrativamente immediatamente \u2014 anche prima della condanna"},{en:"It is only restricted, not suspended",it:"Viene solo limitata, non sospesa"},{en:"You can keep driving until your court date",it:"Puoi continuare a guidare fino alla data del tribunale"}],correct:1,explain_en:"After a DUI arrest in Florida, your license is administratively suspended immediately (10-day review period applies). This is separate from any criminal conviction.",explain_it:"Dopo un arresto DUI in Florida, la patente viene sospesa amministrativamente immediatamente (si applica un periodo di revisione di 10 giorni). Questo \u00e8 separato da qualsiasi condanna penale."},
  {cat:"alcohol",en:"The approximate rate at which the liver eliminates alcohol is:",it:"La velocit\u00e0 approssimativa a cui il fegato elimina l'alcol \u00e8:",options:[{en:"2 drinks per hour",it:"2 drink all'ora"},{en:"1 standard drink per hour",it:"1 drink standard all'ora"},{en:"3 drinks per hour",it:"3 drink all'ora"},{en:"It varies greatly depending on the drink",it:"Varia molto a seconda della bevanda"}],correct:1,explain_en:"The liver metabolizes approximately one standard drink per hour regardless of the type of alcohol, gender, or anything you do to try to speed it up.",explain_it:"Il fegato metabolizza circa un drink standard all'ora indipendentemente dal tipo di alcol, dal genere o da qualsiasi cosa tu faccia per accelerare il processo."},
  {cat:"alcohol",en:"In Florida, 'DUI Manslaughter' means:",it:"In Florida, 'DUI Manslaughter' significa:",options:[{en:"A minor DUI with property damage",it:"Un DUI minore con danni materiali"},{en:"Causing the death of another person while driving under the influence",it:"Causare la morte di un'altra persona mentre si guida sotto l'influenza"},{en:"Driving drunk and causing a minor injury",it:"Guidare ubriachi e causare una lesione minore"},{en:"A reduced charge for DUI with a high BAC",it:"Un'accusa ridotta per DUI con BAC elevato"}],correct:1,explain_en:"DUI Manslaughter is causing a person's death while driving under the influence of alcohol or drugs. It is a second-degree felony in Florida.",explain_it:"Il DUI Manslaughter \u00e8 causare la morte di una persona mentre si guida sotto l'influenza di alcol o droghe. \u00c8 un crimine di secondo grado in Florida."},
  {cat:"alcohol",en:"A 'standard drink' in the U.S. contains approximately:",it:"Un 'drink standard' negli USA contiene approssimativamente:",options:[{en:"0.3 oz of pure alcohol",it:"0,3 once di alcol puro"},{en:"0.6 oz of pure alcohol",it:"0,6 once di alcol puro"},{en:"1.0 oz of pure alcohol",it:"1,0 oncia di alcol puro"},{en:"2.0 oz of pure alcohol",it:"2,0 once di alcol puro"}],correct:1,explain_en:"One standard U.S. drink = 0.6 oz of pure alcohol. This equals: 12 oz of regular beer (5%), 5 oz of wine (12%), or 1.5 oz of distilled spirits (40%).",explain_it:"Un drink standard USA = 0,6 once di alcol puro. Equivale a: 350 ml di birra normale (5%), 150 ml di vino (12%), o 45 ml di superalcolici (40%)."},
  {cat:"alcohol",en:"Alcohol reduces night driving safety by:",it:"L'alcol riduce la sicurezza della guida notturna:",options:[{en:"Making the road look brighter",it:"Facendo sembrare la strada pi\u00f9 luminosa"},{en:"Impairing glare recovery and narrowing peripheral vision",it:"Compromettendo il recupero dall'abbagliamento e restringendo la visione periferica"},{en:"Having no effect on vision",it:"Non avendo effetti sulla visione"},{en:"Only affecting color perception",it:"Influenzando solo la percezione dei colori"}],correct:1,explain_en:"Alcohol specifically impairs night vision by slowing glare recovery from headlights and narrowing peripheral vision \u2014 both critical for safe night driving.",explain_it:"L'alcol compromette specificamente la visione notturna rallentando il recupero dall'abbagliamento dei fari e restringendo la visione periferica \u2014 entrambi critici per la guida notturna sicura."},
  {cat:"alcohol",en:"Florida requires vehicle forfeiture for:",it:"La Florida richiede la confisca del veicolo per:",options:[{en:"Any DUI conviction",it:"Qualsiasi condanna DUI"},{en:"A second or subsequent DUI conviction",it:"Una seconda o successiva condanna DUI"},{en:"Only DUI manslaughter",it:"Solo il DUI manslaughter"},{en:"Florida does not allow vehicle forfeiture",it:"La Florida non consente la confisca del veicolo"}],correct:1,explain_en:"Florida may order vehicle impoundment or forfeiture for a second or subsequent DUI conviction.",explain_it:"La Florida pu\u00f2 ordinare il sequestro o la confisca del veicolo per una seconda o successiva condanna DUI."},
  {cat:"alcohol",en:"A DUI conviction significantly affects your auto insurance because:",it:"Una condanna DUI influenza significativamente la tua assicurazione auto perch\u00e9:",options:[{en:"It has no effect on insurance rates",it:"Non ha effetti sui premi assicurativi"},{en:"It will dramatically increase rates \u2014 sometimes tripling them \u2014 and some insurers may drop you",it:"Aumenter\u00e0 drasticamente i premi \u2014 a volte triplicandoli \u2014 e alcuni assicuratori potrebbero rifiutarti"},{en:"It only affects rates for 6 months",it:"Influenza i premi solo per 6 mesi"},{en:"It decreases rates because you are now seen as a more careful driver",it:"Diminuisce i premi perch\u00e9 ora sei visto come un conducente pi\u00f9 attento"}],correct:1,explain_en:"A DUI conviction typically causes dramatic insurance rate increases \u2014 sometimes tripling premiums \u2014 and some insurers will refuse coverage entirely.",explain_it:"Una condanna DUI causa tipicamente aumenti drammatici dei premi assicurativi \u2014 a volte triplicandoli \u2014 e alcuni assicuratori si rifiuteranno di fornire copertura."},
  {cat:"alcohol",en:"Gender affects alcohol absorption because:",it:"Il genere influenza l'assorbimento dell'alcol perch\u00e9:",options:[{en:"Men always handle alcohol better than women",it:"Gli uomini gestiscono sempre meglio l'alcol delle donne"},{en:"Women generally reach higher BAC from the same amount due to body composition differences",it:"Le donne raggiungono generalmente un BAC pi\u00f9 alto con la stessa quantit\u00e0 a causa di differenze nella composizione corporea"},{en:"Gender has no effect on alcohol absorption",it:"Il genere non ha effetti sull'assorbimento dell'alcol"},{en:"Women process alcohol faster than men",it:"Le donne elaborano l'alcol pi\u00f9 velocemente degli uomini"}],correct:1,explain_en:"Women generally reach higher BAC levels than men of the same weight drinking the same amount due to differences in body composition and enzyme levels.",explain_it:"Le donne raggiungono generalmente livelli di BAC pi\u00f9 alti degli uomini dello stesso peso che bevono la stessa quantit\u00e0, a causa di differenze nella composizione corporea e nei livelli enzimatici."},
  {cat:"alcohol",en:"A 'habitual traffic offender' status for DUI purposes requires how many DUI convictions?",it:"Lo status di 'trasgressore abituale del traffico' per i fini DUI richiede quante condanne DUI?",options:[{en:"2 DUI convictions",it:"2 condanne DUI"},{en:"3 DUI convictions within 5 years",it:"3 condanne DUI entro 5 anni"},{en:"4 DUI convictions",it:"4 condanne DUI"},{en:"Any 2 major violations including 1 DUI",it:"Qualsiasi 2 violazioni gravi incluso 1 DUI"}],correct:1,explain_en:"Three DUI convictions designate a person as a habitual traffic offender in Florida, resulting in a mandatory 5-year license revocation.",explain_it:"Tre condanne DUI designano una persona come trasgressore abituale del traffico in Florida, con una revoca obbligatoria della patente di 5 anni."},
  {cat:"alcohol",en:"The main purpose of Florida's Implied Consent Law is to:",it:"Lo scopo principale della legge del consenso implicito della Florida \u00e8:",options:[{en:"Punish drivers who refuse to take a breath test",it:"Punire i conducenti che rifiutano il test del respiro"},{en:"Deter impaired driving by requiring drivers to submit to chemical testing",it:"Scoraggiare la guida in stato di alterazione richiedendo ai conducenti di sottoporsi ai test chimici"},{en:"Give police additional search powers",it:"Dare alla polizia poteri aggiuntivi di perquisizione"},{en:"Make all chemical test results admissible in court",it:"Rendere tutti i risultati dei test chimici ammissibili in tribunale"}],correct:1,explain_en:"Implied Consent deters drunk driving by making chemical testing a condition of the privilege of driving in Florida. Refusal carries automatic license suspension.",explain_it:"Il consenso implicito scoraggia la guida ubriaca rendendo i test chimici una condizione del privilegio di guidare in Florida. Il rifiuto comporta la sospensione automatica della patente."},
  {cat:"alcohol",en:"Alcohol-related crashes account for what percentage of U.S. traffic fatalities?",it:"Gli incidenti legati all'alcol rappresentano quale percentuale delle vittime stradali negli USA?",options:[{en:"About 5%",it:"Circa il 5%"},{en:"About 10%",it:"Circa il 10%"},{en:"About 28\u201330%",it:"Circa il 28-30%"},{en:"More than 50%",it:"Pi\u00f9 del 50%"}],correct:2,explain_en:"Alcohol-impaired driving accounts for roughly 28\u201330% of all U.S. traffic fatalities \u2014 making it one of the leading causes of preventable traffic deaths.",explain_it:"La guida in stato di ebbrezza rappresenta circa il 28-30% di tutte le vittime stradali negli USA \u2014 rendendola una delle principali cause di morti stradali prevenibili."},
  {cat:"alcohol",en:"A designated driver is a person who:",it:"Un conducente designato \u00e8 una persona che:",options:[{en:"Has had one or two drinks only",it:"Ha bevuto solo uno o due drink"},{en:"Agrees not to drink alcohol so they can safely drive others home",it:"Accetta di non bere alcolici per poter portare a casa gli altri in sicurezza"},{en:"Has a commercial driver's license",it:"Ha una patente per veicoli commerciali"},{en:"Is the oldest person in the group",it:"\u00c8 la persona pi\u00f9 anziana del gruppo"}],correct:1,explain_en:"A designated driver commits to abstaining from alcohol to safely drive their group home. Even 'one or two drinks' can affect driving \u2014 the designated driver should have none.",explain_it:"Un conducente designato si impegna ad astenersi dall'alcol per portare in sicurezza il suo gruppo a casa. Anche 'uno o due drink' possono influenzare la guida \u2014 il conducente designato non ne deve bere."},
  {cat:"license",en:"A standard Florida driver license is valid for:",it:"Una patente di guida standard della Florida \u00e8 valida per:",options:[{en:"4 years",it:"4 anni"},{en:"6 years",it:"6 anni"},{en:"8 years",it:"8 anni"},{en:"10 years",it:"10 anni"}],correct:2,explain_en:"A standard Florida Class E license is valid for 8 years. Drivers aged 80 or older must renew every 6 years.",explain_it:"Una patente Class E standard della Florida \u00e8 valida per 8 anni. I conducenti di 80 anni o pi\u00f9 devono rinnovarla ogni 6 anni."},
  {cat:"license",en:"Florida's point system: accumulating 12 points in 12 months results in:",it:"Sistema a punti della Florida: accumulare 12 punti in 12 mesi comporta:",options:[{en:"A warning letter",it:"Una lettera di avvertimento"},{en:"30-day license suspension",it:"Sospensione della patente di 30 giorni"},{en:"3-month license suspension",it:"Sospensione della patente di 3 mesi"},{en:"1-year license suspension",it:"Sospensione della patente di 1 anno"}],correct:1,explain_en:"12 pts in 12 months = 30-day suspension. 18 pts in 18 months = 3-month suspension. 24 pts in 36 months = 1-year suspension.",explain_it:"12 punti in 12 mesi = sospensione di 30 giorni. 18 punti in 18 mesi = 3 mesi. 24 punti in 36 mesi = 1 anno."},
  {cat:"license",en:"How many points does a speeding violation of less than 15 mph over the limit add in Florida?",it:"Quanti punti aggiunge un'infrazione per eccesso di velocit\u00e0 inferiore a 15 mph in Florida?",options:[{en:"2 points",it:"2 punti"},{en:"3 points",it:"3 punti"},{en:"4 points",it:"4 punti"},{en:"6 points",it:"6 punti"}],correct:1,explain_en:"Speeding less than 15 mph over the limit = 3 points. Speeding 15+ mph over = 4 points. A crash caused by a moving violation = 6 points.",explain_it:"Eccesso di velocit\u00e0 inferiore a 15 mph oltre il limite = 3 punti. 15+ mph oltre = 4 punti. Incidente causato da violazione in movimento = 6 punti."},
  {cat:"license",en:"Florida's minimum required auto insurance includes:",it:"L'assicurazione auto minima richiesta dalla Florida include:",options:[{en:"$10,000 PIP and $10,000 PDL",it:"$10.000 PIP e $10.000 PDL"},{en:"$25,000 bodily injury per person",it:"$25.000 per lesioni per persona"},{en:"$50,000 comprehensive coverage",it:"$50.000 di copertura completa"},{en:"$100,000 liability coverage",it:"$100.000 di copertura di responsabilit\u00e0 civile"}],correct:0,explain_en:"Florida requires $10,000 Personal Injury Protection (PIP) and $10,000 Property Damage Liability (PDL). Florida is a no-fault state \u2014 PIP covers your own injuries.",explain_it:"La Florida richiede $10.000 di Protezione da Infortuni Personali (PIP) e $10.000 di Responsabilit\u00e0 per Danni Materiali (PDL). La Florida \u00e8 uno stato no-fault."},
  {cat:"license",en:"New Florida residents must get a Florida license within:",it:"I nuovi residenti in Florida devono ottenere la patente Florida entro:",options:[{en:"10 days of establishing residency",it:"10 giorni dall'acquisizione della residenza"},{en:"30 days of establishing residency",it:"30 giorni dall'acquisizione della residenza"},{en:"60 days of establishing residency",it:"60 giorni dall'acquisizione della residenza"},{en:"90 days of establishing residency",it:"90 giorni dall'acquisizione della residenza"}],correct:1,explain_en:"New Florida residents must obtain a Florida driver license within 30 days of establishing residency. Out-of-state licenses must be surrendered.",explain_it:"I nuovi residenti in Florida devono ottenere la patente Florida entro 30 giorni dall'acquisizione della residenza. Le patenti di altri stati devono essere consegnate."},
  {cat:"license",en:"Florida's seat belt law requires seat belts for:",it:"La legge sulle cinture della Florida richiede le cinture per:",options:[{en:"Driver only",it:"Solo il conducente"},{en:"Driver and front passenger only",it:"Solo conducente e passeggero anteriore"},{en:"All front-seat occupants AND all passengers under 18 regardless of seat",it:"Tutti gli occupanti anteriori E tutti i passeggeri under 18 indipendentemente dal sedile"},{en:"Everyone in the vehicle without exception",it:"Tutti nel veicolo senza eccezioni"}],correct:2,explain_en:"Florida requires seat belts for all front-seat occupants and for all passengers under 18 in any seat. Adults in the back are not legally required to wear belts (though strongly recommended).",explain_it:"La Florida richiede le cinture per tutti gli occupanti anteriori e per tutti i passeggeri under 18 in qualsiasi sedile. Gli adulti nel sedile posteriore non sono legalmente obbligati (sebbene fortemente raccomandato)."},
  {cat:"license",en:"Florida's Graduated Driver License (GDL) program is designed for:",it:"Il programma di Patente a Guida Progressiva (GDL) della Florida \u00e8 progettato per:",options:[{en:"Commercial truck drivers",it:"Conducenti di camion commerciali"},{en:"Teen drivers under 18 to gain experience safely before full licensing",it:"Conducenti adolescenti under 18 per acquisire esperienza in sicurezza prima della patente completa"},{en:"Drivers over 80 who need license renewal",it:"Conducenti over 80 che necessitano del rinnovo della patente"},{en:"Drivers with DUI convictions needing rehabilitation",it:"Conducenti con condanne DUI che necessitano di riabilitazione"}],correct:1,explain_en:"Florida's GDL program is a step-by-step licensing process for drivers under 18: learner's license \u2192 provisional license \u2192 full license.",explain_it:"Il programma GDL della Florida \u00e8 un processo di patente graduale per i conducenti under 18: patente per principianti \u2192 patente provvisoria \u2192 patente completa."},
  {cat:"license",en:"To get a Florida learner's license (under 18), you must be at least:",it:"Per ottenere la patente per principianti in Florida (under 18), devi avere almeno:",options:[{en:"14 years old",it:"14 anni"},{en:"15 years old",it:"15 anni"},{en:"16 years old",it:"16 anni"},{en:"17 years old",it:"17 anni"}],correct:1,explain_en:"You must be at least 15 years old to obtain a Florida learner's license. You must also pass the Class E knowledge exam and vision screening.",explain_it:"Devi avere almeno 15 anni per ottenere la patente per principianti in Florida. Devi anche superare l'esame di conoscenza Class E e lo screening visivo."},
  {cat:"license",en:"A learner's license holder must be supervised by a licensed driver who is:",it:"Il titolare di una patente per principianti deve essere supervisionato da un conducente con patente che:",options:[{en:"Any licensed adult \u2014 no age requirement",it:"Qualsiasi adulto con patente \u2014 nessun requisito di et\u00e0"},{en:"At least 21 years old, in the front passenger seat",it:"Abbia almeno 21 anni, nel sedile anteriore del passeggero"},{en:"A driving instructor only",it:"Solo un istruttore di guida"},{en:"A parent or guardian only",it:"Solo un genitore o tutore"}],correct:1,explain_en:"Learner's license holders must be supervised by a licensed driver who is at least 21 years old and seated in the front passenger seat.",explain_it:"I titolari di patente per principianti devono essere supervisionati da un conducente con patente di almeno 21 anni seduto nel sedile anteriore del passeggero."},
  {cat:"license",en:"Before getting a Florida provisional license, a teen driver must complete:",it:"Prima di ottenere la patente provvisoria in Florida, un conducente adolescente deve completare:",options:[{en:"10 hours of supervised driving (5 at night)",it:"10 ore di guida supervisionata (5 di notte)"},{en:"50 hours of supervised driving (10 at night)",it:"50 ore di guida supervisionata (10 di notte)"},{en:"25 hours of supervised driving (no night requirement)",it:"25 ore di guida supervisionata (nessun requisito notturno)"},{en:"100 hours of supervised driving",it:"100 ore di guida supervisionata"}],correct:1,explain_en:"Florida requires 50 hours of supervised driving (at least 10 at night) logged before a teen can apply for a provisional license.",explain_it:"La Florida richiede 50 ore di guida supervisionata (almeno 10 di notte) registrate prima che un adolescente possa richiedere la patente provvisoria."},
  {cat:"license",en:"A Florida provisional license restricts driving between:",it:"La patente provvisoria della Florida limita la guida tra:",options:[{en:"10 PM and 5 AM",it:"Le 22:00 e le 5:00"},{en:"11 PM and 6 AM (with exceptions for work, school, or emergencies)",it:"Le 23:00 e le 6:00 (con eccezioni per lavoro, scuola o emergenze)"},{en:"Midnight and 6 AM",it:"Mezzanotte e le 6:00"},{en:"There are no nighttime restrictions",it:"Non ci sono restrizioni notturne"}],correct:1,explain_en:"Provisional license holders (first year) may not drive between 11 PM and 6 AM, with exceptions for work, school, religious activities, or emergencies.",explain_it:"I titolari di patente provvisoria (primo anno) non possono guidare tra le 23:00 e le 6:00, con eccezioni per lavoro, scuola, attivit\u00e0 religiose o emergenze."},
  {cat:"license",en:"What is the 'FR-44' form required for in Florida?",it:"A cosa serve il modulo 'FR-44' in Florida?",options:[{en:"Standard driver's license application",it:"Domanda standard di patente di guida"},{en:"Proof of higher liability insurance coverage required after a DUI conviction",it:"Prova di una copertura assicurativa di responsabilit\u00e0 pi\u00f9 elevata richiesta dopo una condanna DUI"},{en:"Crash report form",it:"Modulo di denuncia incidente"},{en:"Commercial vehicle permit",it:"Permesso per veicoli commerciali"}],correct:1,explain_en:"The FR-44 is a certificate required for DUI offenders proving they carry higher liability insurance (at least $100,000/$300,000 bodily injury, $50,000 property damage).",explain_it:"L'FR-44 \u00e8 un certificato richiesto ai trasgressori DUI che prova che hanno una copertura di responsabilit\u00e0 pi\u00f9 elevata (almeno $100.000/$300.000 per lesioni, $50.000 per danni materiali)."},
  {cat:"license",en:"In Florida, you must notify FLHSMV of an address change within:",it:"In Florida, devi notificare al FLHSMV un cambio di indirizzo entro:",options:[{en:"10 days",it:"10 giorni"},{en:"30 days",it:"30 giorni"},{en:"60 days",it:"60 giorni"},{en:"90 days",it:"90 giorni"}],correct:1,explain_en:"Florida requires notifying FLHSMV of any change of address within 30 days.",explain_it:"La Florida richiede di notificare al FLHSMV qualsiasi cambio di indirizzo entro 30 giorni."},
  {cat:"license",en:"Driving with a suspended license in Florida is:",it:"Guidare con la patente sospesa in Florida \u00e8:",options:[{en:"Only a minor infraction on first offense",it:"Solo un'infrazione minore alla prima offesa"},{en:"A criminal offense \u2014 a misdemeanor or felony depending on prior offenses",it:"Un reato penale \u2014 un'infrazione minore o un crimine a seconda delle offese precedenti"},{en:"Acceptable if driving to work or school",it:"Accettabile se si va al lavoro o a scuola"},{en:"Only ticketed if involved in a crash",it:"Multato solo se coinvolto in un incidente"}],correct:1,explain_en:"Driving with a suspended or revoked license is a criminal offense in Florida \u2014 a misdemeanor for a first offense, potentially a felony for subsequent offenses.",explain_it:"Guidare con la patente sospesa o revocata \u00e8 un reato penale in Florida \u2014 un'infrazione minore per la prima offesa, potenzialmente un crimine per offese successive."},
  {cat:"license",en:"Florida's no-fault auto insurance system means:",it:"Il sistema assicurativo auto no-fault della Florida significa:",options:[{en:"You cannot sue anyone after a crash",it:"Non puoi citare in giudizio nessuno dopo un incidente"},{en:"Your own PIP insurance pays for your injuries up to the policy limit, regardless of who caused the crash",it:"La tua assicurazione PIP paga le tue lesioni fino al limite della polizza, indipendentemente da chi ha causato l'incidente"},{en:"No insurance is required for minor crashes",it:"Nessuna assicurazione \u00e8 richiesta per gli incidenti minori"},{en:"The at-fault driver always pays all costs",it:"Il conducente responsabile paga sempre tutti i costi"}],correct:1,explain_en:"Florida's no-fault system: your own PIP insurance covers your medical costs up to $10,000 regardless of who caused the crash. For serious injuries, you may still sue.",explain_it:"Il sistema no-fault della Florida: la tua assicurazione PIP copre le tue spese mediche fino a $10.000 indipendentemente da chi ha causato l'incidente. Per lesioni gravi, puoi comunque fare causa."},
  {cat:"license",en:"Florida requires you to carry proof of insurance:",it:"La Florida richiede di portare la prova dell'assicurazione:",options:[{en:"Only when driving on interstate highways",it:"Solo quando si guida sulle autostrade interstatali"},{en:"At all times \u2014 and present it when requested by law enforcement",it:"Sempre \u2014 e esibirla quando richiesto dalle forze dell'ordine"},{en:"Only for vehicles newer than 5 years",it:"Solo per i veicoli con meno di 5 anni"},{en:"Only if your vehicle is not paid off",it:"Solo se il tuo veicolo non \u00e8 ancora pagato"}],correct:1,explain_en:"Florida requires drivers to carry proof of insurance at all times and produce it on request by law enforcement. Failure to show proof can result in citation.",explain_it:"La Florida richiede ai conducenti di portare sempre la prova dell'assicurazione e di esibirla su richiesta delle forze dell'ordine. La mancata esibizione pu\u00f2 comportare una multa."},
  {cat:"license",en:"What is REAL ID and when is it required in Florida?",it:"Cos'\u00e8 il REAL ID e quando \u00e8 richiesto in Florida?",options:[{en:"A federal ID required for all drivers since 2020",it:"Un documento federale richiesto a tutti i conducenti dal 2020"},{en:"A compliant license required to board domestic flights and enter certain federal facilities",it:"Una patente conforme richiesta per imbarcarsi su voli nazionali e accedere a determinate strutture federali"},{en:"Required for commercial driving only",it:"Richiesto solo per la guida commerciale"},{en:"A voluntary upgrade with no practical requirement",it:"Un aggiornamento volontario senza alcun requisito pratico"}],correct:1,explain_en:"REAL ID-compliant licenses are required to board domestic flights and access certain federal facilities (e.g., military bases). They require additional identity documentation when applying.",explain_it:"Le patenti conformi al REAL ID sono richieste per imbarcarsi su voli nazionali e accedere a determinate strutture federali (es. basi militari). Richiedono documentazione aggiuntiva."},
  {cat:"license",en:"A 'hardship license' in Florida allows:",it:"Una 'licenza di necessit\u00e0' in Florida consente:",options:[{en:"Full driving privileges despite a suspension",it:"Pieni privilegi di guida nonostante una sospensione"},{en:"Limited driving for essential purposes (work, school, medical) during a suspension",it:"Guida limitata per scopi essenziali (lavoro, scuola, medici) durante una sospensione"},{en:"Driving only with a licensed adult in the vehicle",it:"Guida solo con un adulto con patente nel veicolo"},{en:"Commercial driving only",it:"Solo la guida commerciale"}],correct:1,explain_en:"A hardship (Business Purposes Only or Employment Purposes Only) license allows limited driving for essential purposes during a suspension period.",explain_it:"Una licenza di necessit\u00e0 (Solo per Scopi Lavorativi) consente una guida limitata per scopi essenziali durante un periodo di sospensione."},
  {cat:"license",en:"A moving violation that causes a crash in Florida adds how many points?",it:"Una violazione in movimento che causa un incidente in Florida aggiunge quanti punti?",options:[{en:"2 points",it:"2 punti"},{en:"4 points",it:"4 punti"},{en:"6 points",it:"6 punti"},{en:"8 points",it:"8 punti"}],correct:2,explain_en:"A moving violation that results in a crash adds 6 points to your Florida driving record.",explain_it:"Una violazione in movimento che causa un incidente aggiunge 6 punti al tuo casellario di guida in Florida."},
  {cat:"license",en:"In Florida, if you are 80 years or older, how often must you renew your license?",it:"In Florida, se hai 80 anni o pi\u00f9, con quale frequenza devi rinnovare la patente?",options:[{en:"Every 2 years",it:"Ogni 2 anni"},{en:"Every 4 years",it:"Ogni 4 anni"},{en:"Every 6 years",it:"Ogni 6 anni"},{en:"Every 8 years \u2014 same as everyone else",it:"Ogni 8 anni \u2014 come tutti gli altri"}],correct:2,explain_en:"Drivers aged 80 or older in Florida must renew their license every 6 years instead of the standard 8 years.",explain_it:"I conducenti di 80 anni o pi\u00f9 in Florida devono rinnovare la patente ogni 6 anni invece degli standard 8 anni."},
  {cat:"license",en:"What is 'uninsured motorist' (UM) coverage and is it required in Florida?",it:"Cos'\u00e8 la copertura per 'veicoli non assicurati' (UM) ed \u00e8 obbligatoria in Florida?",options:[{en:"Required \u2014 all Florida drivers must have it",it:"Obbligatoria \u2014 tutti i conducenti in Florida devono averla"},{en:"Optional \u2014 protects you when hit by a driver with no or insufficient insurance",it:"Facoltativa \u2014 ti protegge quando sei colpito da un conducente senza assicurazione o con copertura insufficiente"},{en:"Required only for commercial vehicles",it:"Obbligatoria solo per i veicoli commerciali"},{en:"Not available in Florida",it:"Non disponibile in Florida"}],correct:1,explain_en:"UM coverage is optional in Florida but highly recommended \u2014 it protects you if you're hit by an uninsured or underinsured driver. PIP alone may not cover all costs.",explain_it:"La copertura UM \u00e8 facoltativa in Florida ma altamente raccomandata \u2014 ti protegge se sei colpito da un conducente non assicurato o sottassicurato. Solo il PIP potrebbe non coprire tutti i costi."},
  {cat:"license",en:"Passing a school bus with its stop arm extended is worth how many points in Florida?",it:"Superare uno scuolabus con il braccio di stop esteso vale quanti punti in Florida?",options:[{en:"2 points",it:"2 punti"},{en:"3 points",it:"3 punti"},{en:"4 points",it:"4 punti"},{en:"6 points",it:"6 punti"}],correct:2,explain_en:"Unlawfully passing a school bus with its stop arm extended adds 4 points to your Florida driving record and carries heavy fines.",explain_it:"Superare illegalmente uno scuolabus con il braccio di stop esteso aggiunge 4 punti al tuo casellario di guida in Florida e comporta pesanti sanzioni."},
  {cat:"signs",en:"What does a 'No Parking' sign mean?",it:"Cosa significa un segnale 'No Parking'?",options:[{en:"You may stop briefly to drop off passengers",it:"Puoi fermarti brevemente per far scendere i passeggeri"},{en:"You may not park or leave your vehicle unattended",it:"Non puoi parcheggiare n\u00e9 lasciare il veicolo incustodito"},{en:"Parking allowed between 9 AM and 5 PM",it:"Parcheggio consentito tra le 9:00 e le 17:00"},{en:"Parking is limited to 15 minutes",it:"Parcheggio limitato a 15 minuti"}],correct:1,explain_en:"A No Parking sign means you cannot park or leave your vehicle unattended. You may briefly stop to load/unload passengers.",explain_it:"Un segnale No Parking significa che non puoi parcheggiare n\u00e9 lasciare il veicolo incustodito. Puoi fermarti brevemente per far salire/scendere i passeggeri."},
  {cat:"signs",en:"A 'No Standing' sign means:",it:"Un segnale 'No Standing' significa:",options:[{en:"Parking allowed up to 5 minutes",it:"Parcheggio consentito fino a 5 minuti"},{en:"You may only stop momentarily to pick up or discharge passengers",it:"Puoi fermarti solo momentaneamente per far salire o scendere i passeggeri"},{en:"No stopping allowed at any time",it:"Nessuna fermata consentita in qualsiasi momento"},{en:"Only commercial vehicles may stop here",it:"Solo veicoli commerciali possono fermarsi qui"}],correct:1,explain_en:"No Standing is more restrictive than No Parking \u2014 you may only stop momentarily to pick up/discharge passengers.",explain_it:"No Standing \u00e8 pi\u00f9 restrittivo di No Parking \u2014 puoi fermarti solo momentaneamente per far salire/scendere i passeggeri."},
  {cat:"signs",en:"A 'No Stopping' sign means:",it:"Un segnale 'No Stopping' significa:",options:[{en:"You may not stop for any reason",it:"Non puoi fermarti per nessun motivo"},{en:"You may stop only in an emergency",it:"Puoi fermarti solo in caso di emergenza"},{en:"You may not park but can stop briefly",it:"Non puoi parcheggiare ma puoi fermarti brevemente"},{en:"Only buses may stop here",it:"Solo gli autobus possono fermarsi qui"}],correct:0,explain_en:"No Stopping is the most restrictive \u2014 you may not stop for any reason except to comply with a traffic device or officer.",explain_it:"No Stopping \u00e8 il pi\u00f9 restrittivo \u2014 non puoi fermarti per nessun motivo tranne che per rispettare un segnale o le indicazioni di un agente."},
  {cat:"signs",en:"What does a pedestrian crossing warning sign look like?",it:"Come appare un segnale di avvertimento per attraversamento pedonale?",options:[{en:"A white rectangle with the word WALK",it:"Un rettangolo bianco con la parola WALK"},{en:"A yellow diamond with a walking figure",it:"Un rombo giallo con una figura che cammina"},{en:"A green circle with an arrow",it:"Un cerchio verde con una freccia"},{en:"A red octagon with a figure",it:"Un ottagono rosso con una figura"}],correct:1,explain_en:"Pedestrian crossing warning signs are yellow diamond-shaped with a walking figure.",explain_it:"I segnali di avvertimento per l'attraversamento pedonale sono a rombo giallo con una figura che cammina."},
  {cat:"signs",en:"A 'Divided Highway Begins' sign means:",it:"Un segnale 'Divided Highway Begins' significa:",options:[{en:"The road becomes one-way",it:"La strada diventa a senso unico"},{en:"A median or barrier is about to divide opposing lanes",it:"Una mediana o barriera sta per dividere le corsie opposte"},{en:"The highway ends ahead",it:"L'autostrada finisce in avanti"},{en:"A passing lane begins",it:"Inizia una corsia di sorpasso"}],correct:1,explain_en:"Divided Highway Begins warns that a median or barrier is about to separate opposing lanes of traffic.",explain_it:"Divided Highway Begins avverte che una mediana o barriera sta per separare le corsie di traffico opposte."},
  {cat:"signs",en:"A 'Divided Highway Ends' sign means:",it:"Un segnale 'Divided Highway Ends' significa:",options:[{en:"Traffic must stop ahead",it:"Il traffico deve fermarsi in avanti"},{en:"The dividing median ends \u2014 two-way traffic resumes",it:"La mediana divisoria finisce \u2014 riprende il traffico bidirezionale"},{en:"Speed limit increases ahead",it:"Il limite di velocit\u00e0 aumenta in avanti"},{en:"The highway becomes one-way",it:"L'autostrada diventa a senso unico"}],correct:1,explain_en:"Divided Highway Ends means the median is ending and you will share the road with oncoming traffic. Stay right.",explain_it:"Divided Highway Ends significa che la mediana sta finendo e condividerai la strada con il traffico in arrivo. Tieniti a destra."},
  {cat:"signs",en:"What does a 'Slippery When Wet' sign look like?",it:"Come appare un segnale 'Slippery When Wet'?",options:[{en:"A blue rectangle with water droplets",it:"Un rettangolo blu con gocce d'acqua"},{en:"A yellow diamond showing a skidding car",it:"Un rombo giallo con un'auto in slittamento"},{en:"An orange triangle with wavy lines",it:"Un triangolo arancione con linee ondulate"},{en:"A white rectangle with the word WET",it:"Un rettangolo bianco con la parola WET"}],correct:1,explain_en:"Slippery When Wet is a yellow diamond with a skidding car. It warns that the road is especially slippery when wet.",explain_it:"Slippery When Wet \u00e8 un rombo giallo con un'auto in slittamento. Avverte che la strada \u00e8 particolarmente scivolosa quando bagnata."},
  {cat:"signs",en:"A 'Two-Way Traffic' sign warns:",it:"Un segnale 'Two-Way Traffic' avverte:",options:[{en:"The road is becoming a divided highway",it:"La strada sta diventando un'autostrada divisa"},{en:"You are leaving a one-way road \u2014 two-way traffic ahead",it:"Stai lasciando una strada a senso unico \u2014 traffico bidirezionale in avanti"},{en:"Two lanes are merging ahead",it:"Due corsie si uniscono in avanti"},{en:"Passing allowed in both directions",it:"Il sorpasso \u00e8 consentito in entrambe le direzioni"}],correct:1,explain_en:"Two-Way Traffic warns that you are transitioning from a one-way road to a two-way section. Stay right.",explain_it:"Two-Way Traffic avverte che stai passando da una strada a senso unico a una sezione bidirezionale. Tieniti a destra."},
  {cat:"signs",en:"A 'Winding Road' sign means:",it:"Un segnale 'Winding Road' significa:",options:[{en:"The road ends in a sharp curve",it:"La strada finisce in una curva brusca"},{en:"A series of curves lies ahead",it:"Una serie di curve \u00e8 in avanti"},{en:"Passing is allowed on the curves",it:"Il sorpasso \u00e8 consentito nelle curve"},{en:"The road narrows to one lane",it:"La strada si restringe a una corsia"}],correct:1,explain_en:"A winding road sign warns of multiple curves ahead. Reduce speed and be prepared for turns in both directions.",explain_it:"Un segnale di strada tortuosa avverte di curve multiple in avanti. Riduci la velocit\u00e0 e preparati per svolte in entrambe le direzioni."},
  {cat:"signs",en:"A curved arrow on a yellow diamond means:",it:"Una freccia curva su un rombo giallo significa:",options:[{en:"Merge ahead",it:"Confluenza in avanti"},{en:"A sharp curve in the direction shown is ahead",it:"Una curva brusca nella direzione indicata \u00e8 in avanti"},{en:"Right turn only",it:"Solo svolta a destra"},{en:"Road ends \u2014 turn",it:"La strada finisce \u2014 girare"}],correct:1,explain_en:"A curved arrow on a yellow diamond warns of a sharp curve in that direction. Reduce speed before entering.",explain_it:"Una freccia curva su un rombo giallo avverte di una curva brusca in quella direzione. Riduci la velocit\u00e0 prima di entrare."},
  {cat:"signs",en:"What does a 'Deer Crossing' sign indicate?",it:"Cosa indica un segnale 'Deer Crossing'?",options:[{en:"Hunting is permitted here",it:"La caccia \u00e8 consentita qui"},{en:"Animals frequently cross \u2014 watch for wildlife",it:"Gli animali attraversano frequentemente \u2014 attenzione alla fauna"},{en:"Deer farm area \u2014 slow down",it:"Area di allevamento cervi \u2014 rallentare"},{en:"No animals allowed on the road",it:"Nessun animale consentito sulla strada"}],correct:1,explain_en:"Deer crossing signs warn that animals cross frequently. Be especially alert at dawn and dusk.",explain_it:"I segnali di attraversamento cervi avvertono che gli animali attraversano frequentemente. Sii particolarmente vigile all'alba e al tramonto."},
  {cat:"signs",en:"A 'Dip' sign warns of:",it:"Un segnale 'Dip' avverte di:",options:[{en:"A low point in the road surface",it:"Un punto basso nella superficie stradale"},{en:"A bridge weight limit",it:"Un limite di peso su un ponte"},{en:"Road construction machinery",it:"Macchinari di costruzione"},{en:"A railroad crossing",it:"Un passaggio a livello"}],correct:0,explain_en:"A Dip sign warns of a low valley in the road that may cause the vehicle to bounce. Reduce speed.",explain_it:"Un segnale Dip avverte di un avvallamento nella strada che pu\u00f2 far rimbalzare il veicolo. Riduci la velocit\u00e0."},
  {cat:"signs",en:"A 'Narrow Bridge' sign indicates:",it:"Un segnale 'Narrow Bridge' indica:",options:[{en:"The bridge is closed to heavy vehicles",it:"Il ponte \u00e8 chiuso ai veicoli pesanti"},{en:"The bridge ahead is narrower than the road",it:"Il ponte in avanti \u00e8 pi\u00f9 stretto della strada"},{en:"No passing lane on the bridge",it:"Nessuna corsia di sorpasso sul ponte"},{en:"The bridge has a weight limit",it:"Il ponte ha un limite di peso"}],correct:1,explain_en:"Narrow Bridge warns that the bridge is narrower than the approaching road. Reduce speed and watch for oncoming vehicles.",explain_it:"Narrow Bridge avverte che il ponte \u00e8 pi\u00f9 stretto della strada. Riduci la velocit\u00e0 e fai attenzione ai veicoli in arrivo."},
  {cat:"signs",en:"What does a 'Low Clearance' sign indicate?",it:"Cosa indica un segnale 'Low Clearance'?",options:[{en:"The road surface is low \u2014 flooding risk",it:"La superficie stradale \u00e8 bassa \u2014 rischio inondazioni"},{en:"An overhead structure has limited vertical clearance",it:"Una struttura sopraelevata ha un'altezza libera limitata"},{en:"Speed limit is lowered ahead",it:"Il limite di velocit\u00e0 si riduce in avanti"},{en:"Lane width narrows",it:"La larghezza della corsia si restringe"}],correct:1,explain_en:"Low Clearance signs state the maximum height vehicles can pass under a bridge or overpass.",explain_it:"I segnali Low Clearance indicano l'altezza massima dei veicoli che possono passare sotto un ponte o sovrappasso."},
  {cat:"signs",en:"Fluorescent yellow-green signs are used specifically for:",it:"I segnali giallo-verde fluorescenti sono usati specificamente per:",options:[{en:"Construction zones",it:"Zone di costruzione"},{en:"School zones and pedestrian crossings",it:"Zone scolastiche e attraversamenti pedonali"},{en:"Railroad crossings",it:"Passaggi a livello"},{en:"Highway guide information",it:"Informazioni guida autostradale"}],correct:1,explain_en:"Fluorescent yellow-green is used for school zone and pedestrian warning signs \u2014 highest visibility of any sign color.",explain_it:"Il giallo-verde fluorescente \u00e8 usato per i segnali delle zone scolastiche e di avvertimento pedonale \u2014 massima visibilit\u00e0."},
  {cat:"signs",en:"What color are temporary traffic control signs in construction zones?",it:"Di che colore sono i segnali temporanei nelle zone di lavori?",options:[{en:"Yellow",it:"Giallo"},{en:"Orange",it:"Arancione"},{en:"Red",it:"Rosso"},{en:"White",it:"Bianco"}],correct:1,explain_en:"Orange is the color for temporary traffic control signs in construction and maintenance zones. Fines are doubled.",explain_it:"L'arancione \u00e8 il colore per i segnali temporanei nelle zone di lavori. Le multe sono raddoppiate."},
  {cat:"signs",en:"What is the shape of a railroad advance warning sign?",it:"Qual \u00e8 la forma di un segnale anticipato di avvertimento ferroviario?",options:[{en:"Yellow diamond",it:"Rombo giallo"},{en:"Yellow circle",it:"Cerchio giallo"},{en:"White rectangle",it:"Rettangolo bianco"},{en:"Yellow-green pentagon",it:"Pentagono giallo-verde"}],correct:1,explain_en:"The railroad advance warning sign is uniquely circular and yellow with an X and RR. The only circular yellow warning sign.",explain_it:"Il segnale anticipato ferroviario \u00e8 unicamente circolare e giallo con una X e RR. \u00c8 l'unico segnale di avvertimento circolare giallo."},
  {cat:"signs",en:"A sign with a bicycle symbol inside a red-slash circle means:",it:"Un segnale con un simbolo di bicicletta in un cerchio rosso barrato significa:",options:[{en:"Bicycle lane ahead",it:"Pista ciclabile in avanti"},{en:"Bicycles are prohibited",it:"Le biciclette sono vietate"},{en:"Bicycle repair station ahead",it:"Stazione di riparazione biciclette"},{en:"Share the road with cyclists",it:"Condividi la strada con i ciclisti"}],correct:1,explain_en:"Any symbol inside a circle with a red diagonal slash means that activity is prohibited. Bicycle + red slash = no bicycles.",explain_it:"Qualsiasi simbolo in un cerchio con barra rossa diagonale significa divieto. Bicicletta + barra rossa = biciclette vietate."},
  {cat:"signs",en:"What does a 'Yield Ahead' warning sign look like?",it:"Come appare un segnale 'Yield Ahead'?",options:[{en:"Yellow diamond with YIELD text",it:"Rombo giallo con testo YIELD"},{en:"Yellow downward-pointing triangle",it:"Triangolo giallo con punta verso il basso"},{en:"White rectangle with YIELD in red",it:"Rettangolo bianco con YIELD in rosso"},{en:"Red inverted triangle",it:"Triangolo rovesciato rosso"}],correct:1,explain_en:"The Yield Ahead warning sign is a yellow downward-pointing triangle, giving advance notice of a yield sign.",explain_it:"Il segnale Yield Ahead \u00e8 un triangolo giallo con la punta verso il basso, che avvisa in anticipo di un segnale di precedenza."},
  {cat:"signs",en:"What is a 'Chevron' sign used for?",it:"A cosa serve un segnale 'Chevron'?",options:[{en:"Marking road edges on straight sections",it:"Segnare i bordi della strada nelle sezioni dritte"},{en:"Indicating the direction of a sharp curve",it:"Indicare la direzione di una curva brusca"},{en:"Marking construction zone boundaries",it:"Segnare i confini delle zone di costruzione"},{en:"Showing permitted passing areas",it:"Mostrare le aree di sorpasso consentite"}],correct:1,explain_en:"Chevron alignment signs (black chevron on yellow/orange) are placed on the outside of sharp curves to guide drivers.",explain_it:"I segnali a chevron (chevron nero su giallo/arancione) sono posizionati all'esterno delle curve brusche per guidare i conducenti."},
  {cat:"signs",en:"A 'Soft Shoulder' sign means:",it:"Un segnale 'Soft Shoulder' significa:",options:[{en:"The road surface is soft \u2014 avoid driving",it:"La superficie stradale \u00e8 morbida \u2014 evitare di guidare"},{en:"The roadside shoulder is unpaved or unstable",it:"La banchina laterale non \u00e8 asfaltata o \u00e8 instabile"},{en:"Emergency stopping only",it:"Solo fermate di emergenza"},{en:"Shoulder parking permitted",it:"Parcheggio sulla banchina consentito"}],correct:1,explain_en:"Soft Shoulder means the roadside shoulder is unpaved or may not support a vehicle's weight. Avoid driving on it.",explain_it:"Soft Shoulder significa che la banchina non \u00e8 asfaltata o potrebbe non supportare il peso di un veicolo. Evita di guidarci sopra."},
  {cat:"signs",en:"What does an interstate highway shield sign show?",it:"Cosa mostra un segnale scudo di autostrada interstatale?",options:[{en:"Distance to the next state",it:"Distanza dal prossimo stato"},{en:"The route number of the interstate",it:"Il numero del percorso dell'autostrada interstatale"},{en:"The speed limit",it:"Il limite di velocit\u00e0"},{en:"The toll amount",it:"L'importo del pedaggio"}],correct:1,explain_en:"Interstate shield signs display the route number. Odd = north-south; even = east-west.",explain_it:"I segnali scudo interstatale mostrano il numero del percorso. Dispari = nord-sud; pari = est-ovest."},
  {cat:"signs",en:"A hill grade sign (showing a percentage) means:",it:"Un segnale di pendenza (con percentuale) significa:",options:[{en:"Trucks must stop and check brakes",it:"I camion devono fermarsi e controllare i freni"},{en:"A steep grade ahead \u2014 use lower gears, check brakes",it:"Una pendenza ripida in avanti \u2014 usa marce basse, controlla i freni"},{en:"Speed limit increases on the downhill",it:"Il limite di velocit\u00e0 aumenta in discesa"},{en:"Bicycles must dismount",it:"I ciclisti devono smontare"}],correct:1,explain_en:"Hill grade signs warn of a steep descent. Use lower gears to avoid overheating brakes.",explain_it:"I segnali di pendenza avvertono di una discesa ripida. Usa marce basse per evitare il surriscaldamento dei freni."},
  {cat:"signs",en:"A 'Traffic Signal Ahead' sign is used when:",it:"Un segnale 'Traffic Signal Ahead' viene usato quando:",options:[{en:"Every signal must be preceded by this sign",it:"Ogni semaforo deve essere preceduto da questo segnale"},{en:"A signal may be hard to see in time to stop",it:"Un semaforo potrebbe essere difficile da vedere in tempo per fermarsi"},{en:"The upcoming signal is always red",it:"Il semaforo in avanti \u00e8 sempre rosso"},{en:"This sign marks school signals only",it:"Questo segnale indica solo i semafori scolastici"}],correct:1,explain_en:"Traffic Signal Ahead signs warn where a signal may be hard to see \u2014 on a curve or after a hill.",explain_it:"I segnali Traffic Signal Ahead vengono posti dove un semaforo potrebbe essere difficile da vedere \u2014 in curva o dopo una salita."},
  {cat:"signs",en:"A 'No Trucks' sign looks like:",it:"Un segnale 'No Trucks' appare come:",options:[{en:"A yellow diamond with a truck",it:"Un rombo giallo con un camion"},{en:"A white circle with a truck and a red slash",it:"Un cerchio bianco con un camion e una barra rossa"},{en:"A brown rectangle with a truck",it:"Un rettangolo marrone con un camion"},{en:"A red octagon with a truck",it:"Un ottagono rosso con un camion"}],correct:1,explain_en:"Prohibition signs use a white circle with a red diagonal slash. Truck + red slash = no trucks.",explain_it:"I segnali di divieto usano un cerchio bianco con barra rossa diagonale. Camion + barra rossa = camion vietati."},
  {cat:"signs",en:"A two opposing-arrows diamond sign means:",it:"Un segnale a rombo con due frecce opposte significa:",options:[{en:"Two-way traffic ahead",it:"Traffico bidirezionale in avanti"},{en:"Divided highway ahead",it:"Autostrada divisa in avanti"},{en:"Passing lane begins",it:"Inizia una corsia di sorpasso"},{en:"Road narrows to one lane",it:"La strada si restringe a una corsia"}],correct:0,explain_en:"A diamond with two opposing arrows warns of two-way traffic ahead after a one-way section.",explain_it:"Un rombo con due frecce opposte avverte di traffico bidirezionale in avanti dopo una sezione a senso unico."},
  {cat:"signs",en:"A 'Speed Limit Ahead' sign means:",it:"Un segnale 'Speed Limit Ahead' significa:",options:[{en:"Current speed limit continues",it:"Il limite di velocit\u00e0 corrente continua"},{en:"A new speed limit will take effect \u2014 begin adjusting",it:"Un nuovo limite entrer\u00e0 in vigore \u2014 inizia ad adeguare la velocit\u00e0"},{en:"Speed limit is temporarily removed",it:"Il limite \u00e8 temporaneamente rimosso"},{en:"Advisory speed for a curve",it:"Velocit\u00e0 consigliata per una curva"}],correct:1,explain_en:"Speed Limit Ahead gives advance notice of an upcoming speed change so drivers can adjust.",explain_it:"Speed Limit Ahead d\u00e0 avviso anticipato di un cambio di velocit\u00e0 imminente cos\u00ec i conducenti possono adeguarsi."},
  {cat:"signs",en:"A 'School Bus Stop Ahead' sign means:",it:"Un segnale 'School Bus Stop Ahead' significa:",options:[{en:"A school zone begins",it:"Inizia una zona scolastica"},{en:"Be prepared to stop \u2014 school buses may be loading/unloading children",it:"Preparati a fermarti \u2014 gli scuolabus potrebbero caricare/scaricare bambini"},{en:"No passing for the next mile",it:"Nessun sorpasso per il prossimo miglio"},{en:"Reduce speed to 15 mph",it:"Ridurre la velocit\u00e0 a 15 mph"}],correct:1,explain_en:"School Bus Stop Ahead warns drivers to be prepared to stop for a loading/unloading school bus.",explain_it:"School Bus Stop Ahead avverte i conducenti di prepararsi a fermarsi per uno scuolabus che carica/scarica."},
  {cat:"signs",en:"Advisory speed signs (yellow plaques below speed limit signs) are:",it:"I segnali di velocit\u00e0 consigliata (targhe gialle sotto i segnali di limite) sono:",options:[{en:"Legally enforceable minimum speeds",it:"Velocit\u00e0 minime legalmente applicabili"},{en:"Recommended safe speeds for a curve or condition \u2014 not legally binding",it:"Velocit\u00e0 sicure consigliate per una curva o condizione \u2014 non vincolanti legalmente"},{en:"School zone speed limits",it:"Limiti di velocit\u00e0 delle zone scolastiche"},{en:"Night-only speed limits",it:"Limiti solo notturni"}],correct:1,explain_en:"Advisory speed signs show recommended safe speeds for specific curves or conditions. Not legally enforceable but ignoring them raises crash risk.",explain_it:"I segnali di velocit\u00e0 consigliata mostrano velocit\u00e0 sicure per curve o condizioni specifiche. Non legalmente vincolanti ma ignorarli aumenta il rischio."},
  {cat:"signs",en:"A sign with a truck and wavy lines underneath means:",it:"Un segnale con un camion e linee ondulate sotto significa:",options:[{en:"Trucks must use right lane",it:"I camion devono usare la corsia destra"},{en:"Road condition is dangerous for high-profile vehicles",it:"Le condizioni stradali sono pericolose per i veicoli alti"},{en:"No trucks allowed",it:"Camion non consentiti"},{en:"Truck weigh station ahead",it:"Stazione di pesatura in avanti"}],correct:1,explain_en:"This sign warns of a condition (sharp curve, crosswinds) particularly dangerous for high-profile vehicles like trucks.",explain_it:"Questo segnale avverte di una condizione particolarmente pericolosa per i veicoli alti come i camion."},
  {cat:"laws",en:"Florida's default speed limit on unpaved roads is:",it:"Il limite predefinito in Florida sulle strade non asfaltate \u00e8:",options:[{en:"25 mph",it:"25 mph"},{en:"35 mph",it:"35 mph"},{en:"45 mph",it:"45 mph"},{en:"55 mph",it:"55 mph"}],correct:0,explain_en:"Florida sets a 25 mph default on unpaved roads unless otherwise posted.",explain_it:"La Florida fissa 25 mph di default sulle strade non asfaltate salvo diversa indicazione."},
  {cat:"laws",en:"Speed limit in a Florida municipal park is:",it:"Il limite di velocit\u00e0 in un parco municipale in Florida \u00e8:",options:[{en:"10 mph",it:"10 mph"},{en:"15 mph",it:"15 mph"},{en:"20 mph",it:"20 mph"},{en:"25 mph",it:"25 mph"}],correct:1,explain_en:"The default speed limit in a municipal park is 15 mph in Florida unless otherwise posted.",explain_it:"Il limite predefinito in un parco municipale \u00e8 15 mph in Florida salvo diversa indicazione."},
  {cat:"laws",en:"When is it legal to exceed the posted speed limit in Florida?",it:"Quando \u00e8 legale superare il limite segnalato in Florida?",options:[{en:"When passing another vehicle",it:"Quando si sorpassa un altro veicolo"},{en:"When keeping up with traffic flow",it:"Quando si mantiene il flusso del traffico"},{en:"Never \u2014 posted limits are the maximum allowed",it:"Mai \u2014 i limiti segnalati sono il massimo consentito"},{en:"On highways with no traffic",it:"In autostrada senza traffico"}],correct:2,explain_en:"Posted speed limits are always the maximum. Driving above them is illegal even to pass or keep up with traffic.",explain_it:"I limiti segnalati sono sempre il massimo. Superarli \u00e8 sempre illegale anche per sorpassare o mantenere il flusso."},
  {cat:"laws",en:"You must always obey a traffic control officer even if their instructions conflict with:",it:"Devi sempre obbedire a un agente di controllo anche se le sue istruzioni confliggono con:",options:[{en:"The law",it:"La legge"},{en:"Traffic signs and signals",it:"Segnali stradali e semafori"},{en:"GPS instructions",it:"Le istruzioni del GPS"},{en:"Your employer's instructions",it:"Le istruzioni del datore di lavoro"}],correct:1,explain_en:"A traffic officer's directions take precedence over traffic signals and signs.",explain_it:"Le indicazioni di un agente hanno la precedenza sui segnali stradali e i semafori."},
  {cat:"laws",en:"Florida requires headlights from sunset to sunrise AND:",it:"La Florida richiede i fari dal tramonto all'alba E:",options:[{en:"Only when fog is present",it:"Solo quando c'\u00e8 nebbia"},{en:"Any time wipers are in continuous use",it:"Ogni volta che i tergicristalli sono in uso continuo"},{en:"Only on highways",it:"Solo in autostrada"},{en:"Only in school zones",it:"Solo nelle zone scolastiche"}],correct:1,explain_en:"Florida requires headlights from sunset to sunrise AND any time windshield wipers are in continuous use.",explain_it:"La Florida richiede i fari dal tramonto all'alba E ogni volta che i tergicristalli sono in uso continuo."},
  {cat:"laws",en:"Parking on a sidewalk in Florida is:",it:"Parcheggiare su un marciapiede in Florida \u00e8:",options:[{en:"Allowed if it doesn't block pedestrians",it:"Consentito se non blocca i pedoni"},{en:"Always prohibited",it:"Sempre vietato"},{en:"Allowed up to 15 minutes",it:"Consentito fino a 15 minuti"},{en:"Allowed for motorcycles only",it:"Consentito solo per le motociclette"}],correct:1,explain_en:"Parking on a sidewalk is always prohibited. Sidewalks must remain unobstructed for pedestrians.",explain_it:"Parcheggiare su un marciapiede \u00e8 sempre vietato. I marciapiedi devono rimanere liberi per i pedoni."},
  {cat:"laws",en:"You must not park within how many feet of a crosswalk at an intersection?",it:"Non puoi parcheggiare entro quanti piedi da un passaggio pedonale a un incrocio?",options:[{en:"10 feet",it:"10 piedi"},{en:"15 feet",it:"15 piedi"},{en:"20 feet",it:"20 piedi"},{en:"30 feet",it:"30 piedi"}],correct:2,explain_en:"You may not park within 20 feet of a crosswalk. This ensures visibility for pedestrians and drivers.",explain_it:"Non puoi parcheggiare entro 20 piedi (6 m) da un passaggio pedonale. Garantisce la visibilit\u00e0."},
  {cat:"laws",en:"The 'basic speed rule' in Florida means:",it:"La 'regola di velocit\u00e0 di base' in Florida significa:",options:[{en:"Always drive at exactly the posted limit",it:"Guida sempre esattamente al limite segnalato"},{en:"Never drive faster than safe for current conditions",it:"Non guidare mai pi\u00f9 veloce di quanto sicuro per le condizioni attuali"},{en:"The posted limit applies with no exceptions",it:"Il limite segnalato si applica senza eccezioni"},{en:"Drive 5 mph below the limit always",it:"Guida sempre 5 mph sotto il limite"}],correct:1,explain_en:"Florida's basic speed rule: drive at a speed reasonable and prudent for current conditions \u2014 even below the posted limit.",explain_it:"La regola di velocit\u00e0 di base: guida a una velocit\u00e0 ragionevole per le condizioni attuali \u2014 anche sotto il limite segnalato."},
  {cat:"laws",en:"In Florida, a properly escorted funeral procession:",it:"In Florida, un corteo funebre con scorta adeguata:",options:[{en:"Must obey all traffic signals",it:"Deve rispettare tutti i segnali"},{en:"Has right-of-way through intersections as a unit",it:"Ha la precedenza agli incroci come un'unit\u00e0"},{en:"Has no special rights",it:"Non ha diritti speciali"},{en:"May only travel on roads with no traffic signals",it:"Pu\u00f2 percorrere solo strade senza semafori"}],correct:1,explain_en:"A properly escorted funeral procession has right-of-way at intersections. Don't cut into a procession.",explain_it:"Un corteo funebre con scorta adeguata ha la precedenza agli incroci. Non tagliare un corteo."},
  {cat:"laws",en:"On an undivided two-lane road, when a school bus has its stop arm extended, ALL traffic must:",it:"Su una strada a due corsie non divisa con lo scuolabus e il braccio di stop esteso, TUTTO il traffico deve:",options:[{en:"Slow to 15 mph",it:"Rallentare a 15 mph"},{en:"Stop \u2014 both directions",it:"Fermarsi \u2014 in entrambe le direzioni"},{en:"Yield but not stop",it:"Cedere ma non fermarsi"},{en:"Stop only if children are crossing",it:"Fermarsi solo se i bambini attraversano"}],correct:1,explain_en:"On any undivided two-lane road, ALL traffic in BOTH directions must stop for a school bus with red lights and stop arm.",explain_it:"Su qualsiasi strada a due corsie non divisa, TUTTO il traffico in ENTRAMBE le direzioni deve fermarsi per lo scuolabus."},
  {cat:"laws",en:"In Florida you may only drive in a center left-turn lane when:",it:"In Florida puoi guidare nella corsia centrale di svolta sinistra solo quando:",options:[{en:"You want to avoid slow traffic",it:"Vuoi evitare il traffico lento"},{en:"Preparing for or completing a left turn",it:"Ti prepari o completi una svolta a sinistra"},{en:"Passing a stopped vehicle",it:"Sorpassi un veicolo fermo"},{en:"Emergency vehicles only",it:"Solo veicoli di emergenza"}],correct:1,explain_en:"Center left-turn lanes may only be used to prepare for or complete a left turn. They are not travel lanes.",explain_it:"Le corsie centrali di svolta sinistra possono essere usate solo per prepararsi o completare una svolta a sinistra."},
  {cat:"laws",en:"Florida's '3-Foot Rule' requires maintaining how much clearance when passing a bicycle?",it:"La 'Regola dei 3 Piedi' della Florida richiede quanto spazio quando si sorpassa una bicicletta?",options:[{en:"1 foot",it:"1 piede"},{en:"2 feet",it:"2 piedi"},{en:"3 feet",it:"3 piedi"},{en:"5 feet",it:"5 piedi"}],correct:2,explain_en:"Florida's 3-Foot Rule requires at least 3 feet clearance when passing a bicycle. Change lanes if the road is too narrow.",explain_it:"La Regola dei 3 Piedi della Florida richiede almeno 90 cm di spazio quando si sorpassa una bicicletta."},
  {cat:"laws",en:"Bicyclists on Florida public roads must:",it:"I ciclisti sulle strade pubbliche della Florida devono:",options:[{en:"Always ride on the sidewalk",it:"Sempre andare sul marciapiede"},{en:"Obey the same traffic laws as motor vehicles",it:"Rispettare le stesse leggi dei veicoli a motore"},{en:"Have no legal requirements",it:"Non avere requisiti legali"},{en:"Only ride during daylight",it:"Andare in bicicletta solo di giorno"}],correct:1,explain_en:"Bicyclists on Florida public roads must follow all the same traffic laws as motor vehicle operators.",explain_it:"I ciclisti sulle strade pubbliche devono seguire tutte le stesse leggi dei conducenti di veicoli a motore."},
  {cat:"laws",en:"Florida requires cyclists under what age to wear a helmet?",it:"La Florida richiede ai ciclisti sotto quale et\u00e0 di indossare un casco?",options:[{en:"12",it:"12"},{en:"14",it:"14"},{en:"16",it:"16"},{en:"18",it:"18"}],correct:2,explain_en:"Florida law requires all cyclists under 16 to wear an approved bicycle helmet on public roads.",explain_it:"La legge della Florida richiede a tutti i ciclisti under 16 di indossare un casco approvato su strade pubbliche."},
  {cat:"laws",en:"Regarding flooded roadways in Florida, you should:",it:"Riguardo alle strade allagate in Florida, dovresti:",options:[{en:"Drive through slowly",it:"Attraversare lentamente"},{en:"Turn around \u2014 never drive through flooded roads",it:"Girare indietro \u2014 non guidare mai attraverso strade allagate"},{en:"Speed up to cross fast",it:"Accelerare per attraversare velocemente"},{en:"Flash lights and honk",it:"Lampeggiare e suonare"}],correct:1,explain_en:"'Turn Around, Don't Drown' \u2014 just 6 inches of water can knock a person down; 2 feet can float a car.",explain_it:"'Gira indietro, non annegare' \u2014 solo 15 cm d'acqua possono abbattere una persona; 60 cm possono far galleggiare un'auto."},
  {cat:"laws",en:"Riding in the cargo bed of a pickup truck on Florida public roads is:",it:"Viaggiare nel cassone di un pickup sulle strade pubbliche della Florida \u00e8:",options:[{en:"Legal for adults over 18",it:"Legale per gli adulti sopra i 18 anni"},{en:"Always illegal",it:"Sempre illegale"},{en:"Legal if holding on",it:"Legale se ci si tiene"},{en:"Legal at speeds under 35 mph",it:"Legale a velocit\u00e0 sotto 35 mph"}],correct:1,explain_en:"Florida prohibits any person from riding in the cargo bed of a pickup truck on public roads \u2014 always illegal.",explain_it:"La Florida vieta a qualsiasi persona di viaggiare nel cassone di un pickup su strade pubbliche \u2014 sempre illegale."},
  {cat:"laws",en:"A completely dark traffic signal (all lights out) must be treated as:",it:"Un semaforo completamente spento deve essere trattato come:",options:[{en:"A yield sign",it:"Un segnale di precedenza"},{en:"A four-way stop",it:"Un incrocio a quattro vie con stop"},{en:"An uncontrolled intersection",it:"Un incrocio non controllato"},{en:"Normal driving \u2014 signal is temporary",it:"Guida normale \u2014 il semaforo \u00e8 temporaneo"}],correct:1,explain_en:"A completely dark signal = 4-way stop. All vehicles stop and yield in order of arrival.",explain_it:"Un semaforo completamente spento = incrocio a quattro via con stop. Tutti si fermano e cedono in ordine di arrivo."},
  {cat:"laws",en:"In Florida, U-turns in business districts are legal only:",it:"In Florida, le inversioni di marcia nei quartieri commerciali sono legali solo:",options:[{en:"Never",it:"Mai"},{en:"At intersections or median openings not prohibited by signs",it:"Agli incroci o aperture nelle mediane non vietate da segnali"},{en:"Anytime if no traffic is visible",it:"In qualsiasi momento se non \u00e8 visibile traffico"},{en:"Only from alleys or driveways",it:"Solo da vicoli o vialetti"}],correct:1,explain_en:"In business districts, U-turns are only legal at intersections or median openings where not prohibited by signs.",explain_it:"Nei quartieri commerciali, le inversioni sono legali solo agli incroci o aperture nelle mediane dove non vietate."},
  {cat:"laws",en:"On a multi-lane highway in Florida, you should normally drive in:",it:"Su un'autostrada a pi\u00f9 corsie in Florida, normalmente dovresti guidare:",options:[{en:"The left (fast) lane",it:"La corsia sinistra (veloce)"},{en:"The right lane unless passing or turning left",it:"La corsia destra a meno che non si stia sorpassando o svoltando a sinistra"},{en:"Any lane equally",it:"Qualsiasi corsia allo stesso modo"},{en:"The middle lane for safety",it:"La corsia centrale per sicurezza"}],correct:1,explain_en:"Florida law: stay in the right lane for normal travel. Use the left lane only for passing or turning left.",explain_it:"Legge della Florida: rimani nella corsia destra per la guida normale. Usa la sinistra solo per sorpassare o svoltare."},
  {cat:"laws",en:"What does Florida law require for turn signals when changing lanes?",it:"Cosa richiede la legge della Florida per i segnali di svolta quando si cambia corsia?",options:[{en:"Only on highways",it:"Solo in autostrada"},{en:"Always \u2014 on all roads before every lane change",it:"Sempre \u2014 su tutte le strade prima di ogni cambio di corsia"},{en:"Only when other vehicles are nearby",it:"Solo quando altri veicoli sono nelle vicinanze"},{en:"Only when turning, not lane changing",it:"Solo quando svolti, non quando cambi corsia"}],correct:1,explain_en:"Florida requires turn signals for every lane change and turn, on all roads, regardless of traffic presence.",explain_it:"La Florida richiede segnali di svolta per ogni cambio di corsia e svolta, su tutte le strade."},
  {cat:"laws",en:"Florida prohibits wearing headphones in both ears while driving because:",it:"La Florida vieta di indossare cuffie in entrambe le orecchie durante la guida perch\u00e9:",options:[{en:"It is always legal",it:"\u00c8 sempre legale"},{en:"It impairs the ability to hear sirens and traffic sounds",it:"Compromette la capacit\u00e0 di sentire sirene e rumori del traffico"},{en:"Only prohibited for CDL holders",it:"Vietato solo per i titolari CDL"},{en:"Only prohibited for teen drivers",it:"Vietato solo per i conducenti adolescenti"}],correct:1,explain_en:"Florida prohibits wearing a headset in both ears. One ear is permitted for hands-free communication.",explain_it:"La Florida vieta di indossare cuffie in entrambe le orecchie. Un orecchio \u00e8 consentito per la comunicazione hands-free."},
  {cat:"laws",en:"You are a Florida resident and must get a Florida license if you:",it:"Sei residente in Florida e devi ottenere la patente Florida se:",options:[{en:"Visit for more than 30 days",it:"Visiti per pi\u00f9 di 30 giorni"},{en:"Accept employment, register to vote, enroll children in school, or reside 6+ consecutive months",it:"Accetti lavoro, ti registri per votare, iscrivi figli a scuola o risiedi 6+ mesi consecutivi"},{en:"Own property in Florida",it:"Possiedi propriet\u00e0 in Florida"},{en:"File a state tax return",it:"Presenti una dichiarazione fiscale statale"}],correct:1,explain_en:"You are a Florida resident if you accept employment, register to vote, enroll children in school, or reside 6+ consecutive months.",explain_it:"Sei residente in Florida se accetti lavoro, ti registri per votare, iscrivi figli a scuola o risiedi 6+ mesi consecutivi."},
  {cat:"laws",en:"Florida vehicles towing a trailer on a 3+ lane limited-access highway must stay out of:",it:"I veicoli che trainano un rimorchio su un'autostrada a 3+ corsie devono evitare:",options:[{en:"The right lane",it:"La corsia destra"},{en:"The far-left lane",it:"La corsia pi\u00f9 a sinistra"},{en:"The center lane",it:"La corsia centrale"},{en:"Any lane \u2014 towing is prohibited",it:"Qualsiasi corsia \u2014 il traino \u00e8 vietato"}],correct:1,explain_en:"Vehicles towing another vehicle or trailer are prohibited from using the far-left lane on 3+ lane limited-access highways.",explain_it:"I veicoli che trainano un rimorchio hanno il divieto di usare la corsia pi\u00f9 a sinistra sulle autostrade a 3+ corsie."},
  {cat:"laws",en:"A yellow traffic light means you should:",it:"Un semaforo giallo significa che dovresti:",options:[{en:"Speed up to clear the intersection",it:"Accelerare per liberare l'incrocio"},{en:"Stop if safe to do so",it:"Fermarti se sicuro farlo"},{en:"Always stop",it:"Fermarti sempre"},{en:"Slow slightly and always continue",it:"Rallentare leggermente e continuare sempre"}],correct:1,explain_en:"Yellow means the signal is about to turn red. Stop if safe. If too close to stop safely, continue \u2014 but don't speed up.",explain_it:"Il giallo significa che il semaforo sta per diventare rosso. Fermati se sicuro. Se troppo vicino, continua \u2014 ma non accelerare."},
  {cat:"laws",en:"Florida's red light camera law allows:",it:"La legge delle telecamere per il rosso della Florida consente:",options:[{en:"Only police to issue red-light citations",it:"Solo alla polizia di emettere citazioni per il rosso"},{en:"Automated cameras to capture and issue citations for red-light violations",it:"Telecamere automatizzate di catturare ed emettere citazioni per le violazioni al rosso"},{en:"Red-light cameras are banned statewide",it:"Le telecamere per il rosso sono vietate in tutto lo stato"},{en:"Cameras record only \u2014 no fines",it:"Le telecamere registrano solo \u2014 nessuna multa"}],correct:1,explain_en:"Florida allows local governments to use automated red-light cameras. Fines apply to the registered vehicle owner.",explain_it:"La Florida consente l'uso di telecamere automatizzate per i semafori rossi. Le multe si applicano al proprietario registrato."},
  {cat:"laws",en:"School buses and vehicles transporting hazardous materials must stop at:",it:"Gli scuolabus e i veicoli con materiali pericolosi devono fermarsi a:",options:[{en:"Only active (signaling) crossings",it:"Solo i passaggi attivi (con segnali)"},{en:"ALL railroad crossings even if no train is present",it:"TUTTI i passaggi a livello anche se non c'\u00e8 nessun treno"},{en:"Only crossings with gates",it:"Solo i passaggi con sbarre"},{en:"Crossings with flashing lights only",it:"Solo i passaggi con luci lampeggianti"}],correct:1,explain_en:"School buses and hazmat vehicles must stop at ALL railroad crossings, even without active signals.",explain_it:"Gli scuolabus e i veicoli con materiali pericolosi devono fermarsi a TUTTI i passaggi a livello, anche senza segnali attivi."},
  {cat:"laws",en:"Florida drivers must always carry:",it:"I conducenti in Florida devono sempre portare:",options:[{en:"Only vehicle registration",it:"Solo la registrazione del veicolo"},{en:"Driver's license, vehicle registration, and proof of insurance",it:"Patente, registrazione del veicolo e prova dell'assicurazione"},{en:"Only driver's license",it:"Solo la patente"},{en:"Passport, vehicle title, and insurance",it:"Passaporto, titolo del veicolo e assicurazione"}],correct:1,explain_en:"Florida requires: valid driver's license, current vehicle registration, and proof of insurance (PIP and PDL).",explain_it:"La Florida richiede: patente valida, registrazione del veicolo aggiornata e prova dell'assicurazione (PIP e PDL)."},
  {cat:"laws",en:"Who has right-of-way between a vehicle going straight and a vehicle turning?",it:"Chi ha la precedenza tra un veicolo che va dritto e uno che svolta?",options:[{en:"The turning vehicle",it:"Il veicolo che svolta"},{en:"The vehicle going straight",it:"Il veicolo che va dritto"},{en:"The first to reach the intersection",it:"Il primo a raggiungere l'incrocio"},{en:"The larger vehicle",it:"Il veicolo pi\u00f9 grande"}],correct:1,explain_en:"A vehicle going straight always has right-of-way over a vehicle making a turn at the same intersection.",explain_it:"Un veicolo che va dritto ha sempre la precedenza su un veicolo che svolta allo stesso incrocio."},
  {cat:"laws",en:"Florida's minimum fine for illegally parking in a handicapped spot is:",it:"La multa minima della Florida per parcheggio illegale in spazio disabili \u00e8:",options:[{en:"$50",it:"$50"},{en:"$100",it:"$100"},{en:"$250",it:"$250"},{en:"$500",it:"$500"}],correct:2,explain_en:"Florida imposes a minimum $250 fine for illegally parking in a disabled parking space.",explain_it:"La Florida impone una multa minima di $250 per il parcheggio illegale in uno spazio per disabili."},
  {cat:"laws",en:"If you strike an unattended parked vehicle, Florida law requires you to:",it:"Se colpisci un veicolo parcheggiato incustodito, la legge della Florida richiede di:",options:[{en:"Leave only if damage is minor",it:"Andarsene solo se il danno \u00e8 minore"},{en:"Leave a written note with your contact information",it:"Lasciare un biglietto scritto con le tue informazioni di contatto"},{en:"Call police and wait",it:"Chiamare la polizia e aspettare"},{en:"Take photos and send to insurance only",it:"Scattare foto e inviare solo all'assicurazione"}],correct:1,explain_en:"If you strike an unattended vehicle, locate the owner or leave a note with name, address, and registration.",explain_it:"Se colpisci un veicolo incustodito, rintraccia il proprietario o lascia un biglietto con nome, indirizzo e targa."},
  {cat:"laws",en:"Florida requires you to yield to pedestrians at crosswalks:",it:"La Florida richiede di cedere la precedenza ai pedoni ai passaggi pedonali:",options:[{en:"Only if marked with white lines",it:"Solo se segnalati con linee bianche"},{en:"At all crosswalks \u2014 marked or not",it:"A tutti i passaggi pedonali \u2014 segnalati o meno"},{en:"Only at signalized intersections",it:"Solo agli incroci semaforizzati"},{en:"Main road vehicles have priority over pedestrians",it:"I veicoli sulla strada principale hanno priorit\u00e0 sui pedoni"}],correct:1,explain_en:"Florida law requires yielding to pedestrians at all crosswalks \u2014 marked or unmarked. Every intersection corner is legally a crosswalk.",explain_it:"La legge della Florida richiede di cedere a tutti i passaggi pedonali \u2014 segnalati o meno. Ogni angolo di incrocio \u00e8 legalmente un passaggio pedonale."},
  {cat:"laws",en:"When must you enter an intersection before it turns red?",it:"Quando devi entrare in un incrocio prima che diventi rosso?",options:[{en:"Whenever there is a green light",it:"Ogni volta che c'\u00e8 il verde"},{en:"Only when you can completely clear it before the light changes",it:"Solo quando puoi liberarlo completamente prima che il semaforo cambi"},{en:"Always \u2014 green means go",it:"Sempre \u2014 il verde significa vai"},{en:"Stop briefly at every green light",it:"Fermarsi brevemente a ogni verde"}],correct:1,explain_en:"Only enter an intersection if you can clear it completely before cross-traffic gets a green. Blocking intersections is illegal.",explain_it:"Entra in un incrocio solo se puoi liberarlo completamente prima che il traffico trasversale riceva il verde. Bloccare \u00e8 illegale."},
  {cat:"laws",en:"Florida's 'aggressive careless driving' is defined as:",it:"La 'guida aggressiva negligente' in Florida \u00e8 definita come:",options:[{en:"Driving 10+ mph over the limit",it:"Guidare 10+ mph oltre il limite"},{en:"Three or more moving violations in one incident threatening others",it:"Tre o pi\u00f9 violazioni in movimento in un singolo incidente che minacciano gli altri"},{en:"Passing on the right on a two-lane road",it:"Sorpassare a destra su una strada a due corsie"},{en:"Driving below the minimum speed",it:"Guidare sotto il limite minimo"}],correct:1,explain_en:"Aggressive careless driving: 3+ moving violations in a single incident that endangers others. Enhanced penalties apply.",explain_it:"Guida aggressiva negligente: 3+ violazioni in movimento in un singolo incidente che mette in pericolo gli altri. Penalit\u00e0 maggiorate."},
  {cat:"laws",en:"Lane splitting by motorcycles in Florida is:",it:"Il lane splitting delle motociclette in Florida \u00e8:",options:[{en:"Legal if traffic is stopped",it:"Legale se il traffico \u00e8 fermo"},{en:"Legal under 30 mph",it:"Legale sotto i 30 mph"},{en:"Illegal \u2014 motorcycles must stay within a single lane",it:"Illegale \u2014 le motociclette devono rimanere all'interno di una singola corsia"},{en:"Legal only on highways",it:"Legale solo in autostrada"}],correct:2,explain_en:"Lane splitting is illegal in Florida. Motorcycles must occupy a full lane and follow the same rules as other vehicles.",explain_it:"Il lane splitting \u00e8 illegale in Florida. Le motociclette devono occupare un'intera corsia e seguire le stesse regole."},
  {cat:"laws",en:"At a yield sign you must:",it:"A un segnale di precedenza devi:",options:[{en:"Always come to a full stop",it:"Sempre fare un arresto completo"},{en:"Slow and yield to conflicting traffic \u2014 stop only if necessary",it:"Rallentare e cedere al traffico in conflitto \u2014 fermarsi solo se necessario"},{en:"Maintain speed and yield only in heavy traffic",it:"Mantenere la velocit\u00e0 e cedere solo nel traffico intenso"},{en:"Flash headlights and proceed",it:"Lampeggiare i fari e procedere"}],correct:1,explain_en:"At a yield sign, slow and be prepared to stop. If clear, proceed without a full stop.",explain_it:"A un segnale di precedenza, rallenta e preparati a fermarti. Se libero, puoi procedere senza fermarti completamente."},
  {cat:"laws",en:"Florida drivers must remain in the right lane EXCEPT when:",it:"I conducenti in Florida devono rimanere nella corsia destra TRANNE quando:",options:[{en:"During rush hour",it:"Durante le ore di punta"},{en:"Overtaking another vehicle or turning left",it:"Sorpassano un altro veicolo o svoltano a sinistra"},{en:"Always \u2014 trucks must always stay right",it:"Sempre \u2014 i camion devono sempre rimanere a destra"},{en:"Carrying hazardous materials",it:"Trasportano materiali pericolosi"}],correct:1,explain_en:"Trucks on multi-lane roads must use the right lane except to overtake or turn left.",explain_it:"I camion su strade a pi\u00f9 corsie devono usare la corsia destra tranne per sorpassare o svoltare a sinistra."},
  {cat:"laws",en:"Florida law on driving with a learner's permit requires the supervising driver to be:",it:"La legge della Florida sulla guida con il permesso per principianti richiede che il supervisore sia:",options:[{en:"A parent only",it:"Solo un genitore"},{en:"A licensed driver at least 21 years old seated in the front",it:"Un conducente patentato di almeno 21 anni seduto davanti"},{en:"Any licensed adult over 18",it:"Qualsiasi adulto patentato sopra i 18 anni"},{en:"A certified driving instructor only",it:"Solo un istruttore di guida certificato"}],correct:1,explain_en:"Florida learner's permit: the supervising driver must be a licensed driver at least 21 years old seated in the front passenger seat.",explain_it:"Permesso per principianti Florida: il supervisore deve essere un conducente patentato di almeno 21 anni seduto nel sedile anteriore."},
  {cat:"laws",en:"Florida requires learner's permit holders under 18 to hold the permit for at least:",it:"La Florida richiede ai titolari di permesso per principianti under 18 di tenerlo per almeno:",options:[{en:"30 days",it:"30 giorni"},{en:"6 months",it:"6 mesi"},{en:"12 months",it:"12 mesi"},{en:"3 months",it:"3 mesi"}],correct:2,explain_en:"Florida requires permit holders under 18 to hold the permit for at least 12 months before applying for a provisional license.",explain_it:"La Florida richiede ai titolari di permesso under 18 di tenerlo per almeno 12 mesi prima di richiedere la patente provvisoria."},
  {cat:"laws",en:"When an emergency vehicle approaches with lights and siren, Florida law requires you to:",it:"Quando si avvicina un veicolo di emergenza con luci e sirena, la legge Florida richiede di:",options:[{en:"Speed up and clear the road ahead",it:"Accelerare e liberare la strada davanti"},{en:"Pull to the right and stop \u2014 clear intersection first if in one",it:"Accostare a destra e fermarsi \u2014 libera prima l'incrocio se sei in uno"},{en:"Stop immediately where you are",it:"Fermarsi immediatamente dove sei"},{en:"Reduce speed to 20 mph",it:"Ridurre la velocit\u00e0 a 20 mph"}],correct:1,explain_en:"Pull to the right and stop. If in an intersection, clear it first, then pull right. Don't stop mid-intersection.",explain_it:"Accosta a destra e fermati. Se sei in un incrocio, liberalo prima, poi accosta a destra. Non fermarti a met\u00e0 incrocio."},
  {cat:"laws",en:"Florida's distracted driving law primarily targets:",it:"La legge sulla guida distratta della Florida si rivolge principalmente a:",options:[{en:"Eating while driving",it:"Mangiare durante la guida"},{en:"Manual use of wireless communications devices (texting, typing)",it:"Uso manuale di dispositivi di comunicazione wireless (messaggi, digitazione)"},{en:"Talking to passengers",it:"Parlare con i passeggeri"},{en:"Using GPS",it:"Usare il GPS"}],correct:1,explain_en:"Florida's distracted driving law focuses on manual use of wireless devices (smartphones) while driving.",explain_it:"La legge sulla guida distratta si concentra sull'uso manuale di dispositivi wireless (smartphone) durante la guida."},
  {cat:"laws",en:"In Florida, if a crash involves property damage only, you should:",it:"In Florida, se un incidente coinvolge solo danni materiali, dovresti:",options:[{en:"Leave \u2014 minor damage requires no action",it:"Andarsene \u2014 i danni minori non richiedono azioni"},{en:"Move vehicles to safety and exchange information",it:"Spostare i veicoli in sicurezza e scambiare le informazioni"},{en:"Wait for police regardless of traffic",it:"Aspettare la polizia indipendentemente dal traffico"},{en:"Take photos and leave without exchanging info",it:"Scattare foto e andarsene senza scambiare informazioni"}],correct:1,explain_en:"If safe, move vehicles out of traffic to prevent further crashes, then exchange information.",explain_it:"Se sicuro, sposta i veicoli fuori dal traffico per prevenire ulteriori incidenti, poi scambia le informazioni."},
  {cat:"laws",en:"Double parking in Florida is:",it:"Il doppio parcheggio in Florida \u00e8:",options:[{en:"Allowed briefly for unloading",it:"Consentito brevemente per lo scarico"},{en:"Prohibited \u2014 it blocks the traffic lane",it:"Vietato \u2014 blocca la corsia di traffico"},{en:"Allowed for commercial vehicles with hazard lights",it:"Consentito per i veicoli commerciali con luci di pericolo"},{en:"Allowed for up to 10 minutes",it:"Consentito fino a 10 minuti"}],correct:1,explain_en:"Double parking is prohibited because it blocks a travel lane and creates hazards for other drivers.",explain_it:"Il doppio parcheggio \u00e8 vietato perch\u00e9 blocca una corsia di marcia e crea pericoli."},
  {cat:"laws",en:"You must not park within how many feet of a driveway?",it:"Non puoi parcheggiare entro quanti piedi da un vialetto privato?",options:[{en:"5 feet",it:"5 piedi"},{en:"10 feet",it:"10 piedi"},{en:"15 feet",it:"15 piedi"},{en:"20 feet",it:"20 piedi"}],correct:0,explain_en:"The standard clearance is 5 feet on either side of a driveway. Never block public or private driveways.",explain_it:"Lo spazio standard \u00e8 5 piedi (1,5 m) su entrambi i lati di un vialetto. Non bloccare mai vialetti."},
  {cat:"laws",en:"Florida's minimum expressway speed that may be required is:",it:"La velocit\u00e0 minima in autostrada che pu\u00f2 essere richiesta in Florida \u00e8:",options:[{en:"30 mph",it:"30 mph"},{en:"40 mph",it:"40 mph"},{en:"45 mph",it:"45 mph"},{en:"50 mph",it:"50 mph"}],correct:2,explain_en:"Florida may post minimum speed limits of 45 mph on limited-access highways.",explain_it:"La Florida pu\u00f2 indicare limiti di velocit\u00e0 minimi di 45 mph sulle autostrade ad accesso limitato."},
  {cat:"laws",en:"What does Florida's 'Slow Driver Law' require slower vehicles to do?",it:"Cosa richiede la 'Legge sul Conducente Lento' della Florida ai veicoli pi\u00f9 lenti?",options:[{en:"Flash hazard lights when below the speed limit",it:"Lampeggiare le luci di pericolo quando si \u00e8 sotto il limite"},{en:"Keep right and yield to faster traffic",it:"Tenersi a destra e cedere al traffico pi\u00f9 veloce"},{en:"Pull over and stop when followed closely",it:"Accostare e fermarsi quando si \u00e8 seguiti da vicino"},{en:"Increase speed to match traffic flow",it:"Aumentare la velocit\u00e0 per adeguarsi al flusso"}],correct:1,explain_en:"Slower vehicles must stay right. Blocking the left lane even at the speed limit is illegal if faster traffic is impeded.",explain_it:"I veicoli pi\u00f9 lenti devono rimanere a destra. Bloccare la corsia sinistra \u00e8 illegale se ostacola il traffico pi\u00f9 veloce."},
  {cat:"laws",en:"Florida law requires all children under what age to be in a federally approved child restraint?",it:"La legge della Florida richiede a tutti i bambini sotto quale et\u00e0 di essere in un seggiolino approvato?",options:[{en:"3",it:"3"},{en:"4",it:"4"},{en:"5",it:"5"},{en:"6",it:"6"}],correct:2,explain_en:"Florida requires all children under 5 to be secured in a federally approved child restraint device.",explain_it:"La Florida richiede che tutti i bambini under 5 siano fissati in un dispositivo di ritenuta approvato federalmente."},
  {cat:"laws",en:"What must you do when approaching a railroad crossing with a train present?",it:"Cosa devi fare avvicinandoti a un passaggio a livello con un treno presente?",options:[{en:"Slow to 15 mph",it:"Rallentare a 15 mph"},{en:"Stop and wait for the train to pass",it:"Fermarsi e aspettare che il treno passi"},{en:"Proceed if gates are not down",it:"Procedere se le sbarre non sono abbassate"},{en:"Stop only if the train is within 500 feet",it:"Fermarsi solo se il treno \u00e8 entro 500 piedi"}],correct:1,explain_en:"Always yield to trains at railroad crossings. A train cannot stop quickly. Stop and wait regardless of gates.",explain_it:"Cedi sempre la precedenza ai treni. Un treno non pu\u00f2 fermarsi rapidamente. Fermati e aspetta indipendentemente dalle sbarre."},
  {cat:"safety",en:"The 'No-Zone' around large trucks refers to:",it:"La 'No-Zone' intorno ai camion grandi si riferisce a:",options:[{en:"Within 50 feet behind the truck",it:"Entro 15 m dietro il camion"},{en:"The four blind spots \u2014 front, rear, and both sides",it:"I quattro punti ciechi \u2014 davanti, dietro e su entrambi i lati"},{en:"Only the left side of the truck",it:"Solo il lato sinistro del camion"},{en:"Directly in front of the truck only",it:"Solo direttamente davanti al camion"}],correct:1,explain_en:"The No-Zone describes the four large blind spots around a truck: directly in front, behind, and on both sides.",explain_it:"La No-Zone descrive i quattro grandi punti ciechi intorno a un camion: davanti, dietro e su entrambi i lati."},
  {cat:"safety",en:"If a vehicle drifts toward you in your lane, you should:",it:"Se un veicolo si sposta verso di te nella tua corsia, dovresti:",options:[{en:"Speed up and swerve left",it:"Accelerare e sterzare a sinistra"},{en:"Sound horn, steer right, reduce speed",it:"Suonare il clacson, sterzare a destra, ridurre la velocit\u00e0"},{en:"Brake hard and stay in lane",it:"Frenare bruscamente e rimanere in corsia"},{en:"Flash high beams and hold your lane",it:"Lampeggiare gli abbaglianti e tenere la corsia"}],correct:1,explain_en:"If a vehicle drifts toward you: sound horn, steer right toward the shoulder, reduce speed. Avoid swerving left.",explain_it:"Se un veicolo si sposta verso di te: suona il clacson, sterza a destra verso la banchina, riduci la velocit\u00e0."},
  {cat:"safety",en:"'Highway hypnosis' is caused by:",it:"La 'ipnosi autostradale' \u00e8 causata da:",options:[{en:"High traffic density",it:"Alta densit\u00e0 di traffico"},{en:"Monotonous driving causing a trance-like state of reduced attention",it:"Guida monotona che causa uno stato simile alla trance con attenzione ridotta"},{en:"Slippery road surfaces",it:"Superfici stradali scivolose"},{en:"Reduced speed limits at night",it:"Limiti di velocit\u00e0 ridotti di notte"}],correct:1,explain_en:"Highway hypnosis: a trance-like state from monotonous driving. Eyes are open but attention is gone. Take breaks every 2 hours.",explain_it:"Ipnosi autostradale: uno stato di trance dalla guida monotona. Occhi aperti ma attenzione assente. Fai pause ogni 2 ore."},
  {cat:"safety",en:"What is the correct response if you miss your highway exit?",it:"Qual \u00e8 la risposta corretta se manchi la tua uscita in autostrada?",options:[{en:"Back up on the shoulder",it:"Fare retromarcia sulla banchina"},{en:"Continue to the next exit and turn around",it:"Continuare fino alla prossima uscita e tornare indietro"},{en:"Cross the median",it:"Attraversare la mediana"},{en:"Stop in the emergency lane",it:"Fermarsi nella corsia di emergenza"}],correct:1,explain_en:"Never reverse or make U-turns on a highway. Continue to the next exit and safely turn around.",explain_it:"Non fare mai retromarcia o inversioni in autostrada. Procedi fino alla prossima uscita e torna indietro in sicurezza."},
  {cat:"safety",en:"What is 'target fixation' in driving?",it:"Cos'\u00e8 la 'fissazione dell'obiettivo' nella guida?",options:[{en:"Using GPS to navigate precisely",it:"Usare il GPS per navigare precisamente"},{en:"Tendency to steer toward whatever you are looking at",it:"Tendenza a sterzare verso ci\u00f2 che si sta guardando"},{en:"Keeping eyes on the center of the lane",it:"Mantenere gli occhi al centro della corsia"},{en:"Watching a specific vehicle in mirrors",it:"Osservare un veicolo specifico negli specchi"}],correct:1,explain_en:"Target fixation: drivers steer toward what they focus on. In a panic, look where you WANT to go \u2014 not at the obstacle.",explain_it:"Fissazione dell'obiettivo: i conducenti sterzano verso ci\u00f2 su cui si concentrano. Nel panico, guarda dove VUOI andare."},
  {cat:"safety",en:"'Covering the brake' means:",it:"'Coprire il freno' significa:",options:[{en:"Keeping your foot on the brake at all times",it:"Tenere il piede sul freno in ogni momento"},{en:"Moving your foot over the brake pedal when anticipating a hazard",it:"Spostare il piede sopra il pedale del freno quando si anticipa un pericolo"},{en:"Applying the parking brake as backup",it:"Applicare il freno di parcheggio come supporto"},{en:"Engine braking on downhill grades",it:"Freno motore nelle discese"}],correct:1,explain_en:"Covering the brake means hovering over the brake pedal when anticipating a hazard, reducing reaction time.",explain_it:"Coprire il freno significa tenere il piede sopra il pedale del freno quando si anticipa un pericolo, riducendo il tempo di reazione."},
  {cat:"safety",en:"'Brake fade' on a long downhill is caused by:",it:"La 'brake fade' su una lunga discesa \u00e8 causata da:",options:[{en:"Moisture in brake pads",it:"Umidit\u00e0 nelle pastiglie dei freni"},{en:"Overheated brakes from prolonged use",it:"Freni surriscaldati dall'uso prolungato"},{en:"ABS malfunction",it:"Malfunzionamento dell'ABS"},{en:"Low tire pressure",it:"Bassa pressione degli pneumatici"}],correct:1,explain_en:"Brake fade: brakes overheat from sustained use downhill, reducing stopping power. Use engine braking (lower gears).",explain_it:"Brake fade: i freni si surriscaldano dall'uso prolungato in discesa, riducendo il potere frenante. Usa il freno motore."},
  {cat:"safety",en:"'Engine braking' means:",it:"Il 'freno motore' significa:",options:[{en:"Applying gas and brake simultaneously",it:"Applicare gas e freno simultaneamente"},{en:"Using lower gears to let the engine slow the vehicle",it:"Usare marce basse per lasciare che il motore rallenti il veicolo"},{en:"Revving to generate exhaust braking",it:"Imballare il motore per il freno di scarico"},{en:"Turning off the engine to slow down",it:"Spegnere il motore per rallentare"}],correct:1,explain_en:"Engine braking means downshifting so the engine's natural resistance slows the vehicle. Useful on long downhill grades.",explain_it:"Il freno motore significa scalare la marcia cos\u00ec la resistenza del motore rallenta il veicolo. Utile nelle lunghe discese."},
  {cat:"safety",en:"The biggest risk of parking on a highway shoulder is:",it:"Il rischio maggiore del parcheggio sulla banchina autostradale \u00e8:",options:[{en:"Tire damage on gravel",it:"Danni agli pneumatici sul ghiaino"},{en:"Being struck by passing traffic, especially at night",it:"Essere colpito dal traffico in transito, specialmente di notte"},{en:"Receiving a parking citation",it:"Ricevere una multa per sosta"},{en:"Running out of fuel",it:"Rimanere senza carburante"}],correct:1,explain_en:"Stopped vehicles on highway shoulders are struck by traffic frequently, especially at night. Maximize visibility with hazard lights.",explain_it:"I veicoli fermi sulle banchine autostradali vengono colpiti dal traffico frequentemente. Massimizza la visibilit\u00e0 con le luci di pericolo."},
  {cat:"safety",en:"What is the correct response when your vehicle runs off the paved road?",it:"Qual \u00e8 la risposta corretta quando il tuo veicolo esce dalla strada asfaltata?",options:[{en:"Jerk the steering wheel back hard",it:"Girare bruscamente il volante di ritorno"},{en:"Ease off gas, hold wheel firmly, slow down, ease back onto road",it:"Togli il gas, tieni saldamente il volante, rallenta, rientra gradualmente"},{en:"Apply brakes hard immediately",it:"Applica i freni fortemente immediatamente"},{en:"Steer left immediately",it:"Sterza immediatamente a sinistra"}],correct:1,explain_en:"Running off the road: ease off gas, grip wheel, slow to ~25 mph, then gently steer back. Jerking back can cause rollover.",explain_it:"Uscita di strada: togli il gas, stringi il volante, rallenta a ~40 km/h, poi sterza delicatamente di ritorno. Girare bruscamente pu\u00f2 causare ribaltamento."},
  {cat:"safety",en:"24 hours without sleep produces impairment equivalent to a BAC of:",it:"24 ore senza dormire producono una compromissione equivalente a un BAC di:",options:[{en:"0.04%",it:"0,04%"},{en:"0.06%",it:"0,06%"},{en:"0.10%",it:"0,10%"},{en:"0.15%",it:"0,15%"}],correct:2,explain_en:"Research shows 24 hours without sleep = impairment equivalent to 0.10% BAC. Fatigued driving is as dangerous as drunk driving.",explain_it:"La ricerca mostra che 24 ore senza dormire = compromissione equivalente a 0,10% BAC. La guida affaticata \u00e8 pericolosa quanto quella ubriaca."},
  {cat:"safety",en:"How does alcohol affect depth perception?",it:"Come influisce l'alcol sulla percezione della profondit\u00e0?",options:[{en:"Improves it at low BAC",it:"La migliora a bassi livelli di BAC"},{en:"Significantly impairs it \u2014 making speed and distance judgment dangerous",it:"La compromette significativamente \u2014 rendendo pericoloso il giudizio di velocit\u00e0 e distanza"},{en:"Only affects reaction time, not depth perception",it:"Influisce solo sul tempo di reazione"},{en:"Only affects vision above 0.10%",it:"Influisce sulla visione solo sopra 0,10%"}],correct:1,explain_en:"Alcohol impairs depth perception, peripheral vision, and reaction time simultaneously \u2014 all at low BAC levels.",explain_it:"L'alcol compromette la percezione della profondit\u00e0, la visione periferica e il tempo di reazione \u2014 anche a bassi livelli."},
  {cat:"safety",en:"When is cruise control unsafe to use?",it:"Quando non \u00e8 sicuro usare il cruise control?",options:[{en:"On flat highways with light traffic",it:"Su autostrade piatte con traffico leggero"},{en:"In rain, snow, ice, fog, heavy traffic, or on winding roads",it:"In pioggia, neve, ghiaccio, nebbia, traffico intenso o su strade tortuose"},{en:"Only when towing a trailer",it:"Solo quando si traino un rimorchio"},{en:"Cruise control is always safe at the speed limit",it:"Il cruise control \u00e8 sempre sicuro al limite"}],correct:1,explain_en:"Never use cruise control in rain, snow, ice, fog, or heavy traffic. In slippery conditions it can cause loss of control.",explain_it:"Non usare mai il cruise control in pioggia, neve, ghiaccio, nebbia o traffico intenso. In condizioni scivolose pu\u00f2 causare perdita del controllo."},
  {cat:"safety",en:"Driving when angry or emotionally upset is dangerous because:",it:"Guidare arrabbiati o emotivamente turbati \u00e8 pericoloso perch\u00e9:",options:[{en:"Emotions have no effect on driving",it:"Le emozioni non hanno effetti sulla guida"},{en:"Strong emotions impair judgment, increase aggression, and reduce road focus",it:"Le emozioni forti compromettono il giudizio, aumentano l'aggressivit\u00e0 e riducono la concentrazione"},{en:"Only sadness affects driving",it:"Solo la tristezza influisce sulla guida"},{en:"Only affects new drivers",it:"Colpisce solo i nuovi conducenti"}],correct:1,explain_en:"Strong emotions impair judgment, reaction time, and decision-making. Wait until calm before driving.",explain_it:"Le emozioni forti compromettono il giudizio, il tempo di reazione e le decisioni. Aspetta di essere calmo."},
  {cat:"safety",en:"The best response to road rage from another driver is:",it:"La risposta migliore alla rabbia stradale di un altro conducente \u00e8:",options:[{en:"Assert your right-of-way firmly",it:"Affermare con fermezza la tua precedenza"},{en:"Avoid eye contact, don't gesture, and create distance",it:"Evitare il contatto visivo, non gesticolare e creare distanza"},{en:"Match their driving behavior",it:"Abbinare il loro comportamento"},{en:"Pull over and exit your car",it:"Accostare e uscire dall'auto"}],correct:1,explain_en:"Non-engagement is safest: no eye contact, no gestures, and put distance between you and the aggressive driver.",explain_it:"Il non coinvolgimento \u00e8 il pi\u00f9 sicuro: nessun contatto visivo, nessun gesto e metti distanza tra te e il conducente aggressivo."},
  {cat:"safety",en:"Under-inflated tires cause:",it:"Gli pneumatici sotto-gonfiati causano:",options:[{en:"Better fuel economy",it:"Migliore economia di carburante"},{en:"Excessive heat, increased wear, blowout risk, and poor handling",it:"Calore eccessivo, usura aumentata, rischio di scoppio e scarsa manovrabilit\u00e0"},{en:"Slightly longer stopping distances only",it:"Solo distanze di frenata leggermente maggiori"},{en:"No significant safety effect",it:"Nessun effetto significativo sulla sicurezza"}],correct:1,explain_en:"Under-inflated tires generate excessive heat (leading to blowouts), wear faster, reduce fuel efficiency, and impair handling.",explain_it:"Gli pneumatici sotto-gonfiati generano calore eccessivo (scoppi), si consumano pi\u00f9 velocemente e compromettono la manovrabilit\u00e0."},
  {cat:"safety",en:"'Progressive braking' means:",it:"La 'frenata progressiva' significa:",options:[{en:"Pumping the brakes to prevent ABS activation",it:"Pompare i freni per prevenire l'ABS"},{en:"Gradually increasing brake pressure for smooth, controlled stops",it:"Aumentare gradualmente la pressione per arresti fluidi e controllati"},{en:"Braking only in the last 50 feet",it:"Frenare solo negli ultimi 15 m"},{en:"Using the parking brake as primary stop method",it:"Usare il freno di parcheggio come metodo principale"}],correct:1,explain_en:"Progressive braking: apply brakes gradually \u2014 light at first, increasing as needed \u2014 for smooth stops.",explain_it:"Frenata progressiva: applica i freni gradualmente \u2014 leggero all'inizio, aumentando secondo necessit\u00e0 \u2014 per arresti fluidi."},
  {cat:"safety",en:"The safe curve-driving sequence is:",it:"La sequenza sicura per la guida in curva \u00e8:",options:[{en:"Accelerate through, then brake after",it:"Accelerare attraverso, poi frenare dopo"},{en:"Brake before, steady speed through, accelerate after",it:"Frenare prima, velocit\u00e0 costante durante, accelerare dopo"},{en:"Brake throughout the curve",it:"Frenare per tutta la curva"},{en:"Downshift while braking through the curve",it:"Scalare la marcia mentre si frena in curva"}],correct:1,explain_en:"Slow BEFORE the curve (on the straight), maintain steady speed THROUGH it, then accelerate AFTER.",explain_it:"Rallenta PRIMA della curva (in rettilineo), mantieni velocit\u00e0 costante DURANTE, poi accelera DOPO."},
  {cat:"safety",en:"If your vehicle starts to roll unexpectedly, you should:",it:"Se il tuo veicolo inizia a scorrere inaspettatamente, dovresti:",options:[{en:"Jump out immediately",it:"Saltare fuori immediatamente"},{en:"Apply parking brake and steer to safety",it:"Applicare il freno di parcheggio e sterzare verso un luogo sicuro"},{en:"Turn off the engine to lock wheels",it:"Spegnere il motore per bloccare le ruote"},{en:"Accelerate to regain control",it:"Accelerare per riprendere il controllo"}],correct:1,explain_en:"If the vehicle rolls: apply the parking/emergency brake, steer to safety (curb, soft soil). Do not jump out.",explain_it:"Se il veicolo scorre: applica il freno di parcheggio, sterza verso un luogo sicuro. Non saltare fuori."},
  {cat:"safety",en:"When driving in areas where deer are common:",it:"Quando si guida in zone con cervi comuni:",options:[{en:"Speed up to clear the area fast",it:"Accelerare per liberare l'area velocemente"},{en:"Be most alert at dawn/dusk; if one crosses, others may follow",it:"Essere pi\u00f9 vigile all'alba/tramonto; se uno attraversa, altri potrebbero seguire"},{en:"Continuously flash high beams",it:"Lampeggiare continuamente gli abbaglianti"},{en:"Sound the horn when you see one",it:"Suonare il clacson quando ne vedi uno"}],correct:1,explain_en:"Deer are most active at dawn/dusk. They travel in groups. If one crosses, slow down \u2014 more may follow.",explain_it:"I cervi sono pi\u00f9 attivi all'alba/tramonto. Viaggiano in gruppo. Se uno attraversa, rallenta \u2014 altri potrebbero seguire."},
  {cat:"safety",en:"The recommended headrest position is:",it:"La posizione raccomandata per i poggiatesta \u00e8:",options:[{en:"As low as possible for comfort",it:"Il pi\u00f9 in basso possibile per il comfort"},{en:"Top of headrest at or above the top of your head",it:"La parte superiore all'altezza o sopra la sommit\u00e0 della testa"},{en:"Headrests have no safety function",it:"I poggiatesta non hanno funzione di sicurezza"},{en:"Angled forward as far as possible",it:"Inclinato in avanti il pi\u00f9 possibile"}],correct:1,explain_en:"Properly adjusted headrests reduce whiplash in rear-end collisions. Top should be at least as high as the top of your head.",explain_it:"I poggiatesta ben regolati riducono il colpo di frusta nelle collisioni posteriori. La parte superiore deve essere almeno all'altezza della testa."},
  {cat:"safety",en:"What is 'situational awareness' in driving?",it:"Cos'\u00e8 la 'consapevolezza situazionale' nella guida?",options:[{en:"Knowing the speed limit in every zone",it:"Conoscere il limite in ogni zona"},{en:"Constantly monitoring surroundings \u2014 road, traffic, pedestrians, hazards",it:"Monitorare costantemente l'ambiente \u2014 strada, traffico, pedoni, pericoli"},{en:"Using GPS to track exact location",it:"Usare il GPS per tracciare la posizione"},{en:"Being aware of vehicle mechanical condition",it:"Essere consapevoli delle condizioni meccaniche del veicolo"}],correct:1,explain_en:"Situational awareness: continuously observe and understand everything happening around your vehicle \u2014 and anticipate what may happen.",explain_it:"Consapevolezza situazionale: osserva e comprendi costantemente tutto ci\u00f2 che accade intorno al veicolo \u2014 e anticipa ci\u00f2 che potrebbe accadere."},
  {cat:"safety",en:"What is 'understeer' in a vehicle?",it:"Cos'\u00e8 il 'sottosterzo' in un veicolo?",options:[{en:"Rear tires lose grip and rear swings out",it:"Gli pneumatici posteriori perdono aderenza e il retro si sposta"},{en:"Front tires lose grip \u2014 car continues straight despite turning wheel",it:"Gli pneumatici anteriori perdono aderenza \u2014 l'auto va dritto nonostante si giri il volante"},{en:"Steering feels very heavy",it:"Lo sterzo sembra molto pesante"},{en:"Steering wheel vibrates at speed",it:"Il volante vibra ad alta velocit\u00e0"}],correct:1,explain_en:"Understeer: front wheels lose grip in a curve \u2014 car goes straight. Response: ease off gas, let traction return.",explain_it:"Sottosterzo: le ruote anteriori perdono aderenza \u2014 l'auto va dritto. Risposta: togli il gas, lascia che la trazione torni."},
  {cat:"safety",en:"Rear-end collisions are most commonly caused by:",it:"Le collisioni posteriori sono pi\u00f9 comunemente causate da:",options:[{en:"Using turn signals when changing lanes",it:"Usare i segnali di svolta"},{en:"Following too closely combined with distraction",it:"Seguire troppo da vicino combinato con la distrazione"},{en:"Driving at the speed limit",it:"Guidare al limite di velocit\u00e0"},{en:"Checking mirrors regularly",it:"Controllare regolarmente gli specchi"}],correct:1,explain_en:"Rear-end crashes: tailgating + distraction = no time to react when the vehicle ahead brakes.",explain_it:"Collisioni posteriori: distanza insufficiente + distrazione = nessun tempo per reagire quando il veicolo davanti frena."},
  {cat:"safety",en:"If a vehicle fire starts, the correct response is:",it:"Se scoppia un incendio del veicolo, la risposta corretta \u00e8:",options:[{en:"Open the hood to ventilate engine",it:"Aprire il cofano per ventilare il motore"},{en:"Pull over, turn off engine, exit, call 911, stay far away",it:"Accostare, spegnere il motore, uscire, chiamare il 911, stare lontano"},{en:"Drive to a fire station",it:"Andare a una stazione dei pompieri"},{en:"Pour water on the engine",it:"Versare acqua sul motore"}],correct:1,explain_en:"Vehicle fire: pull over, shut off engine, get everyone out, call 911, and move far from the vehicle. Fires spread rapidly.",explain_it:"Incendio del veicolo: accosta, spegni il motore, fai uscire tutti, chiama il 911 e allontanati. Gli incendi si diffondono rapidamente."},
  {cat:"safety",en:"What makes a safe lane change on a highway?",it:"Cosa rende sicuro un cambio di corsia in autostrada?",options:[{en:"Change as quickly as possible",it:"Cambiare il pi\u00f9 velocemente possibile"},{en:"Check mirrors, signal, check blind spots, ensure adequate space",it:"Controlla specchi, segnala, controlla i punti ciechi, assicura spazio adeguato"},{en:"Only when vehicles behind are very far",it:"Solo quando i veicoli dietro sono molto lontani"},{en:"No special precautions needed",it:"Nessuna precauzione speciale"}],correct:1,explain_en:"Safe lane change: check mirrors, signal 200 ft ahead, physically check blind spots, confirm space, then smoothly change.",explain_it:"Cambio sicuro: controlla specchi, segnala 60 m prima, controlla i punti ciechi, conferma lo spazio, poi cambia fluidamente."},
  {cat:"safety",en:"'Inattentional blindness' while driving means:",it:"La 'cecit\u00e0 da disattenzione' durante la guida significa:",options:[{en:"Inability to see in the dark",it:"Incapacit\u00e0 di vedere al buio"},{en:"Missing visible hazards because the mind is focused elsewhere",it:"Non vedere pericoli visibili perch\u00e9 la mente \u00e8 concentrata altrove"},{en:"Temporary vision loss from bright headlights",it:"Perdita temporanea della visione dai fari"},{en:"Misjudging distances at night",it:"Valutare male le distanze di notte"}],correct:1,explain_en:"Inattentional blindness: eyes are open but the brain fails to process visible hazards due to distraction.",explain_it:"Cecit\u00e0 da disattenzione: occhi aperti ma il cervello non elabora i pericoli visibili a causa della distrazione."},
  {cat:"safety",en:"Delineator posts (flexible orange sticks) on roads are used to:",it:"I delineatori (bastoncini arancioni flessibili) sulle strade servono a:",options:[{en:"Mark no-parking zones",it:"Segnare zone di divieto di sosta"},{en:"Guide drivers along road edges \u2014 curves, narrow sections, construction",it:"Guidare i conducenti lungo i bordi della strada \u2014 curve, sezioni strette, costruzioni"},{en:"Mark school zone beginnings",it:"Segnare l'inizio delle zone scolastiche"},{en:"Separate bicycle lanes",it:"Separare le piste ciclabili"}],correct:1,explain_en:"Delineator posts guide drivers along road edges, curves, and narrow/construction sections. Flexibility allows minor impacts.",explain_it:"I delineatori guidano i conducenti lungo i bordi della strada, le curve e le sezioni strette. La flessibilit\u00e0 consente impatti minori."},
  {cat:"safety",en:"After airbag deployment, you should:",it:"Dopo il dispiegamento dell'airbag, dovresti:",options:[{en:"Remain in vehicle \u2014 chemicals are harmless",it:"Rimanere nel veicolo \u2014 i prodotti chimici sono innocui"},{en:"Exit if safe \u2014 deployment powder can irritate lungs and eyes",it:"Uscire se sicuro \u2014 la polvere pu\u00f2 irritare polmoni e occhi"},{en:"Drive away immediately",it:"Allontanarsi immediatamente"},{en:"Keep engine running",it:"Tenere il motore acceso"}],correct:1,explain_en:"After airbag deployment, residue powder can irritate eyes and lungs. Exit if safe and seek fresh air.",explain_it:"Dopo il dispiegamento dell'airbag, la polvere residua pu\u00f2 irritare occhi e polmoni. Esci se sicuro e cerca aria fresca."},
  {cat:"safety",en:"When approaching a stopped school bus with caution sign, what extra following distance is recommended?",it:"Quando ci si avvicina a uno scuolabus che si ferma frequentemente, quale distanza extra \u00e8 raccomandata?",options:[{en:"Standard 3-second rule",it:"Regola standard dei 3 secondi"},{en:"At least 10 car lengths / ~5 seconds",it:"Almeno 10 lunghezze auto / ~5 secondi"},{en:"Same as any other vehicle",it:"Uguale a qualsiasi altro veicolo"},{en:"30 feet exactly",it:"Esattamente 30 piedi"}],correct:1,explain_en:"Follow school buses with extra distance \u2014 at least 10 car lengths \u2014 because they stop frequently with little warning.",explain_it:"Segui gli scuolabus con distanza extra \u2014 almeno 10 lunghezze auto \u2014 perch\u00e9 si fermano frequentemente con poco preavviso."},
  {cat:"safety",en:"If your hood flies open while driving, you should:",it:"Se il cofano si apre durante la guida, dovresti:",options:[{en:"Brake hard and stop immediately",it:"Frenare bruscamente e fermarsi immediatamente"},{en:"Look through the gap, steer right, slow gradually",it:"Guardare attraverso il divario, sterzare a destra, rallentare gradualmente"},{en:"Accelerate to close it with air pressure",it:"Accelerare per chiuderlo con la pressione dell'aria"},{en:"Turn on hazard lights and maintain speed",it:"Accendere le luci di pericolo e mantenere la velocit\u00e0"}],correct:1,explain_en:"If the hood opens: look through the gap below it, slow gradually, steer to the shoulder, and stop safely.",explain_it:"Se il cofano si apre: guarda attraverso il divario, rallenta gradualmente, sterza verso la banchina e fermati."},
  {cat:"safety",en:"'Vehicle dynamics' awareness means understanding:",it:"La consapevolezza della 'dinamica del veicolo' significa capire:",options:[{en:"The car's GPS systems",it:"I sistemi GPS dell'auto"},{en:"How weight transfer, tire grip, and momentum affect vehicle control",it:"Come il trasferimento di peso, l'aderenza e lo slancio influenzano il controllo"},{en:"The engine specifications",it:"Le specifiche del motore"},{en:"How to adjust mirrors and seats",it:"Come regolare specchi e sedili"}],correct:1,explain_en:"Vehicle dynamics: braking shifts weight forward, acceleration backward, cornering sideways \u2014 all affecting tire grip and stability.",explain_it:"Dinamica del veicolo: la frenata sposta il peso avanti, l'accelerazione indietro, le curve di lato \u2014 tutto influenzando aderenza e stabilit\u00e0."},
  {cat:"safety",en:"The correct left turn sequence from a two-lane road is:",it:"La sequenza corretta per la svolta a sinistra da una strada a due corsie \u00e8:",options:[{en:"Check mirrors, signal, move left, yield to oncoming, complete turn",it:"Controlla specchi, segnala, spostati a sinistra, cedi ai veicoli in arrivo, completa la svolta"},{en:"Signal, brake sharply, turn immediately",it:"Segnala, frena bruscamente, svolta immediatamente"},{en:"Move left first, then signal while turning",it:"Spostati a sinistra prima, poi segnala mentre svolti"},{en:"Check mirrors only after beginning the turn",it:"Controlla gli specchi solo dopo aver iniziato la svolta"}],correct:0,explain_en:"For a left turn: check mirrors early, signal 100-200 ft before, position left, yield to oncoming traffic, complete turn.",explain_it:"Per una svolta a sinistra: controlla specchi in anticipo, segnala 30-60 m prima, posizionati a sinistra, cedi ai veicoli in arrivo."},
  {cat:"safety",en:"What is the danger of driving in a tunnel from bright daylight?",it:"Qual \u00e8 il pericolo di guidare in un tunnel dalla luce solare?",options:[{en:"Speed limits are higher in tunnels",it:"I limiti sono pi\u00f9 alti nei tunnel"},{en:"Abrupt light change can temporarily impair vision",it:"Il brusco cambio di luce pu\u00f2 compromettere temporaneamente la visione"},{en:"GPS signals are stronger in tunnels",it:"I segnali GPS sono pi\u00f9 forti nei tunnel"},{en:"Tunnels always require lower speeds",it:"I tunnel richiedono sempre velocit\u00e0 pi\u00f9 basse"}],correct:1,explain_en:"Entering a tunnel from bright daylight can temporarily blind you as eyes adjust. Turn on headlights before entering.",explain_it:"Entrare in un tunnel dalla luce solare pu\u00f2 temporaneamente accecarti. Accendi i fari prima di entrare."},
  {cat:"safety",en:"When another driver cuts you off, the safest response is:",it:"Quando un altro conducente ti taglia la strada, la risposta pi\u00f9 sicura \u00e8:",options:[{en:"Speed up alongside to show displeasure",it:"Accelerare accanto a loro"},{en:"Slow down, re-establish following distance, let it go",it:"Rallenta, ristabilisci la distanza, lascia perdere"},{en:"Brake hard and sound horn repeatedly",it:"Frenare bruscamente e suonare ripetutamente"},{en:"Tailgate to teach them a lesson",it:"Seguirli da vicino per dargli una lezione"}],correct:1,explain_en:"When cut off: slow down to re-establish safe following distance and let the incident go. Retaliation escalates danger.",explain_it:"Quando ti tagliano la strada: rallenta per ristabilire distanza sicura e lascia perdere. La ritorsione aumenta il pericolo."},
  {cat:"safety",en:"The biggest risk of 'inattentional blindness' is:",it:"Il rischio principale della 'cecit\u00e0 da disattenzione' \u00e8:",options:[{en:"Not seeing in dark conditions",it:"Non vedere in condizioni di buio"},{en:"Failing to process visible hazards due to mental distraction",it:"Non riuscire a elaborare i pericoli visibili a causa della distrazione mentale"},{en:"Glare from oncoming headlights",it:"Abbagliamento dai fari in arrivo"},{en:"Misjudging gap in traffic",it:"Valutare male il divario nel traffico"}],correct:1,explain_en:"Inattentional blindness: brain occupied elsewhere doesn't register visible hazards \u2014 like talking on phone while driving.",explain_it:"Cecit\u00e0 da disattenzione: il cervello occupato altrove non registra i pericoli visibili \u2014 come parlare al telefono mentre si guida."},
  {cat:"safety",en:"Properly adjusted headrests reduce the risk of:",it:"I poggiatesta correttamente regolati riducono il rischio di:",options:[{en:"Head injuries in a frontal crash",it:"Lesioni alla testa in un incidente frontale"},{en:"Whiplash injury in rear-end collisions",it:"Colpo di frusta nelle collisioni posteriori"},{en:"Concussion from airbag deployment",it:"Commozione cerebrale dal dispiegamento dell'airbag"},{en:"Sun glare through the rear window",it:"Abbagliamento solare dal lunotto posteriore"}],correct:1,explain_en:"Headrests reduce whiplash injury in rear-end collisions. Top should be at or above the head.",explain_it:"I poggiatesta riducono il colpo di frusta nelle collisioni posteriori. La parte superiore deve essere all'altezza della testa."},
  {cat:"safety",en:"What is 'progressive braking' and its advantage?",it:"Cos'\u00e8 la 'frenata progressiva' e il suo vantaggio?",options:[{en:"Pumping brakes to avoid lock-up",it:"Pompare i freni per evitare il blocco"},{en:"Gradually increasing pressure \u2014 smooth stops that don't startle following traffic",it:"Aumentare gradualmente la pressione \u2014 arresti fluidi che non sorprendono il traffico che segue"},{en:"Braking only in the last 50 feet",it:"Frenare solo negli ultimi 15 m"},{en:"Using parking brake as primary method",it:"Usare il freno di parcheggio come metodo principale"}],correct:1,explain_en:"Progressive braking = light pressure building gradually. Smooth stops reduce rear-end collision risk from following traffic.",explain_it:"Frenata progressiva = pressione leggera che aumenta gradualmente. Arresti fluidi riducono il rischio di collisioni posteriori."},
  {cat:"safety",en:"Why should you reduce speed in construction zones even without workers present?",it:"Perch\u00e9 dovresti ridurre la velocit\u00e0 nelle zone di lavoro anche senza operai presenti?",options:[{en:"Speed limits don't apply when workers are absent",it:"I limiti non si applicano quando gli operai sono assenti"},{en:"Uneven surfaces, lane shifts, and equipment can appear suddenly",it:"Superfici irregolari, spostamenti di corsia e attrezzature possono apparire improvvisamente"},{en:"Only lower speed when orange signs are visible",it:"Rallentare solo quando i segnali arancioni sono visibili"},{en:"No reason \u2014 fines apply only with workers present",it:"Nessun motivo \u2014 le multe si applicano solo con operai presenti"}],correct:1,explain_en:"Construction zones remain dangerous even without workers: uneven pavement, lane changes, barriers, and equipment pose risks.",explain_it:"Le zone di lavoro rimangono pericolose anche senza operai: pavimentazione irregolare, cambi di corsia, barriere e attrezzature pongono rischi."},
  {cat:"safety",en:"The purpose of a vehicle's ABS (Anti-lock Braking System) is to:",it:"Lo scopo dell'ABS (Sistema Frenante Anti-blocco) \u00e8:",options:[{en:"Stop the vehicle faster than normal braking",it:"Fermare il veicolo pi\u00f9 velocemente della frenata normale"},{en:"Prevent wheel lock-up so the driver can still steer while braking hard",it:"Prevenire il blocco delle ruote cos\u00ec il conducente pu\u00f2 ancora sterzare durante la frenata"},{en:"Automatically apply brakes in emergencies",it:"Applicare automaticamente i freni nelle emergenze"},{en:"Reduce brake wear on highway driving",it:"Ridurre l'usura dei freni in autostrada"}],correct:1,explain_en:"ABS prevents wheels from locking under hard braking, allowing the driver to maintain steering control. Apply steady firm pressure \u2014 don't pump ABS brakes.",explain_it:"L'ABS previene il blocco delle ruote durante la frenata, consentendo al conducente di mantenere il controllo dello sterzo. Applica pressione ferma costante \u2014 non pompare i freni ABS."},
  {cat:"safety",en:"What is the safe following distance in normal conditions?",it:"Qual \u00e8 la distanza di sicurezza in condizioni normali?",options:[{en:"1 car length per 10 mph",it:"1 lunghezza auto per 10 mph"},{en:"At least 3 seconds",it:"Almeno 3 secondi"},{en:"50 feet minimum",it:"Minimo 50 piedi"},{en:"2 seconds at all speeds",it:"2 secondi a tutte le velocit\u00e0"}],correct:1,explain_en:"The 3-second rule: pick a fixed object; after the vehicle ahead passes it, count 3 seconds before you reach it.",explain_it:"La regola dei 3 secondi: scegli un oggetto fisso; dopo che il veicolo davanti lo passa, conta 3 secondi prima di raggiungerlo."},
  {cat:"safety",en:"When must you increase following distance beyond 3 seconds?",it:"Quando devi aumentare la distanza oltre i 3 secondi?",options:[{en:"Never \u2014 3 seconds is always sufficient",it:"Mai \u2014 3 secondi sono sempre sufficienti"},{en:"In rain, fog, heavy traffic, when following trucks, or when tired",it:"In pioggia, nebbia, traffico intenso, quando si seguono camion o quando si \u00e8 stanchi"},{en:"Only on highways",it:"Solo in autostrada"},{en:"Only at night",it:"Solo di notte"}],correct:1,explain_en:"Increase to 4-6 seconds or more in adverse conditions: rain, fog, heavy traffic, following large trucks, or when fatigued.",explain_it:"Aumenta a 4-6 secondi o pi\u00f9 in condizioni avverse: pioggia, nebbia, traffico intenso, seguendo camion grandi o quando sei stanco."},
  {cat:"safety",en:"What is the first thing you should do before backing a vehicle?",it:"Qual \u00e8 la prima cosa da fare prima di fare retromarcia?",options:[{en:"Check only the rearview mirror",it:"Controllare solo lo specchietto retrovisore"},{en:"Walk around the vehicle to check for obstacles, then check all mirrors",it:"Camminare intorno al veicolo per controllare gli ostacoli, poi controllare tutti gli specchi"},{en:"Sound the horn to warn pedestrians",it:"Suonare il clacson per avvisare i pedoni"},{en:"No preparation needed if in a known area",it:"Nessuna preparazione necessaria in un'area conosciuta"}],correct:1,explain_en:"Before reversing: physically walk around the vehicle to check for children, pets, and obstacles invisible in mirrors.",explain_it:"Prima di fare retromarcia: cammina fisicamente intorno al veicolo per controllare bambini, animali e ostacoli invisibili negli specchi."},
  {cat:"safety",en:"What is the 'danger zone' directly in front of a large truck?",it:"Qual \u00e8 la 'zona pericolosa' direttamente davanti a un camion grande?",options:[{en:"10 feet in front",it:"10 piedi in avanti"},{en:"Approximately 20 feet \u2014 the driver cannot see this area",it:"Circa 20 piedi \u2014 il conducente non pu\u00f2 vedere questa zona"},{en:"There is no blind spot in front",it:"Non c'\u00e8 punto cieco davanti"},{en:"Only 5 feet directly ahead",it:"Solo 5 piedi direttamente davanti"}],correct:1,explain_en:"Large trucks have a 20-foot blind spot directly in front. If you can't see the driver's mirrors, they can't see you.",explain_it:"I camion grandi hanno un punto cieco di 20 piedi direttamente davanti. Se non puoi vedere gli specchi del camionista, lui non pu\u00f2 vedere te."},
  {cat:"safety",en:"Which of these is a sign of driver fatigue?",it:"Quale di questi \u00e8 un segnale di stanchezza del conducente?",options:[{en:"Increased alertness and sharp reflexes",it:"Maggiore vigilanza e riflessi acuti"},{en:"Frequent blinking, yawning, drifting from lane, missing exits",it:"Battito di ciglia frequente, sbadiglio, deriva dalla corsia, perdita di uscite"},{en:"Improved vision at night",it:"Visione migliorata di notte"},{en:"Reduced thirst and hunger",it:"Riduzione della sete e della fame"}],correct:1,explain_en:"Signs of fatigue: frequent blinking, yawning, lane drift, missing exits, and not remembering the last few miles.",explain_it:"Segni di stanchezza: battito di ciglia frequente, sbadiglio, deriva dalla corsia, perdita di uscite e non ricordare gli ultimi km."},
  {cat:"safety",en:"What is the safest way to handle a tire blowout at highway speed?",it:"Qual \u00e8 il modo pi\u00f9 sicuro di gestire lo scoppio di uno pneumatico in autostrada?",options:[{en:"Brake hard and pull immediately to the shoulder",it:"Frenare bruscamente e accostare immediatamente"},{en:"Grip steering wheel firmly, ease off gas, steer straight, slow gradually",it:"Stringi saldamente il volante, togli il gas, sterza dritto, rallenta gradualmente"},{en:"Steer sharply to the opposite side",it:"Sterzare bruscamente verso il lato opposto"},{en:"Accelerate briefly to stabilize before braking",it:"Accelerare brevemente per stabilizzare prima di frenare"}],correct:1,explain_en:"Blowout: grip the wheel firmly, ease off the gas (don't brake hard), maintain direction, and slow gradually to the shoulder.",explain_it:"Scoppio: stringi il volante, togli il gas (non frenare bruscamente), mantieni la direzione e rallenta gradualmente verso la banchina."},
  {cat:"alcohol",en:"At a BAC of 0.02%, a driver typically experiences:",it:"A un BAC di 0,02%, un conducente tipicamente sperimenta:",options:[{en:"No detectable effects",it:"Nessun effetto rilevabile"},{en:"Subtle loss of judgment, slight relaxation, altered mood",it:"Sottile perdita di giudizio, leggero rilassamento, alterazione dell'umore"},{en:"Severe impairment",it:"Grave compromissione"},{en:"Complete inability to drive",it:"Completa incapacit\u00e0 di guidare"}],correct:1,explain_en:"Even at 0.02% BAC \u2014 well below the legal limit \u2014 drivers experience relaxation and subtle loss of judgment.",explain_it:"Anche a 0,02% BAC \u2014 ben sotto il limite legale \u2014 i conducenti sperimentano rilassamento e sottile perdita di giudizio."},
  {cat:"alcohol",en:"At a BAC of 0.05%, a driver typically shows:",it:"A un BAC di 0,05%, un conducente mostra tipicamente:",options:[{en:"No measurable impairment",it:"Nessuna compromissione misurabile"},{en:"Reduced coordination, reduced ability to track objects, impaired judgment",it:"Coordinazione ridotta, ridotta capacit\u00e0 di seguire oggetti, giudizio compromesso"},{en:"Only minor vision changes",it:"Solo lievi cambiamenti visivi"},{en:"Fully intact driving ability",it:"Piena capacit\u00e0 di guida intatta"}],correct:1,explain_en:"At 0.05% BAC: reduced coordination, difficulty tracking moving objects, difficulty steering, reduced emergency response.",explain_it:"A 0,05% BAC: coordinazione ridotta, difficolt\u00e0 a seguire oggetti in movimento, difficolt\u00e0 di sterzo, risposta di emergenza ridotta."},
  {cat:"alcohol",en:"At a BAC of 0.08%, a driver typically shows:",it:"A un BAC di 0,08%, un conducente mostra tipicamente:",options:[{en:"Only minor fine motor impairment",it:"Solo lieve compromissione motoria fine"},{en:"Poor muscle coordination, impaired perception, difficulty detecting danger",it:"Scarsa coordinazione muscolare, percezione compromessa, difficolt\u00e0 nel rilevare il pericolo"},{en:"Only confusion and disorientation",it:"Solo confusione e disorientamento"},{en:"No ability to drive",it:"Nessuna capacit\u00e0 di guidare"}],correct:1,explain_en:"At 0.08% BAC: poor muscle coordination, slower reaction, difficulty detecting danger, impaired judgment and memory.",explain_it:"A 0,08% BAC: scarsa coordinazione muscolare, reazione pi\u00f9 lenta, difficolt\u00e0 a rilevare il pericolo, giudizio e memoria compromessi."},
  {cat:"alcohol",en:"Alcohol causes 'tunnel vision' which means:",it:"L'alcol causa 'visione a tunnel' che significa:",options:[{en:"Better focus on the road ahead",it:"Migliore concentrazione sulla strada davanti"},{en:"Narrowed field of view reducing peripheral awareness",it:"Campo visivo ristretto che riduce la consapevolezza periferica"},{en:"Night vision improves at low BAC",it:"La visione notturna migliora a bassi BAC"},{en:"Vision is the last sense impaired",it:"La visione \u00e8 l'ultimo senso compromesso"}],correct:1,explain_en:"Alcohol causes tunnel vision \u2014 narrowing the field of view. Drivers miss hazards approaching from the sides.",explain_it:"L'alcol causa visione a tunnel \u2014 restringendo il campo visivo. I conducenti mancano i pericoli dai lati."},
  {cat:"alcohol",en:"What is TRUE about 'sobering up'?",it:"Cosa \u00e8 VERO riguardo allo 'smaltire' l'alcol?",options:[{en:"Eating after drinking speeds up sobering",it:"Mangiare dopo aver bevuto accelera la sobriet\u00e0"},{en:"Nothing speeds the process \u2014 only time eliminates alcohol",it:"Niente accelera il processo \u2014 solo il tempo elimina l'alcol"},{en:"Water dilutes alcohol and lowers BAC quickly",it:"L'acqua diluisce l'alcol e abbassa rapidamente il BAC"},{en:"Exercise burns alcohol twice as fast",it:"L'esercizio brucia l'alcol due volte pi\u00f9 velocemente"}],correct:1,explain_en:"No food, coffee, water, exercise, or fresh air speeds up alcohol elimination. The liver processes at ~one drink per hour.",explain_it:"Nessun cibo, caff\u00e8, acqua, esercizio o aria fresca accelera l'eliminazione dell'alcol. Il fegato elabora a ~un drink all'ora."},
  {cat:"alcohol",en:"Florida DUI law covers impairment from:",it:"La legge DUI della Florida copre la compromissione da:",options:[{en:"Alcohol only",it:"Solo alcol"},{en:"Alcohol, controlled substances, AND chemical substances",it:"Alcol, sostanze controllate E sostanze chimiche"},{en:"Illegal drugs only",it:"Solo droghe illegali"},{en:"Prescription medications only with alcohol",it:"Solo farmaci da prescrizione con l'alcol"}],correct:1,explain_en:"Florida DUI applies to impairment from alcohol, controlled substances (illegal drugs), AND chemical substances (inhalants).",explain_it:"Il DUI della Florida si applica alla compromissione da alcol, sostanze controllate E sostanze chimiche (inalanti)."},
  {cat:"alcohol",en:"A person who 'feels fine' to drive after drinking:",it:"Una persona che 'si sente bene' per guidare dopo aver bevuto:",options:[{en:"Is probably right",it:"Ha probabilmente ragione"},{en:"Is likely more impaired than they realize \u2014 alcohol impairs self-assessment first",it:"\u00c8 probabilmente pi\u00f9 compromessa di quanto realizzi \u2014 l'alcol compromette prima la valutazione di s\u00e9"},{en:"Should only drive short distances",it:"Dovrebbe guidare solo brevi distanze"},{en:"Can drive safely with a sober passenger",it:"Pu\u00f2 guidare in sicurezza con un passeggero sobrio"}],correct:1,explain_en:"Alcohol impairs the ability to assess one's own impairment. Feeling 'fine' is a dangerous cognitive distortion.",explain_it:"L'alcol compromette la capacit\u00e0 di valutare la propria compromissione. Sentirsi 'bene' \u00e8 una pericolosa distorsione cognitiva."},
  {cat:"alcohol",en:"The legal BAC limit for CDL holders in Florida is:",it:"Il limite legale di BAC per i titolari CDL in Florida \u00e8:",options:[{en:"0.08%",it:"0,08%"},{en:"0.04%",it:"0,04%"},{en:"0.02%",it:"0,02%"},{en:"0.06%",it:"0,06%"}],correct:1,explain_en:"CDL holders face a stricter BAC limit of 0.04% because of the increased risk of large commercial vehicles.",explain_it:"I titolari CDL hanno un limite BAC pi\u00f9 severo di 0,04% per il rischio aumentato dei veicoli commerciali grandi."},
  {cat:"alcohol",en:"The three standardized field sobriety tests (SFSTs) are:",it:"I tre test di sobriet\u00e0 sul campo standardizzati (SFST) sono:",options:[{en:"Breathalyzer, blood draw, urine test",it:"Breathalyzer, prelievo di sangue, test delle urine"},{en:"Horizontal Gaze Nystagmus, Walk-and-Turn, One-Leg Stand",it:"Nistagmo Orizzontale dello Sguardo, Camminata e Giravolta, Postura su Una Gamba"},{en:"Blood pressure, reaction time, vision test",it:"Pressione sanguigna, tempo di reazione, test della vista"},{en:"Memory test, balance test, speech clarity",it:"Test di memoria, test di equilibrio, chiarezza del discorso"}],correct:1,explain_en:"NHTSA-approved SFSTs: HGN (eye test), Walk-and-Turn, and One-Leg Stand.",explain_it:"SFST approvati dalla NHTSA: HGN (test oculare), Camminata e Giravolta, e Postura su Una Gamba."},
  {cat:"alcohol",en:"Florida's Implied Consent Law means:",it:"La legge del Consenso Implicito della Florida significa:",options:[{en:"You must agree verbally to every police request",it:"Devi acconsentire verbalmente a ogni richiesta della polizia"},{en:"Operating a vehicle constitutes automatic consent to BAC testing if lawfully arrested",it:"Operare un veicolo costituisce consenso automatico ai test BAC se legalmente arrestato"},{en:"You must sign a consent form before driving",it:"Devi firmare un modulo di consenso prima di guidare"},{en:"Police cannot search your vehicle without consent",it:"La polizia non pu\u00f2 perquisire il veicolo senza consenso"}],correct:1,explain_en:"By obtaining a Florida license and driving, you automatically consent to chemical BAC testing when lawfully arrested for DUI.",explain_it:"Ottenendo la patente Florida e guidando, acconsenti automaticamente ai test chimici BAC quando legalmente arrestato per DUI."},
  {cat:"alcohol",en:"Refusing a BAC test under Florida's Implied Consent Law results in:",it:"Il rifiuto di un test BAC ai sensi del Consenso Implicito della Florida risulta in:",options:[{en:"No consequences \u2014 refusal is your right",it:"Nessuna conseguenza \u2014 il rifiuto \u00e8 un tuo diritto"},{en:"Automatic 1-year license suspension (first refusal)",it:"Sospensione automatica della patente di 1 anno (primo rifiuto)"},{en:"Immediate arrest only",it:"Solo arresto immediato"},{en:"A small fine but no suspension",it:"Una piccola multa ma nessuna sospensione"}],correct:1,explain_en:"First refusal: automatic 1-year license suspension. Second refusal: 18-month suspension and possible misdemeanor charge.",explain_it:"Primo rifiuto: sospensione automatica della patente di 1 anno. Secondo rifiuto: 18 mesi e possibile accusa."},
  {cat:"alcohol",en:"Marijuana use and driving in Florida:",it:"L'uso di marijuana e la guida in Florida:",options:[{en:"Is legal with a medical marijuana card",it:"\u00c8 legale con una tessera di marijuana medica"},{en:"Can result in DUI if normal faculties are impaired",it:"Pu\u00f2 risultare in DUI se le facolt\u00e0 normali sono compromesse"},{en:"Is only DUI if combined with alcohol",it:"\u00c8 solo DUI se combinato con l'alcol"},{en:"Is not covered by Florida DUI law",it:"Non \u00e8 coperto dalla legge DUI della Florida"}],correct:1,explain_en:"Florida's DUI law covers all substances. Driving impaired by marijuana \u2014 medical or otherwise \u2014 is DUI if faculties are impaired.",explain_it:"La legge DUI della Florida copre tutte le sostanze. Guidare compromessi dalla marijuana \u00e8 DUI se le facolt\u00e0 sono compromesse."},
  {cat:"alcohol",en:"Florida DUI with property damage or minor injury is classified as:",it:"Il DUI della Florida con danni materiali o lesioni minori \u00e8 classificato come:",options:[{en:"Standard DUI \u2014 no enhanced penalties",it:"DUI standard \u2014 nessuna penalit\u00e0 maggiorata"},{en:"A first-degree misdemeanor with enhanced penalties",it:"Un'infrazione minore di primo grado con penalit\u00e0 maggiorate"},{en:"A second-degree felony",it:"Un crimine di secondo grado"},{en:"A non-criminal infraction",it:"Un'infrazione non penale"}],correct:1,explain_en:"DUI with property damage or minor injury = first-degree misdemeanor with enhanced fines and possible jail time.",explain_it:"DUI con danni materiali o lesioni minori = infrazione minore di primo grado con multe maggiorate e possibile carcere."},
  {cat:"alcohol",en:"A BAC of 0.15% or higher triggers in Florida:",it:"Un BAC di 0,15% o superiore scatena in Florida:",options:[{en:"No additional penalties",it:"Nessuna penalit\u00e0 aggiuntiva"},{en:"Enhanced penalties: higher fines, mandatory ignition interlock",it:"Penalit\u00e0 maggiorate: multe pi\u00f9 alte, interlock obbligatorio"},{en:"Only mandatory DUI school",it:"Solo scuola DUI obbligatoria"},{en:"Immediate 10-year suspension",it:"Sospensione immediata di 10 anni"}],correct:1,explain_en:"BAC 0.15%+ triggers enhanced penalties: fines $1,000-$2,000 (1st offense), mandatory ignition interlock, potentially longer jail.",explain_it:"BAC 0,15%+ scatena penalit\u00e0 maggiorate: multe $1.000-$2.000 (1a offesa), interlock obbligatorio, potenzialmente pi\u00f9 carcere."},
  {cat:"alcohol",en:"The minimum period a Florida license is revoked after a first DUI conviction is:",it:"Il periodo minimo di revoca della patente dopo la prima condanna DUI in Florida \u00e8:",options:[{en:"30 days",it:"30 giorni"},{en:"90 days",it:"90 giorni"},{en:"180 days (6 months)",it:"180 giorni (6 mesi)"},{en:"1 year",it:"1 anno"}],correct:2,explain_en:"First DUI conviction: minimum 180-day (6-month) license revocation, maximum 1 year.",explain_it:"Prima condanna DUI: revoca minima della patente di 180 giorni (6 mesi), massimo 1 anno."},
  {cat:"alcohol",en:"A second DUI within 5 years of the first in Florida results in:",it:"Un secondo DUI entro 5 anni dal primo in Florida risulta in:",options:[{en:"Fine only \u2014 no jail",it:"Solo multa \u2014 nessun carcere"},{en:"Mandatory minimum 10-day jail and 5-year license revocation",it:"Minimo 10 giorni di carcere obbligatori e revoca della patente di 5 anni"},{en:"Same penalties as first conviction",it:"Stesse penalit\u00e0 della prima condanna"},{en:"Community service only",it:"Solo servizio alla comunit\u00e0"}],correct:1,explain_en:"2nd DUI within 5 years: mandatory 10-day jail minimum, 5-year license revocation, fines up to $4,000, ignition interlock.",explain_it:"2\u00b0 DUI entro 5 anni: minimo 10 giorni di carcere obbligatori, revoca 5 anni, multe fino a $4.000, interlock."},
  {cat:"alcohol",en:"A fourth DUI conviction in Florida results in:",it:"Una quarta condanna DUI in Florida risulta in:",options:[{en:"Same as third \u2014 no additional penalties",it:"Uguale alla terza \u2014 nessuna penalit\u00e0 aggiuntiva"},{en:"Permanent license revocation",it:"Revoca permanente della patente"},{en:"A third-degree felony with up to 5 years",it:"Un crimine di terzo grado con fino a 5 anni"},{en:"Only an enhanced fine",it:"Solo una multa maggiorata"}],correct:1,explain_en:"A fourth or subsequent DUI: permanent license revocation and classified as a third-degree felony.",explain_it:"Una quarta o successiva condanna DUI: revoca permanente della patente e classificata come crimine di terzo grado."},
  {cat:"alcohol",en:"Florida first DUI conviction requires a minimum of how many community service hours?",it:"La prima condanna DUI in Florida richiede un minimo di quante ore di servizio alla comunit\u00e0?",options:[{en:"10 hours",it:"10 ore"},{en:"25 hours",it:"25 ore"},{en:"50 hours",it:"50 ore"},{en:"100 hours",it:"100 ore"}],correct:2,explain_en:"First DUI: minimum 50 hours of community service, of which at least 10 hours involve litter pickup.",explain_it:"Primo DUI: minimo 50 ore di servizio alla comunit\u00e0, di cui almeno 10 ore prevedono la raccolta di rifiuti."},
  {cat:"alcohol",en:"DUI school (TLSAE) in Florida is:",it:"La scuola DUI in Florida \u00e8:",options:[{en:"A voluntary class reducing fines",it:"Un corso volontario che riduce le multe"},{en:"A mandatory substance abuse education program required for license reinstatement",it:"Un programma obbligatorio di educazione sull'abuso di sostanze richiesto per il ripristino della patente"},{en:"Only for drivers under 21",it:"Solo per i conducenti under 21"},{en:"An online defensive driving course",it:"Un corso online di guida difensiva"}],correct:1,explain_en:"Florida requires DUI school (substance abuse evaluation and education) as a mandatory condition for license reinstatement.",explain_it:"La Florida richiede la scuola DUI come condizione obbligatoria per il ripristino della patente."},
  {cat:"alcohol",en:"The '10-Day Letter' after a DUI arrest is:",it:"La 'Lettera dei 10 Giorni' dopo un arresto DUI \u00e8:",options:[{en:"A letter requiring court appearance in 10 days",it:"Una lettera che richiede comparizione in tribunale entro 10 giorni"},{en:"A temporary driving permit valid 10 days \u2014 allowing time to request a hearing",it:"Un permesso di guida temporaneo valido 10 giorni \u2014 che consente di richiedere un'udienza"},{en:"A 10-day jail sentence",it:"Una pena detentiva di 10 giorni"},{en:"The period for blood test processing",it:"Il periodo per l'elaborazione del test del sangue"}],correct:1,explain_en:"After DUI arrest, drivers receive a 10-Day Letter: a temporary permit valid 10 days to request a formal review hearing.",explain_it:"Dopo l'arresto DUI, i conducenti ricevono la Lettera dei 10 Giorni: un permesso temporaneo valido 10 giorni per richiedere un'udienza."},
  {cat:"alcohol",en:"How does eating before drinking affect BAC?",it:"Come influisce mangiare prima di bere sul BAC?",options:[{en:"Food has no effect on alcohol absorption",it:"Il cibo non ha effetti sull'assorbimento dell'alcol"},{en:"Food slows absorption \u2014 delays peak BAC but does NOT lower total alcohol",it:"Il cibo rallenta l'assorbimento \u2014 ritarda il picco BAC ma NON abbassa il totale"},{en:"Food neutralizes alcohol completely",it:"Il cibo neutralizza l'alcol completamente"},{en:"Fatty foods eliminate alcohol twice as fast",it:"I cibi grassi eliminano l'alcol due volte pi\u00f9 velocemente"}],correct:1,explain_en:"Food slows alcohol absorption and delays peak BAC \u2014 but it does NOT reduce total alcohol processed. Same BAC eventually.",explain_it:"Il cibo rallenta l'assorbimento e ritarda il picco BAC \u2014 ma NON riduce il totale dell'alcol elaborato. Stesso BAC alla fine."},
  {cat:"alcohol",en:"An officer can arrest for DUI based on:",it:"Un agente pu\u00f2 arrestare per DUI in base a:",options:[{en:"Only a BAC of 0.08%+",it:"Solo un BAC di 0,08%+"},{en:"Observable signs of impairment OR a BAC of 0.08%+",it:"Segni osservabili di compromissione O un BAC di 0,08%+"},{en:"Only if the driver refuses a breath test",it:"Solo se il conducente rifiuta un test del respiro"},{en:"Only if there was a crash",it:"Solo se c'\u00e8 stato un incidente"}],correct:1,explain_en:"Officers can arrest based on observable impairment (bloodshot eyes, slurred speech, odor) even before a BAC test.",explain_it:"Gli agenti possono arrestare in base alla compromissione osservabile anche prima di un test BAC."},
  {cat:"alcohol",en:"Which chemical test is required under Florida's Implied Consent?",it:"Quale test chimico \u00e8 richiesto dal Consenso Implicito della Florida?",options:[{en:"Blood test only",it:"Solo il test del sangue"},{en:"Breath, blood, or urine \u2014 as selected by the officer",it:"Respiro, sangue o urine \u2014 come selezionato dall'agente"},{en:"Only the breathalyzer",it:"Solo il breathalyzer"},{en:"Only field sobriety tests",it:"Solo i test di sobriet\u00e0 sul campo"}],correct:1,explain_en:"Under Implied Consent, if lawfully arrested for DUI, you must submit to breath, blood, or urine test as designated by the officer.",explain_it:"In base al Consenso Implicito, se legalmente arrestato per DUI, devi sottoporti a test del respiro, sangue o urine come designato dall'agente."},
  {cat:"alcohol",en:"Florida adults who provide alcohol to minors may face:",it:"Gli adulti in Florida che forniscono alcol ai minori possono affrontare:",options:[{en:"No liability \u2014 only the minor is responsible",it:"Nessuna responsabilit\u00e0 \u2014 solo il minore \u00e8 responsabile"},{en:"Civil and criminal liability if the minor drives and injures someone",it:"Responsabilit\u00e0 civile e penale se il minore guida e ferisce qualcuno"},{en:"Only licensed bars have such liability",it:"Solo i bar con licenza hanno tale responsabilit\u00e0"},{en:"No legal obligation to monitor guest drinking",it:"Nessun obbligo legale di monitorare il bere degli ospiti"}],correct:1,explain_en:"Florida law imposes liability on adults who knowingly provide alcohol to minors if the minor drives and injures or kills someone.",explain_it:"La legge della Florida impone responsabilit\u00e0 agli adulti che forniscono consapevolmente alcol ai minori se il minore guida e ferisce qualcuno."},
  {cat:"alcohol",en:"DUI with a minor under 18 in the vehicle triggers:",it:"Il DUI con un minore under 18 nel veicolo scatena:",options:[{en:"Standard DUI penalties only",it:"Solo penalit\u00e0 DUI standard"},{en:"Enhanced penalties: higher mandatory fines and ignition interlock",it:"Penalit\u00e0 maggiorate: multe obbligatorie pi\u00f9 alte e interlock"},{en:"Only child endangerment charges",it:"Solo accuse di messa in pericolo di minori"},{en:"Automatic permanent revocation",it:"Revoca automatica permanente"}],correct:1,explain_en:"DUI with a minor in the vehicle triggers enhanced penalties in Florida: higher mandatory fines and ignition interlock.",explain_it:"Il DUI con un minore nel veicolo scatena penalit\u00e0 maggiorate in Florida: multe obbligatorie pi\u00f9 alte e interlock."},
  {cat:"alcohol",en:"Open container laws in Florida apply:",it:"Le leggi sui contenitori aperti in Florida si applicano:",options:[{en:"Only while the vehicle is moving",it:"Solo mentre il veicolo \u00e8 in movimento"},{en:"To any vehicle on a public road \u2014 moving or parked",it:"A qualsiasi veicolo su una strada pubblica \u2014 in movimento o parcheggiato"},{en:"Only if the engine is running",it:"Solo se il motore \u00e8 acceso"},{en:"Only if children are present",it:"Solo se sono presenti bambini"}],correct:1,explain_en:"Florida's open container law applies to any vehicle on a public road \u2014 whether moving or parked, engine on or off.",explain_it:"La legge sui contenitori aperti si applica a qualsiasi veicolo su una strada pubblica \u2014 in movimento o parcheggiato, motore acceso o spento."},
  {cat:"alcohol",en:"Florida DUI probation for a first conviction lasts:",it:"La libert\u00e0 vigilata DUI per una prima condanna in Florida dura:",options:[{en:"30 days",it:"30 giorni"},{en:"6 months",it:"6 mesi"},{en:"Up to 1 year",it:"Fino a 1 anno"},{en:"5 years",it:"5 anni"}],correct:2,explain_en:"First DUI conviction: probation up to 1 year. Total sentence (jail + probation) cannot exceed 1 year.",explain_it:"Prima condanna DUI: libert\u00e0 vigilata fino a 1 anno. La pena totale (carcere + libert\u00e0 vigilata) non pu\u00f2 superare 1 anno."},
  {cat:"alcohol",en:"'Horizontal Gaze Nystagmus' (HGN) test looks for:",it:"Il test 'Nistagmo Orizzontale dello Sguardo' (HGN) cerca:",options:[{en:"Pupil dilation changes",it:"Cambiamenti della dilatazione pupillare"},{en:"Involuntary eye jerking when tracking a moving object sideways",it:"Tremore involontario degli occhi quando si segue un oggetto in movimento lateralmente"},{en:"Peripheral vision loss",it:"Perdita della visione periferica"},{en:"Ability to focus on near objects",it:"Capacit\u00e0 di messa a fuoco su oggetti vicini"}],correct:1,explain_en:"HGN: alcohol causes involuntary jerking (nystagmus) of the eyes when tracking sideways. Officers look for onset angle and distinctness.",explain_it:"HGN: l'alcol causa tremore involontario degli occhi quando si traccia lateralmente. Gli agenti cercano l'angolo di inizio e la nitidezza."},
  {cat:"alcohol",en:"Vehicle forfeiture is NOT a penalty for:",it:"La confisca del veicolo NON \u00e8 una penalit\u00e0 per:",options:[{en:"A second DUI",it:"Un secondo DUI"},{en:"A first DUI",it:"Un primo DUI"},{en:"A third DUI",it:"Un terzo DUI"},{en:"DUI manslaughter",it:"Omicidio colposo DUI"}],correct:1,explain_en:"Vehicle forfeiture is not a penalty for a FIRST DUI in Florida. It may be ordered for second and subsequent convictions.",explain_it:"La confisca del veicolo non \u00e8 una penalit\u00e0 per il PRIMO DUI in Florida. Pu\u00f2 essere ordinata per condanne successive."},
  {cat:"alcohol",en:"Which best describes 'DUI manslaughter' in Florida?",it:"Quale descrive meglio l'omicidio colposo DUI in Florida?",options:[{en:"A misdemeanor when death results from DUI",it:"Un'infrazione minore quando la morte deriva dal DUI"},{en:"A second-degree felony when DUI causes the death of another person",it:"Un crimine di secondo grado quando il DUI causa la morte di un'altra persona"},{en:"Only applies to multiple fatalities",it:"Si applica solo a decessi multipli"},{en:"Same classification as standard DUI",it:"Stessa classificazione del DUI standard"}],correct:1,explain_en:"DUI manslaughter (causing death while DUI) is a second-degree felony in Florida with up to 15 years in prison.",explain_it:"L'omicidio colposo DUI (causare la morte mentre si \u00e8 in DUI) \u00e8 un crimine di secondo grado in Florida con fino a 15 anni."},
  {cat:"alcohol",en:"Cold weather, exercise, or fresh air after drinking:",it:"Freddo, esercizio o aria fresca dopo aver bevuto:",options:[{en:"Lower BAC by causing sweating",it:"Abbassano il BAC causando sudorazione"},{en:"Do NOT significantly affect the rate of alcohol metabolism",it:"NON influiscono significativamente sulla velocit\u00e0 del metabolismo dell'alcol"},{en:"Exercise burns alcohol twice as fast",it:"L'esercizio brucia l'alcol due volte pi\u00f9 velocemente"},{en:"Cold weather slows metabolism considerably",it:"Il freddo rallenta considerevolmente il metabolismo"}],correct:1,explain_en:"Nothing speeds up alcohol metabolism \u2014 not cold, exercise, sweating, or fresh air. Only time and the liver.",explain_it:"Niente accelera il metabolismo dell'alcol \u2014 non il freddo, l'esercizio, la sudorazione o l'aria fresca. Solo il tempo e il fegato."},
  {cat:"alcohol",en:"Florida's ignition interlock device (IID) requirement means:",it:"Il requisito del dispositivo interlock per l'accensione (IID) della Florida significa:",options:[{en:"The car starts automatically if BAC is low",it:"L'auto si avvia automaticamente se il BAC \u00e8 basso"},{en:"The driver must blow into a device before starting \u2014 it prevents start if BAC is above threshold",it:"Il conducente deve soffiare nel dispositivo prima di avviare \u2014 impedisce l'avvio se il BAC supera la soglia"},{en:"Only required for commercial drivers",it:"Richiesto solo per i conducenti commerciali"},{en:"An optional safety device",it:"Un dispositivo di sicurezza opzionale"}],correct:1,explain_en:"An IID requires the driver to provide a breath sample before the car will start. If BAC exceeds the threshold, the vehicle won't start.",explain_it:"Un IID richiede al conducente di fornire un campione di respiro prima che l'auto si avvii. Se il BAC supera la soglia, il veicolo non si avvia."},
  {cat:"alcohol",en:"Florida DUI school provides what minimum service?",it:"La scuola DUI della Florida fornisce quale servizio minimo?",options:[{en:"A one-hour online video",it:"Un video online di un'ora"},{en:"A substance abuse evaluation and a course on traffic laws and substance abuse",it:"Una valutazione dell'abuso di sostanze e un corso sulle leggi del traffico e l'abuso di sostanze"},{en:"A defensive driving refresher only",it:"Solo un aggiornamento di guida difensiva"},{en:"A medical examination",it:"Una visita medica"}],correct:1,explain_en:"DUI school provides substance abuse evaluation and education. Further treatment may be ordered based on the evaluation.",explain_it:"La scuola DUI fornisce valutazione e istruzione sull'abuso di sostanze. Ulteriore trattamento pu\u00f2 essere ordinato in base alla valutazione."},
  {cat:"alcohol",en:"At a BAC of 0.10%, driving impairment includes:",it:"A un BAC di 0,10%, la compromissione della guida include:",options:[{en:"Color vision only",it:"Solo la visione dei colori"},{en:"Clear deterioration of reaction time, vehicle control, and braking ability",it:"Chiaro deterioramento del tempo di reazione, controllo del veicolo e capacit\u00e0 di frenata"},{en:"Only difficulty reading signs",it:"Solo difficolt\u00e0 a leggere i segnali"},{en:"No impairment until 0.15%",it:"Nessuna compromissione fino a 0,15%"}],correct:1,explain_en:"At 0.10% BAC: clear deterioration of reaction time and control, slurred speech, slowed thinking, impaired braking.",explain_it:"A 0,10% BAC: chiaro deterioramento del tempo di reazione e controllo, parola rallentata, pensiero rallentato, frenata compromessa."},
  {cat:"alcohol",en:"What does 'BAC' stand for?",it:"Cosa significa 'BAC'?",options:[{en:"Blood Alcohol Count",it:"Blood Alcohol Count"},{en:"Blood Alcohol Content (or Concentration)",it:"Blood Alcohol Content (Concentrazione Alcolica nel Sangue)"},{en:"Breath Alcohol Calculation",it:"Breath Alcohol Calculation"},{en:"Body Alcohol Capability",it:"Body Alcohol Capability"}],correct:1,explain_en:"BAC = Blood Alcohol Content/Concentration. 0.08% means 0.08 grams of alcohol per 100 mL of blood.",explain_it:"BAC = Blood Alcohol Content. 0,08% significa 0,08 grammi di alcol per 100 mL di sangue."},
  {cat:"alcohol",en:"DUI reinstatement in Florida requires:",it:"Il ripristino DUI in Florida richiede:",options:[{en:"Only paying a reinstatement fee",it:"Solo pagare una quota di ripristino"},{en:"DUI school, substance abuse evaluation, any required treatment, fees, and FR-44 insurance",it:"Scuola DUI, valutazione abuso sostanze, eventuale trattamento, quote e assicurazione FR-44"},{en:"Simply wait out the revocation period",it:"Semplicemente aspettare il periodo di revoca"},{en:"Pass the knowledge test only",it:"Solo superare il test di conoscenza"}],correct:1,explain_en:"DUI reinstatement requires: DUI school, substance abuse evaluation (and treatment), reinstatement fee, and FR-44 insurance.",explain_it:"Il ripristino DUI richiede: scuola DUI, valutazione abuso sostanze (e trattamento), quota di ripristino e assicurazione FR-44."},
  {cat:"alcohol",en:"Drug Recognition Experts (DRE) are trained to:",it:"Gli Esperti di Riconoscimento delle Droghe (DRE) sono formati per:",options:[{en:"Analyze blood samples in the lab",it:"Analizzare campioni di sangue in laboratorio"},{en:"Evaluate whether drivers are impaired by drugs other than alcohol",it:"Valutare se i conducenti sono compromessi da droghe diverse dall'alcol"},{en:"Consult on medication-related cases",it:"Consultare su casi legati ai farmaci"},{en:"Specialize as DUI judges",it:"Specializzarsi come giudici DUI"}],correct:1,explain_en:"DREs are specially trained officers using a 12-step evaluation to determine drug impairment beyond alcohol.",explain_it:"I DRE sono agenti appositamente formati che usano una valutazione in 12 fasi per determinare la compromissione da droghe."},
  {cat:"alcohol",en:"Alcohol poisoning is dangerous because:",it:"L'avvelenamento da alcol \u00e8 pericoloso perch\u00e9:",options:[{en:"It is the same as being legally drunk",it:"\u00c8 lo stesso che essere legalmente ubriachi"},{en:"It causes unconsciousness, vomiting, seizures, and respiratory depression \u2014 life-threatening",it:"Causa incoscienza, vomito, convulsioni e depressione respiratoria \u2014 potenzialmente fatale"},{en:"Only a mild hangover effect",it:"Solo un lieve effetto da postumi"},{en:"Only from mixing alcohol with medications",it:"Solo dalla miscela di alcol con farmaci"}],correct:1,explain_en:"Alcohol poisoning (BAC ~0.25%+): unconsciousness, vomiting while unconscious, seizures, respiratory depression. Requires immediate medical attention.",explain_it:"Avvelenamento da alcol (BAC ~0,25%+): incoscienza, vomito, convulsioni, depressione respiratoria. Richiede assistenza medica immediata."},
  {cat:"license",en:"To get a Florida driver's license for the first time you need:",it:"Per ottenere la patente Florida per la prima volta hai bisogno di:",options:[{en:"Another state's license only",it:"Solo la patente di un altro stato"},{en:"Primary ID, Social Security proof, two FL residency proofs, and TLSAE/DETS completion",it:"Documento d'identit\u00e0 primario, prova SS, due prove di residenza FL e completamento TLSAE/DETS"},{en:"Passport and utility bill only",it:"Solo passaporto e bolletta"},{en:"Birth certificate and school enrollment",it:"Certificato di nascita e iscrizione scolastica"}],correct:1,explain_en:"Florida requires: primary ID, Social Security, two FL residency docs, and TLSAE/DETS course completion for first-time applicants.",explain_it:"La Florida richiede: documento primario, previdenza sociale, due documenti di residenza FL e completamento TLSAE/DETS."},
  {cat:"license",en:"TLSAE course for first-time adult drivers is:",it:"Il corso TLSAE per i conducenti adulti per la prima volta \u00e8:",options:[{en:"A 6-hour teen driving course",it:"Un corso di guida adolescenti di 6 ore"},{en:"A 4-hour Traffic Law and Substance Abuse Education course",it:"Un corso di 4 ore sull'Educazione alle Leggi del Traffico e sull'Abuso di Sostanze"},{en:"A technical license exam",it:"Un esame tecnico di patente"},{en:"A commercial vehicle test",it:"Un test per veicoli commerciali"}],correct:1,explain_en:"TLSAE (Traffic Law and Substance Abuse Education) is a 4-hour course required for adults (18+) getting their first Florida license.",explain_it:"TLSAE \u00e8 un corso di 4 ore richiesto per gli adulti (18+) che ottengono la loro prima patente Florida."},
  {cat:"license",en:"Florida's DETS course for teen drivers is:",it:"Il corso DETS della Florida per i conducenti adolescenti \u00e8:",options:[{en:"A 4-hour drug education course",it:"Un corso di educazione sulle droghe di 4 ore"},{en:"A state-approved 6-hour driver education course for drivers under 18",it:"Un corso di educazione alla guida di 6 ore approvato dallo stato per i conducenti under 18"},{en:"A defensive driving course for repeat offenders",it:"Un corso di guida difensiva per recidivi"},{en:"An optional online driving test",it:"Un test di guida online facoltativo"}],correct:1,explain_en:"DETS is a 6-hour state-approved course required for drivers under 18 seeking a Florida learner's license.",explain_it:"DETS \u00e8 un corso di 6 ore approvato dallo stato richiesto per i conducenti under 18 che richiedono il permesso per principianti."},
  {cat:"license",en:"What is a 'Class E' Florida driver license?",it:"Cos'\u00e8 una patente di guida 'Class E' della Florida?",options:[{en:"A commercial truck license",it:"Una patente per camion commerciali"},{en:"The standard non-commercial license for vehicles up to 26,000 lbs GVWR",it:"La patente non commerciale standard per veicoli fino a 26.000 libbre GVWR"},{en:"A motorcycle-only license",it:"Una patente solo per motociclette"},{en:"A learner's permit class",it:"Una classe di permesso per principianti"}],correct:1,explain_en:"Class E is Florida's standard license for non-commercial vehicles with GVWR of 26,000 lbs or less \u2014 the most common type.",explain_it:"La Class E \u00e8 la patente standard della Florida per veicoli non commerciali con GVWR di 26.000 libbre o meno."},
  {cat:"license",en:"Florida's point system adds 6 points for:",it:"Il sistema a punti della Florida aggiunge 6 punti per:",options:[{en:"Speeding 15+ mph over the limit",it:"Eccesso di velocit\u00e0 di 15+ mph"},{en:"Any moving violation causing a crash",it:"Qualsiasi violazione in movimento che causa un incidente"},{en:"Driving on a suspended license",it:"Guidare con la patente sospesa"},{en:"Failure to signal",it:"Mancato uso dei segnali"}],correct:1,explain_en:"Any moving violation causing a crash adds 6 points. Speeding 15+ mph adds 4; less than 15 adds 3.",explain_it:"Qualsiasi violazione in movimento che causa un incidente aggiunge 6 punti. Eccesso 15+ mph aggiunge 4; meno di 15 aggiunge 3."},
  {cat:"license",en:"Speeding 15 mph or more over the limit adds how many points in Florida?",it:"L'eccesso di velocit\u00e0 di 15 mph o pi\u00f9 oltre il limite aggiunge quanti punti in Florida?",options:[{en:"2 points",it:"2 punti"},{en:"3 points",it:"3 punti"},{en:"4 points",it:"4 punti"},{en:"6 points",it:"6 punti"}],correct:2,explain_en:"Speeding 15+ mph over the limit adds 4 points. Less than 15 mph over = 3 points.",explain_it:"L'eccesso di velocit\u00e0 di 15+ mph aggiunge 4 punti. Meno di 15 mph = 3 punti."},
  {cat:"license",en:"How many points trigger a 3-month license suspension in Florida?",it:"Quanti punti provocano una sospensione di 3 mesi in Florida?",options:[{en:"12 points in 12 months",it:"12 punti in 12 mesi"},{en:"18 points in 18 months",it:"18 punti in 18 mesi"},{en:"24 points in 36 months",it:"24 punti in 36 mesi"},{en:"30 points in 36 months",it:"30 punti in 36 mesi"}],correct:1,explain_en:"Florida: 12 pts/12mo = 30 days; 18 pts/18mo = 3 months; 24 pts/36mo = 1 year.",explain_it:"Florida: 12 punti/12 mesi = 30 giorni; 18 punti/18 mesi = 3 mesi; 24 punti/36 mesi = 1 anno."},
  {cat:"license",en:"A Florida driver can avoid points after a citation by:",it:"Un conducente in Florida pu\u00f2 evitare i punti dopo una multa:",options:[{en:"Paying the fine immediately",it:"Pagando immediatamente la multa"},{en:"Electing a BDI course within 30 days to withhold adjudication",it:"Scegliendo un corso BDI entro 30 giorni per sospendere il giudizio"},{en:"Points cannot be avoided for any violation",it:"I punti non possono essere evitati"},{en:"Contesting the ticket always removes points",it:"Contestare la multa rimuove sempre i punti"}],correct:1,explain_en:"Florida allows a BDI (Basic Driver Improvement) course once/year (up to 5 times lifetime) to withhold adjudication and avoid points.",explain_it:"La Florida consente un corso BDI una volta all'anno (fino a 5 volte nel corso della vita) per sospendere il giudizio ed evitare i punti."},
  {cat:"license",en:"'Withhold of adjudication' for a traffic ticket means:",it:"La 'sospensione del giudizio' per una multa significa:",options:[{en:"The ticket is dismissed with no fine",it:"La multa viene archiviata senza multa"},{en:"The court does not formally convict you \u2014 no points added",it:"Il tribunale non ti condanna formalmente \u2014 nessun punto aggiunto"},{en:"You are convicted but fine is reduced",it:"Sei condannato ma la multa \u00e8 ridotta"},{en:"The ticket is deferred 6 months",it:"La multa viene rinviata di 6 mesi"}],correct:1,explain_en:"Withhold of adjudication: court accepts your plea without formally adjudicating guilty \u2014 no conviction and no points.",explain_it:"Sospensione del giudizio: il tribunale accetta la dichiarazione senza giudicare formalmente colpevole \u2014 nessuna condanna e nessun punto."},
  {cat:"license",en:"Major violations leading to habitual offender status include:",it:"Le violazioni gravi che portano allo status di trasgressore abituale includono:",options:[{en:"Any speeding ticket",it:"Qualsiasi multa per eccesso di velocit\u00e0"},{en:"DUI, leaving the scene, racing, fleeing law enforcement",it:"DUI, fuga dalla scena, corse, fuga dalle forze dell'ordine"},{en:"Parking violations",it:"Violazioni di parcheggio"},{en:"Failure to renew registration",it:"Mancato rinnovo della registrazione"}],correct:1,explain_en:"Major violations: DUI, leaving the scene, driving with revoked license, racing, and fleeing from law enforcement.",explain_it:"Violazioni gravi: DUI, fuga dalla scena, guida con patente revocata, corse e fuga dalle forze dell'ordine."},
  {cat:"license",en:"Florida's FR-44 (SR-22) insurance certificate proves:",it:"Il certificato assicurativo FR-44 (SR-22) della Florida prova:",options:[{en:"You own the vehicle",it:"Sei proprietario del veicolo"},{en:"You carry the state-required minimum liability insurance \u2014 filed by insurer with FLHSMV",it:"Hai l'assicurazione di responsabilit\u00e0 minima richiesta dallo stato \u2014 presentata dall'assicuratore al FLHSMV"},{en:"Special teen driver insurance",it:"Assicurazione speciale per conducenti adolescenti"},{en:"Collision insurance after any accident",it:"Assicurazione di collisione dopo qualsiasi incidente"}],correct:1,explain_en:"FR-44/SR-22: certificate filed by your insurer with FLHSMV proving minimum required insurance \u2014 needed after certain violations.",explain_it:"FR-44/SR-22: certificato presentato dall'assicuratore al FLHSMV che prova l'assicurazione minima \u2014 richiesto dopo alcune violazioni."},
  {cat:"license",en:"What is 'PIP' insurance in Florida?",it:"Cos'\u00e8 l'assicurazione 'PIP' in Florida?",options:[{en:"Property Insurance Protection",it:"Property Insurance Protection"},{en:"Personal Injury Protection \u2014 pays your medical expenses regardless of fault, up to $10,000",it:"Personal Injury Protection \u2014 paga le spese mediche indipendentemente dalla responsabilit\u00e0, fino a $10.000"},{en:"Pedestrian Injury Protection",it:"Pedestrian Injury Protection"},{en:"Permanent Injury Plan",it:"Permanent Injury Plan"}],correct:1,explain_en:"PIP is Florida's no-fault insurance paying up to $10,000 for your medical expenses and 60% lost wages after a crash.",explain_it:"PIP \u00e8 l'assicurazione no-fault della Florida che paga fino a $10.000 per spese mediche e 60% dei salari persi dopo un incidente."},
  {cat:"license",en:"Florida's minimum PDL (Property Damage Liability) requirement is:",it:"Il requisito minimo PDL (Responsabilit\u00e0 per Danni alla Propriet\u00e0) della Florida \u00e8:",options:[{en:"$5,000",it:"$5.000"},{en:"$10,000",it:"$10.000"},{en:"$25,000",it:"$25.000"},{en:"$50,000",it:"$50.000"}],correct:1,explain_en:"Florida requires a minimum $10,000 PDL (Property Damage Liability) covering damage you cause to another's property.",explain_it:"La Florida richiede un minimo di $10.000 PDL che copre i danni causati alla propriet\u00e0 di un'altra persona."},
  {cat:"license",en:"Florida's Graduated Driver License (GDL) curfew is:",it:"Il coprifuoco della Patente a Guida Progressiva (GDL) della Florida \u00e8:",options:[{en:"9 PM to 6 AM",it:"21:00-6:00"},{en:"11 PM to 6 AM",it:"23:00-6:00"},{en:"10 PM to 5 AM",it:"22:00-5:00"},{en:"Midnight to 5 AM",it:"Mezzanotte-5:00"}],correct:1,explain_en:"GDL curfew: teens on provisional license may not drive from 11 PM to 6 AM (with exceptions for work, school, etc.).",explain_it:"Coprifuoco GDL: i giovani con patente provvisoria non possono guidare dalle 23:00 alle 6:00 (con eccezioni per lavoro, scuola, ecc.)."},
  {cat:"license",en:"During the first year of a Florida provisional license, passengers under 18 are limited to:",it:"Durante il primo anno di patente provvisoria in Florida, i passeggeri under 18 sono limitati a:",options:[{en:"No limit",it:"Nessun limite"},{en:"Only 1 passenger under 18 unless a licensed adult 21+ is present",it:"Solo 1 passeggero under 18 a meno che non ci sia un adulto con patente 21+ presente"},{en:"No passengers under 18 at all",it:"Nessun passeggero under 18"},{en:"Maximum 3 regardless of age",it:"Massimo 3 indipendentemente dall'et\u00e0"}],correct:1,explain_en:"First year provisional: only 1 passenger under 18 unless a licensed driver 21+ is in the vehicle. Family members exempt.",explain_it:"Primo anno provvisorio: solo 1 passeggero under 18 a meno che non ci sia un conducente patentato 21+ nel veicolo. Familiari esenti."},
  {cat:"license",en:"'Driving While License Suspended' (DWLS) is in Florida:",it:"'Guidare con la Patente Sospesa' (DWLS) in Florida \u00e8:",options:[{en:"A civil infraction with $50 fine",it:"Un'infrazione civile con multa di $50"},{en:"A criminal offense \u2014 misdemeanor first, felony third+ offense",it:"Un reato penale \u2014 infrazione minore al primo, crimine alla terza+ offesa"},{en:"Only results in points being added",it:"Risulta solo nell'aggiunta di punti"},{en:"Not prohibited for work/school driving",it:"Non vietato per guidare al lavoro/scuola"}],correct:1,explain_en:"DWLS: first offense = 2nd-degree misdemeanor; second = 1st-degree misdemeanor; third+ = 3rd-degree felony.",explain_it:"DWLS: prima offesa = infrazione minore di 2\u00b0 grado; seconda = 1\u00b0 grado; terza+ = crimine di 3\u00b0 grado."},
  {cat:"license",en:"Florida's Financial Responsibility Law requires drivers to:",it:"La Legge sulla Responsabilit\u00e0 Finanziaria della Florida richiede ai conducenti di:",options:[{en:"Pay taxes on vehicle purchases",it:"Pagare le tasse sugli acquisti di veicoli"},{en:"Maintain minimum insurance to cover damages they cause to others",it:"Mantenere un'assicurazione minima per coprire i danni causati agli altri"},{en:"Register all vehicles with a loan",it:"Registrare tutti i veicoli con un prestito"},{en:"Prove income to obtain a license",it:"Dimostrare il reddito per ottenere la patente"}],correct:1,explain_en:"Florida's Financial Responsibility Law: all drivers must be financially responsible for damages they cause \u2014 minimum PIP + PDL.",explain_it:"La Legge sulla Responsabilit\u00e0 Finanziaria: tutti i conducenti devono essere finanziariamente responsabili per i danni \u2014 minimo PIP + PDL."},
  {cat:"license",en:"Reckless driving conviction in Florida adds:",it:"La condanna per guida spericolata in Florida aggiunge:",options:[{en:"No points",it:"Nessun punto"},{en:"4 points \u2014 and the court may suspend your license",it:"4 punti \u2014 e il tribunale pu\u00f2 sospendere la patente"},{en:"Automatic 1-year revocation",it:"Revoca automatica di 1 anno"},{en:"Only a warning for first offense",it:"Solo un avvertimento alla prima offesa"}],correct:1,explain_en:"Reckless driving: 4 points added. Courts may also impose discretionary license suspension.",explain_it:"Guida spericolata: 4 punti aggiunti. I tribunali possono anche imporre una sospensione discrezionale."},
  {cat:"license",en:"Florida's organ donor program on a driver's license is:",it:"Il programma di donazione degli organi sulla patente della Florida \u00e8:",options:[{en:"Mandatory for all holders",it:"Obbligatorio per tutti i titolari"},{en:"Voluntary \u2014 designation noted on license and in the registry",it:"Volontario \u2014 la designazione \u00e8 annotata sulla patente e nel registro"},{en:"Requires parental consent under 21",it:"Richiede il consenso dei genitori under 21"},{en:"Has no legal effect",it:"Non ha effetto legale"}],correct:1,explain_en:"Florida organ donor program is voluntary. Designation is stored in the Florida Organ and Tissue Donor Registry.",explain_it:"Il programma \u00e8 volontario. La designazione \u00e8 memorizzata nel Registro dei Donatori di Organi e Tessuti della Florida."},
  {cat:"license",en:"The minimum age for interstate CDL driving in Florida is:",it:"L'et\u00e0 minima per la guida CDL interstatale in Florida \u00e8:",options:[{en:"18 for all CDL",it:"18 per tutto il CDL"},{en:"18 intrastate; 21 interstate",it:"18 intrastatale; 21 interstatale"},{en:"21 for all CDL",it:"21 per tutto il CDL"},{en:"16 with parental consent",it:"16 con il consenso dei genitori"}],correct:1,explain_en:"CDL: minimum 18 years for intrastate (within Florida), 21 years for interstate (crossing state lines) operations.",explain_it:"CDL: minimo 18 anni per intrastatale (all'interno della Florida), 21 anni per interstatale (attraversamento dei confini statali)."},
  {cat:"license",en:"Florida comparative negligence means:",it:"La negligenza comparata della Florida significa:",options:[{en:"Only the most negligent party pays",it:"Solo la parte pi\u00f9 negligente paga"},{en:"Each party pays in proportion to their percentage of fault",it:"Ogni parte paga in proporzione alla loro percentuale di responsabilit\u00e0"},{en:"Negligence determined only by police report",it:"La negligenza determinata solo dalla relazione della polizia"},{en:"Florida uses pure contributory negligence",it:"La Florida usa la negligenza contributiva pura"}],correct:1,explain_en:"Modified comparative negligence: if more than 50% at fault, you cannot recover damages. Otherwise, compensation reduced by fault %.",explain_it:"Negligenza comparata modificata: se pi\u00f9 del 50% responsabile, non puoi recuperare danni. Altrimenti, compensazione ridotta della % di responsabilit\u00e0."},
  {cat:"license",en:"Information to exchange after a Florida crash includes:",it:"Le informazioni da scambiare dopo un incidente in Florida includono:",options:[{en:"Insurance company and policy number only",it:"Solo compagnia assicurativa e numero di polizza"},{en:"Name, address, vehicle registration number, and insurance information",it:"Nome, indirizzo, numero di registrazione del veicolo e informazioni assicurative"},{en:"License plate number only",it:"Solo il numero di targa"},{en:"Only your driver's license number",it:"Solo il tuo numero di patente"}],correct:1,explain_en:"After a crash exchange: name, address, vehicle registration number, and proof of insurance. Also provide driver's license if requested.",explain_it:"Dopo un incidente scambia: nome, indirizzo, numero di registrazione del veicolo e prova dell'assicurazione."},
  {cat:"license",en:"Florida restriction codes on a license indicate:",it:"I codici di restrizione su una patente della Florida indicano:",options:[{en:"The license has been suspended",it:"La patente \u00e8 stata sospesa"},{en:"A specific condition \u2014 such as 'corrective lenses required'",it:"Una condizione specifica \u2014 come 'lenti correttive richieste'"},{en:"The driver is on probation",it:"Il conducente \u00e8 in libert\u00e0 vigilata"},{en:"The license is provisional",it:"La patente \u00e8 provvisoria"}],correct:1,explain_en:"Restriction codes indicate conditions on driving privileges: corrective lenses (A), daytime only (B), no expressway, etc.",explain_it:"I codici di restrizione indicano condizioni sui privilegi di guida: lenti correttive (A), solo di giorno (B), nessuna autostrada, ecc."},
  {cat:"license",en:"What is a 'hardship reinstatement' in Florida?",it:"Cos'\u00e8 un 'ripristino per necessit\u00e0' in Florida?",options:[{en:"Automatic reinstatement after paying a fine",it:"Ripristino automatico dopo aver pagato una multa"},{en:"A court-granted limited driving privilege during suspension for work or medical needs",it:"Un privilegio di guida limitato concesso dal tribunale durante una sospensione per lavoro o cure mediche"},{en:"A traffic school to reduce suspension length",it:"Una scuola di guida per ridurre la sospensione"},{en:"Emergency driving rights granted by the DMV",it:"Diritti di guida di emergenza concessi dal DMV"}],correct:1,explain_en:"Hardship reinstatement (BPO or EPO license): court-granted limited driving privilege for essential needs during suspension.",explain_it:"Il ripristino per necessit\u00e0: privilegio di guida limitato concesso dal tribunale per bisogni essenziali durante una sospensione."},
  {cat:"license",en:"To get a motorcycle endorsement on a Florida license you must:",it:"Per ottenere l'abilitazione alla moto sulla patente Florida devi:",options:[{en:"Pass the same Class E test",it:"Superare lo stesso test Class E"},{en:"Complete a MSAP course or pass a motorcycle skills test",it:"Completare un corso MSAP o superare un test di abilit\u00e0 moto"},{en:"Only an online motorcycle theory exam",it:"Solo un esame teorico online sulla moto"},{en:"No additional requirement",it:"Nessun requisito aggiuntivo"}],correct:1,explain_en:"Motorcycle endorsement: complete MSAP (Motorcycle Safety Awareness Program) or pass the DHSMV motorcycle skills test.",explain_it:"Abilitazione moto: completa il corso MSAP o supera il test di abilit\u00e0 moto DHSMV."},
  {cat:"license",en:"Florida vision screening for a driver's license requires:",it:"Lo screening visivo della Florida per la patente richiede:",options:[{en:"All drivers to have 20/20 uncorrected vision",it:"Tutti i conducenti con visione 20/20 non corretta"},{en:"Meeting minimum standards \u2014 corrective lenses noted on license if needed",it:"Soddisfare gli standard minimi \u2014 le lenti correttive vengono annotate sulla patente se necessario"},{en:"Screening only for drivers over 65",it:"Screening solo per i conducenti over 65"},{en:"Vision is not tested",it:"La visione non viene testata"}],correct:1,explain_en:"Florida requires vision screening during license application. If corrective lenses are required, this appears as a restriction on the license.",explain_it:"La Florida richiede lo screening visivo. Se sono richieste lenti correttive, appare come restrizione sulla patente."},
  {cat:"license",en:"GDL curfew exceptions in Florida include:",it:"Le eccezioni al coprifuoco GDL in Florida includono:",options:[{en:"No exceptions",it:"Nessuna eccezione"},{en:"Driving to/from work, school, or with a licensed adult 21+",it:"Guidare da/verso lavoro, scuola o con un adulto patentato 21+"},{en:"Only on school nights",it:"Solo nelle notti scolastiche"},{en:"Only after 6 months of holding the license",it:"Solo dopo 6 mesi dalla patente"}],correct:1,explain_en:"GDL curfew (11 PM\u20136 AM) exceptions: travel to/from work, school-sanctioned activities, or with licensed 21+ driver in front seat.",explain_it:"Eccezioni coprifuoco GDL (23:00-6:00): viaggio da/verso lavoro, attivit\u00e0 scolastiche o con conducente 21+ in sedile anteriore."},
  {cat:"license",en:"A 'moving violation' is any traffic violation that occurs:",it:"Una 'violazione in movimento' \u00e8 qualsiasi violazione del traffico che si verifica:",options:[{en:"While a vehicle is being towed",it:"Mentre un veicolo viene trainato"},{en:"While the vehicle is in motion \u2014 speeding, red lights, illegal turns",it:"Mentre il veicolo \u00e8 in movimento \u2014 eccesso di velocit\u00e0, semafori rossi, svolte illegali"},{en:"Only in construction zones",it:"Solo nelle zone di lavori"},{en:"Only for commercial drivers",it:"Solo per i conducenti commerciali"}],correct:1,explain_en:"A moving violation occurs while the vehicle is in motion \u2014 speeding, red lights, illegal turns, failure to yield. Adds points to record.",explain_it:"Una violazione in movimento si verifica mentre il veicolo \u00e8 in movimento \u2014 eccesso di velocit\u00e0, rosso, svolte illegali. Aggiunge punti al casellario."},
  {cat:"license",en:"Non-owner auto insurance provides:",it:"L'assicurazione auto non-proprietario fornisce:",options:[{en:"Coverage when someone borrows your car",it:"Copertura quando qualcuno prende in prestito la tua auto"},{en:"Liability coverage for drivers who don't own a vehicle but occasionally drive others' cars",it:"Copertura di responsabilit\u00e0 per i conducenti che non possiedono un veicolo ma guidano occasionalmente le auto degli altri"},{en:"Rental car insurance only",it:"Solo assicurazione per auto a noleggio"},{en:"Coverage only for commercial vehicles",it:"Copertura solo per veicoli commerciali"}],correct:1,explain_en:"Non-owner insurance provides liability coverage for drivers without a vehicle who occasionally borrow or rent cars. Often required for reinstatement.",explain_it:"L'assicurazione non-proprietario fornisce copertura di responsabilit\u00e0 per i conducenti senza veicolo che guidano occasionalmente auto degli altri."},
  {cat:"license",en:"Florida license reinstatement fee after a point suspension is typically:",it:"La quota di ripristino della patente dopo una sospensione per punti \u00e8 tipicamente:",options:[{en:"Free \u2014 reinstatement is automatic",it:"Gratuita \u2014 il ripristino \u00e8 automatico"},{en:"Around $45-$60 plus any required course fees",it:"Circa $45-$60 pi\u00f9 eventuali quote del corso"},{en:"A flat $500 fine",it:"Una multa fissa di $500"},{en:"Only the cost of a new photo",it:"Solo il costo di una nuova foto"}],correct:1,explain_en:"Florida charges a reinstatement fee (~$45 basic) plus any required course fees (BDI, DUI school, etc.) to restore a suspended license.",explain_it:"La Florida addebita una quota di ripristino (~$45 base) pi\u00f9 eventuali quote del corso (BDI, scuola DUI, ecc.)."},
  {cat:"license",en:"What is Florida's 'no-fault' insurance system?",it:"Cos'\u00e8 il sistema assicurativo 'no-fault' della Florida?",options:[{en:"Drivers pay their own expenses regardless of fault",it:"I conducenti pagano le proprie spese indipendentemente dalla responsabilit\u00e0"},{en:"PIP pays your own medical expenses up to $10,000 regardless of who caused the crash",it:"Il PIP paga le tue spese mediche fino a $10.000 indipendentemente da chi ha causato l'incidente"},{en:"Nobody is ever at fault in Florida",it:"Nessuno \u00e8 mai responsabile in Florida"},{en:"Insurance companies determine fault before any payment",it:"Le compagnie assicurative determinano la responsabilit\u00e0 prima di qualsiasi pagamento"}],correct:1,explain_en:"Florida's no-fault system: PIP pays your own medical costs up to $10,000 regardless of fault, speeding up claims.",explain_it:"Il sistema no-fault della Florida: il PIP paga le tue spese mediche fino a $10.000 indipendentemente dalla responsabilit\u00e0, accelerando le richieste."},
  {cat:"license",en:"Florida requires proof of PIP and PDL insurance to be carried:",it:"La Florida richiede che la prova dell'assicurazione PIP e PDL sia portata:",options:[{en:"Only for commercial vehicles",it:"Solo per i veicoli commerciali"},{en:"At all times in the vehicle",it:"In ogni momento nel veicolo"},{en:"Only when driving on interstates",it:"Solo quando si guida sulle autostrade interstatali"},{en:"Only when towing",it:"Solo quando si traino"}],correct:1,explain_en:"Florida law requires proof of PIP and PDL insurance in the vehicle at all times. Failure to present it = citation.",explain_it:"La legge della Florida richiede la prova dell'assicurazione nel veicolo in ogni momento. Mancata presentazione = citazione."},
  {cat:"license",en:"What does Florida's 'Implied Consent' mean for driving?",it:"Cosa significa il 'Consenso Implicito' della Florida per la guida?",options:[{en:"You must verbally consent to every stop",it:"Devi acconsentire verbalmente a ogni fermo"},{en:"Operating a vehicle = automatic consent to BAC testing if lawfully arrested for DUI",it:"Operare un veicolo = consenso automatico ai test BAC se legalmente arrestato per DUI"},{en:"You must sign a form before driving",it:"Devi firmare un modulo prima di guidare"},{en:"Police cannot search without verbal consent",it:"La polizia non pu\u00f2 perquisire senza consenso verbale"}],correct:1,explain_en:"Florida Implied Consent: obtaining a license and driving = automatic consent to chemical BAC testing when lawfully arrested.",explain_it:"Consenso Implicito Florida: ottenere la patente e guidare = consenso automatico ai test chimici BAC quando legalmente arrestato."},
  {cat:"license",en:"Florida habitual offender status results from accumulating how many major convictions in 5 years?",it:"Lo status di trasgressore abituale in Florida deriva dall'accumulo di quante condanne gravi in 5 anni?",options:[{en:"2 major convictions",it:"2 condanne gravi"},{en:"3 major convictions",it:"3 condanne gravi"},{en:"4 major convictions",it:"4 condanne gravi"},{en:"5 major convictions",it:"5 condanne gravi"}],correct:1,explain_en:"3 major violations (DUI, leaving scene, racing, etc.) within 5 years = habitual traffic offender status and 5-year revocation.",explain_it:"3 violazioni gravi (DUI, fuga dalla scena, corse, ecc.) in 5 anni = status di trasgressore abituale e revoca di 5 anni."},
  {cat:"license",en:"What is 'comparative negligence' in Florida accident law?",it:"Cos'\u00e8 la 'negligenza comparata' nella legge sugli incidenti in Florida?",options:[{en:"Only the most negligent party pays",it:"Solo la parte pi\u00f9 negligente paga"},{en:"Each party's compensation is reduced by their percentage of fault",it:"Il risarcimento di ogni parte \u00e8 ridotto della loro percentuale di responsabilit\u00e0"},{en:"Fault only determined by police",it:"La responsabilit\u00e0 determinata solo dalla polizia"},{en:"Florida uses pure contributory negligence",it:"La Florida usa la negligenza contributiva pura"}],correct:1,explain_en:"Modified comparative negligence: your compensation is reduced by your % of fault. If 50%+ at fault, you cannot recover damages.",explain_it:"Negligenza comparata modificata: il tuo risarcimento \u00e8 ridotto della tua % di responsabilit\u00e0. Se 50%+ responsabile, non puoi recuperare danni."},
  {cat:"license",en:"Florida license suspension of 30 days is triggered by:",it:"La sospensione della patente di 30 giorni in Florida \u00e8 scatenata da:",options:[{en:"18 points in 18 months",it:"18 punti in 18 mesi"},{en:"12 points in 12 months",it:"12 punti in 12 mesi"},{en:"24 points in 36 months",it:"24 punti in 36 mesi"},{en:"6 points in 6 months",it:"6 punti in 6 mesi"}],correct:1,explain_en:"12 points within 12 months = 30-day suspension. 18 points/18 months = 3 months. 24 points/36 months = 1 year.",explain_it:"12 punti in 12 mesi = sospensione di 30 giorni. 18 punti/18 mesi = 3 mesi. 24 punti/36 mesi = 1 anno."},
  {cat:"license",en:"Florida license reinstatement after DUI revocation requires maintaining FR-44 for:",it:"Il ripristino della patente Florida dopo la revoca DUI richiede di mantenere l'FR-44 per:",options:[{en:"6 months",it:"6 mesi"},{en:"3 years from reinstatement date",it:"3 anni dalla data di ripristino"},{en:"1 year",it:"1 anno"},{en:"Only until the first renewal",it:"Solo fino al primo rinnovo"}],correct:1,explain_en:"FR-44 insurance must be maintained for 3 years from the reinstatement date after a DUI revocation.",explain_it:"L'assicurazione FR-44 deve essere mantenuta per 3 anni dalla data di ripristino dopo una revoca DUI."},
  {cat:"signs",en:"What does a STOP sign require you to do?",it:"Cosa richiede un segnale STOP?",options:[{en:"Slow to 5 mph and proceed if clear",it:"Rallentare a 5 mph e procedere se libero"},{en:"Come to a complete stop before the line, then yield before proceeding",it:"Effettuare un arresto completo prima della linea, poi cedere la precedenza"},{en:"Stop only if other vehicles are present",it:"Fermarsi solo se altri veicoli sono presenti"},{en:"Stop for 3 seconds then go",it:"Fermarsi 3 secondi poi andare"}],correct:1,explain_en:"A STOP sign requires a complete stop before the stop line or crosswalk. After stopping, yield to all traffic and pedestrians before proceeding.",explain_it:"Un segnale STOP richiede un arresto completo prima della linea. Dopo la fermata, cedi la precedenza a tutto il traffico e ai pedoni prima di procedere."},
  {cat:"signs",en:"What color are guide signs (showing routes and distances) on highways?",it:"Di che colore sono i segnali di guida (percorsi e distanze) in autostrada?",options:[{en:"Blue",it:"Blu"},{en:"Green",it:"Verde"},{en:"White",it:"Bianco"},{en:"Brown",it:"Marrone"}],correct:1,explain_en:"Green signs are used for highway guide information \u2014 route numbers, distances to cities, and highway exits.",explain_it:"I segnali verdi sono usati per le informazioni guida in autostrada \u2014 numeri di percorso, distanze dalle citta e uscite."},
  {cat:"signs",en:"What color are recreational and cultural interest signs?",it:"Di che colore sono i segnali per aree ricreative e di interesse culturale?",options:[{en:"Green",it:"Verde"},{en:"Blue",it:"Blu"},{en:"Brown",it:"Marrone"},{en:"Yellow",it:"Giallo"}],correct:2,explain_en:"Brown signs indicate recreational areas, parks, scenic areas, and cultural points of interest.",explain_it:"I segnali marroni indicano aree ricreative, parchi, zone panoramiche e punti di interesse culturale."},
  {cat:"signs",en:"What do blue highway signs indicate?",it:"Cosa indicano i segnali blu in autostrada?",options:[{en:"Speed limits",it:"Limiti di velocita"},{en:"Motorist services \u2014 gas, food, lodging, hospitals",it:"Servizi per automobilisti \u2014 carburante, cibo, alloggio, ospedali"},{en:"Construction zones",it:"Zone di costruzione"},{en:"State border crossings",it:"Attraversamenti di confini statali"}],correct:1,explain_en:"Blue signs indicate motorist services: gas stations, restaurants, lodging, hospitals, and rest areas.",explain_it:"I segnali blu indicano servizi per automobilisti: stazioni di servizio, ristoranti, alloggi, ospedali e aree di sosta."},
  {cat:"signs",en:"A flashing yellow traffic light means:",it:"Un semaforo giallo lampeggiante significa:",options:[{en:"Stop and wait for green",it:"Fermarsi e aspettare il verde"},{en:"Proceed with caution \u2014 slow down and watch for hazards",it:"Procedere con cautela \u2014 rallentare e fare attenzione ai pericoli"},{en:"The light is malfunctioning \u2014 treat as four-way stop",it:"Il semaforo e in avaria \u2014 trattare come incrocio a quattro vie"},{en:"Yield to all traffic",it:"Cedere la precedenza a tutto il traffico"}],correct:1,explain_en:"A flashing yellow light means slow down and proceed with caution. It is a warning signal, not a stop signal.",explain_it:"Un semaforo giallo lampeggiante significa rallentare e procedere con cautela. E un segnale di avvertimento, non di stop."},
  {cat:"signs",en:"A flashing red traffic light means:",it:"Un semaforo rosso lampeggiante significa:",options:[{en:"Proceed at reduced speed",it:"Procedere a velocita ridotta"},{en:"Stop completely, then proceed when safe \u2014 same as a STOP sign",it:"Fermarsi completamente, poi procedere quando sicuro \u2014 come un segnale STOP"},{en:"Yield without stopping",it:"Cedere senza fermarsi"},{en:"Signal is broken \u2014 proceed normally",it:"Il segnale e rotto \u2014 procedere normalmente"}],correct:1,explain_en:"A flashing red light is treated the same as a STOP sign: come to a complete stop, then proceed when safe.",explain_it:"Un semaforo rosso lampeggiante si tratta come un segnale STOP: fermata completa, poi procedere quando sicuro."},
  {cat:"signs",en:"What does a green arrow on a traffic signal mean?",it:"Cosa significa una freccia verde su un semaforo?",options:[{en:"Proceed in any direction",it:"Procedere in qualsiasi direzione"},{en:"A protected turn is allowed in the direction of the arrow \u2014 oncoming traffic is stopped",it:"E consentita una svolta protetta nella direzione della freccia \u2014 il traffico in arrivo e fermato"},{en:"Yield before turning in arrow direction",it:"Cedere prima di svoltare nella direzione della freccia"},{en:"Turn only if no pedestrians are crossing",it:"Svoltare solo se non ci sono pedoni che attraversano"}],correct:1,explain_en:"A green arrow means a protected turn \u2014 oncoming traffic and conflicting movements are stopped by red lights.",explain_it:"Una freccia verde significa una svolta protetta \u2014 il traffico in arrivo e i movimenti in conflitto sono fermati dal rosso."},
  {cat:"signs",en:"A 'Wrong Way' sign means:",it:"Un segnale 'Wrong Way' significa:",options:[{en:"You may proceed but use caution",it:"Puoi procedere ma con cautela"},{en:"You are driving against the flow of traffic \u2014 turn around immediately",it:"Stai guidando contro il flusso del traffico \u2014 gira immediatamente"},{en:"A detour is required ahead",it:"E richiesta una deviazione in avanti"},{en:"Construction workers are present",it:"Sono presenti operai edili"}],correct:1,explain_en:"A Wrong Way sign means you have entered a road going in the wrong direction. Turn around immediately and exit safely.",explain_it:"Un segnale Wrong Way significa che hai imboccato una strada nella direzione sbagliata. Gira subito e esci in sicurezza."},
  {cat:"signs",en:"What does a 'Do Not Enter' sign look like?",it:"Come appare un segnale 'Do Not Enter'?",options:[{en:"A yellow diamond with an X",it:"Un rombo giallo con una X"},{en:"A white square with red circle containing a white horizontal bar",it:"Un quadrato bianco con cerchio rosso contenente una barra orizzontale bianca"},{en:"A red octagon with white letters",it:"Un ottagono rosso con lettere bianche"},{en:"A black rectangle with white text",it:"Un rettangolo nero con testo bianco"}],correct:1,explain_en:"The Do Not Enter sign is a white square with a red circle and white horizontal bar. It marks one-way entries where you cannot enter.",explain_it:"Il segnale Do Not Enter e un quadrato bianco con cerchio rosso e barra orizzontale bianca. Segna ingressi a senso unico dove non puoi entrare."},
  {cat:"signs",en:"What does a 'One Way' sign look like?",it:"Come appare un segnale 'One Way'?",options:[{en:"A yellow circle with a single arrow",it:"Un cerchio giallo con una singola freccia"},{en:"A black rectangle with a white arrow pointing in the direction of travel",it:"Un rettangolo nero con una freccia bianca che punta nella direzione di marcia"},{en:"A red square with a white arrow",it:"Un quadrato rosso con una freccia bianca"},{en:"A white diamond with a black arrow",it:"Un rombo bianco con una freccia nera"}],correct:1,explain_en:"One Way signs are black rectangles with white arrows indicating the only direction of traffic flow.",explain_it:"I segnali One Way sono rettangoli neri con frecce bianche che indicano l'unica direzione del flusso del traffico."},
  {cat:"signs",en:"A 'Merge' sign means:",it:"Un segnale 'Merge' significa:",options:[{en:"Stop and wait for a gap in traffic",it:"Fermarsi e aspettare un'apertura nel traffico"},{en:"Your lane is ending and you must merge with the adjacent lane",it:"La tua corsia sta finendo e devi confluire con la corsia adiacente"},{en:"The road is widening \u2014 an extra lane is added",it:"La strada si allarga \u2014 viene aggiunta una corsia extra"},{en:"A lane is closing ahead due to construction",it:"Una corsia si chiude in avanti per lavori"}],correct:1,explain_en:"A Merge sign warns that your lane (or an entering lane) is combining with another. Adjust speed and position to merge safely.",explain_it:"Un segnale Merge avverte che la tua corsia si sta unendo a un'altra. Regola velocita e posizione per confluire in sicurezza."},
  {cat:"signs",en:"What does a 'Keep Right' sign indicate?",it:"Cosa indica un segnale 'Keep Right'?",options:[{en:"Pass only on the right",it:"Sorpassare solo a destra"},{en:"You must stay to the right side of a divider, island, or obstacle",it:"Devi rimanere sul lato destro di un divisore, isola o ostacolo"},{en:"Right turns only at the next intersection",it:"Solo svolte a destra al prossimo incrocio"},{en:"Right lane must be used on this road",it:"La corsia destra deve essere usata su questa strada"}],correct:1,explain_en:"Keep Right signs indicate a physical divider, island, or obstruction that you must pass on the right side.",explain_it:"I segnali Keep Right indicano un divisore fisico, isola o ostacolo che devi passare sul lato destro."},
  {cat:"signs",en:"What does a 'Dead End' sign mean?",it:"Cosa significa un segnale 'Dead End'?",options:[{en:"The road becomes unpaved ahead",it:"La strada diventa non asfaltata in avanti"},{en:"The road ahead has no outlet \u2014 you must turn around",it:"La strada in avanti non ha sbocco \u2014 devi girare"},{en:"No trucks allowed on this road",it:"Nessun camion consentito su questa strada"},{en:"The road merges with a highway ahead",it:"La strada confluisce con un'autostrada in avanti"}],correct:1,explain_en:"A Dead End sign warns that the road has no outlet. Turn around before reaching the dead end.",explain_it:"Un segnale Dead End avverte che la strada non ha sbocco. Gira prima di raggiungere il vicolo cieco."},
  {cat:"signs",en:"What does a 'Pedestrian Crossing' signal hand (red hand) mean for pedestrians?",it:"Cosa significa il segnale mano rossa per i pedoni?",options:[{en:"Cross quickly",it:"Attraversare velocemente"},{en:"Do not start crossing \u2014 wait for the walking figure signal",it:"Non iniziare ad attraversare \u2014 aspettare il segnale della figura che cammina"},{en:"Cross only if no cars are present",it:"Attraversare solo se non ci sono auto"},{en:"Cross from right to left only",it:"Attraversare solo da destra a sinistra"}],correct:1,explain_en:"The red hand (or raised hand) signal means pedestrians should NOT begin crossing. If already crossing, they should complete the crossing quickly.",explain_it:"Il segnale mano rossa significa che i pedoni NON devono iniziare ad attraversare. Se gia attraversando, devono completare velocemente."},
  {cat:"signs",en:"A 'Speed Limit' sign with a black border on white background is:",it:"Un segnale 'Speed Limit' con bordo nero su sfondo bianco e:",options:[{en:"An advisory recommendation only",it:"Solo una raccomandazione consigliata"},{en:"A legally enforceable maximum speed",it:"Una velocita massima legalmente applicabile"},{en:"A minimum speed requirement",it:"Un requisito di velocita minima"},{en:"A nighttime-only speed restriction",it:"Una restrizione di velocita solo notturna"}],correct:1,explain_en:"White rectangular speed limit signs post the legally enforceable maximum speed for that road.",explain_it:"I segnali di limite di velocita rettangolari bianchi indicano la velocita massima legalmente applicabile per quella strada."},
  {cat:"signs",en:"What does a 'School Zone' sign look like?",it:"Come appare un segnale di 'Zona Scolastica'?",options:[{en:"A red octagon",it:"Un ottagono rosso"},{en:"A fluorescent yellow-green pentagon with children walking",it:"Un pentagono giallo-verde fluorescente con bambini che camminano"},{en:"A blue rectangle with school text",it:"Un rettangolo blu con testo scolastico"},{en:"An orange diamond with a school bus",it:"Un rombo arancione con uno scuolabus"}],correct:1,explain_en:"School zone signs are fluorescent yellow-green pentagons showing children walking. They indicate reduced speed zones near schools.",explain_it:"I segnali di zona scolastica sono pentagoni giallo-verde fluorescenti con bambini che camminano. Indicano zone a velocita ridotta vicino alle scuole."},
  {cat:"signs",en:"A 'Road Closed' sign means:",it:"Un segnale 'Road Closed' significa:",options:[{en:"The road is closed to trucks only",it:"La strada e chiusa solo ai camion"},{en:"The road is completely closed \u2014 all vehicles must use an alternate route",it:"La strada e completamente chiusa \u2014 tutti i veicoli devono usare un percorso alternativo"},{en:"One lane is closed \u2014 use caution",it:"Una corsia e chiusa \u2014 usare cautela"},{en:"The road closes at night only",it:"La strada chiude solo di notte"}],correct:1,explain_en:"A Road Closed sign means the road ahead is completely closed to all traffic. Use an alternate route.",explain_it:"Un segnale Road Closed significa che la strada in avanti e completamente chiusa a tutto il traffico. Usa un percorso alternativo."},
  {cat:"signs",en:"What does a 'Roundabout Ahead' sign look like?",it:"Come appare un segnale 'Roundabout Ahead'?",options:[{en:"A yellow diamond with circular arrows",it:"Un rombo giallo con frecce circolari"},{en:"An orange circle with arrows",it:"Un cerchio arancione con frecce"},{en:"A white rectangle with the word ROUNDABOUT",it:"Un rettangolo bianco con la parola ROUNDABOUT"},{en:"A red circle with a U-turn arrow",it:"Un cerchio rosso con una freccia di inversione"}],correct:0,explain_en:"A Roundabout Ahead warning sign is a yellow diamond with circular (counterclockwise) arrows indicating a rotary intersection ahead.",explain_it:"Un segnale Roundabout Ahead e un rombo giallo con frecce circolari (senso antiorario) che indica una rotonda in avanti."},
  {cat:"signs",en:"Inside a roundabout, you should:",it:"All'interno di una rotonda, dovresti:",options:[{en:"Stop at each exit to check for pedestrians",it:"Fermarti a ogni uscita per controllare i pedoni"},{en:"Yield to traffic already in the roundabout and travel counterclockwise",it:"Cedere al traffico gia nella rotonda e viaggiare in senso antiorario"},{en:"Always travel clockwise",it:"Viaggiare sempre in senso orario"},{en:"Maintain your speed \u2014 other vehicles must yield to you",it:"Mantenere la velocita \u2014 gli altri veicoli devono cederti la precedenza"}],correct:1,explain_en:"In a roundabout, yield to circulating traffic already inside, travel counterclockwise, and exit at your desired road.",explain_it:"In una rotonda, cedi al traffico in circolazione gia all'interno, viaggia in senso antiorario ed esci alla strada desiderata."},
  {cat:"signs",en:"What does a 'Hospital' sign on the highway look like?",it:"Come appare un segnale 'Hospital' in autostrada?",options:[{en:"A red rectangle with H",it:"Un rettangolo rosso con H"},{en:"A blue rectangle with a white H",it:"Un rettangolo blu con una H bianca"},{en:"A white diamond with a red cross",it:"Un rombo bianco con una croce rossa"},{en:"A brown square with a medical symbol",it:"Un quadrato marrone con un simbolo medico"}],correct:1,explain_en:"Hospital signs are blue rectangles with a white H, indicating the direction to the nearest hospital or emergency medical facility.",explain_it:"I segnali Hospital sono rettangoli blu con una H bianca, che indicano la direzione verso l'ospedale piu vicino."},
  {cat:"signs",en:"What does a 'Telephone' service sign on a blue highway sign look like?",it:"Come appare un segnale di servizio 'Telephone' su un segnale blu autostradale?",options:[{en:"A blue rectangle with a white phone receiver",it:"Un rettangolo blu con un ricevitore telefonico bianco"},{en:"A white rectangle with a black phone",it:"Un rettangolo bianco con un telefono nero"},{en:"A red square with a phone icon",it:"Un quadrato rosso con un'icona telefono"},{en:"A green diamond with a cell phone",it:"Un rombo verde con un cellulare"}],correct:0,explain_en:"Motorist service signs on highways are blue with white symbols. A phone receiver symbol indicates telephone service available at that exit.",explain_it:"I segnali di servizio per automobilisti sono blu con simboli bianchi. Un simbolo ricevitore telefonico indica servizio telefonico disponibile a quella uscita."},
  {cat:"signs",en:"A 'No U-Turn' sign shows:",it:"Un segnale 'No U-Turn' mostra:",options:[{en:"A yellow diamond with a curved arrow",it:"Un rombo giallo con una freccia curva"},{en:"A white circle with a U-turn arrow and red slash",it:"Un cerchio bianco con una freccia di inversione e barra rossa"},{en:"A red octagon with a U arrow",it:"Un ottagono rosso con una freccia U"},{en:"A black rectangle with U-TURN PROHIBITED",it:"Un rettangolo nero con U-TURN PROHIBITED"}],correct:1,explain_en:"No U-Turn signs use the standard prohibition format: white circle with the prohibited action (U-turn arrow) crossed by a red diagonal slash.",explain_it:"I segnali No U-Turn usano il formato standard di divieto: cerchio bianco con l'azione vietata attraversata da una barra diagonale rossa."},
  {cat:"signs",en:"A 'Begin Right Turn Lane, Yield to Bikes' sign means:",it:"Un segnale 'Begin Right Turn Lane, Yield to Bikes' significa:",options:[{en:"Cyclists must stop for turning vehicles",it:"I ciclisti devono fermarsi per i veicoli in svolta"},{en:"A bike lane merges \u2014 turning drivers must yield to cyclists before entering the turn lane",it:"Una pista ciclabile si unisce \u2014 i conducenti in svolta devono cedere ai ciclisti prima di entrare nella corsia di svolta"},{en:"No bikes allowed in the turn lane",it:"Nessuna bici consentita nella corsia di svolta"},{en:"Turn signal required when bikes are present",it:"Segnale di svolta richiesto quando sono presenti bici"}],correct:1,explain_en:"This sign indicates where a bike lane intersects a right-turn lane. Drivers must yield to cyclists before moving into the turn lane.",explain_it:"Questo segnale indica dove una pista ciclabile interseca una corsia di svolta destra. I conducenti devono cedere ai ciclisti prima di entrare nella corsia di svolta."},
  {cat:"signs",en:"What does 'R X R' on a round yellow sign mean?",it:"Cosa significa 'R X R' su un segnale circolare giallo?",options:[{en:"Road crossing \u2014 intersection ahead",it:"Attraversamento stradale \u2014 incrocio in avanti"},{en:"Railroad crossing advance warning",it:"Avvertimento anticipato di passaggio a livello"},{en:"Restricted crossing for large vehicles",it:"Attraversamento limitato per veicoli grandi"},{en:"Reduced speed zone begins",it:"Inizia zona a velocita ridotta"}],correct:1,explain_en:"The round yellow RXR sign is the advance warning for a railroad crossing. It is the only circular yellow warning sign.",explain_it:"Il segnale circolare giallo RXR e l'avvertimento anticipato per un passaggio a livello. E l'unico segnale di avvertimento circolare giallo."},
  {cat:"signs",en:"Orange construction zone signs require:",it:"I segnali arancioni delle zone di costruzione richiedono:",options:[{en:"Only reducing speed to 25 mph",it:"Solo ridurre la velocita a 25 mph"},{en:"Full compliance \u2014 same legal weight as permanent signs, with doubled fines",it:"Piena conformita \u2014 stesso peso legale dei segnali permanenti, con multe raddoppiate"},{en:"Compliance only when workers are visible",it:"Conformita solo quando gli operai sono visibili"},{en:"Slowing down but no stop requirement",it:"Rallentare ma nessun requisito di stop"}],correct:1,explain_en:"Orange construction zone signs carry full legal authority. Fines are doubled for violations in active work zones whether workers are present or not.",explain_it:"I segnali arancioni hanno piena autorita legale. Le multe sono raddoppiate per le violazioni nelle zone di lavoro attive sia con che senza operai."},
  {cat:"signs",en:"A 'Bicycle Lane' sign with a white bicycle on a green background means:",it:"Un segnale 'Bicycle Lane' con bicicletta bianca su sfondo verde significa:",options:[{en:"Cyclists must use this lane",it:"I ciclisti devono usare questa corsia"},{en:"A designated bicycle lane \u2014 cyclists have priority, motor vehicles may not use it",it:"Una corsia ciclabile designata \u2014 i ciclisti hanno priorita, i veicoli a motore non possono usarla"},{en:"Cyclists and motor vehicles share this lane equally",it:"Ciclisti e veicoli a motore condividono questa corsia ugualmente"},{en:"The lane is for electric bikes only",it:"La corsia e solo per bici elettriche"}],correct:1,explain_en:"A dedicated bike lane (green or white bike symbol) is reserved for cyclists. Motor vehicles may not drive or park in it.",explain_it:"Una corsia ciclabile dedicata (simbolo bici verde o bianco) e riservata ai ciclisti. I veicoli a motore non possono guidare o parcheggiarci."},
  {cat:"signs",en:"What is a 'Crossbuck' sign at a railroad crossing?",it:"Cos'e un segnale 'Crossbuck' a un passaggio a livello?",options:[{en:"A yellow diamond before the crossing",it:"Un rombo giallo prima dell'attraversamento"},{en:"The white X-shaped sign with 'Railroad Crossing' at the actual crossing",it:"Il segnale a X bianco con 'Railroad Crossing' all'attraversamento effettivo"},{en:"A red gate that lowers when a train approaches",it:"Un cancello rosso che si abbassa quando si avvicina un treno"},{en:"A flashing yellow light",it:"Una luce gialla lampeggiante"}],correct:1,explain_en:"The Crossbuck is the white X-shaped sign with 'Railroad Crossing' installed at the crossing itself. Treat it as a yield sign when no other signals are present.",explain_it:"Il Crossbuck e il segnale a X bianco con 'Railroad Crossing' installato all'attraversamento. Trattalo come un segnale di precedenza quando non ci sono altri segnali."},
  {cat:"signs",en:"What does a 'Lane Ends \u2014 Merge Left' sign look like?",it:"Come appare un segnale 'Lane Ends \u2014 Merge Left'?",options:[{en:"A yellow diamond with two lines merging from the right",it:"Un rombo giallo con due linee che confluiscono dalla destra"},{en:"An orange rectangle with MERGE LEFT",it:"Un rettangolo arancione con MERGE LEFT"},{en:"A red circle with a left arrow",it:"Un cerchio rosso con una freccia sinistra"},{en:"A white rectangle with an arrow pointing left",it:"Un rettangolo bianco con una freccia che punta a sinistra"}],correct:0,explain_en:"Lane Ends warning signs are yellow diamonds showing two lane lines converging \u2014 indicating the right lane ends and traffic must merge left.",explain_it:"I segnali Lane Ends sono rombi gialli con due linee di corsia che convergono \u2014 indicando che la corsia destra finisce e il traffico deve confluire a sinistra."},
  {cat:"signs",en:"What does a 'Passing Zone' (broken yellow center line) indicate?",it:"Cosa indica una 'Zona di Sorpasso' (linea centrale gialla tratteggiata)?",options:[{en:"No passing allowed in either direction",it:"Nessun sorpasso consentito in nessuna direzione"},{en:"Passing is permitted from your side when safe",it:"Il sorpasso e consentito dal tuo lato quando sicuro"},{en:"Passing allowed only at night",it:"Sorpasso consentito solo di notte"},{en:"Only emergency vehicles may pass here",it:"Solo i veicoli di emergenza possono sorpassare qui"}],correct:1,explain_en:"A broken (dashed) yellow center line on your side means passing is permitted from your side when it is safe to do so.",explain_it:"Una linea centrale gialla tratteggiata sul tuo lato significa che il sorpasso e consentito dal tuo lato quando sicuro."},
  {cat:"laws",en:"Florida's Move Over Law requires you to, when approaching a stopped emergency vehicle with lights on a multi-lane road:",it:"La legge Move Over della Florida richiede di, avvicinandosi a un veicolo di emergenza fermo con luci su una strada a piu corsie:",options:[{en:"Maintain speed and lane",it:"Mantenere velocita e corsia"},{en:"Move over one lane away from the vehicle OR reduce speed by 20 mph below the posted limit",it:"Spostarti di una corsia lontano dal veicolo O ridurre la velocita di 20 mph sotto il limite segnalato"},{en:"Stop completely until the vehicle moves",it:"Fermarti completamente finche il veicolo non si muove"},{en:"Flash headlights as warning",it:"Lampeggiare i fari come segnale"}],correct:1,explain_en:"Florida Move Over Law: move over one lane if possible OR reduce speed 20 mph below the posted limit. Applies to emergency, utility, and sanitation vehicles.",explain_it:"Legge Move Over: spostati di una corsia se possibile O riduci la velocita di 20 mph sotto il limite. Si applica ai veicoli di emergenza, utility e nettezza urbana."},
  {cat:"laws",en:"Florida's Move Over Law also applies to which non-emergency vehicles?",it:"La legge Move Over della Florida si applica anche a quali veicoli non di emergenza?",options:[{en:"Only fire trucks and ambulances",it:"Solo autopompe e ambulanze"},{en:"Utility and sanitation vehicles stopped with lights activated",it:"Veicoli utility e nettezza urbana fermi con luci attivate"},{en:"Only vehicles with yellow warning lights",it:"Solo i veicoli con luci gialle di avvertimento"},{en:"Only law enforcement vehicles",it:"Solo i veicoli delle forze dell'ordine"}],correct:1,explain_en:"Florida's Move Over Law was expanded to include utility and sanitation vehicles with activated warning lights stopped on the roadside.",explain_it:"La legge Move Over della Florida e stata ampliata per includere i veicoli utility e nettezza urbana con luci di avvertimento attivate fermi sul bordo della strada."},
  {cat:"laws",en:"When can you legally pass on the right in Florida?",it:"Quando puoi legalmente sorpassare a destra in Florida?",options:[{en:"Whenever the lane is clear",it:"Ogni volta che la corsia e libera"},{en:"When a vehicle ahead is making a left turn and there is a paved lane to the right",it:"Quando un veicolo davanti sta svoltando a sinistra e c'e una corsia asfaltata a destra"},{en:"Only on multi-lane highways",it:"Solo sulle autostrade a piu corsie"},{en:"Passing on the right is always illegal in Florida",it:"Il sorpasso a destra e sempre illegale in Florida"}],correct:1,explain_en:"You may pass on the right when the vehicle ahead is turning left and there is a paved lane wide enough to permit safe passing.",explain_it:"Puoi sorpassare a destra quando il veicolo davanti sta svoltando a sinistra e c'e una corsia asfaltata abbastanza larga per sorpassare in sicurezza."},
  {cat:"laws",en:"In Florida, you must not pass within how many feet of a railroad crossing?",it:"In Florida, non puoi sorpassare entro quanti piedi da un passaggio a livello?",options:[{en:"50 feet",it:"50 piedi"},{en:"100 feet",it:"100 piedi"},{en:"200 feet",it:"200 piedi"},{en:"500 feet",it:"500 piedi"}],correct:1,explain_en:"Passing is prohibited within 100 feet of a railroad crossing. Maintain a single lane as you approach.",explain_it:"Il sorpasso e vietato entro 100 piedi (30 m) da un passaggio a livello. Mantieni una corsia sola mentre ti avvicini."},
  {cat:"laws",en:"What is the Florida law on texting while driving?",it:"Qual e la legge della Florida sulla messaggistica durante la guida?",options:[{en:"Legal if stopped at a red light",it:"Legale se fermo a un semaforo rosso"},{en:"A primary offense \u2014 police may stop and cite you solely for texting while driving",it:"Un'infrazione principale \u2014 la polizia puo fermarti e multarti solo per messaggiare durante la guida"},{en:"Only a secondary offense \u2014 must have another violation first",it:"Solo un'infrazione secondaria \u2014 deve esserci prima un'altra violazione"},{en:"Legal for drivers over 21",it:"Legale per i conducenti sopra i 21 anni"}],correct:1,explain_en:"In Florida, texting/typing while driving is a primary offense \u2014 law enforcement can pull you over solely for this violation.",explain_it:"In Florida, messaggiare/digitare durante la guida e un'infrazione principale \u2014 le forze dell'ordine possono fermarti solo per questa violazione."},
  {cat:"laws",en:"What is the Florida law about using a handheld phone while driving in a school or work zone?",it:"Qual e la legge della Florida sull'uso di un telefono a mano durante la guida in una zona scolastica o di lavoro?",options:[{en:"Permitted with a hands-free mount",it:"Consentito con un supporto hands-free"},{en:"Prohibited \u2014 holding a phone while driving through a school or active work zone is illegal",it:"Vietato \u2014 tenere un telefono durante la guida in una zona scolastica o di lavoro attiva e illegale"},{en:"Only illegal for CDL holders",it:"Illegale solo per i titolari CDL"},{en:"Legal if speed is below 20 mph",it:"Legale se la velocita e sotto 20 mph"}],correct:1,explain_en:"Florida prohibits holding a wireless device while driving through school zones and active work zones \u2014 even if not texting.",explain_it:"La Florida vieta di tenere un dispositivo wireless durante la guida in zone scolastiche e di lavoro attive \u2014 anche se non si sta inviando messaggi."},
  {cat:"laws",en:"How much are fines for moving violations in an active Florida construction zone?",it:"Di quanto sono le multe per violazioni in movimento in una zona di lavori attiva in Florida?",options:[{en:"The same as normal",it:"Le stesse del normale"},{en:"Doubled",it:"Raddoppiate"},{en:"Tripled",it:"Triplicate"},{en:"$500 flat fine for all violations",it:"Multa fissa di $500 per tutte le violazioni"}],correct:1,explain_en:"Fines for moving violations in active construction zones are doubled in Florida, whether workers are present or not.",explain_it:"Le multe per le violazioni in movimento nelle zone di lavori attive sono raddoppiate in Florida, sia che gli operai siano presenti o meno."},
  {cat:"laws",en:"Who has right-of-way when two vehicles arrive simultaneously at an uncontrolled intersection?",it:"Chi ha la precedenza quando due veicoli arrivano simultaneamente a un incrocio non controllato?",options:[{en:"The vehicle on the left",it:"Il veicolo a sinistra"},{en:"The vehicle on the right",it:"Il veicolo a destra"},{en:"The larger vehicle",it:"Il veicolo piu grande"},{en:"The vehicle traveling faster",it:"Il veicolo che viaggia piu veloce"}],correct:1,explain_en:"When two vehicles arrive simultaneously at an uncontrolled intersection, the vehicle on the LEFT yields to the vehicle on the RIGHT.",explain_it:"Quando due veicoli arrivano simultaneamente a un incrocio non controllato, il veicolo a SINISTRA cede la precedenza al veicolo a DESTRA."},
  {cat:"laws",en:"In Florida, what is the rule for passing a school bus stopped on a divided highway (with a raised median)?",it:"In Florida, qual e la regola per sorpassare uno scuolabus fermo su un'autostrada divisa (con mediana rialzata)?",options:[{en:"All traffic in both directions must stop",it:"Tutto il traffico in entrambe le direzioni deve fermarsi"},{en:"Only traffic on the same side as the bus must stop \u2014 traffic on the other side may proceed",it:"Solo il traffico sullo stesso lato del bus deve fermarsi \u2014 il traffico dall'altro lato puo procedere"},{en:"Traffic may proceed at 15 mph",it:"Il traffico puo procedere a 15 mph"},{en:"Only stop if the bus is loading children",it:"Fermarsi solo se il bus sta caricando bambini"}],correct:1,explain_en:"On a divided highway with a raised median or physical barrier, only traffic on the SAME side as the school bus must stop. Traffic on the opposite side may continue.",explain_it:"Su un'autostrada divisa con mediana rialzata o barriera fisica, solo il traffico sullo STESSO lato dello scuolabus deve fermarsi. Il traffico sul lato opposto puo continuare."},
  {cat:"laws",en:"What must you do if an emergency vehicle approaches from behind while you are on a one-way street?",it:"Cosa devi fare se un veicolo di emergenza si avvicina da dietro mentre sei su una strada a senso unico?",options:[{en:"Speed up to get out of the way",it:"Accelerare per toglierti di mezzo"},{en:"Pull to the nearest curb (right or left) and stop",it:"Accostare al marciapiede piu vicino (destra o sinistra) e fermarti"},{en:"Stop immediately wherever you are",it:"Fermarti immediatamente dove sei"},{en:"Continue driving at normal speed",it:"Continuare a guidare a velocita normale"}],correct:1,explain_en:"On a one-way street, pull to whichever curb (right or left) is nearest and stop to allow the emergency vehicle to pass.",explain_it:"Su una strada a senso unico, accosta al marciapiede piu vicino (destra o sinistra) e fermati per consentire al veicolo di emergenza di passare."},
  {cat:"laws",en:"What is the Florida law regarding leaving a child under 6 in a vehicle?",it:"Qual e la legge della Florida riguardo all'abbandono di un bambino sotto i 6 anni in un veicolo?",options:[{en:"Allowed for up to 10 minutes with windows cracked",it:"Consentito fino a 10 minuti con i finestrini aperti"},{en:"Never permitted \u2014 a child under 6 must not be left alone in a motor vehicle",it:"Mai consentito \u2014 un bambino sotto i 6 anni non deve essere lasciato solo in un veicolo"},{en:"Allowed if the engine is off and keys removed",it:"Consentito se il motore e spento e le chiavi rimosse"},{en:"Allowed if a sibling over 12 is present",it:"Consentito se e presente un fratello/sorella di eta superiore ai 12 anni"}],correct:1,explain_en:"Florida law prohibits leaving a child 6 or younger alone in a vehicle. Violations can result in criminal charges, especially if the child is harmed.",explain_it:"La legge della Florida vieta di lasciare un bambino di 6 anni o meno da solo in un veicolo. Le violazioni possono comportare accuse penali."},
  {cat:"laws",en:"In Florida, what is the maximum fine for speeding in a school zone?",it:"In Florida, qual e la multa massima per eccesso di velocita in una zona scolastica?",options:[{en:"Standard fine \u2014 no enhancement in school zones",it:"Multa standard \u2014 nessun aumento nelle zone scolastiche"},{en:"Fines are doubled in school zones",it:"Le multe sono raddoppiate nelle zone scolastiche"},{en:"A flat $500 regardless of speed",it:"Una multa fissa di $500 indipendentemente dalla velocita"},{en:"Only a warning for first offense",it:"Solo un avvertimento alla prima offesa"}],correct:1,explain_en:"Speeding fines are doubled in school zones in Florida when children are present.",explain_it:"Le multe per eccesso di velocita sono raddoppiate nelle zone scolastiche in Florida quando i bambini sono presenti."},
  {cat:"laws",en:"What does Florida's 'anti-road rage' law prohibit?",it:"Cosa vieta la legge 'anti-rabbia stradale' della Florida?",options:[{en:"Using the horn more than once",it:"Usare il clacson piu di una volta"},{en:"Aggressive driving maneuvers intended to intimidate, injure, or impede another driver",it:"Manovre di guida aggressive intese a intimidire, ferire o ostacolare un altro conducente"},{en:"Driving at the speed limit in the left lane",it:"Guidare al limite di velocita nella corsia sinistra"},{en:"Flashing headlights at other drivers",it:"Lampeggiare i fari agli altri conducenti"}],correct:1,explain_en:"Florida's aggressive driving/road rage law prohibits driving in a manner intended to intimidate, injure, or block other drivers.",explain_it:"La legge sulla guida aggressiva della Florida vieta di guidare in modo inteso a intimidire, ferire o bloccare altri conducenti."},
  {cat:"laws",en:"What is required when a Florida driver's license address changes?",it:"Cosa e richiesto quando cambia l'indirizzo di una patente di guida Florida?",options:[{en:"Nothing \u2014 the DMV updates it automatically",it:"Niente \u2014 il DMV lo aggiorna automaticamente"},{en:"You must notify FLHSMV within 30 days of the change",it:"Devi notificare il FLHSMV entro 30 giorni dal cambiamento"},{en:"Only update when you renew your license",it:"Aggiornare solo al rinnovo della patente"},{en:"Address changes are not tracked on driver's licenses",it:"I cambi di indirizzo non vengono tracciati sulle patenti"}],correct:1,explain_en:"Florida drivers must notify FLHSMV of an address change within 30 days. Failure to do so is a violation.",explain_it:"I conducenti in Florida devono notificare al FLHSMV un cambio di indirizzo entro 30 giorni. Il mancato rispetto e una violazione."},
  {cat:"laws",en:"What is the penalty for leaving the scene of a crash with injuries in Florida?",it:"Qual e la sanzione per la fuga dalla scena di un incidente con lesioni in Florida?",options:[{en:"A minor traffic infraction",it:"Una minore infrazione del traffico"},{en:"A felony \u2014 up to 5 years in prison if injury occurred",it:"Un crimine \u2014 fino a 5 anni di prigione se si sono verificate lesioni"},{en:"License suspension only",it:"Solo sospensione della patente"},{en:"A fine of up to $500",it:"Una multa fino a $500"}],correct:1,explain_en:"Leaving the scene of a crash with injuries is a felony in Florida \u2014 up to 5 years in prison, plus fines, license revocation, and possible vehicle forfeiture.",explain_it:"Lasciare la scena di un incidente con lesioni e un crimine in Florida \u2014 fino a 5 anni di prigione, piu multe, revoca della patente e possibile confisca del veicolo."},
  {cat:"laws",en:"In Florida, how long do you have to report a crash to law enforcement?",it:"In Florida, quanto tempo hai per segnalare un incidente alle forze dell'ordine?",options:[{en:"Immediately \u2014 at the scene only",it:"Immediatamente \u2014 solo sulla scena"},{en:"Within 10 days if police did not respond to the scene and damage exceeds $500",it:"Entro 10 giorni se la polizia non ha risposto alla scena e i danni superano $500"},{en:"Within 24 hours for any crash",it:"Entro 24 ore per qualsiasi incidente"},{en:"Only if injury or death occurred",it:"Solo se si sono verificate lesioni o decessi"}],correct:1,explain_en:"If police do not respond to a crash scene and damage exceeds $500 or there are injuries, you must report to FLHSMV within 10 days.",explain_it:"Se la polizia non risponde alla scena e i danni superano $500 o ci sono lesioni, devi segnalare al FLHSMV entro 10 giorni."},
  {cat:"laws",en:"What must you do if a traffic signal is red but you are already in the intersection when it changes?",it:"Cosa devi fare se il semaforo diventa rosso ma sei gia nell'incrocio quando cambia?",options:[{en:"Stop immediately in the intersection",it:"Fermarti immediatamente nell'incrocio"},{en:"Complete your turn or cross \u2014 you are legally in the intersection",it:"Completare la svolta o attraversare \u2014 sei legalmente nell'incrocio"},{en:"Back up out of the intersection",it:"Fare retromarcia fuori dall'incrocio"},{en:"Turn on hazard lights and wait",it:"Accendere le luci di pericolo e aspettare"}],correct:1,explain_en:"If you lawfully entered an intersection before the light changed, complete your movement. However, never enter an intersection unless you can completely clear it.",explain_it:"Se sei entrato legittimamente nell'incrocio prima che il semaforo cambiasse, completa il tuo movimento. Non entrare mai se non puoi liberarlo completamente."},
  {cat:"laws",en:"In Florida, what is the law on parking near a fire hydrant?",it:"In Florida, qual e la legge sul parcheggio vicino a un idrante antincendio?",options:[{en:"No restriction \u2014 fire hydrants have no parking buffer",it:"Nessuna restrizione \u2014 gli idranti non hanno buffer di parcheggio"},{en:"You must not park within 15 feet of a fire hydrant",it:"Non devi parcheggiare entro 15 piedi (4,5 m) da un idrante"},{en:"You must not park within 10 feet of a fire hydrant",it:"Non devi parcheggiare entro 10 piedi (3 m) da un idrante"},{en:"You must not park within 25 feet of a fire hydrant",it:"Non devi parcheggiare entro 25 piedi (7,5 m) da un idrante"}],correct:1,explain_en:"Florida prohibits parking within 15 feet of a fire hydrant. The space must remain clear for emergency access.",explain_it:"La Florida vieta il parcheggio entro 15 piedi (4,5 m) da un idrante. Lo spazio deve rimanere libero per l'accesso di emergenza."},
  {cat:"laws",en:"In Florida, what is the law on using a cell phone while driving for adults (non-school/work zone)?",it:"In Florida, qual e la legge sull'uso del cellulare durante la guida per gli adulti (fuori zone scolastiche/lavoro)?",options:[{en:"Completely prohibited \u2014 hands-free only always",it:"Completamente vietato \u2014 solo mani libere sempre"},{en:"Talking on a handheld phone while driving is a secondary offense \u2014 primary in school/work zones",it:"Parlare su un telefono a mano durante la guida e un'infrazione secondaria \u2014 primaria in zone scolastiche/lavoro"},{en:"Always legal for adults over 21",it:"Sempre legale per gli adulti over 21"},{en:"Legal if using speakerphone",it:"Legale se si usa il vivavoce"}],correct:1,explain_en:"Outside school and work zones, using a handheld phone while driving is a secondary offense for adults. In school/work zones it is a primary offense.",explain_it:"Al di fuori delle zone scolastiche e di lavoro, usare un telefono a mano e un'infrazione secondaria per gli adulti. Nelle zone scolastiche/lavoro e primaria."},
  {cat:"laws",en:"What is the 'implied consent' to alcohol testing for drivers in Florida?",it:"Qual e il 'consenso implicito' ai test alcolici per i conducenti in Florida?",options:[{en:"A verbal agreement made at a sobriety checkpoint",it:"Un accordo verbale fatto a un posto di blocco"},{en:"By operating a vehicle in Florida, you consent to a BAC test if lawfully arrested for DUI",it:"Operando un veicolo in Florida, acconsenti a un test BAC se legalmente arrestato per DUI"},{en:"A written consent form signed at the DMV",it:"Un modulo di consenso scritto firmato al DMV"},{en:"Only applies to commercial drivers",it:"Si applica solo ai conducenti commerciali"}],correct:1,explain_en:"Florida's Implied Consent Law means operating a vehicle constitutes automatic consent to chemical BAC testing when lawfully arrested for DUI.",explain_it:"La legge del Consenso Implicito della Florida significa che operare un veicolo costituisce consenso automatico ai test chimici BAC quando legalmente arrestato per DUI."},
  {cat:"laws",en:"In Florida, when may you make a right turn on red?",it:"In Florida, quando puoi svoltare a destra con il rosso?",options:[{en:"Always \u2014 red means stop, then you may always turn right",it:"Sempre \u2014 il rosso significa stop, poi puoi sempre svoltare a destra"},{en:"After coming to a complete stop and yielding to all traffic and pedestrians, unless a sign prohibits it",it:"Dopo un arresto completo e aver ceduto a tutto il traffico e pedoni, a meno che un segnale non lo vieti"},{en:"Only when no pedestrians are crossing",it:"Solo quando non ci sono pedoni che attraversano"},{en:"Only at intersections with a dedicated right-turn lane",it:"Solo agli incroci con una corsia di svolta destra dedicata"}],correct:1,explain_en:"Right on red in Florida: stop completely, yield to all traffic and pedestrians, then proceed \u2014 unless a 'No Turn on Red' sign is posted.",explain_it:"Svolta destra con il rosso in Florida: arresto completo, cedere a tutto il traffico e pedoni, poi procedere \u2014 a meno che non ci sia un segnale 'No Turn on Red'."},
  {cat:"laws",en:"In Florida, when may you make a left turn on red?",it:"In Florida, quando puoi svoltare a sinistra con il rosso?",options:[{en:"Never \u2014 left on red is always prohibited",it:"Mai \u2014 la svolta sinistra con il rosso e sempre vietata"},{en:"From a one-way street onto another one-way street, after stopping and yielding",it:"Da una strada a senso unico su un'altra strada a senso unico, dopo essersi fermati e aver ceduto"},{en:"From any road when no traffic is present",it:"Da qualsiasi strada quando non c'e traffico"},{en:"Only if a green arrow is displayed",it:"Solo se viene mostrata una freccia verde"}],correct:1,explain_en:"In Florida, a left turn on red is permitted ONLY from a one-way street onto another one-way street \u2014 after stopping and yielding.",explain_it:"In Florida, la svolta sinistra con il rosso e consentita SOLO da una strada a senso unico su un'altra strada a senso unico \u2014 dopo essersi fermati e aver ceduto."},
  {cat:"laws",en:"Florida requires vehicles to stop how many feet before a railroad crossing when a train is approaching?",it:"La Florida richiede ai veicoli di fermarsi a quanti piedi da un passaggio a livello quando un treno si avvicina?",options:[{en:"10 feet",it:"10 piedi"},{en:"15 feet",it:"15 piedi"},{en:"20 feet",it:"20 piedi"},{en:"50 feet",it:"50 piedi"}],correct:2,explain_en:"You must stop no closer than 15 feet and no further than 50 feet from the nearest rail when a train is approaching.",explain_it:"Devi fermarti non piu vicino di 15 piedi (4,5 m) e non piu lontano di 50 piedi (15 m) dalla rotaia piu vicina quando un treno si avvicina."},
  {cat:"laws",en:"In Florida, who must wear a seat belt?",it:"In Florida, chi deve indossare la cintura di sicurezza?",options:[{en:"Only the driver",it:"Solo il conducente"},{en:"All front seat occupants, and all passengers under 18 in any seat",it:"Tutti gli occupanti del sedile anteriore e tutti i passeggeri under 18 in qualsiasi sedile"},{en:"Only children under 13",it:"Solo i bambini under 13"},{en:"Seat belts are optional for adults in rear seats",it:"Le cinture sono facoltative per gli adulti nei sedili posteriori"}],correct:1,explain_en:"Florida requires all front-seat occupants and all passengers under 18 (in any seat) to wear seat belts. Adults 18+ in rear seats are not covered by the primary law.",explain_it:"La Florida richiede a tutti gli occupanti dei sedili anteriori e a tutti i passeggeri under 18 (in qualsiasi sedile) di indossare le cinture."},
  {cat:"laws",en:"Florida's seat belt law for adults is classified as:",it:"La legge sulle cinture di sicurezza della Florida per gli adulti e classificata come:",options:[{en:"A secondary offense \u2014 only cited with another violation",it:"Un'infrazione secondaria \u2014 solo citata con un'altra violazione"},{en:"A primary offense \u2014 police may stop you solely for not wearing a seat belt",it:"Un'infrazione primaria \u2014 la polizia puo fermarti solo per non indossare la cintura"},{en:"Not enforced for adults over 18",it:"Non applicata per gli adulti over 18"},{en:"Only a fine for the driver, not the passenger",it:"Solo una multa per il conducente, non per il passeggero"}],correct:1,explain_en:"Florida's seat belt law is a primary offense for front-seat occupants \u2014 law enforcement can stop and cite you solely for not wearing one.",explain_it:"La legge sulle cinture in Florida e un'infrazione primaria per gli occupanti del sedile anteriore \u2014 le forze dell'ordine possono fermarti e multarti solo per questo."},
  {cat:"laws",en:"In Florida, what is the law about passing another vehicle on a hill or curve?",it:"In Florida, qual e la legge sul sorpasso di un altro veicolo su una collina o in curva?",options:[{en:"Passing is allowed if you can see 500 feet ahead",it:"Il sorpasso e consentito se si puo vedere 500 piedi avanti"},{en:"Passing is prohibited when you cannot see far enough ahead to ensure safety",it:"Il sorpasso e vietato quando non si puo vedere abbastanza avanti per garantire la sicurezza"},{en:"Passing on a hill is allowed going downhill only",it:"Il sorpasso su una collina e consentito solo in discesa"},{en:"Passing is always allowed if the center line is dashed",it:"Il sorpasso e sempre consentito se la linea centrale e tratteggiata"}],correct:1,explain_en:"Never pass on a hill or curve where you cannot see far enough ahead to ensure it is safe. A solid yellow line on your side also prohibits passing.",explain_it:"Non sorpassare mai su una collina o in curva dove non puoi vedere abbastanza avanti per garantire la sicurezza. Una linea gialla continua sul tuo lato vieta anche il sorpasso."},
  {cat:"laws",en:"What is the Florida law on horn use?",it:"Qual e la legge della Florida sull'uso del clacson?",options:[{en:"Horns may never be used on residential streets",it:"I clacson non possono mai essere usati nelle strade residenziali"},{en:"Horns must only be used when reasonably necessary \u2014 not for anger or amusement",it:"I clacson devono essere usati solo quando ragionevolmente necessario \u2014 non per rabbia o divertimento"},{en:"Horns must be sounded at all intersections",it:"I clacson devono essere suonati a tutti gli incroci"},{en:"There are no restrictions on horn use in Florida",it:"Non ci sono restrizioni sull'uso del clacson in Florida"}],correct:1,explain_en:"Florida law permits horn use only when reasonably necessary for safety. Using a horn for road rage or amusement is prohibited.",explain_it:"La legge della Florida consente l'uso del clacson solo quando ragionevolmente necessario per la sicurezza. L'uso del clacson per la rabbia stradale o il divertimento e vietato."},
  {cat:"laws",en:"When a school bus is stopped with red lights flashing on a four-lane road WITHOUT a median, traffic coming from the opposite direction must:",it:"Quando uno scuolabus e fermo con luci rosse lampeggianti su una strada a quattro corsie SENZA mediana, il traffico proveniente dalla direzione opposta deve:",options:[{en:"Proceed at 15 mph",it:"Procedere a 15 mph"},{en:"Stop \u2014 four-lane undivided roads require all traffic to stop",it:"Fermarsi \u2014 le strade a quattro corsie non divise richiedono che tutto il traffico si fermi"},{en:"Continue at normal speed \u2014 only same-side traffic stops",it:"Continuare a velocita normale \u2014 solo il traffico sullo stesso lato si ferma"},{en:"Slow to 20 mph and watch for children",it:"Rallentare a 20 mph e fare attenzione ai bambini"}],correct:1,explain_en:"A four-lane road WITHOUT a raised median is treated the same as a two-lane road \u2014 ALL traffic in both directions must stop for a school bus with red lights.",explain_it:"Una strada a quattro corsie SENZA mediana rialzata e trattata come una strada a due corsie \u2014 TUTTO il traffico in entrambe le direzioni deve fermarsi per lo scuolabus."},
  {cat:"laws",en:"What does Florida law say about driving with improperly loaded cargo?",it:"Cosa dice la legge della Florida sulla guida con carico impropriamente caricato?",options:[{en:"It is only an issue if cargo falls from the vehicle",it:"E solo un problema se il carico cade dal veicolo"},{en:"Cargo must be secured to prevent shifting or falling \u2014 driver is responsible for all loads",it:"Il carico deve essere fissato per prevenire spostamenti o cadute \u2014 il conducente e responsabile di tutti i carichi"},{en:"Only commercial vehicles must secure loads",it:"Solo i veicoli commerciali devono fissare i carichi"},{en:"Unsecured cargo is only illegal on highways",it:"Il carico non fissato e illegale solo in autostrada"}],correct:1,explain_en:"Florida law requires all cargo to be properly secured. The driver is responsible for ensuring loads don't shift or fall. Unsecured loads can cause fatal accidents.",explain_it:"La legge della Florida richiede che tutto il carico sia adeguatamente fissato. Il conducente e responsabile di garantire che i carichi non si spostino o cadano."},
  {cat:"laws",en:"In Florida, what is the law about racing on public roads?",it:"In Florida, qual e la legge sulle corse su strade pubbliche?",options:[{en:"Legal if both drivers consent and no one else is present",it:"Legale se entrambi i conducenti acconsentono e nessun altro e presente"},{en:"Illegal \u2014 street racing is a criminal offense in Florida",it:"Illegale \u2014 le corse stradali sono un reato penale in Florida"},{en:"Only illegal for drivers under 21",it:"Illegale solo per i conducenti under 21"},{en:"Legal in designated areas only",it:"Legale solo in aree designate"}],correct:1,explain_en:"Street racing (drag racing) on public roads is a criminal offense in Florida, resulting in license revocation and possible imprisonment.",explain_it:"Le corse stradali su strade pubbliche sono un reato penale in Florida, con conseguente revoca della patente e possibile reclusione."},
  {cat:"laws",en:"What is required when a Florida driver changes their name?",it:"Cosa e richiesto quando un conducente della Florida cambia il proprio nome?",options:[{en:"No action needed \u2014 the DMV updates it from court records",it:"Nessuna azione necessaria \u2014 il DMV lo aggiorna dai documenti del tribunale"},{en:"Apply for a replacement license with new legal name documents within 30 days",it:"Richiedere una patente sostitutiva con i nuovi documenti legali del nome entro 30 giorni"},{en:"Only update at license renewal",it:"Aggiornare solo al rinnovo della patente"},{en:"Name changes are not reflected on driver's licenses",it:"I cambi di nome non sono rispecchiati sulle patenti"}],correct:1,explain_en:"Florida drivers must apply for a replacement license within 30 days of a legal name change, presenting appropriate documentation.",explain_it:"I conducenti della Florida devono richiedere una patente sostitutiva entro 30 giorni da un cambio legale di nome, presentando la documentazione appropriata."},
  {cat:"laws",en:"In Florida, it is illegal to block an intersection. What does this mean practically?",it:"In Florida, e illegale bloccare un incrocio. Cosa significa in pratica?",options:[{en:"You must stop before every intersection",it:"Devi fermarti prima di ogni incrocio"},{en:"Do not enter an intersection you cannot fully clear before the light changes or cross traffic proceeds",it:"Non entrare in un incrocio che non puoi liberare completamente prima che il semaforo cambi o il traffico trasversale proceda"},{en:"Turning left at an intersection is prohibited",it:"Svoltare a sinistra a un incrocio e vietato"},{en:"You must stop for pedestrians before every intersection",it:"Devi fermarti per i pedoni prima di ogni incrocio"}],correct:1,explain_en:"Do not enter an intersection unless you can completely clear it before conflicting traffic receives a green. Blocking intersections is a moving violation.",explain_it:"Non entrare in un incrocio a meno che non possa liberarlo completamente prima che il traffico in conflitto riceva il verde. Bloccare gli incroci e una violazione in movimento."},
  {cat:"laws",en:"Florida law requires how many feet of signal before making a turn?",it:"La legge della Florida richiede quanti piedi di segnale prima di svoltare?",options:[{en:"50 feet",it:"50 piedi"},{en:"100 feet on all roads",it:"100 piedi su tutte le strade"},{en:"100 feet in residential areas; 200 feet on highways",it:"100 piedi nelle aree residenziali; 200 piedi sulle autostrade"},{en:"200 feet on all roads",it:"200 piedi su tutte le strade"}],correct:2,explain_en:"Florida requires signaling at least 100 feet before a turn in residential and non-highway areas, and at least 200 feet on highways.",explain_it:"La Florida richiede di segnalare almeno 100 piedi prima di una svolta nelle aree residenziali, e almeno 200 piedi sulle autostrade."},
  {cat:"laws",en:"What is Florida's 'surcharge' on traffic fines?",it:"Cos'e il 'supplemento' sulle multe stradali della Florida?",options:[{en:"A discount for paying early",it:"Uno sconto per il pagamento anticipato"},{en:"Additional fees added to base fines \u2014 such as court costs and state add-ons \u2014 making the total much higher than the base fine",it:"Tariffe aggiuntive aggiunte alle multe base \u2014 come costi giudiziari e supplementi statali \u2014 che rendono il totale molto piu alto della multa base"},{en:"A charge for requesting a hearing",it:"Un onere per richiedere un'udienza"},{en:"An insurance company fee after a violation",it:"Una tariffa della compagnia assicurativa dopo una violazione"}],correct:1,explain_en:"Florida traffic fines include multiple surcharges and court costs that can triple or quadruple the base fine. A $100 base fine may cost $300+ total.",explain_it:"Le multe stradali della Florida includono molteplici supplementi e costi giudiziari che possono triplicare o quadruplicare la multa base."},
  {cat:"laws",en:"What is Florida's 'No Zone' law regarding large trucks?",it:"Qual e la legge della Florida sulla 'No Zone' riguardo ai camion grandi?",options:[{en:"Trucks must stay in designated lanes only",it:"I camion devono rimanere solo nelle corsie designate"},{en:"Drivers should avoid lingering in the blind spots (No-Zones) around large trucks",it:"I conducenti dovrebbero evitare di indugiare nei punti ciechi (No-Zone) intorno ai camion grandi"},{en:"Trucks are prohibited from the left lane at all times",it:"I camion sono vietati dalla corsia sinistra in ogni momento"},{en:"There is no Florida law specifically about truck No-Zones",it:"Non c'e alcuna legge della Florida specificamente sulle No-Zone dei camion"}],correct:1,explain_en:"While not a formal statute, Florida traffic law addresses the duty to avoid the No-Zones (blind spots) of large vehicles for safety.",explain_it:"Sebbene non sia uno statuto formale, la legge del traffico della Florida affronta il dovere di evitare le No-Zone (punti ciechi) dei veicoli grandi per la sicurezza."},
  {cat:"laws",en:"What does Florida law require if your vehicle breaks down on an interstate?",it:"Cosa richiede la legge della Florida se il tuo veicolo si ferma su un'autostrada interstatale?",options:[{en:"Stop in the left lane for visibility",it:"Fermarsi nella corsia sinistra per la visibilita"},{en:"Move to the right shoulder if possible, turn on hazard lights, and display reflectors or flares",it:"Spostarsi sulla banchina destra se possibile, accendere le luci di pericolo e mostrare riflettori o razzi"},{en:"Stand behind your vehicle to direct traffic",it:"Stare dietro il veicolo per dirigere il traffico"},{en:"Stay in your vehicle with seat belt on regardless of conditions",it:"Rimanere nel veicolo con la cintura allacciata indipendentemente dalle condizioni"}],correct:1,explain_en:"If your vehicle breaks down: move to the right shoulder, turn on hazard lights, and place reflective triangles or flares to warn approaching traffic.",explain_it:"Se il veicolo si ferma: spostati sulla banchina destra, accendi le luci di pericolo e posiziona triangoli riflettenti o razzi per avvisare il traffico in avvicinamento."},
  {cat:"laws",en:"Florida law prohibits parking within how many feet of a stop sign?",it:"La legge della Florida vieta il parcheggio entro quanti piedi da un segnale di stop?",options:[{en:"10 feet",it:"10 piedi"},{en:"20 feet",it:"20 piedi"},{en:"30 feet",it:"30 piedi"},{en:"50 feet",it:"50 piedi"}],correct:2,explain_en:"You may not park within 30 feet of a stop sign or yield sign \u2014 this ensures visibility for approaching drivers.",explain_it:"Non puoi parcheggiare entro 30 piedi (9 m) da un segnale di stop o precedenza \u2014 questo garantisce la visibilita per i conducenti in avvicinamento."},
  {cat:"laws",en:"What is required of a Florida driver when an authorized emergency vehicle is stationary on the side of the road?",it:"Cosa e richiesto a un conducente della Florida quando un veicolo di emergenza autorizzato e fermo sul lato della strada?",options:[{en:"Honk to alert the officers",it:"Suonare per avvisare gli agenti"},{en:"Move to the furthest available lane from the vehicle OR reduce speed significantly below the limit",it:"Spostarsi nella corsia piu lontana disponibile dal veicolo O ridurre significativamente la velocita sotto il limite"},{en:"Slow to exactly 20 mph when passing",it:"Rallentare esattamente a 20 mph quando si passa"},{en:"No requirement \u2014 normal driving rules apply",it:"Nessun requisito \u2014 si applicano le normali regole di guida"}],correct:1,explain_en:"Florida's Move Over Law: when an authorized emergency or utility vehicle is on the side with lights on, move over one lane OR slow to 20 mph below the posted limit.",explain_it:"Legge Move Over: quando un veicolo di emergenza o utility autorizzato e sul lato con le luci accese, spostati di una corsia O rallenta di 20 mph sotto il limite segnalato."},
  {cat:"laws",en:"In Florida, a solid white line between lanes means:",it:"In Florida, una linea bianca continua tra le corsie significa:",options:[{en:"Passing is encouraged in this area",it:"Il sorpasso e incoraggiato in questa zona"},{en:"Lane changes are discouraged \u2014 stay in your lane",it:"I cambi di corsia sono sconsigliati \u2014 rimani nella tua corsia"},{en:"The lanes travel in opposite directions",it:"Le corsie viaggiano in direzioni opposte"},{en:"You must remain in this lane until the next exit",it:"Devi rimanere in questa corsia fino alla prossima uscita"}],correct:1,explain_en:"A solid white line discourages (but does not always prohibit) lane changes. It is commonly used near intersections or in merge areas.",explain_it:"Una linea bianca continua sconsiglia (ma non sempre vieta) i cambi di corsia. E comunemente usata vicino agli incroci o nelle aree di confluenza."},
  {cat:"laws",en:"In Florida, what does a double solid yellow center line mean?",it:"In Florida, cosa significa una doppia linea gialla continua al centro?",options:[{en:"Passing is allowed in both directions",it:"Il sorpasso e consentito in entrambe le direzioni"},{en:"Passing is prohibited in both directions",it:"Il sorpasso e vietato in entrambe le direzioni"},{en:"Only left turns are permitted across this line",it:"Solo le svolte a sinistra sono consentite attraverso questa linea"},{en:"The center turn lane begins",it:"Inizia la corsia di svolta centrale"}],correct:1,explain_en:"A double solid yellow line prohibits passing in BOTH directions. Neither side may cross the line except to turn.",explain_it:"Una doppia linea gialla continua vieta il sorpasso in ENTRAMBE le direzioni. Nessun lato puo attraversare la linea tranne che per svoltare."},
  {cat:"laws",en:"What does Florida law require after purchasing a used vehicle?",it:"Cosa richiede la legge della Florida dopo l'acquisto di un veicolo usato?",options:[{en:"Register it within 60 days",it:"Registrarlo entro 60 giorni"},{en:"Transfer the title and register it within 30 days",it:"Trasferire il titolo e registrarlo entro 30 giorni"},{en:"Get a new VIN inspection within 10 days",it:"Ottenere una nuova ispezione del VIN entro 10 giorni"},{en:"Insurance is the only requirement",it:"L'assicurazione e l'unico requisito"}],correct:1,explain_en:"After purchasing a used vehicle in Florida, you must transfer the title and register it within 30 days to avoid late fees and penalties.",explain_it:"Dopo l'acquisto di un veicolo usato in Florida, devi trasferire il titolo e registrarlo entro 30 giorni per evitare more e sanzioni."},
  {cat:"laws",en:"In Florida, the space between a solid and broken yellow center line means:",it:"In Florida, lo spazio tra una linea gialla continua e una tratteggiata al centro significa:",options:[{en:"Both sides may pass whenever clear",it:"Entrambi i lati possono sorpassare quando libero"},{en:"The driver beside the broken line may pass; the driver beside the solid line may not",it:"Il conducente accanto alla linea tratteggiata puo sorpassare; il conducente accanto alla linea continua non puo"},{en:"Passing is forbidden from both sides",it:"Il sorpasso e vietato da entrambi i lati"},{en:"This marking is only used in construction zones",it:"Questa marcatura e usata solo nelle zone di costruzione"}],correct:1,explain_en:"A solid line on your side = no passing. A broken line on your side = passing permitted when safe. Each driver follows the line on their side.",explain_it:"Una linea continua sul tuo lato = nessun sorpasso. Una linea tratteggiata sul tuo lato = sorpasso consentito quando sicuro. Ogni conducente segue la linea sul proprio lato."},
  {cat:"safety",en:"What is the purpose of the 'SIPDE' driving strategy?",it:"Qual e lo scopo della strategia di guida 'SIPDE'?",options:[{en:"A method for parallel parking",it:"Un metodo per il parcheggio parallelo"},{en:"Scan, Identify, Predict, Decide, Execute \u2014 a systematic hazard-management process",it:"Scan, Identify, Predict, Decide, Execute \u2014 un processo sistematico di gestione dei rischi"},{en:"A system for highway merging",it:"Un sistema per la confluenza in autostrada"},{en:"Speed, Intercept, Pass, Disengage, Escape \u2014 an evasion technique",it:"Speed, Intercept, Pass, Disengage, Escape \u2014 una tecnica di evasione"}],correct:1,explain_en:"SIPDE: Scan the road, Identify hazards, Predict what may happen, Decide on a response, Execute the action. A structured approach to hazard perception.",explain_it:"SIPDE: Scansiona la strada, Identifica i pericoli, Prevedi cosa potrebbe accadere, Decidi una risposta, Esegui l'azione. Un approccio strutturato alla percezione dei pericoli."},
  {cat:"safety",en:"What is the 'two-second rule' eye scanning technique for highway driving?",it:"Qual e la tecnica di scansione degli occhi della 'regola dei due secondi' per la guida in autostrada?",options:[{en:"Check mirrors every 2 seconds",it:"Controlla gli specchi ogni 2 secondi"},{en:"Scan far enough ahead that your eyes lead by at least 12-15 seconds of travel time",it:"Scansiona abbastanza avanti che i tuoi occhi guidano di almeno 12-15 secondi di tempo di viaggio"},{en:"Count 2 seconds between each mirror check",it:"Conta 2 secondi tra ogni controllo degli specchi"},{en:"Look 2 seconds back for following traffic",it:"Guarda 2 secondi indietro per il traffico che segue"}],correct:1,explain_en:"Highway eye-lead time: scan 12-15 seconds ahead (about quarter mile at 60 mph) to see and respond to hazards early. Also check mirrors every 5-8 seconds.",explain_it:"Tempo di visione in autostrada: scansiona 12-15 secondi avanti (circa 400 m a 100 km/h) per vedere e rispondere ai pericoli in anticipo."},
  {cat:"safety",en:"What is the main danger of a 'blind spot' when changing lanes?",it:"Qual e il pericolo principale di un 'punto cieco' quando si cambia corsia?",options:[{en:"Glare from the sun makes the mirror hard to read",it:"Il riflesso del sole rende difficile leggere lo specchio"},{en:"Another vehicle may be alongside you but invisible in your mirrors \u2014 causing a collision if you change lanes",it:"Un altro veicolo puo essere accanto a te ma invisibile negli specchi \u2014 causando una collisione se cambi corsia"},{en:"Blind spots only affect large trucks",it:"I punti ciechi colpiscono solo i camion grandi"},{en:"Mirrors always show everything \u2014 there are no true blind spots in modern vehicles",it:"Gli specchi mostrano sempre tutto \u2014 non ci sono veri punti ciechi nei veicoli moderni"}],correct:1,explain_en:"A blind spot is an area not visible in your mirrors. Always do a shoulder check (physically look) before changing lanes.",explain_it:"Un punto cieco e un'area non visibile negli specchi. Fai sempre un controllo della spalla (guarda fisicamente) prima di cambiare corsia."},
  {cat:"safety",en:"When should you use your high-beam headlights?",it:"Quando dovresti usare i fari abbaglianti?",options:[{en:"At all times for better visibility",it:"In ogni momento per una migliore visibilita"},{en:"On open roads with no oncoming traffic or vehicles ahead \u2014 dim when within 500 feet of others",it:"Su strade aperte senza traffico in arrivo o veicoli davanti \u2014 abbassare entro 500 piedi dagli altri"},{en:"Only in fog and rain",it:"Solo nella nebbia e nella pioggia"},{en:"Only on highways with a speed limit above 55 mph",it:"Solo sulle autostrade con un limite di velocita superiore a 55 mph"}],correct:1,explain_en:"Use high beams on open rural roads when no other traffic is nearby. Dim to low beams within 500 feet of oncoming traffic or 300 feet when following a vehicle.",explain_it:"Usa gli abbaglianti su strade rurali aperte senza altro traffico vicino. Abbassa i fari entro 500 piedi dal traffico in arrivo o 300 piedi quando segui un veicolo."},
  {cat:"safety",en:"What does 'scanning' mean in defensive driving?",it:"Cosa significa 'scansionare' nella guida difensiva?",options:[{en:"Checking your phone for navigation updates",it:"Controllare il telefono per gli aggiornamenti di navigazione"},{en:"Continuously moving your eyes to observe the full driving environment \u2014 mirrors, ahead, sides",it:"Muovere continuamente gli occhi per osservare l'intero ambiente di guida \u2014 specchi, avanti, lati"},{en:"Using a backup camera to check behind",it:"Usare una telecamera posteriore per controllare dietro"},{en:"Scanning radio channels for traffic reports",it:"Eseguire la scansione dei canali radio per i rapporti sul traffico"}],correct:1,explain_en:"Scanning means continuously moving your eyes \u2014 ahead 12-15 seconds, checking mirrors every 5-8 seconds, and monitoring all sides for developing hazards.",explain_it:"Scansionare significa muovere continuamente gli occhi \u2014 avanti 12-15 secondi, controllare gli specchi ogni 5-8 secondi e monitorare tutti i lati per i pericoli in sviluppo."},
  {cat:"safety",en:"What should you do when driving in dense fog?",it:"Cosa dovresti fare quando guidi in fitta nebbia?",options:[{en:"Use high beams to see further",it:"Usare gli abbaglianti per vedere piu lontano"},{en:"Use low beams or fog lights, reduce speed significantly, increase following distance",it:"Usare i fari anabbaglianti o le luci per la nebbia, ridurre significativamente la velocita, aumentare la distanza"},{en:"Turn on hazard lights and drive at normal speed",it:"Accendere le luci di pericolo e guidare a velocita normale"},{en:"Stop immediately and wait for the fog to clear",it:"Fermarsi immediatamente e aspettare che la nebbia si diradi"}],correct:1,explain_en:"In fog: use low beams (high beams reflect off fog making it worse), reduce speed, increase following distance, and consider pulling over if visibility is near zero.",explain_it:"Nella nebbia: usa i fari anabbaglianti (gli abbaglianti riflettono sulla nebbia peggiorandola), riduci la velocita, aumenta la distanza e considera di accostare se la visibilita e quasi zero."},
  {cat:"safety",en:"What is 'hydroplaning' and when does it occur?",it:"Cos'e il 'aquaplaning' e quando si verifica?",options:[{en:"A vehicle bouncing on rough pavement",it:"Un veicolo che rimbalza su un pavimento irregolare"},{en:"When water builds up between tires and road faster than it can disperse \u2014 tires lose contact with road",it:"Quando l'acqua si accumula tra gli pneumatici e la strada piu velocemente di quanto possa disperdersi \u2014 gli pneumatici perdono contatto con la strada"},{en:"When the engine overheats in rainy conditions",it:"Quando il motore si surriscalda in condizioni di pioggia"},{en:"Skidding on black ice at low temperatures",it:"Slittamento su ghiaccio nero a basse temperature"}],correct:1,explain_en:"Hydroplaning: a layer of water causes tires to lose road contact. Occurs at higher speeds on wet roads, especially with worn tires. Response: ease off gas, don't brake hard.",explain_it:"Acquaplaning: uno strato d'acqua fa perdere il contatto stradale agli pneumatici. Si verifica ad alta velocita su strade bagnate, specialmente con pneumatici consumati. Risposta: togli il gas, non frenare bruscamente."},
  {cat:"safety",en:"If your vehicle hydroplanes, you should:",it:"Se il tuo veicolo fa acquaplaning, dovresti:",options:[{en:"Brake hard to stop quickly",it:"Frenare bruscamente per fermarsi rapidamente"},{en:"Ease off the gas, hold the wheel straight, and let the tires regain traction naturally",it:"Togli il gas, tieni il volante dritto e lascia che gli pneumatici riprendano l'aderenza naturalmente"},{en:"Turn the wheel sharply to regain control",it:"Girare bruscamente il volante per riprendere il controllo"},{en:"Accelerate to power through the water",it:"Accelerare per passare attraverso l'acqua"}],correct:1,explain_en:"Hydroplaning response: ease off the gas (don't brake), steer straight, and let the vehicle slow naturally until tires regain road contact.",explain_it:"Risposta all'acquaplaning: togli il gas (non frenare), sterza dritto e lascia che il veicolo rallenti naturalmente finche gli pneumatici riprendono il contatto."},
  {cat:"safety",en:"What is the danger of driving too close to the right edge of the road (off the pavement edge)?",it:"Qual e il pericolo di guidare troppo vicino al bordo destro della strada (fuori dal bordo dell'asfalto)?",options:[{en:"No danger \u2014 the shoulder is designed for vehicles",it:"Nessun pericolo \u2014 la banchina e progettata per i veicoli"},{en:"A tire can drop off the pavement edge causing loss of control \u2014 especially at highway speeds",it:"Un pneumatico puo cadere dal bordo dell'asfalto causando perdita del controllo \u2014 specialmente alle velocita autostradali"},{en:"Only a risk in wet conditions",it:"Solo un rischio in condizioni bagnate"},{en:"The only risk is damage to tires",it:"L'unico rischio e il danno agli pneumatici"}],correct:1,explain_en:"Dropping a tire off the pavement edge at speed can cause violent loss of control. If it happens: ease off gas, steer gently \u2014 never jerk the wheel.",explain_it:"Far cadere uno pneumatico dal bordo dell'asfalto a velocita puo causare una violenta perdita di controllo. Se accade: togli il gas, sterza delicatamente \u2014 non tirare mai il volante."},
  {cat:"safety",en:"What should you do when you see a pedestrian with a white cane or guide dog?",it:"Cosa dovresti fare quando vedi un pedone con un bastone bianco o un cane guida?",options:[{en:"Proceed normally \u2014 they have the same rights as other pedestrians",it:"Procedere normalmente \u2014 hanno gli stessi diritti degli altri pedoni"},{en:"Yield completely and wait \u2014 they have the absolute right-of-way at all crossings",it:"Cedere completamente e aspettare \u2014 hanno la precedenza assoluta a tutti gli attraversamenti"},{en:"Sound your horn to alert them of your presence",it:"Suonare il clacson per avvisarli della tua presenza"},{en:"Slow to 5 mph and pass carefully",it:"Rallentare a 5 mph e passare con cautela"}],correct:1,explain_en:"Drivers must yield COMPLETELY to visually impaired pedestrians using white canes or guide dogs at all intersections and crosswalks.",explain_it:"I conducenti devono cedere COMPLETAMENTE ai pedoni con disabilita visiva che usano bastoni bianchi o cani guida a tutti gli incroci e passaggi pedonali."},
  {cat:"safety",en:"What is the correct action when being tailgated?",it:"Qual e l'azione corretta quando si e seguiti troppo da vicino?",options:[{en:"Brake suddenly to teach the driver a lesson",it:"Frenare improvvisamente per dare una lezione al conducente"},{en:"Gradually slow down to increase distance between you \u2014 or change lanes to let them pass",it:"Rallentare gradualmente per aumentare la distanza tra voi \u2014 o cambiare corsia per lasciarli passare"},{en:"Speed up to match their following pace",it:"Accelerare per adeguarsi al loro ritmo"},{en:"Tap your brakes repeatedly to warn them",it:"Premere ripetutamente i freni per avvertirli"}],correct:1,explain_en:"When tailgated: gradually slow down to increase space ahead (giving yourself more stopping room) or safely move over to let them pass. Do not brake-check.",explain_it:"Quando si e seguiti da vicino: rallenta gradualmente per aumentare lo spazio davanti (dandoti piu spazio di frenata) o spostati in sicurezza per lasciarli passare."},
  {cat:"safety",en:"What is the safest way to approach a green light at an intersection?",it:"Qual e il modo piu sicuro di avvicinarsi a un semaforo verde a un incrocio?",options:[{en:"Accelerate to clear it before it changes",it:"Accelerare per liberarlo prima che cambi"},{en:"Cover the brake and scan cross-traffic before entering \u2014 never assume it is safe",it:"Coprire il freno e scansionare il traffico trasversale prima di entrare \u2014 non assumere mai che sia sicuro"},{en:"Maintain speed \u2014 green means the intersection is clear",it:"Mantenere la velocita \u2014 il verde significa che l'incrocio e libero"},{en:"Sound your horn to warn cross-traffic",it:"Suonare il clacson per avvisare il traffico trasversale"}],correct:1,explain_en:"Even on green, cover the brake and check cross-traffic before entering. Red-light runners and blocked intersections are leading causes of intersection crashes.",explain_it:"Anche con il verde, copri il freno e controlla il traffico trasversale prima di entrare. I passatori con il rosso e gli incroci bloccati sono le principali cause degli incidenti agli incroci."},
  {cat:"safety",en:"What is the 'friction point' in a manual transmission vehicle?",it:"Cos'e il 'punto di frizione' in un veicolo con cambio manuale?",options:[{en:"The point where the clutch fully disengages",it:"Il punto in cui la frizione si disinnesta completamente"},{en:"The point where the clutch begins to engage and the vehicle starts to move",it:"Il punto in cui la frizione inizia ad innestare e il veicolo inizia a muoversi"},{en:"The maximum gear position before the engine redlines",it:"La posizione massima della marcia prima che il motore raggiunga il limite"},{en:"A point of excessive brake wear",it:"Un punto di usura eccessiva dei freni"}],correct:1,explain_en:"The friction point is where the clutch plates begin to make contact and the vehicle starts to creep forward. It is the key control point for smooth starts.",explain_it:"Il punto di frizione e dove le piastre della frizione iniziano a fare contatto e il veicolo inizia a muoversi. E il punto di controllo chiave per le partenze fluide."},
  {cat:"safety",en:"What is the primary danger of 'overdriving headlights' at night?",it:"Qual e il pericolo principale di 'guidare piu veloce dei fari' di notte?",options:[{en:"Blinding oncoming drivers with high beams",it:"Abbagliare i conducenti in arrivo con gli abbaglianti"},{en:"Traveling faster than your ability to stop within the distance illuminated by headlights",it:"Viaggiare piu veloce della capacita di fermarsi entro la distanza illuminata dai fari"},{en:"Draining the battery faster",it:"Scaricare la batteria piu velocemente"},{en:"Causing glare on wet roads",it:"Causare riflessi sulle strade bagnate"}],correct:1,explain_en:"Overdriving headlights: if you travel faster than your stopping distance within your headlight range, you cannot stop in time for unseen hazards.",explain_it:"Guidare piu veloce dei fari: se viaggi piu veloce della distanza di arresto entro il campo dei fari, non puoi fermarti in tempo per i pericoli non visti."},
  {cat:"safety",en:"What is a 'space cushion' in driving?",it:"Cos'e un 'cuscinetto di spazio' nella guida?",options:[{en:"The air inside your tires",it:"L'aria all'interno degli pneumatici"},{en:"A buffer of space maintained around your vehicle on all sides to allow reaction time",it:"Un buffer di spazio mantenuto intorno al veicolo su tutti i lati per consentire il tempo di reazione"},{en:"The distance between the front and rear bumper of your car",it:"La distanza tra il paraurti anteriore e posteriore della tua auto"},{en:"The gap left in a parking space",it:"Lo spazio lasciato in un parcheggio"}],correct:1,explain_en:"A space cushion is the buffer zone around your vehicle \u2014 front, rear, and sides. Maintaining it gives you time and space to react to any hazard.",explain_it:"Un cuscinetto di spazio e la zona buffer intorno al veicolo \u2014 davanti, dietro e sui lati. Mantenerlo ti da tempo e spazio per reagire a qualsiasi pericolo."},
  {cat:"safety",en:"What is the most effective method to stay awake on a long drive?",it:"Qual e il metodo piu efficace per rimanere sveglio in un lungo viaggio?",options:[{en:"Drink strong coffee continuously",it:"Bere caffe forte continuamente"},{en:"Pull over and take a short nap of 15-20 minutes, and take breaks every 2 hours",it:"Accostare e fare un breve pisolino di 15-20 minuti, e fare pause ogni 2 ore"},{en:"Open the window for cold air",it:"Aprire il finestrino per l'aria fredda"},{en:"Turn up the radio volume",it:"Alzare il volume della radio"}],correct:1,explain_en:"The only effective fatigue remedy is sleep. A 15-20 minute power nap significantly restores alertness. Take breaks every 2 hours on long trips.",explain_it:"L'unico rimedio efficace contro la stanchezza e il sonno. Un pisolino di 15-20 minuti ripristina significativamente la vigilanza. Fai pause ogni 2 ore nei viaggi lunghi."},
  {cat:"safety",en:"What does 'oversteering' a vehicle mean?",it:"Cosa significa 'sovrasterzo' di un veicolo?",options:[{en:"Steering wheel vibrates at high speed",it:"Il volante vibra ad alta velocita"},{en:"The rear tires lose grip and the rear of the car swings out in the direction opposite to the turn",it:"Gli pneumatici posteriori perdono aderenza e il retro dell'auto si sposta nella direzione opposta alla svolta"},{en:"Front tires losing grip causing the car to go straight",it:"Pneumatici anteriori che perdono aderenza causando l'andare dritto dell'auto"},{en:"The car turns too sharply due to a fault in the steering system",it:"L'auto gira troppo bruscamente a causa di un difetto nel sistema di sterzo"}],correct:1,explain_en:"Oversteer: rear tires lose grip and the tail swings out. Response: steer in the direction of the skid (into the turn) and ease off gas.",explain_it:"Sovrasterzo: gli pneumatici posteriori perdono aderenza e la coda si sposta. Risposta: sterza nella direzione dello slittamento (nella svolta) e togli il gas."},
  {cat:"safety",en:"What is the best way to handle a sudden tire blowout on a highway?",it:"Qual e il modo migliore per gestire uno scoppio improvviso in autostrada?",options:[{en:"Immediately steer hard to the shoulder",it:"Sterzare immediatamente bruscamente verso la banchina"},{en:"Grip the wheel firmly, ease off gas, maintain direction, steer gently to the shoulder",it:"Stringi fermamente il volante, togli il gas, mantieni la direzione, sterza delicatamente verso la banchina"},{en:"Brake hard to stop the car quickly",it:"Frenare bruscamente per fermare l'auto rapidamente"},{en:"Accelerate briefly to stabilize before slowing",it:"Accelerare brevemente per stabilizzare prima di rallentare"}],correct:1,explain_en:"Blowout: grip the wheel, ease off gas (don't brake hard), maintain direction, and slow gradually to the shoulder. Hard braking during a blowout can cause rollover.",explain_it:"Scoppio: stringi il volante, togli il gas (non frenare bruscamente), mantieni la direzione e rallenta gradualmente verso la banchina."},
  {cat:"safety",en:"What is the safest following distance when driving behind a motorcycle?",it:"Qual e la distanza di sicurezza piu sicura quando si guida dietro una moto?",options:[{en:"Same as following any other vehicle \u2014 3 seconds",it:"La stessa di qualsiasi altro veicolo \u2014 3 secondi"},{en:"At least 4 seconds \u2014 motorcycles can stop faster and are more vulnerable",it:"Almeno 4 secondi \u2014 le moto possono fermarsi piu velocemente e sono piu vulnerabili"},{en:"1 car length is sufficient",it:"1 lunghezza auto e sufficiente"},{en:"Motorcycles are fast \u2014 keep 6 car lengths",it:"Le moto sono veloci \u2014 mantieni 6 lunghezze auto"}],correct:1,explain_en:"Follow motorcycles with at least 4 seconds of following distance. They can stop quickly and are harder to see. A rear-end impact can be fatal to a motorcyclist.",explain_it:"Segui le moto con almeno 4 secondi di distanza. Possono fermarsi rapidamente e sono piu difficili da vedere. Un impatto posteriore puo essere fatale per un motociclista."},
  {cat:"safety",en:"What is a 'stale green light' and why is it dangerous?",it:"Cos'e un 'verde stantio' e perche e pericoloso?",options:[{en:"A signal that has been flashing green for a long time",it:"Un segnale che lampeggia verde da molto tempo"},{en:"A green light that has been on for a long time and is likely about to change",it:"Un verde che e rimasto acceso a lungo e probabilmente sta per cambiare"},{en:"A broken green traffic light",it:"Un semaforo verde rotto"},{en:"A green light at a dangerous intersection",it:"Un semaforo verde a un incrocio pericoloso"}],correct:1,explain_en:"A stale green light has been green for a while and may change soon. Slow down and cover the brake as you approach \u2014 don't speed up to beat the change.",explain_it:"Un verde stantio e rimasto verde per un po' e potrebbe cambiare presto. Rallenta e copri il freno mentre ti avvicini \u2014 non accelerare per bruciarlo."},
  {cat:"safety",en:"What is the correct way to check for traffic when backing out of a parking space?",it:"Qual e il modo corretto per controllare il traffico quando si fa retromarcia fuori da un parcheggio?",options:[{en:"Use the rearview mirror only",it:"Usare solo lo specchietto retrovisore"},{en:"Check all mirrors, look over both shoulders, and back out slowly \u2014 then use a backup camera if available",it:"Controlla tutti gli specchi, guarda oltre entrambe le spalle e fai retromarcia lentamente \u2014 poi usa una telecamera posteriore se disponibile"},{en:"Sound the horn and reverse quickly",it:"Suonare il clacson e fare retromarcia velocemente"},{en:"Only check for pedestrians \u2014 vehicles have priority",it:"Controllare solo i pedoni \u2014 i veicoli hanno la priorita"}],correct:1,explain_en:"Before backing: check all mirrors, look over both shoulders, and move slowly. Other vehicles and pedestrians may not see you \u2014 always yield when backing.",explain_it:"Prima di fare retromarcia: controlla tutti gli specchi, guarda oltre entrambe le spalle e muoviti lentamente. Gli altri veicoli e i pedoni potrebbero non vederti."},
  {cat:"safety",en:"What is the key danger when driving in a large truck's 'No-Zone' (rear blind spot)?",it:"Qual e il pericolo principale quando si guida nella 'No-Zone' (punto cieco posteriore) di un camion grande?",options:[{en:"The truck driver cannot see your turn signals",it:"Il conducente del camion non puo vedere i tuoi segnali di svolta"},{en:"The truck driver has no visibility of you \u2014 if they change lanes or brake suddenly, collision is likely",it:"Il conducente del camion non ha visibilita su di te \u2014 se cambia corsia o frena improvvisamente, la collisione e probabile"},{en:"You receive radio interference from the truck",it:"Ricevi interferenze radio dal camion"},{en:"The truck's exhaust fumes are strongest in this zone",it:"I gas di scarico del camion sono piu forti in questa zona"}],correct:1,explain_en:"In a truck's rear No-Zone (within 30 feet), the driver cannot see you at all. If the truck brakes suddenly you have no time to react. Stay well back.",explain_it:"Nella No-Zone posteriore di un camion (entro 30 piedi), il conducente non puo vederti affatto. Se il camion frena improvvisamente non hai tempo per reagire."},
  {cat:"safety",en:"When should you turn on your hazard (emergency) lights?",it:"Quando dovresti accendere le luci di pericolo (emergenza)?",options:[{en:"Any time you are driving slowly in traffic",it:"Ogni volta che guidi lentamente nel traffico"},{en:"When your vehicle is stopped or disabled in a hazardous location, or to warn of a traffic hazard ahead",it:"Quando il veicolo e fermo o guasto in un luogo pericoloso, o per avvisare di un pericolo del traffico in avanti"},{en:"When driving in rain at night",it:"Quando si guida nella pioggia di notte"},{en:"As a substitute for turn signals in heavy traffic",it:"Come sostituto dei segnali di svolta nel traffico intenso"}],correct:1,explain_en:"Hazard lights indicate your vehicle is a hazard \u2014 use them when stopped or disabled, not as a substitute for turn signals or while driving slowly.",explain_it:"Le luci di pericolo indicano che il veicolo e un pericolo \u2014 usale quando sei fermo o guasto, non come sostituto dei segnali di svolta o durante la guida lenta."},
  {cat:"safety",en:"What is 'night blindness' and how does it affect driving safety?",it:"Cos'e la 'cecita notturna' e come influisce sulla sicurezza alla guida?",options:[{en:"Complete inability to drive after dark",it:"Completa incapacita di guidare dopo il buio"},{en:"Reduced ability to see clearly in low-light conditions \u2014 increasing crash risk after dark",it:"Ridotta capacita di vedere chiaramente in condizioni di luce scarsa \u2014 aumentando il rischio di incidenti dopo il tramonto"},{en:"Only affects older drivers over 70",it:"Colpisce solo i conducenti anziani over 70"},{en:"A condition caused by bright headlights only",it:"Una condizione causata solo dai fari luminosi"}],correct:1,explain_en:"Night blindness reduces contrast sensitivity in low light. All drivers experience reduced vision after dark \u2014 especially adjusting after bright lights (takes 7+ seconds).",explain_it:"La cecita notturna riduce la sensibilita al contrasto in poca luce. Tutti i conducenti sperimentano una visione ridotta dopo il tramonto \u2014 specialmente dopo luci luminose (richiede 7+ secondi)."},
  {cat:"safety",en:"What is the correct response to a medical emergency (e.g., heart attack) while driving?",it:"Qual e la risposta corretta a un'emergenza medica (p.es. attacco di cuore) durante la guida?",options:[{en:"Continue driving to the nearest hospital",it:"Continuare a guidare fino all'ospedale piu vicino"},{en:"Safely pull over, put the vehicle in park, call 911, and stay with the vehicle",it:"Accostare in sicurezza, mettere il veicolo in parcheggio, chiamare il 911 e rimanere con il veicolo"},{en:"Flash hazard lights and continue at normal speed",it:"Lampeggiare le luci di pericolo e continuare a velocita normale"},{en:"Ask a passenger to steer while you treat the condition",it:"Chiedere a un passeggero di sterzare mentre tratti la condizione"}],correct:1,explain_en:"Medical emergency while driving: safely pull over as soon as possible, stop the vehicle, call 911. Do not attempt to drive to a hospital \u2014 you may lose consciousness.",explain_it:"Emergenza medica durante la guida: accosta in sicurezza il prima possibile, ferma il veicolo, chiama il 911. Non tentare di guidare fino a un ospedale \u2014 potresti perdere conoscenza."},
  {cat:"safety",en:"What should you do when sun glare severely limits your visibility while driving?",it:"Cosa dovresti fare quando il riflesso solare limita gravemente la tua visibilita durante la guida?",options:[{en:"Accelerate to pass through the glare area quickly",it:"Accelerare per passare attraverso la zona abbagliante velocemente"},{en:"Reduce speed, use sun visor or sunglasses, increase following distance",it:"Ridurre la velocita, usare il parasole o occhiali da sole, aumentare la distanza"},{en:"Turn on high beams to compensate",it:"Accendere gli abbaglianti per compensare"},{en:"Glare only affects night driving \u2014 daytime is safe",it:"L'abbagliamento colpisce solo la guida notturna \u2014 il giorno e sicuro"}],correct:1,explain_en:"Sun glare: reduce speed, use sun visor and polarized sunglasses, increase following distance. If visibility becomes zero, pull over safely and wait.",explain_it:"Abbagliamento solare: riduci la velocita, usa il parasole e occhiali polarizzati, aumenta la distanza. Se la visibilita diventa zero, accosta in sicurezza e aspetta."},
  {cat:"safety",en:"What is the effect of prescription medication on driving ability?",it:"Qual e l'effetto dei farmaci da prescrizione sulla capacita di guida?",options:[{en:"Prescription medications are always safe to drive on since a doctor approved them",it:"I farmaci da prescrizione sono sempre sicuri da guidare poiche un medico li ha approvati"},{en:"Many medications can impair driving \u2014 always check labels for drowsiness, dizziness, or impairment warnings",it:"Molti farmaci possono compromettere la guida \u2014 controlla sempre le etichette per avvertenze di sonnolenza, vertigini o compromissione"},{en:"Only illegal drugs affect driving",it:"Solo le droghe illegali influenzano la guida"},{en:"Medications only affect driving above a certain dosage",it:"I farmaci influenzano la guida solo sopra un certo dosaggio"}],correct:1,explain_en:"Many legal prescription and OTC medications (antihistamines, sedatives, pain killers) can cause drowsiness or impairment. Always read labels and ask your doctor.",explain_it:"Molti farmaci da prescrizione e da banco (antistaminici, sedativi, antidolorifici) possono causare sonnolenza o compromissione. Leggi sempre le etichette e chiedi al tuo medico."},
  {cat:"safety",en:"What should you do if your accelerator sticks (gas pedal stays down) while driving?",it:"Cosa dovresti fare se l'acceleratore rimane bloccato (il pedale del gas rimane premuto) durante la guida?",options:[{en:"Turn off the engine immediately at any speed",it:"Spegnere immediatamente il motore a qualsiasi velocita"},{en:"Shift to neutral, apply brakes firmly, steer to safety, then turn off engine when stopped",it:"Inserire il neutro, applicare i freni con fermezza, sterzare verso un luogo sicuro, poi spegnere il motore quando fermo"},{en:"Press the brake and gas simultaneously",it:"Premere il freno e il gas contemporaneamente"},{en:"Steer off the road immediately",it:"Sterzare fuori dalla strada immediatamente"}],correct:1,explain_en:"Stuck accelerator: shift to neutral (disengages engine from wheels), apply firm brake pressure, steer to safety, then turn off the engine once stopped.",explain_it:"Acceleratore bloccato: inserisci il neutro (disinnesta il motore dalle ruote), applica la pressione del freno, sterza verso un luogo sicuro, poi spegni il motore una volta fermo."},
  {cat:"safety",en:"Why is it dangerous to park too close to a fire hydrant?",it:"Perche e pericoloso parcheggiare troppo vicino a un idrante?",options:[{en:"It is a hazard to other parked vehicles",it:"E un pericolo per gli altri veicoli parcheggiati"},{en:"Emergency responders cannot access the hydrant \u2014 potentially delaying fire suppression",it:"I soccorritori non possono accedere all'idrante \u2014 potenzialmente ritardando la soppressione dell'incendio"},{en:"The hydrant may damage your vehicle",it:"L'idrante potrebbe danneggiare il veicolo"},{en:"It blocks pedestrian access to the sidewalk",it:"Blocca l'accesso pedonale al marciapiede"}],correct:1,explain_en:"Blocking a fire hydrant prevents firefighters from quickly connecting their hoses. The 15-foot clearance must be maintained at all times.",explain_it:"Bloccare un idrante impedisce ai vigili del fuoco di collegare rapidamente i tubi. La distanza di 15 piedi deve essere mantenuta in ogni momento."},
  {cat:"safety",en:"What is the '12 second rule' in driving?",it:"Cos'e la 'regola dei 12 secondi' nella guida?",options:[{en:"Wait 12 seconds at every stop sign",it:"Aspettare 12 secondi a ogni segnale di stop"},{en:"Scan at least 12 seconds ahead to identify hazards early \u2014 about quarter mile at 60 mph",it:"Scansiona almeno 12 secondi avanti per identificare i pericoli in anticipo \u2014 circa un quarto di miglio a 60 mph"},{en:"A 12-second following distance on highways",it:"Una distanza di 12 secondi in autostrada"},{en:"Allow 12 seconds to complete a safe lane change",it:"Consentire 12 secondi per completare un cambio di corsia sicuro"}],correct:1,explain_en:"The 12-second rule: scan at least 12 seconds ahead. This gives you early warning of hazards and time to plan your response before reaching them.",explain_it:"La regola dei 12 secondi: scansiona almeno 12 secondi avanti. Questo ti da un preavviso dei pericoli e il tempo per pianificare la risposta prima di raggiungerli."},
  {cat:"safety",en:"What is the danger of 'fixating' (staring) at an object in your path?",it:"Qual e il pericolo di 'fissarsi' (fissare lo sguardo) su un oggetto nel proprio percorso?",options:[{en:"It wastes time you could use for other observations",it:"Spreca tempo che potresti usare per altre osservazioni"},{en:"Target fixation causes you to unconsciously steer toward the object you are staring at",it:"La fissazione dell'obiettivo ti fa sterzare inconsciamente verso l'oggetto che stai fissando"},{en:"Objects in your path are too close to steer around",it:"Gli oggetti nel tuo percorso sono troppo vicini per sterzare intorno"},{en:"It only affects motorcycle riders",it:"Colpisce solo i motociclisti"}],correct:1,explain_en:"Target fixation: staring at a hazard causes involuntary steering toward it. Always look WHERE YOU WANT TO GO \u2014 not at the obstacle.",explain_it:"Fissazione dell'obiettivo: fissare un pericolo causa uno sterzo involontario verso di esso. Guarda sempre DOVE VUOI ANDARE \u2014 non verso l'ostacolo."},
  {cat:"safety",en:"What does 'left-turn across traffic' (LTAC) crash mean?",it:"Cosa significa incidente 'svolta sinistra attraverso il traffico' (LTAC)?",options:[{en:"A crash caused by running a red light",it:"Un incidente causato dal passare con il rosso"},{en:"A collision occurring when a driver turns left and misjudges the speed of oncoming traffic",it:"Una collisione che si verifica quando un conducente svolta a sinistra e valuta male la velocita del traffico in arrivo"},{en:"An accident in a left-turn-only lane",it:"Un incidente in una corsia solo svolta sinistra"},{en:"A U-turn crash on a divided highway",it:"Un incidente da inversione su un'autostrada divisa"}],correct:1,explain_en:"LTAC crashes occur when turning left drivers underestimate the speed of oncoming vehicles. Always ensure a large safety gap before turning left across traffic.",explain_it:"Gli incidenti LTAC si verificano quando i conducenti che svoltano a sinistra sottovalutano la velocita dei veicoli in arrivo. Assicurati sempre un ampio divario di sicurezza prima di svoltare a sinistra."},
  {cat:"safety",en:"What is the safest position for your hands on the steering wheel?",it:"Qual e la posizione piu sicura per le mani sul volante?",options:[{en:"10 and 2 o'clock position",it:"Posizione 10 e 2"},{en:"9 and 3 o'clock position \u2014 better airbag clearance and control",it:"Posizione 9 e 3 \u2014 migliore spazio per l'airbag e controllo"},{en:"One hand at the bottom (6 o'clock)",it:"Una mano in basso (ore 6)"},{en:"Both hands at the top (12 o'clock)",it:"Entrambe le mani in alto (ore 12)"}],correct:1,explain_en:"9 and 3 (or 8 and 4) is recommended \u2014 provides better control and keeps hands away from the airbag deployment path, reducing injury risk.",explain_it:"9 e 3 (o 8 e 4) e raccomandato \u2014 fornisce un controllo migliore e mantiene le mani lontane dal percorso di dispiegamento dell'airbag, riducendo il rischio di lesioni."},
  {cat:"safety",en:"What is the most important thing to do before a long road trip?",it:"Qual e la cosa piu importante da fare prima di un lungo viaggio in auto?",options:[{en:"Program your GPS",it:"Programmare il GPS"},{en:"Inspect the vehicle: tires, fluids, brakes, lights, and ensure you are well rested",it:"Ispezionare il veicolo: pneumatici, fluidi, freni, luci e assicurarsi di essere ben riposati"},{en:"Fill the gas tank only",it:"Fare solo il pieno di carburante"},{en:"Download offline maps",it:"Scaricare mappe offline"}],correct:1,explain_en:"Pre-trip inspection: check tires (pressure and tread), oil and coolant, brakes, lights, and windshield wipers. Most importantly, ensure you are well rested.",explain_it:"Ispezione pre-viaggio: controlla pneumatici (pressione e battistrada), olio e refrigerante, freni, luci e tergicristalli. La cosa piu importante: assicurati di essere ben riposato."},
  {cat:"safety",en:"What is the danger of driving alongside another vehicle in their blind spot for an extended time?",it:"Qual e il pericolo di guidare accanto a un altro veicolo nel suo punto cieco per un tempo prolungato?",options:[{en:"No danger \u2014 it is the other driver's responsibility to check before changing lanes",it:"Nessun pericolo \u2014 e responsabilita dell'altro conducente controllare prima di cambiare corsia"},{en:"You become invisible to that driver \u2014 if they change lanes, you may be sideswiped",it:"Diventi invisibile a quel conducente \u2014 se cambia corsia, potresti essere urtato lateralmente"},{en:"Only dangerous for motorcycles",it:"Pericoloso solo per le moto"},{en:"It is safe as long as you can see their mirrors",it:"E sicuro finche puoi vedere i loro specchi"}],correct:1,explain_en:"Lingering in another driver's blind spot is dangerous \u2014 move through quickly or drop back. You may not be visible in their mirrors.",explain_it:"Indugiare nel punto cieco di un altro conducente e pericoloso \u2014 passa velocemente o rallenta. Potresti non essere visibile nei loro specchi."},
  {cat:"safety",en:"When should you NOT use your parking brake as an emergency brake?",it:"Quando NON dovresti usare il freno a mano come freno di emergenza?",options:[{en:"When driving uphill",it:"Quando guidi in salita"},{en:"At highway speeds \u2014 the rear wheels can lock up causing loss of control or spin",it:"Alle velocita autostradali \u2014 le ruote posteriori possono bloccarsi causando perdita di controllo o giro"},{en:"In wet weather conditions",it:"In condizioni di pioggia"},{en:"The parking brake should always be used in emergencies",it:"Il freno a mano dovrebbe sempre essere usato nelle emergenze"}],correct:1,explain_en:"The parking brake at highway speed will lock the rear wheels, causing the car to spin or flip. Use it only at low speeds if the foot brake fails completely.",explain_it:"Il freno a mano alle velocita autostradali bloccera le ruote posteriori, causando la rotazione o il ribaltamento dell'auto. Usalo solo a basse velocita se il freno a pedale cede completamente."},
  {cat:"safety",en:"What is the correct response when a car coming toward you swerves into your lane?",it:"Qual e la risposta corretta quando un'auto che viene verso di te si sposta nella tua corsia?",options:[{en:"Speed up to pass them quickly",it:"Accelerare per passarli velocemente"},{en:"Sound horn, move to the right, and reduce speed \u2014 avoid swerving left",it:"Suona il clacson, spostati a destra e riduci la velocita \u2014 evita di sterzare a sinistra"},{en:"Brake hard and steer left to give them room",it:"Frenare bruscamente e sterzare a sinistra per dar loro spazio"},{en:"Flash high beams repeatedly",it:"Lampeggiare ripetutamente gli abbaglianti"}],correct:1,explain_en:"When a car comes at you head-on: sound horn, move right (toward the shoulder), slow down. Never steer left into oncoming traffic.",explain_it:"Quando un'auto viene verso di te frontalmente: suona il clacson, spostati a destra (verso la banchina), rallenta. Non sterzare mai a sinistra nel traffico in arrivo."},
  {cat:"safety",en:"What is the main purpose of ABS (Anti-lock Braking System)?",it:"Qual e lo scopo principale dell'ABS (Sistema Frenante Anti-blocco)?",options:[{en:"To stop the vehicle faster than pumping the brakes manually",it:"Per fermare il veicolo piu velocemente pompando i freni manualmente"},{en:"To prevent wheel lock-up so you can steer while braking hard in an emergency",it:"Per prevenire il blocco delle ruote in modo da poter sterzare durante la frenata in un'emergenza"},{en:"To automatically apply brakes when a sensor detects an obstacle",it:"Per applicare automaticamente i freni quando un sensore rileva un ostacolo"},{en:"To reduce brake wear on highway driving",it:"Per ridurre l'usura dei freni in autostrada"}],correct:1,explain_en:"ABS prevents wheel lockup under hard braking \u2014 allowing you to maintain steering control. Apply firm steady pressure; do NOT pump ABS brakes.",explain_it:"L'ABS previene il blocco delle ruote durante la frenata brusca \u2014 permettendoti di mantenere il controllo dello sterzo. Applica una pressione ferma e costante; NON pompare i freni ABS."},
  {cat:"safety",en:"What should you do if your car starts to skid on a slippery surface?",it:"Cosa dovresti fare se la tua auto inizia a slittare su una superficie scivolosa?",options:[{en:"Brake hard and steer straight",it:"Frenare bruscamente e sterzare dritto"},{en:"Ease off gas, steer in the direction the rear is sliding, and avoid hard braking",it:"Togli il gas, sterza nella direzione in cui scivola il retro e evita la frenata brusca"},{en:"Accelerate to regain traction quickly",it:"Accelerare per riprendere l'aderenza velocemente"},{en:"Apply the parking brake to stop the skid",it:"Applicare il freno a mano per fermare lo slittamento"}],correct:1,explain_en:"Skid recovery: ease off gas, steer INTO the skid direction (where the rear is sliding), avoid hard braking. This straightens the vehicle.",explain_it:"Recupero da slittamento: togli il gas, sterza VERSO la direzione dello slittamento (dove scivola il retro), evita la frenata brusca. Questo raddrizza il veicolo."},
  {cat:"safety",en:"What is the main benefit of an 'escape route' while driving?",it:"Qual e il principale vantaggio di una 'via di fuga' durante la guida?",options:[{en:"A pre-planned route to the nearest hospital",it:"Un percorso pre-pianificato verso l'ospedale piu vicino"},{en:"A mental plan of where to steer if the vehicle ahead stops suddenly",it:"Un piano mentale di dove sterzare se il veicolo davanti si ferma improvvisamente"},{en:"An alternate highway route to avoid congestion",it:"Un percorso autostradale alternativo per evitare la congestione"},{en:"The shoulder of the road \u2014 only for breakdowns",it:"La banchina della strada \u2014 solo per guasti"}],correct:1,explain_en:"An escape route is a mentally pre-planned path you can steer to if something goes wrong. Always know where you can move to avoid a sudden hazard.",explain_it:"Una via di fuga e un percorso mentalmente pre-pianificato verso cui sterzare se qualcosa va storto. Sappi sempre dove puoi spostarti per evitare un pericolo improvviso."},
  {cat:"safety",en:"What is the proper way to merge onto a highway?",it:"Qual e il modo corretto per immettersi in un'autostrada?",options:[{en:"Stop at the end of the ramp and wait for a gap",it:"Fermarsi alla fine della rampa e aspettare un'apertura"},{en:"Match highway traffic speed on the acceleration lane, signal, and merge into a safe gap",it:"Adeguare la velocita del traffico autostradale nella corsia di accelerazione, segnalare e confluire in un'apertura sicura"},{en:"Merge at any speed \u2014 highway drivers must yield to merging vehicles",it:"Confluire a qualsiasi velocita \u2014 i conducenti in autostrada devono cedere ai veicoli in confluenza"},{en:"Force your way in quickly to avoid backing up traffic on the ramp",it:"Inserirti rapidamente per evitare code sulla rampa"}],correct:1,explain_en:"Merging: accelerate to match highway speed in the acceleration lane, signal, find a safe gap, and merge smoothly. Do not stop at the end of ramps.",explain_it:"Confluenza: accelera per adeguarti alla velocita autostradale nella corsia di accelerazione, segnala, trova un'apertura sicura e confluisci fluidamente."},
  {cat:"safety",en:"What special hazard do motorcycles pose to other drivers?",it:"Quale pericolo speciale rappresentano le moto per gli altri conducenti?",options:[{en:"They are always faster than other vehicles",it:"Sono sempre piu veloci degli altri veicoli"},{en:"They are harder to see, can stop quickly, and their distance and speed are often misjudged",it:"Sono piu difficili da vedere, possono fermarsi rapidamente e la loro distanza e velocita vengono spesso valutate male"},{en:"They always have the right of way",it:"Hanno sempre la precedenza"},{en:"They create large blind spots for trucks",it:"Creano grandi punti ciechi per i camion"}],correct:1,explain_en:"Motorcycles are hard to see (small profile), stop quickly, and drivers often misjudge their speed and distance. Always check twice for motorcycles when turning or changing lanes.",explain_it:"Le moto sono difficili da vedere (profilo piccolo), si fermano rapidamente e i conducenti spesso valutano male la loro velocita e distanza. Controlla sempre due volte le moto quando svolti o cambi corsia."},
  {cat:"safety",en:"Why is 'following too closely' (tailgating) particularly dangerous at highway speeds?",it:"Perche 'seguire troppo da vicino' (tailgating) e particolarmente pericoloso alle velocita autostradali?",options:[{en:"It is rude but not particularly dangerous",it:"E maleducato ma non particolarmente pericoloso"},{en:"At 60 mph, perception and reaction time plus braking distance exceed the gap \u2014 making a crash unavoidable",it:"A 60 mph, il tempo di percezione e reazione piu la distanza di frenata superano il divario \u2014 rendendo inevitabile un incidente"},{en:"Only dangerous at speeds above 80 mph",it:"Pericoloso solo a velocita superiori a 80 mph"},{en:"The main risk is that the following driver gets a ticket",it:"Il rischio principale e che il conducente che segue riceva una multa"}],correct:1,explain_en:"At 60 mph: perception/reaction alone takes ~1.5 seconds (132 feet). Add braking distance. If you are tailgating, you CANNOT stop in time if the car ahead brakes.",explain_it:"A 60 mph: la sola percezione/reazione richiede ~1,5 secondi (40 m). Aggiungi la distanza di frenata. Se sei troppo vicino, NON puoi fermarti in tempo se l'auto davanti frena."},
  {cat:"safety",en:"What is the safest way to drive through a flooded road section?",it:"Qual e il modo piu sicuro di guidare attraverso una sezione di strada allagata?",options:[{en:"Drive fast through it to avoid water getting in the engine",it:"Guidare veloce per evitare che l'acqua entri nel motore"},{en:"Do not drive through \u2014 turn around and find alternate route",it:"Non guidare attraverso \u2014 gira indietro e trova un percorso alternativo"},{en:"Drive through in the center lane \u2014 it is usually the shallowest",it:"Guidare nel centro corsia \u2014 e di solito il piu basso"},{en:"Put the car in reverse gear when crossing flooded roads",it:"Mettere la marcia indietro quando si attraversano strade allagate"}],correct:1,explain_en:"Turn Around, Don't Drown. Just 6 inches of water can knock a person down; 12 inches can carry away a small vehicle; 2 feet can float most cars.",explain_it:"Gira indietro, non annegare. Solo 15 cm d'acqua possono abbattere una persona; 30 cm possono trascinare via un piccolo veicolo; 60 cm possono far galleggiare la maggior parte delle auto."},
  {cat:"safety",en:"What is the minimum tread depth before tires must be replaced?",it:"Qual e la profondita minima del battistrada prima che gli pneumatici debbano essere sostituiti?",options:[{en:"1/16 inch",it:"1/16 di pollice"},{en:"2/32 inch (1/16 inch)",it:"2/32 di pollice (1/16 di pollice)"},{en:"4/32 inch",it:"4/32 di pollice"},{en:"6/32 inch",it:"6/32 di pollice"}],correct:1,explain_en:"Tires must be replaced when tread depth reaches 2/32 inch (the top of Lincoln's head on a penny). Most experts recommend replacing at 4/32 for wet-weather safety.",explain_it:"Gli pneumatici devono essere sostituiti quando la profondita del battistrada raggiunge 2/32 di pollice. La maggior parte degli esperti raccomanda la sostituzione a 4/32 per la sicurezza sul bagnato."},
  {cat:"safety",en:"What does it mean to 'over-correct' when a vehicle starts to skid?",it:"Cosa significa 'correggere eccessivamente' quando un veicolo inizia a slittare?",options:[{en:"Applying too much brake pressure",it:"Applicare troppa pressione del freno"},{en:"Turning the steering wheel too sharply in the opposite direction, causing the vehicle to skid the other way",it:"Girare il volante troppo bruscamente nella direzione opposta, facendo slittare il veicolo nell'altra direzione"},{en:"Using the wrong gear when decelerating",it:"Usare la marcia sbagliata durante la decelerazione"},{en:"Applying full brake pressure when ABS is not available",it:"Applicare la piena pressione del freno quando l'ABS non e disponibile"}],correct:1,explain_en:"Over-correcting: turning the wheel too sharply causes a counter-skid in the opposite direction \u2014 sometimes more violent. Use small, smooth steering inputs to recover.",explain_it:"Correzione eccessiva: girare il volante troppo bruscamente causa uno slittamento nella direzione opposta \u2014 a volte piu violento. Usa piccoli input di sterzo fluidi per recuperare."},
  {cat:"safety",en:"When driving in heavy rain, what should you do to improve visibility?",it:"Quando si guida in forte pioggia, cosa dovresti fare per migliorare la visibilita?",options:[{en:"Use high beams for better illumination",it:"Usare gli abbaglianti per una migliore illuminazione"},{en:"Use low beams or fog lights, reduce speed, increase following distance, run wipers on max",it:"Usare i fari anabbaglianti o nebbia, ridurre la velocita, aumentare la distanza, far girare i tergicristalli al massimo"},{en:"Turn on hazard lights and drive normally",it:"Accendere le luci di pericolo e guidare normalmente"},{en:"No special adjustments needed in modern vehicles",it:"Nessuna regolazione speciale necessaria nei veicoli moderni"}],correct:1,explain_en:"In heavy rain: low beams (high beams reflect off rain), max wipers, reduce speed, increase following distance. If visibility is near zero \u2014 pull over.",explain_it:"In forte pioggia: fari anabbaglianti (gli abbaglianti riflettono sulla pioggia), tergicristalli al massimo, riduci la velocita, aumenta la distanza. Se la visibilita e quasi zero \u2014 accosta."},
  {cat:"safety",en:"What is a 'runaway truck ramp' (emergency escape ramp) used for?",it:"A cosa serve una 'rampa di fuga per camion' (rampa di fuga di emergenza)?",options:[{en:"A lane for trucks to park temporarily",it:"Una corsia per i camion per parcheggiare temporaneamente"},{en:"An uphill sand or gravel escape path for trucks with brake failure on steep grades",it:"Un percorso di fuga in salita di sabbia o ghiaia per i camion con guasto ai freni su pendenze ripide"},{en:"A weigh station bypass for trucks",it:"Un bypass della stazione di pesatura per i camion"},{en:"A mandatory rest area for truck drivers",it:"Un'area di riposo obbligatoria per i conducenti di camion"}],correct:1,explain_en:"Runaway truck ramps are uphill escape paths filled with sand or gravel that stop a truck whose brakes have failed on a long descent.",explain_it:"Le rampe di fuga sono percorsi in salita riempiti di sabbia o ghiaia che fermano un camion i cui freni hanno ceduto in una lunga discesa."},
  {cat:"alcohol",en:"What is the liver's rate of alcohol metabolism?",it:"Qual e la velocita di metabolizzazione dell'alcol da parte del fegato?",options:[{en:"Depends on how much you drink",it:"Dipende da quanto si beve"},{en:"Approximately one standard drink per hour \u2014 regardless of other factors",it:"Circa un drink standard all'ora \u2014 indipendentemente da altri fattori"},{en:"Two drinks per hour for large individuals",it:"Due drink all'ora per individui grandi"},{en:"Faster if you exercise after drinking",it:"Piu veloce se si fa esercizio dopo aver bevuto"}],correct:1,explain_en:"The liver metabolizes alcohol at approximately one standard drink (0.6 oz pure alcohol) per hour. Body size, food, water, and exercise do NOT speed this up.",explain_it:"Il fegato metabolizza l'alcol a circa un drink standard (0,6 once di alcol puro) all'ora. Corporatura, cibo, acqua ed esercizio NON accelerano questo processo."},
  {cat:"alcohol",en:"What is a 'standard drink' in the US?",it:"Cos'e un 'drink standard' negli USA?",options:[{en:"Any amount consumed in one sitting",it:"Qualsiasi quantita consumata in una seduta"},{en:"A drink containing approximately 0.6 oz (14 grams) of pure alcohol \u2014 one beer, 5 oz wine, or 1.5 oz spirits",it:"Un drink contenente circa 0,6 once (14 grammi) di alcol puro \u2014 una birra, 5 once di vino o 1,5 once di liquori"},{en:"Any alcoholic beverage served in a single glass",it:"Qualsiasi bevanda alcolica servita in un singolo bicchiere"},{en:"A 12 oz beer only",it:"Solo una birra da 12 once"}],correct:1,explain_en:"A standard drink = 0.6 oz pure alcohol: 12 oz regular beer (5%), 5 oz wine (12%), or 1.5 oz distilled spirits (40%). All contain the same amount of alcohol.",explain_it:"Un drink standard = 0,6 once di alcol puro: 12 once di birra normale (5%), 5 once di vino (12%), o 1,5 once di liquori (40%). Tutti contengono la stessa quantita di alcol."},
  {cat:"alcohol",en:"What factors affect how quickly a person reaches a given BAC?",it:"Quali fattori influenzano la velocita con cui una persona raggiunge un determinato BAC?",options:[{en:"Only the amount of alcohol consumed",it:"Solo la quantita di alcol consumata"},{en:"Body weight, gender, food intake, speed of drinking, and individual metabolism",it:"Peso corporeo, sesso, assunzione di cibo, velocita di assunzione e metabolismo individuale"},{en:"Only age and body weight",it:"Solo eta e peso corporeo"},{en:"BAC is the same for everyone after the same number of drinks",it:"Il BAC e lo stesso per tutti dopo lo stesso numero di drink"}],correct:1,explain_en:"BAC is affected by: number of drinks, rate of consumption, body weight, gender (women reach higher BAC faster), food intake, and individual metabolism.",explain_it:"Il BAC e influenzato da: numero di drink, tasso di consumo, peso corporeo, sesso (le donne raggiungono un BAC piu alto piu velocemente), assunzione di cibo e metabolismo individuale."},
  {cat:"alcohol",en:"Why does the same amount of alcohol typically produce a higher BAC in women than men?",it:"Perche la stessa quantita di alcol produce tipicamente un BAC piu alto nelle donne che negli uomini?",options:[{en:"Women have a faster liver metabolism",it:"Le donne hanno un metabolismo epatico piu veloce"},{en:"Women generally have a higher percentage of body fat and less water content, concentrating alcohol more",it:"Le donne hanno generalmente una percentuale piu alta di grasso corporeo e meno contenuto d'acqua, concentrando maggiormente l'alcol"},{en:"Women process alcohol differently due to hormones only",it:"Le donne elaborano l'alcol diversamente solo a causa degli ormoni"},{en:"There is no significant difference",it:"Non c'e una differenza significativa"}],correct:1,explain_en:"Women typically have more body fat (which doesn't absorb alcohol) and less body water than men of the same weight \u2014 resulting in higher BAC from the same intake.",explain_it:"Le donne hanno tipicamente piu grasso corporeo (che non assorbe l'alcol) e meno acqua corporea rispetto agli uomini dello stesso peso \u2014 con conseguente BAC piu alto dallo stesso consumo."},
  {cat:"alcohol",en:"What is 'binge drinking' and how does it relate to driving?",it:"Cos'e il 'binge drinking' e come si relaziona alla guida?",options:[{en:"Drinking any alcohol before driving",it:"Bere qualsiasi alcol prima di guidare"},{en:"Consuming 4+ drinks (women) or 5+ drinks (men) within about 2 hours \u2014 rapidly raising BAC to dangerous levels",it:"Consumare 4+ drink (donne) o 5+ drink (uomini) entro circa 2 ore \u2014 alzando rapidamente il BAC a livelli pericolosi"},{en:"Drinking alcohol every day",it:"Bere alcol ogni giorno"},{en:"Drinking hard liquor instead of beer",it:"Bere liquori forti invece della birra"}],correct:1,explain_en:"Binge drinking rapidly raises BAC to 0.08%+ and severely impairs driving. The liver cannot process alcohol fast enough, causing rapid intoxication.",explain_it:"Il binge drinking alza rapidamente il BAC a 0,08%+ e compromette gravemente la guida. Il fegato non riesce a elaborare l'alcol abbastanza velocemente, causando una rapida intossicazione."},
  {cat:"alcohol",en:"What does 'zero tolerance' mean for Florida drivers under 21?",it:"Cosa significa 'tolleranza zero' per i conducenti Florida under 21?",options:[{en:"No driving at night allowed",it:"Nessuna guida notturna consentita"},{en:"Any measurable BAC (.02%+) while driving is illegal \u2014 subject to license suspension",it:"Qualsiasi BAC misurabile (0,02%+) durante la guida e illegale \u2014 soggetto a sospensione della patente"},{en:"Under 21s may not purchase alcohol",it:"I minori di 21 anni non possono acquistare alcol"},{en:"No alcohol allowed at any time in vehicles",it:"Nessun alcol consentito in qualsiasi momento nei veicoli"}],correct:1,explain_en:"Florida's Zero Tolerance law: drivers under 21 with a BAC of 0.02% or higher (about one drink) face license suspension and other penalties.",explain_it:"La legge della Florida Tolleranza Zero: i conducenti under 21 con un BAC di 0,02% o superiore (circa un drink) affrontano la sospensione della patente e altre sanzioni."},
  {cat:"alcohol",en:"What is the minimum BAC at which a driver under 21 loses their license in Florida?",it:"Qual e il BAC minimo al quale un conducente under 21 perde la patente in Florida?",options:[{en:"0.05%",it:"0,05%"},{en:"0.02%",it:"0,02%"},{en:"0.08%",it:"0,08%"},{en:"Any detectable amount",it:"Qualsiasi quantita rilevabile"}],correct:1,explain_en:"Florida's zero tolerance: drivers under 21 face license suspension at 0.02% BAC \u2014 effectively 'any amount' of alcohol while driving.",explain_it:"Tolleranza zero Florida: i conducenti under 21 affrontano la sospensione della patente a 0,02% BAC \u2014 praticamente 'qualsiasi quantita' di alcol durante la guida."},
  {cat:"alcohol",en:"What is the role of the liver in alcohol processing?",it:"Qual e il ruolo del fegato nell'elaborazione dell'alcol?",options:[{en:"Filters alcohol directly into the kidneys",it:"Filtra l'alcol direttamente nei reni"},{en:"Breaks down alcohol using enzymes (primarily alcohol dehydrogenase) at a fixed rate",it:"Scompone l'alcol usando enzimi (principalmente alcol deidrogenasi) a una velocita fissa"},{en:"Stores alcohol until it can be excreted",it:"Immagazzina l'alcol finche non puo essere escreto"},{en:"Only processes alcohol when blood sugar is low",it:"Elabora l'alcol solo quando la glicemia e bassa"}],correct:1,explain_en:"The liver uses alcohol dehydrogenase to break down alcohol at a fixed rate (~one drink/hour). Excess alcohol circulates in the bloodstream causing impairment.",explain_it:"Il fegato usa l'alcol deidrogenasi per scomporre l'alcol a una velocita fissa (~un drink/ora). L'alcol in eccesso circola nel sangue causando compromissione."},
  {cat:"alcohol",en:"How is BAC measured in a breath test?",it:"Come viene misurato il BAC in un test del respiro?",options:[{en:"By counting molecules of alcohol in each breath",it:"Contando le molecole di alcol in ogni respiro"},{en:"Alcohol in the blood equilibrates with alcohol in deep lung air \u2014 breath alcohol concentration correlates with blood alcohol",it:"L'alcol nel sangue si equilibra con l'alcol nell'aria profonda dei polmoni \u2014 la concentrazione di alcol nel respiro correla con quella nel sangue"},{en:"Breath tests only detect alcohol in the stomach",it:"I test del respiro rilevano solo l'alcol nello stomaco"},{en:"The device detects alcohol in saliva, not breath",it:"Il dispositivo rileva l'alcol nella saliva, non nel respiro"}],correct:1,explain_en:"Breathalyzers measure deep-lung (alveolar) air alcohol, which is in equilibrium with blood alcohol. The result is converted to BAC using a partition ratio.",explain_it:"I breathalyzer misurano l'alcol nell'aria profonda dei polmoni (alveolare), che e in equilibrio con l'alcol nel sangue. Il risultato viene convertito in BAC usando un rapporto di partizione."},
  {cat:"alcohol",en:"What is a 'DUI checkpoint' (sobriety checkpoint) in Florida?",it:"Cos'e un 'checkpoint DUI' (posto di blocco di sobriety) in Florida?",options:[{en:"A random stop of all vehicles by police with no specific justification",it:"Un fermo casuale di tutti i veicoli dalla polizia senza giustificazione specifica"},{en:"A legally authorized roadblock where police check all passing drivers for signs of impairment",it:"Un posto di blocco legalmente autorizzato dove la polizia controlla tutti i conducenti di passaggio per segni di compromissione"},{en:"A private checkpoint operated by insurance companies",it:"Un posto di blocco privato gestito dalle compagnie assicurative"},{en:"Only used at major holidays",it:"Usato solo nei giorni festivi principali"}],correct:1,explain_en:"DUI checkpoints are legally authorized stops where all (or a systematic fraction) of drivers are briefly checked for impairment. Florida courts have upheld their constitutionality.",explain_it:"I checkpoint DUI sono fermi legalmente autorizzati dove tutti (o una frazione sistematica) dei conducenti vengono brevemente controllati per la compromissione."},
  {cat:"alcohol",en:"What is 'alcohol tolerance' and why is it dangerous for driving?",it:"Cos'e la 'tolleranza all'alcol' e perche e pericolosa per la guida?",options:[{en:"The legal alcohol limit",it:"Il limite legale di alcol"},{en:"When habitual drinkers need more alcohol to feel effects \u2014 but their driving is still equally impaired at any given BAC",it:"Quando i bevitori abituali hanno bisogno di piu alcol per sentire gli effetti \u2014 ma la loro guida e ancora ugualmente compromessa a qualsiasi BAC dato"},{en:"The ability to metabolize alcohol faster over time",it:"La capacita di metabolizzare l'alcol piu velocemente nel tempo"},{en:"A genetic resistance to alcohol intoxication",it:"Una resistenza genetica all'intossicazione da alcol"}],correct:1,explain_en:"Tolerance means feeling less drunk \u2014 but driving performance is equally impaired. Tolerant drinkers may drive at high BAC believing they are fine \u2014 a dangerous illusion.",explain_it:"La tolleranza significa sentirsi meno ubriachi \u2014 ma le prestazioni alla guida sono ugualmente compromesse. I bevitori tolleranti possono guidare ad alto BAC credendo di stare bene \u2014 un'illlusione pericolosa."},
  {cat:"alcohol",en:"What is the 'walk-and-turn' field sobriety test checking for?",it:"Cosa controlla il test di sobriety 'walk-and-turn'?",options:[{en:"Muscle strength in the legs",it:"Forza muscolare nelle gambe"},{en:"Divided attention \u2014 ability to follow instructions while performing a physical task simultaneously",it:"Attenzione divisa \u2014 capacita di seguire le istruzioni mentre si esegue contemporaneamente un compito fisico"},{en:"Blood pressure changes from walking",it:"Cambiamenti della pressione sanguigna durante la camminata"},{en:"Coordination of the upper body only",it:"Solo la coordinazione della parte superiore del corpo"}],correct:1,explain_en:"Walk-and-turn tests divided attention \u2014 a key driving skill. Impaired people have difficulty listening to instructions while also performing the physical walking task.",explain_it:"Il walk-and-turn testa l'attenzione divisa \u2014 un'abilita chiave alla guida. Le persone compromesse hanno difficolta ad ascoltare le istruzioni mentre eseguono contemporaneamente il compito fisico."},
  {cat:"alcohol",en:"What is the 'one-leg stand' field sobriety test measuring?",it:"Cosa misura il test di sobriety 'one-leg stand'?",options:[{en:"The strength of the non-dominant leg",it:"La forza della gamba non dominante"},{en:"Balance and divided attention \u2014 ability to maintain balance while counting aloud",it:"Equilibrio e attenzione divisa \u2014 capacita di mantenere l'equilibrio mentre si conta ad alta voce"},{en:"Reaction time when switching feet",it:"Tempo di reazione nel passare da un piede all'altro"},{en:"Ankle flexibility and coordination",it:"Flessibilita e coordinazione della caviglia"}],correct:1,explain_en:"One-leg stand measures balance and divided attention \u2014 standing on one foot while counting out loud for 30 seconds. Impaired individuals frequently sway, hop, or put foot down.",explain_it:"Il one-leg stand misura equilibrio e attenzione divisa \u2014 stare su un piede mentre si conta ad alta voce per 30 secondi. Le persone compromesse spesso oscillano, saltano o mettono gi\u00f9 il piede."},
  {cat:"alcohol",en:"What is the legal consequence of a third DUI conviction in Florida?",it:"Qual e la conseguenza legale di una terza condanna DUI in Florida?",options:[{en:"Same as a second conviction",it:"La stessa di una seconda condanna"},{en:"A third-degree felony with up to 5 years in prison and 10-year license revocation",it:"Un crimine di terzo grado con fino a 5 anni di prigione e revoca della patente di 10 anni"},{en:"Only an enhanced fine \u2014 no imprisonment",it:"Solo una multa maggiorata \u2014 nessuna reclusione"},{en:"Automatic permanent revocation with no reinstatement",it:"Revoca automatica permanente senza possibilita di ripristino"}],correct:1,explain_en:"Third DUI in Florida: third-degree felony, up to 5 years in prison, fines up to $5,000, and 10-year license revocation (mandatory if within 10 years of prior DUI).",explain_it:"Terzo DUI in Florida: crimine di terzo grado, fino a 5 anni di prigione, multe fino a $5.000 e revoca della patente di 10 anni (obbligatoria se entro 10 anni dal DUI precedente)."},
  {cat:"alcohol",en:"What does Florida law say about drinking alcohol while driving?",it:"Cosa dice la legge della Florida sul bere alcol durante la guida?",options:[{en:"Legal if BAC stays below 0.08%",it:"Legale se il BAC rimane sotto 0,08%"},{en:"Illegal \u2014 consuming alcohol while operating a vehicle is prohibited",it:"Illegale \u2014 consumare alcol durante la guida di un veicolo e vietato"},{en:"Legal for passengers \u2014 only the driver is prohibited",it:"Legale per i passeggeri \u2014 solo il conducente ha il divieto"},{en:"Only illegal if the container is open",it:"Illegale solo se il contenitore e aperto"}],correct:1,explain_en:"Consuming alcohol while operating a vehicle is illegal in Florida, regardless of the driver's BAC level.",explain_it:"Consumare alcol durante la guida di un veicolo e illegale in Florida, indipendentemente dal livello di BAC del conducente."},
  {cat:"alcohol",en:"What are the financial consequences of a first DUI conviction in Florida?",it:"Quali sono le conseguenze finanziarie di una prima condanna DUI in Florida?",options:[{en:"A $100 fine only",it:"Solo una multa di $100"},{en:"Fines of $500-$1,000 (higher with aggravating factors), plus court costs, insurance increases, and legal fees",it:"Multe di $500-$1.000 (piu alte con fattori aggravanti), piu costi giudiziari, aumenti assicurativi e spese legali"},{en:"Only an insurance surcharge \u2014 no fine",it:"Solo un supplemento assicurativo \u2014 nessuna multa"},{en:"A flat $2,500 fine with no other costs",it:"Una multa fissa di $2.500 senza altri costi"}],correct:1,explain_en:"First DUI total costs including fines, court fees, insurance increases, DUI school, ignition interlock, and legal fees often exceed $10,000-$15,000.",explain_it:"I costi totali del primo DUI inclusi multe, spese giudiziarie, aumenti assicurativi, scuola DUI, interlock e spese legali spesso superano $10.000-$15.000."},
  {cat:"alcohol",en:"What is the Florida law about alcohol in a vehicle's passenger compartment?",it:"Qual e la legge della Florida sull'alcol nell'abitacolo di un veicolo?",options:[{en:"Open containers are allowed in the trunk only",it:"I contenitori aperti sono consentiti solo nel bagagliaio"},{en:"Open alcoholic beverage containers are prohibited in the passenger area \u2014 sealed containers may be transported",it:"I contenitori di bevande alcoliche aperti sono vietati nell'area passeggeri \u2014 i contenitori sigillati possono essere trasportati"},{en:"Any amount of alcohol is allowed in the passenger compartment",it:"Qualsiasi quantita di alcol e consentita nell'abitacolo"},{en:"Only applies to the driver's area, not rear seats",it:"Si applica solo all'area del conducente, non ai sedili posteriori"}],correct:1,explain_en:"Florida prohibits open alcoholic beverage containers in the passenger compartment. Sealed, unopened containers may be transported. Open containers belong in the trunk.",explain_it:"La Florida vieta i contenitori di bevande alcoliche aperti nell'abitacolo. I contenitori sigillati e non aperti possono essere trasportati. I contenitori aperti appartengono al bagagliaio."},
  {cat:"alcohol",en:"What effect does alcohol have on a driver's risk-taking behavior?",it:"Che effetto ha l'alcol sul comportamento a rischio di un conducente?",options:[{en:"Makes drivers more cautious",it:"Rende i conducenti piu cauti"},{en:"Reduces inhibitions and increases risk-taking \u2014 leading to speeding, unsafe passing, and reckless decisions",it:"Riduce le inibizioni e aumenta la propensione al rischio \u2014 portando a eccesso di velocita, sorpassi pericolosi e decisioni sconsiderate"},{en:"Has no effect on risk-taking below 0.08%",it:"Non ha effetti sulla propensione al rischio sotto 0,08%"},{en:"Only affects risk-taking in combination with drugs",it:"Influisce sulla propensione al rischio solo in combinazione con le droghe"}],correct:1,explain_en:"Alcohol reduces inhibitions and impairs judgment \u2014 causing drivers to take risks they would not take sober, including speeding, aggressive passing, and tailgating.",explain_it:"L'alcol riduce le inibizioni e compromette il giudizio \u2014 facendo si che i conducenti si prendano rischi che non si prenderebbero sobri, inclusi eccesso di velocita e sorpassi aggressivi."},
  {cat:"alcohol",en:"What is the term for when a person drives impaired but believes they are driving well?",it:"Qual e il termine per quando una persona guida compromessa ma crede di guidare bene?",options:[{en:"Competence illusion",it:"Illusione di competenza"},{en:"Alcohol myopia \u2014 the narrowing of attention and overconfidence caused by alcohol",it:"Miopia da alcol \u2014 il restringimento dell'attenzione e la fiducia eccessiva causati dall'alcol"},{en:"Selective amnesia",it:"Amnesia selettiva"},{en:"False sobriety syndrome",it:"Sindrome di sobriety falsa"}],correct:1,explain_en:"Alcohol myopia: alcohol narrows attention and creates overconfidence. Impaired drivers often believe they are driving fine \u2014 one of the most dangerous effects of drinking.",explain_it:"Miopia da alcol: l'alcol restringe l'attenzione e crea fiducia eccessiva. I conducenti compromessi spesso credono di guidare bene \u2014 uno degli effetti piu pericolosi dell'alcol."},
  {cat:"alcohol",en:"What happens to a commercial driver's CDL if convicted of DUI while operating a personal vehicle?",it:"Cosa succede al CDL di un conducente commerciale se condannato per DUI durante la guida di un veicolo personale?",options:[{en:"Nothing \u2014 personal vehicle DUI does not affect a CDL",it:"Niente \u2014 il DUI con veicolo personale non influisce su un CDL"},{en:"CDL is disqualified for at least 1 year \u2014 a second DUI results in lifetime disqualification",it:"Il CDL e squalificato per almeno 1 anno \u2014 un secondo DUI comporta la squalifica permanente"},{en:"Only affected if BAC was above 0.08%",it:"Colpito solo se il BAC era superiore a 0,08%"},{en:"CDL is suspended for 90 days only",it:"Il CDL e sospeso solo per 90 giorni"}],correct:1,explain_en:"A DUI conviction \u2014 even in a personal vehicle \u2014 results in a minimum 1-year CDL disqualification. A second DUI = lifetime CDL disqualification.",explain_it:"Una condanna DUI \u2014 anche in un veicolo personale \u2014 comporta una squalifica minima del CDL di 1 anno. Un secondo DUI = squalifica permanente del CDL."},
  {cat:"alcohol",en:"What is an 'ignition interlock device (IID)' and when is it required in Florida?",it:"Cos'e un 'dispositivo interlock per l'accensione (IID)' e quando e richiesto in Florida?",options:[{en:"A GPS tracker installed after DUI conviction",it:"Un localizzatore GPS installato dopo la condanna DUI"},{en:"A breathalyzer connected to the ignition \u2014 car won't start if BAC is above threshold; required after certain DUI convictions",it:"Un breathalyzer collegato al motore \u2014 l'auto non si avvia se il BAC supera la soglia; richiesto dopo certe condanne DUI"},{en:"An anti-theft device mandated by insurance",it:"Un dispositivo antifurto richiesto dall'assicurazione"},{en:"A camera that records driving behavior",it:"Una telecamera che registra il comportamento alla guida"}],correct:1,explain_en:"IID is a car breathalyzer \u2014 if your breath sample shows BAC above the threshold (~0.025%), the car won't start. Required after DUI with BAC 0.15%+, with minors, or for repeat DUI.",explain_it:"L'IID e un breathalyzer per auto \u2014 se il campione di respiro mostra un BAC sopra la soglia (~0,025%), l'auto non si avvia. Richiesto dopo DUI con BAC 0,15%+, con minori o per DUI ripetuti."},
  {cat:"alcohol",en:"What is 'DUI per se' in Florida law?",it:"Cos'e il 'DUI per se' nella legge Florida?",options:[{en:"DUI charged only with observed impairment",it:"DUI accusato solo con compromissione osservata"},{en:"Driving with a BAC of 0.08% or higher is illegal regardless of whether the driver appears impaired",it:"Guidare con un BAC di 0,08% o superiore e illegale indipendentemente dal fatto che il conducente sembri compromesso"},{en:"DUI causing injury or death",it:"DUI che causa lesioni o morte"},{en:"A DUI occurring on a private road",it:"Un DUI che si verifica su una strada privata"}],correct:1,explain_en:"DUI per se: a BAC of 0.08%+ makes the driver legally intoxicated regardless of how they appear or feel. No additional proof of impairment is required.",explain_it:"DUI per se: un BAC di 0,08%+ rende il conducente legalmente intossicato indipendentemente da come appare o si sente. Non e richiesta prova aggiuntiva di compromissione."},
  {cat:"alcohol",en:"What is the effect of alcohol on night vision?",it:"Qual e l'effetto dell'alcol sulla visione notturna?",options:[{en:"Alcohol improves night vision at moderate BAC",it:"L'alcol migliora la visione notturna a BAC moderato"},{en:"Alcohol impairs night vision \u2014 reduces ability to adapt to darkness and recover from glare",it:"L'alcol compromette la visione notturna \u2014 riduce la capacita di adattarsi all'oscurita e riprendersi dall'abbagliamento"},{en:"Night vision is not affected by alcohol",it:"La visione notturna non e influenzata dall'alcol"},{en:"Only high BAC (above 0.15%) affects night vision",it:"Solo un BAC alto (sopra 0,15%) influisce sulla visione notturna"}],correct:1,explain_en:"Alcohol impairs night vision even at low BAC: reduces the ability to adapt to darkness, recover from headlight glare, and see in low contrast conditions.",explain_it:"L'alcol compromette la visione notturna anche a basso BAC: riduce la capacita di adattarsi all'oscurita, riprendersi dall'abbagliamento dei fari e vedere in condizioni di basso contrasto."},
  {cat:"alcohol",en:"What does it mean for DUI sentencing if a defendant is 'adjudicated guilty' vs. 'withhold of adjudication'?",it:"Cosa significa per la sentenza DUI se un imputato e 'giudicato colpevole' vs. 'sospensione del giudizio'?",options:[{en:"There is no legal difference between the two",it:"Non c'e differenza legale tra i due"},{en:"Adjudicated guilty = formal conviction on record; withhold = no formal conviction (but DUI priors still count for enhancement purposes)",it:"Giudicato colpevole = condanna formale nel casellario; sospensione = nessuna condanna formale (ma i DUI precedenti contano ancora per le maggiorazioni)"},{en:"Withhold is only for juvenile DUI",it:"La sospensione e solo per il DUI giovanile"},{en:"With adjudication, no license suspension occurs",it:"Con il giudizio, non si verifica nessuna sospensione della patente"}],correct:1,explain_en:"For DUI in Florida: withhold of adjudication is NOT available. Conviction is mandatory. Unlike other offenses, a DUI conviction cannot be withheld or expunged.",explain_it:"Per il DUI in Florida: la sospensione del giudizio NON e disponibile. La condanna e obbligatoria. A differenza di altri reati, una condanna DUI non puo essere sospesa o cancellata."},
  {cat:"alcohol",en:"Can a Florida DUI conviction ever be expunged from a criminal record?",it:"Puo una condanna DUI in Florida essere cancellata da un casellario penale?",options:[{en:"Yes \u2014 after 5 years with no further offenses",it:"Si \u2014 dopo 5 anni senza ulteriori reati"},{en:"No \u2014 DUI convictions in Florida cannot be expunged or sealed",it:"No \u2014 le condanne DUI in Florida non possono essere cancellate o sigillate"},{en:"Yes \u2014 if it was a first offense with no accident",it:"Si \u2014 se era una prima offesa senza incidente"},{en:"Yes \u2014 only if community service was completed",it:"Si \u2014 solo se il servizio alla comunit\u00e0 e stato completato"}],correct:1,explain_en:"Florida DUI convictions cannot be expunged or sealed. They remain permanently on your criminal and driving record.",explain_it:"Le condanne DUI in Florida non possono essere cancellate o sigillate. Rimangono permanentemente nel casellario penale e di guida."},
  {cat:"alcohol",en:"What is the effect of mixing alcohol with energy drinks?",it:"Qual e l'effetto della miscela di alcol con bevande energetiche?",options:[{en:"Energy drinks neutralize the effects of alcohol",it:"Le bevande energetiche neutralizzano gli effetti dell'alcol"},{en:"Caffeine masks feelings of sedation but does NOT reduce BAC or impairment \u2014 creating a 'wide awake drunk'",it:"La caffeina maschera le sensazioni di sedazione ma NON riduce il BAC o la compromissione \u2014 creando un 'ubriaco sveglio'"},{en:"Mixing reduces how quickly alcohol is absorbed",it:"La miscela riduce la velocita di assorbimento dell'alcol"},{en:"Energy drinks have no effect on alcohol",it:"Le bevande energetiche non hanno effetti sull'alcol"}],correct:1,explain_en:"Caffeine in energy drinks masks the sedating effects of alcohol but does NOT reduce impairment. Users feel more awake but are equally impaired \u2014 making them more likely to drive.",explain_it:"La caffeina nelle bevande energetiche maschera gli effetti sedativi dell'alcol ma NON riduce la compromissione. Gli utenti si sentono piu svegli ma sono ugualmente compromessi."},
  {cat:"alcohol",en:"What is 'vehicular manslaughter' vs. 'DUI manslaughter' in Florida?",it:"Cos'e il 'omicidio colposo del veicolo' vs. 'omicidio colposo DUI' in Florida?",options:[{en:"They are the same offense",it:"Sono lo stesso reato"},{en:"DUI manslaughter requires alcohol/drug impairment; vehicular homicide requires reckless driving causing death without necessarily being impaired",it:"L'omicidio colposo DUI richiede la compromissione da alcol/droghe; l'omicidio con veicolo richiede guida spericolata che causa morte senza necessariamente essere compromesso"},{en:"Only DUI manslaughter is a criminal offense",it:"Solo l'omicidio colposo DUI e un reato penale"},{en:"Vehicular manslaughter applies only to pedestrian fatalities",it:"L'omicidio con veicolo si applica solo alle vittime pedonali"}],correct:1,explain_en:"DUI manslaughter: death caused while driving under the influence (2nd-degree felony). Vehicular homicide: death caused by reckless driving without necessarily being impaired.",explain_it:"Omicidio colposo DUI: morte causata durante la guida sotto l'influenza (crimine di 2\u00b0 grado). Omicidio con veicolo: morte causata da guida spericolata senza necessariamente essere compromessi."},
  {cat:"alcohol",en:"What is Florida's law on prescription drugs that cause drowsiness and driving?",it:"Qual e la legge della Florida sui farmaci da prescrizione che causano sonnolenza e la guida?",options:[{en:"Legal to drive if a doctor prescribed the medication",it:"Legale guidare se un medico ha prescritto il farmaco"},{en:"Illegal to drive if the medication impairs normal faculties \u2014 regardless of prescription status",it:"Illegale guidare se il farmaco compromette le facolt\u00e0 normali \u2014 indipendentemente dallo stato di prescrizione"},{en:"Only illegal for CDL holders",it:"Illegale solo per i titolari CDL"},{en:"Legal if the dosage is as prescribed",it:"Legale se il dosaggio e come prescritto"}],correct:1,explain_en:"Florida DUI law applies to any substance impairing normal faculties \u2014 including legal prescription drugs. A valid prescription is NOT a defense to DUI.",explain_it:"La legge DUI della Florida si applica a qualsiasi sostanza che compromette le facolt\u00e0 normali \u2014 inclusi i farmaci da prescrizione legali. Una prescrizione valida NON e una difesa al DUI."},
  {cat:"alcohol",en:"What is the legal definition of 'under the influence' in Florida DUI law?",it:"Qual e la definizione legale di 'sotto l'influenza' nella legge DUI della Florida?",options:[{en:"Having any detectable amount of alcohol in the bloodstream",it:"Avere qualsiasi quantita rilevabile di alcol nel sangue"},{en:"Normal faculties are impaired by alcohol or a controlled substance to the extent that the person is less able to drive safely",it:"Le facolta normali sono compromesse da alcol o una sostanza controllata al punto che la persona e meno in grado di guidare in sicurezza"},{en:"Being visibly drunk or intoxicated",it:"Essere visibilmente ubriaco o intossicato"},{en:"Having a BAC at or above 0.08%",it:"Avere un BAC pari o superiore a 0,08%"}],correct:1,explain_en:"'Under the influence' means normal faculties are impaired to the extent the driver is less capable than a sober person. This standard can apply even below 0.08% BAC.",explain_it:"'Sotto l'influenza' significa che le facolta normali sono compromesse al punto che il conducente e meno capace di una persona sobria. Questo standard puo applicarsi anche sotto 0,08% BAC."},
  {cat:"alcohol",en:"What is the purpose of Florida's DUI vehicle impoundment?",it:"Qual e lo scopo del sequestro del veicolo DUI della Florida?",options:[{en:"To punish the driver financially",it:"Per punire il conducente finanziariamente"},{en:"To prevent the impaired driver from continuing to operate the vehicle immediately after arrest",it:"Per impedire al conducente compromesso di continuare a guidare il veicolo immediatamente dopo l'arresto"},{en:"For evidence collection only",it:"Solo per la raccolta delle prove"},{en:"It is optional and rarely used",it:"E opzionale e raramente usato"}],correct:1,explain_en:"Vehicle impoundment after DUI arrest prevents the impaired driver from retrieving the vehicle and driving again. For a first DUI: 10-day impoundment; second: 30 days; third: 90 days.",explain_it:"Il sequestro del veicolo dopo l'arresto DUI impedisce al conducente compromesso di recuperare il veicolo e guidare di nuovo. Primo DUI: 10 giorni; secondo: 30 giorni; terzo: 90 giorni."},
  {cat:"alcohol",en:"Under Florida law, what must happen if a person refuses a BAC test for the second time?",it:"Ai sensi della legge Florida, cosa deve accadere se una persona rifiuta un test BAC per la seconda volta?",options:[{en:"No additional consequence \u2014 refusal is always the driver's right",it:"Nessuna conseguenza aggiuntiva \u2014 il rifiuto e sempre il diritto del conducente"},{en:"18-month license suspension AND can be charged with a first-degree misdemeanor",it:"Sospensione della patente di 18 mesi E puo essere accusato di un'infrazione minore di primo grado"},{en:"Only a 6-month suspension",it:"Solo una sospensione di 6 mesi"},{en:"The same consequence as the first refusal",it:"La stessa conseguenza del primo rifiuto"}],correct:1,explain_en:"Second BAC test refusal in Florida: 18-month license suspension AND a first-degree misdemeanor criminal charge for the refusal itself.",explain_it:"Secondo rifiuto del test BAC in Florida: sospensione della patente di 18 mesi E un'accusa penale per infrazione minore di primo grado per il rifiuto stesso."},
  {cat:"alcohol",en:"What is the effect of alcohol on driving at low speeds vs. highway speeds?",it:"Qual e l'effetto dell'alcol sulla guida a basse velocita vs. velocita autostradali?",options:[{en:"Alcohol is only dangerous at highway speeds",it:"L'alcol e pericoloso solo alle velocita autostradali"},{en:"Alcohol impairs driving at ALL speeds \u2014 even low-speed maneuvers require judgment, coordination, and reaction time",it:"L'alcol compromette la guida a TUTTE le velocita \u2014 anche le manovre a bassa velocita richiedono giudizio, coordinazione e tempo di reazione"},{en:"Low-speed driving is safe even at 0.15% BAC",it:"La guida a bassa velocita e sicura anche a 0,15% BAC"},{en:"Only reaction time is affected at low speeds",it:"Solo il tempo di reazione e influenzato a basse velocita"}],correct:1,explain_en:"Alcohol impairs driving at ALL speeds. Even parking, backing, and low-speed turns require coordination, judgment, and spatial awareness \u2014 all impaired by alcohol.",explain_it:"L'alcol compromette la guida a TUTTE le velocita. Anche il parcheggio, la retromarcia e le curve a bassa velocita richiedono coordinazione, giudizio e consapevolezza spaziale."},
  {cat:"alcohol",en:"What is the Florida law on alcohol consumption by boat operators?",it:"Qual e la legge della Florida sul consumo di alcol da parte degli operatori di barche?",options:[{en:"Boating has no alcohol restrictions",it:"La navigazione non ha restrizioni sull'alcol"},{en:"BUI (Boating Under the Influence) uses the same 0.08% BAC standard as driving \u2014 and carries similar penalties",it:"BUI (Boating Under the Influence) usa lo stesso standard BAC di 0,08% della guida \u2014 e comporta sanzioni simili"},{en:"Boat operators may drink as long as they are not visibly drunk",it:"Gli operatori di barche possono bere purche non siano visibilmente ubriachi"},{en:"Only fishing boats are subject to BUI laws",it:"Solo le barche da pesca sono soggette alle leggi BUI"}],correct:1,explain_en:"Florida's BUI law mirrors DUI: 0.08% BAC limit, implied consent, similar penalties. Boating and alcohol are a dangerous combination \u2014 over half of boating fatalities involve alcohol.",explain_it:"La legge BUI della Florida rispecchia il DUI: limite BAC di 0,08%, consenso implicito, sanzioni simili. Navigare e alcol sono una combinazione pericolosa."},
  {cat:"alcohol",en:"What is the 'responsible server' law concept in Florida?",it:"Cos'e il concetto di legge sul 'servizio responsabile' in Florida?",options:[{en:"A law requiring all restaurant staff to be trained in food safety",it:"Una legge che richiede a tutto il personale dei ristoranti di essere formato sulla sicurezza alimentare"},{en:"Dram shop liability \u2014 licensed establishments may be liable for damages if they serve alcohol to a visibly intoxicated person who then causes a DUI crash",it:"Responsabilita del dram shop \u2014 i locali con licenza possono essere responsabili per i danni se servono alcol a una persona visibilmente intossicata che poi causa un incidente DUI"},{en:"A requirement for bartenders to call taxis for drunk patrons",it:"Un requisito per i baristi di chiamare taxi per i clienti ubriachi"},{en:"Florida has no dram shop liability",it:"La Florida non ha responsabilita del dram shop"}],correct:1,explain_en:"Florida's dram shop law: licensed alcohol vendors may face civil liability if they knowingly serve visibly intoxicated individuals who subsequently cause injury or death.",explain_it:"La legge del dram shop della Florida: i venditori di alcol con licenza possono affrontare responsabilita civile se servono consapevolmente individui visibilmente intossicati che successivamente causano lesioni o morte."},
  {cat:"alcohol",en:"What is the most effective way to prevent drunk driving?",it:"Qual e il modo piu efficace per prevenire la guida in stato di ebbrezza?",options:[{en:"Never drink more than 2 beers",it:"Non bere mai piu di 2 birre"},{en:"Plan ahead \u2014 designate a sober driver, use rideshare, or arrange other transportation before drinking",it:"Pianifica in anticipo \u2014 designa un conducente sobrio, usa un rideshare o organizza altri trasporti prima di bere"},{en:"Drink coffee before driving to sober up",it:"Bere caffe prima di guidare per smaltire l'alcol"},{en:"Only drive short distances when slightly impaired",it:"Guidare solo brevi distanze quando leggermente compromesso"}],correct:1,explain_en:"Planning ahead is the key: designate a sober driver before the event, use Uber/Lyft, take a taxi, or arrange to stay overnight. Never plan to 'drive a little' after drinking.",explain_it:"Pianificare in anticipo e la chiave: designa un conducente sobrio prima dell'evento, usa Uber/Lyft, prendi un taxi o organizza di rimanere a dormire."},
  {cat:"alcohol",en:"What is the difference between Florida's administrative license suspension and the criminal DUI suspension?",it:"Qual e la differenza tra la sospensione amministrativa della patente della Florida e la sospensione penale DUI?",options:[{en:"They are the same process",it:"Sono lo stesso processo"},{en:"Administrative suspension is immediate upon arrest (by FLHSMV); criminal suspension follows conviction in court \u2014 both may run concurrently",it:"La sospensione amministrativa e immediata all'arresto (dal FLHSMV); quella penale segue la condanna in tribunale \u2014 entrambe possono essere concorrenti"},{en:"Administrative suspension is optional",it:"La sospensione amministrativa e opzionale"},{en:"Only one suspension can apply \u2014 not both",it:"Solo una sospensione puo applicarsi \u2014 non entrambe"}],correct:1,explain_en:"Administrative suspension (by FLHSMV): immediate upon failing/refusing BAC test. Criminal suspension: ordered by court at conviction. Both can occur and sometimes overlap.",explain_it:"Sospensione amministrativa (dal FLHSMV): immediata al fallimento/rifiuto del test BAC. Sospensione penale: ordinata dal tribunale alla condanna. Entrambe possono verificarsi e talvolta si sovrappongono."},
  {cat:"alcohol",en:"What happens to your Florida driver's license if you fail a BAC test (0.08%+) at a DUI stop?",it:"Cosa succede alla tua patente Florida se fallisci un test BAC (0,08%+) a un fermo DUI?",options:[{en:"Nothing until you are convicted in court",it:"Niente fino alla condanna in tribunale"},{en:"FLHSMV automatically suspends it for 6 months (first offense) \u2014 independent of any criminal proceedings",it:"Il FLHSMV la sospende automaticamente per 6 mesi (prima offesa) \u2014 indipendente da qualsiasi procedimento penale"},{en:"License is suspended only if you are convicted",it:"La patente e sospesa solo se sei condannato"},{en:"License is immediately confiscated and destroyed",it:"La patente viene immediatamente confiscata e distrutta"}],correct:1,explain_en:"Failing a BAC test triggers an automatic administrative suspension by FLHSMV: 6 months for a first offense (regardless of criminal outcome). You receive the 10-Day Letter.",explain_it:"Il fallimento di un test BAC scatena una sospensione amministrativa automatica dal FLHSMV: 6 mesi per una prima offesa (indipendente dall'esito penale). Ricevi la Lettera dei 10 Giorni."},
  {cat:"alcohol",en:"What is the minimum jail time for a first DUI conviction in Florida?",it:"Qual e il tempo minimo di carcere per una prima condanna DUI in Florida?",options:[{en:"No mandatory minimum jail time",it:"Nessun tempo minimo obbligatorio di carcere"},{en:"24 hours minimum",it:"Minimo 24 ore"},{en:"48 hours minimum",it:"Minimo 48 ore"},{en:"10 days mandatory",it:"10 giorni obbligatori"}],correct:0,explain_en:"There is no mandatory minimum jail time for a first DUI in Florida (unless enhanced circumstances exist). The court may sentence up to 6 months in jail, but it is not mandatory.",explain_it:"Non c'e un tempo minimo obbligatorio di carcere per un primo DUI in Florida (a meno che non esistano circostanze aggravate). Il tribunale puo condannare fino a 6 mesi di carcere, ma non e obbligatorio."},
  {cat:"alcohol",en:"What percentage of fatal traffic crashes in the US involve alcohol-impaired driving?",it:"Quale percentuale degli incidenti stradali mortali negli USA coinvolge la guida con compromissione da alcol?",options:[{en:"About 10%",it:"Circa il 10%"},{en:"About 30%",it:"Circa il 30%"},{en:"About 50%",it:"Circa il 50%"},{en:"About 70%",it:"Circa il 70%"}],correct:1,explain_en:"Approximately 30% of all traffic fatalities in the US involve a driver with BAC 0.08%+. Alcohol-impaired driving kills about 10,000 people per year.",explain_it:"Circa il 30% di tutti i decessi stradali negli USA coinvolge un conducente con BAC 0,08%+. La guida con compromissione da alcol uccide circa 10.000 persone all'anno."},
  {cat:"alcohol",en:"What is 'blackout drinking' and why is it especially dangerous for drivers?",it:"Cos'e il 'bere fino al blackout' e perche e particolarmente pericoloso per i conducenti?",options:[{en:"Drinking coffee at night to stay awake while driving",it:"Bere caffe di notte per rimanere svegli durante la guida"},{en:"Alcohol-induced amnesia where the drinker has no memory of events \u2014 may drive without realizing they are impaired",it:"Amnesia indotta dall'alcol dove il bevitore non ha memoria degli eventi \u2014 puo guidare senza rendersi conto di essere compromesso"},{en:"Blacking out the car windows to sleep",it:"Oscurare i finestrini dell'auto per dormire"},{en:"A blackout occurs only at BAC above 0.20%",it:"Un blackout si verifica solo con BAC superiore a 0,20%"}],correct:1,explain_en:"Alcohol-induced blackout: the person is awake and seemingly functioning but forming no new memories. They may drive, make decisions, and appear somewhat normal while being severely impaired.",explain_it:"Blackout indotto dall'alcol: la persona e sveglia e apparentemente funzionale ma non forma nuovi ricordi. Possono guidare, prendere decisioni e sembrare normali mentre sono gravemente compromessi."},
  {cat:"alcohol",en:"What is the required action if a Florida driver is stopped at a DUI sobriety checkpoint?",it:"Qual e l'azione richiesta se un conducente Florida e fermato a un checkpoint di sobriety DUI?",options:[{en:"You may legally turn around before reaching the checkpoint",it:"Puoi legalmente girare prima di raggiungere il checkpoint"},{en:"Comply with the officer \u2014 provide license, registration, insurance; answer basic questions; submit to testing if arrested",it:"Conformarsi all'agente \u2014 fornire patente, registrazione, assicurazione; rispondere alle domande di base; sottoporsi ai test se arrestato"},{en:"You have the right to refuse all interaction",it:"Hai il diritto di rifiutare qualsiasi interazione"},{en:"You may only be stopped if the officer has probable cause",it:"Puoi essere fermato solo se l'agente ha una causa probabile"}],correct:1,explain_en:"At a checkpoint: provide documents, answer basic questions. You are not required to perform field sobriety tests unless arrested, but implied consent applies if arrested.",explain_it:"A un checkpoint: fornisci i documenti, rispondi alle domande di base. Non sei obbligato a eseguire i test di sobriety a meno che non sei arrestato, ma il consenso implicito si applica se arrestato."},
  {cat:"alcohol",en:"What is the impact of DUI on a professional license in Florida (e.g., medical, legal, nursing)?",it:"Qual e l'impatto del DUI su una licenza professionale in Florida (p.es. medica, legale, infermieristica)?",options:[{en:"No impact \u2014 DUI is a traffic matter only",it:"Nessun impatto \u2014 il DUI e solo una questione di traffico"},{en:"Professional licensing boards may suspend or revoke professional licenses based on DUI conviction",it:"I consigli di licenza professionali possono sospendere o revocare le licenze professionali sulla base di una condanna DUI"},{en:"Only affects CDL holders",it:"Influisce solo sui titolari CDL"},{en:"Impact only occurs after a second DUI",it:"L'impatto si verifica solo dopo un secondo DUI"}],correct:1,explain_en:"A DUI conviction can trigger review by professional licensing boards (medical, legal, nursing, teaching, etc.) and may result in suspension or revocation of professional licenses.",explain_it:"Una condanna DUI puo innescare una revisione da parte dei consigli di licenza professionali (medici, legali, infermieristici, ecc.) e puo comportare la sospensione o revoca delle licenze professionali."},
  {cat:"alcohol",en:"What is the most common time period for DUI arrests in Florida?",it:"Qual e il periodo di tempo piu comune per gli arresti DUI in Florida?",options:[{en:"During morning rush hours",it:"Durante le ore di punta mattutine"},{en:"Late night and early morning hours \u2014 especially weekends",it:"Ore serali e del mattino presto \u2014 specialmente nei weekend"},{en:"During afternoon school dismissal",it:"Durante il fine delle lezioni pomeridiane"},{en:"During major sporting events only",it:"Solo durante i principali eventi sportivi"}],correct:1,explain_en:"Most DUI arrests occur between midnight and 3 AM, particularly on Friday and Saturday nights. Alcohol-related crashes peak during these hours.",explain_it:"La maggior parte degli arresti DUI avviene tra mezzanotte e le 3:00, particolarmente nelle notti di venerdi e sabato. Gli incidenti legati all'alcol raggiungono il picco in queste ore."},
  {cat:"license",en:"What is a 'Real ID' compliant Florida driver's license?",it:"Cos'e una patente di guida Florida conforme al 'Real ID'?",options:[{en:"A license with a gold star symbol meeting federal identification standards",it:"Una patente con un simbolo stella dorata che soddisfa gli standard federali di identificazione"},{en:"A standard Florida license",it:"Una patente Florida standard"},{en:"Only available to US citizens",it:"Disponibile solo ai cittadini USA"},{en:"Required for all international travel",it:"Richiesta per tutti i viaggi internazionali"}],correct:0,explain_en:"A Real ID compliant Florida license has a gold star. It meets federal standards and is required for domestic flights and accessing federal buildings starting May 2025.",explain_it:"Una patente Florida conforme al Real ID ha una stella dorata. Soddisfa gli standard federali ed e richiesta per i voli nazionali e l'accesso agli edifici federali a partire da maggio 2025."},
  {cat:"license",en:"What is the difference between a driver's license 'suspension' and 'revocation' in Florida?",it:"Qual e la differenza tra 'sospensione' e 'revoca' di una patente in Florida?",options:[{en:"They are the same thing",it:"Sono la stessa cosa"},{en:"Suspension is temporary \u2014 driving privileges may be restored after the period; revocation permanently ends the license",it:"La sospensione e temporanea \u2014 i privilegi di guida possono essere ripristinati dopo il periodo; la revoca termina permanentemente la patente"},{en:"Revocation is temporary; suspension is permanent",it:"La revoca e temporanea; la sospensione e permanente"},{en:"Suspension is for traffic violations; revocation is for criminal offenses only",it:"La sospensione e per le violazioni del traffico; la revoca e solo per i reati penali"}],correct:1,explain_en:"Suspension: temporary loss of driving privileges \u2014 can be reinstated after the period and requirements are met. Revocation: the license is cancelled \u2014 must reapply and requalify.",explain_it:"Sospensione: perdita temporanea dei privilegi di guida \u2014 puo essere ripristinata dopo il periodo e il soddisfacimento dei requisiti. Revoca: la patente viene cancellata \u2014 devi richiedere e riqualificarti."},
  {cat:"license",en:"What is Florida's 'habitual traffic offender' revocation period?",it:"Qual e il periodo di revoca per il 'trasgressore abituale del traffico' in Florida?",options:[{en:"1 year",it:"1 anno"},{en:"5 years",it:"5 anni"},{en:"10 years",it:"10 anni"},{en:"Permanent",it:"Permanente"}],correct:1,explain_en:"A habitual traffic offender faces a mandatory 5-year license revocation. Reinstatement requires a hardship hearing and meeting all FLHSMV requirements.",explain_it:"Un trasgressore abituale del traffico affronta una revoca obbligatoria della patente di 5 anni. Il ripristino richiede un'udienza per necessita e il soddisfacimento di tutti i requisiti FLHSMV."},
  {cat:"license",en:"What is a 'Business Purposes Only' (BPO) license in Florida?",it:"Cos'e una patente 'Solo per Scopi Lavorativi' (BPO) in Florida?",options:[{en:"A license for commercial vehicle operators only",it:"Una patente solo per gli operatori di veicoli commerciali"},{en:"A restricted license allowing driving only to/from work, school, church, and medical appointments during suspension",it:"Una patente con restrizioni che consente di guidare solo da/verso il lavoro, scuola, chiesa e appuntamenti medici durante la sospensione"},{en:"A license issued to self-employed individuals",it:"Una patente rilasciata agli individui autonomi"},{en:"A temporary license while waiting for a new one to be issued",it:"Una patente temporanea mentre si aspetta l'emissione di una nuova"}],correct:1,explain_en:"BPO (Business Purposes Only) and EPO (Employment Purposes Only) are restricted hardship licenses allowing limited driving during a suspension for essential purposes.",explain_it:"BPO (Solo per Scopi Lavorativi) ed EPO (Solo per Scopi di Impiego) sono patenti con restrizioni per necessita che consentono una guida limitata durante una sospensione per scopi essenziali."},
  {cat:"license",en:"What is Florida's law on the use of a driver's license as identification?",it:"Qual e la legge della Florida sull'uso della patente di guida come documento di identita?",options:[{en:"A driver's license can only be used while in a vehicle",it:"Una patente puo essere usata solo mentre si e in un veicolo"},{en:"A Florida driver's license is valid government-issued ID for most purposes \u2014 including age verification",it:"Una patente Florida e un documento d'identita governativo valido per la maggior parte degli scopi \u2014 inclusa la verifica dell'eta"},{en:"Driver's licenses are not accepted as ID for official federal purposes",it:"Le patenti non sono accettate come documento d'identita per scopi federali ufficiali"},{en:"Only a passport serves as valid ID in Florida",it:"Solo un passaporto serve come documento d'identita valido in Florida"}],correct:1,explain_en:"A Florida driver's license (especially Real ID compliant) serves as valid government ID for most purposes including boarding domestic flights and entering federal facilities.",explain_it:"Una patente Florida (specialmente conforme al Real ID) serve come documento d'identita governativo valido per la maggior parte degli scopi incluso l'imbarco sui voli nazionali."},
  {cat:"license",en:"What is the 'Motorcycle Only' restriction on a Florida license?",it:"Cos'e la restrizione 'Solo Motocicletta' su una patente Florida?",options:[{en:"The driver is prohibited from riding motorcycles",it:"Al conducente e vietato guidare le motociclette"},{en:"The driver may only operate motorcycles \u2014 not automobiles",it:"Il conducente puo solo guidare motociclette \u2014 non automobili"},{en:"A restriction allowing motorcycles in addition to cars",it:"Una restrizione che consente le motociclette in aggiunta alle auto"},{en:"The driver must ride with a licensed instructor",it:"Il conducente deve guidare con un istruttore patentato"}],correct:1,explain_en:"A 'Motorcycle Only' license restricts the driver to motorcycle operation only. They do not have Class E driving privileges for regular automobiles.",explain_it:"Una patente 'Solo Motocicletta' limita il conducente alla sola guida di motociclette. Non hanno i privilegi di guida Class E per le normali automobili."},
  {cat:"license",en:"What is the Florida law on sharing a driver's license with another person?",it:"Qual e la legge della Florida sulla condivisione di una patente di guida con un'altra persona?",options:[{en:"Legal if you trust the person",it:"Legale se ti fidi della persona"},{en:"Illegal \u2014 lending or using another person's license is a criminal offense",it:"Illegale \u2014 prestare o usare la patente di un'altra persona e un reato penale"},{en:"Only illegal if the other person gets in an accident",it:"Illegale solo se l'altra persona ha un incidente"},{en:"Legal between spouses",it:"Legale tra coniugi"}],correct:1,explain_en:"Lending your driver's license or using another person's license is a criminal offense in Florida \u2014 even between family members.",explain_it:"Prestare la tua patente o usare la patente di un'altra persona e un reato penale in Florida \u2014 anche tra familiari."},
  {cat:"license",en:"What does Florida's 'provisional license' (for drivers 16-17) restrict?",it:"Cosa limita la 'patente provvisoria' della Florida (per i conducenti di 16-17 anni)?",options:[{en:"Must drive with a licensed adult at all times",it:"Deve sempre guidare con un adulto patentato"},{en:"No driving 11 PM\u20136 AM (curfew), max 1 passenger under 18 first year, no handheld devices",it:"Nessuna guida 23:00-6:00 (coprifuoco), max 1 passeggero under 18 nel primo anno, nessun dispositivo a mano"},{en:"Speed limit reduced to 45 mph at all times",it:"Limite di velocita ridotto a 45 mph in ogni momento"},{en:"Must display a P sticker on the vehicle",it:"Deve mostrare un adesivo P sul veicolo"}],correct:1,explain_en:"Florida provisional license (16-17): curfew 11PM-6AM, only 1 non-family passenger under 18 during first 12 months, and no handheld devices while driving.",explain_it:"Patente provvisoria Florida (16-17): coprifuoco 23:00-6:00, solo 1 passeggero non familiare under 18 durante i primi 12 mesi e nessun dispositivo a mano durante la guida."},
  {cat:"license",en:"How many supervised driving hours are required before a Florida teen can get a provisional license?",it:"Quante ore di guida supervisionata sono richieste prima che un adolescente Florida possa ottenere la patente provvisoria?",options:[{en:"25 hours (5 at night)",it:"25 ore (5 di notte)"},{en:"50 hours (10 at night)",it:"50 ore (10 di notte)"},{en:"100 hours (20 at night)",it:"100 ore (20 di notte)"},{en:"No hour requirement \u2014 only the knowledge test",it:"Nessun requisito orario \u2014 solo il test di conoscenza"}],correct:1,explain_en:"Florida requires teen drivers to log 50 hours of supervised driving (10 at night) with a licensed adult 21+ before applying for a provisional license.",explain_it:"La Florida richiede ai conducenti adolescenti di registrare 50 ore di guida supervisionata (10 di notte) con un adulto patentato 21+ prima di richiedere la patente provvisoria."},
  {cat:"license",en:"What is the Florida law on wearing corrective lenses if your license requires them?",it:"Qual e la legge della Florida sull'indossare lenti correttive se la tua patente le richiede?",options:[{en:"Optional \u2014 your license is a suggestion only",it:"Facoltativo \u2014 la tua patente e solo un suggerimento"},{en:"You must wear them whenever driving \u2014 failure to do so is a violation",it:"Devi indossarle ogni volta che guidi \u2014 la mancata osservanza e una violazione"},{en:"Only required at night",it:"Richieste solo di notte"},{en:"Only required on highways",it:"Richieste solo in autostrada"}],correct:1,explain_en:"If your license has a corrective lens restriction (code A), you must wear glasses or contacts whenever operating a vehicle. Driving without them is a violation.",explain_it:"Se la tua patente ha la restrizione per lenti correttive (codice A), devi indossare occhiali o lenti a contatto ogni volta che guidi. Guidare senza e una violazione."},
  {cat:"license",en:"What is the minimum age for a Florida Class A or B commercial license?",it:"Qual e l'eta minima per una patente commerciale Florida Class A o B?",options:[{en:"16 years old",it:"16 anni"},{en:"18 for intrastate; 21 for interstate",it:"18 per intrastatale; 21 per interstatale"},{en:"21 for all commercial licenses",it:"21 per tutte le patenti commerciali"},{en:"18 for all CDL classes",it:"18 per tutte le classi CDL"}],correct:1,explain_en:"Class A and B CDL: minimum 18 years for intrastate commerce, 21 years for interstate or transporting hazardous materials.",explain_it:"CDL Class A e B: minimo 18 anni per il commercio intrastatale, 21 anni per quello interstatale o il trasporto di materiali pericolosi."},
  {cat:"license",en:"What is the Florida penalty for using a fake or altered driver's license?",it:"Qual e la sanzione Florida per l'uso di una patente di guida falsa o alterata?",options:[{en:"A civil fine only",it:"Solo una multa civile"},{en:"A criminal offense \u2014 up to a first-degree misdemeanor or higher depending on circumstances",it:"Un reato penale \u2014 fino a un'infrazione minore di primo grado o superiore a seconda delle circostanze"},{en:"Only loss of driving privileges",it:"Solo perdita dei privilegi di guida"},{en:"A warning for first offense",it:"Un avvertimento alla prima offesa"}],correct:1,explain_en:"Using, making, or possessing a fake or altered driver's license is a criminal offense in Florida. Minors using fake IDs to purchase alcohol face enhanced penalties.",explain_it:"Usare, creare o possedere una patente falsa o alterata e un reato penale in Florida. I minori che usano documenti falsi per acquistare alcol affrontano sanzioni maggiorate."},
  {cat:"license",en:"What must you do if your Florida driver's license is lost or stolen?",it:"Cosa devi fare se la tua patente Florida viene persa o rubata?",options:[{en:"Wait until renewal \u2014 no need to replace it",it:"Aspettare il rinnovo \u2014 non c'e bisogno di sostituirla"},{en:"Apply for a replacement license at FLHSMV or online if eligible",it:"Richiedere una patente sostitutiva al FLHSMV o online se idoneo"},{en:"File a police report only",it:"Solo presentare un rapporto di polizia"},{en:"Use a photocopy as a temporary license",it:"Usare una fotocopia come patente temporanea"}],correct:1,explain_en:"If your Florida license is lost or stolen, apply for a replacement at any FLHSMV office or online (if eligible). A small fee applies.",explain_it:"Se la tua patente Florida viene persa o rubata, richiedi una sostitutiva in qualsiasi ufficio FLHSMV o online (se idoneo). Si applica una piccola quota."},
  {cat:"license",en:"What disqualifies a person from getting a Florida driver's license?",it:"Cosa squalifica una persona dall'ottenere una patente Florida?",options:[{en:"Having any prior traffic ticket",it:"Avere qualsiasi multa precedente"},{en:"Current license revocation or suspension, unresolved tickets, or certain convictions (DUI, felony traffic violations)",it:"Revoca o sospensione della patente attuale, multe non risolte o certe condanne (DUI, violazioni del traffico da reato)"},{en:"Being over 75 years old",it:"Avere piu di 75 anni"},{en:"Having a medical condition of any kind",it:"Avere qualsiasi condizione medica"}],correct:1,explain_en:"You cannot get a Florida license if your current license is suspended/revoked, you have outstanding tickets, unpaid child support, or certain disqualifying criminal convictions.",explain_it:"Non puoi ottenere una patente Florida se la tua patente attuale e sospesa/revocata, hai multe in sospeso, mancato pagamento del mantenimento figli o certe condanne penali squalificanti."},
  {cat:"license",en:"In Florida, what is a 'Notice of Suspension' given to a driver?",it:"In Florida, cos'e un 'Avviso di Sospensione' dato a un conducente?",options:[{en:"An advance warning before a ticket is issued",it:"Un avvertimento anticipato prima dell'emissione di una multa"},{en:"An official notification that driving privileges are or will be suspended, specifying the reason and effective date",it:"Una notifica ufficiale che i privilegi di guida sono o saranno sospesi, specificando il motivo e la data effettiva"},{en:"A courtesy reminder to renew your license",it:"Un promemoria di cortesia per rinnovare la patente"},{en:"A notice from an insurance company about rate increases",it:"Una notifica di una compagnia assicurativa sull'aumento delle tariffe"}],correct:1,explain_en:"A Notice of Suspension is an official document from FLHSMV informing the driver that their license is being suspended, the reason, and the effective date.",explain_it:"Un Avviso di Sospensione e un documento ufficiale del FLHSMV che informa il conducente che la patente e in corso di sospensione, il motivo e la data effettiva."},
  {cat:"license",en:"What is a 'SR-22' certificate and when is it required?",it:"Cos'e un certificato 'SR-22' e quando e richiesto?",options:[{en:"A vehicle safety inspection certificate",it:"Un certificato di ispezione della sicurezza del veicolo"},{en:"A certificate of financial responsibility filed by your insurer \u2014 required after serious violations or license reinstatement",it:"Un certificato di responsabilita finanziaria presentato dall'assicuratore \u2014 richiesto dopo violazioni gravi o ripristino della patente"},{en:"A medical fitness certificate for commercial drivers",it:"Un certificato di idoneita medica per i conducenti commerciali"},{en:"A document allowing driving in multiple states",it:"Un documento che consente di guidare in piu stati"}],correct:1,explain_en:"SR-22 (or FR-44 for DUI) is a certificate your insurance company files with FLHSMV proving you maintain minimum required coverage. Required after serious violations.",explain_it:"SR-22 (o FR-44 per il DUI) e un certificato che la tua compagnia assicurativa presenta al FLHSMV provando che mantieni la copertura minima richiesta. Richiesto dopo violazioni gravi."},
  {cat:"license",en:"What is the Florida requirement for insurance when a license is reinstated?",it:"Qual e il requisito assicurativo della Florida quando una patente viene ripristinata?",options:[{en:"No special insurance requirement",it:"Nessun requisito assicurativo speciale"},{en:"Must obtain and maintain FR-44 (DUI) or SR-22 (other violations) for required period",it:"Deve ottenere e mantenere FR-44 (DUI) o SR-22 (altre violazioni) per il periodo richiesto"},{en:"Only PIP insurance is required",it:"E richiesta solo l'assicurazione PIP"},{en:"Insurance is not verified during reinstatement",it:"L'assicurazione non viene verificata durante il ripristino"}],correct:1,explain_en:"License reinstatement requires maintaining FR-44 (for DUI) or SR-22 (for other violations) for 3 years. The insurance company reports any lapse to FLHSMV, triggering re-suspension.",explain_it:"Il ripristino della patente richiede il mantenimento di FR-44 (per DUI) o SR-22 (per altre violazioni) per 3 anni. La compagnia assicurativa segnala qualsiasi mancanza al FLHSMV, scatenando la re-sospensione."},
  {cat:"license",en:"What is the Florida 'CHOICES' program for teen drivers?",it:"Cos'e il programma Florida 'CHOICES' per i conducenti adolescenti?",options:[{en:"A diversion program allowing teens to avoid DUI charges",it:"Un programma di diversione che consente agli adolescenti di evitare le accuse DUI"},{en:"A driver education program emphasizing decision-making and consequences of unsafe driving",it:"Un programma di educazione alla guida che enfatizza il processo decisionale e le conseguenze della guida non sicura"},{en:"A commercial driver training program",it:"Un programma di formazione per conducenti commerciali"},{en:"A program for teens with prior traffic violations",it:"Un programma per adolescenti con precedenti violazioni del traffico"}],correct:1,explain_en:"CHOICES is a Florida teen driver education program that supplements formal driver's education \u2014 focusing on decision-making, peer pressure, and real-world crash consequences.",explain_it:"CHOICES e un programma di educazione alla guida per adolescenti Florida che integra l'educazione alla guida formale \u2014 concentrandosi sul processo decisionale e le conseguenze reali degli incidenti."},
  {cat:"license",en:"What does Florida law require regarding vision for renewing a driver's license?",it:"Cosa richiede la legge Florida riguardo alla visione per il rinnovo della patente?",options:[{en:"Vision is only tested when first getting a license",it:"La visione viene testata solo al primo conseguimento della patente"},{en:"Vision may be tested at renewal \u2014 especially after age 80; corrective lens restrictions updated if needed",it:"La visione puo essere testata al rinnovo \u2014 specialmente dopo i 80 anni; le restrizioni per lenti correttive vengono aggiornate se necessario"},{en:"Vision is never tested at license renewal",it:"La visione non viene mai testata al rinnovo della patente"},{en:"Annual vision tests are required for all drivers",it:"I test annuali della visione sono richiesti per tutti i conducenti"}],correct:1,explain_en:"Florida may require vision testing at license renewal, particularly for older drivers. If your vision has changed requiring correction, the restriction on your license is updated.",explain_it:"La Florida puo richiedere il test della visione al rinnovo della patente, particolarmente per i conducenti anziani. Se la visione e cambiata richiedendo correzione, la restrizione sulla patente viene aggiornata."},
  {cat:"license",en:"What must a Florida driver do if their vehicle's liability insurance lapses?",it:"Cosa deve fare un conducente Florida se l'assicurazione di responsabilita del veicolo scade?",options:[{en:"Nothing \u2014 insurance is optional if you can pay out of pocket",it:"Niente \u2014 l'assicurazione e facoltativa se puoi pagare di tasca propria"},{en:"Maintain continuous coverage \u2014 a lapse triggers automatic FLHSMV suspension of registration and license",it:"Mantenere una copertura continua \u2014 una mancanza scatena la sospensione automatica del FLHSMV della registrazione e della patente"},{en:"Have 30 days to reinstate before any penalty",it:"Avere 30 giorni per ripristinare prima di qualsiasi sanzione"},{en:"Only affects commercial vehicles",it:"Influisce solo sui veicoli commerciali"}],correct:1,explain_en:"Florida requires continuous PIP and PDL insurance. An insurance lapse triggers automatic suspension of vehicle registration AND driver's license by FLHSMV.",explain_it:"La Florida richiede un'assicurazione PIP e PDL continua. Una mancanza assicurativa scatena la sospensione automatica della registrazione del veicolo E della patente da parte del FLHSMV."},
  {cat:"license",en:"What is 'implied consent' when you accept a Florida driver's license?",it:"Cos'e il 'consenso implicito' quando si accetta una patente di guida Florida?",options:[{en:"You agree to obey all traffic laws",it:"Accetti di rispettare tutte le leggi del traffico"},{en:"You consent to submit to a BAC test if lawfully arrested for DUI \u2014 refusal has consequences",it:"Acconsenti a sottoporti a un test BAC se legalmente arrestato per DUI \u2014 il rifiuto ha conseguenze"},{en:"You agree to carry insurance at all times",it:"Accetti di portare l'assicurazione in ogni momento"},{en:"You accept FLHSMV's right to revoke your license",it:"Accetti il diritto del FLHSMV di revocare la tua patente"}],correct:1,explain_en:"Implied consent: obtaining a Florida license means you consent to BAC testing when lawfully arrested for DUI. Refusal = license suspension and potential misdemeanor charge.",explain_it:"Consenso implicito: ottenere una patente Florida significa che acconsenti ai test BAC quando legalmente arrestato per DUI. Rifiuto = sospensione della patente e potenziale accusa."},
  {cat:"license",en:"How long does a Florida driver have to satisfy an outstanding judgment after a crash?",it:"Quanto tempo ha un conducente Florida per soddisfare un giudizio pendente dopo un incidente?",options:[{en:"No time limit",it:"Nessun limite di tempo"},{en:"Until the judgment is paid or a payment plan is approved \u2014 failure results in license suspension",it:"Finche il giudizio non e pagato o un piano di pagamento e approvato \u2014 il mancato rispetto comporta la sospensione della patente"},{en:"6 months from the date of the crash",it:"6 mesi dalla data dell'incidente"},{en:"1 year from the court judgment date",it:"1 anno dalla data del giudizio del tribunale"}],correct:1,explain_en:"An unsatisfied court judgment for a vehicle crash results in license suspension in Florida until the judgment is paid or a satisfactory payment arrangement is made.",explain_it:"Un giudizio del tribunale non soddisfatto per un incidente con veicolo comporta la sospensione della patente in Florida finche il giudizio non e pagato o si fa un accordo di pagamento soddisfacente."},
  {cat:"license",en:"What happens to a Florida teen driver's provisional license if they accumulate 6 or more points in 12 months?",it:"Cosa succede alla patente provvisoria di un adolescente Florida se accumula 6 o piu punti in 12 mesi?",options:[{en:"Nothing \u2014 point rules only apply to adults",it:"Niente \u2014 le regole sui punti si applicano solo agli adulti"},{en:"Their provisional license is suspended for 30 days",it:"La loro patente provvisoria viene sospesa per 30 giorni"},{en:"They must retake the knowledge test",it:"Devono ripetere il test di conoscenza"},{en:"They receive a warning letter only",it:"Ricevono solo una lettera di avvertimento"}],correct:1,explain_en:"Florida provisional license holders who accumulate 6+ points in 12 months face a 30-day suspension. 7+ points = 90 days suspension. 12+ points = 1-year suspension.",explain_it:"I titolari di patente provvisoria Florida che accumulano 6+ punti in 12 mesi affrontano una sospensione di 30 giorni. 7+ punti = 90 giorni. 12+ punti = 1 anno."},
  {cat:"license",en:"What is the Florida insurance penalty for driving without PIP/PDL coverage?",it:"Qual e la sanzione assicurativa Florida per guidare senza copertura PIP/PDL?",options:[{en:"A $50 fine",it:"Una multa di $50"},{en:"License and registration suspension plus a reinstatement fee of $150-$500 plus requirement to maintain FR-44 for 3 years",it:"Sospensione della patente e della registrazione piu una quota di ripristino di $150-$500 piu il requisito di mantenere FR-44 per 3 anni"},{en:"Only a warning for first offense",it:"Solo un avvertimento alla prima offesa"},{en:"A $100 fine with no suspension",it:"Una multa di $100 senza sospensione"}],correct:1,explain_en:"Driving without required insurance in Florida: license and registration suspended, reinstatement fee $150-$500, and possibly required to maintain FR-44 insurance for 3 years.",explain_it:"Guidare senza l'assicurazione richiesta in Florida: sospensione della patente e della registrazione, quota di ripristino $150-$500 e possibilmente obbligo di mantenere FR-44 per 3 anni."},
  {cat:"license",en:"What is the minimum liability insurance required for a third-party claim against a Florida driver?",it:"Qual e l'assicurazione minima di responsabilita richiesta per un reclamo di terze parti contro un conducente Florida?",options:[{en:"PIP is sufficient for all claims",it:"Il PIP e sufficiente per tutti i reclami"},{en:"PDL ($10,000) covers property damage; bodily injury liability is NOT required but recommended",it:"PDL ($10.000) copre i danni materiali; la responsabilita per lesioni corporali NON e richiesta ma raccomandata"},{en:"$100,000 minimum bodily injury liability",it:"Minimo $100.000 di responsabilita per lesioni corporali"},{en:"Full coverage is the only legal requirement",it:"La copertura completa e l'unico requisito legale"}],correct:1,explain_en:"Florida's minimum is PIP ($10K) + PDL ($10K). Bodily Injury (BI) liability is NOT mandatory (though many drivers carry it). Florida is a no-fault state for personal injury up to PIP limits.",explain_it:"Il minimo in Florida e PIP ($10K) + PDL ($10K). La responsabilita per Lesioni Corporali (BI) NON e obbligatoria (sebbene molti conducenti la portino). Florida e uno stato no-fault."},
  {cat:"license",en:"What is the Florida law on minors obtaining a driver's license if they have dropped out of school?",it:"Qual e la legge Florida sui minori che ottengono la patente se hanno abbandonato la scuola?",options:[{en:"No connection between school enrollment and driving",it:"Nessuna connessione tra l'iscrizione scolastica e la guida"},{en:"Minors who drop out of school without meeting minimum requirements may have their license withheld or suspended",it:"I minori che abbandonano la scuola senza soddisfare i requisiti minimi possono avere la patente trattenuta o sospesa"},{en:"Only affects those under 16",it:"Influisce solo su quelli sotto i 16 anni"},{en:"Homeschooled students cannot get a license",it:"Gli studenti istruzione a casa non possono ottenere la patente"}],correct:1,explain_en:"Florida's 'Stay in School' law: minors who drop out without meeting requirements or have excessive absences may face license suspension as a consequence.",explain_it:"La legge 'Stay in School' della Florida: i minori che abbandonano la scuola senza soddisfare i requisiti o hanno eccessive assenze possono affrontare la sospensione della patente."},
  {cat:"license",en:"What is required to apply for a Florida license after moving from another state?",it:"Cosa e richiesto per richiedere la patente Florida dopo essersi trasferiti da un altro stato?",options:[{en:"Take the full knowledge and road test again regardless",it:"Sostenere di nuovo il test di conoscenza e pratico indipendentemente"},{en:"Surrender the out-of-state license, provide identity and residency documents \u2014 knowledge test may be waived for experienced drivers",it:"Cedere la patente dell'altro stato, fornire documenti di identita e residenza \u2014 il test di conoscenza puo essere rinunciato per i conducenti esperti"},{en:"Only proof of identity is needed",it:"E necessaria solo la prova di identita"},{en:"Out-of-state licenses are automatically converted",it:"Le patenti di altri stati vengono convertite automaticamente"}],correct:1,explain_en:"New Florida residents: surrender out-of-state license, provide ID and two FL residency proofs. Knowledge test may be waived if you have a valid out-of-state license.",explain_it:"Nuovi residenti Florida: cedere la patente dell'altro stato, fornire documento d'identita e due prove di residenza FL. Il test di conoscenza puo essere rinunciato per i conducenti con una patente valida di un altro stato."},
  {cat:"license",en:"What is the Florida law on the use of turn signals for lane changes on a limited access highway?",it:"Qual e la legge Florida sull'uso dei segnali di svolta per i cambi di corsia su un'autostrada ad accesso limitato?",options:[{en:"Signals are not required on highways",it:"I segnali non sono richiesti in autostrada"},{en:"Signal at least 200 feet before any lane change \u2014 failure to signal is a moving violation",it:"Segnalare almeno 200 piedi prima di qualsiasi cambio di corsia \u2014 la mancata segnalazione e una violazione in movimento"},{en:"Signal only if other vehicles are nearby",it:"Segnalare solo se altri veicoli sono nelle vicinanze"},{en:"Signal only when changing from the right lane",it:"Segnalare solo quando si cambia dalla corsia destra"}],correct:1,explain_en:"Florida requires signaling at least 200 feet before a lane change on limited access highways (100 feet on other roads). Failing to signal is a moving violation.",explain_it:"La Florida richiede di segnalare almeno 200 piedi prima di un cambio di corsia sulle autostrade ad accesso limitato (100 piedi sulle altre strade). La mancata segnalazione e una violazione in movimento."},
  {cat:"license",en:"What does 'uninsured motorist' (UM) coverage protect against in Florida?",it:"Da cosa protegge la copertura 'automobilista non assicurato' (UM) in Florida?",options:[{en:"Damage to your vehicle from all causes",it:"Danni al tuo veicolo da tutte le cause"},{en:"Injuries to you caused by a driver with no insurance or insufficient coverage \u2014 when your own PIP is exhausted",it:"Lesioni a te causate da un conducente senza assicurazione o copertura insufficiente \u2014 quando il tuo PIP e esaurito"},{en:"Liability when you cause an accident",it:"Responsabilita quando causi un incidente"},{en:"Weather-related vehicle damage",it:"Danni al veicolo legati al maltempo"}],correct:1,explain_en:"UM (Uninsured/Underinsured Motorist) coverage pays for YOUR injuries when hit by an uninsured or underinsured driver, beyond your PIP limit. Not mandatory in Florida but highly recommended.",explain_it:"La copertura UM paga per LE TUE lesioni quando sei colpito da un conducente non assicurato o sottoassicurato, oltre il tuo limite PIP. Non obbligatoria in Florida ma altamente raccomandata."},
  {cat:"license",en:"What is the Florida law regarding a vehicle owner's responsibility when they lend their car?",it:"Qual e la legge Florida riguardo alla responsabilita del proprietario del veicolo quando presta la macchina?",options:[{en:"The owner has no liability \u2014 only the driver is responsible",it:"Il proprietario non ha responsabilita \u2014 solo il conducente e responsabile"},{en:"The vehicle owner may be liable for damages if the borrower causes an accident \u2014 under Florida's dangerous instrumentality doctrine",it:"Il proprietario del veicolo puo essere responsabile per i danni se il mutuatario causa un incidente \u2014 in base alla dottrina dello strumento pericoloso della Florida"},{en:"Only liable if the borrower is under 18",it:"Responsabile solo se il mutuatario ha meno di 18 anni"},{en:"Liability only arises if the car was stolen",it:"La responsabilita sorge solo se l'auto e stata rubata"}],correct:1,explain_en:"Florida's dangerous instrumentality doctrine: vehicle owners who voluntarily entrust their car to another person may be liable for that driver's negligence.",explain_it:"La dottrina dello strumento pericoloso della Florida: i proprietari di veicoli che affidano volontariamente la loro auto a un'altra persona possono essere responsabili per la negligenza di quel conducente."},
  {cat:"license",en:"What is the Florida law about title transfer when a vehicle owner dies?",it:"Qual e la legge Florida sul trasferimento del titolo quando un proprietario del veicolo muore?",options:[{en:"The vehicle automatically goes to the next of kin",it:"Il veicolo va automaticamente al parente prossimo"},{en:"Title must be transferred through probate or appropriate legal process to the heir",it:"Il titolo deve essere trasferito attraverso la successione o il processo legale appropriato all'erede"},{en:"The vehicle may be driven by any family member without transfer",it:"Il veicolo puo essere guidato da qualsiasi membro della famiglia senza trasferimento"},{en:"The state takes ownership of all vehicles when owner dies",it:"Lo stato prende la proprieta di tutti i veicoli quando il proprietario muore"}],correct:1,explain_en:"When a vehicle owner dies, the title must be legally transferred to heirs through probate, joint ownership, or a designated beneficiary \u2014 before the new owner can register or insure the vehicle.",explain_it:"Quando un proprietario di veicolo muore, il titolo deve essere legalmente trasferito agli eredi attraverso la successione, la proprieta congiunta o un beneficiario designato."},
  {cat:"license",en:"What is Florida's law on vehicles with salvage titles?",it:"Qual e la legge Florida sui veicoli con titolo di recupero (salvage)?",options:[{en:"Salvage title vehicles may be driven normally",it:"I veicoli con titolo salvage possono essere guidati normalmente"},{en:"A salvage title vehicle must pass a Florida-licensed salvage inspection before it can be retitled as 'rebuilt' and registered",it:"Un veicolo con titolo salvage deve superare un'ispezione di recupero con licenza Florida prima di poter essere ritolato come 'ricostruito' e registrato"},{en:"Salvage vehicles cannot be registered in Florida",it:"I veicoli salvage non possono essere registrati in Florida"},{en:"Any body shop can certify a salvage vehicle",it:"Qualsiasi carrozzeria puo certificare un veicolo salvage"}],correct:1,explain_en:"A salvage title vehicle (significantly damaged) must pass a Florida DMV inspection and be retitled as 'Rebuilt/Reconstructed' before it can legally be registered and driven.",explain_it:"Un veicolo con titolo salvage (significativamente danneggiato) deve superare un'ispezione DMV Florida ed essere ritolato come 'Ricostruito' prima di poter essere legalmente registrato e guidato."},
  {cat:"license",en:"What is required when selling a vehicle in Florida?",it:"Cosa e richiesto quando si vende un veicolo in Florida?",options:[{en:"Only hand over the keys",it:"Solo consegnare le chiavi"},{en:"Transfer the title to the buyer, remove your license plates, and notify FLHSMV of the sale",it:"Trasferire il titolo all'acquirente, rimuovere le targhe e notificare il FLHSMV della vendita"},{en:"The buyer is responsible for all paperwork",it:"L'acquirente e responsabile di tutta la documentazione"},{en:"License plates transfer automatically with the vehicle",it:"Le targhe si trasferiscono automaticamente con il veicolo"}],correct:1,explain_en:"When selling: sign and transfer the title, remove your plates (plates stay with the owner \u2014 not the car in Florida), and notify FLHSMV within 30 days to release liability.",explain_it:"Quando si vende: firma e trasferisci il titolo, rimuovi le targhe (le targhe rimangono con il proprietario \u2014 non con l'auto in Florida) e notifica il FLHSMV entro 30 giorni per liberare la responsabilita."},
  {cat:"license",en:"What is the Florida law about using a driver's license from another country?",it:"Qual e la legge Florida sull'uso di una patente di guida di un altro paese?",options:[{en:"Foreign licenses are never valid in Florida",it:"Le patenti straniere non sono mai valide in Florida"},{en:"Valid foreign licenses allow temporary driving; after becoming a Florida resident you must get a Florida license within a set timeframe",it:"Le patenti straniere valide consentono la guida temporanea; dopo essere diventato residente Florida devi ottenere una patente Florida entro un determinato periodo"},{en:"Foreign licenses are accepted permanently without conversion",it:"Le patenti straniere sono accettate permanentemente senza conversione"},{en:"A foreign license must be translated to English before use",it:"Una patente straniera deve essere tradotta in inglese prima dell'uso"}],correct:1,explain_en:"Valid foreign licenses allow temporary operation of vehicles in Florida. Once you become a Florida resident, you must obtain a Florida driver's license.",explain_it:"Le patenti straniere valide consentono la guida temporanea di veicoli in Florida. Una volta diventato residente Florida, devi ottenere una patente Florida."},
  {cat:"license",en:"What is the Florida law about license plate display on vehicles?",it:"Qual e la legge Florida sull'esposizione delle targhe sui veicoli?",options:[{en:"Only a rear plate is required in Florida",it:"Solo la targa posteriore e richiesta in Florida"},{en:"One license plate displayed on the rear of the vehicle \u2014 must be legible, lit at night, and unobstructed",it:"Una targa esposta sul retro del veicolo \u2014 deve essere leggibile, illuminata di notte e non ostruita"},{en:"Both front and rear plates are required",it:"Sono richieste sia le targhe anteriori che posteriori"},{en:"Plates may be covered with a tinted cover for privacy",it:"Le targhe possono essere coperte con un copri-targa tinto per la privacy"}],correct:1,explain_en:"Florida requires one license plate on the rear, clearly visible, properly illuminated at night, and not obscured by covers, dirt, or decorative frames that impair readability.",explain_it:"La Florida richiede una targa sul retro, chiaramente visibile, opportunamente illuminata di notte e non oscurata da coperture, sporcizia o cornici decorative che compromettono la leggibilita."},
  {cat:"license",en:"What is required for a non-resident of Florida to drive legally in the state?",it:"Cosa e richiesto a un non-residente della Florida per guidare legalmente nello stato?",options:[{en:"Must obtain a Florida license immediately upon entry",it:"Deve ottenere immediatamente una patente Florida all'ingresso"},{en:"A valid driver's license from their home state or country \u2014 as long as they have not established Florida residency",it:"Una patente valida del loro stato o paese d'origine \u2014 finche non hanno stabilito la residenza Florida"},{en:"Must carry an international driving permit at all times",it:"Deve portare sempre un permesso di guida internazionale"},{en:"Non-residents may not drive in Florida without a Florida license",it:"I non-residenti non possono guidare in Florida senza una patente Florida"}],correct:1,explain_en:"Non-residents with a valid license from their home state or country may drive in Florida without obtaining a Florida license \u2014 as long as they do not establish residency.",explain_it:"I non-residenti con una patente valida del loro stato o paese d'origine possono guidare in Florida senza ottenere una patente Florida \u2014 finche non stabiliscono la residenza."},
  {cat:"license",en:"What is Florida's law on vehicle registration renewal?",it:"Qual e la legge Florida sul rinnovo della registrazione del veicolo?",options:[{en:"Annual renewal only at a FLHSMV office",it:"Rinnovo annuale solo in un ufficio FLHSMV"},{en:"Vehicles must be registered annually or biennially \u2014 renewal notices sent to registered owner; late renewal incurs penalties",it:"I veicoli devono essere registrati annualmente o biennalmente \u2014 avvisi di rinnovo inviati al proprietario registrato; il rinnovo tardivo comporta sanzioni"},{en:"Registration never expires in Florida",it:"La registrazione non scade mai in Florida"},{en:"Only commercial vehicles require annual renewal",it:"Solo i veicoli commerciali richiedono il rinnovo annuale"}],correct:1,explain_en:"Florida vehicle registrations must be renewed annually or biennially. Late renewals incur a $25 delinquent fee. Driving with expired registration is a non-criminal traffic infraction.",explain_it:"Le registrazioni dei veicoli Florida devono essere rinnovate annualmente o biennialmente. I rinnovi tardivi comportano una mora di $25. Guidare con registrazione scaduta e una violazione non penale."},
  {cat:"license",en:"What is a 'certificate of title' for a vehicle in Florida?",it:"Cos'e un 'certificato di titolo' per un veicolo in Florida?",options:[{en:"The vehicle's owner's manual",it:"Il manuale del proprietario del veicolo"},{en:"The legal document proving ownership of the vehicle",it:"Il documento legale che prova la proprieta del veicolo"},{en:"The vehicle registration certificate",it:"Il certificato di registrazione del veicolo"},{en:"A copy of the bill of sale",it:"Una copia della ricevuta di vendita"}],correct:1,explain_en:"A certificate of title is the legal document proving vehicle ownership. It must be transferred when a vehicle is sold and is required for registration.",explain_it:"Un certificato di titolo e il documento legale che prova la proprieta del veicolo. Deve essere trasferito quando un veicolo viene venduto ed e richiesto per la registrazione."},
  {cat:"license",en:"What is the minimum age for a Florida learner's license (learner's permit)?",it:"Qual e l'eta minima per il permesso per principianti Florida?",options:[{en:"14 years old",it:"14 anni"},{en:"15 years old",it:"15 anni"},{en:"16 years old",it:"16 anni"},{en:"17 years old",it:"17 anni"}],correct:1,explain_en:"Florida's minimum age for a learner's license (learner's permit) is 15 years old.",explain_it:"L'eta minima per il permesso per principianti Florida e 15 anni."},
  {cat:"license",en:"What must be presented at a Florida DMV for a first-time driver's license application?",it:"Cosa deve essere presentato al DMV Florida per una domanda di patente per la prima volta?",options:[{en:"Only a birth certificate",it:"Solo un certificato di nascita"},{en:"Primary ID, proof of Social Security, two proofs of FL residency, and completed TLSAE/DETS",it:"Documento d'identita primario, prova del numero di previdenza sociale, due prove di residenza FL e TLSAE/DETS completato"},{en:"Passport only",it:"Solo passaporto"},{en:"School enrollment record",it:"Documento di iscrizione scolastica"}],correct:1,explain_en:"First-time FL license: primary ID (birth certificate, passport, etc.), SSN proof, two FL residency proofs, and TLSAE (adults 18+) or DETS (teens under 18) certificate.",explain_it:"Prima patente FL: documento primario (certificato di nascita, passaporto, ecc.), prova SSN, due prove di residenza FL e certificato TLSAE (adulti 18+) o DETS (adolescenti under 18)."},
  {cat:"signs",en:"What shape is a 'Yield' sign in the United States?",it:"Che forma ha un segnale 'Yield' negli Stati Uniti?",options:[{en:"An octagon",it:"Un ottagono"},{en:"An inverted red triangle with white center",it:"Un triangolo rosso rovesciato con centro bianco"},{en:"A yellow diamond",it:"Un rombo giallo"},{en:"A white rectangle with red letters",it:"Un rettangolo bianco con lettere rosse"}],correct:1,explain_en:"The Yield sign is a downward-pointing triangle \u2014 red border with white center. It means slow down and be prepared to stop if necessary for conflicting traffic.",explain_it:"Il segnale Yield e un triangolo che punta verso il basso \u2014 bordo rosso con centro bianco. Significa rallentare ed essere pronti a fermarsi se necessario per il traffico in conflitto."},
  {cat:"laws",en:"What is Florida's 'Kimberlyn's Law' regarding school bus stop arms?",it:"Cos'e la 'Legge di Kimberlyn' della Florida riguardo ai bracci di stop degli scuolabus?",options:[{en:"Increased fines to $400 for illegally passing a stopped school bus",it:"Aumentato le multe a $400 per il passaggio illegale di uno scuolabus fermo"},{en:"Requires all school buses to have external cameras documenting stop arm violations",it:"Richiede a tutti gli scuolabus di avere telecamere esterne che documentino le violazioni del braccio di stop"},{en:"Mandates school bus escort vehicles on all routes",it:"Impone veicoli di scorta per gli scuolabus su tutti i percorsi"},{en:"Requires students to wait 10 feet from the road",it:"Richiede agli studenti di aspettare a 10 piedi dalla strada"}],correct:1,explain_en:"Florida law requires school buses to be equipped with external cameras to document stop-arm violations \u2014 helping identify and fine drivers who illegally pass stopped buses.",explain_it:"La legge Florida richiede agli scuolabus di essere dotati di telecamere esterne per documentare le violazioni del braccio di stop \u2014 aiutando a identificare e multare i conducenti che passano illegalmente."},
  {cat:"laws",en:"What is the fine range for illegally passing a stopped school bus in Florida?",it:"Qual e la gamma delle multe per il passaggio illegale di uno scuolabus fermo in Florida?",options:[{en:"$50-$100",it:"$50-$100"},{en:"$100-$250",it:"$100-$250"},{en:"$200-$400",it:"$200-$400"},{en:"$500 flat",it:"$500 fisso"}],correct:2,explain_en:"Illegally passing a stopped school bus in Florida carries a fine of $200-$400 for a first offense. Subsequent offenses carry higher fines and possible imprisonment.",explain_it:"Il passaggio illegale di uno scuolabus fermo in Florida comporta una multa di $200-$400 per la prima offesa. Le offese successive comportano multe piu alte e possibile reclusione."},
  {cat:"laws",en:"In Florida, within how many feet of a driveway or alley exit must you yield to pedestrians?",it:"In Florida, entro quanti piedi dall'uscita di un vialetto o vicolo devi cedere la precedenza ai pedoni?",options:[{en:"5 feet",it:"5 piedi"},{en:"10 feet",it:"10 piedi"},{en:"When exiting any driveway or alley you must yield to all sidewalk pedestrians before crossing the sidewalk",it:"Uscendo da qualsiasi vialetto o vicolo devi cedere a tutti i pedoni sul marciapiede prima di attraversarlo"},{en:"Pedestrians must yield to vehicles exiting driveways",it:"I pedoni devono cedere ai veicoli che escono dai vialetti"}],correct:2,explain_en:"When exiting a driveway, alley, or building, you must yield to all pedestrians on the sidewalk before crossing it, and then yield to all traffic before entering the road.",explain_it:"Uscendo da un vialetto, vicolo o edificio, devi cedere a tutti i pedoni sul marciapiede prima di attraversarlo, poi cedere a tutto il traffico prima di entrare in strada."},
  {cat:"laws",en:"What is the Florida law about riding in the bed of a pickup truck?",it:"Qual e la legge Florida sul viaggiare nel cassone di un pick-up?",options:[{en:"Always legal for adults",it:"Sempre legale per gli adulti"},{en:"Illegal for anyone under 18 to ride in an open truck bed on a public road",it:"Illegale per chiunque abbia meno di 18 anni viaggiare nel cassone aperto di un camion su una strada pubblica"},{en:"Legal only on roads under 35 mph",it:"Legale solo su strade sotto i 35 mph"},{en:"Florida has no law on truck bed passengers",it:"La Florida non ha leggi sui passeggeri nel cassone"}],correct:1,explain_en:"Florida prohibits passengers under 18 from riding in the open bed of a pickup truck on public roads. Adults (18+) may legally ride in open truck beds.",explain_it:"La Florida vieta ai passeggeri under 18 di viaggiare nel cassone aperto di un pick-up su strade pubbliche. Gli adulti (18+) possono legalmente viaggiare nei cassoni aperti."},
  {cat:"laws",en:"In Florida, what is the law about passing on the right shoulder?",it:"In Florida, qual e la legge sul sorpasso sulla banchina destra?",options:[{en:"Legal if traffic is heavy",it:"Legale se il traffico e intenso"},{en:"Illegal \u2014 you may not use the shoulder to pass a vehicle",it:"Illegale \u2014 non puoi usare la banchina per sorpassare un veicolo"},{en:"Legal only at speeds under 30 mph",it:"Legale solo a velocita inferiori a 30 mph"},{en:"Legal on highways with a paved shoulder",it:"Legale sulle autostrade con banchina asfaltata"}],correct:1,explain_en:"Passing on the right shoulder (paved or unpaved) is illegal in Florida. The shoulder is for emergency stops \u2014 not for passing stopped or slow traffic.",explain_it:"Il sorpasso sulla banchina destra (asfaltata o non) e illegale in Florida. La banchina e per le soste di emergenza \u2014 non per sorpassare il traffico fermo o lento."},
  {cat:"laws",en:"What is the rule in Florida about speed when approaching a hill or curve?",it:"Qual e la regola in Florida sulla velocita quando ci si avvicina a una collina o una curva?",options:[{en:"Maintain posted speed \u2014 the limit covers all conditions",it:"Mantenere la velocita segnalata \u2014 il limite copre tutte le condizioni"},{en:"Reduce speed to a safe level where you can stop within your visible road ahead",it:"Ridurre la velocita a un livello sicuro dove puoi fermarti entro la strada visibile davanti"},{en:"Increase speed to cross the hill or curve quickly",it:"Aumentare la velocita per attraversare la collina o la curva velocemente"},{en:"Only slow down if there is a speed advisory sign",it:"Rallentare solo se c'e un segnale di velocita consigliata"}],correct:1,explain_en:"You must reduce speed when approaching hills or curves so that you can stop within the visible ahead distance. 'Basic Speed Law' applies regardless of posted limits.",explain_it:"Devi ridurre la velocita avvicinandoti a colline o curve in modo da poter fermarti entro la distanza visibile. La 'Legge della Velocita di Base' si applica indipendentemente dai limiti segnalati."},
  {cat:"laws",en:"What is Florida's minimum speed law?",it:"Qual e la legge Florida sulla velocita minima?",options:[{en:"No minimum speed laws exist",it:"Non esistono leggi sulla velocita minima"},{en:"You must drive fast enough not to impede or block normal traffic \u2014 driving unreasonably slowly can be a violation",it:"Devi guidare abbastanza veloce da non ostacolare o bloccare il traffico normale \u2014 guidare irragionevolmente lentamente puo essere una violazione"},{en:"Minimum speed of 40 mph on all highways",it:"Velocita minima di 40 mph su tutte le autostrade"},{en:"Minimum speed only applies on interstate highways",it:"La velocita minima si applica solo sulle autostrade interstatali"}],correct:1,explain_en:"Florida law prohibits driving so slowly as to impede normal traffic flow. Unreasonably slow driving (especially on highways) can be cited as a moving violation.",explain_it:"La legge Florida vieta di guidare cosi lentamente da ostacolare il flusso normale del traffico. La guida irragionevolmente lenta (specialmente in autostrada) puo essere citata come violazione."},
  {cat:"laws",en:"What is required in Florida when two lanes merge into one?",it:"Cosa e richiesto in Florida quando due corsie si uniscono in una?",options:[{en:"Larger vehicles have priority",it:"I veicoli piu grandi hanno la priorita"},{en:"The driver in the lane that is ending must yield to vehicles in the continuing lane",it:"Il conducente nella corsia che termina deve cedere ai veicoli nella corsia che continua"},{en:"First-come first-served regardless of lane position",it:"Prima arrivato, primo servito indipendentemente dalla posizione in corsia"},{en:"Both lanes alternate (zipper merge is required)",it:"Entrambe le corsie si alternano (il merge a cerniera e richiesto)"}],correct:1,explain_en:"When a lane ends in a merge, the driver in the ending lane must yield to vehicles in the continuing lane unless traffic is at a standstill \u2014 then a zipper merge may be appropriate.",explain_it:"Quando una corsia termina in una confluenza, il conducente nella corsia che termina deve cedere ai veicoli nella corsia che continua, a meno che il traffico sia fermo."},
  {cat:"laws",en:"What is the Florida law about lighting requirements for bicycles at night?",it:"Qual e la legge Florida sui requisiti di illuminazione per le biciclette di notte?",options:[{en:"No lighting required for bicycles",it:"Nessuna illuminazione richiesta per le biciclette"},{en:"A white front light visible from 500 feet and a red rear reflector or light visible from 600 feet",it:"Una luce anteriore bianca visibile da 500 piedi e un riflettore o luce posteriore rossa visibile da 600 piedi"},{en:"Only a rear reflector is required",it:"E richiesto solo un riflettore posteriore"},{en:"Reflective clothing is sufficient instead of lights",it:"L'abbigliamento riflettente e sufficiente invece delle luci"}],correct:1,explain_en:"Florida law: bicycles used at night must have a white front light (visible 500 ft) and a red rear reflector or light (visible 600 ft). Additional reflectors on pedals and sides are also required.",explain_it:"Legge Florida: le biciclette usate di notte devono avere una luce anteriore bianca (visibile 500 piedi) e un riflettore o luce posteriore rossa (visibile 600 piedi)."},
  {cat:"laws",en:"In Florida, who has the right-of-way when a vehicle and a pedestrian are at an unmarked crosswalk?",it:"In Florida, chi ha la precedenza quando un veicolo e un pedone sono a un passaggio pedonale non segnalato?",options:[{en:"The vehicle \u2014 unmarked crosswalks are not official",it:"Il veicolo \u2014 i passaggi pedonali non segnalati non sono ufficiali"},{en:"The pedestrian \u2014 drivers must yield to pedestrians at all crosswalks, marked or unmarked",it:"Il pedone \u2014 i conducenti devono cedere ai pedoni a tutti i passaggi pedonali, segnalati o meno"},{en:"Whoever arrives first",it:"Chi arriva per primo"},{en:"Only applies at traffic lights",it:"Si applica solo ai semafori"}],correct:1,explain_en:"Florida requires drivers to yield to pedestrians at ALL crosswalks \u2014 marked (painted) or unmarked (the legal extension of a sidewalk at intersections).",explain_it:"La Florida richiede ai conducenti di cedere ai pedoni a TUTTI i passaggi pedonali \u2014 segnalati (verniciati) o non segnalati (l'estensione legale di un marciapiede agli incroci)."},
  {cat:"laws",en:"In Florida, what must a driver do when a funeral procession is passing?",it:"In Florida, cosa deve fare un conducente quando passa un corteo funebre?",options:[{en:"Proceed normally \u2014 they have no special rights",it:"Procedere normalmente \u2014 non hanno diritti speciali"},{en:"Yield the right-of-way to all vehicles in the procession \u2014 do not cut through it",it:"Cedere la precedenza a tutti i veicoli nel corteo \u2014 non tagliarlo"},{en:"Stop completely until the entire procession has passed",it:"Fermarsi completamente finche l'intero corteo e passato"},{en:"Only yield if the lead vehicle has its lights on",it:"Cedere solo se il veicolo di testa ha le luci accese"}],correct:1,explain_en:"Florida law grants right-of-way to funeral processions. Do not cut through a procession \u2014 all vehicles in a funeral cortege may proceed together through intersections.",explain_it:"La legge Florida concede la precedenza ai cortei funebri. Non tagliare un corteo \u2014 tutti i veicoli in un corteo funebre possono procedere insieme attraverso gli incroci."},
  {cat:"safety",en:"Why should you avoid parking near a railroad crossing?",it:"Perche dovresti evitare di parcheggiare vicino a un passaggio a livello?",options:[{en:"It creates a speed hazard",it:"Crea un pericolo di velocita"},{en:"Parking within 50 feet of a railroad crossing is prohibited \u2014 vehicles may be hit by a train or block sight distances",it:"Il parcheggio entro 50 piedi da un passaggio a livello e vietato \u2014 i veicoli possono essere colpiti da un treno o bloccare le distanze di visibilita"},{en:"Only trucks must avoid parking near crossings",it:"Solo i camion devono evitare di parcheggiare vicino agli attraversamenti"},{en:"No restriction \u2014 railroad crossings are public areas",it:"Nessuna restrizione \u2014 i passaggi a livello sono aree pubbliche"}],correct:1,explain_en:"Florida prohibits parking within 50 feet of a railroad crossing. Parked vehicles can obstruct sight lines for other drivers and may be struck by trains.",explain_it:"La Florida vieta il parcheggio entro 50 piedi da un passaggio a livello. I veicoli parcheggiati possono ostruire le linee di visibilita per altri conducenti e possono essere colpiti dai treni."},
  {cat:"safety",en:"What should you do if a traffic light is completely dark (no signal at all)?",it:"Cosa dovresti fare se un semaforo e completamente buio (nessun segnale)?",options:[{en:"Proceed normally \u2014 assume it is green",it:"Procedere normalmente \u2014 supponi che sia verde"},{en:"Treat it as a four-way stop \u2014 come to a complete stop and yield appropriately",it:"Trattarlo come un incrocio a quattro vie \u2014 fermarsi completamente e cedere appropriatamente"},{en:"Only stop if other vehicles are present",it:"Fermarsi solo se altri veicoli sono presenti"},{en:"Turn around and find another route",it:"Girare indietro e trovare un altro percorso"}],correct:1,explain_en:"A dark (non-functioning) traffic light should be treated as a four-way stop: stop completely, yield in the appropriate order, then proceed when safe.",explain_it:"Un semaforo buio (non funzionante) deve essere trattato come un incrocio a quattro vie: fermarsi completamente, cedere nell'ordine appropriato, poi procedere quando sicuro."},
  {cat:"safety",en:"What is the safest action when a wild animal (deer, alligator) is on the road ahead?",it:"Qual e l'azione piu sicura quando un animale selvatico (cervo, alligatore) e sulla strada davanti?",options:[{en:"Swerve sharply to miss the animal",it:"Sterzare bruscamente per evitare l'animale"},{en:"Brake firmly and stay in your lane \u2014 swerving may cause a worse crash",it:"Frenare con fermezza e rimanere nella corsia \u2014 sterzare puo causare un incidente peggiore"},{en:"Speed up to scare the animal away",it:"Accelerare per spaventare l'animale"},{en:"Flash headlights repeatedly",it:"Lampeggiare i fari ripetutamente"}],correct:1,explain_en:"Brake firmly and stay in your lane. Swerving to avoid an animal often causes more serious crashes \u2014 you may cross into oncoming traffic or roll over.",explain_it:"Frena con fermezza e rimani nella corsia. Sterzare per evitare un animale spesso causa incidenti piu gravi \u2014 potresti finire nel traffico in arrivo o ribaltarti."},
  {cat:"safety",en:"What is the purpose of 'rumble strips' on the side of a highway?",it:"Qual e lo scopo delle 'strisce vibranti' sul lato di un'autostrada?",options:[{en:"A decorative pavement feature",it:"Un elemento decorativo del manto stradale"},{en:"To alert drowsy or distracted drivers that they are drifting off the road by creating noise and vibration",it:"Per allertare i conducenti assonnati o distratti che stanno deviando dalla strada creando rumore e vibrazione"},{en:"To slow down vehicles entering a construction zone",it:"Per rallentare i veicoli che entrano in una zona di costruzione"},{en:"To mark the edge of the lane for night driving",it:"Per segnare il bordo della corsia per la guida notturna"}],correct:1,explain_en:"Rumble strips are grooved patterns on road edges or center lines that create noise and vibration when driven over \u2014 alerting drowsy or drifting drivers before they leave the roadway.",explain_it:"Le strisce vibranti sono pattern scanalati sul bordo della strada o sulle linee centrali che creano rumore e vibrazione quando si guida sopra \u2014 allertando i conducenti assonnati prima che lascino la carreggiata."},
  {cat:"safety",en:"What does Florida law require drivers to do when approaching a pedestrian in a crosswalk?",it:"Cosa richiede la legge Florida ai conducenti quando si avvicinano a un pedone in un passaggio pedonale?",options:[{en:"Slow down but need not stop if the pedestrian is on the other half of the road",it:"Rallentare ma non necessariamente fermarsi se il pedone e nell'altra meta della strada"},{en:"Stop and remain stopped until the pedestrian has completely crossed the lane the vehicle is in",it:"Fermarsi e rimanere fermo finche il pedone ha completamente attraversato la corsia in cui si trova il veicolo"},{en:"Sound the horn to alert the pedestrian to hurry",it:"Suonare il clacson per avvisare il pedone di affrettarsi"},{en:"Pass behind the pedestrian if possible",it:"Passare dietro al pedone se possibile"}],correct:1,explain_en:"Florida requires stopping for pedestrians in crosswalks. You must remain stopped until they have fully cleared the lane you are in (and adjacent lanes in some cases).",explain_it:"La Florida richiede di fermarsi per i pedoni nei passaggi pedonali. Devi rimanere fermo finche hanno completamente attraversato la corsia in cui ti trovi."},
  {cat:"safety",en:"What is the greatest risk when driving through a flooded underpass?",it:"Qual e il rischio maggiore quando si guida attraverso un sottopassaggio allagato?",options:[{en:"Hydroplaning on shallow water",it:"Acquaplaning sull'acqua poco profonda"},{en:"The water may be much deeper than it appears \u2014 even a few feet of water can sweep a car away",it:"L'acqua puo essere molto piu profonda di quanto appaia \u2014 anche pochi piedi d'acqua possono travolgere un'auto"},{en:"Electrical hazards from submerged cables",it:"Pericoli elettrici dai cavi sommersi"},{en:"The engine will flood immediately in any water",it:"Il motore si allagherebbe immediatamente in qualsiasi acqua"}],correct:1,explain_en:"Flooded underpasses are especially dangerous \u2014 depth is impossible to judge visually. Water 2 feet deep can float most cars. Turn Around, Don't Drown.",explain_it:"I sottopassaggi allagati sono particolarmente pericolosi \u2014 la profondita e impossibile da giudicare visivamente. L'acqua profonda 60 cm puo far galleggiare la maggior parte delle auto."},
  {cat:"alcohol",en:"What does alcohol do to a driver's peripheral (side) vision?",it:"Cosa fa l'alcol alla visione periferica (laterale) di un conducente?",options:[{en:"Enhances peripheral vision",it:"Migliora la visione periferica"},{en:"Reduces peripheral vision \u2014 creating 'tunnel vision' effect",it:"Riduce la visione periferica \u2014 creando un effetto di 'visione a tunnel'"},{en:"Has no effect on peripheral vision",it:"Non ha effetti sulla visione periferica"},{en:"Only affects peripheral vision at BAC above 0.15%",it:"Influisce sulla visione periferica solo con BAC superiore a 0,15%"}],correct:1,explain_en:"Alcohol reduces peripheral (side) vision, creating a tunnel-vision effect. Drivers may fail to see vehicles, pedestrians, or hazards in their side view.",explain_it:"L'alcol riduce la visione periferica (laterale), creando un effetto di visione a tunnel. I conducenti possono non vedere veicoli, pedoni o pericoli nella loro visione laterale."},
  {cat:"alcohol",en:"What effect does alcohol have on a driver's coordination?",it:"Che effetto ha l'alcol sulla coordinazione di un conducente?",options:[{en:"Improves fine motor coordination",it:"Migliora la coordinazione motoria fine"},{en:"Impairs the fine motor skills needed for steering, braking, and accelerating smoothly",it:"Compromette le abilita motorie fini necessarie per sterzare, frenare e accelerare fluidamente"},{en:"Only affects gross motor skills, not driving tasks",it:"Influisce solo sulle abilita motorie grossolane, non sui compiti di guida"},{en:"Coordination is only impaired above 0.10% BAC",it:"La coordinazione e compromessa solo sopra 0,10% BAC"}],correct:1,explain_en:"Alcohol impairs fine motor skills \u2014 the precise muscle control needed for smooth steering inputs, brake modulation, and accelerator control.",explain_it:"L'alcol compromette le abilita motorie fini \u2014 il controllo muscolare preciso necessario per gli input di sterzo fluidi, la modulazione del freno e il controllo dell'acceleratore."},
  {cat:"alcohol",en:"What is the Florida law about alcohol sales near schools?",it:"Qual e la legge Florida sulla vendita di alcol vicino alle scuole?",options:[{en:"No restriction on alcohol sales near schools",it:"Nessuna restrizione sulla vendita di alcol vicino alle scuole"},{en:"Alcohol sales within 1,000 feet of a school are generally prohibited without a special license exemption",it:"La vendita di alcol entro 1.000 piedi da una scuola e generalmente vietata senza un'esenzione speciale della licenza"},{en:"A 500-foot buffer is required",it:"E richiesto un buffer di 500 piedi"},{en:"Only bars \u2014 liquor stores may operate near schools",it:"Solo i bar \u2014 le liquorerie possono operare vicino alle scuole"}],correct:1,explain_en:"Florida Beverage Law generally prohibits new alcohol licenses within 1,000 feet of a school or house of worship \u2014 with exceptions for existing establishments and local ordinances.",explain_it:"La legge sulle bevande Florida generalmente vieta nuove licenze alcoliche entro 1.000 piedi da una scuola o luogo di culto \u2014 con eccezioni per strutture esistenti e ordinanze locali."},
  {cat:"alcohol",en:"What does research show about the effectiveness of 'designated driver' programs?",it:"Cosa mostrano le ricerche sull'efficacia dei programmi di 'conducente designato'?",options:[{en:"They are ineffective because people still drive after drinking",it:"Sono inefficaci perche le persone guidano ancora dopo aver bevuto"},{en:"They significantly reduce DUI rates when properly planned \u2014 but the driver must be truly sober, not just 'least drunk'",it:"Riducono significativamente i tassi DUI quando pianificati correttamente \u2014 ma il conducente deve essere veramente sobrio, non solo 'meno ubriaco'"},{en:"Effective only for groups of 4+ people",it:"Efficaci solo per gruppi di 4+ persone"},{en:"Only effective in urban areas",it:"Efficaci solo nelle aree urbane"}],correct:1,explain_en:"Designated driver programs work when the driver is completely sober. The concept fails when the 'designated driver' also drinks \u2014 a common but dangerous practice.",explain_it:"I programmi di conducente designato funzionano quando il conducente e completamente sobrio. Il concetto fallisce quando il 'conducente designato' beve anche lui \u2014 una pratica comune ma pericolosa."},
  {cat:"alcohol",en:"What is the effect of one standard drink on a 120 lb woman's BAC versus a 200 lb man?",it:"Qual e l'effetto di un drink standard sul BAC di una donna di 54 kg rispetto a un uomo di 90 kg?",options:[{en:"Identical \u2014 weight does not affect BAC",it:"Identico \u2014 il peso non influisce sul BAC"},{en:"The woman's BAC will be significantly higher from the same drink due to lower body water content",it:"Il BAC della donna sara significativamente piu alto dallo stesso drink a causa del minor contenuto d'acqua corporea"},{en:"The man's BAC will be higher due to higher muscle content",it:"Il BAC dell'uomo sara piu alto a causa del maggior contenuto muscolare"},{en:"Only age affects the difference, not weight",it:"Solo l'eta influisce sulla differenza, non il peso"}],correct:1,explain_en:"Body weight and water content affect BAC: a 120 lb woman reaches significantly higher BAC from one drink than a 200 lb man. Never compare your tolerance to others.",explain_it:"Il peso corporeo e il contenuto d'acqua influenzano il BAC: una donna di 54 kg raggiunge un BAC significativamente piu alto da un drink rispetto a un uomo di 90 kg."},
  {cat:"alcohol",en:"What is the Florida law about alcohol and someone who 'just feels fine to drive'?",it:"Qual e la legge Florida riguardo all'alcol e a qualcuno che 'si sente bene per guidare'?",options:[{en:"Feeling fine is a legal defense to DUI",it:"Sentirsi bene e una difesa legale al DUI"},{en:"DUI per se: if BAC is 0.08%+ you are legally impaired regardless of how you feel",it:"DUI per se: se il BAC e 0,08%+ sei legalmente compromesso indipendentemente da come ti senti"},{en:"Officers must observe visible impairment before making a DUI arrest",it:"Gli agenti devono osservare una compromissione visibile prima di effettuare un arresto DUI"},{en:"A BAC test is required before any DUI arrest can be made",it:"Un test BAC e richiesto prima che possa essere effettuato qualsiasi arresto DUI"}],correct:1,explain_en:"DUI per se means a BAC of 0.08%+ is legally conclusive proof of impairment \u2014 regardless of whether the driver feels fine, looks sober, or drives without incident.",explain_it:"DUI per se significa che un BAC di 0,08%+ e prova legalmente conclusiva di compromissione \u2014 indipendentemente dal fatto che il conducente si senta bene, sembri sobrio o guidi senza incidenti."},
  {cat:"alcohol",en:"How does food affect alcohol absorption?",it:"Come influisce il cibo sull'assorbimento dell'alcol?",options:[{en:"Food has no effect on alcohol absorption",it:"Il cibo non ha effetti sull'assorbimento dell'alcol"},{en:"Food in the stomach slows alcohol absorption, delaying peak BAC \u2014 but total alcohol consumed is the same",it:"Il cibo nello stomaco rallenta l'assorbimento dell'alcol, ritardando il BAC di picco \u2014 ma l'alcol totale consumato e lo stesso"},{en:"Food permanently prevents alcohol from entering the bloodstream",it:"Il cibo impedisce permanentemente all'alcol di entrare nel flusso sanguigno"},{en:"High-fat foods neutralize alcohol",it:"Gli alimenti ad alto contenuto di grassi neutralizzano l'alcol"}],correct:1,explain_en:"Eating before/during drinking slows the rate of alcohol absorption \u2014 delaying how fast BAC rises. However, the same total alcohol will still be absorbed eventually.",explain_it:"Mangiare prima/durante il bere rallenta la velocita di assorbimento dell'alcol \u2014 ritardando la velocita di aumento del BAC. Tuttavia, lo stesso alcol totale verra comunque assorbito eventualmente."},
  {cat:"alcohol",en:"What is the relationship between BAC and crash risk?",it:"Qual e la relazione tra BAC e rischio di incidente?",options:[{en:"Crash risk is only significantly elevated above 0.15% BAC",it:"Il rischio di incidente e significativamente elevato solo sopra 0,15% BAC"},{en:"Crash risk increases exponentially with BAC \u2014 doubling roughly every 0.02% increase",it:"Il rischio di incidente aumenta esponenzialmente con il BAC \u2014 raddoppiando approssimativamente ogni aumento di 0,02%"},{en:"Crash risk is linear \u2014 the same increase regardless of BAC level",it:"Il rischio di incidente e lineare \u2014 lo stesso aumento indipendentemente dal livello di BAC"},{en:"Only impaired drivers with prior DUI convictions have elevated crash risk",it:"Solo i conducenti compromessi con precedenti condanne DUI hanno un rischio di incidente elevato"}],correct:1,explain_en:"Crash risk is exponential: at 0.08% it is approximately 5x normal; at 0.15% it is 25x or more. Even at 0.05% crash risk is already meaningfully elevated.",explain_it:"Il rischio di incidente e esponenziale: a 0,08% e circa 5 volte la norma; a 0,15% e 25 volte o piu. Anche a 0,05% il rischio di incidente e gia significativamente elevato."},
  {cat:"alcohol",en:"What is the effect of alcohol on a driver's tracking ability?",it:"Qual e l'effetto dell'alcol sulla capacita di tracciamento di un conducente?",options:[{en:"Improves smooth tracking at low BAC",it:"Migliora il tracciamento fluido a basso BAC"},{en:"Impairs the ability to maintain lane position and track curves \u2014 even at low BAC levels",it:"Compromette la capacita di mantenere la posizione in corsia e seguire le curve \u2014 anche a bassi livelli di BAC"},{en:"Only affects tracking at BAC above 0.10%",it:"Influisce sul tracciamento solo con BAC superiore a 0,10%"},{en:"No effect on straight-line tracking",it:"Nessun effetto sul tracciamento in linea retta"}],correct:1,explain_en:"Alcohol impairs tracking \u2014 the ability to follow curves and maintain lane position. This is detectable even at 0.02% BAC, well below the legal limit.",explain_it:"L'alcol compromette il tracciamento \u2014 la capacita di seguire le curve e mantenere la posizione in corsia. Questo e rilevabile anche a 0,02% BAC, ben al di sotto del limite legale."},
  {cat:"alcohol",en:"What is the effect of alcohol on a driver's information processing?",it:"Qual e l'effetto dell'alcol sull'elaborazione delle informazioni di un conducente?",options:[{en:"Speeds up decision making",it:"Accelera il processo decisionale"},{en:"Slows the ability to process multiple inputs simultaneously \u2014 mirrors, signs, traffic, pedestrians",it:"Rallenta la capacita di elaborare piu input simultaneamente \u2014 specchi, segnali, traffico, pedoni"},{en:"Only affects verbal information processing",it:"Influisce solo sull'elaborazione delle informazioni verbali"},{en:"Processing is not affected below 0.08%",it:"L'elaborazione non e influenzata sotto 0,08%"}],correct:1,explain_en:"Alcohol reduces information processing speed and capacity \u2014 impairing multitasking, situation awareness, and decision-making quality even at low BAC levels.",explain_it:"L'alcol riduce la velocita e la capacita di elaborazione delle informazioni \u2014 compromettendo il multitasking, la consapevolezza situazionale e la qualita decisionale anche a bassi livelli di BAC."},
  {cat:"alcohol",en:"What happens to a Florida driver's license if they are convicted of DUI in another state?",it:"Cosa succede alla patente Florida di un conducente se viene condannato per DUI in un altro stato?",options:[{en:"Nothing \u2014 out-of-state convictions do not affect Florida licenses",it:"Niente \u2014 le condanne in altri stati non influenzano le patenti Florida"},{en:"Florida honors reciprocity \u2014 out-of-state DUI convictions are reported to Florida and treated as in-state",it:"La Florida onora la reciprocita \u2014 le condanne DUI in altri stati vengono segnalate alla Florida e trattate come in-state"},{en:"Only if the other state notifies Florida",it:"Solo se l'altro stato notifica la Florida"},{en:"Florida may only take action after a second out-of-state DUI",it:"La Florida puo agire solo dopo un secondo DUI fuori stato"}],correct:1,explain_en:"Through the Driver License Compact, most states share DUI conviction information. A DUI conviction in another state will be reported to Florida and may result in Florida suspension.",explain_it:"Attraverso il Driver License Compact, la maggior parte degli stati condivide le informazioni sulle condanne DUI. Una condanna DUI in un altro stato verra segnalata alla Florida e puo comportare la sospensione Florida."},
  {cat:"alcohol",en:"What is Florida's law on hosting a party where minors drink alcohol?",it:"Qual e la legge Florida sull'ospitare una festa dove i minori bevono alcol?",options:[{en:"Legal on private property",it:"Legale su proprieta privata"},{en:"Illegal \u2014 adults who knowingly allow minors to drink on their property can face criminal charges",it:"Illegale \u2014 gli adulti che permettono consapevolmente ai minori di bere sulla loro proprieta possono affrontare accuse penali"},{en:"Legal if parents are present",it:"Legale se i genitori sono presenti"},{en:"Only illegal if the minors drive afterward",it:"Illegale solo se i minori guidano dopo"}],correct:1,explain_en:"Florida's 'social host liability' law: adults who knowingly allow minors to consume alcohol on their property can face criminal charges, even if they did not directly provide the alcohol.",explain_it:"La legge sulla 'responsabilita dell'host sociale' Florida: gli adulti che permettono consapevolmente ai minori di consumare alcol sulla loro proprieta possono affrontare accuse penali."},
  {cat:"alcohol",en:"What is the relationship between alcohol and fatigue in driving impairment?",it:"Qual e la relazione tra alcol e stanchezza nella compromissione alla guida?",options:[{en:"Fatigue cancels out alcohol impairment",it:"La stanchezza annulla la compromissione da alcol"},{en:"Alcohol and fatigue compound each other \u2014 even small amounts of alcohol dramatically worsen the effects of fatigue",it:"Alcol e stanchezza si compoundano \u2014 anche piccole quantita di alcol peggiorano drammaticamente gli effetti della stanchezza"},{en:"Only one factor affects driving at a time",it:"Solo un fattore influisce sulla guida alla volta"},{en:"Coffee eliminates both fatigue and alcohol impairment",it:"Il caffe elimina sia la stanchezza che la compromissione da alcol"}],correct:1,explain_en:"Alcohol and fatigue have a synergistic effect \u2014 each amplifies the other. Even one drink when tired can impair driving as severely as several drinks when well-rested.",explain_it:"Alcol e stanchezza hanno un effetto sinergico \u2014 ognuno amplifica l'altro. Anche un drink quando si e stanchi puo compromettere la guida tanto quanto diversi drink quando si e riposati."},
  {cat:"alcohol",en:"What is Florida's 'Drug Recognition Expert' (DRE) program?",it:"Cos'e il programma Florida 'Drug Recognition Expert' (DRE)?",options:[{en:"A program for treating drug-addicted drivers",it:"Un programma per il trattamento dei conducenti tossicodipendenti"},{en:"Specially trained officers who evaluate drivers suspected of drug (non-alcohol) impairment using a standardized 12-step protocol",it:"Agenti appositamente addestrati che valutano i conducenti sospettati di compromissione da droghe (non alcol) usando un protocollo standardizzato in 12 fasi"},{en:"A drug testing program for commercial drivers only",it:"Un programma di test antidroga solo per i conducenti commerciali"},{en:"A civilian reporting program for suspected drugged drivers",it:"Un programma civile di segnalazione per i conducenti sospettati di essere drogati"}],correct:1,explain_en:"DRE officers are trained to detect impairment from drugs other than alcohol using a 12-step evaluation. Their testimony can support DUI-drug charges even without a breath test.",explain_it:"Gli agenti DRE sono addestrati per rilevare la compromissione da droghe diverse dall'alcol usando una valutazione in 12 fasi. La loro testimonianza puo supportare le accuse DUI-droga anche senza un test del respiro."},
  {cat:"alcohol",en:"At what BAC does most research show driving performance begins to noticeably degrade?",it:"A quale BAC la maggior parte delle ricerche mostra che le prestazioni alla guida iniziano a degradarsi notevolmente?",options:[{en:"0.08% \u2014 the legal limit",it:"0,08% \u2014 il limite legale"},{en:"0.05% \u2014 below the legal limit",it:"0,05% \u2014 al di sotto del limite legale"},{en:"0.10% \u2014 well above the legal limit",it:"0,10% \u2014 ben al di sopra del limite legale"},{en:"0.02% \u2014 any measurable amount",it:"0,02% \u2014 qualsiasi quantita misurabile"}],correct:1,explain_en:"Research shows measurable driving impairment beginning around 0.05% BAC. The 0.08% legal limit does not mean driving is safe below it \u2014 it is just the threshold for per se DUI.",explain_it:"Le ricerche mostrano un deterioramento misurabile della guida a partire da circa 0,05% BAC. Il limite legale di 0,08% non significa che guidare sia sicuro sotto di esso \u2014 e solo la soglia per il DUI per se."},
  {cat:"alcohol",en:"What is 'retrograde extrapolation' used for in DUI cases?",it:"Cos'e l'estrapolazione retrogradi usata nei casi DUI?",options:[{en:"Estimating a driver's BAC at the time of driving based on a later BAC test result",it:"Stimare il BAC di un conducente al momento della guida basandosi su un risultato del test BAC successivo"},{en:"A method to reduce DUI charges to reckless driving",it:"Un metodo per ridurre le accuse DUI a guida spericolata"},{en:"A technique for breath test calibration",it:"Una tecnica per la calibrazione del test del respiro"},{en:"Calculating how much alcohol someone consumed",it:"Calcolare quanta alcol ha consumato qualcuno"}],correct:0,explain_en:"Retrograde extrapolation: a forensic technique estimating what a driver's BAC was at the time of driving, based on a BAC test taken later (at arrest or hospital) and known elimination rates.",explain_it:"Estrapolazione retrograda: una tecnica forense che stima quale fosse il BAC del conducente al momento della guida, basandosi su un test BAC preso successivamente e i tassi di eliminazione noti."},
  {cat:"alcohol",en:"What is the role of a 'BAC calculator' app in preventing DUI?",it:"Qual e il ruolo di un'app 'calcolatore BAC' nella prevenzione del DUI?",options:[{en:"These apps are fully reliable for determining whether you can drive legally",it:"Queste app sono completamente affidabili per determinare se puoi guidare legalmente"},{en:"They provide rough estimates only \u2014 individual variations make them unreliable for legal driving decisions",it:"Forniscono solo stime approssimative \u2014 le variazioni individuali le rendono inaffidabili per le decisioni legali di guida"},{en:"They are certified by the NHTSA for DUI prevention",it:"Sono certificate dalla NHTSA per la prevenzione DUI"},{en:"Using such apps proves the driver was trying to drive safely",it:"Usare tali app prova che il conducente stava cercando di guidare in sicurezza"}],correct:1,explain_en:"BAC calculator apps give rough estimates based on self-reported data. Individual metabolism varies too widely to rely on them for a legal driving decision. Only a certified breathalyzer is accurate.",explain_it:"Le app calcolatrice BAC danno stime approssimative basate su dati auto-riportati. Il metabolismo individuale varia troppo ampiamente per affidarsi a loro per una decisione legale di guida."},
  {cat:"alcohol",en:"What is the difference between 'drunk driving' and 'drugged driving' under Florida DUI law?",it:"Qual e la differenza tra 'guida in stato di ebbrezza' e 'guida sotto l'effetto di droghe' nella legge DUI Florida?",options:[{en:"Only drunk driving is covered by DUI law",it:"Solo la guida in stato di ebbrezza e coperta dalla legge DUI"},{en:"Florida DUI law covers impairment by alcohol, controlled substances, OR chemical substances \u2014 same penalties apply",it:"La legge DUI Florida copre la compromissione da alcol, sostanze controllate O sostanze chimiche \u2014 si applicano le stesse sanzioni"},{en:"Drugged driving charges require a BAC test",it:"Le accuse di guida drogata richiedono un test BAC"},{en:"Drugged driving is a lesser offense than drunk driving",it:"La guida drogata e un'offesa minore rispetto alla guida in stato di ebbrezza"}],correct:1,explain_en:"Florida DUI law applies equally to impairment by alcohol, illegal drugs, prescription drugs, or chemical substances. The same penalties, tests, and procedures apply.",explain_it:"La legge DUI Florida si applica ugualmente alla compromissione da alcol, droghe illegali, farmaci da prescrizione o sostanze chimiche. Si applicano le stesse sanzioni, test e procedure."},
  {cat:"license",en:"What is the Florida 'FR-44' insurance certificate?",it:"Cos'e il certificato assicurativo Florida 'FR-44'?",options:[{en:"Standard liability insurance proof",it:"Prova standard di assicurazione di responsabilita"},{en:"High-limit insurance certificate required after DUI conviction \u2014 requires $100,000/$300,000 BI and $50,000 PDL",it:"Certificato assicurativo ad alto limite richiesto dopo una condanna DUI \u2014 richiede $100.000/$300.000 BI e $50.000 PDL"},{en:"Same as SR-22 but for motorcycles",it:"Uguale a SR-22 ma per le moto"},{en:"Proof of uninsured motorist coverage",it:"Prova di copertura automobilista non assicurato"}],correct:1,explain_en:"FR-44 is required after DUI conviction in Florida. It requires much higher liability limits ($100K/$300K bodily injury, $50K property damage) than standard SR-22, and must be maintained for 3 years.",explain_it:"FR-44 e richiesto dopo la condanna DUI in Florida. Richiede limiti di responsabilita molto piu alti ($100K/$300K lesioni corporali, $50K danni materiali) dello standard SR-22 e deve essere mantenuto per 3 anni."},
  {cat:"license",en:"What Florida driving record points are added for a speeding violation of 16-29 mph over the limit?",it:"Quanti punti vengono aggiunti al record Florida per una violazione di velocita di 16-29 mph sopra il limite?",options:[{en:"2 points",it:"2 punti"},{en:"3 points",it:"3 punti"},{en:"4 points",it:"4 punti"},{en:"6 points",it:"6 punti"}],correct:2,explain_en:"Florida point system: 3 points for speeding 15 mph or less over; 4 points for speeding 16-29 mph over; 6 points for 30+ mph over or speeding in school zone.",explain_it:"Sistema punti Florida: 3 punti per velocita fino a 15 mph sopra; 4 punti per 16-29 mph sopra; 6 punti per 30+ mph sopra o velocita in zona scolastica."},
  {cat:"license",en:"What Florida driving record points result in a mandatory 30-day license suspension?",it:"Quanti punti del record Florida comportano una sospensione obbligatoria della patente di 30 giorni?",options:[{en:"12 points in 12 months",it:"12 punti in 12 mesi"},{en:"18 points in 18 months",it:"18 punti in 18 mesi"},{en:"24 points in 36 months",it:"24 punti in 36 mesi"},{en:"Any 3 violations regardless of points",it:"Qualsiasi 3 violazioni indipendentemente dai punti"}],correct:0,explain_en:"Florida point system suspensions: 12 points in 12 months = 30-day suspension; 18 points in 18 months = 3-month suspension; 24 points in 36 months = 1-year suspension.",explain_it:"Sospensioni del sistema punti Florida: 12 punti in 12 mesi = sospensione 30 giorni; 18 punti in 18 mesi = sospensione 3 mesi; 24 punti in 36 mesi = sospensione 1 anno."},
  {cat:"license",en:"How many points does a Florida DUI conviction add to a driving record?",it:"Quanti punti aggiunge una condanna DUI Florida a un record di guida?",options:[{en:"4 points",it:"4 punti"},{en:"6 points",it:"6 punti"},{en:"DUI is handled by license revocation \u2014 not a point violation",it:"Il DUI e gestito dalla revoca della patente \u2014 non una violazione a punti"},{en:"12 points",it:"12 punti"}],correct:2,explain_en:"A DUI conviction results in license revocation \u2014 not a point addition. The revocation period depends on the offense level (1st, 2nd, 3rd+).",explain_it:"Una condanna DUI comporta la revoca della patente \u2014 non un'aggiunta di punti. Il periodo di revoca dipende dal livello dell'offesa (1\u00b0, 2\u00b0, 3\u00b0+)."},
  {cat:"license",en:"How long does a moving violation remain on a Florida driving record for point purposes?",it:"Per quanto tempo una violazione in movimento rimane su un record di guida Florida ai fini dei punti?",options:[{en:"1 year",it:"1 anno"},{en:"3 years",it:"3 anni"},{en:"5 years",it:"5 anni"},{en:"Permanently",it:"Permanentemente"}],correct:1,explain_en:"Points from moving violations remain on your Florida driving record for 3 years \u2014 affecting insurance rates and the point-based suspension thresholds.",explain_it:"I punti delle violazioni in movimento rimangono sul tuo record di guida Florida per 3 anni \u2014 influenzando le tariffe assicurative e le soglie di sospensione basate sui punti."},
  {cat:"license",en:"What is the TLSAE (Traffic Law and Substance Abuse Education) course in Florida?",it:"Cos'e il corso TLSAE (Traffic Law and Substance Abuse Education) in Florida?",options:[{en:"A course only for DUI offenders",it:"Un corso solo per i trasgressori DUI"},{en:"A required 4-hour course for first-time Florida license applicants 18 and older",it:"Un corso obbligatorio di 4 ore per i richiedenti la prima patente Florida di 18 anni e piu"},{en:"An optional safety course that reduces insurance rates",it:"Un corso di sicurezza opzionale che riduce le tariffe assicurative"},{en:"A course required after any moving violation",it:"Un corso richiesto dopo qualsiasi violazione in movimento"}],correct:1,explain_en:"TLSAE (also called Drug and Alcohol Test or DATA) is a 4-hour course required for adults (18+) applying for their first Florida license. Covers traffic laws and substance abuse effects.",explain_it:"Il TLSAE (noto anche come Drug and Alcohol Test o DATA) e un corso di 4 ore richiesto per gli adulti (18+) che richiedono la prima patente Florida. Copre le leggi del traffico e gli effetti dell'abuso di sostanze."},
  {cat:"license",en:"What is the penalty for a Florida driver who accumulates 12 points in 12 months?",it:"Qual e la sanzione per un conducente Florida che accumula 12 punti in 12 mesi?",options:[{en:"A written warning only",it:"Solo un avvertimento scritto"},{en:"30-day license suspension",it:"Sospensione della patente di 30 giorni"},{en:"6-month suspension",it:"Sospensione di 6 mesi"},{en:"Required to retake the driving test",it:"Obbligato a ripetere l'esame di guida"}],correct:1,explain_en:"12 points within 12 months = 30-day Florida license suspension. This is an administrative action by FLHSMV \u2014 separate from any court fines.",explain_it:"12 punti entro 12 mesi = sospensione della patente Florida di 30 giorni. Questa e un'azione amministrativa del FLHSMV \u2014 separata da qualsiasi multa del tribunale."},
  {cat:"license",en:"What is the Florida law on the Graduated Driver Licensing (GDL) curfew exception for employment?",it:"Qual e la legge Florida sulla eccezione al coprifuoco del Graduated Driver Licensing (GDL) per l'occupazione?",options:[{en:"No exceptions to GDL curfew",it:"Nessuna eccezione al coprifuoco GDL"},{en:"A teen with a provisional license may drive after 11 PM for employment with a signed note from employer",it:"Un adolescente con patente provvisoria puo guidare dopo le 23:00 per motivi di lavoro con una nota firmata del datore di lavoro"},{en:"Employment exceptions require a court order",it:"Le eccezioni per l'occupazione richiedono un ordine del tribunale"},{en:"Only age 17 drivers get the employment exception",it:"Solo i conducenti di 17 anni ottengono l'eccezione per l'occupazione"}],correct:1,explain_en:"Florida GDL curfew exceptions include: employment (with employer documentation), medical necessity, or driving to/from school events. Documentation must be in the vehicle.",explain_it:"Le eccezioni al coprifuoco GDL Florida includono: occupazione (con documentazione del datore di lavoro), necessita medica o guida da/verso eventi scolastici. La documentazione deve essere nel veicolo."},
  {cat:"license",en:"What is the age when Florida drivers must renew their license every 6 years (vs. 8 years for younger drivers)?",it:"Qual e l'eta in cui i conducenti Florida devono rinnovare la patente ogni 6 anni (vs. 8 anni per i conducenti piu giovani)?",options:[{en:"60 years old",it:"60 anni"},{en:"65 years old",it:"65 anni"},{en:"70 years old",it:"70 anni"},{en:"80 years old",it:"80 anni"}],correct:3,explain_en:"Florida drivers under 80 may renew every 8 years. At age 80+, renewal is required every 6 years, and must be done in person (not online) with a vision test.",explain_it:"I conducenti Florida under 80 possono rinnovare ogni 8 anni. A 80+ anni, il rinnovo e richiesto ogni 6 anni e deve essere fatto di persona (non online) con un test della visione."},
  {cat:"license",en:"What is a 'hardship reinstatement' in Florida?",it:"Cos'e un 'ripristino per necessita' in Florida?",options:[{en:"A reduced fine for low-income drivers",it:"Una multa ridotta per i conducenti a basso reddito"},{en:"A limited driving privilege granted during a suspension for essential purposes like work, school, or medical",it:"Un privilegio di guida limitato concesso durante una sospensione per scopi essenziali come lavoro, scuola o medici"},{en:"Automatic reinstatement after serving half a suspension",it:"Ripristino automatico dopo aver servito meta della sospensione"},{en:"A program only available after DUI revocations",it:"Un programma disponibile solo dopo le revoche DUI"}],correct:1,explain_en:"Hardship reinstatement allows limited driving during a suspension (BPO/EPO license) for employment, medical, or education. Requires an application, fees, and sometimes a hearing.",explain_it:"Il ripristino per necessita consente una guida limitata durante una sospensione (patente BPO/EPO) per lavoro, medici o istruzione. Richiede una domanda, quote e a volte un'udienza."},
  {cat:"license",en:"What is the Florida law on abandoned vehicles?",it:"Qual e la legge Florida sui veicoli abbandonati?",options:[{en:"Anyone can take a vehicle left on a public road",it:"Chiunque puo prendere un veicolo lasciato su una strada pubblica"},{en:"Vehicles left on public roads or property without movement for 48+ hours may be reported and towed at owner's expense",it:"I veicoli lasciati su strade o proprieta pubbliche senza movimento per 48+ ore possono essere segnalati e rimossi a spese del proprietario"},{en:"Abandoned vehicles must remain for 7 days before action",it:"I veicoli abbandonati devono rimanere 7 giorni prima di agire"},{en:"Only applies to vehicles on private property",it:"Si applica solo ai veicoli su proprieta privata"}],correct:1,explain_en:"Florida defines an abandoned vehicle as one left stationary on public property for 48+ hours without authorization. Law enforcement can have it towed at the owner's expense.",explain_it:"La Florida definisce un veicolo abbandonato come uno lasciato fermo su proprieta pubblica per 48+ ore senza autorizzazione. Le forze dell'ordine possono farlo rimorchiare a spese del proprietario."},
  {cat:"license",en:"What is required before a Florida teen (under 18) can get a learner's license?",it:"Cosa e richiesto prima che un adolescente Florida (under 18) possa ottenere il permesso per principianti?",options:[{en:"Only a vision test",it:"Solo un test della visione"},{en:"Pass a written knowledge test, vision test, and provide required documents",it:"Superare un test di conoscenza scritto, test della visione e fornire i documenti richiesti"},{en:"Complete a driver education course first",it:"Completare prima un corso di guida"},{en:"Parent or guardian must apply on their behalf",it:"Il genitore o tutore deve fare domanda per loro conto"}],correct:1,explain_en:"To get a learner's license in Florida (age 15): pass the vision test and written knowledge test, and provide required ID and residency documents at a FLHSMV office.",explain_it:"Per ottenere il permesso per principianti in Florida (eta 15): superare il test della visione e il test di conoscenza scritto e fornire i documenti di identita e residenza richiesti al FLHSMV."},
  {cat:"license",en:"What is the Florida law on minimum age for a full unrestricted Class E license?",it:"Qual e la legge Florida sull'eta minima per la patente Class E completa senza restrizioni?",options:[{en:"16 years old",it:"16 anni"},{en:"17 years old",it:"17 anni"},{en:"18 years old",it:"18 anni"},{en:"21 years old",it:"21 anni"}],correct:2,explain_en:"A full, unrestricted Florida Class E license requires age 18. Drivers 16-17 hold a provisional license with GDL restrictions that lift at age 18.",explain_it:"Una patente Florida Class E completa e senza restrizioni richiede 18 anni. I conducenti di 16-17 anni hanno una patente provvisoria con restrizioni GDL che si tolgono a 18 anni."},
  {cat:"license",en:"What is the Florida law on driving a moped without a license?",it:"Qual e la legge Florida sulla guida di un moped senza patente?",options:[{en:"Mopeds require no license",it:"I moped non richiedono patente"},{en:"A valid Florida driver's license or ID is required to operate a moped on public roads",it:"Una patente di guida Florida valida o documento d'identita e richiesto per guidare un moped su strade pubbliche"},{en:"Only a state ID card is needed",it:"E necessaria solo una carta d'identita statale"},{en:"Anyone 14+ may operate a moped",it:"Chiunque abbia 14+ anni puo guidare un moped"}],correct:1,explain_en:"To legally operate a moped (max 50cc, max 30 mph) in Florida, you need a valid driver's license or ID. No motorcycle endorsement is required.",explain_it:"Per guidare legalmente un moped (max 50cc, max 30 mph) in Florida, e necessaria una patente di guida o documento d'identita valido. Non e richiesto l'endorsement per motociclette."},
  {cat:"license",en:"What is Florida's 'point reduction' driving school benefit?",it:"Qual e il beneficio della scuola guida per la 'riduzione dei punti' in Florida?",options:[{en:"Removes all points from driving record",it:"Rimuove tutti i punti dal record di guida"},{en:"Reduces points by 3 once every 12 months (up to 5 times in your lifetime) \u2014 elected at time of ticket payment",it:"Riduce i punti di 3 una volta ogni 12 mesi (fino a 5 volte nella vita) \u2014 scelto al momento del pagamento della multa"},{en:"Guarantees insurance rate reduction",it:"Garantisce la riduzione del tasso assicurativo"},{en:"Only available for first-time violators",it:"Disponibile solo per i trasgressori per la prima volta"}],correct:1,explain_en:"Florida Basic Driver Improvement (BDI) course: completing it can reduce 3 points from your record, once per 12 months, up to 5 times lifetime. Must be elected before adjudication.",explain_it:"Il corso Florida Basic Driver Improvement (BDI): completarlo puo ridurre 3 punti dal tuo record, una volta ogni 12 mesi, fino a 5 volte nella vita. Deve essere scelto prima della giudicazione."},
  {cat:"license",en:"What is a 'Uniform Traffic Citation' (UTC) in Florida?",it:"Cos'e una 'Uniform Traffic Citation' (UTC) in Florida?",options:[{en:"A commendation for good driving",it:"Un riconoscimento per la buona guida"},{en:"The standard traffic ticket issued by Florida law enforcement \u2014 creates a court record and may add points",it:"La multa stradale standard emessa dalle forze dell'ordine Florida \u2014 crea un verbale del tribunale e puo aggiungere punti"},{en:"A warning notice with no legal effect",it:"Un avviso di avvertimento senza effetto legale"},{en:"Only issued for felony traffic violations",it:"Emessa solo per violazioni del traffico da reato"}],correct:1,explain_en:"A Uniform Traffic Citation is the standard traffic ticket in Florida. It may require a court appearance or fine payment, and points may be assessed to your driving record upon adjudication.",explain_it:"Una Uniform Traffic Citation e la multa stradale standard in Florida. Puo richiedere una comparizione in tribunale o il pagamento di una multa, e i punti possono essere aggiunti al record di guida alla giudicazione."},
  {cat:"license",en:"What is the effect of a Florida license suspension on your ability to get car insurance?",it:"Qual e l'effetto di una sospensione della patente Florida sulla capacita di ottenere l'assicurazione auto?",options:[{en:"No effect \u2014 insurance is separate from licensing",it:"Nessun effetto \u2014 l'assicurazione e separata dalla patente"},{en:"Insurers consider driving record when setting rates \u2014 suspensions increase risk classification and premiums significantly",it:"Le compagnie assicurative considerano il record di guida nel fissare le tariffe \u2014 le sospensioni aumentano significativamente la classificazione del rischio e i premi"},{en:"Insurance companies are not notified of suspensions",it:"Le compagnie assicurative non vengono notificate delle sospensioni"},{en:"Only DUI suspensions affect insurance rates",it:"Solo le sospensioni DUI influenzano le tariffe assicurative"}],correct:1,explain_en:"Insurance companies access driving records and factor in suspensions, violations, and accidents. A suspension typically results in significantly higher premiums or policy cancellation.",explain_it:"Le compagnie assicurative accedono ai record di guida e considerano sospensioni, violazioni e incidenti. Una sospensione tipicamente comporta premi significativamente piu alti o cancellazione della polizza."},

  // ══ SESSION 5 ══════════════════════════════════
  {cat:"signs",en:"What does a white rectangular sign with black text generally indicate?",it:"Cosa indica generalmente un segnale rettangolare bianco con testo nero?",options:[{en:"A warning about a hazard ahead",it:"Un avvertimento su un pericolo in avanti"},{en:"A regulatory requirement -- speed limits, turn restrictions, parking rules",it:"Un requisito normativo -- limiti di velocita, restrizioni di svolta, regole di parcheggio"},{en:"Guidance information like distances and routes",it:"Informazioni guida come distanze e percorsi"},{en:"A temporary construction zone instruction",it:"Un'istruzione temporanea per zone di costruzione"}],correct:1,explain_en:"White rectangular signs are regulatory -- they tell you what you must or must not do: speed limits, no-turn signs, parking regulations.",explain_it:"I segnali rettangolari bianchi sono normativi -- indicano cosa devi o non devi fare: limiti di velocita, divieti di svolta, regole di parcheggio."},
  {cat:"signs",en:"What does a 'Slippery When Wet' sign look like?",it:"Come appare un segnale 'Slippery When Wet'?",options:[{en:"A blue rectangle with water waves",it:"Un rettangolo blu con onde d'acqua"},{en:"A yellow diamond with a car skidding sideways",it:"Un rombo giallo con un'auto che slittava lateralmente"},{en:"An orange diamond in construction zones only",it:"Un rombo arancione solo nelle zone di costruzione"},{en:"A white rectangle with a raindrop symbol",it:"Un rettangolo bianco con un simbolo di goccia di pioggia"}],correct:1,explain_en:"Slippery When Wet is a yellow diamond with a skidding car symbol. It warns that the road surface becomes slick in wet conditions.",explain_it:"Slippery When Wet e un rombo giallo con il simbolo di un'auto che slitta. Avvisa che la superficie stradale diventa scivolosa in condizioni bagnate."},
  {cat:"signs",en:"What does a 'Low Clearance' sign on a bridge mean?",it:"Cosa significa un segnale 'Low Clearance' su un ponte?",options:[{en:"The bridge is weight-restricted",it:"Il ponte ha restrizioni di peso"},{en:"The maximum height of vehicles that may pass under",it:"L'altezza massima dei veicoli che possono passare sotto"},{en:"Reduced speed required on the bridge",it:"Velocita ridotta richiesta sul ponte"},{en:"Clearance for standard passenger cars only",it:"Libero solo per normali auto passeggeri"}],correct:1,explain_en:"Low Clearance signs display the maximum vehicle height for that underpass or bridge. Trucks and RVs must know their height and detour if necessary.",explain_it:"I segnali Low Clearance mostrano l'altezza massima del veicolo per quel sottopasso o ponte. I camion e i camper devono conoscere la loro altezza e deviare se necessario."},
  {cat:"signs",en:"What is the meaning of a 'Weight Limit' sign on a road or bridge?",it:"Qual e il significato di un segnale 'Weight Limit' su una strada o ponte?",options:[{en:"Advisory only -- heavier vehicles may proceed with caution",it:"Solo consiglio -- i veicoli piu pesanti possono procedere con cautela"},{en:"The maximum gross vehicle weight permitted",it:"Il peso massimo lordo del veicolo consentito"},{en:"Applies only to commercial trucks",it:"Si applica solo ai camion commerciali"},{en:"Applies only during rainy seasons",it:"Si applica solo durante le stagioni delle piogge"}],correct:1,explain_en:"Weight limit signs are regulatory -- exceeding the posted limit risks structural damage to the road or bridge and is a traffic violation.",explain_it:"I segnali di limite di peso sono normativi -- superare il limite segnalato rischia di danneggiare la struttura stradale o il ponte ed e una violazione del traffico."},
  {cat:"signs",en:"What does a 'Pedestrian Crossing' warning sign look like?",it:"Come appare un segnale di avvertimento 'Pedestrian Crossing'?",options:[{en:"A white rectangle with a walking figure",it:"Un rettangolo bianco con una figura che cammina"},{en:"A yellow diamond with a walking pedestrian figure",it:"Un rombo giallo con la figura di un pedone che cammina"},{en:"A green circle with footprints",it:"Un cerchio verde con impronte"},{en:"A blue rectangle with a crosswalk symbol",it:"Un rettangolo blu con il simbolo del passaggio pedonale"}],correct:1,explain_en:"Pedestrian crossing WARNING signs are yellow diamonds with a walking person symbol -- alerting drivers to expect pedestrians at or near this location.",explain_it:"I segnali di AVVERTIMENTO attraversamento pedonale sono rombi gialli con il simbolo di una persona che cammina."},
  {cat:"signs",en:"What does a 'Divided Highway Begins' sign look like?",it:"Come appare un segnale 'Divided Highway Begins'?",options:[{en:"A yellow diamond with a single line splitting into two",it:"Un rombo giallo con una linea che si divide in due"},{en:"A white rectangle with two parallel arrows",it:"Un rettangolo bianco con due frecce parallele"},{en:"A green rectangle indicating the divided road ahead",it:"Un rettangolo verde che indica la strada divisa in avanti"},{en:"A red circle prohibiting certain vehicles",it:"Un cerchio rosso che vieta certi veicoli"}],correct:0,explain_en:"Divided Highway Begins: a yellow diamond showing one line splitting into two separated roadways. Keep right -- a physical barrier or median separates lanes ahead.",explain_it:"Divided Highway Begins: un rombo giallo che mostra una linea che si divide in due carreggiate separate. Mantieniti a destra."},
  {cat:"signs",en:"What does a 'Bicycle Crossing' warning sign indicate?",it:"Cosa indica un segnale di avvertimento 'Bicycle Crossing'?",options:[{en:"A designated bicycle lane begins",it:"Inizia una corsia ciclabile designata"},{en:"Cyclists frequently cross or enter the road at this location",it:"I ciclisti attraversano spesso o entrano in strada in questo punto"},{en:"Bicycles are prohibited beyond this sign",it:"Le biciclette sono vietate oltre questo segnale"},{en:"A shared bike and pedestrian path is ahead",it:"Un percorso condiviso bici e pedoni e in avanti"}],correct:1,explain_en:"A bicycle crossing warning sign alerts drivers that cyclists may be crossing or entering the roadway -- slow down and watch for bikes.",explain_it:"Un segnale di avvertimento attraversamento ciclisti avvisa i conducenti che i ciclisti potrebbero attraversare o entrare in strada."},
  {cat:"signs",en:"What does a 'Deer Crossing' warning sign tell drivers?",it:"Cosa dice ai conducenti un segnale di avvertimento 'Deer Crossing'?",options:[{en:"Hunting is permitted in this area",it:"La caccia e consentita in questa zona"},{en:"Deer frequently cross this road -- watch for animals and slow down",it:"I cervi attraversano spesso questa strada -- fare attenzione agli animali e rallentare"},{en:"A wildlife preserve begins",it:"Inizia una riserva naturale"},{en:"Stop for deer in road",it:"Fermarsi per i cervi in strada"}],correct:1,explain_en:"Deer Crossing warning signs alert drivers to areas where deer frequently cross. Slow down especially at dawn and dusk when animals are most active.",explain_it:"I segnali di avvertimento Deer Crossing avvisano i conducenti delle zone in cui i cervi attraversano frequentemente. Rallentare specialmente all'alba e al tramonto."},
  {cat:"signs",en:"What does a 'Narrow Bridge' warning sign mean?",it:"Cosa significa un segnale di avvertimento 'Narrow Bridge'?",options:[{en:"The bridge is closed to trucks",it:"Il ponte e chiuso ai camion"},{en:"The bridge is narrower than the road -- be prepared for limited space",it:"Il ponte e piu stretto della strada -- prepararsi per lo spazio limitato"},{en:"Only one-way traffic on the bridge",it:"Solo traffico a senso unico sul ponte"},{en:"Pedestrians share the bridge",it:"I pedoni condividono il ponte"}],correct:1,explain_en:"Narrow Bridge warns that the bridge width is less than the road width. Slow down and be prepared to carefully pass oncoming traffic.",explain_it:"Narrow Bridge avvisa che la larghezza del ponte e inferiore alla larghezza della strada. Rallentare e prepararsi a passare con attenzione il traffico in senso opposto."},
  {cat:"signs",en:"What does a solid white edge line on the right side of the road indicate?",it:"Cosa indica una linea bordo bianca continua sul lato destro della strada?",options:[{en:"The beginning of a bicycle lane",it:"L'inizio di una corsia ciclabile"},{en:"The right edge of the travel lane -- do not drive to the right except to turn or stop",it:"Il bordo destro della corsia di marcia -- non guidare a destra tranne per svoltare o fermarsi"},{en:"A no-parking zone begins",it:"Inizia una zona di divieto di parcheggio"},{en:"The lane is reserved for buses",it:"La corsia e riservata agli autobus"}],correct:1,explain_en:"The solid white edge line marks the right boundary of the travel lane. Driving on the shoulder is only for stopping/turning. Crossing it to pass is prohibited.",explain_it:"La linea bordo bianca continua segna il confine destro della corsia di marcia. Guidare sulla banchina e solo per fermarsi/svoltare."},
  {cat:"laws",en:"What is Florida's default speed limit in a residential or business district when no speed limit is posted?",it:"Qual e il limite di velocita predefinito della Florida in un distretto residenziale o commerciale quando non e segnalato?",options:[{en:"25 mph",it:"25 mph"},{en:"30 mph",it:"30 mph"},{en:"35 mph",it:"35 mph"},{en:"45 mph",it:"45 mph"}],correct:1,explain_en:"Florida's default speed limit in residential and business districts (when no sign is posted) is 30 mph.",explain_it:"Il limite di velocita predefinito della Florida nei distretti residenziali e commerciali e 30 mph."},
  {cat:"laws",en:"What is the maximum speed limit on most Florida state highways?",it:"Qual e il limite massimo di velocita sulla maggior parte delle autostrade statali Florida?",options:[{en:"55 mph",it:"55 mph"},{en:"60 mph",it:"60 mph"},{en:"65 mph",it:"65 mph"},{en:"70 mph",it:"70 mph"}],correct:2,explain_en:"Most Florida state highways have a maximum speed limit of 65 mph. Interstate highways may be posted up to 70 mph.",explain_it:"La maggior parte delle autostrade statali della Florida ha un limite massimo di velocita di 65 mph. Le autostrade interstatali possono essere segnalate fino a 70 mph."},
  {cat:"laws",en:"What is the Florida law about cutting through a parking lot to avoid a traffic signal?",it:"Qual e la legge Florida sull'attraversamento di un parcheggio per evitare un semaforo?",options:[{en:"Legal if the lot is open to the public",it:"Legale se il parcheggio e aperto al pubblico"},{en:"Illegal -- it is called cornering and is a moving violation",it:"Illegale -- si chiama cornering ed e una violazione in movimento"},{en:"Legal only if no pedestrians are present",it:"Legale solo se non ci sono pedoni"},{en:"Legal for motorcycles only",it:"Legale solo per le motociclette"}],correct:1,explain_en:"Cutting through private property to avoid traffic controls is illegal in Florida -- known as improper use of private property or cornering.",explain_it:"Attraversare proprieta privata per evitare i controlli del traffico e illegale in Florida -- noto come uso improprio di proprieta privata."},
  {cat:"laws",en:"What is Florida's law on driving in the left lane on a multi-lane highway?",it:"Qual e la legge Florida sulla guida nella corsia sinistra su un'autostrada a piu corsie?",options:[{en:"You may drive in any lane at any time",it:"Puoi guidare in qualsiasi corsia in qualsiasi momento"},{en:"The left lane is for passing -- slower traffic must keep right",it:"La corsia sinistra e per il sorpasso -- il traffico piu lento deve mantenersi a destra"},{en:"The left lane is for driving at the speed limit",it:"La corsia sinistra e per guidare al limite di velocita"},{en:"Only emergency vehicles may use the left lane",it:"Solo i veicoli di emergenza possono usare la corsia sinistra"}],correct:1,explain_en:"Florida requires slower traffic to keep right. The left lane is for passing. Driving slowly in the left lane impeding traffic can be cited as a moving violation.",explain_it:"La Florida richiede che il traffico piu lento si mantenga a destra. La corsia sinistra e per il sorpasso."},
  {cat:"laws",en:"What is the Florida law on headlights when windshield wipers are in use?",it:"Qual e la legge Florida sui fari quando i tergicristalli sono in uso?",options:[{en:"Headlights are optional when wipers are used",it:"I fari sono opzionali quando i tergicristalli sono in uso"},{en:"Headlights must be on anytime windshield wipers are in use due to weather conditions",it:"I fari devono essere accesi ogni volta che i tergicristalli sono in uso a causa delle condizioni meteorologiche"},{en:"Only at night when wipers are in use",it:"Solo di notte quando i tergicristalli sono in uso"},{en:"Only on highways",it:"Solo sulle autostrade"}],correct:1,explain_en:"Florida law: when your windshield wipers are on due to rain or weather, your headlights must also be on -- even during daytime.",explain_it:"Legge Florida: quando i tergicristalli sono accesi a causa della pioggia, anche i fari devono essere accesi -- anche durante il giorno."},
  {cat:"laws",en:"What is the Florida law about driving on a sidewalk?",it:"Qual e la legge Florida sulla guida su un marciapiede?",options:[{en:"Legal if pedestrians are not present",it:"Legale se i pedoni non sono presenti"},{en:"Illegal -- a driver may only cross a sidewalk when entering or exiting a driveway",it:"Illegale -- un conducente puo attraversare un marciapiede solo quando entra o esce da un vialetto"},{en:"Legal for bicycles but not motor vehicles",it:"Legale per le biciclette ma non per i veicoli a motore"},{en:"Legal for emergencies only",it:"Legale solo per le emergenze"}],correct:1,explain_en:"Driving on a sidewalk is illegal in Florida. A vehicle may cross a sidewalk only when entering or exiting a driveway -- yielding to pedestrians.",explain_it:"Guidare su un marciapiede e illegale in Florida. Un veicolo puo attraversare un marciapiede solo quando entra/esce da un vialetto -- cedendo ai pedoni."},
  {cat:"laws",en:"In Florida, how close to a driveway may you park?",it:"In Florida, quanto vicino a un vialetto puoi parcheggiare?",options:[{en:"Right next to it if on the correct side",it:"Proprio accanto se sul lato corretto"},{en:"No parking within 20 feet of a driveway entrance",it:"Nessun parcheggio entro 20 piedi dall'ingresso di un vialetto"},{en:"No parking within 10 feet of a driveway",it:"Nessun parcheggio entro 10 piedi da un vialetto"},{en:"No restriction if it does not block traffic",it:"Nessuna restrizione se non blocca il traffico"}],correct:1,explain_en:"Florida prohibits parking within 20 feet of a driveway entrance -- this ensures vehicles can see approaching traffic.",explain_it:"La Florida vieta il parcheggio entro 20 piedi dall'ingresso di un vialetto."},
  {cat:"laws",en:"What is the Florida law about making a turn from a multi-lane road?",it:"Qual e la legge Florida sulle svolte da una strada a piu corsie?",options:[{en:"Turn from any lane as long as you signal",it:"Svoltare da qualsiasi corsia purche si segnali"},{en:"Begin and complete turns from the lane nearest the direction of the turn",it:"Iniziare e completare le svolte dalla corsia piu vicina alla direzione della svolta"},{en:"Always turn from the rightmost lane",it:"Svoltare sempre dalla corsia piu a destra"},{en:"Turn from the center lane for all turns",it:"Svoltare dalla corsia centrale per tutte le svolte"}],correct:1,explain_en:"For turns: right turns from the rightmost lane into the rightmost lane; left turns from the leftmost lane into the leftmost lane.",explain_it:"Per le svolte: svolte destra dalla corsia piu a destra nella corsia piu a destra; svolte sinistra dalla corsia piu a sinistra."},
  {cat:"laws",en:"What is the Florida law about children under 5 and car seats?",it:"Qual e la legge Florida sui bambini sotto i 5 anni e i seggiolini auto?",options:[{en:"Car seats are optional if a seat belt fits",it:"I seggiolini sono opzionali se la cintura si adatta"},{en:"Children under 5 must be restrained in a federally approved child restraint device",it:"I bambini sotto i 5 anni devono essere trattenuti in un dispositivo di ritenuta approvato"},{en:"Only children under 3 require a car seat",it:"Solo i bambini sotto i 3 anni richiedono un seggiolino auto"},{en:"Children under 5 must sit in the back seat only",it:"I bambini sotto i 5 anni devono sedere solo nel sedile posteriore"}],correct:1,explain_en:"Florida requires children under 5 to be secured in a federally approved child restraint device.",explain_it:"La Florida richiede ai bambini sotto i 5 anni di essere assicurati in un dispositivo di ritenuta per bambini approvato federalmente."},
  {cat:"laws",en:"What is the Florida law about parking on a bridge?",it:"Qual e la legge Florida sul parcheggio su un ponte?",options:[{en:"Parking on bridges is permitted if the bridge has a shoulder",it:"Il parcheggio sui ponti e consentito se il ponte ha una banchina"},{en:"Parking on a bridge or overpass is prohibited",it:"Il parcheggio su un ponte o cavalcavia e vietato"},{en:"Parking allowed on bridges outside city limits",it:"Parcheggio consentito sui ponti fuori dai limiti della citta"},{en:"Parking for 15 minutes is allowed on any bridge",it:"Il parcheggio per 15 minuti e consentito su qualsiasi ponte"}],correct:1,explain_en:"Florida prohibits parking on bridges, overpasses, or in tunnels. These locations create dangerous conditions for other drivers.",explain_it:"La Florida vieta il parcheggio su ponti, cavalcavia o in gallerie."},
  {cat:"laws",en:"What must you do if involved in a crash that results in injury or death?",it:"Cosa devi fare se coinvolto in un incidente che provoca lesioni o morte?",options:[{en:"Wait for police to arrive before doing anything",it:"Aspettare l'arrivo della polizia prima di fare qualsiasi cosa"},{en:"Remain at the scene, render aid, call 911, and give your information to police",it:"Rimanere sulla scena, prestare soccorso, chiamare il 911 e dare le tue informazioni alla polizia"},{en:"Move vehicles immediately to prevent traffic backup",it:"Spostare immediatamente i veicoli per prevenire ingorghi"},{en:"Photograph the scene and leave to find a phone",it:"Fotografare la scena e andarsene per trovare un telefono"}],correct:1,explain_en:"After a crash with injury or death: stay at the scene, render reasonable aid, call 911, exchange information, and cooperate with law enforcement.",explain_it:"Dopo un incidente con lesioni o morte: rimanere sulla scena, prestare assistenza, chiamare il 911, scambiare informazioni e cooperare con le forze dell'ordine."},
  {cat:"laws",en:"What is the fine range for a first-time red-light camera violation in Florida?",it:"Qual e la gamma delle multe per una prima violazione della telecamera al semaforo rosso in Florida?",options:[{en:"$50",it:"$50"},{en:"$158 (non-moving) or $277 if escalated",it:"$158 (non in movimento) o $277 se escalato"},{en:"$300 flat",it:"$300 fisso"},{en:"$500",it:"$500"}],correct:1,explain_en:"Florida red-light camera violations: $158 if paid within 30 days. If contested or unpaid, it becomes $277 as a Uniform Traffic Citation.",explain_it:"Violazioni telecamera semaforo rosso Florida: $158 se pagate entro 30 giorni. Se si contesta, aumenta a $277 come Uniform Traffic Citation."},
  {cat:"laws",en:"What is required by Florida law when you hear a siren but cannot see the emergency vehicle?",it:"Cosa richiede la legge Florida quando senti una sirena ma non vedi il veicolo di emergenza?",options:[{en:"Maintain speed until you can see it",it:"Mantenere la velocita fino a quando puoi vederlo"},{en:"Immediately pull to the right and stop",it:"Accostare immediatamente a destra e fermarsi"},{en:"Only yield once the vehicle is visible",it:"Cedere solo quando il veicolo e visibile"},{en:"Slow to 25 mph and look for the vehicle",it:"Rallentare a 25 mph e cercare il veicolo"}],correct:1,explain_en:"When you hear an emergency siren: immediately pull to the right and stop -- even if you cannot see the vehicle.",explain_it:"Quando senti una sirena di emergenza: accosta immediatamente a destra e fermati -- anche se non riesci a vedere il veicolo."},
  {cat:"laws",en:"What is Florida's 'no fault' insurance system?",it:"Cos'e il sistema assicurativo 'no fault' della Florida?",options:[{en:"You cannot sue anyone after a car accident",it:"Non puoi citare in giudizio nessuno dopo un incidente"},{en:"Your own PIP insurance pays your medical bills regardless of who caused the accident",it:"La tua assicurazione PIP paga le tue spese mediche indipendentemente da chi ha causato l'incidente"},{en:"No one is at fault in any Florida accident",it:"Nessuno e in colpa in nessun incidente Florida"},{en:"Insurance companies cannot raise rates after accidents",it:"Le compagnie assicurative non possono aumentare le tariffe dopo gli incidenti"}],correct:1,explain_en:"Florida is a no-fault state: your own PIP covers your injuries up to $10,000 regardless of fault.",explain_it:"La Florida e uno stato no-fault: il tuo PIP copre le tue lesioni fino a $10.000 indipendentemente dalla colpa."},
  {cat:"laws",en:"What is the Florida law about parking in front of a public or private driveway?",it:"Cosa dice la legge Florida sul parcheggio davanti a un vialetto?",options:[{en:"Legal for up to 30 minutes",it:"Legale fino a 30 minuti"},{en:"Illegal -- do not park in a way that blocks any driveway",it:"Illegale -- non parcheggiare bloccando qualsiasi vialetto"},{en:"Legal if the driveway owner gives permission",it:"Legale se il proprietario del vialetto da il permesso"},{en:"Legal only on weekends",it:"Legale solo nei fine settimana"}],correct:1,explain_en:"Florida prohibits parking in front of or blocking a public or private driveway. Violators may be ticketed or towed.",explain_it:"La Florida vieta il parcheggio davanti o che blocca un vialetto. I trasgressori possono essere multati o rimossi."},
  {cat:"laws",en:"What is the Florida law on bicyclists riding on the road?",it:"Qual e la legge Florida sui ciclisti che circolano sulla strada?",options:[{en:"Bicyclists must always use the sidewalk",it:"I ciclisti devono sempre usare il marciapiede"},{en:"Bicyclists have the same rights and duties as motor vehicle drivers",it:"I ciclisti hanno gli stessi diritti e doveri dei conducenti di veicoli a motore"},{en:"Bicyclists must ride on the shoulder only",it:"I ciclisti devono andare solo sulla banchina"},{en:"Bicycles are not allowed on roads above 25 mph",it:"Le biciclette non sono consentite sulle strade sopra i 25 mph"}],correct:1,explain_en:"In Florida, bicyclists have the same legal rights and responsibilities as motor vehicle drivers. They may ride in the travel lane and must follow all traffic laws.",explain_it:"In Florida, i ciclisti hanno gli stessi diritti e responsabilita legali dei conducenti di veicoli a motore."},
  {cat:"laws",en:"In Florida, when is it legal to pass a vehicle on a two-lane road?",it:"In Florida, quando e legale sorpassare un veicolo su una strada a due corsie?",options:[{en:"Whenever you can see 500 feet ahead",it:"Ogni volta che puoi vedere 500 piedi avanti"},{en:"When the center line on your side is dashed, you have adequate sight distance, and it is safe",it:"Quando la linea centrale sul tuo lato e tratteggiata, hai visibilita adeguata ed e sicuro"},{en:"Only if the vehicle ahead is going 15 mph below the limit",it:"Solo se il veicolo davanti sta andando a 15 mph sotto il limite"},{en:"At any time as long as you signal",it:"In qualsiasi momento purche segnali"}],correct:1,explain_en:"Passing on a two-lane road is legal when the dashed center line is on your side, you have adequate visibility, and it is safe.",explain_it:"Il sorpasso su una strada a due corsie e legale quando la linea centrale tratteggiata e sul tuo lato, hai visibilita adeguata ed e sicuro."},
  {cat:"laws",en:"In Florida, how far from a crosswalk must you stop when required?",it:"In Florida, a quanta distanza da un attraversamento pedonale devi fermarti?",options:[{en:"At the crosswalk line",it:"Alla linea dell'attraversamento"},{en:"Before the stop line or within 20 feet of the crosswalk if no line",it:"Prima della linea di stop o entro 20 piedi dall'attraversamento se non c'e linea"},{en:"At least 50 feet from any crosswalk",it:"Almeno 50 piedi da qualsiasi attraversamento"},{en:"At the front edge of the crosswalk",it:"Al bordo anteriore dell'attraversamento"}],correct:1,explain_en:"Stop before the marked stop line. Where there is no stop line, stop within 20 feet of a crosswalk.",explain_it:"Fermarsi prima della linea di stop segnata. Dove non c'e linea di stop, fermarsi entro 20 piedi da un attraversamento pedonale."},
  {cat:"laws",en:"What is the Florida 3-foot passing law for bicycles?",it:"Qual e la legge Florida dei 3 piedi di sorpasso per le biciclette?",options:[{en:"Honk to alert the cyclist you want to pass",it:"Suonare il clacson per avvisare il ciclista"},{en:"Allow at least 3 feet of clearance when passing a bicycle",it:"Consentire almeno 3 piedi di distanza quando si sorpassa una bicicletta"},{en:"Follow at 2 seconds distance",it:"Seguire a 2 secondi di distanza"},{en:"Bicycles must yield to motor vehicles at all times",it:"Le biciclette devono sempre cedere ai veicoli a motore"}],correct:1,explain_en:"Florida's 3-foot passing law requires motor vehicles to give cyclists at least 3 feet of clearance when passing.",explain_it:"La legge dei 3 piedi di sorpasso della Florida richiede ai veicoli a motore di dare ai ciclisti almeno 3 piedi di distanza quando li sorpassano."},
  {cat:"laws",en:"What is the Florida law on parking in a disabled space without a valid permit?",it:"Qual e la legge Florida sul parcheggio in uno spazio disabili senza un permesso valido?",options:[{en:"Anyone can use it if it is the only space available",it:"Chiunque puo usarlo se e l'unico posto disponibile"},{en:"Only vehicles with a valid disability permit or plate may park there",it:"Solo i veicoli con un permesso o targa di disabilita validi possono parcheggiare"},{en:"Legal for 15 minutes for any vehicle",it:"Legale per 15 minuti per qualsiasi veicolo"},{en:"Only vehicles carrying a disabled person at that moment",it:"Solo i veicoli che trasportano una persona disabile in quel momento"}],correct:1,explain_en:"Parking in a disabled space without a valid placard or disability license plate is a serious violation in Florida -- fines start at $250.",explain_it:"Parcheggiare in uno spazio disabili senza permesso valido e una grave violazione in Florida -- le multe iniziano da $250."},
  {cat:"laws",en:"What is the Florida law about driving with an expired registration?",it:"Qual e la legge Florida sulla guida con una registrazione scaduta?",options:[{en:"No penalty if less than 30 days expired",it:"Nessuna sanzione se scaduta da meno di 30 giorni"},{en:"A non-criminal traffic infraction with fines",it:"Un'infrazione stradale non penale con multe"},{en:"A criminal offense requiring court appearance",it:"Un reato penale che richiede comparizione in tribunale"},{en:"No law -- registration expiration is not enforced",it:"Nessuna legge -- la scadenza della registrazione non e applicata"}],correct:1,explain_en:"Driving with expired registration is a non-criminal infraction in Florida. Fines start at $25 late fee plus registration cost.",explain_it:"Guidare con registrazione scaduta e un'infrazione non penale in Florida. Le multe iniziano con una mora di $25."},
  {cat:"laws",en:"What is Florida's law on the use of turn signals for lane changes on a highway?",it:"Qual e la legge Florida sull'uso dei segnali di svolta per i cambi di corsia in autostrada?",options:[{en:"Signals are not required on highways",it:"I segnali non sono richiesti in autostrada"},{en:"Signal at least 200 feet before any lane change",it:"Segnalare almeno 200 piedi prima di qualsiasi cambio di corsia"},{en:"Signal only if other vehicles are nearby",it:"Segnalare solo se altri veicoli sono nelle vicinanze"},{en:"Signal only when changing from the right lane",it:"Segnalare solo quando si cambia dalla corsia destra"}],correct:1,explain_en:"Florida requires signaling at least 200 feet before a lane change on limited access highways (100 feet on other roads).",explain_it:"La Florida richiede di segnalare almeno 200 piedi prima di un cambio di corsia sulle autostrade."},
  {cat:"laws",en:"When can a Florida driver legally make a U-turn?",it:"Quando puo un conducente Florida eseguire legalmente un'inversione di marcia?",options:[{en:"Never -- U-turns are always illegal",it:"Mai -- le inversioni di marcia sono sempre illegali"},{en:"When permitted by sign or signal and it can be done safely without interfering with traffic",it:"Quando consentito da un segnale e puo essere eseguito in sicurezza senza interferire con il traffico"},{en:"Only at intersections with traffic lights",it:"Solo agli incroci con semafori"},{en:"Only on roads with a posted speed limit under 35 mph",it:"Solo su strade con limite di velocita inferiore a 35 mph"}],correct:1,explain_en:"U-turns are permitted in Florida where not prohibited by sign and when they can be completed safely. They are prohibited in many locations including near hills, curves, and intersections.",explain_it:"Le inversioni di marcia sono consentite in Florida dove non proibite da segnale e quando possono essere completate in sicurezza."},
  {cat:"safety",en:"What is the primary purpose of defensive driving?",it:"Qual e lo scopo principale della guida difensiva?",options:[{en:"To drive as fast as possible while avoiding tickets",it:"Guidare il piu veloce possibile evitando le multe"},{en:"To anticipate hazards and the mistakes of other drivers",it:"Anticipare i pericoli e gli errori degli altri conducenti"},{en:"To defend your right of way aggressively",it:"Difendere il tuo diritto di precedenza in modo aggressivo"},{en:"To always drive below the speed limit",it:"Guidare sempre sotto il limite di velocita"}],correct:1,explain_en:"Defensive driving means anticipating hazards, maintaining awareness, and being prepared for others' mistakes -- proactively reducing risk.",explain_it:"La guida difensiva significa anticipare i pericoli, mantenere la consapevolezza ed essere preparati per gli errori degli altri."},
  {cat:"safety",en:"What does 'brake fade' mean?",it:"Cosa significa 'brake fade'?",options:[{en:"When brake pads wear thin",it:"Quando le pastiglie dei freni si assottigliano"},{en:"Reduction in braking effectiveness due to heat buildup from repeated braking",it:"Riduzione dell'efficacia frenante a causa dell'accumulo di calore"},{en:"When the brake fluid level is low",it:"Quando il livello del fluido dei freni e basso"},{en:"The gradual fading of brake light intensity",it:"La graduale dissolvenza dell'intensita delle luci dei freni"}],correct:1,explain_en:"Brake fade occurs when brakes overheat -- reducing stopping power. Common on long downhill grades. Prevention: use lower gears to engine-brake.",explain_it:"Il brake fade si verifica quando i freni si surriscaldano -- riducendo il potere frenante. Comune in lunghe discese. Prevenzione: usare marce piu basse."},
  {cat:"safety",en:"What is the correct technique for driving through a sharp curve?",it:"Qual e la tecnica corretta per guidare in una curva stretta?",options:[{en:"Brake during the curve to maintain control",it:"Frenare durante la curva per mantenere il controllo"},{en:"Brake before the curve, ease off gas, steer smoothly, then gently accelerate out",it:"Frenare prima della curva, togliere il gas, sterzare fluidamente, poi accelerare in uscita"},{en:"Accelerate before entering to carry speed through",it:"Accelerare prima di entrare per mantenere la velocita"},{en:"Apply the parking brake slightly to control speed",it:"Applicare leggermente il freno a mano per controllare la velocita"}],correct:1,explain_en:"Proper curve technique: slow BEFORE the curve, ease off gas entering, steer smoothly through, then gently accelerate as you exit. Braking in a curve can cause loss of control.",explain_it:"Tecnica corretta per le curve: rallentare PRIMA della curva, togliere il gas in entrata, sterzare fluidamente, poi accelerare delicatamente in uscita."},
  {cat:"safety",en:"What is the effect of low tire pressure on vehicle handling?",it:"Qual e l'effetto della bassa pressione degli pneumatici sulla maniabilita?",options:[{en:"Improves grip on wet roads",it:"Migliora la presa sulle strade bagnate"},{en:"Reduces steering response, increases blowout risk, and increases stopping distance",it:"Riduce la risposta dello sterzo, aumenta il rischio di foratura e aumenta la distanza di frenata"},{en:"Has no effect on modern vehicles with TPMS",it:"Non ha effetti sui veicoli moderni con TPMS"},{en:"Only affects highway driving",it:"Influisce solo sulla guida in autostrada"}],correct:1,explain_en:"Low tire pressure: reduces fuel efficiency, impairs handling and steering, increases heat buildup (blowout risk), and increases stopping distance.",explain_it:"Bassa pressione degli pneumatici: riduce l'efficienza del carburante, compromette la maniabilita e lo sterzo, aumenta il rischio di foratura e la distanza di frenata."},
  {cat:"safety",en:"What should you do if your vehicle begins to overheat?",it:"Cosa dovresti fare se il tuo veicolo inizia a surriscaldarsi?",options:[{en:"Speed up to increase airflow to the engine",it:"Accelerare per aumentare il flusso d'aria al motore"},{en:"Turn off A/C, turn on heater, pull over safely and let it cool",it:"Spegnere l'A/C, accendere il riscaldamento, accostare in sicurezza e lasciarlo raffreddare"},{en:"Add cold water to the radiator immediately",it:"Aggiungere acqua fredda al radiatore immediatamente"},{en:"Continue driving to the nearest service station",it:"Continuare a guidare fino alla stazione di servizio piu vicina"}],correct:1,explain_en:"Overheating: turn off A/C, turn on heater (draws heat from coolant), pull over safely to cool. Never open a hot radiator cap -- steam burns.",explain_it:"Surriscaldamento: spegni l'A/C, accendi il riscaldamento, accosta in sicurezza per far raffreddare. Non aprire mai un tappo del radiatore caldo."},
  {cat:"safety",en:"What is the greatest danger of sudden lane changes without checking blind spots?",it:"Qual e il pericolo maggiore dei cambi di corsia improvvisi senza controllare i punti ciechi?",options:[{en:"Reduced fuel efficiency",it:"Ridotta efficienza del carburante"},{en:"Side-impact collision with a vehicle in the blind spot",it:"Collisione laterale con un veicolo nel punto cieco"},{en:"Activation of the ABS",it:"Attivazione dell'ABS"},{en:"Increased wear on tires",it:"Aumento dell'usura degli pneumatici"}],correct:1,explain_en:"Failing to check blind spots before lane changes is a leading cause of side-impact crashes. Always mirror-check AND shoulder check before every lane change.",explain_it:"Non controllare i punti ciechi prima dei cambi di corsia e una delle principali cause di incidenti laterali. Controllare sempre gli specchi E la spalla."},
  {cat:"safety",en:"What is the two-second rule for following distance?",it:"Cos'e la regola dei due secondi per la distanza di seguimento?",options:[{en:"Leave 2 car lengths between you and the vehicle ahead",it:"Lasciare 2 lunghezze auto tra te e il veicolo davanti"},{en:"When the vehicle ahead passes a fixed point, at least 2 seconds should pass before you reach it",it:"Quando il veicolo davanti passa un punto fisso, dovrebbero passare almeno 2 secondi prima che tu lo raggiunga"},{en:"Brake 2 seconds before any intersection",it:"Frenare 2 secondi prima di qualsiasi incrocio"},{en:"Check mirrors every 2 seconds",it:"Controllare gli specchi ogni 2 secondi"}],correct:1,explain_en:"Two-second rule: when the car ahead passes a fixed object, count two seconds before you pass it. Increase to 4+ seconds in poor conditions.",explain_it:"Regola dei due secondi: quando l'auto davanti supera un oggetto fisso, conta due secondi prima che tu lo superi. Aumenta a 4+ secondi in condizioni di scarsa visibilita."},
  {cat:"safety",en:"Why is it dangerous to drive with your left foot resting on the brake pedal?",it:"Perche e pericoloso guidare con il piede sinistro appoggiato sul pedale del freno?",options:[{en:"It is ergonomically uncomfortable",it:"E ergonomicamente scomodo"},{en:"It heats brakes, reduces effectiveness, and confuses drivers behind",it:"Scalda i freni, riduce l'efficacia e confonde i conducenti dietro"},{en:"It depletes brake fluid faster",it:"Esaurisce il fluido dei freni piu velocemente"},{en:"Left-foot braking is illegal in Florida",it:"La frenata con il piede sinistro e illegale in Florida"}],correct:1,explain_en:"Resting on the brake heats pads causing fade, keeps brake lights on confusing following drivers, and reduces braking effectiveness.",explain_it:"Appoggiarsi al freno scalda le pastiglie causando surriscaldamento, mantiene le luci dei freni accese confondendo i conducenti che seguono."},
  {cat:"safety",en:"What is the safest lane to drive in on a three-lane highway?",it:"Qual e la corsia piu sicura per guidare su un'autostrada a tre corsie?",options:[{en:"The leftmost lane",it:"La corsia piu a sinistra"},{en:"The center lane -- fewer merges and exits than right, less passing pressure than left",it:"La corsia centrale -- meno confluenze della destra, meno pressione della sinistra"},{en:"The rightmost lane",it:"La corsia piu a destra"},{en:"Rotate between all three lanes",it:"Ruotare tra tutte e tre le corsie"}],correct:1,explain_en:"The center lane on a 3-lane highway is generally safest: fewer merging vehicles than the right and fewer fast passes than the left.",explain_it:"La corsia centrale su un'autostrada a 3 corsie e generalmente la piu sicura."},
  {cat:"safety",en:"What is the most important thing to do before a long road trip?",it:"Qual e la cosa piu importante da fare prima di un lungo viaggio?",options:[{en:"Program your GPS",it:"Programmare il GPS"},{en:"Inspect the vehicle: tires, fluids, brakes, lights, and ensure you are well rested",it:"Ispezionare il veicolo: pneumatici, fluidi, freni, luci e assicurarsi di essere ben riposati"},{en:"Fill the gas tank only",it:"Fare solo il pieno di carburante"},{en:"Download offline maps",it:"Scaricare mappe offline"}],correct:1,explain_en:"Pre-trip inspection: check tires, oil and coolant, brakes, lights, and windshield wipers. Most importantly, ensure you are well rested.",explain_it:"Ispezione pre-viaggio: controlla pneumatici, olio e refrigerante, freni, luci e tergicristalli. La cosa piu importante: assicurati di essere ben riposato."},
  {cat:"safety",en:"What is the proper use of hazard lights while driving slowly on a highway?",it:"Qual e l'uso corretto delle luci di pericolo durante la guida lenta su un'autostrada?",options:[{en:"Always recommended when driving slowly",it:"Sempre raccomandato quando si guida lentamente"},{en:"Not recommended while moving -- they mask turn signals and confuse other drivers",it:"Non raccomandato mentre ci si muove -- mascherano i segnali di svolta e confondono gli altri conducenti"},{en:"Required by Florida law when below 45 mph",it:"Richiesto dalla legge Florida quando si e sotto i 45 mph"},{en:"Required in all construction zones",it:"Richiesto in tutte le zone di costruzione"}],correct:1,explain_en:"Hazard lights while driving are not recommended -- they hide turn signals. They should only be used when stopped or as a traffic hazard warning.",explain_it:"Le luci di pericolo durante la guida sono sconsigliate -- nascondono i segnali di svolta. Dovrebbero essere usate solo quando fermi o come avvertimento di pericolo."},
  {cat:"safety",en:"What is the best way to handle an aggressive driver who is tailgating?",it:"Qual e il modo migliore per gestire un conducente aggressivo che segue troppo da vicino?",options:[{en:"Speed up to put distance between you",it:"Accelerare per mettere distanza tra voi"},{en:"Safely move over and let them pass -- do not engage or escalate",it:"Spostarsi in sicurezza e lasciarli passare -- non impegnarsi o aggravare"},{en:"Brake suddenly to make them back off",it:"Frenare improvvisamente per farli indietreggiare"},{en:"Match their aggression",it:"Corrispondere alla loro aggressivita"}],correct:1,explain_en:"Aggressive driver response: move over calmly and let them pass. Do not engage, brake check, or make eye contact. Road rage can turn deadly.",explain_it:"Risposta al conducente aggressivo: spostarsi con calma e lasciarli passare. Non impegnarsi, controllare i freni o fare contatto visivo."},
  {cat:"safety",en:"What is the effect of driving while under the influence of marijuana on reaction time?",it:"Qual e l'effetto sulla guida sotto l'influenza della marijuana sul tempo di reazione?",options:[{en:"No effect -- marijuana does not impair driving",it:"Nessun effetto -- la marijuana non compromette la guida"},{en:"Marijuana impairs reaction time, judgment, and tracking",it:"La marijuana compromette il tempo di reazione, il giudizio e il tracciamento"},{en:"Only impairs driving in high doses",it:"Compromette la guida solo in dosi elevate"},{en:"Marijuana slightly improves focus at low doses",it:"La marijuana migliora leggermente la concentrazione a basse dosi"}],correct:1,explain_en:"Marijuana impairs driving: reduces reaction time, impairs lane tracking, distorts time/distance perception. DUI-drug laws apply in Florida.",explain_it:"La marijuana compromette la guida: riduce il tempo di reazione, compromette il tracciamento di corsia. Si applicano le leggi DUI-droga in Florida."},
  {cat:"safety",en:"What is the Florida law on the use of earphones while driving?",it:"Qual e la legge Florida sull'uso di auricolari durante la guida?",options:[{en:"Completely prohibited for all drivers",it:"Completamente vietato per tutti i conducenti"},{en:"A headset covering both ears is prohibited -- one ear is legal for non-CDL drivers",it:"Un auricolare che copre entrambe le orecchie e vietato -- un orecchio e legale per i conducenti non CDL"},{en:"Earphones are always legal while driving",it:"Gli auricolari sono sempre legali durante la guida"},{en:"Only illegal for motorcycle riders",it:"Illegale solo per i motociclisti"}],correct:1,explain_en:"Florida prohibits wearing a headset covering BOTH ears while driving a motor vehicle. One ear is permitted. CDL holders may not use any headset.",explain_it:"La Florida vieta di indossare cuffie che coprono ENTRAMBE le orecchie durante la guida. Un orecchio e consentito. I titolari CDL non possono usare alcuna cuffia."},
  {cat:"safety",en:"What should you do if a traffic light is completely dark?",it:"Cosa dovresti fare se un semaforo e completamente buio?",options:[{en:"Proceed normally -- assume it is green",it:"Procedere normalmente -- supponi che sia verde"},{en:"Treat it as a four-way stop",it:"Trattarlo come un incrocio a quattro vie"},{en:"Only stop if other vehicles are present",it:"Fermarsi solo se altri veicoli sono presenti"},{en:"Turn around and find another route",it:"Girare indietro e trovare un altro percorso"}],correct:1,explain_en:"A dark non-functioning traffic light should be treated as a four-way stop: stop completely, yield in the appropriate order, then proceed when safe.",explain_it:"Un semaforo buio deve essere trattato come un incrocio a quattro vie: fermarsi completamente, cedere nell'ordine appropriato, poi procedere."},
  {cat:"safety",en:"Why is passing a large truck on the right especially dangerous?",it:"Perche e particolarmente pericoloso sorpassare un camion grande a destra?",options:[{en:"Trucks always merge right",it:"I camion confluiscono sempre a destra"},{en:"The right rear blind spot extends much farther -- the truck driver cannot see you",it:"Il punto cieco posteriore destro si estende molto piu lontano -- il camionista non puo vederti"},{en:"Trucks are required to travel in the right lane",it:"I camion sono obbligati a viaggiare nella corsia destra"},{en:"It is not particularly dangerous",it:"Non e particolarmente pericoloso"}],correct:1,explain_en:"The right rear No-Zone of a truck extends up to 30 feet back. Passing on the right is the most dangerous position because the driver has the least visibility there.",explain_it:"La No-Zone posteriore destra di un camion si estende fino a 30 piedi. Sorpassare a destra e la posizione piu pericolosa."},
  {cat:"alcohol",en:"What effect does alcohol have on a driver's ability to judge distances?",it:"Che effetto ha l'alcol sulla capacita di valutare le distanze?",options:[{en:"Improves depth perception",it:"Migliora la percezione della profondita"},{en:"Impairs depth perception making gaps seem larger and objects farther away",it:"Compromette la percezione della profondita facendo sembrare i gap piu grandi e gli oggetti piu lontani"},{en:"Has no effect on distance perception",it:"Non ha effetti sulla percezione della distanza"},{en:"Only affects distance judgment above 0.15% BAC",it:"Influisce solo sopra 0,15% BAC"}],correct:1,explain_en:"Alcohol distorts depth perception and distance judgment -- drivers misjudge following distances and oncoming traffic speeds.",explain_it:"L'alcol distorce la percezione della profondita e il giudizio della distanza -- i conducenti valutano male le distanze di seguimento."},
  {cat:"alcohol",en:"What is polydrug use and why is it especially dangerous for driving?",it:"Cos'e l'uso polidroga e perche e particolarmente pericoloso per la guida?",options:[{en:"Using two types of prescription medications",it:"Usare due tipi di farmaci da prescrizione"},{en:"Combining alcohol with other drugs -- effects multiply rather than add",it:"Combinare l'alcol con altre droghe -- gli effetti si moltiplicano"},{en:"Taking vitamins with alcohol",it:"Assumere vitamine con l'alcol"},{en:"Using caffeine to counteract alcohol",it:"Usare la caffeina per contrastare l'alcol"}],correct:1,explain_en:"Polydrug use (alcohol plus other substances) is extremely dangerous -- effects are multiplicative not additive. Alcohol plus sedatives or marijuana can cause profound impairment at low doses of each.",explain_it:"L'uso polidroga (alcol + altre sostanze) e estremamente pericoloso -- gli effetti si moltiplicano. Alcol + sedativi o marijuana possono causare compromissione profonda."},
  {cat:"alcohol",en:"What is the BAC legal limit for a CDL driver operating a commercial vehicle in Florida?",it:"Qual e il limite BAC legale per un conducente CDL che opera un veicolo commerciale in Florida?",options:[{en:"0.08%",it:"0,08%"},{en:"0.04%",it:"0,04%"},{en:"0.06%",it:"0,06%"},{en:"0.02%",it:"0,02%"}],correct:1,explain_en:"CDL holders operating a commercial vehicle have a stricter BAC limit of 0.04% -- half the standard 0.08% limit.",explain_it:"I titolari CDL che operano un veicolo commerciale hanno un limite BAC piu rigido di 0,04% -- meta del limite standard di 0,08%."},
  {cat:"alcohol",en:"What is the effect of a cold shower or coffee on a person's BAC?",it:"Qual e l'effetto di una doccia fredda o del caffe sul BAC?",options:[{en:"Both effectively reduce BAC",it:"Entrambi riducono efficacemente il BAC"},{en:"Neither affects BAC -- only time allows the liver to eliminate alcohol",it:"Nessuno dei due influisce sul BAC -- solo il tempo permette al fegato di eliminare l'alcol"},{en:"Cold water reduces BAC",it:"L'acqua fredda riduce il BAC"},{en:"Coffee speeds metabolism by 50%",it:"Il caffe accelera il metabolismo del 50%"}],correct:1,explain_en:"Cold showers and coffee do NOT reduce BAC. They may make you feel more alert but the alcohol in your blood is unchanged. Only time eliminates alcohol.",explain_it:"Le docce fredde e il caffe NON riducono il BAC. Solo il tempo e il metabolismo epatico eliminano l'alcol."},
  {cat:"alcohol",en:"How long does it take for alcohol to begin affecting the brain after consumption?",it:"Quanto tempo ci vuole perche l'alcol inizi ad influire sul cervello?",options:[{en:"Immediately within 30 seconds",it:"Immediatamente entro 30 secondi"},{en:"Within 5-10 minutes",it:"Entro 5-10 minuti"},{en:"Only after 30 minutes",it:"Solo dopo 30 minuti"},{en:"After the stomach is empty",it:"Dopo che lo stomaco e vuoto"}],correct:1,explain_en:"Alcohol begins reaching the brain within 5-10 minutes of consumption. Peak BAC occurs 30-90 minutes after the last drink.",explain_it:"L'alcol inizia a raggiungere il cervello entro 5-10 minuti dal consumo. Il BAC di picco si verifica 30-90 minuti dopo l'ultimo drink."},
  {cat:"alcohol",en:"What does Florida's aggravated DUI charge require?",it:"Cosa richiede l'accusa di DUI aggravato della Florida?",options:[{en:"Any DUI conviction",it:"Qualsiasi condanna DUI"},{en:"BAC of 0.15%+ OR with a minor in the vehicle OR causing property damage or injury",it:"BAC di 0,15%+ O con un minore nel veicolo O causando danni materiali o lesioni"},{en:"DUI on a highway",it:"DUI su un'autostrada"},{en:"DUI committed during a holiday",it:"DUI commesso durante un giorno festivo"}],correct:1,explain_en:"Aggravated DUI factors in Florida: BAC 0.15%+ (mandatory IID), minor passenger, property damage, or injury. Each factor increases penalties significantly.",explain_it:"Fattori DUI aggravato in Florida: BAC 0,15%+, passeggero minore, danni materiali o lesioni. Ogni fattore aumenta significativamente le sanzioni."},
  {cat:"alcohol",en:"What is the effect of alcohol on a driver's divided attention?",it:"Qual e l'effetto dell'alcol sull'attenzione divisa di un conducente?",options:[{en:"Improves focus on the most important task",it:"Migliora la concentrazione sul compito piu importante"},{en:"Impairs divided attention making multitasking much harder",it:"Compromette l'attenzione divisa rendendo il multitasking molto piu difficile"},{en:"Only affects attention at high BAC",it:"Influisce sull'attenzione solo ad alto BAC"},{en:"Has no effect on multitasking ability",it:"Non ha effetti sulla capacita di multitasking"}],correct:1,explain_en:"Divided attention is one of the first skills impaired by alcohol. Driving requires constant simultaneous monitoring -- alcohol reduces this capacity even below 0.05% BAC.",explain_it:"L'attenzione divisa e una delle prime abilita compromesse dall'alcol. La guida richiede un monitoraggio simultaneo costante."},
  {cat:"alcohol",en:"What is the minimum DUI revocation period for a first offense in Florida?",it:"Qual e il periodo minimo di revoca DUI per una prima infrazione in Florida?",options:[{en:"30 days",it:"30 giorni"},{en:"90 days",it:"90 giorni"},{en:"180 days",it:"180 giorni"},{en:"1 year",it:"1 anno"}],correct:2,explain_en:"First DUI Florida: minimum 180-day license revocation. With BAC 0.15%+ or minor passenger, minimum 1 year.",explain_it:"Primo DUI Florida: revoca minima della patente di 180 giorni. Con BAC 0,15%+ o passeggero minore, minimo 1 anno."},
  {cat:"alcohol",en:"What is the Florida community service requirement for a first DUI conviction?",it:"Qual e il requisito di servizio alla comunita per una prima condanna DUI in Florida?",options:[{en:"No community service required",it:"Nessun servizio alla comunita richiesto"},{en:"Minimum 50 hours or $10 for each hour in lieu",it:"Minimo 50 ore o $10 per ogni ora in sostituzione"},{en:"100 hours mandatory",it:"100 ore obbligatorie"},{en:"25 hours minimum",it:"Minimo 25 ore"}],correct:1,explain_en:"First DUI Florida: minimum 50 hours community service (or $10/hour in lieu). Must be completed before license reinstatement.",explain_it:"Primo DUI Florida: minimo 50 ore di servizio alla comunita (o $10/ora in sostituzione). Deve essere completato prima del ripristino della patente."},
  {cat:"alcohol",en:"Can a Florida DUI conviction be expunged from a criminal record?",it:"Puo una condanna DUI Florida essere cancellata da un casellario penale?",options:[{en:"Yes after 5 years with no further offenses",it:"Si dopo 5 anni senza ulteriori infrazioni"},{en:"No -- DUI convictions cannot be expunged or sealed in Florida",it:"No -- le condanne DUI non possono essere cancellate o sigillate in Florida"},{en:"Yes if it was a first offense with no accident",it:"Si se era una prima offesa senza incidente"},{en:"Yes only if community service was completed",it:"Si solo se il servizio alla comunita e stato completato"}],correct:1,explain_en:"Florida DUI convictions cannot be expunged or sealed. They remain permanently on your criminal and driving record.",explain_it:"Le condanne DUI in Florida non possono essere cancellate o sigillate. Rimangono permanentemente nel casellario."},
  {cat:"alcohol",en:"What is the effect of food on alcohol absorption?",it:"Come influisce il cibo sull'assorbimento dell'alcol?",options:[{en:"Food has no effect on alcohol absorption",it:"Il cibo non ha effetti sull'assorbimento dell'alcol"},{en:"Food slows absorption delaying peak BAC but total alcohol consumed is the same",it:"Il cibo rallenta l'assorbimento ritardando il BAC di picco ma l'alcol totale e lo stesso"},{en:"Food permanently prevents alcohol from entering the bloodstream",it:"Il cibo impedisce permanentemente all'alcol di entrare nel flusso sanguigno"},{en:"High-fat foods neutralize alcohol",it:"Gli alimenti grassi neutralizzano l'alcol"}],correct:1,explain_en:"Eating slows the rate of alcohol absorption -- delaying how fast BAC rises. However, the same total alcohol will still be absorbed eventually.",explain_it:"Mangiare rallenta la velocita di assorbimento dell'alcol -- ritardando l'aumento del BAC. Tuttavia, lo stesso alcol totale verra comunque assorbito."},
  {cat:"license",en:"What is the Florida FR-44 insurance certificate?",it:"Cos'e il certificato assicurativo Florida FR-44?",options:[{en:"Standard liability insurance proof",it:"Prova standard di assicurazione di responsabilita"},{en:"High-limit insurance certificate required after DUI -- requires $100,000/$300,000 BI and $50,000 PDL",it:"Certificato assicurativo ad alto limite richiesto dopo DUI -- richiede $100.000/$300.000 BI e $50.000 PDL"},{en:"Same as SR-22 but for motorcycles",it:"Uguale a SR-22 ma per le moto"},{en:"Proof of uninsured motorist coverage",it:"Prova di copertura automobilista non assicurato"}],correct:1,explain_en:"FR-44 is required after DUI conviction in Florida. It requires much higher liability limits than standard SR-22 and must be maintained for 3 years.",explain_it:"FR-44 e richiesto dopo la condanna DUI in Florida. Richiede limiti di responsabilita molto piu alti dello standard SR-22 e deve essere mantenuto per 3 anni."},
  {cat:"license",en:"What happens to a Florida driver who accumulates 18 points in 18 months?",it:"Cosa succede a un conducente Florida che accumula 18 punti in 18 mesi?",options:[{en:"A warning letter only",it:"Solo una lettera di avvertimento"},{en:"3-month license suspension",it:"Sospensione della patente di 3 mesi"},{en:"6-month suspension",it:"Sospensione di 6 mesi"},{en:"1-year suspension",it:"Sospensione di 1 anno"}],correct:1,explain_en:"Florida point system: 18 points in 18 months = 3-month suspension. 24 points in 36 months = 1-year suspension.",explain_it:"Sistema punti Florida: 18 punti in 18 mesi = sospensione di 3 mesi. 24 punti in 36 mesi = sospensione di 1 anno."},
  {cat:"license",en:"What is the TLSAE course required for first-time Florida license applicants?",it:"Cos'e il corso TLSAE richiesto per i richiedenti la prima patente Florida?",options:[{en:"A course only for DUI offenders",it:"Un corso solo per i trasgressori DUI"},{en:"A required 4-hour course for first-time Florida license applicants 18 and older",it:"Un corso obbligatorio di 4 ore per i richiedenti la prima patente Florida di 18 anni e piu"},{en:"An optional safety course",it:"Un corso di sicurezza opzionale"},{en:"A course required after any moving violation",it:"Un corso richiesto dopo qualsiasi violazione in movimento"}],correct:1,explain_en:"TLSAE (also called DATA) is a 4-hour course required for adults 18+ applying for their first Florida license. Covers traffic laws and substance abuse effects.",explain_it:"Il TLSAE (noto anche come DATA) e un corso di 4 ore richiesto per gli adulti 18+ che richiedono la prima patente Florida."},
  {cat:"license",en:"How long do Florida DUI convictions stay on a driving record?",it:"Per quanto tempo le condanne DUI rimangono sul casellario di guida Florida?",options:[{en:"3 years",it:"3 anni"},{en:"7 years",it:"7 anni"},{en:"10 years",it:"10 anni"},{en:"Permanently",it:"Permanentemente"}],correct:3,explain_en:"Florida DUI convictions remain on the driving record PERMANENTLY. They never age off.",explain_it:"Le condanne DUI della Florida rimangono PERMANENTEMENTE sul casellario di guida. Non scompaiono mai."},
  {cat:"license",en:"What is the minimum age for a full unrestricted Class E license in Florida?",it:"Qual e l'eta minima per la patente Class E completa senza restrizioni in Florida?",options:[{en:"16 years old",it:"16 anni"},{en:"17 years old",it:"17 anni"},{en:"18 years old",it:"18 anni"},{en:"21 years old",it:"21 anni"}],correct:2,explain_en:"A full, unrestricted Florida Class E license requires age 18. Drivers 16-17 hold a provisional license with GDL restrictions that lift at 18.",explain_it:"Una patente Florida Class E completa e senza restrizioni richiede 18 anni. I conducenti di 16-17 anni hanno una patente provvisoria con restrizioni GDL che si tolgono a 18 anni."},
  {cat:"license",en:"What Florida traffic violation adds 6 points to a driving record?",it:"Quale violazione del traffico Florida aggiunge 6 punti al casellario?",options:[{en:"Running a red light",it:"Passare con il rosso"},{en:"Speeding 30+ mph over the limit or any speeding in a school zone",it:"Eccesso di velocita di 30+ mph sopra il limite o qualsiasi velocita eccessiva in zona scolastica"},{en:"Failure to yield",it:"Mancata precedenza"},{en:"Improper turn",it:"Svolta impropria"}],correct:1,explain_en:"6-point violations in Florida: speeding 30+ mph over limit, speeding in a school zone, or leaving the scene of a crash with property damage.",explain_it:"Violazioni a 6 punti in Florida: eccesso di velocita di 30+ mph sopra il limite, velocita eccessiva in zona scolastica, o fuga dalla scena di un incidente."},
  {cat:"license",en:"What is Florida's minimum insurance requirement for vehicle registration?",it:"Qual e il requisito assicurativo minimo della Florida per la registrazione del veicolo?",options:[{en:"PIP $5,000 / PDL $5,000",it:"PIP $5.000 / PDL $5.000"},{en:"PIP $10,000 / PDL $10,000",it:"PIP $10.000 / PDL $10.000"},{en:"PIP $25,000 / PDL $10,000",it:"PIP $25.000 / PDL $10.000"},{en:"PIP $50,000 / PDL $25,000",it:"PIP $50.000 / PDL $25.000"}],correct:1,explain_en:"Florida requires minimum PIP of $10,000 and PDL of $10,000. These are required to register and maintain a vehicle.",explain_it:"La Florida richiede un minimo PIP di $10.000 e PDL di $10.000. Questi sono richiesti per registrare e mantenere un veicolo."},
  {cat:"license",en:"What is the Habitual Traffic Offender designation in Florida?",it:"Cos'e la designazione Habitual Traffic Offender in Florida?",options:[{en:"A driver with more than 10 tickets in a year",it:"Un conducente con piu di 10 multe in un anno"},{en:"A driver who accumulates 3 major offenses in 5 years or 15 total convictions in 5 years",it:"Un conducente che accumula 3 gravi infrazioni in 5 anni o 15 condanne totali in 5 anni"},{en:"Any driver with a DUI conviction",it:"Qualsiasi conducente con una condanna DUI"},{en:"A driver who caused 2+ at-fault accidents",it:"Un conducente che ha causato 2+ incidenti per colpa propria"}],correct:1,explain_en:"HTO designation: 3 major offenses in 5 years (DUI, reckless driving, manslaughter) OR 15 convictions in 5 years. Results in mandatory 5-year license revocation.",explain_it:"Designazione HTO: 3 gravi infrazioni in 5 anni O 15 condanne in 5 anni. Comporta una revoca obbligatoria della patente di 5 anni."},
  {cat:"license",en:"What is required for a Florida driver to reinstate after HTO revocation?",it:"Cosa e richiesto per ripristinare la patente dopo una revoca HTO in Florida?",options:[{en:"Automatic reinstatement after 5 years",it:"Ripristino automatico dopo 5 anni"},{en:"Must wait the full revocation period then petition FLHSMV and meet all requirements",it:"Deve aspettare l'intero periodo di revoca poi presentare petizione al FLHSMV e soddisfare tutti i requisiti"},{en:"Only need to pay a reinstatement fee",it:"E necessario solo pagare una quota di ripristino"},{en:"Requires a court order only",it:"Richiede solo un ordine del tribunale"}],correct:1,explain_en:"After HTO revocation: wait the full 5-year period, then petition FLHSMV for reinstatement. May require fees, insurance proof, and possible re-examination.",explain_it:"Dopo la revoca HTO: aspettare l'intero periodo di 5 anni, poi presentare petizione al FLHSMV per il ripristino."},
  {cat:"license",en:"What does Florida's Motor Vehicle Records (MVR) include?",it:"Cosa include il Motor Vehicle Records della Florida?",options:[{en:"Only criminal convictions",it:"Solo le condanne penali"},{en:"All traffic violations, suspensions, revocations, accidents, and DUI convictions",it:"Tutte le violazioni del traffico, sospensioni, revoche, incidenti e condanne DUI"},{en:"Only the last 3 years of violations",it:"Solo gli ultimi 3 anni di violazioni"},{en:"Only violations resulting in license suspension",it:"Solo le violazioni che hanno comportato sospensione della patente"}],correct:1,explain_en:"Florida MVR contains: all traffic convictions, suspensions/revocations, accidents, DUI convictions, and license status -- available to courts, insurers, and employers.",explain_it:"Il MVR Florida contiene: tutte le condanne del traffico, sospensioni/revoche, incidenti, condanne DUI e informazioni sullo stato della patente."},
  {cat:"license",en:"What is the Florida law on providing false information on a driver's license application?",it:"Qual e la legge Florida sul fornire informazioni false su una domanda di patente?",options:[{en:"Results in a warning only",it:"Comporta solo un avvertimento"},{en:"A criminal offense that can result in charges and permanent disqualification",it:"Un reato penale che puo comportare accuse e squalifica permanente"},{en:"Only results in the application being denied",it:"Comporta solo il rifiuto della domanda"},{en:"Only illegal for commercial license applications",it:"Illegale solo per le domande di patente commerciale"}],correct:1,explain_en:"Providing false information on a Florida license application is a criminal offense -- fraud, perjury, or making a false official statement.",explain_it:"Fornire informazioni false su una domanda di patente Florida e un reato penale."},
  {cat:"license",en:"What is the minimum age for a Florida learner's permit?",it:"Qual e l'eta minima per il permesso per principianti Florida?",options:[{en:"14 years old",it:"14 anni"},{en:"15 years old",it:"15 anni"},{en:"16 years old",it:"16 anni"},{en:"17 years old",it:"17 anni"}],correct:1,explain_en:"Florida's minimum age for a learner's license (learner's permit) is 15 years old.",explain_it:"L'eta minima per il permesso per principianti Florida e 15 anni."},

  // ══ SESSION 6 ══════════════════════════════════
{cat:"signs",en:"What does a flashing yellow traffic light mean?",it:"Cosa significa un semaforo giallo lampeggiante?",options:[{en:"Stop and wait for green",it:"Fermarsi e aspettare il verde"},{en:"Proceed with caution -- slow down and be alert",it:"Procedere con cautela -- rallentare ed essere vigili"},{en:"The light is broken -- treat as stop sign",it:"Il semaforo e rotto -- trattarlo come stop"},{en:"Yield to all traffic",it:"Cedere a tutto il traffico"}],correct:1,explain_en:"Flashing yellow means proceed with caution. Slow down, look for hazards, but you do not need to stop.",explain_it:"Il giallo lampeggiante significa procedere con cautela. Rallentare, cercare pericoli, ma non e necessario fermarsi."},
  {cat:"signs",en:"What does a flashing red traffic light mean?",it:"Cosa significa un semaforo rosso lampeggiante?",options:[{en:"Yield to oncoming traffic",it:"Cedere al traffico in arrivo"},{en:"Stop completely, then proceed when safe -- treat as a stop sign",it:"Fermarsi completamente, poi procedere quando sicuro -- trattarlo come un segnale di stop"},{en:"Slow to 15 mph and proceed",it:"Rallentare a 15 mph e procedere"},{en:"The intersection is closed",it:"L incrocio e chiuso"}],correct:1,explain_en:"Flashing red equals stop sign. Come to a complete stop, yield as appropriate, then proceed when safe.",explain_it:"Rosso lampeggiante uguale segnale di stop. Fermarsi completamente, cedere appropriatamente, poi procedere quando sicuro."},
  {cat:"signs",en:"What does a green arrow on a traffic light mean?",it:"Cosa significa una freccia verde su un semaforo?",options:[{en:"You may proceed in the direction of the arrow -- oncoming traffic is stopped",it:"Puoi procedere nella direzione della freccia -- il traffico in arrivo e fermato"},{en:"Pedestrians have the right of way",it:"I pedoni hanno la precedenza"},{en:"The intersection ahead is clear",it:"L incrocio davanti e libero"},{en:"You must turn in the direction of the arrow",it:"Devi svoltare nella direzione della freccia"}],correct:0,explain_en:"A green arrow is a protected signal -- traffic in the arrow direction is stopped. You may proceed in that direction safely.",explain_it:"Una freccia verde e un segnale protetto -- il traffico nella direzione della freccia e fermato. Puoi procedere in quella direzione in sicurezza."},
  {cat:"signs",en:"What does a yellow X signal in a lane control signal mean?",it:"Cosa significa una X gialla in un segnale di controllo corsia?",options:[{en:"The lane is open for travel",it:"La corsia e aperta al transito"},{en:"The lane is closing soon -- move out of this lane",it:"La corsia si sta chiudendo presto -- uscire da questa corsia"},{en:"Proceed at reduced speed",it:"Procedere a velocita ridotta"},{en:"The lane is reserved for buses",it:"La corsia e riservata agli autobus"}],correct:1,explain_en:"Yellow X on a lane control signal means the lane is about to close -- move to an adjacent open lane as soon as safely possible.",explain_it:"X gialla su un segnale di controllo corsia significa che la corsia sta per chiudersi -- spostarsi in una corsia aperta adiacente il prima possibile."},
  {cat:"signs",en:"What does a red X in a lane control signal mean?",it:"Cosa significa una X rossa in un segnale di controllo corsia?",options:[{en:"Proceed with extreme caution",it:"Procedere con estrema cautela"},{en:"The lane is closed -- do not use this lane",it:"La corsia e chiusa -- non usare questa corsia"},{en:"The lane speed limit is reduced",it:"Il limite di velocita della corsia e ridotto"},{en:"Use this lane for passing only",it:"Usa questa corsia solo per sorpassare"}],correct:1,explain_en:"Red X means the lane is CLOSED. Driving in a lane marked with a red X is illegal and extremely dangerous.",explain_it:"X rossa significa che la corsia e CHIUSA. Guidare in una corsia contrassegnata con una X rossa e illegale ed estremamente pericoloso."},
  {cat:"signs",en:"What does a Do Not Enter sign look like?",it:"Come appare un segnale Do Not Enter?",options:[{en:"White rectangle with black text",it:"Rettangolo bianco con testo nero"},{en:"Red circle with white horizontal bar",it:"Cerchio rosso con barra orizzontale bianca"},{en:"Red octagon",it:"Ottagono rosso"},{en:"Orange diamond",it:"Rombo arancione"}],correct:1,explain_en:"Do Not Enter: red circle with white horizontal bar. You are facing the wrong direction on a one-way road or entering a restricted area.",explain_it:"Do Not Enter: cerchio rosso con barra orizzontale bianca. Stai andando nella direzione sbagliata su una strada a senso unico."},
  {cat:"signs",en:"What does a Wrong Way sign mean when you see it?",it:"Cosa significa un segnale Wrong Way quando lo vedi?",options:[{en:"Make a U-turn at the next opportunity",it:"Fare un inversione di marcia alla prossima opportunita"},{en:"You are going the wrong direction -- stop and turn around safely",it:"Stai andando nella direzione sbagliata -- fermarsi e girare in sicurezza"},{en:"Oncoming traffic is going the wrong way",it:"Il traffico in arrivo sta andando nella direzione sbagliata"},{en:"Detour ahead",it:"Deviazione in avanti"}],correct:1,explain_en:"Wrong Way means you are traveling against traffic -- a potentially fatal situation. Stop and safely reverse or turn around.",explain_it:"Wrong Way significa che stai viaggiando contro il traffico -- una situazione potenzialmente fatale. Fermarsi e fare inversione in sicurezza."},
  {cat:"signs",en:"What does a blue sign along an interstate typically indicate?",it:"Cosa indica tipicamente un segnale blu lungo un autostrada interstatale?",options:[{en:"A state park or recreation area",it:"Un parco statale o area ricreativa"},{en:"Services at the next exit: gas, food, lodging, hospital",it:"Servizi alla prossima uscita: carburante, cibo, alloggio, ospedale"},{en:"A toll booth ahead",it:"Un casello in avanti"},{en:"A rest area with restrooms",it:"Un area di sosta con servizi igienici"}],correct:1,explain_en:"Blue interstate signs show motorist services at upcoming exits: gas stations, restaurants, lodging, and hospitals.",explain_it:"I segnali blu autostradali mostrano i servizi per gli automobilisti alle prossime uscite: stazioni di servizio, ristoranti, alloggi e ospedali."},
  {cat:"signs",en:"What does a brown sign along a highway indicate?",it:"Cosa indica un segnale marrone lungo un autostrada?",options:[{en:"A construction zone",it:"Una zona di costruzione"},{en:"A recreational area, national park, or cultural attraction",it:"Un area ricreativa, parco nazionale o attrazione culturale"},{en:"A private road or restricted area",it:"Una strada privata o area riservata"},{en:"A rest stop with food services",it:"Un area di sosta con servizi alimentari"}],correct:1,explain_en:"Brown highway signs indicate recreational areas, national parks, monuments, historical sites, and cultural attractions.",explain_it:"I segnali autostradali marroni indicano aree ricreative, parchi nazionali, monumenti, siti storici e attrazioni culturali."},
  {cat:"signs",en:"What does a Road Narrows warning sign indicate?",it:"Cosa indica un segnale di avvertimento Road Narrows?",options:[{en:"The road ends ahead",it:"La strada finisce in avanti"},{en:"The road becomes narrower ahead -- be prepared for reduced width",it:"La strada diventa piu stretta in avanti -- prepararsi per larghezza ridotta"},{en:"A one-way road begins",it:"Inizia una strada a senso unico"},{en:"Weight restriction ahead",it:"Restrizione di peso in avanti"}],correct:1,explain_en:"Road Narrows warns that the travel lane becomes narrower. Reduce speed and be prepared for vehicles from the opposite direction being closer.",explain_it:"Road Narrows avvisa che la corsia di marcia diventa piu stretta. Ridurre la velocita e prepararsi per i veicoli dalla direzione opposta piu vicini."},
  {cat:"signs",en:"What does an orange colored sign on a highway indicate?",it:"Cosa indica un segnale di colore arancione su un autostrada?",options:[{en:"A recreational area nearby",it:"Un area ricreativa nelle vicinanze"},{en:"A work zone -- construction or maintenance workers are present",it:"Una zona di lavoro -- sono presenti operai edili o di manutenzione"},{en:"A seasonal road closure",it:"Una chiusura stagionale della strada"},{en:"An alternate route",it:"Un percorso alternativo"}],correct:1,explain_en:"Orange signs indicate construction or work zones. Fines are typically doubled and workers are present -- slow down and pay attention.",explain_it:"I segnali arancioni indicano zone di costruzione o lavoro. Le multe sono tipicamente raddoppiate e sono presenti operai."},
  {cat:"signs",en:"What does a Soft Shoulder warning sign mean?",it:"Cosa significa un segnale di avvertimento Soft Shoulder?",options:[{en:"A sharp drop-off on the edge of the road",it:"Un brusco calo sul bordo della strada"},{en:"The road shoulder is soft -- your vehicle may become stuck or hard to control if you drive on it",it:"La banchina stradale e morbida -- il tuo veicolo potrebbe bloccarsi se ci guidi"},{en:"No shoulder is available for emergency stopping",it:"Nessuna banchina disponibile per le soste di emergenza"},{en:"The shoulder is reserved for cyclists",it:"La banchina e riservata ai ciclisti"}],correct:1,explain_en:"Soft Shoulder: the unpaved shoulder is unstable. If you pull onto it at speed, your vehicle may veer off or become stuck.",explain_it:"Soft Shoulder: la banchina non asfaltata e instabile. Se ci sali a velocita, il tuo veicolo potrebbe deviare o bloccarsi."},
  {cat:"signs",en:"What does a Dip warning sign indicate?",it:"Cosa indica un segnale di avvertimento Dip?",options:[{en:"A sharp curve ahead",it:"Una curva stretta in avanti"},{en:"A low area in the road that may collect water -- reduce speed",it:"Un area bassa nella strada che potrebbe raccogliere acqua -- ridurre la velocita"},{en:"The road ends at a body of water",it:"La strada finisce in un corpo d acqua"},{en:"A speed bump ahead",it:"Un dosso rallentatore in avanti"}],correct:1,explain_en:"A Dip sign warns of a low spot in the road. It can cause loss of control at speed and may flood after rain.",explain_it:"Un segnale Dip avvisa di un punto basso nella strada. Puo causare perdita di controllo a velocita e potrebbe allagarsi dopo la pioggia."},
  {cat:"signs",en:"What is the meaning of double solid yellow center lines?",it:"Qual e il significato delle doppie linee gialle centrali continue?",options:[{en:"Passing is permitted from either direction",it:"Il sorpasso e consentito da entrambe le direzioni"},{en:"Passing is prohibited from both directions",it:"Il sorpasso e vietato da entrambe le direzioni"},{en:"A divided highway begins",it:"Inizia un autostrada divisa"},{en:"The road ahead is one-way",it:"La strada davanti e a senso unico"}],correct:1,explain_en:"Double solid yellow center lines mean NO passing from either direction. These are placed where sight distance is limited or passing is unsafe.",explain_it:"Le doppie linee gialle centrali continue significano NESSUN sorpasso da nessuna direzione."},
  {cat:"signs",en:"What does a single broken white line between lanes mean?",it:"Cosa significa una singola linea bianca tratteggiata tra le corsie?",options:[{en:"Do not change lanes",it:"Non cambiare corsia"},{en:"Lane changes are permitted when safe -- traffic flows in the same direction",it:"I cambi di corsia sono consentiti quando sicuro -- il traffico scorre nella stessa direzione"},{en:"A bike lane is ahead",it:"Una corsia ciclabile e in avanti"},{en:"The lane is for high-occupancy vehicles only",it:"La corsia e solo per veicoli ad alta occupazione"}],correct:1,explain_en:"Broken white lines between lanes indicate you may change lanes when safe. Traffic in all lanes travels in the same direction.",explain_it:"Le linee bianche tratteggiate tra le corsie indicano che puoi cambiare corsia quando e sicuro farlo."},
  {cat:"signs",en:"What does a solid white line at an intersection represent?",it:"Cosa rappresenta una linea bianca continua a un incrocio?",options:[{en:"A suggested stopping point",it:"Un punto di sosta suggerito"},{en:"The stop line -- you must stop before this line at a stop sign or red light",it:"La linea di stop -- devi fermarti prima di questa linea a uno stop o semaforo rosso"},{en:"A crosswalk boundary",it:"Un confine dell attraversamento pedonale"},{en:"The edge of the road",it:"Il bordo della strada"}],correct:1,explain_en:"The solid white transverse line at an intersection is the stop line. Your vehicle must stop completely behind it.",explain_it:"La linea bianca trasversale continua a un incrocio e la linea di stop. Il tuo veicolo deve fermarsi completamente dietro di essa."},
  {cat:"signs",en:"What does a yellow broken center line mean?",it:"Cosa significa una linea centrale gialla tratteggiata?",options:[{en:"No passing zone",it:"Zona di divieto di sorpasso"},{en:"Passing is permitted on your side when safe",it:"Il sorpasso e consentito dal tuo lato quando sicuro"},{en:"Two-way left turn lane",it:"Corsia di svolta sinistra a doppio senso"},{en:"Highway interchange ahead",it:"Svincolo autostradale in avanti"}],correct:1,explain_en:"A broken yellow center line means passing is permitted when safe -- the broken line is on the side of the driver who may pass.",explain_it:"Una linea centrale gialla tratteggiata significa che il sorpasso e consentito quando sicuro."},
  {cat:"signs",en:"What is the purpose of a Two-Way Left Turn Lane in the center of a road?",it:"Qual e lo scopo di una corsia di svolta sinistra a doppio senso al centro di una strada?",options:[{en:"A passing lane for faster traffic",it:"Una corsia di sorpasso per il traffico piu veloce"},{en:"A shared lane for vehicles from either direction to make left turns",it:"Una corsia condivisa per i veicoli da entrambe le direzioni per svoltare a sinistra"},{en:"A bicycle lane in the center",it:"Una corsia ciclabile al centro"},{en:"A median for emergency vehicles",it:"Una mediana per i veicoli di emergenza"}],correct:1,explain_en:"A TWLTL is a shared center lane for left turns only. Do not use it as a travel or passing lane.",explain_it:"Una TWLTL e una corsia centrale condivisa solo per le svolte sinistra. Non usarla come corsia di marcia o di sorpasso."},
  {cat:"signs",en:"What does a School Zone sign require?",it:"Cosa richiede un segnale School Zone?",options:[{en:"Stop completely regardless of activity",it:"Fermarsi completamente indipendentemente dall attivita"},{en:"Reduce speed to the posted limit when children are present or during posted hours",it:"Ridurre la velocita al limite segnalato quando i bambini sono presenti o durante le ore segnalate"},{en:"Yield to school buses at all times",it:"Cedere agli scuolabus in ogni momento"},{en:"No driving in school zones",it:"Nessuna guida nelle zone scolastiche"}],correct:1,explain_en:"School zone speed limits apply when children are present or during posted times. Violations carry doubled fines in Florida.",explain_it:"I limiti di velocita delle zone scolastiche si applicano quando i bambini sono presenti o durante gli orari segnalati. Le violazioni comportano multe raddoppiate in Florida."},
  {cat:"signs",en:"What does a green arrow signal at an intersection allow?",it:"Cosa consente un segnale a freccia verde a un incrocio?",options:[{en:"Pedestrians may cross freely",it:"I pedoni possono attraversare liberamente"},{en:"A protected turn in the direction of the arrow -- conflicting traffic is held",it:"Una svolta protetta nella direzione della freccia -- il traffico in conflitto e trattenuto"},{en:"You may proceed at any speed",it:"Puoi procedere a qualsiasi velocita"},{en:"Emergency vehicles have the right of way",it:"I veicoli di emergenza hanno la precedenza"}],correct:1,explain_en:"A green arrow allows a protected turn -- traffic that would conflict with your turn is stopped. You still must watch for pedestrians.",explain_it:"Una freccia verde consente una svolta protetta -- il traffico che sarebbe in conflitto con la tua svolta e fermato. Devi comunque fare attenzione ai pedoni."},
  {cat:"laws",en:"What is the Florida Move Over Law?",it:"Cos e la legge Florida Move Over?",options:[{en:"A law requiring slow drivers to move right",it:"Una legge che richiede ai conducenti lenti di spostarsi a destra"},{en:"When approaching a stopped emergency vehicle with lights on, move over one lane or slow to 20 mph below the posted limit",it:"Avvicinandosi a un veicolo di emergenza fermo con luci accese, spostarsi di una corsia o rallentare a 20 mph sotto il limite segnalato"},{en:"A law about changing lanes on highways",it:"Una legge sui cambi di corsia in autostrada"},{en:"Required when any vehicle is stopped on the shoulder",it:"Richiesto quando qualsiasi veicolo e fermo sulla banchina"}],correct:1,explain_en:"Florida Move Over Law: when approaching a stopped law enforcement, emergency, or utility vehicle with lights flashing, move over one lane OR slow to 20 mph below posted limit.",explain_it:"Legge Florida Move Over: avvicinandosi a un veicolo di emergenza fermo con luci lampeggianti, spostarsi di una corsia O rallentare a 20 mph sotto il limite segnalato."},
  {cat:"laws",en:"What is the Florida law about parking near a fire hydrant?",it:"Qual e la legge Florida sul parcheggio vicino a un idrante antincendio?",options:[{en:"No restriction if the hydrant is on private property",it:"Nessuna restrizione se l idrante e su proprieta privata"},{en:"No parking within 15 feet of a fire hydrant",it:"Nessun parcheggio entro 15 piedi da un idrante antincendio"},{en:"No parking within 10 feet of a fire hydrant",it:"Nessun parcheggio entro 10 piedi da un idrante antincendio"},{en:"No parking within 25 feet of a fire hydrant",it:"Nessun parcheggio entro 25 piedi da un idrante antincendio"}],correct:1,explain_en:"Florida prohibits parking within 15 feet of a fire hydrant -- emergency access must be maintained at all times.",explain_it:"La Florida vieta il parcheggio entro 15 piedi da un idrante antincendio -- l accesso di emergenza deve essere mantenuto in ogni momento."},
  {cat:"laws",en:"What does Florida law say about right-of-way at a four-way stop?",it:"Cosa dice la legge Florida sulla precedenza a uno stop a quattro vie?",options:[{en:"The vehicle going straight always has priority",it:"Il veicolo che va dritto ha sempre la priorita"},{en:"First to stop proceeds first -- ties go to the vehicle on the right",it:"Il primo a fermarsi procede per primo -- in caso di parita ha la precedenza il veicolo a destra"},{en:"The larger vehicle proceeds first",it:"Il veicolo piu grande procede per primo"},{en:"The vehicle with the most passengers proceeds first",it:"Il veicolo con piu passeggeri procede per primo"}],correct:1,explain_en:"Four-way stop: first to arrive proceeds first. If simultaneous, yield to the vehicle on your right. If facing each other going straight, both may proceed.",explain_it:"Stop a quattro vie: il primo ad arrivare procede per primo. Se simultaneo, cedere al veicolo a destra."},
  {cat:"laws",en:"What is the Florida law on pedestrians in a crosswalk?",it:"Qual e la legge Florida sui pedoni in un attraversamento pedonale?",options:[{en:"Pedestrians must yield to vehicles at all times",it:"I pedoni devono cedere ai veicoli in ogni momento"},{en:"Drivers must stop and yield to pedestrians in a marked or unmarked crosswalk",it:"I conducenti devono fermarsi e cedere ai pedoni in un attraversamento marcato o non marcato"},{en:"Drivers only yield at marked crosswalks",it:"I conducenti cedono solo agli attraversamenti marcati"},{en:"Pedestrians must wait for a walk signal",it:"I pedoni devono aspettare il segnale di attraversamento"}],correct:1,explain_en:"Florida requires drivers to stop for pedestrians in both marked and unmarked crosswalks. An unmarked crosswalk exists at any intersection with curbs or sidewalks.",explain_it:"La Florida richiede ai conducenti di fermarsi per i pedoni sia negli attraversamenti marcati che non marcati."},
  {cat:"laws",en:"What is the Florida law about driving with a suspended license?",it:"Qual e la legge Florida sulla guida con una patente sospesa?",options:[{en:"A minor civil infraction",it:"Una minore infrazione civile"},{en:"A criminal traffic offense -- first offense is a first-degree misdemeanor",it:"Un infrazione del traffico penale -- la prima infrazione e un reato minore di primo grado"},{en:"Only penalized if caught a second time",it:"Sanzionato solo se colto una seconda volta"},{en:"Results only in a fine",it:"Comporta solo una multa"}],correct:1,explain_en:"Driving with a suspended license in Florida is a first-degree misdemeanor (up to 1 year jail, $1,000 fine). Habitual offenders face felony charges.",explain_it:"Guidare con la patente sospesa in Florida e un reato minore di primo grado (fino a 1 anno di prigione, $1.000 di multa)."},
  {cat:"laws",en:"What is the Florida law on use of turn signals before turning?",it:"Qual e la legge Florida sull uso dei segnali di svolta?",options:[{en:"Signals are optional if no traffic is present",it:"I segnali sono opzionali se non c e traffico"},{en:"Signal at least 100 feet before turning in a city and 200 feet on a highway",it:"Segnalare almeno 100 piedi prima di svoltare in citta e 200 piedi in autostrada"},{en:"Signal only when another vehicle is behind you",it:"Segnalare solo quando un altro veicolo e dietro di te"},{en:"Only required on roads above 35 mph",it:"Richiesto solo su strade sopra i 35 mph"}],correct:1,explain_en:"Florida: signal at least 100 feet before turning on city streets, and at least 200 feet before turning on limited-access highways.",explain_it:"Florida: segnalare almeno 100 piedi prima di svoltare sulle strade cittadine, e almeno 200 piedi in autostrada."},
  {cat:"laws",en:"What is Florida's law on yielding to blind pedestrians with a white cane?",it:"Qual e la legge Florida sul cedere ai pedoni non vedenti con bastone bianco?",options:[{en:"Same as for any pedestrian",it:"Uguale a qualsiasi pedone"},{en:"Drivers must stop and yield the entire roadway to a pedestrian carrying a white cane or guided by a dog",it:"I conducenti devono fermarsi e cedere l intera carreggiata a un pedone con bastone bianco o guidato da un cane"},{en:"Blind pedestrians must wait for the walk signal",it:"I pedoni non vedenti devono aspettare il segnale"},{en:"Only applies at marked crosswalks",it:"Si applica solo agli attraversamenti marcati"}],correct:1,explain_en:"Florida requires ALL drivers to stop and yield the entire road to pedestrians carrying a white cane or guided by a guide dog -- at ALL locations.",explain_it:"La Florida richiede a TUTTI i conducenti di fermarsi e cedere l intera strada ai pedoni con bastone bianco o guidati da un cane guida."},
  {cat:"laws",en:"What is the Florida law on right-of-way when merging onto a highway?",it:"Qual e la legge Florida sulla precedenza quando si confluisce in autostrada?",options:[{en:"Highway traffic must yield to merging vehicles",it:"Il traffico autostradale deve cedere ai veicoli che confluiscono"},{en:"Merging vehicles must yield to highway traffic and match speed",it:"I veicoli che confluiscono devono cedere al traffico autostradale e abbinare la velocita"},{en:"Both vehicles have equal right-of-way",it:"Entrambi i veicoli hanno uguale precedenza"},{en:"Larger vehicles have priority",it:"I veicoli piu grandi hanno la priorita"}],correct:1,explain_en:"When merging, you must yield to traffic already on the highway. Use the ramp to accelerate and match highway speed before merging.",explain_it:"Quando si confluisce, si deve cedere al traffico gia sull autostrada. Usare la rampa per accelerare e abbinare la velocita autostradale."},
  {cat:"laws",en:"What is the Florida law about using a cell phone while driving?",it:"Qual e la legge Florida sull uso del cellulare durante la guida?",options:[{en:"Cell phone use is always legal while driving",it:"L uso del cellulare e sempre legale durante la guida"},{en:"Handheld use is prohibited in school and work zones; texting prohibited everywhere while driving",it:"L uso in mano e vietato nelle zone scolastiche e di lavoro; gli SMS sono vietati ovunque durante la guida"},{en:"Only texting is prohibited",it:"Solo gli SMS sono vietati"},{en:"Cell phone use only restricted at night",it:"L uso del cellulare e limitato solo di notte"}],correct:1,explain_en:"Florida law: texting and handheld phone use while driving is a primary offense. In school/work zones, handheld use is also prohibited. Hands-free is always permitted.",explain_it:"Legge Florida: l uso di SMS e cellulare in mano durante la guida e un infrazione primaria. Nelle zone scolastiche/di lavoro, anche l uso in mano e vietato."},
  {cat:"laws",en:"What Florida law applies when two vehicles reach an uncontrolled intersection simultaneously?",it:"Quale legge Florida si applica quando due veicoli raggiungono simultaneamente un incrocio non controllato?",options:[{en:"The vehicle going straight has priority",it:"Il veicolo che va dritto ha la priorita"},{en:"Yield to the vehicle on your right",it:"Cedere al veicolo a destra"},{en:"The vehicle going uphill has priority",it:"Il veicolo in salita ha la priorita"},{en:"Both drivers must wait for police",it:"Entrambi i conducenti devono aspettare la polizia"}],correct:1,explain_en:"At an uncontrolled intersection, yield to the vehicle on your right. This prevents deadlock and assigns clear priority.",explain_it:"A un incrocio non controllato, cedere al veicolo a destra. Questo previene lo stallo e assegna una priorita chiara."},
  {cat:"laws",en:"What is the Florida law on the use of high beams in fog?",it:"Qual e la legge Florida sull uso degli abbaglianti nella nebbia?",options:[{en:"High beams improve visibility in fog",it:"Gli abbaglianti migliorano la visibilita nella nebbia"},{en:"Use low beams in fog -- high beams reflect off fog and reduce visibility",it:"Usare le luci anabbaglianti nella nebbia -- gli abbaglianti si riflettono sulla nebbia e riducono la visibilita"},{en:"High beams required in all low-visibility conditions",it:"Gli abbaglianti sono richiesti in tutte le condizioni di bassa visibilita"},{en:"Fog lights and high beams together are optimal",it:"Le luci antinebbia e gli abbaglianti insieme sono ottimali"}],correct:1,explain_en:"In fog use low beams or fog lights. High beams reflect back off water droplets creating glare that reduces YOUR visibility.",explain_it:"Nella nebbia usare le luci anabbaglianti o luci antinebbia. Gli abbaglianti si riflettono sulle goccioline d acqua, creando bagliore che riduce la TUA visibilita."},
  {cat:"laws",en:"What does Florida law require when you park on a hill facing uphill with a curb?",it:"Cosa richiede la legge Florida quando parcheggi su una collina guardando verso l alto con un marciapiede?",options:[{en:"Turn wheels to the left toward the center of the road",it:"Girare le ruote a sinistra verso il centro della strada"},{en:"Turn wheels to the right toward the curb",it:"Girare le ruote a destra verso il marciapiede"},{en:"Wheels straight apply parking brake",it:"Ruote dritte applicare il freno a mano"},{en:"Turn wheels toward the curb and apply parking brake",it:"Girare le ruote verso il marciapiede e applicare il freno a mano"}],correct:0,explain_en:"Facing uphill with a curb: turn wheels LEFT away from curb. If brakes fail the car rolls back and the rear tire hits the curb stopping the vehicle.",explain_it:"Di fronte alla salita con marciapiede: girare le ruote a SINISTRA lontano dal marciapiede. Se i freni cedono, l auto rotola indietro e il pneumatico colpisce il marciapiede."},
  {cat:"laws",en:"What does Florida law require when you park downhill on a hill?",it:"Cosa richiede la legge Florida quando parcheggi in discesa?",options:[{en:"Turn wheels left away from the curb",it:"Girare le ruote a sinistra lontano dal marciapiede"},{en:"Turn wheels right toward the curb whether or not there is a curb",it:"Girare le ruote a destra verso il marciapiede con o senza marciapiede"},{en:"Wheels straight rely on parking brake",it:"Ruote dritte affidarsi al freno a mano"},{en:"Turn wheels left and apply emergency brake",it:"Girare le ruote a sinistra e applicare il freno di emergenza"}],correct:1,explain_en:"Facing downhill: always turn wheels to the RIGHT. If brakes fail the front tire contacts the curb stopping the forward roll.",explain_it:"Di fronte alla discesa: girare sempre le ruote a DESTRA. Se i freni cedono il pneumatico anteriore tocca il marciapiede."},
  {cat:"laws",en:"What is the minimum following distance behind a fire truck responding to an alarm?",it:"Qual e la distanza minima di seguimento dietro un autopompa che risponde a un allarme?",options:[{en:"100 feet",it:"100 piedi"},{en:"300 feet",it:"300 piedi"},{en:"500 feet",it:"500 piedi"},{en:"1000 feet",it:"1000 piedi"}],correct:2,explain_en:"Florida law requires at least 500 feet following distance behind a responding fire truck. Never park within 500 feet of a fire apparatus at the scene.",explain_it:"La legge Florida richiede almeno 500 piedi di distanza dietro un autopompa in risposta."},
  {cat:"laws",en:"What is the Florida law on parking near a stop sign?",it:"Qual e la legge Florida sul parcheggio vicino a un segnale di stop?",options:[{en:"No restriction near stop signs",it:"Nessuna restrizione vicino ai segnali di stop"},{en:"No parking within 30 feet of a stop sign",it:"Nessun parcheggio entro 30 piedi da un segnale di stop"},{en:"No parking within 50 feet of a stop sign",it:"Nessun parcheggio entro 50 piedi da un segnale di stop"},{en:"No parking within 10 feet of a stop sign",it:"Nessun parcheggio entro 10 piedi da un segnale di stop"}],correct:1,explain_en:"Florida prohibits parking within 30 feet of a stop sign to ensure drivers at the intersection can see and be seen.",explain_it:"La Florida vieta il parcheggio entro 30 piedi da un segnale di stop."},
  {cat:"laws",en:"What is Florida's law on yielding when exiting a parking lot onto a road?",it:"Qual e la legge Florida sul cedere quando si esce da un parcheggio su una strada?",options:[{en:"The vehicle exiting has the right-of-way",it:"Il veicolo in uscita ha la precedenza"},{en:"The vehicle exiting must yield to all road traffic and pedestrians",it:"Il veicolo in uscita deve cedere a tutto il traffico stradale e ai pedoni"},{en:"Vehicles alternate right-of-way",it:"I veicoli si alternano nella precedenza"},{en:"Only yield if the speed limit is above 35 mph",it:"Cedere solo se il limite di velocita e superiore a 35 mph"}],correct:1,explain_en:"When exiting a parking lot, driveway, or alley onto a road, you must yield to all traffic on the road and all pedestrians on the sidewalk.",explain_it:"Quando si esce da un parcheggio, vialetto o vicolo su una strada, si deve cedere a tutto il traffico sulla strada e ai pedoni sul marciapiede."},
  {cat:"laws",en:"What is the Florida law about funeral processions?",it:"Qual e la legge Florida sui cortei funebri?",options:[{en:"You may pass through if the light is green",it:"Puoi passare se il semaforo e verde"},{en:"You must yield to a properly escorted funeral procession and not cut through it",it:"Devi cedere a un corteo funebre adeguatamente scortato e non attraversarlo"},{en:"Funeral processions must pull over for regular traffic",it:"I cortei funebri devono fermarsi per il traffico normale"},{en:"Only emergency vehicles may interrupt a funeral procession",it:"Solo i veicoli di emergenza possono interrompere un corteo funebre"}],correct:1,explain_en:"Funeral processions have the right-of-way in Florida when properly escorted by law enforcement. Do not cut through or interfere with a procession.",explain_it:"I cortei funebri hanno la precedenza in Florida quando adeguatamente scortati. Non attraversare o interferire con un corteo."},
  {cat:"laws",en:"What is Florida's minimum speed law on highways?",it:"Qual e la legge sulla velocita minima delle autostrade in Florida?",options:[{en:"No minimum speed is required",it:"Nessuna velocita minima e richiesta"},{en:"You may not drive so slowly as to impede the normal flow of traffic",it:"Non puoi guidare cosi lentamente da ostacolare il normale flusso del traffico"},{en:"Minimum 45 mph on all interstates",it:"Minimo 45 mph su tutte le autostrade interstatali"},{en:"Minimum 55 mph when traffic is light",it:"Minimo 55 mph quando il traffico e leggero"}],correct:1,explain_en:"Impeding traffic by driving too slowly is a violation in Florida. You must not drive at a speed that unreasonably blocks traffic.",explain_it:"Ostacolare il traffico guidando troppo lentamente e una violazione in Florida."},
  {cat:"laws",en:"What is required by Florida law after a crash with no injuries where damage exceeds $500?",it:"Cosa richiede la legge Florida dopo un incidente senza lesioni in cui i danni superano i $500?",options:[{en:"Only exchange phone numbers",it:"Solo scambiare i numeri di telefono"},{en:"Exchange name address license registration and insurance information",it:"Scambiare nome indirizzo patente registrazione e informazioni sull assicurazione"},{en:"Call 911 immediately regardless of damage",it:"Chiamare il 911 immediatamente indipendentemente dai danni"},{en:"No action needed if both drivers agree",it:"Nessuna azione necessaria se entrambi i conducenti sono d accordo"}],correct:1,explain_en:"After a property-damage crash over $500: exchange name, address, registration, driver license number, and insurance information with all parties involved.",explain_it:"Dopo un incidente con danni materiali oltre $500: scambiare nome, indirizzo, registrazione, numero di patente e informazioni assicurative con tutte le parti."},
  {cat:"laws",en:"What is the Florida law on crossing a solid yellow line to pass?",it:"Qual e la legge Florida sul attraversare una linea gialla continua per sorpassare?",options:[{en:"Legal if the road ahead is clear",it:"Legale se la strada davanti e libera"},{en:"Illegal -- a solid yellow line on your side means passing is prohibited",it:"Illegale -- una linea gialla continua sul tuo lato significa che il sorpasso e vietato"},{en:"Legal if you return to your lane within 500 feet",it:"Legale se torni nella tua corsia entro 500 piedi"},{en:"Legal for motorcycles only",it:"Legale solo per le motociclette"}],correct:1,explain_en:"A solid yellow center line on YOUR side means no passing. Crossing it is illegal regardless of visibility.",explain_it:"Una linea gialla continua sul TUO lato significa nessun sorpasso. Attraversarla e illegale indipendentemente dalla visibilita."},
  {cat:"laws",en:"What is the Florida law about speeding in a school zone?",it:"Qual e la legge Florida sull eccesso di velocita in una zona scolastica?",options:[{en:"Same fine as a normal speeding ticket",it:"Stessa multa di un normale biglietto per eccesso di velocita"},{en:"Fines doubled and 6-point violation when children are present",it:"Le multe sono raddoppiate e 6 punti quando i bambini sono presenti"},{en:"A warning for the first offense",it:"Un avvertimento per la prima infrazione"},{en:"License suspended immediately",it:"Patente sospesa immediatamente"}],correct:1,explain_en:"Speeding in a school zone when children are present: fines doubled and 6 points added to your driving record.",explain_it:"Eccesso di velocita in zona scolastica quando i bambini sono presenti: le multe sono raddoppiate e vengono aggiunti 6 punti al casellario."},
  {cat:"laws",en:"What is Florida's law on lane usage on a road with three or more lanes?",it:"Qual e la legge Florida sull uso delle corsie su una strada con tre o piu corsie?",options:[{en:"Any lane may be used at any speed",it:"Qualsiasi corsia puo essere utilizzata a qualsiasi velocita"},{en:"Keep right except to pass -- left lanes are for faster-moving traffic and passing",it:"Mantenersi a destra tranne per sorpassare -- le corsie sinistra sono per il traffico piu veloce e il sorpasso"},{en:"Center lanes reserved for commercial trucks",it:"Le corsie centrali sono riservate ai camion commerciali"},{en:"Speed limit increases per lane from right to left",it:"Il limite di velocita aumenta per corsia da destra a sinistra"}],correct:1,explain_en:"Keep right except to pass. Left lanes are for passing -- driving slowly in the left lane and impeding traffic is a moving violation in Florida.",explain_it:"Mantenersi a destra tranne per sorpassare. Le corsie sinistra sono per il sorpasso."},
  {cat:"laws",en:"What is the Florida law about honking at a bicycle rider?",it:"Qual e la legge Florida sul suonare il clacson a un ciclista?",options:[{en:"Always required before passing a cyclist",it:"Sempre richiesto prima di sorpassare un ciclista"},{en:"Only use horn when reasonably necessary for safety -- never to harass",it:"Usare il clacson solo quando ragionevolmente necessario per la sicurezza -- mai per molestare"},{en:"Honking is encouraged to alert cyclists",it:"Suonare il clacson ai ciclisti e incoraggiato"},{en:"Prohibited within 100 feet of a cyclist",it:"Vietato entro 100 piedi da un ciclista"}],correct:1,explain_en:"Use the horn only when necessary for safety. Honking to intimidate or startle a cyclist is prohibited and dangerous -- it can cause them to swerve.",explain_it:"Usa il clacson solo quando necessario per la sicurezza. Suonare per intimidire o spaventare un ciclista e vietato e pericoloso."},
  {cat:"laws",en:"What must a Florida driver do before backing out of a parking space?",it:"Cosa deve fare un conducente Florida prima di uscire in retromarcia da un posto auto?",options:[{en:"Honk twice",it:"Suonare due volte il clacson"},{en:"Check all mirrors and look over shoulder for pedestrians and vehicles",it:"Controllare tutti gli specchi e guardare oltre la spalla per pedoni e veicoli"},{en:"Turn on hazard lights",it:"Accendere le luci di pericolo"},{en:"Wait for all vehicles to clear",it:"Aspettare che tutti i veicoli siano liberi"}],correct:1,explain_en:"Before backing: check all mirrors, look over both shoulders, and proceed slowly. Be especially alert for pedestrians, children, and cyclists.",explain_it:"Prima di fare retromarcia: controlla tutti gli specchi, guarda oltre entrambe le spalle e procedi lentamente."},
  {cat:"safety",en:"What is the minimum recommended following distance behind a large truck?",it:"Quale e la distanza minima di seguimento raccomandata dietro un camion grande?",options:[{en:"2 seconds",it:"2 secondi"},{en:"4 seconds or more -- large trucks have much longer stopping distances",it:"4 secondi o piu -- i camion grandi hanno distanze di frenata molto piu lunghe"},{en:"1 car length per 10 mph",it:"1 lunghezza auto per ogni 10 mph"},{en:"Same as following any other vehicle",it:"Uguale a seguire qualsiasi altro veicolo"}],correct:1,explain_en:"Large trucks need up to 40% more stopping distance than cars. Follow at least 4 seconds behind -- more in bad weather.",explain_it:"I camion grandi hanno bisogno fino al 40% di distanza di frenata in piu delle auto. Seguire ad almeno 4 secondi."},
  {cat:"safety",en:"What is the safest action when a tire blows out at highway speed?",it:"Qual e l azione piu sicura quando un pneumatico esplode ad alta velocita?",options:[{en:"Brake hard immediately",it:"Frenare forte immediatamente"},{en:"Hold the wheel firmly ease off the gas gradually and steer straight",it:"Tenere il volante fermamente togliere gradualmente il gas e sterzare dritto"},{en:"Turn the steering wheel sharply to compensate",it:"Girare bruscamente il volante per compensare"},{en:"Apply the parking brake to slow down",it:"Applicare il freno a mano per rallentare"}],correct:1,explain_en:"Blowout: grip the wheel firmly, ease off the gas (do NOT brake hard), steer straight to maintain control, then gradually slow and pull off.",explain_it:"Foratura: tieni il volante fermamente, togli il gas (NON frenare forte), sterza dritto per mantenere il controllo, poi rallenta gradualmente."},
  {cat:"safety",en:"What is hydroplaning and how should a driver respond?",it:"Cos e l aquaplaning e come dovrebbe rispondere un conducente?",options:[{en:"Tires overheating -- apply brakes",it:"Pneumatici surriscaldati -- applicare i freni"},{en:"Tires riding on water film losing road contact -- ease off gas do not brake hard and steer straight",it:"Pneumatici che scivolano su un film d acqua -- togliere il gas non frenare forte e sterzare dritto"},{en:"Brakes locking in wet conditions -- pump brakes",it:"Freni che si bloccano in condizioni bagnate -- pompare i freni"},{en:"Engine flooding in rain -- turn off ignition",it:"Motore allagato nella pioggia -- spegnere l accensione"}],correct:1,explain_en:"Hydroplaning: tires float on water film. Response: ease off gas, hold wheel steady, do not brake suddenly. Speed and tire tread are the main factors.",explain_it:"Aquaplaning: i pneumatici galleggiano su un film d acqua. Risposta: togli il gas, tieni il volante fermo, non frenare improvvisamente."},
  {cat:"safety",en:"What is the Move It law in Florida regarding minor crashes?",it:"Qual e la legge Move It in Florida riguardo ai piccoli incidenti?",options:[{en:"Always leave vehicles exactly where they stopped",it:"Lasciare sempre i veicoli esattamente dove si sono fermati"},{en:"If no injuries and vehicles are driveable move them out of traffic to prevent secondary crashes",it:"Se non ci sono lesioni e i veicoli sono guidabili spostarli fuori dal traffico per prevenire incidenti secondari"},{en:"Move vehicles only if police instruct you to",it:"Spostare i veicoli solo se la polizia lo istruisce"},{en:"Only applicable on interstates",it:"Si applica solo alle autostrade interstatali"}],correct:1,explain_en:"Florida Move It law: if a crash involves no injuries and vehicles can be driven, move them to a safe location to prevent traffic blockage and secondary crashes.",explain_it:"Legge Florida Move It: se un incidente non ha lesioni e i veicoli possono essere guidati, spostarli in un posto sicuro per prevenire intasamenti e incidenti secondari."},
  {cat:"safety",en:"What is the correct technique to regain control in a rear-wheel skid?",it:"Qual e la tecnica corretta per riprendere il controllo in una sbandata posteriore?",options:[{en:"Steer away from the skid and brake firmly",it:"Sterzare nella direzione opposta alla sbandata e frenare fermamente"},{en:"Steer in the direction of the skid -- turn into it -- to straighten the vehicle",it:"Sterzare nella direzione della sbandata -- sterzare verso di essa -- per raddrizzare il veicolo"},{en:"Accelerate to regain traction",it:"Accelerare per riprendere l aderenza"},{en:"Apply the emergency brake",it:"Applicare il freno di emergenza"}],correct:1,explain_en:"Rear-wheel skid (oversteer): steer INTO the skid (same direction the rear is sliding). Ease off gas. Do not brake. This counteracts the rotation.",explain_it:"Sbandata posteriore (sovrasterzo): sterzare VERSO la sbandata (stessa direzione in cui sta scivolando il retrotreno). Togli il gas. Non frenare."},
  {cat:"safety",en:"Why is it dangerous to drive in another vehicle blind spot on a highway?",it:"Perche e pericoloso guidare nel punto cieco di un altro veicolo in autostrada?",options:[{en:"The other driver may swerve toward you without seeing you",it:"L altro conducente potrebbe sterzare verso di te senza vederti"},{en:"You use more fuel in a blind spot",it:"Consumi piu carburante in un punto cieco"},{en:"It is illegal to drive next to another vehicle",it:"E illegale guidare accanto a un altro veicolo"},{en:"Your GPS loses signal in blind spots",it:"Il tuo GPS perde il segnale nei punti ciechi"}],correct:0,explain_en:"Driving in another vehicle blind spot is dangerous because they cannot see you and may change lanes into your space. Pass quickly or drop back to a safe following distance.",explain_it:"Guidare nel punto cieco di un altro veicolo e pericoloso perche non possono vederti e potrebbero cambiare corsia."},
  {cat:"safety",en:"What should you do if a vehicle accelerator sticks while driving?",it:"Cosa dovresti fare se l acceleratore si blocca durante la guida?",options:[{en:"Turn off the ignition immediately",it:"Spegnere immediatamente l accensione"},{en:"Shift to neutral apply brakes steer to safety then turn off ignition",it:"Mettere in folle applicare i freni sterzare verso la sicurezza poi spegnere l accensione"},{en:"Pump the gas to free the accelerator",it:"Pompare il gas per liberare l acceleratore"},{en:"Apply the emergency brake at full force",it:"Applicare il freno di emergenza a piena forza"}],correct:1,explain_en:"Stuck accelerator: shift to neutral (cuts engine power), apply brakes firmly, steer to the shoulder, then turn off ignition when stopped.",explain_it:"Acceleratore bloccato: mettere in folle (elimina la potenza del motore), applicare i freni fermamente, sterzare verso la banchina, poi spegnere l accensione."},
  {cat:"safety",en:"What should you do if your brakes fail completely while driving?",it:"Cosa dovresti fare se i freni cedono completamente durante la guida?",options:[{en:"Turn off the ignition while moving",it:"Spegnere l accensione mentre si e in movimento"},{en:"Pump the brakes downshift use parking brake gently then steer to a safe area",it:"Pompare i freni scalare marcia usare il freno a mano delicatamente poi sterzare verso un area sicura"},{en:"Increase speed to outrun the problem",it:"Aumentare la velocita per superare il problema"},{en:"Open the door and drag your feet",it:"Aprire la porta e trascinare i piedi"}],correct:1,explain_en:"Total brake failure: pump brakes, downshift to slow via engine braking, apply parking brake gently to avoid spin, then steer to a safe stop.",explain_it:"Totale cedimento dei freni: pompare i freni, scalare marcia per frenare con il motore, applicare il freno a mano delicatamente, poi sterzare verso una sosta sicura."},
  {cat:"safety",en:"What is the most common cause of collisions at intersections?",it:"Qual e la causa piu comune di collisioni agli incroci?",options:[{en:"Speed too high for conditions",it:"Velocita troppo alta per le condizioni"},{en:"Failure to yield the right-of-way",it:"Mancata concessione della precedenza"},{en:"Running red lights",it:"Passare con il rosso"},{en:"Poor road conditions",it:"Cattive condizioni stradali"}],correct:1,explain_en:"Failure to yield is the leading cause of intersection crashes. Always scan the intersection before entering even on green.",explain_it:"La mancata concessione della precedenza e la principale causa di incidenti agli incroci. Scansionare sempre l incrocio prima di entrare."},
  {cat:"safety",en:"What should you do if an oncoming vehicle has high beams on and is blinding you?",it:"Cosa dovresti fare se un veicolo in arrivo ti sta accecando con gli abbaglianti?",options:[{en:"Flash your high beams repeatedly",it:"Lampeggiare gli abbaglianti ripetutamente"},{en:"Look toward the right edge of the road and slow down",it:"Guardare verso il bordo destro della strada e rallentare"},{en:"Stop your vehicle in the lane",it:"Fermare il veicolo nella corsia"},{en:"Steer toward the oncoming vehicle side",it:"Sterzare verso il lato del veicolo in arrivo"}],correct:1,explain_en:"Oncoming high beams: look toward the right edge of your lane (not at the lights), slow down. Do not stare at the lights.",explain_it:"Abbaglianti in arrivo: guarda verso il bordo destro della tua corsia (non verso le luci), rallenta."},
  {cat:"safety",en:"What is the safest way to merge onto a highway from a ramp?",it:"Qual e il modo piu sicuro per confluire in autostrada da una rampa?",options:[{en:"Stop at the end of the ramp and wait for a gap",it:"Fermarsi alla fine della rampa e aspettare un varco"},{en:"Use the acceleration lane to match highway speed check mirrors and blind spots then merge smoothly",it:"Usare la corsia di accelerazione per abbinare la velocita autostradale controllare specchi e punti ciechi poi confluire fluidamente"},{en:"Merge immediately as soon as you enter the ramp",it:"Confluire immediatamente non appena si entra nella rampa"},{en:"Honk to alert highway traffic you are merging",it:"Suonare il clacson per avvisare il traffico autostradale"}],correct:1,explain_en:"Merging: use the entire acceleration lane to reach highway speed, check mirrors and blind spots, signal, then merge smoothly into a gap.",explain_it:"Confluire: usa l intera corsia di accelerazione per raggiungere la velocita autostradale, controlla specchi e punti ciechi, segnala, poi confluisci fluidamente."},
  {cat:"safety",en:"When is it legal to drive on the shoulder of an interstate in Florida?",it:"Quando e legale guidare sulla banchina di un autostrada interstatale in Florida?",options:[{en:"Any time to avoid traffic",it:"In qualsiasi momento per evitare il traffico"},{en:"Only in an emergency or when directed by law enforcement",it:"Solo in un emergenza o quando indicato dalle forze dell ordine"},{en:"Legal if you drive below 30 mph",it:"Legale se si guida sotto i 30 mph"},{en:"Legal to pass during traffic jams",it:"Legale per sorpassare durante gli ingorghi"}],correct:1,explain_en:"The shoulder is for emergency stops only. Driving on the shoulder to avoid traffic is illegal and endangers stopped vehicles.",explain_it:"La banchina e solo per le soste di emergenza. Guidare sulla banchina per evitare il traffico e illegale."},
  {cat:"safety",en:"What is the effect of carbon monoxide in a vehicle?",it:"Qual e l effetto del monossido di carbonio in un veicolo?",options:[{en:"Makes the driver more alert",it:"Rende il conducente piu vigile"},{en:"Odorless colorless gas from exhaust that can cause drowsiness impairment and death",it:"Gas inodore e incolore dallo scarico che puo causare sonnolenza compromissione e morte"},{en:"Causes vision impairment only at high concentrations",it:"Causa solo compromissione della visione ad alte concentrazioni"},{en:"Has no effect on a moving vehicle",it:"Non ha effetti su un veicolo in movimento"}],correct:1,explain_en:"Carbon monoxide is odorless and colorless. Even low levels cause drowsiness and impairment. Never run a vehicle in a closed garage.",explain_it:"Il monossido di carbonio e inodore e incolore. Anche bassi livelli causano sonnolenza e compromissione. Non far mai girare un veicolo in un garage chiuso."},
  {cat:"safety",en:"What is the proper technique to regain control in a front-wheel skid?",it:"Qual e la tecnica corretta per riprendere il controllo in una sbandata anteriore?",options:[{en:"Accelerate to spin front wheels and regain traction",it:"Accelerare per far girare le ruote anteriori e riprendere l aderenza"},{en:"Ease off the gas avoid braking and steer gently in the intended direction",it:"Togliere il gas evitare di frenare e sterzare delicatamente nella direzione prevista"},{en:"Steer away from the skid direction",it:"Sterzare nella direzione opposta alla sbandata"},{en:"Brake hard to regain traction",it:"Frenare forte per riprendere l aderenza"}],correct:1,explain_en:"Front-wheel skid (understeer): ease off gas, do not brake, steer smoothly in the direction you want to go. The front wheels need traction to steer.",explain_it:"Sbandata anteriore (sottosterzo): togli il gas, non frenare e sterza fluidamente nella direzione in cui vuoi andare."},
  {cat:"safety",en:"What is night blindness and how does it affect driving?",it:"Cos e la cecita notturna e come influisce sulla guida?",options:[{en:"Complete inability to see at night",it:"Incapacita completa di vedere di notte"},{en:"Reduced ability to see in low light especially affecting older drivers",it:"Capacita ridotta di vedere con poca luce soprattutto gli anziani"},{en:"A condition only caused by alcohol",it:"Una condizione causata solo dall alcol"},{en:"Temporary blindness from streetlights",it:"Cecita temporanea dai lampioni"}],correct:1,explain_en:"Night blindness: difficulty seeing in low-light conditions. Older drivers are most affected. Mitigation: slow down, increase following distance, ensure headlights are clean.",explain_it:"Cecita notturna: difficolta a vedere in condizioni di scarsa luce. I conducenti anziani sono i piu colpiti. Mitigazione: rallentare di notte, aumentare la distanza di seguimento."},
  {cat:"safety",en:"What is the most important thing to do before a long road trip?",it:"Qual e la cosa piu importante da fare prima di un lungo viaggio?",options:[{en:"Program your GPS",it:"Programmare il GPS"},{en:"Inspect tires fluids brakes lights and ensure you are well rested",it:"Ispezionare pneumatici fluidi freni luci e assicurarsi di essere ben riposati"},{en:"Fill the gas tank only",it:"Fare solo il pieno di carburante"},{en:"Download offline maps",it:"Scaricare mappe offline"}],correct:1,explain_en:"Pre-trip inspection: check tires, oil, coolant, brakes, lights, and wipers. Most importantly ensure you are well rested -- fatigue is a major crash factor.",explain_it:"Ispezione pre-viaggio: controlla pneumatici, olio, refrigerante, freni, luci e tergicristalli. La cosa piu importante: assicurati di essere ben riposato."},
  {cat:"safety",en:"What should you do if a traffic light is completely dark?",it:"Cosa dovresti fare se un semaforo e completamente buio?",options:[{en:"Proceed normally -- assume it is green",it:"Procedere normalmente -- supponi che sia verde"},{en:"Treat it as a four-way stop",it:"Trattarlo come un incrocio a quattro vie"},{en:"Only stop if other vehicles are present",it:"Fermarsi solo se altri veicoli sono presenti"},{en:"Turn around and find another route",it:"Girare indietro e trovare un altro percorso"}],correct:1,explain_en:"A dark non-functioning traffic light should be treated as a four-way stop: stop completely, yield in order, then proceed when safe.",explain_it:"Un semaforo buio deve essere trattato come un incrocio a quattro vie: fermarsi completamente, cedere nell ordine appropriato, poi procedere."},
  {cat:"safety",en:"What is the danger of driving in wet conditions at night?",it:"Qual e il pericolo di guidare in condizioni bagnate di notte?",options:[{en:"No difference -- modern cars handle both equally",it:"Nessuna differenza -- le auto moderne gestiscono entrambe ugualmente"},{en:"Wet roads reduce friction headlights glare on wet pavement and stopping distance increases",it:"Le strade bagnate riducono l attrito il bagliore dei fari riduce la visibilita e la distanza di frenata aumenta"},{en:"Wet conditions only matter above 60 mph",it:"Le condizioni bagnate contano solo sopra i 60 mph"},{en:"Headlights are more effective on wet roads",it:"I fari sono piu efficaci sulle strade bagnate"}],correct:1,explain_en:"Wet night driving: less traction, headlight glare off wet pavement reduces visibility, AND stopping distance greatly increases. A triple hazard.",explain_it:"Guida notturna bagnata: meno aderenza, bagliore dei fari riduce la visibilita, E la distanza di frenata aumenta notevolmente."},
  {cat:"alcohol",en:"What happens when a Florida driver refuses a breath test for a second time?",it:"Cosa succede quando un conducente Florida rifiuta un test del respiro per la seconda volta?",options:[{en:"18-month suspension",it:"Sospensione di 18 mesi"},{en:"18-month suspension and a first-degree misdemeanor criminal charge",it:"Sospensione di 18 mesi e un accusa penale di reato minore di primo grado"},{en:"Same as first refusal -- 1 year",it:"Uguale al primo rifiuto -- 1 anno"},{en:"Automatic DUI conviction",it:"Condanna DUI automatica"}],correct:1,explain_en:"Second refusal: 18-month license suspension AND it is a first-degree misdemeanor. Prior refusal is also admissible at trial.",explain_it:"Secondo rifiuto: sospensione della patente di 18 mesi E un reato minore di primo grado. Il rifiuto precedente e anche ammissibile in tribunale."},
  {cat:"alcohol",en:"What is wet reckless in Florida DUI law?",it:"Cos e il wet reckless nella legge DUI della Florida?",options:[{en:"A DUI charge with a high BAC",it:"Un accusa DUI con un BAC elevato"},{en:"A plea deal to reckless driving with alcohol -- counts toward DUI enhancement for a future DUI",it:"Un accordo di patteggiamento per guida spericolata con alcol -- conta per le aggravanti DUI in futuro"},{en:"A DUI that occurs in the rain",it:"Un DUI che si verifica sotto la pioggia"},{en:"A second DUI conviction",it:"Una seconda condanna DUI"}],correct:1,explain_en:"Wet reckless is a plea bargain reduction from DUI to reckless driving with alcohol. Lighter penalties but counts as prior DUI for enhancement if you get another DUI.",explain_it:"Il wet reckless e una riduzione di patteggiamento da DUI a guida spericolata con alcol. Ha sanzioni piu lievi ma conta come DUI precedente per l aggravamento."},
  {cat:"alcohol",en:"What is the effect of alcohol on a driver peripheral vision?",it:"Qual e l effetto dell alcol sulla visione periferica di un conducente?",options:[{en:"Alcohol improves peripheral vision",it:"L alcol migliora la visione periferica"},{en:"Alcohol reduces peripheral vision creating tunnel vision effect",it:"L alcol riduce la visione periferica creando un effetto di visione a tunnel"},{en:"No effect on peripheral vision",it:"Nessun effetto sulla visione periferica"},{en:"Only affects peripheral vision above 0.15% BAC",it:"Influisce sulla visione periferica solo sopra 0,15% BAC"}],correct:1,explain_en:"Alcohol causes tunnel vision -- reducing peripheral (side) vision. Drivers may miss pedestrians and vehicles approaching from the sides.",explain_it:"L alcol causa visione a tunnel -- riducendo la visione periferica (laterale). I conducenti potrebbero non notare pedoni e veicoli che si avvicinano dai lati."},
  {cat:"alcohol",en:"What is the minimum vehicle impoundment period after a first DUI conviction in Florida?",it:"Qual e il periodo minimo di sequestro del veicolo dopo una prima condanna DUI in Florida?",options:[{en:"No impoundment required",it:"Nessun sequestro richiesto"},{en:"10 days",it:"10 giorni"},{en:"30 days",it:"30 giorni"},{en:"90 days",it:"90 giorni"}],correct:1,explain_en:"First DUI Florida: minimum 10-day vehicle impoundment or immobilization. Second DUI: 30 days. Third: 90 days.",explain_it:"Primo DUI Florida: sequestro minimo del veicolo di 10 giorni o immobilizzazione. Secondo DUI: 30 giorni. Terzo: 90 giorni."},
  {cat:"alcohol",en:"What is the body rate of alcohol metabolism per hour?",it:"Qual e il tasso di metabolismo dell alcol del corpo per ora?",options:[{en:"It varies -- exercise and coffee speed it up",it:"Varia -- l esercizio e il caffe lo accelerano"},{en:"About 0.015% BAC per hour regardless of other factors",it:"Circa 0,015% BAC per ora indipendentemente dagli altri fattori"},{en:"One standard drink per 30 minutes",it:"Un drink standard ogni 30 minuti"},{en:"Depends entirely on body weight",it:"Dipende interamente dal peso corporeo"}],correct:1,explain_en:"The liver metabolizes alcohol at about 0.015% BAC per hour regardless of exercise, coffee, or food. Time is the ONLY way to reduce BAC.",explain_it:"Il fegato metabolizza l alcol a circa 0,015% BAC per ora indipendentemente dall esercizio, dal caffe o dal cibo. Il tempo e l UNICO modo per ridurre il BAC."},
  {cat:"alcohol",en:"How does alcohol affect an older driver differently?",it:"In che modo l alcol influisce su un conducente anziano diversamente?",options:[{en:"Older drivers build greater tolerance",it:"I conducenti anziani sviluppano una maggiore tolleranza"},{en:"Older adults reach higher BAC from the same amount and are more likely on medications that interact with alcohol",it:"Gli adulti piu anziani raggiungono un BAC piu alto dalla stessa quantita e hanno piu probabilita di essere su farmaci che interagiscono con l alcol"},{en:"Age has no effect on alcohol impairment",it:"L eta non ha effetti sulla compromissione da alcol"},{en:"Older drivers are less impaired due to experience",it:"I conducenti anziani sono meno compromessi grazie all esperienza"}],correct:1,explain_en:"Older adults reach higher BAC from the same alcohol (less body water, slower metabolism) and are more likely on medications that interact with alcohol.",explain_it:"Gli adulti piu anziani raggiungono un BAC piu alto dalla stessa quantita di alcol e hanno piu probabilita di essere su farmaci che interagiscono con l alcol."},
  {cat:"alcohol",en:"What does Florida consider a standard drink for BAC purposes?",it:"Cosa considera la Florida un drink standard ai fini del BAC?",options:[{en:"Any size beer",it:"Qualsiasi taglia di birra"},{en:"14 grams of pure alcohol: 12 oz regular beer 5 oz wine or 1.5 oz 80-proof spirits",it:"14 grammi di alcol puro: 12 oz birra normale 5 oz vino o 1,5 oz liquori a 80 gradi"},{en:"One full bottle of wine",it:"Una bottiglia intera di vino"},{en:"Any alcoholic beverage consumed in one sitting",it:"Qualsiasi bevanda alcolica consumata in un unica seduta"}],correct:1,explain_en:"A standard drink contains about 14g pure alcohol: 12oz regular beer (5%), 5oz wine (12%), or 1.5oz spirits (40%).",explain_it:"Un drink standard contiene circa 14g di alcol puro: 12oz di birra normale (5%), 5oz di vino (12%) o 1,5oz di liquori (40%)."},
  {cat:"alcohol",en:"What is the Florida DUI school requirement after conviction?",it:"Qual e il requisito della scuola DUI Florida dopo la condanna?",options:[{en:"Optional course for reduced fines",it:"Corso opzionale per multe ridotte"},{en:"Mandatory substance abuse education required before license reinstatement",it:"Educazione obbligatoria sull abuso di sostanze richiesta prima del ripristino della patente"},{en:"A 1-day course for all drivers",it:"Un corso di 1 giorno per tutti i conducenti"},{en:"Only required for under-21 DUI convictions",it:"Richiesto solo per le condanne DUI under-21"}],correct:1,explain_en:"Florida DUI school is mandatory before reinstatement. Level I (21 hours) for standard DUI. Level II (21+ hours with treatment) for higher BAC or repeat offense.",explain_it:"La scuola DUI Florida e obbligatoria prima del ripristino. Livello I (21 ore) per DUI standard. Livello II (21+ ore con trattamento) per BAC piu alto o infrazione ripetuta."},
  {cat:"alcohol",en:"What is the Florida FR-44 insurance requirement?",it:"Qual e il requisito assicurativo FR-44 della Florida?",options:[{en:"Standard liability insurance proof",it:"Prova standard di assicurazione di responsabilita"},{en:"High-limit insurance required after DUI -- $100,000/$300,000 BI and $50,000 PDL for 3 years",it:"Assicurazione ad alto limite richiesta dopo DUI -- $100.000/$300.000 BI e $50.000 PDL per 3 anni"},{en:"Same as SR-22 but for motorcycles",it:"Uguale a SR-22 ma per le moto"},{en:"Proof of uninsured motorist coverage",it:"Prova di copertura automobilista non assicurato"}],correct:1,explain_en:"FR-44 is required after DUI conviction in Florida. It requires much higher liability limits than standard SR-22 and must be maintained for 3 years.",explain_it:"FR-44 e richiesto dopo la condanna DUI in Florida. Richiede limiti di responsabilita molto piu alti dello standard SR-22 e deve essere mantenuto per 3 anni."},
  {cat:"alcohol",en:"What is the nystagmus test used in DUI stops?",it:"Cos e il test del nistagmo usato nei fermi DUI?",options:[{en:"A test of how fast the eyes blink",it:"Un test di quanto velocemente battono gli occhi"},{en:"Observation of involuntary eye jerking when looking sideways -- alcohol causes exaggerated nystagmus",it:"Osservazione del tremore involontario degli occhi quando si guarda di lato -- l alcol causa un nistagmo esagerato"},{en:"A reading test to check for impairment",it:"Un test di lettura per verificare la compromissione"},{en:"Measuring the dilation of the pupil",it:"Misurare la dilatazione della pupilla"}],correct:1,explain_en:"HGN test: officer moves a stimulus horizontally. Alcohol causes distinct involuntary eye jerking (nystagmus) at certain angles -- used as a DUI indicator.",explain_it:"Test HGN: un agente muove uno stimolo orizzontalmente. L alcol causa un involontario tremore degli occhi (nistagmo) a certi angoli -- usato come indicatore DUI."},
  {cat:"alcohol",en:"What is the first organ primarily affected by alcohol after consumption?",it:"Qual e il primo organo principalmente influenzato dall alcol dopo il consumo?",options:[{en:"The liver",it:"Il fegato"},{en:"The brain -- alcohol reaches it within minutes via the bloodstream",it:"Il cervello -- l alcol lo raggiunge in pochi minuti attraverso il flusso sanguigno"},{en:"The kidneys",it:"I reni"},{en:"The stomach",it:"Lo stomaco"}],correct:1,explain_en:"Alcohol reaches the brain within 5-10 minutes of consumption. The frontal lobes (judgment, impulse control) are impaired first.",explain_it:"L alcol raggiunge il cervello entro 5-10 minuti dal consumo. I lobi frontali (giudizio, controllo degli impulsi) sono compromessi per primi."},
  {cat:"alcohol",en:"What are the Florida community service hours required for a first DUI?",it:"Quante ore di servizio alla comunita sono richieste per un primo DUI in Florida?",options:[{en:"25 hours",it:"25 ore"},{en:"50 hours minimum or $10 per hour in lieu",it:"Minimo 50 ore o $10 per ora in sostituzione"},{en:"100 hours mandatory",it:"100 ore obbligatorie"},{en:"200 hours mandatory",it:"200 ore obbligatorie"}],correct:1,explain_en:"First DUI Florida: minimum 50 hours community service (or $10/hour in lieu). Must be completed before license reinstatement.",explain_it:"Primo DUI Florida: minimo 50 ore di servizio alla comunita (o $10/ora in sostituzione). Deve essere completato prima del ripristino della patente."},
  {cat:"alcohol",en:"What is the minimum DUI fine for a first offense in Florida?",it:"Qual e la multa minima DUI per una prima infrazione in Florida?",options:[{en:"$100",it:"$100"},{en:"$500",it:"$500"},{en:"$1,000",it:"$1.000"},{en:"$2,500",it:"$2.500"}],correct:1,explain_en:"First DUI in Florida: minimum $500 fine (up to $1,000); with BAC 0.15%+ or minor in vehicle: $1,000 minimum (up to $2,000). Plus court costs and fees.",explain_it:"Primo DUI in Florida: multa minima $500 (fino a $1.000); con BAC 0,15%+ o minore nel veicolo: minimo $1.000 (fino a $2.000). Piu spese giudiziarie."},
  {cat:"alcohol",en:"What is the maximum jail time for a first DUI offense in Florida with no injury?",it:"Qual e il tempo massimo di prigione per una prima infrazione DUI in Florida senza lesioni?",options:[{en:"24 hours",it:"24 ore"},{en:"6 months",it:"6 mesi"},{en:"1 year",it:"1 anno"},{en:"5 years",it:"5 anni"}],correct:1,explain_en:"First DUI in Florida: up to 6 months jail. With BAC 0.15%+ or minor passenger: up to 9 months. Total combined jail + probation cannot exceed 12 months.",explain_it:"Primo DUI in Florida: fino a 6 mesi di prigione. Con BAC 0,15%+ o passeggero minore: fino a 9 mesi. Il totale carcere + liberta vigilata non puo superare 12 mesi."},
  {cat:"alcohol",en:"What does implied consent in Florida mean for commercial drivers?",it:"Cosa significa il consenso implicito in Florida per i conducenti commerciali?",options:[{en:"Commercial drivers are exempt from implied consent",it:"I conducenti commerciali sono esenti dal consenso implicito"},{en:"CDL holders are subject to implied consent and their 0.04% BAC limit applies even in a personal vehicle in some situations",it:"I titolari CDL sono soggetti al consenso implicito e il loro limite di 0,04% BAC si applica anche in un veicolo personale in alcune situazioni"},{en:"Only applies when driving a commercial vehicle",it:"Si applica solo quando si guida un veicolo commerciale"},{en:"Commercial drivers have additional refusal options",it:"I conducenti commerciali hanno opzioni di rifiuto aggiuntive"}],correct:1,explain_en:"CDL holders are subject to implied consent. The 0.04% limit applies when operating a commercial vehicle. A CDL refusal can result in both license suspensions and CDL disqualification.",explain_it:"I titolari CDL sono soggetti al consenso implicito. Il limite di 0,04% si applica quando si opera un veicolo commerciale."},
  {cat:"license",en:"What is the Florida GDL system for teens?",it:"Cos e il sistema GDL della Florida per gli adolescenti?",options:[{en:"A direct full license at age 16",it:"Una patente completa diretta a 16 anni"},{en:"Three phases: learner license at 15 provisional at 16 full unrestricted at 18",it:"Tre fasi: patente per principianti a 15 provvisoria a 16 completa a 18"},{en:"A driving test at 16 for a full license",it:"Un test di guida a 16 anni per la patente completa"},{en:"A learner permit valid until age 21",it:"Un permesso per principianti valido fino a 21 anni"}],correct:1,explain_en:"Florida GDL: Learner License (15+, minimum 12 months with 50 supervised hours including 10 at night), Provisional License (16-17, curfew and passenger restrictions), Full License (18+).",explain_it:"GDL Florida: Patente per Principianti (15+, minimo 12 mesi con 50 ore supervisionate incluse 10 di notte), Patente Provvisoria (16-17), Patente Completa (18+)."},
  {cat:"license",en:"What are the driving restrictions for a Florida provisional license holder aged 16-17?",it:"Quali sono le restrizioni per un titolare di patente provvisoria Florida di 16-17 anni?",options:[{en:"No restrictions -- full driving privileges",it:"Nessuna restrizione -- pieno privilegio di guida"},{en:"No driving 11PM to 6AM except employment school or emergencies; max 1 non-family passenger under 18",it:"Nessuna guida dalle 23 alle 6 tranne per lavoro scuola o emergenze; max 1 passeggero non familiare under 18"},{en:"Must be accompanied by a licensed adult at all times",it:"Deve essere accompagnato da un adulto patentato in ogni momento"},{en:"Only allowed to drive to school and work",it:"Autorizzato a guidare solo a scuola e al lavoro"}],correct:1,explain_en:"Florida provisional license (16-17): no driving 11PM-6AM (except school, work, emergencies), and no more than 1 non-family passenger under 18 for the first year.",explain_it:"Patente provvisoria Florida (16-17): nessuna guida dalle 23 alle 6 (tranne scuola, lavoro, emergenze), e non piu di 1 passeggero non familiare under 18 per il primo anno."},
  {cat:"license",en:"How many supervised hours must a Florida learner log before getting a provisional license?",it:"Quante ore supervisionate deve registrare un apprendista Florida prima di ottenere la patente provvisoria?",options:[{en:"25 hours total",it:"25 ore totali"},{en:"50 hours total including 10 at night",it:"50 ore totali incluse 10 di notte"},{en:"100 hours total",it:"100 ore totali"},{en:"No minimum hour requirement",it:"Nessun requisito minimo di ore"}],correct:1,explain_en:"Florida learner license: 50 supervised driving hours (10 at night) over at least 12 months before applying for provisional license.",explain_it:"Patente per principianti Florida: 50 ore di guida supervisionate (10 di notte) in almeno 12 mesi prima di richiedere la patente provvisoria."},
  {cat:"license",en:"What is required for a Florida REAL ID driver license?",it:"Cosa e richiesto per una patente Florida REAL ID?",options:[{en:"Only a birth certificate",it:"Solo un certificato di nascita"},{en:"Proof of identity Social Security number and two proofs of Florida residential address",it:"Prova di identita numero di previdenza sociale e due prove di indirizzo residenziale in Florida"},{en:"Passport only",it:"Solo passaporto"},{en:"Voter registration card and birth certificate",it:"Carta di iscrizione elettorale e certificato di nascita"}],correct:1,explain_en:"Florida REAL ID requires: proof of identity (passport or birth certificate plus photo ID), Social Security documentation, and TWO proofs of Florida residential address.",explain_it:"REAL ID Florida richiede: prova di identita, documentazione di previdenza sociale e DUE prove di indirizzo residenziale in Florida."},
  {cat:"license",en:"What is the Florida SR-22 insurance certificate?",it:"Cos e il certificato assicurativo Florida SR-22?",options:[{en:"Basic proof of insurance",it:"Prova base di assicurazione"},{en:"A certificate filed by your insurer proving minimum required coverage -- required after certain violations for 3 years",it:"Un certificato presentato dalla tua assicurazione che prova la copertura minima richiesta -- richiesto dopo certe violazioni per 3 anni"},{en:"Insurance for high-performance vehicles",it:"Assicurazione per veicoli ad alte prestazioni"},{en:"A no-fault insurance waiver",it:"Una rinuncia all assicurazione no-fault"}],correct:1,explain_en:"SR-22 is a certificate your insurer files with FLHSMV proving you have required minimum liability insurance. Required after certain violations for 3 years.",explain_it:"SR-22 e un certificato che la tua assicurazione deposita presso FLHSMV provando che hai la copertura assicurativa minima richiesta."},
  {cat:"license",en:"What is the Florida Basic Driver Improvement BDI course?",it:"Cos e il corso Florida Basic Driver Improvement BDI?",options:[{en:"A mandatory course for all new drivers",it:"Un corso obbligatorio per tutti i nuovi conducenti"},{en:"A voluntary course that removes 3 points from your record -- available once per year up to 5 times lifetime",it:"Un corso volontario che rimuove 3 punti dal tuo casellario -- disponibile una volta l anno fino a 5 volte nella vita"},{en:"A DUI treatment program",it:"Un programma di trattamento DUI"},{en:"Required only for drivers under 21",it:"Richiesto solo per i conducenti under 21"}],correct:1,explain_en:"BDI: elect it when ticketed instead of paying the fine. Removes 3 points. Available once per 12 months, maximum 5 times in a lifetime.",explain_it:"BDI: sceglierlo quando si riceve una multa invece di pagare. Rimuove 3 punti. Disponibile una volta ogni 12 mesi, massimo 5 volte nella vita."},
  {cat:"license",en:"What is the Florida law on insurance when driving a car you do not own?",it:"Qual e la legge Florida sull assicurazione quando si guida un auto che non si possiede?",options:[{en:"Your personal insurance always covers any car you drive",it:"La tua assicurazione personale copre sempre qualsiasi auto che guidi"},{en:"Insurance follows the vehicle -- owner insurance is primary your own may be secondary",it:"L assicurazione segue il veicolo -- l assicurazione del proprietario e primaria la tua puo essere secondaria"},{en:"Must purchase a separate policy for every vehicle you drive",it:"Devi acquistare una polizza separata per ogni veicolo che guidi"},{en:"No insurance required when borrowing a vehicle",it:"Nessuna assicurazione e richiesta quando si prende in prestito un veicolo"}],correct:1,explain_en:"Auto insurance is tied to the vehicle in Florida. The car owner policy is primary. Your own insurance may provide secondary coverage.",explain_it:"L assicurazione auto e legata al veicolo in Florida. La polizza del proprietario e primaria. La tua assicurazione puo fornire copertura secondaria."},
  {cat:"license",en:"What are the required documents for a non-US citizen to get a Florida driver license?",it:"Quali sono i documenti richiesti per un cittadino non americano per ottenere la patente Florida?",options:[{en:"Foreign passport only",it:"Solo passaporto straniero"},{en:"Valid immigration document plus standard Florida license requirements",it:"Documento di immigrazione valido piu i requisiti standard per la patente Florida"},{en:"No special documents required",it:"Nessun documento speciale richiesto"},{en:"Must become a US citizen first",it:"Deve prima diventare cittadino americano"}],correct:1,explain_en:"Non-US citizens must provide valid immigration documentation (visa, green card, etc.) plus standard requirements: identity proof, Social Security or ineligibility letter, and two proofs of Florida address.",explain_it:"I cittadini non americani devono fornire documentazione di immigrazione valida piu i requisiti standard: prova di identita, previdenza sociale e due prove di indirizzo Florida."},
  {cat:"license",en:"What point values apply to common Florida traffic violations?",it:"Quali valori di punti si applicano alle comuni violazioni del traffico Florida?",options:[{en:"All violations equal 2 points",it:"Tutte le violazioni uguale 2 punti"},{en:"Minor violations 3 points moderate 4 points serious 6 points",it:"Violazioni minori 3 punti moderate 4 punti gravi 6 punti"},{en:"All violations equal 3 points",it:"Tutte le violazioni uguale 3 punti"},{en:"Points only added for speeding",it:"I punti vengono aggiunti solo per la velocita"}],correct:1,explain_en:"Florida points: 3 points (minor violations, speeding under 15 mph over); 4 points (reckless driving, speeding 15-29 over, passing school bus); 6 points (speeding 30+ over, leaving crash scene).",explain_it:"Punti Florida: 3 punti (violazioni minori); 4 punti (guida spericolata, velocita 15-29 oltre, sorpasso scuolabus); 6 punti (velocita 30+ oltre, fuga dalla scena)."},
  {cat:"license",en:"What is the minimum age to apply for a Florida CDL?",it:"Qual e l eta minima per richiedere la CDL Florida?",options:[{en:"16 years old",it:"16 anni"},{en:"18 for intrastate 21 for interstate commerce",it:"18 per il trasporto intrastatale 21 per il commercio interstatale"},{en:"21 for all CDL holders",it:"21 per tutti i titolari CDL"},{en:"18 for all CDL holders",it:"18 per tutti i titolari CDL"}],correct:1,explain_en:"CDL: 18 to drive commercially within Florida; 21 to drive commercially across state lines. Federal law requires 21 for interstate CDL operations.",explain_it:"CDL: 18 anni per guidare commercialmente in Florida; 21 per guidare commercialmente attraverso i confini statali."},
  {cat:"license",en:"What is the penalty for a first-time violation of the Florida provisional license curfew?",it:"Qual e la sanzione per una prima violazione del coprifuoco della patente provvisoria Florida?",options:[{en:"Automatic license revocation",it:"Revoca automatica della patente"},{en:"A moving violation -- the provisional license may be extended and GDL clock may restart",it:"Una violazione in movimento -- la patente provvisoria puo essere estesa e l orologio GDL puo ripartire"},{en:"Only a verbal warning from police",it:"Solo un avvertimento verbale dalla polizia"},{en:"A $500 fine with no license impact",it:"Una multa di $500 senza impatto sulla patente"}],correct:1,explain_en:"Violating GDL restrictions (curfew, passenger limits) is a moving violation. The provisional period may be extended and the teen may lose driving privileges.",explain_it:"Violare le restrizioni GDL (coprifuoco, limiti di passeggeri) e una violazione in movimento. Il periodo provvisorio puo essere esteso."},
  {cat:"license",en:"What is the Florida law on vision requirements for a driver license?",it:"Qual e la legge Florida sui requisiti di visione per la patente?",options:[{en:"No vision requirements",it:"Nessun requisito di visione"},{en:"At least 20/40 vision in the better eye with or without correction",it:"Almeno visione 20/40 nell occhio migliore con o senza correzione"},{en:"20/20 vision required in both eyes",it:"Visione 20/20 richiesta in entrambi gli occhi"},{en:"Only required for CDL holders",it:"Richiesto solo per i titolari CDL"}],correct:1,explain_en:"Florida requires minimum 20/40 vision in the better eye (with glasses or contacts if needed). Drivers who do not meet this require a restriction on their license.",explain_it:"La Florida richiede visione minima 20/40 nell occhio migliore (con occhiali o lenti a contatto se necessario)."},
  {cat:"license",en:"What does a Florida driver license restriction code B mean?",it:"Cosa significa il codice di restrizione B della patente Florida?",options:[{en:"No highway driving",it:"Nessuna guida in autostrada"},{en:"Corrective lenses required while driving",it:"Lenti correttive richieste durante la guida"},{en:"Daylight driving only",it:"Guida solo di giorno"},{en:"Automatic transmission only",it:"Solo cambio automatico"}],correct:1,explain_en:"Restriction B on a Florida license means corrective lenses (glasses or contact lenses) must be worn while driving. Driving without them is a traffic violation.",explain_it:"La restrizione B sulla patente Florida significa che le lenti correttive devono essere indossate durante la guida. Guidare senza di esse e una violazione del traffico."},
  {cat:"license",en:"What is the Florida law on driving without proof of insurance?",it:"Qual e la legge Florida sulla guida senza prova di assicurazione?",options:[{en:"Only a warning for first offense",it:"Solo un avvertimento per la prima infrazione"},{en:"A non-criminal traffic infraction with a fine plus potential license suspension for no actual insurance",it:"Un infrazione del traffico non penale con multa piu potenziale sospensione della patente per assenza di assicurazione effettiva"},{en:"A criminal misdemeanor",it:"Un reato minore penale"},{en:"No penalty -- insurance is optional in Florida",it:"Nessuna sanzione -- l assicurazione e opzionale in Florida"}],correct:1,explain_en:"Driving without proof of insurance: fine plus possible license suspension. Driving without actual insurance (not just proof): license and registration suspended until you obtain coverage and pay reinstatement fee.",explain_it:"Guidare senza prova di assicurazione: multa piu possibile sospensione della patente."},
  {cat:"license",en:"What happens to a Florida driver license when the owner moves to a new state?",it:"Cosa succede alla patente Florida quando il proprietario si trasferisce in un nuovo stato?",options:[{en:"The Florida license remains valid indefinitely",it:"La patente Florida rimane valida indefinitamente"},{en:"Must obtain the new state license within that state required time -- typically 30 to 90 days of establishing residency",it:"Deve ottenere la patente del nuovo stato entro il tempo richiesto da quello stato -- tipicamente 30-90 giorni dopo aver stabilito la residenza"},{en:"Must return the Florida license by mail",it:"Deve restituire la patente Florida per posta"},{en:"Florida license is suspended automatically when leaving the state",it:"La patente Florida viene sospesa automaticamente quando si lascia lo stato"}],correct:1,explain_en:"When establishing residency in a new state, you must obtain that state license within their required timeframe (usually 30-90 days). The old license is surrendered when getting the new one.",explain_it:"Quando si stabilisce la residenza in un nuovo stato, si deve ottenere la patente di quello stato entro i tempi richiesti (di solito 30-90 giorni)."},
  {cat:"license",en:"What is the fee to reinstate a Florida license after a DUI conviction?",it:"Qual e la quota per ripristinare la patente Florida dopo una condanna DUI?",options:[{en:"A flat $50 fee",it:"Una tariffa fissa di $50"},{en:"Between $150 and $500 plus FR-44 insurance DUI school and other requirements",it:"Tra $150 e $500 piu assicurazione FR-44 scuola DUI e altri requisiti"},{en:"No reinstatement fee only DUI school required",it:"Nessuna quota di ripristino solo scuola DUI richiesta"},{en:"$1,000 flat fee",it:"Quota fissa di $1.000"}],correct:1,explain_en:"Florida DUI reinstatement: $150-$500 FLHSMV fee plus FR-44 insurance plus DUI school plus IID if required plus court fees. Total costs can exceed $5,000.",explain_it:"Ripristino DUI Florida: quota FLHSMV di $150-$500 piu assicurazione FR-44 piu scuola DUI piu costi IID se richiesti piu spese giudiziarie."},
  {cat:"license",en:"When can a Florida driver's license be voluntarily surrendered?",it:"Quando puo essere volontariamente consegnata la patente Florida?",options:[{en:"Only when ordered by a court",it:"Solo quando ordinato da un tribunale"},{en:"At any time -- a driver may voluntarily surrender their license to FLHSMV",it:"In qualsiasi momento -- un conducente puo volontariamente consegnare la patente al FLHSMV"},{en:"Only during license renewal",it:"Solo durante il rinnovo della patente"},{en:"Only when moving out of state",it:"Solo quando ci si trasferisce fuori dallo stato"}],correct:1,explain_en:"A Florida driver may voluntarily surrender their license to FLHSMV at any time -- for example when they decide to stop driving due to health or age.",explain_it:"Un conducente Florida puo volontariamente consegnare la patente al FLHSMV in qualsiasi momento -- ad esempio quando decide di smettere di guidare per salute o eta."},
  {cat:"license",en:"What is the Florida law on driving after a license expires?",it:"Qual e la legge Florida sulla guida dopo la scadenza della patente?",options:[{en:"Legal for up to 6 months after expiration",it:"Legale fino a 6 mesi dopo la scadenza"},{en:"Illegal -- driving with an expired license is a traffic infraction",it:"Illegale -- guidare con la patente scaduta e un infrazione del traffico"},{en:"Legal as long as you have valid insurance",it:"Legale purche si abbia assicurazione valida"},{en:"Legal for renewals in process",it:"Legale per i rinnovi in corso"}],correct:1,explain_en:"Driving with an expired license is a traffic infraction in Florida. Renew before expiration -- most renewals can be done online, by mail, or in person.",explain_it:"Guidare con la patente scaduta e un infrazione del traffico in Florida. Rinnovare prima della scadenza."},
  {cat:"license",en:"What is the Florida law on wearing corrective lenses if your license requires them?",it:"Qual e la legge Florida sull indossare lenti correttive se la tua patente le richiede?",options:[{en:"Advisory only -- no enforcement",it:"Solo consiglio -- nessuna applicazione"},{en:"You must wear corrective lenses whenever you drive -- not wearing them is a traffic violation",it:"Devi indossare lenti correttive ogni volta che guidi -- non indossarle e una violazione del traffico"},{en:"Only required during night driving",it:"Richiesto solo durante la guida notturna"},{en:"Recommended but not legally required",it:"Raccomandato ma non legalmente richiesto"}],correct:1,explain_en:"If your Florida license has a corrective lens restriction (code B), you MUST wear glasses or contacts whenever you drive. Driving without them violates your license restriction.",explain_it:"Se la tua patente Florida ha la restrizione lenti correttive (codice B), DEVI indossare occhiali o lenti a contatto ogni volta che guidi."},,

  // SESSION 7
  {cat:"signs",en:"What does a 'Keep Left' sign with an arrow indicate?",it:"Cosa indica un segnale 'Keep Left' con una freccia?",options:[{en:"Move to the left lane only",it:"Spostarsi solo nella corsia sinistra"},{en:"Pass an obstruction or median on the left side",it:"Passare un ostacolo o mediano sul lato sinistro"},{en:"Left lane is open",it:"La corsia sinistra e aperta"},{en:"Make a left turn ahead",it:"Fare una svolta sinistra in avanti"}],correct:1,explain_en:"Keep Left with arrow directs you to pass an obstacle, island, or divider on its left side.",explain_it:"Keep Left con freccia ti indica di passare un ostacolo, un'isola o un divisore sul suo lato sinistro."},
  {cat:"signs",en:"What is the color of a guide sign that shows highway route numbers?",it:"Qual e il colore di un segnale guida che mostra i numeri delle rotte autostradali?",options:[{en:"Blue",it:"Blu"},{en:"Green",it:"Verde"},{en:"White",it:"Bianco"},{en:"Brown",it:"Marrone"}],correct:1,explain_en:"Green signs are guide signs showing highway route numbers, directions, distances, and destinations.",explain_it:"I segnali verdi sono segnali guida che mostrano i numeri delle rotte autostradali, le direzioni, le distanze e le destinazioni."},
  {cat:"signs",en:"What does a yellow diamond sign with a picture of a truck tilting show?",it:"Cosa mostra un segnale a rombo giallo con l'immagine di un camion che si inclina?",options:[{en:"Slippery road ahead for trucks",it:"Strada scivolosa in avanti per i camion"},{en:"Side winds or rollover risk on the road ahead -- especially for high-sided vehicles",it:"Venti laterali o rischio di ribaltamento sulla strada in avanti -- specialmente per i veicoli alti"},{en:"Uneven lane widths ahead",it:"Larghezze di corsia irregolari in avanti"},{en:"Trucks must use lower gear",it:"I camion devono usare una marcia piu bassa"}],correct:1,explain_en:"A tilting truck sign warns of crosswind conditions or road geometry that poses a rollover risk, especially for trucks, RVs, and high-profile vehicles.",explain_it:"Un segnale di camion che si inclina avvisa delle condizioni di vento trasversale o della geometria della strada che pone un rischio di ribaltamento, specialmente per camion e veicoli alti."},
  {cat:"signs",en:"What does a white diamond-shaped sign in a travel lane indicate?",it:"Cosa indica un segnale bianco a forma di rombo in una corsia di marcia?",options:[{en:"A caution zone for new drivers",it:"Una zona di cautela per i nuovi conducenti"},{en:"A reserved lane for High Occupancy Vehicles (HOV) or special use",it:"Una corsia riservata per i veicoli ad alta occupazione (HOV) o uso speciale"},{en:"A passing zone begins",it:"Inizia una zona di sorpasso"},{en:"The lane narrows ahead",it:"La corsia si restringe in avanti"}],correct:1,explain_en:"White diamond pavement markings indicate lanes reserved for HOV (carpool) or other special use. These lanes may have specific time restrictions.",explain_it:"Le marcature stradali a rombo bianco indicano corsie riservate per HOV (car pooling) o altro uso speciale. Queste corsie possono avere restrizioni di orario specifiche."},
  {cat:"signs",en:"What does a 'Merge' sign indicate on a highway entrance ramp?",it:"Cosa indica un segnale 'Merge' su una rampa di accesso autostradale?",options:[{en:"The right lane is ending -- merge left",it:"La corsia destra sta finendo -- confluire a sinistra"},{en:"Another road is joining your road -- be prepared for merging traffic",it:"Un'altra strada si unisce alla tua -- preparati per il traffico confluente"},{en:"You must slow to 35 mph",it:"Devi rallentare a 35 mph"},{en:"Stay in your current lane",it:"Rimani nella tua corsia attuale"}],correct:1,explain_en:"Merge signs warn that another road joins yours. Traffic from the merging road must yield. Drivers on the main road should allow space when safely possible.",explain_it:"I segnali Merge avvisano che un'altra strada si unisce alla tua. Il traffico dalla strada confluente deve cedere. I conducenti sulla strada principale dovrebbero lasciare spazio quando possibile."},
  {cat:"signs",en:"What does a sign reading 'ROAD CLOSED' mean?",it:"Cosa significa un segnale 'ROAD CLOSED'?",options:[{en:"Road is closed at night only",it:"La strada e chiusa solo di notte"},{en:"The road is completely closed to through traffic -- use an alternate route",it:"La strada e completamente chiusa al traffico di transito -- utilizzare un percorso alternativo"},{en:"Road closed for construction -- slow to 25 mph",it:"Strada chiusa per costruzione -- rallentare a 25 mph"},{en:"One lane closed -- alternating traffic",it:"Una corsia chiusa -- traffico alternato"}],correct:1,explain_en:"Road Closed signs indicate the road is completely closed to traffic. You must turn around and use an alternate route.",explain_it:"I segnali Road Closed indicano che la strada e completamente chiusa al traffico. Devi girare indietro e usare un percorso alternativo."},
  {cat:"signs",en:"What does a 'Lane Ends Merge Left' sign mean?",it:"Cosa significa un segnale 'Lane Ends Merge Left'?",options:[{en:"Move to the right lane immediately",it:"Spostarsi immediatamente nella corsia destra"},{en:"Your current lane ends ahead -- safely move left into the continuing lane",it:"La tua corsia attuale finisce in avanti -- spostarsi in sicurezza a sinistra nella corsia che continua"},{en:"Only trucks must merge",it:"Solo i camion devono confluire"},{en:"Speed up and merge before the sign",it:"Accelerare e confluire prima del segnale"}],correct:1,explain_en:"Lane Ends Merge Left means your lane is dropping. Begin safely moving left before the lane ends -- do not rush to the last second.",explain_it:"Lane Ends Merge Left significa che la tua corsia sta terminando. Iniziare a spostarsi a sinistra in sicurezza prima che la corsia finisca."},
  {cat:"signs",en:"What does an orange 'Detour' sign indicate?",it:"Cosa indica un segnale arancione 'Detour'?",options:[{en:"A scenic alternate route",it:"Un percorso alternativo panoramico"},{en:"The normal road is closed and you must follow the temporary alternate route indicated",it:"La strada normale e chiusa e devi seguire il percorso alternativo temporaneo indicato"},{en:"A shorter route to your destination",it:"Un percorso piu breve verso la tua destinazione"},{en:"A toll road bypass",it:"Un bypass per la strada a pedaggio"}],correct:1,explain_en:"Orange Detour signs direct drivers on a temporary alternate route when the normal road is closed for construction, emergencies, or events.",explain_it:"I segnali arancioni Detour dirigono i conducenti su un percorso alternativo temporaneo quando la strada normale e chiusa per costruzione, emergenze o eventi."},
  {cat:"signs",en:"What does a 'Speed Zone Ahead' sign tell you?",it:"Cosa ti dice un segnale 'Speed Zone Ahead'?",options:[{en:"The current speed limit ends",it:"Il limite di velocita attuale finisce"},{en:"A reduced speed zone is approaching -- prepare to reduce speed to the upcoming posted limit",it:"Si sta avvicinando una zona a velocita ridotta -- prepararsi a ridurre la velocita al prossimo limite segnalato"},{en:"No speed limit applies ahead",it:"Nessun limite di velocita si applica in avanti"},{en:"You are entering a highway",it:"Stai entrando in un'autostrada"}],correct:1,explain_en:"Speed Zone Ahead warns that a reduced speed is coming up (school zone, work zone, business district). Begin slowing now.",explain_it:"Speed Zone Ahead avvisa che si sta avvicinando una velocita ridotta (zona scolastica, zona di lavoro, distretto commerciale). Iniziare a rallentare ora."},
  {cat:"signs",en:"What does a 'Crossover' sign on a divided highway indicate?",it:"Cosa indica un segnale 'Crossover' su un'autostrada divisa?",options:[{en:"A railroad crossing ahead",it:"Un passaggio a livello in avanti"},{en:"An opening in the median that allows crossing to the opposite side -- typically for emergency or maintenance vehicles",it:"Un'apertura nel mediano che consente di attraversare al lato opposto -- tipicamente per veicoli di emergenza o manutenzione"},{en:"A U-turn is permitted here",it:"Un'inversione di marcia e consentita qui"},{en:"An intersection with a crossroad",it:"Un incrocio con una strada trasversale"}],correct:1,explain_en:"Crossover openings in medians are for authorized vehicles (emergency, maintenance). Civilian drivers may only use them when directed by police or traffic control.",explain_it:"Le aperture di crossover nei mediani sono per i veicoli autorizzati (emergenza, manutenzione). I conducenti civili possono usarli solo quando indicato dalla polizia o dal controllo del traffico."},
  {cat:"signs",en:"What is the meaning of a yellow-green fluorescent sign in a school zone?",it:"Qual e il significato di un segnale verde-giallo fluorescente in una zona scolastica?",options:[{en:"Standard warning sign color",it:"Colore standard del segnale di avvertimento"},{en:"Enhanced visibility school warning sign -- used to draw extra attention to pedestrian and school hazards",it:"Segnale di avvertimento scolastico ad alta visibilita -- usato per attirare ulteriore attenzione ai pericoli pedonali e scolastici"},{en:"Indicates a park or recreation area",it:"Indica un parco o un'area ricreativa"},{en:"Construction zone for school buildings",it:"Zona di costruzione per edifici scolastici"}],correct:1,explain_en:"Fluorescent yellow-green signs are used in school and pedestrian zones for maximum visibility -- the color is highly attention-grabbing day or night.",explain_it:"I segnali verde-giallo fluorescente sono usati nelle zone scolastiche e pedonali per la massima visibilita."},
  {cat:"signs",en:"What does 'BEGIN RIGHT TURN LANE MUST TURN RIGHT' pavement marking mean?",it:"Cosa significa la marcatura stradale 'BEGIN RIGHT TURN LANE MUST TURN RIGHT'?",options:[{en:"Right turns are recommended here",it:"Le svolte destra sono raccomandate qui"},{en:"A mandatory right-turn-only lane begins -- vehicles in this lane must turn right",it:"Inizia una corsia solo svolta destra obbligatoria -- i veicoli in questa corsia devono svoltare a destra"},{en:"Keep right unless passing",it:"Mantenersi a destra tranne quando si sorpassa"},{en:"Right turn signal must be used",it:"Il segnale di svolta destra deve essere usato"}],correct:1,explain_en:"'Must Turn Right' markings indicate a mandatory turn lane -- you cannot go straight from this lane. It prevents through traffic from blocking turning lanes.",explain_it:"Le marcature 'Must Turn Right' indicano una corsia di svolta obbligatoria -- non puoi andare dritto da questa corsia."},
  {cat:"signs",en:"What does a white line painted across the road at an intersection represent?",it:"Cosa rappresenta una linea bianca dipinta attraverso la strada a un incrocio?",options:[{en:"A crosswalk for pedestrians",it:"Un attraversamento pedonale per i pedoni"},{en:"A stop line -- where your vehicle must stop behind",it:"Una linea di stop -- dove il tuo veicolo deve fermarsi"},{en:"A yield line",it:"Una linea di precedenza"},{en:"The edge of the intersection",it:"Il bordo dell'incrocio"}],correct:1,explain_en:"A solid white line across the road is a stop line. Your vehicle must stop with the front bumper behind this line when required by a sign or signal.",explain_it:"Una linea bianca continua attraverso la strada e una linea di stop. Il tuo veicolo deve fermarsi con il paraurti anteriore dietro questa linea quando richiesto."},
  {cat:"signs",en:"What do triangular white yield lines painted on the road at an intersection indicate?",it:"Cosa indicano le linee di precedenza triangolari bianche dipinte sulla strada a un incrocio?",options:[{en:"A railroad crossing",it:"Un passaggio a livello"},{en:"A yield point -- slow down and be prepared to yield to cross traffic",it:"Un punto di precedenza -- rallentare ed essere pronti a cedere al traffico trasversale"},{en:"The beginning of a bike lane",it:"L'inizio di una corsia ciclabile"},{en:"A pedestrian refuge island",it:"Un'isola rifugio per pedoni"}],correct:1,explain_en:"Triangular yield lines (shark teeth) mark where vehicles must yield. Stop if necessary to let crossing traffic pass before proceeding.",explain_it:"Le linee di precedenza triangolari (denti di squalo) segnano dove i veicoli devono cedere. Fermarsi se necessario per lasciare passare il traffico trasversale prima di procedere."},
  {cat:"signs",en:"What does a white edge line on the left side of a one-way road mean?",it:"Cosa significa una linea bordo bianca sul lato sinistro di una strada a senso unico?",options:[{en:"The left edge of the roadway -- do not drive to the left of it",it:"Il bordo sinistro della carreggiata -- non guidare a sinistra di essa"},{en:"A bus lane begins",it:"Inizia una corsia bus"},{en:"The passing lane begins",it:"Inizia la corsia di sorpasso"},{en:"The shoulder is usable for all traffic",it:"La banchina e utilizzabile per tutto il traffico"}],correct:0,explain_en:"White edge lines on the left of a one-way road mark the left boundary. On two-way roads, the left edge is marked with a yellow line.",explain_it:"Le linee bordo bianche sul lato sinistro di una strada a senso unico segnano il confine sinistro. Sulle strade a due sensi, il bordo sinistro e segnato con una linea gialla."},
  {cat:"signs",en:"What does a double yellow center line on a two-lane road indicate?",it:"Cosa indica una doppia linea gialla centrale su una strada a due corsie?",options:[{en:"Passing is permitted in both directions",it:"Il sorpasso e consentito in entrambe le direzioni"},{en:"Passing is prohibited in both directions -- do not cross either line",it:"Il sorpasso e vietato in entrambe le direzioni -- non attraversare nessuna delle due linee"},{en:"Only left turns are prohibited",it:"Solo le svolte sinistra sono vietate"},{en:"Divided highway begins",it:"Inizia un'autostrada divisa"}],correct:1,explain_en:"Double solid yellow lines prohibit passing in both directions. You may not cross them except to turn into a driveway or intersection.",explain_it:"Le doppie linee gialle continue vietano il sorpasso in entrambe le direzioni. Non puoi attraversarle tranne che per svoltare in un vialetto o incrocio."},
  {cat:"signs",en:"What does a broken (dashed) white line between lanes on a multi-lane road mean?",it:"Cosa significa una linea bianca tratteggiata tra le corsie su una strada a piu corsie?",options:[{en:"No lane changes permitted",it:"Nessun cambio di corsia consentito"},{en:"Lane changes are permitted when safe",it:"I cambi di corsia sono consentiti quando sicuro"},{en:"The lane is ending",it:"La corsia sta finendo"},{en:"HOV lane restriction",it:"Restrizione corsia HOV"}],correct:1,explain_en:"Dashed white lines between lanes mean lane changes are permitted when it is safe to do so. Always check mirrors and blind spots before changing lanes.",explain_it:"Le linee bianche tratteggiate tra le corsie significano che i cambi di corsia sono consentiti quando e sicuro farlo."},
  {cat:"signs",en:"What does a solid white line between lanes of traffic moving in the same direction mean?",it:"Cosa significa una linea bianca continua tra le corsie di traffico che si muovono nella stessa direzione?",options:[{en:"Lane changes are encouraged",it:"I cambi di corsia sono incoraggiati"},{en:"Lane changes are discouraged -- do not cross unless necessary for safety",it:"I cambi di corsia sono scoraggiati -- non attraversare se non necessario per la sicurezza"},{en:"The lanes merge ahead",it:"Le corsie confluiscono in avanti"},{en:"Reserved lane for cyclists",it:"Corsia riservata ai ciclisti"}],correct:1,explain_en:"Solid white lane lines discourage lane changes (near intersections, on ramps, in tunnels). Cross only if necessary for safety.",explain_it:"Le linee di corsia bianche continue scoraggiano i cambi di corsia (vicino agli incroci, sulle rampe, nelle gallerie). Attraversare solo se necessario per la sicurezza."},
  {cat:"signs",en:"What is the meaning of yellow crosshatch markings on the road?",it:"Qual e il significato delle marcature gialle a tratteggio incrociato sulla strada?",options:[{en:"A slow-down zone",it:"Una zona di rallentamento"},{en:"A keep-clear zone -- do not stop or park in this area even if traffic is backed up",it:"Una zona libera -- non fermarsi o parcheggiare in quest'area anche se il traffico e intasato"},{en:"A pedestrian waiting area",it:"Un'area di attesa pedonale"},{en:"A school bus loading zone",it:"Una zona di carico degli scuolabus"}],correct:1,explain_en:"Yellow crosshatch (box junction) markings mean keep clear -- do not enter unless your exit is clear. Common near intersections and fire station exits.",explain_it:"Le marcature a tratteggio incrociato giallo (box junction) significano tenersi liberi -- non entrare se l'uscita non e libera. Comuni vicino agli incroci e alle uscite delle stazioni dei pompieri."},
  {cat:"signs",en:"What does a white diagonal line through a painted bicycle symbol in a lane mean?",it:"Cosa significa una linea diagonale bianca attraverso un simbolo di bicicletta dipinto in una corsia?",options:[{en:"Bicycles must use this lane",it:"Le biciclette devono usare questa corsia"},{en:"Bicycles are prohibited from this lane",it:"Le biciclette sono vietate in questa corsia"},{en:"The bicycle lane is ending",it:"La corsia ciclabile sta finendo"},{en:"The bicycle lane begins",it:"La corsia ciclabile inizia"}],correct:1,explain_en:"A bicycle symbol with a diagonal prohibition line means bicycles are prohibited from that lane.",explain_it:"Un simbolo di bicicletta con una linea di divieto diagonale significa che le biciclette sono vietate in quella corsia."},
  {cat:"laws",en:"What is Florida's law on right of way at an uncontrolled intersection?",it:"Qual e la legge Florida sulla precedenza a un incrocio non controllato?",options:[{en:"Larger vehicles always have the right of way",it:"I veicoli piu grandi hanno sempre la precedenza"},{en:"The vehicle on the right has the right of way when vehicles arrive at approximately the same time",it:"Il veicolo a destra ha la precedenza quando i veicoli arrivano approssimativamente allo stesso tempo"},{en:"The vehicle going straight always has priority",it:"Il veicolo che va dritto ha sempre la priorita"},{en:"First to arrive always has the right of way",it:"Il primo ad arrivare ha sempre la precedenza"}],correct:1,explain_en:"At an uncontrolled intersection (no signs/signals), yield to the vehicle on your right when arriving simultaneously.",explain_it:"A un incrocio non controllato (nessun segnale), cedere al veicolo alla tua destra quando si arriva simultaneamente."},
  {cat:"laws",en:"What is the Florida law on yielding to a blind pedestrian with a white cane?",it:"Qual e la legge Florida sul cedere a un pedone cieco con un bastone bianco?",options:[{en:"Yield only at marked crosswalks",it:"Cedere solo agli attraversamenti pedonali segnati"},{en:"Always yield to a person carrying a white cane or guide dog regardless of location",it:"Cedere sempre a una persona con un bastone bianco o cane guida indipendentemente dalla posizione"},{en:"Only if the pedestrian is in a crosswalk",it:"Solo se il pedone e in un attraversamento pedonale"},{en:"Only applies to school zones",it:"Si applica solo alle zone scolastiche"}],correct:1,explain_en:"Florida law requires all drivers to yield to pedestrians using a white cane or guide dog -- indicating blindness or severe visual impairment. This applies at all locations.",explain_it:"La legge Florida richiede a tutti i conducenti di cedere ai pedoni che usano un bastone bianco o un cane guida -- che indica cecita o grave disabilita visiva."},
  {cat:"laws",en:"What is the law in Florida about driving on a suspended license?",it:"Qual e la legge Florida sulla guida con la patente sospesa?",options:[{en:"Only a civil infraction",it:"Solo un'infrazione civile"},{en:"A criminal traffic offense -- first offense is a misdemeanor, repeat offenses escalate to felonies",it:"Un'infrazione del traffico penale -- la prima infrazione e un reato minore, le infrazioni ripetute aumentano fino ai reati gravi"},{en:"Same fine as expired license",it:"Stessa multa della patente scaduta"},{en:"Legal if driving to work",it:"Legale se si guida per andare al lavoro"}],correct:1,explain_en:"Driving with a suspended/revoked license in Florida: first offense = second-degree misdemeanor (up to 60 days jail/$500 fine). Third+ offense = third-degree felony.",explain_it:"Guidare con la patente sospesa/revocata in Florida: prima infrazione = reato minore di secondo grado (fino a 60 giorni di carcere/$500 di multa). Terza+ infrazione = reato grave di terzo grado."},
  {cat:"laws",en:"What is the Florida law about yielding when entering a road from a driveway?",it:"Qual e la legge Florida sul cedere quando si entra su una strada da un vialetto?",options:[{en:"Traffic on the road must yield to exiting vehicles",it:"Il traffico sulla strada deve cedere ai veicoli in uscita"},{en:"Vehicles leaving a driveway must yield to all traffic on the road -- road traffic has priority",it:"I veicoli che lasciano un vialetto devono cedere a tutto il traffico sulla strada -- il traffico stradale ha la priorita"},{en:"Right of way is shared equally",it:"La precedenza e condivisa equamente"},{en:"Yield only if there are no traffic signs",it:"Cedere solo se non ci sono segnali stradali"}],correct:1,explain_en:"When leaving a driveway, alley, or private road, you must yield to all traffic on the public road including pedestrians and cyclists.",explain_it:"Quando si lascia un vialetto, un vicolo o una strada privata, si deve cedere a tutto il traffico sulla strada pubblica inclusi pedoni e ciclisti."},
  {cat:"laws",en:"In Florida, can you legally drive in a bike lane?",it:"In Florida, puoi legalmente guidare in una corsia ciclabile?",options:[{en:"Yes at any time",it:"Si in qualsiasi momento"},{en:"Only when making a right turn within 200 feet of the turn -- briefly entering to yield",it:"Solo quando si fa una svolta destra entro 200 piedi dalla svolta -- entrando brevemente per cedere"},{en:"Whenever no cyclists are present",it:"Ogni volta che non ci sono ciclisti"},{en:"Never -- bike lanes are always prohibited to motor vehicles",it:"Mai -- le corsie ciclabili sono sempre vietate ai veicoli a motore"}],correct:1,explain_en:"Motor vehicles may briefly enter a bike lane only to complete a right turn or when turning into a driveway -- and only within 200 feet of the turn. Otherwise bike lanes are off-limits.",explain_it:"I veicoli a motore possono entrare brevemente in una corsia ciclabile solo per completare una svolta destra o quando si svolta in un vialetto -- e solo entro 200 piedi dalla svolta."},
  {cat:"laws",en:"What is the Florida law on turning left from a two-way road onto a one-way road?",it:"Qual e la legge Florida sulla svolta sinistra da una strada a due sensi a una strada a senso unico?",options:[{en:"Turn into the nearest lane going in the correct direction",it:"Svoltare nella corsia piu vicina che va nella direzione corretta"},{en:"Turn into the leftmost lane of the one-way road",it:"Svoltare nella corsia piu a sinistra della strada a senso unico"},{en:"Turn into any open lane",it:"Svoltare in qualsiasi corsia aperta"},{en:"Left turns onto one-way roads are prohibited",it:"Le svolte sinistra sulle strade a senso unico sono vietate"}],correct:1,explain_en:"When turning left onto a one-way road, turn into the leftmost lane. This prevents conflicts with vehicles already in the right lanes.",explain_it:"Quando si svolta a sinistra su una strada a senso unico, svoltare nella corsia piu a sinistra. Questo previene conflitti con i veicoli gia nelle corsie destre."},
  {cat:"laws",en:"What is the Florida law on the use of vehicle horns near hospitals?",it:"Qual e la legge Florida sull'uso del clacson del veicolo vicino agli ospedali?",options:[{en:"No restriction on horn use near hospitals",it:"Nessuna restrizione sull'uso del clacson vicino agli ospedali"},{en:"Horn use is prohibited within 200 feet of a hospital, unless for safety",it:"L'uso del clacson e vietato entro 200 piedi da un ospedale, tranne che per motivi di sicurezza"},{en:"Only emergency vehicles may use horns near hospitals",it:"Solo i veicoli di emergenza possono usare il clacson vicino agli ospedali"},{en:"Restricted to daylight hours only",it:"Limitato solo alle ore diurne"}],correct:1,explain_en:"Florida prohibits unnecessary horn use near hospitals, courts, and churches. Horn use is restricted to safety purposes within 200 feet of such facilities.",explain_it:"La Florida vieta l'uso non necessario del clacson vicino a ospedali, tribunali e chiese. L'uso del clacson e limitato a scopi di sicurezza entro 200 piedi da tali strutture."},
  {cat:"laws",en:"What is the Florida law on abandoning a vehicle on a highway?",it:"Qual e la legge Florida sull'abbandono di un veicolo su un'autostrada?",options:[{en:"Legal if the vehicle is disabled",it:"Legale se il veicolo e fuori uso"},{en:"Illegal -- abandoned vehicles on highways can be cited and towed at the owner's expense",it:"Illegale -- i veicoli abbandonati sulle autostrade possono essere sanzionati e rimossi a spese del proprietario"},{en:"Legal for up to 24 hours",it:"Legale fino a 24 ore"},{en:"Only illegal if blocking a lane",it:"Illegale solo se blocca una corsia"}],correct:1,explain_en:"Abandoning a vehicle on a highway is illegal. Even disabled vehicles must be moved off the roadway ASAP -- or at minimum, off the travel lanes with hazard lights on.",explain_it:"Abbandonare un veicolo su un'autostrada e illegale. Anche i veicoli fuori uso devono essere spostati dalla carreggiata il prima possibile."},
  {cat:"laws",en:"What is the Florida law on parking in a safety zone?",it:"Qual e la legge Florida sul parcheggio in una zona di sicurezza?",options:[{en:"Legal for 15 minutes",it:"Legale per 15 minuti"},{en:"Prohibited -- safety zones are set aside for pedestrians or specific uses and must remain clear",it:"Vietato -- le zone di sicurezza sono riservate ai pedoni o usi specifici e devono rimanere libere"},{en:"Only illegal during school hours",it:"Illegale solo durante le ore scolastiche"},{en:"Legal if a police officer supervises",it:"Legale se un agente di polizia supervisiona"}],correct:1,explain_en:"Florida prohibits parking in safety zones -- areas set aside for pedestrian safety or transit operations. These include bus stops, pedestrian islands, and school zones.",explain_it:"La Florida vieta il parcheggio nelle zone di sicurezza -- aree riservate alla sicurezza pedonale o alle operazioni di transito."},
  {cat:"laws",en:"What happens in Florida if you fail to report a crash that causes more than $500 in damages?",it:"Cosa succede in Florida se non si segnala un incidente che causa danni superiori a $500?",options:[{en:"No penalty -- reporting is optional",it:"Nessuna sanzione -- la segnalazione e opzionale"},{en:"Failure to report is a traffic violation -- license may be suspended",it:"La mancata segnalazione e una violazione del traffico -- la patente puo essere sospesa"},{en:"Only a $50 fine",it:"Solo una multa di $50"},{en:"A criminal felony charge",it:"Un'accusa penale grave"}],correct:1,explain_en:"Florida requires reporting any crash involving injury, death, or over $500 in property damage within 10 days using the Long Form. Failure may result in suspension.",explain_it:"La Florida richiede la segnalazione di qualsiasi incidente che coinvolge lesioni, morte o piu di $500 di danni entro 10 giorni usando il Long Form."},
  {cat:"laws",en:"In Florida, what is the maximum speed limit on unpaved roads unless otherwise posted?",it:"In Florida, qual e il limite massimo di velocita sulle strade non asfaltate se non diversamente segnalato?",options:[{en:"15 mph",it:"15 mph"},{en:"25 mph",it:"25 mph"},{en:"35 mph",it:"35 mph"},{en:"45 mph",it:"45 mph"}],correct:1,explain_en:"Florida's default speed limit on unpaved roads is 25 mph unless otherwise posted. These surfaces require slower speeds for safety.",explain_it:"Il limite di velocita predefinito della Florida sulle strade non asfaltate e 25 mph se non diversamente segnalato."},
  {cat:"laws",en:"What is the Florida law about pedestrians walking along roads without sidewalks?",it:"Qual e la legge Florida sui pedoni che camminano lungo le strade senza marciapiedi?",options:[{en:"Pedestrians must walk on the right side",it:"I pedoni devono camminare sul lato destro"},{en:"Pedestrians should walk on the left side facing traffic -- so they can see and react to oncoming vehicles",it:"I pedoni dovrebbero camminare sul lato sinistro di fronte al traffico -- in modo da poter vedere e reagire ai veicoli in arrivo"},{en:"Pedestrians are prohibited from walking on roads without sidewalks",it:"I pedoni sono vietati sulle strade senza marciapiedi"},{en:"Pedestrians may walk on either side",it:"I pedoni possono camminare su entrambi i lati"}],correct:1,explain_en:"Florida law: pedestrians on roads without sidewalks should walk on the left side, facing oncoming traffic -- this way they can see and avoid approaching vehicles.",explain_it:"Legge Florida: i pedoni sulle strade senza marciapiedi dovrebbero camminare sul lato sinistro, di fronte al traffico in arrivo -- in questo modo possono vedere e evitare i veicoli in avvicinamento."},
  {cat:"laws",en:"What is Florida's law on the right of way when a vehicle is already in a traffic circle (roundabout)?",it:"Qual e la legge Florida sulla precedenza quando un veicolo e gia in una rotonda?",options:[{en:"Vehicles entering have the right of way",it:"I veicoli che entrano hanno la precedenza"},{en:"Vehicles already in the circle have the right of way -- entering vehicles must yield",it:"I veicoli gia nel cerchio hanno la precedenza -- i veicoli che entrano devono cedere"},{en:"Right of way depends on which lane you are in",it:"La precedenza dipende dalla corsia in cui si e"},{en:"Traffic signals inside the circle control right of way",it:"I segnali stradali all'interno del cerchio controllano la precedenza"}],correct:1,explain_en:"In a roundabout, vehicles already circulating inside have the right of way. Entering vehicles must yield and wait for a safe gap before entering.",explain_it:"In una rotonda, i veicoli gia in circolazione all'interno hanno la precedenza. I veicoli che entrano devono cedere e aspettare un'apertura sicura prima di entrare."},
  {cat:"laws",en:"What is the Florida law about the use of hazard lights on a disabled vehicle?",it:"Qual e la legge Florida sull'uso delle luci di pericolo su un veicolo fuori uso?",options:[{en:"Hazard lights are optional on disabled vehicles",it:"Le luci di pericolo sono opzionali sui veicoli fuori uso"},{en:"Hazard lights should be activated on a disabled vehicle to warn other drivers",it:"Le luci di pericolo dovrebbero essere attivate su un veicolo fuori uso per avvisare gli altri conducenti"},{en:"Hazard lights are only for moving vehicles",it:"Le luci di pericolo sono solo per i veicoli in movimento"},{en:"Hazard lights may only be used on highways",it:"Le luci di pericolo possono essere usate solo sulle autostrade"}],correct:1,explain_en:"Activate hazard lights immediately if your vehicle becomes disabled on the road. Also place flares or reflective triangles behind the vehicle if available.",explain_it:"Attivare immediatamente le luci di pericolo se il veicolo si ferma sulla strada. Posizionare anche bengala o triangoli riflettenti dietro il veicolo se disponibili."},
  {cat:"laws",en:"What is the Florida law about using a radar detector?",it:"Qual e la legge Florida sull'uso di un rilevatore radar?",options:[{en:"Illegal for all vehicles",it:"Illegale per tutti i veicoli"},{en:"Legal for non-commercial vehicles -- illegal for commercial vehicles over 18,000 lbs",it:"Legale per i veicoli non commerciali -- illegale per i veicoli commerciali oltre 18.000 libbre"},{en:"Legal for all vehicles",it:"Legale per tutti i veicoli"},{en:"Illegal only on highways",it:"Illegale solo sulle autostrade"}],correct:1,explain_en:"Radar detectors are legal for private passenger vehicles in Florida but are prohibited in commercial vehicles over 18,000 lbs (federal regulation).",explain_it:"I rilevatori radar sono legali per i veicoli privati in Florida ma sono vietati nei veicoli commerciali oltre 18.000 libbre (regolamento federale)."},
  {cat:"laws",en:"What must you do when an emergency vehicle is blocking a lane on a limited-access highway?",it:"Cosa devi fare quando un veicolo di emergenza blocca una corsia su un'autostrada ad accesso limitato?",options:[{en:"Stop behind it and wait",it:"Fermarsi dietro e aspettare"},{en:"Move over a lane away from the emergency vehicle -- if not possible, reduce speed to 20 mph below the posted limit",it:"Spostarsi di una corsia lontano dal veicolo di emergenza -- se non possibile, ridurre la velocita a 20 mph sotto il limite segnalato"},{en:"Pass it at normal speed since it is blocking the lane",it:"Superarlo alla velocita normale poiche blocca la corsia"},{en:"Use the shoulder to pass",it:"Usare la banchina per passare"}],correct:1,explain_en:"Florida Move Over Law applies: move over one lane OR slow to 20 mph below the posted limit (min 5 mph if limit is 20). Applies to police, fire, ambulance, utility, sanitation, and tow trucks.",explain_it:"Si applica la legge Move Over della Florida: spostarsi di una corsia O rallentare a 20 mph sotto il limite segnalato. Si applica a polizia, pompieri, ambulanza, servizi, nettezza urbana e carri attrezzi."},
  {cat:"laws",en:"What is the Florida law about parking within 30 feet of a flashing beacon or traffic control signal?",it:"Qual e la legge Florida sul parcheggio entro 30 piedi da un segnale lampeggiante o semaforo?",options:[{en:"Legal at any time",it:"Legale in qualsiasi momento"},{en:"Prohibited -- parking within 30 feet of traffic signals or beacons obstructs visibility",it:"Vietato -- il parcheggio entro 30 piedi dai segnali stradali o segnali lampeggianti ostruisce la visibilita"},{en:"Legal overnight only",it:"Legale solo di notte"},{en:"Legal for 15 minutes with hazard lights",it:"Legale per 15 minuti con le luci di pericolo"}],correct:1,explain_en:"Florida prohibits parking within 30 feet of a traffic signal or flashing beacon -- ensuring drivers can see the signal clearly from a distance.",explain_it:"La Florida vieta il parcheggio entro 30 piedi da un semaforo o segnale lampeggiante -- assicurando che i conducenti possano vedere chiaramente il segnale da lontano."},
  {cat:"laws",en:"What must Florida drivers do when a flagger in a construction zone signals them to stop?",it:"Cosa devono fare i conducenti Florida quando un segnalatore in una zona di costruzione li segnala di fermarsi?",options:[{en:"Stop only if no cars are behind them",it:"Fermarsi solo se non ci sono auto dietro"},{en:"Stop immediately and obey all flagger directions -- flaggers have the same authority as traffic signals",it:"Fermarsi immediatamente e obbedire a tutte le istruzioni del segnalatore -- i segnalatori hanno la stessa autorita dei segnali stradali"},{en:"Slow to 15 mph and proceed",it:"Rallentare a 15 mph e procedere"},{en:"Flaggers only apply to trucks",it:"I segnalatori si applicano solo ai camion"}],correct:1,explain_en:"Construction zone flaggers have the same legal authority as traffic control signals in Florida. Failure to obey a flagger is a moving violation with doubled fines.",explain_it:"I segnalatori delle zone di costruzione hanno la stessa autorita legale dei segnali stradali in Florida. Il mancato rispetto di un segnalatore e una violazione in movimento con multe raddoppiate."},
  {cat:"laws",en:"What is the Florida law on tinted windows?",it:"Qual e la legge Florida sui finestrini oscurati?",options:[{en:"Any tint level is legal",it:"Qualsiasi livello di oscuramento e legale"},{en:"Front side windows must allow at least 28% light; rear windows 15%; windshield tint limited to top 6 inches",it:"I finestrini laterali anteriori devono consentire almeno il 28% di luce; finestrini posteriori 15%; oscuramento del parabrezza limitato ai 6 pollici superiori"},{en:"All windows may be fully blacked out",it:"Tutti i finestrini possono essere completamente oscurati"},{en:"Tinting is only regulated for commercial vehicles",it:"L'oscuramento e regolamentato solo per i veicoli commerciali"}],correct:1,explain_en:"Florida window tint law: front side windows 28%+ VLT; rear side and back window 15%+ VLT; windshield strip max 6 inches from top. Non-reflective tint only for most windows.",explain_it:"Legge sull'oscuramento dei finestrini Florida: finestrini laterali anteriori 28%+ VLT; finestrini laterali posteriori e lunotto 15%+ VLT; striscia parabrezza max 6 pollici dall'alto."},
  {cat:"laws",en:"What is the Florida law on car insurance for a newly purchased vehicle?",it:"Qual e la legge Florida sull'assicurazione auto per un veicolo appena acquistato?",options:[{en:"You have 30 days before insurance is required",it:"Hai 30 giorni prima che l'assicurazione sia richiesta"},{en:"Insurance is required before the vehicle can be driven legally -- at the time of purchase",it:"L'assicurazione e richiesta prima che il veicolo possa essere guidato legalmente -- al momento dell'acquisto"},{en:"Insurance is only required when registering the vehicle",it:"L'assicurazione e richiesta solo quando si registra il veicolo"},{en:"The dealer provides temporary coverage for 7 days",it:"Il concessionario fornisce copertura temporanea per 7 giorni"}],correct:1,explain_en:"Florida requires minimum PIP and PDL insurance before operating any vehicle on public roads. Coverage must be in place at the time of purchase or first operation.",explain_it:"La Florida richiede un'assicurazione minima PIP e PDL prima di operare qualsiasi veicolo sulle strade pubbliche."},
  {cat:"laws",en:"What is the Florida law on distracted driving -- beyond just texting?",it:"Qual e la legge Florida sulla guida distratta -- oltre ai soli messaggi?",options:[{en:"Only texting is regulated",it:"Solo i messaggi sono regolamentati"},{en:"Any activity that impairs attention can result in careless or reckless driving charges if it causes an accident",it:"Qualsiasi attivita che compromette l'attenzione puo comportare accuse di guida imprudente o spericolata se causa un incidente"},{en:"Distracted driving is only illegal at night",it:"La guida distratta e illegale solo di notte"},{en:"Only applies to commercial drivers",it:"Si applica solo ai conducenti commerciali"}],correct:1,explain_en:"While Florida specifically targets texting, any distraction leading to careless driving (eating, grooming, adjusting radio) can result in careless or reckless driving charges if it causes an accident.",explain_it:"Mentre la Florida si rivolge specificamente ai messaggi, qualsiasi distrazione che porta a una guida imprudente puo comportare accuse di guida imprudente se causa un incidente."},
  {cat:"laws",en:"What is the Florida law about hitchhiking?",it:"Qual e la legge Florida sull'autostop?",options:[{en:"Legal everywhere",it:"Legale ovunque"},{en:"Soliciting rides on highways or limited access roads is prohibited",it:"Sollecitare passaggi sulle autostrade o strade ad accesso limitato e vietato"},{en:"Only illegal for minors",it:"Illegale solo per i minori"},{en:"Legal on all Florida roads",it:"Legale su tutte le strade Florida"}],correct:1,explain_en:"Hitchhiking on highways and limited access roads is illegal in Florida. It creates hazardous conditions for both the hitchhiker and drivers.",explain_it:"L'autostop sulle autostrade e sulle strade ad accesso limitato e illegale in Florida. Crea condizioni pericolose sia per chi fa l'autostop che per i conducenti."},
  {cat:"laws",en:"What is Florida's 'Fleeing and Eluding' law?",it:"Cos'e la legge Florida sulla 'Fuga e Elusione'?",options:[{en:"A minor traffic infraction for not stopping quickly",it:"Una minore infrazione del traffico per non essersi fermati velocemente"},{en:"A criminal offense when a driver willfully fails to stop for police -- felony charges with prison time",it:"Un reato penale quando un conducente si rifiuta volontariamente di fermarsi per la polizia -- accuse di reato grave con pena detentiva"},{en:"Only applies to high-speed chases",it:"Si applica solo agli inseguimenti ad alta velocita"},{en:"A misdemeanor for a first offense",it:"Un reato minore per la prima infrazione"}],correct:1,explain_en:"Florida's Fleeing and Eluding: willfully failing to stop for law enforcement is a felony. Penalties escalate with speed, injury, and other factors -- can result in years in prison.",explain_it:"Fuga e Elusione Florida: rifiutarsi volontariamente di fermarsi per le forze dell'ordine e un reato grave. Le sanzioni aumentano con la velocita, le lesioni e altri fattori."},
  {cat:"safety",en:"What is the 'Ladder Frame' technique for changing lanes safely?",it:"Cos'e la tecnica 'Ladder Frame' per cambiare corsia in sicurezza?",options:[{en:"Use a ladder to check the roof of your vehicle",it:"Usare una scala per controllare il tetto del veicolo"},{en:"Mirror check, signal, shoulder check, steer, then cancel signal -- a structured sequence for safe lane changes",it:"Controllo specchio, segnale, controllo spalla, sterzata, poi cancella segnale -- una sequenza strutturata per cambi di corsia sicuri"},{en:"Always change lanes at a 45-degree angle",it:"Cambiare sempre corsia con un angolo di 45 gradi"},{en:"A method for navigating multi-lane roundabouts",it:"Un metodo per navigare le rotonde a piu corsie"}],correct:1,explain_en:"Safe lane change sequence: (1) Check mirrors, (2) Signal, (3) Shoulder check blind spot, (4) Steer smoothly into the new lane, (5) Cancel signal. Never skip steps.",explain_it:"Sequenza sicura di cambio corsia: (1) Controlla specchi, (2) Segnala, (3) Controlla il punto cieco della spalla, (4) Sterza fluidamente nella nuova corsia, (5) Cancella il segnale."},
  {cat:"safety",en:"What is the effect of sun glare on driving safety?",it:"Qual e l'effetto del riverbero solare sulla sicurezza di guida?",options:[{en:"Minimal effect on modern vehicles with UV glass",it:"Effetto minimo sui veicoli moderni con vetro UV"},{en:"Can temporarily blind a driver making it impossible to see traffic signals, pedestrians, or other vehicles",it:"Puo temporaneamente accecare un conducente rendendo impossibile vedere segnali stradali, pedoni o altri veicoli"},{en:"Only affects vision when driving west",it:"Influisce sulla visione solo quando si guida verso ovest"},{en:"Only relevant in desert climates",it:"Rilevante solo nei climi desertici"}],correct:1,explain_en:"Sun glare can cause temporary blindness -- especially at sunrise/sunset when driving directly into the sun. Use sun visors, quality sunglasses, and slow down when glare is severe.",explain_it:"Il riverbero solare puo causare cecita temporanea -- specialmente all'alba/tramonto. Usare parasole, occhiali da sole di qualita e rallentare quando il riverbero e intenso."},
  {cat:"safety",en:"What is the correct action when your vehicle starts to skid on ice?",it:"Qual e l'azione corretta quando il tuo veicolo inizia a slittare sul ghiaccio?",options:[{en:"Brake hard and steer straight",it:"Frenare forte e sterzare dritto"},{en:"Ease off the gas, steer in the direction you want to go, avoid sudden inputs",it:"Togliere il gas, sterzare nella direzione in cui vuoi andare, evitare input improvvisi"},{en:"Accelerate to regain traction",it:"Accelerare per ripristinare la trazione"},{en:"Apply the parking brake firmly",it:"Applicare fermamente il freno a mano"}],correct:1,explain_en:"Ice skid: ease off gas, avoid hard braking, steer gently in the direction you want to go. Sudden inputs make skidding worse.",explain_it:"Scivolamento sul ghiaccio: togliere il gas, evitare frenate brusche, sterzare delicatamente nella direzione in cui vuoi andare. Gli input improvvisi peggiorano lo scivolamento."},
  {cat:"safety",en:"Why is it important to keep your gas tank at least one-quarter full?",it:"Perche e importante tenere il serbatoio almeno a un quarto?",options:[{en:"Full tanks improve fuel efficiency",it:"I serbatoi pieni migliorano l'efficienza del carburante"},{en:"Prevents fuel pump damage, avoids running out in emergencies, and in cold weather prevents fuel line freeze",it:"Previene danni alla pompa del carburante, evita di restare senza carburante nelle emergenze, e nel freddo previene il congelamento della linea del carburante"},{en:"Insurance requires it",it:"L'assicurazione lo richiede"},{en:"Only matters for diesel vehicles",it:"Conta solo per i veicoli diesel"}],correct:1,explain_en:"Keeping at least 1/4 tank: protects the fuel pump (submerged pumps need fuel to stay cool), prevents running dry in emergencies, and prevents fuel line issues in cold weather.",explain_it:"Tenere almeno 1/4 di serbatoio: protegge la pompa del carburante, evita di restare senza carburante nelle emergenze e previene problemi alla linea del carburante nel freddo."},
  {cat:"safety",en:"What is the correct action when you encounter a wrong-way driver on the highway?",it:"Qual e l'azione corretta quando incontri un conducente in senso contrario in autostrada?",options:[{en:"Flash your lights and maintain speed",it:"Lampeggiare con i fari e mantenere la velocita"},{en:"Move to the right, brake gently, flash lights, honk, and call 911 after stopping safely",it:"Spostarsi a destra, frenare delicatamente, lampeggiare con i fari, suonare il clacson, e chiamare il 911 dopo essersi fermati in sicurezza"},{en:"Speed up to pass the wrong-way driver quickly",it:"Accelerare per superare velocemente il conducente in senso contrario"},{en:"Swerve to the left median",it:"Sterzare verso il mediano sinistro"}],correct:1,explain_en:"Wrong-way driver: steer right (toward the shoulder), brake smoothly, flash lights and honk to warn, then call 911. Never swerve left toward the median -- the wrong-way driver may also steer there.",explain_it:"Conducente in senso contrario: sterzare a destra (verso la banchina), frenare gradualmente, lampeggiare e suonare per avvisare, poi chiamare il 911."},
  {cat:"safety",en:"What is 'velocity prediction error' when following another vehicle?",it:"Cos'e l'errore di previsione della velocita quando si segue un altro veicolo?",options:[{en:"Misjudging your own speed",it:"Valutare male la propria velocita"},{en:"Assuming the vehicle ahead will continue at its current speed when it may brake suddenly",it:"Assumere che il veicolo davanti continuera alla sua velocita attuale quando potrebbe frenare improvvisamente"},{en:"GPS error in speed reporting",it:"Errore GPS nella segnalazione della velocita"},{en:"Overestimating how fast other cars are going",it:"Sopravvalutare la velocita degli altri veicoli"}],correct:1,explain_en:"Never assume the vehicle ahead will maintain speed. Maintain sufficient following distance to react if they brake suddenly -- a key principle of defensive driving.",explain_it:"Non presumere mai che il veicolo davanti mantenga la velocita. Mantenere una distanza sufficiente per reagire se frenano improvvisamente."},
  {cat:"safety",en:"What is the recommended action when you miss your highway exit?",it:"Qual e l'azione raccomandata quando perdi la tua uscita autostradale?",options:[{en:"Immediately brake and reverse on the highway",it:"Frenare immediatamente e fare retromarcia in autostrada"},{en:"Continue to the next exit and turn around -- never reverse on a highway",it:"Continuare fino alla prossima uscita e girare indietro -- non fare mai retromarcia in autostrada"},{en:"Cross the median to return",it:"Attraversare il mediano per tornare"},{en:"Stop on the shoulder and wait for a gap",it:"Fermarsi sulla banchina e aspettare un'apertura"}],correct:1,explain_en:"If you miss your exit: continue to the next exit. Never reverse, stop in a lane, or cross a median. The inconvenience of the next exit is far better than the risk of a highway crash.",explain_it:"Se perdi la tua uscita: continua fino alla prossima uscita. Non fare mai retromarcia, fermarti in una corsia o attraversare un mediano."},
  {cat:"safety",en:"What is the danger of driving with the seat too far from the pedals?",it:"Qual e il pericolo di guidare con il sedile troppo lontano dai pedali?",options:[{en:"No safety issue -- it is more comfortable",it:"Nessun problema di sicurezza -- e piu comodo"},{en:"Reduced pedal control and delayed brake application -- longer stopping distance",it:"Controllo del pedale ridotto e applicazione ritardata del freno -- distanza di frenata maggiore"},{en:"Only affects steering wheel reach",it:"Influisce solo sulla portata del volante"},{en:"Causes back pain only",it:"Causa solo mal di schiena"}],correct:1,explain_en:"Seat too far from pedals: you cannot apply full braking force quickly, reducing emergency braking ability. Adjust seat so you can fully depress the brake pedal with slight knee bend.",explain_it:"Sedile troppo lontano dai pedali: non puoi applicare la piena forza frenante rapidamente, riducendo la capacita di frenata di emergenza."},
  {cat:"safety",en:"What does the term 'space cushion' mean in defensive driving?",it:"Cosa significa il termine 'space cushion' nella guida difensiva?",options:[{en:"Padding in the seat for comfort",it:"Imbottitura nel sedile per il comfort"},{en:"A buffer of open space around your vehicle maintained to allow reaction time and escape routes",it:"Un buffer di spazio aperto intorno al veicolo mantenuto per consentire il tempo di reazione e le vie di fuga"},{en:"The distance from the curb when parking",it:"La distanza dal cordolo quando si parcheggia"},{en:"The gap between lanes at a stop light",it:"Il gap tra le corsie a un semaforo"}],correct:1,explain_en:"A space cushion is maintained around your vehicle in all directions. It provides time to react, room to maneuver, and escape routes if the unexpected occurs.",explain_it:"Un space cushion e mantenuto intorno al veicolo in tutte le direzioni. Fornisce tempo per reagire, spazio per manovrare e vie di fuga se accade l'imprevisto."},
  {cat:"safety",en:"What should you do when you are following a vehicle that is braking repeatedly for no apparent reason?",it:"Cosa dovresti fare quando stai seguendo un veicolo che frena ripetutamente senza motivo apparente?",options:[{en:"Flash your lights to signal them",it:"Lampeggiare con i fari per segnalare loro"},{en:"Increase your following distance and consider changing lanes to pass when safe",it:"Aumentare la distanza e considerare di cambiare corsia per sorpassare quando sicuro"},{en:"Brake to match their pattern exactly",it:"Frenare per abbinare esattamente il loro schema"},{en:"Honk to alert the driver",it:"Suonare il clacson per avvisare il conducente"}],correct:1,explain_en:"Repeatedly braking drivers may be distracted, impaired, or unsure of their route. Increase following distance to avoid rear-ending them, and pass when it is safe to do so.",explain_it:"I conducenti che frenano ripetutamente possono essere distratti, compromessi o incerti del percorso. Aumentare la distanza per evitare di tamponarli e sorpassare quando e sicuro."},
  {cat:"safety",en:"What is the effect of dehydration on driving ability?",it:"Qual e l'effetto della disidratazione sulla capacita di guida?",options:[{en:"No effect on driving",it:"Nessun effetto sulla guida"},{en:"Reduces concentration and reaction time, increases fatigue and irritability -- similar to mild impairment",it:"Riduce la concentrazione e il tempo di reazione, aumenta la fatica e l'irritabilita -- simile a una lieve compromissione"},{en:"Only affects vision",it:"Influisce solo sulla visione"},{en:"Dehydration improves alertness",it:"La disidratazione migliora la vigilanza"}],correct:1,explain_en:"Studies show that mild dehydration causes driving errors comparable to a 0.08% BAC. Stay hydrated on long drives -- stop every 2 hours.",explain_it:"Gli studi mostrano che la disidratazione lieve causa errori di guida comparabili a un BAC di 0,08%. Rimanere idratati nei lunghi viaggi -- fermarsi ogni 2 ore."},
  {cat:"safety",en:"What is the safest way to park on a downhill slope without a curb?",it:"Qual e il modo piu sicuro di parcheggiare su una pendenza in discesa senza cordolo?",options:[{en:"Set parking brake only",it:"Impostare solo il freno a mano"},{en:"Turn front wheels to the right (toward shoulder), set parking brake, leave in Park/first gear",it:"Girare le ruote anteriori a destra (verso la banchina), impostare il freno a mano, lasciare in Park/prima marcia"},{en:"Turn front wheels to the left (toward road center)",it:"Girare le ruote anteriori a sinistra (verso il centro della strada)"},{en:"Park perpendicular to the slope",it:"Parcheggiare perpendicolare alla pendenza"}],correct:1,explain_en:"Downhill without curb: turn wheels RIGHT toward the shoulder. If the car rolls, it moves off the road rather than into traffic. Always set parking brake and leave in Park.",explain_it:"Discesa senza cordolo: girare le ruote A DESTRA verso la banchina. Se l'auto rotola, si sposta fuori dalla strada anziche nel traffico. Impostare sempre il freno a mano e lasciare in Park."},
  {cat:"safety",en:"What is the safest way to park on an uphill slope?",it:"Qual e il modo piu sicuro di parcheggiare su una pendenza in salita?",options:[{en:"Turn wheels to the right always",it:"Girare le ruote a destra sempre"},{en:"Turn front wheels away from the curb (left), so if the car rolls it will be stopped by the curb",it:"Girare le ruote anteriori lontano dal cordolo (a sinistra), in modo che se l'auto rotola venga fermata dal cordolo"},{en:"Leave wheels straight to prevent tire wear",it:"Lasciare le ruote dritte per prevenire l'usura degli pneumatici"},{en:"No wheel position needed if parking brake is set",it:"Nessuna posizione delle ruote necessaria se il freno a mano e impostato"}],correct:1,explain_en:"Uphill with curb: turn wheels LEFT (away from curb). The car would roll back into the curb -- stopping it. Uphill without curb: turn RIGHT (toward shoulder). Always set parking brake.",explain_it:"Salita con cordolo: girare le ruote A SINISTRA (lontano dal cordolo). L'auto rotolerebbe indietro nel cordolo -- fermandola. Salita senza cordolo: girare A DESTRA (verso la banchina)."},
  {cat:"safety",en:"What is the correct following distance in heavy rain?",it:"Qual e la distanza corretta di seguimento con la pioggia intensa?",options:[{en:"Same 2-second rule",it:"La stessa regola dei 2 secondi"},{en:"At least 4-6 seconds -- wet roads significantly increase stopping distance",it:"Almeno 4-6 secondi -- le strade bagnate aumentano significativamente la distanza di frenata"},{en:"1-second distance -- rain reduces speed differences",it:"Distanza di 1 secondo -- la pioggia riduce le differenze di velocita"},{en:"Stay close to see through the rain better",it:"Avvicinarsi per vedere meglio attraverso la pioggia"}],correct:1,explain_en:"In heavy rain: increase following distance to at least 4-6 seconds. Wet roads can double stopping distance. Visibility is also reduced.",explain_it:"Con pioggia intensa: aumentare la distanza di seguimento ad almeno 4-6 secondi. Le strade bagnate possono raddoppiare la distanza di frenata."},
  {cat:"safety",en:"What is the correct procedure when a traffic signal is not working and police are directing traffic?",it:"Qual e la procedura corretta quando un semaforo non funziona e la polizia dirige il traffico?",options:[{en:"Follow the traffic signals even if police give different instructions",it:"Seguire i segnali stradali anche se la polizia da istruzioni diverse"},{en:"Always obey police officer directions -- they override traffic signals and signs",it:"Obbedire sempre alle istruzioni degli agenti di polizia -- prevalgono sui segnali stradali e i segni"},{en:"Use your own judgment when instructions seem unclear",it:"Usare il proprio giudizio quando le istruzioni sembrano poco chiare"},{en:"Come to a complete stop and call 911 for clarification",it:"Fermarsi completamente e chiamare il 911 per chiarimenti"}],correct:1,explain_en:"A law enforcement officer directing traffic has authority that overrides all traffic signals, signs, and lane markings. Always obey police officer directions immediately.",explain_it:"Un agente delle forze dell'ordine che dirige il traffico ha autorita che prevale su tutti i segnali stradali, segni e marcature di corsia."},
  {cat:"safety",en:"What is 'lane departure' and how can it be avoided?",it:"Cos'e il 'lane departure' e come puo essere evitato?",options:[{en:"Intentionally changing lanes",it:"Cambiare corsia intenzionalmente"},{en:"Unintentionally drifting out of your lane -- prevented by staying alert, checking mirrors regularly, and avoiding distractions",it:"Uscire involontariamente dalla corsia -- prevenuto rimanendo vigile, controllando regolarmente gli specchi e evitando le distrazioni"},{en:"Driving too slowly in a lane",it:"Guidare troppo lentamente in una corsia"},{en:"Using the center lane on a highway",it:"Usare la corsia centrale in autostrada"}],correct:1,explain_en:"Lane departure is unintentional drifting -- caused by fatigue, distraction, or medical events. Prevention: stay alert, take breaks, avoid all distractions, use lane departure warning systems if available.",explain_it:"Il lane departure e la deriva involontaria -- causata da fatica, distrazione o eventi medici. Prevenzione: rimani vigile, fai pause, evita tutte le distrazioni."},
  {cat:"safety",en:"What is the recommended speed reduction when driving in heavy fog?",it:"Qual e la riduzione di velocita raccomandata quando si guida in nebbia fitta?",options:[{en:"Reduce by 10 mph",it:"Ridurre di 10 mph"},{en:"Reduce speed as much as needed to see and stop within your visible distance",it:"Ridurre la velocita quanto necessario per vedere e fermarsi entro la distanza visibile"},{en:"Reduce to exactly 25 mph",it:"Ridurre esattamente a 25 mph"},{en:"Speed has no effect in fog",it:"La velocita non ha effetti nella nebbia"}],correct:1,explain_en:"In fog: you must be able to stop within the distance you can see. This may mean driving very slowly -- sometimes only a few mph. The key rule: stop within your visible distance.",explain_it:"Nella nebbia: devi essere in grado di fermarti entro la distanza che puoi vedere. Questo potrebbe significare guidare molto lentamente. La regola chiave: fermarsi entro la distanza visibile."},
  {cat:"safety",en:"What is a 'passive restraint system' in a vehicle?",it:"Cos'e un 'sistema di ritenuta passivo' in un veicolo?",options:[{en:"The seat belt that you manually buckle",it:"La cintura di sicurezza che si allaccia manualmente"},{en:"An airbag system that deploys automatically without driver action in a crash",it:"Un sistema di airbag che si attiva automaticamente senza azione del conducente in un incidente"},{en:"Child safety locks on rear doors",it:"Blocchi di sicurezza per bambini sulle porte posteriori"},{en:"Automatic windshield wipers",it:"Tergicristalli automatici"}],correct:1,explain_en:"Passive restraints deploy automatically -- airbags are passive restraints. Seat belts are active (require buckling). Both work together for maximum protection.",explain_it:"I sistemi di ritenuta passivi si attivano automaticamente -- gli airbag sono sistemi di ritenuta passivi. Le cinture sono attive (richiedono di essere allacciate). Entrambi lavorano insieme."},
  {cat:"safety",en:"Why should you never use your phone for GPS navigation by holding it while driving?",it:"Perche non dovresti mai usare il telefono per la navigazione GPS tenendolo mentre guidi?",options:[{en:"GPS apps use too much battery",it:"Le app GPS consumano troppa batteria"},{en:"Holding a phone while driving is a manual, visual, and cognitive distraction simultaneously -- the most dangerous combination",it:"Tenere un telefono mentre si guida e una distrazione manuale, visiva e cognitiva simultaneamente -- la combinazione piu pericolosa"},{en:"Phone GPS is less accurate than in-car systems",it:"Il GPS del telefono e meno preciso dei sistemi in auto"},{en:"Data charges apply when navigating",it:"Si applicano costi dati durante la navigazione"}],correct:1,explain_en:"Using a handheld phone for navigation involves all three distraction types: manual (holding), visual (looking at screen), cognitive (processing directions). Use a mount and hands-free system.",explain_it:"Usare un telefono portatile per la navigazione comporta tutti e tre i tipi di distrazione: manuale (tenere), visiva (guardare lo schermo), cognitiva (elaborare le istruzioni)."},
  {cat:"safety",en:"What is the correct eye-scanning technique for safe highway driving?",it:"Qual e la tecnica corretta di scansione oculare per la guida autostradale sicura?",options:[{en:"Focus on the vehicle directly ahead",it:"Concentrarsi sul veicolo direttamente davanti"},{en:"Alternate between looking far ahead, middle distance, nearby traffic, and mirrors every few seconds",it:"Alternare tra guardare lontano in avanti, distanza media, traffico vicino e specchi ogni pochi secondi"},{en:"Look only at the road surface immediately ahead",it:"Guardare solo la superficie stradale immediatamente davanti"},{en:"Check mirrors only when changing lanes",it:"Controllare gli specchi solo quando si cambia corsia"}],correct:1,explain_en:"Good eye scanning: look 10-15 seconds ahead (far), 4-6 seconds (medium), check mirrors every 5-8 seconds, and glance at nearby traffic. This gives maximum awareness.",explain_it:"Buona scansione oculare: guardare 10-15 secondi avanti (lontano), 4-6 secondi (medio), controllare gli specchi ogni 5-8 secondi, e dare un'occhiata al traffico vicino."},
  {cat:"alcohol",en:"What are the typical behavioral signs of a drunk driver?",it:"Quali sono i segni comportamentali tipici di un conducente ubriaco?",options:[{en:"Driving very fast only",it:"Guidare molto veloce solo"},{en:"Weaving, sudden braking, wide turns, straddling center line, driving too slowly",it:"Serpentinamento, frenate improvvise, svolte larghe, cavalcare la linea centrale, guidare troppo lentamente"},{en:"Only speeding on highways",it:"Solo eccesso di velocita in autostrada"},{en:"Driving with lights off only",it:"Guidare solo con le luci spente"}],correct:1,explain_en:"Drunk driver signs: weaving between lanes, unusually slow or erratic speeds, wide turns, straddling lines, sudden braking, driving with no lights. Maintain distance and call 911.",explain_it:"Segni del conducente ubriaco: serpentinamento tra le corsie, velocita insolitamente lenta o erratica, svolte larghe, cavalcare le linee, frenate improvvise, guidare senza luci."},
  {cat:"alcohol",en:"What is the Florida law on serving alcohol to a visibly intoxicated person who later causes an accident?",it:"Qual e la legge Florida sul servire alcol a una persona visibilmente intossicata che poi causa un incidente?",options:[{en:"The alcohol server has no liability",it:"Il somministratore di alcol non ha responsabilita"},{en:"Under Florida's Dram Shop law, vendors may be liable if they serve a visibly drunk person who then causes injury",it:"Ai sensi della legge Dram Shop della Florida, i venditori possono essere responsabili se servono una persona visibilmente ubriaca che poi causa lesioni"},{en:"Only the driver is responsible",it:"Solo il conducente e responsabile"},{en:"Liability applies only to bars, not restaurants",it:"La responsabilita si applica solo ai bar, non ai ristoranti"}],correct:1,explain_en:"Florida's Dram Shop Act creates liability for establishments that knowingly serve alcohol to minors or visibly intoxicated adults who then cause accidents resulting in injury or death.",explain_it:"La legge Dram Shop della Florida crea responsabilita per gli esercizi che servono consapevolmente alcol a minori o adulti visibilmente intossicati che poi causano incidenti."},
  {cat:"alcohol",en:"What is the Florida law on DUI and commercial driver's license (CDL)?",it:"Qual e la legge Florida sul DUI e la patente commerciale (CDL)?",options:[{en:"Same consequences as regular license",it:"Stesse conseguenze della patente normale"},{en:"First DUI conviction results in 1-year CDL disqualification -- lifetime disqualification for DUI in a hazmat vehicle",it:"La prima condanna DUI comporta 1 anno di squalifica CDL -- squalifica a vita per DUI in un veicolo hazmat"},{en:"CDL holders are exempt from DUI laws",it:"I titolari CDL sono esenti dalle leggi DUI"},{en:"Only matters if the DUI occurred while driving commercially",it:"Conta solo se il DUI e avvenuto mentre si guidava commercialmente"}],correct:1,explain_en:"CDL DUI: 1-year disqualification (first offense), regardless of whether in commercial or personal vehicle. Life disqualification for DUI while transporting hazmat.",explain_it:"DUI CDL: squalifica di 1 anno (prima infrazione), indipendentemente dal fatto che si guidasse un veicolo commerciale o personale. Squalifica a vita per DUI durante il trasporto di hazmat."},
  {cat:"alcohol",en:"What is the Florida law on DUI and professional licenses?",it:"Qual e la legge Florida sul DUI e le licenze professionali?",options:[{en:"DUI has no effect on professional licenses",it:"Il DUI non ha effetti sulle licenze professionali"},{en:"DUI convictions may trigger mandatory reporting to licensing boards -- can result in license suspension for professions like medicine, law, nursing",it:"Le condanne DUI possono attivare la segnalazione obbligatoria ai board di licenze -- puo comportare la sospensione della licenza per professioni come medicina, legge, infermieristica"},{en:"Only applies to transportation professions",it:"Si applica solo alle professioni di trasporto"},{en:"DUI affects professional licenses only if it involves drugs",it:"Il DUI influisce sulle licenze professionali solo se coinvolge droghe"}],correct:1,explain_en:"Many Florida professional licenses (medicine, law, nursing, real estate, education) require reporting criminal convictions including DUI. The board may suspend or revoke professional licenses.",explain_it:"Molte licenze professionali Florida richiedono la segnalazione delle condanne penali incluso il DUI. Il board puo sospendere o revocare le licenze professionali."},
  {cat:"alcohol",en:"What makes alcohol more dangerous when combined with driving at night?",it:"Cosa rende l'alcol piu pericoloso se combinato con la guida notturna?",options:[{en:"Alcohol and night driving have no interaction",it:"L'alcol e la guida notturna non hanno interazione"},{en:"Alcohol further reduces already-diminished night vision, depth perception, and reaction time",it:"L'alcol riduce ulteriormente la visione notturna, la percezione della profondita e il tempo di reazione gia diminuiti"},{en:"Night air reduces alcohol absorption",it:"L'aria notturna riduce l'assorbimento dell'alcol"},{en:"Only affects drivers over 60",it:"Influisce solo sui conducenti over 60"}],correct:1,explain_en:"At night: vision is already reduced. Adding alcohol further degrades night vision, depth perception, and reaction time -- creating a compounded risk far greater than either alone.",explain_it:"Di notte: la visione e gia ridotta. Aggiungere l'alcol degrada ulteriormente la visione notturna, la percezione della profondita e il tempo di reazione."},
  {cat:"alcohol",en:"What is the Florida law about drinking alcohol while operating a vehicle?",it:"Qual e la legge Florida sul bere alcol mentre si opera un veicolo?",options:[{en:"Legal in small quantities",it:"Legale in piccole quantita"},{en:"Illegal -- consuming alcohol while operating a motor vehicle is prohibited",it:"Illegale -- consumare alcol mentre si opera un veicolo a motore e vietato"},{en:"Legal for passengers but not the driver",it:"Legale per i passeggeri ma non per il conducente"},{en:"Legal if BAC remains below 0.08%",it:"Legale se il BAC rimane sotto 0,08%"}],correct:1,explain_en:"Consuming alcohol while driving a motor vehicle is illegal in Florida, separate from DUI. Open container law also prohibits any open alcohol in the passenger compartment.",explain_it:"Consumare alcol mentre si guida un veicolo a motore e illegale in Florida, separatamente dal DUI."},
  {cat:"alcohol",en:"What is 'alcohol poisoning' and how does it relate to a driver's safety?",it:"Cos'e l'avvelenamento da alcol e come si relaziona alla sicurezza di un conducente?",options:[{en:"A minor reaction to cheap alcohol",it:"Una reazione minore all'alcol economico"},{en:"A life-threatening condition from excessive alcohol -- at this level the person cannot safely operate any vehicle",it:"Una condizione che mette a rischio la vita da eccesso di alcol -- a questo livello la persona non puo operare in sicurezza nessun veicolo"},{en:"Only occurs with spirits, not beer or wine",it:"Si verifica solo con i superalcolici, non con birra o vino"},{en:"Not relevant to driving",it:"Non rilevante per la guida"}],correct:1,explain_en:"Alcohol poisoning (BAC 0.25%+) is a medical emergency. At this level, consciousness is lost -- making driving physically impossible. Below this but above 0.08%, legal and physical impairment is severe.",explain_it:"L'avvelenamento da alcol (BAC 0,25%+) e un'emergenza medica. A questo livello, la coscienza viene persa -- rendendo la guida fisicamente impossibile."},
  {cat:"alcohol",en:"What is the Florida law on a second DUI offense within 5 years?",it:"Qual e la legge Florida su una seconda infrazione DUI entro 5 anni?",options:[{en:"Same as a first offense",it:"Uguale alla prima infrazione"},{en:"Minimum 10 days in jail, up to 9 months, up to $2,000 fine, mandatory IID, 5-year license revocation",it:"Minimo 10 giorni di carcere, fino a 9 mesi, fino a $2.000 di multa, IID obbligatorio, revoca della patente di 5 anni"},{en:"Only increased fines -- no additional jail",it:"Solo multe aumentate -- nessun carcere aggiuntivo"},{en:"Automatic felony charge",it:"Accusa automatica di reato grave"}],correct:1,explain_en:"Florida second DUI within 5 years: mandatory minimum 10 days jail; up to 9 months total; fine $1,000-$2,000; mandatory ignition interlock device; 5-year license revocation.",explain_it:"Florida secondo DUI entro 5 anni: minimo obbligatorio 10 giorni di carcere; fino a 9 mesi totali; multa $1.000-$2.000; dispositivo interlock obbligatorio; revoca della patente di 5 anni."},
  {cat:"alcohol",en:"What is the mandatory minimum jail time for a first DUI conviction in Florida?",it:"Qual e il tempo minimo obbligatorio in carcere per la prima condanna DUI in Florida?",options:[{en:"No mandatory minimum jail time",it:"Nessun tempo minimo obbligatorio in carcere"},{en:"8 hours",it:"8 ore"},{en:"24 hours",it:"24 ore"},{en:"72 hours",it:"72 ore"}],correct:0,explain_en:"For a first DUI in Florida, there is NO mandatory minimum jail time -- though up to 6 months is possible. Community service (50 hours minimum) and probation are typically required instead.",explain_it:"Per la prima DUI in Florida, NON c'e un tempo minimo obbligatorio in carcere -- anche se fino a 6 mesi sono possibili."},
  {cat:"alcohol",en:"What happens to a Florida minor's license if they refuse an alcohol test under zero tolerance?",it:"Cosa succede alla patente di un minore Florida se rifiuta un test dell'alcol ai sensi della tolleranza zero?",options:[{en:"Same 12-month suspension as adults",it:"Stessa sospensione di 12 mesi degli adulti"},{en:"1-year license suspension for first refusal",it:"Sospensione della patente di 1 anno per il primo rifiuto"},{en:"No consequence for minors",it:"Nessuna conseguenza per i minori"},{en:"Only a warning for first refusal",it:"Solo un avvertimento per il primo rifiuto"}],correct:1,explain_en:"Under Florida's zero tolerance law, a minor who refuses chemical testing faces 1-year license suspension for the first refusal, 18 months for subsequent refusals.",explain_it:"Ai sensi della legge di tolleranza zero della Florida, un minore che rifiuta i test chimici affronta una sospensione della patente di 1 anno per il primo rifiuto, 18 mesi per i successivi."},
  {cat:"license",en:"What is the Florida law about commercial vehicle drivers and medical examinations?",it:"Qual e la legge Florida sulle visite mediche per i conducenti di veicoli commerciali?",options:[{en:"No medical requirements for CDL holders",it:"Nessun requisito medico per i titolari CDL"},{en:"CDL holders must pass a DOT physical examination and carry a valid Medical Examiner's Certificate",it:"I titolari CDL devono superare una visita medica DOT e portare un valido certificato del medico esaminatore"},{en:"Medical exam required only for drivers over 65",it:"Visita medica richiesta solo per i conducenti over 65"},{en:"Annual eye test only required",it:"Richiesto solo test della vista annuale"}],correct:1,explain_en:"CDL holders must pass a DOT physical and carry a valid Medical Examiner's Certificate (typically valid 2 years, less for certain conditions). This ensures commercial drivers meet health standards.",explain_it:"I titolari CDL devono superare una visita medica DOT e portare un valido Certificato del Medico Esaminatore (tipicamente valido 2 anni, meno per certe condizioni)."},
  {cat:"license",en:"What is the Florida law on driving with a learner's license -- who must be in the car?",it:"Qual e la legge Florida sulla guida con il permesso per principianti -- chi deve essere in auto?",options:[{en:"Any licensed driver of any age",it:"Qualsiasi conducente patentato di qualsiasi eta"},{en:"A licensed driver who is at least 21 years old must be in the front passenger seat",it:"Un conducente patentato di almeno 21 anni deve essere nel sedile anteriore del passeggero"},{en:"Any adult over 18 in any seat",it:"Qualsiasi adulto over 18 in qualsiasi posto"},{en:"No supervision required after first 30 days",it:"Nessuna supervisione richiesta dopo i primi 30 giorni"}],correct:1,explain_en:"Florida learner's permit: a licensed driver age 21 or older must be in the front seat at all times when the permit holder is driving.",explain_it:"Permesso per principianti Florida: un conducente patentato di 21 anni o piu deve essere nel sedile anteriore in ogni momento quando il titolare del permesso guida."},
  {cat:"license",en:"What is a Florida 'E-Learning' course option for driver's license renewal?",it:"Cos'e un'opzione di corso 'E-Learning' Florida per il rinnovo della patente?",options:[{en:"A required course for all renewals",it:"Un corso obbligatorio per tutti i rinnovi"},{en:"Optional online courses that may substitute for in-person renewal requirements in some cases",it:"Corsi online opzionali che possono sostituire i requisiti di rinnovo di persona in alcuni casi"},{en:"Available only for commercial drivers",it:"Disponibile solo per i conducenti commerciali"},{en:"Not available in Florida",it:"Non disponibile in Florida"}],correct:1,explain_en:"Florida offers various online options for driver education and some renewal requirements. However, in-person renewal is still required for drivers 80+ and those needing vision testing.",explain_it:"La Florida offre varie opzioni online per l'educazione alla guida e alcuni requisiti di rinnovo."},
  {cat:"license",en:"What is the Florida requirement for obtaining a REAL ID driver's license?",it:"Qual e il requisito Florida per ottenere una patente REAL ID?",options:[{en:"Just a Florida address",it:"Solo un indirizzo Florida"},{en:"Proof of identity, Social Security number, two proofs of Florida residency, and lawful status documentation",it:"Prova di identita, numero di previdenza sociale, due prove di residenza Florida e documentazione di stato legale"},{en:"Only a passport is needed",it:"E necessario solo un passaporto"},{en:"REAL ID is automatically issued to all applicants",it:"REAL ID viene rilasciato automaticamente a tutti i richiedenti"}],correct:1,explain_en:"Florida REAL ID requires: identity proof (passport/birth certificate), SSN verification, two Florida residency proofs, and lawful status docs. Needed for domestic air travel and federal facilities after enforcement date.",explain_it:"Florida REAL ID richiede: prova di identita, verifica SSN, due prove di residenza Florida e documenti di stato legale. Necessario per i voli domestici e le strutture federali."},
  {cat:"license",en:"What is the Florida law on insurance requirements for motorcycle riders?",it:"Qual e la legge Florida sui requisiti assicurativi per i motociclisti?",options:[{en:"Same as car requirements -- PIP and PDL",it:"Stessi requisiti delle auto -- PIP e PDL"},{en:"Motorcycles are exempt from PIP requirements -- but must have liability insurance if financed or required by lender",it:"Le moto sono esenti dai requisiti PIP -- ma devono avere l'assicurazione di responsabilita se finanziate o richiesto dal finanziatore"},{en:"No insurance required for motorcycles",it:"Nessuna assicurazione richiesta per le moto"},{en:"Only liability insurance required",it:"Solo l'assicurazione di responsabilita richiesta"}],correct:1,explain_en:"Florida: motorcycles are NOT required to carry PIP insurance (no-fault doesn't apply). However, lenders typically require insurance if the bike is financed. Liability coverage is strongly recommended.",explain_it:"Florida: le moto NON sono tenute a portare l'assicurazione PIP (no-fault non si applica). Tuttavia, i finanziatori tipicamente richiedono l'assicurazione se la moto e finanziata."},
  {cat:"license",en:"What is the Florida law on vehicle registration -- how often must it be renewed?",it:"Qual e la legge Florida sulla registrazione del veicolo -- ogni quanto deve essere rinnovata?",options:[{en:"Every year",it:"Ogni anno"},{en:"Annually or biennially depending on the vehicle type and owner's choice",it:"Annualmente o biennalmente a seconda del tipo di veicolo e della scelta del proprietario"},{en:"Every 3 years",it:"Ogni 3 anni"},{en:"Only when selling or transferring the vehicle",it:"Solo quando si vende o trasferisce il veicolo"}],correct:1,explain_en:"Florida vehicle registration can be renewed annually or on a 2-year basis. The renewal fee is due before the expiration date on the registration.",explain_it:"La registrazione del veicolo Florida puo essere rinnovata annualmente o su base biennale."},
  {cat:"license",en:"What is the Florida 'Surrender of License' requirement after a DUI conviction?",it:"Qual e il requisito Florida di 'Consegna della Patente' dopo una condanna DUI?",options:[{en:"Optional -- driver may keep the license",it:"Opzionale -- il conducente puo tenere la patente"},{en:"The license must be surrendered to the court or FLHSMV during the revocation period",it:"La patente deve essere consegnata al tribunale o FLHSMV durante il periodo di revoca"},{en:"Only CDL holders must surrender",it:"Solo i titolari CDL devono consegnare"},{en:"License is automatically destroyed by DMV",it:"La patente viene automaticamente distrutta dal DMV"}],correct:1,explain_en:"After a DUI conviction resulting in revocation, the license must be physically surrendered. Driving on a revoked DUI license is a separate criminal offense.",explain_it:"Dopo una condanna DUI che comporta la revoca, la patente deve essere fisicamente consegnata. Guidare con una patente revocata per DUI e un reato penale separato."},
  {cat:"license",en:"What is the Florida law about sharing personal information on a driver's license?",it:"Qual e la legge Florida sulla condivisione delle informazioni personali su una patente?",options:[{en:"Anyone can access your license information",it:"Chiunque puo accedere alle informazioni della tua patente"},{en:"Florida's Driver's Privacy Protection Act limits who can access personal information from license records",it:"La legge sulla protezione della privacy dei conducenti della Florida limita chi puo accedere alle informazioni personali dai registri della patente"},{en:"License information is public record",it:"Le informazioni della patente sono di pubblico dominio"},{en:"Only your insurance company may access your information",it:"Solo la tua compagnia assicurativa puo accedere alle tue informazioni"}],correct:1,explain_en:"The Florida Driver's Privacy Protection Act (implementing federal DPPA) restricts access to personal information in driver's license records to specific permissible uses.",explain_it:"La legge sulla protezione della privacy dei conducenti della Florida limita l'accesso alle informazioni personali nei registri della patente a usi consentiti specifici."},
  {cat:"license",en:"What is the minimum liability coverage required to REGISTER a commercial truck in Florida?",it:"Qual e la copertura minima di responsabilita richiesta per REGISTRARE un camion commerciale in Florida?",options:[{en:"Same as passenger vehicles",it:"Uguale ai veicoli passeggeri"},{en:"Higher minimums based on vehicle weight and cargo type -- DOT/FMCSA requirements apply",it:"Minimi piu alti in base al peso del veicolo e al tipo di carico -- si applicano i requisiti DOT/FMCSA"},{en:"No insurance required for commercial vehicles",it:"Nessuna assicurazione richiesta per i veicoli commerciali"},{en:"Only PIP is required",it:"E richiesto solo PIP"}],correct:1,explain_en:"Commercial trucks face higher insurance minimums set by DOT/FMCSA based on weight class and cargo. For example, vehicles over 10,001 lbs in interstate commerce require minimum $750,000 liability.",explain_it:"I camion commerciali affrontano minimi assicurativi piu alti fissati da DOT/FMCSA in base alla classe di peso e al carico."},
  {cat:"license",en:"What is the Florida law about a new resident obtaining a Florida driver's license?",it:"Qual e la legge Florida su un nuovo residente che ottiene una patente Florida?",options:[{en:"No requirement to change license",it:"Nessun requisito per cambiare la patente"},{en:"Must obtain a Florida license within 30 days of establishing Florida residency",it:"Deve ottenere una patente Florida entro 30 giorni dall'istituzione della residenza Florida"},{en:"Must change license within 90 days",it:"Deve cambiare la patente entro 90 giorni"},{en:"Can use out-of-state license indefinitely",it:"Puo usare la patente di un altro stato indefinitamente"}],correct:1,explain_en:"New Florida residents must obtain a Florida driver's license within 30 days of establishing residency. They must surrender their out-of-state license when applying.",explain_it:"I nuovi residenti Florida devono ottenere una patente Florida entro 30 giorni dall'istituzione della residenza. Devono consegnare la patente di un altro stato quando fanno domanda."},

  // SESSION 6
  {cat:"signs",en:"What does a flashing yellow traffic light mean?",it:"Cosa significa un semaforo giallo lampeggiante?",options:[{en:"Stop completely before proceeding",it:"Fermarsi completamente prima di procedere"},{en:"Slow down and proceed with caution",it:"Rallentare e procedere con cautela"},{en:"Treat it as a green light",it:"Trattarlo come un semaforo verde"},{en:"The intersection is closed",it:"L'incrocio e chiuso"}],correct:1,explain_en:"A flashing yellow light means slow down and proceed with caution. You do not need to stop, but must be alert for cross traffic.",explain_it:"Un semaforo giallo lampeggiante significa rallentare e procedere con cautela. Non e necessario fermarsi, ma bisogna essere attenti al traffico trasversale."},
  {cat:"signs",en:"What does a flashing red traffic light mean?",it:"Cosa significa un semaforo rosso lampeggiante?",options:[{en:"Slow down and proceed with caution",it:"Rallentare e procedere con cautela"},{en:"Stop completely, yield, then proceed when safe",it:"Fermarsi completamente, cedere, poi procedere quando sicuro"},{en:"The light is broken -- treat as green",it:"Il semaforo e rotto -- trattarlo come verde"},{en:"Emergency vehicles approaching",it:"Veicoli di emergenza in avvicinamento"}],correct:1,explain_en:"A flashing red light must be treated as a stop sign: stop completely, yield to traffic and pedestrians, then proceed when safe.",explain_it:"Un semaforo rosso lampeggiante deve essere trattato come un segnale di stop: fermarsi completamente, cedere al traffico e ai pedoni, poi procedere quando sicuro."},
  {cat:"signs",en:"What shape is a railroad crossing advance warning sign?",it:"Che forma ha un segnale di avvertimento anticipato per il passaggio a livello?",options:[{en:"Round yellow sign",it:"Segnale rotondo giallo"},{en:"X-shaped white crossbuck at the tracks",it:"Crossbuck bianco a forma di X ai binari"},{en:"Red octagon",it:"Ottagono rosso"},{en:"Orange diamond",it:"Rombo arancione"}],correct:0,explain_en:"The advance warning sign for a railroad crossing is a round yellow sign with an X and RR symbols. The crossbuck at the crossing itself is white X-shaped.",explain_it:"Il segnale di avvertimento anticipato per un passaggio a livello e un segnale rotondo giallo con simboli X e RR."},
  {cat:"signs",en:"What does a DO NOT ENTER sign mean?",it:"Cosa significa un segnale DO NOT ENTER?",options:[{en:"Road under construction",it:"Strada in costruzione"},{en:"You may not enter this road from this direction -- usually on exit ramps",it:"Non puoi entrare in questa strada da questa direzione -- di solito sulle rampe di uscita"},{en:"Parking prohibited",it:"Parcheggio vietato"},{en:"One-way road ahead",it:"Strada a senso unico in avanti"}],correct:1,explain_en:"DO NOT ENTER (white horizontal bar on red background) means you cannot enter that road from your current direction. Commonly placed at highway exit ramps.",explain_it:"DO NOT ENTER significa che non puoi entrare in quella strada dalla tua direzione attuale. Comunemente posizionato alle rampe di uscita autostradale."},
  {cat:"signs",en:"What does a WRONG WAY sign mean?",it:"Cosa significa un segnale WRONG WAY?",options:[{en:"Road curves sharply",it:"La strada curva bruscamente"},{en:"You are traveling in the wrong direction -- stop and reverse",it:"Stai viaggiando nella direzione sbagliata -- fermati e fai retromarcia"},{en:"Left turns are prohibited",it:"Le svolte sinistra sono vietate"},{en:"U-turns allowed here",it:"Inversioni di marcia consentite qui"}],correct:1,explain_en:"WRONG WAY means you have entered a road in the wrong direction. Stop immediately, back up safely, and do not proceed.",explain_it:"WRONG WAY significa che hai imboccato una strada nella direzione sbagliata. Fermati immediatamente, fai retromarcia in sicurezza e non procedere."},
  {cat:"signs",en:"What color are guide signs on interstate highways?",it:"Di che colore sono i segnali guida sulle autostrade interstatali?",options:[{en:"Green",it:"Verde"},{en:"Blue",it:"Blu"},{en:"White",it:"Bianco"},{en:"Brown",it:"Marrone"}],correct:0,explain_en:"Green signs on highways provide route guidance: exit numbers, highway names, destinations, and distances.",explain_it:"I segnali verdi sulle autostrade forniscono indicazioni di percorso: numeri di uscita, nomi di autostrade, destinazioni e distanze."},
  {cat:"signs",en:"What do blue signs on highways indicate?",it:"Cosa indicano i segnali blu sulle autostrade?",options:[{en:"Speed limits",it:"Limiti di velocita"},{en:"Services available at the next exit -- gas, food, lodging, hospitals",it:"Servizi disponibili alla prossima uscita -- carburante, cibo, alloggio, ospedali"},{en:"Construction zones ahead",it:"Zone di costruzione in avanti"},{en:"Rest areas only",it:"Solo aree di sosta"}],correct:1,explain_en:"Blue highway signs indicate motorist services: gas stations, restaurants, lodging, hospitals, and other services available at the next exit.",explain_it:"I segnali autostradali blu indicano i servizi per gli automobilisti disponibili alla prossima uscita."},
  {cat:"signs",en:"What do brown signs indicate on highways?",it:"Cosa indicano i segnali marroni sulle autostrade?",options:[{en:"Agricultural areas",it:"Aree agricole"},{en:"Recreational areas, parks, historic sites, and points of interest",it:"Aree ricreative, parchi, siti storici e punti di interesse"},{en:"Restricted military zones",it:"Zone militari riservate"},{en:"Toll roads ahead",it:"Strade a pedaggio in avanti"}],correct:1,explain_en:"Brown signs designate recreational, cultural, and historical attractions: parks, forests, historic sites, scenic areas, and tourist destinations.",explain_it:"I segnali marroni designano attrazioni ricreative, culturali e storiche."},
  {cat:"signs",en:"What does a School Zone sign require?",it:"Cosa richiede un segnale School Zone?",options:[{en:"Stop and wait for a crossing guard",it:"Fermarsi e aspettare un vigile"},{en:"Reduce speed to 20 mph during posted school hours and watch for children",it:"Ridurre la velocita a 20 mph durante gli orari scolastici segnalati e fare attenzione ai bambini"},{en:"No special action required unless children are present",it:"Nessuna azione speciale richiesta a meno che i bambini non siano presenti"},{en:"Honk horn to warn children",it:"Suonare il clacson per avvisare i bambini"}],correct:1,explain_en:"School zones in Florida require 20 mph during school hours. Fines are doubled and police strictly enforce these zones.",explain_it:"Le zone scolastiche in Florida richiedono 20 mph durante gli orari scolastici. Le multe sono raddoppiate."},
  {cat:"signs",en:"What does an orange construction zone sign mean?",it:"Cosa significa un segnale arancione di zona di costruzione?",options:[{en:"Advisory information only",it:"Solo informazioni consultive"},{en:"Temporary traffic control -- must be obeyed like permanent signs and fines are doubled",it:"Controllo temporaneo del traffico -- deve essere rispettato come i segnali permanenti e le multe sono raddoppiate"},{en:"Detour suggested but not required",it:"Deviazione suggerita ma non obbligatoria"},{en:"Applies only to commercial vehicles",it:"Si applica solo ai veicoli commerciali"}],correct:1,explain_en:"Orange construction zone signs carry the same legal weight as permanent signs. Violations are subject to doubled fines in Florida work zones.",explain_it:"I segnali arancioni delle zone di costruzione hanno lo stesso valore legale dei segnali permanenti. Le violazioni sono soggette a multe raddoppiate nelle zone di lavoro."},
  {cat:"signs",en:"What does a Lane Ends Merge Left sign mean?",it:"Cosa significa un segnale Lane Ends Merge Left?",options:[{en:"Slow down -- road narrows",it:"Rallentare -- la strada si restringe"},{en:"Your lane is ending -- merge into the left lane safely",it:"La tua corsia sta finendo -- confluisci nella corsia sinistra in sicurezza"},{en:"Left lane closed ahead",it:"Corsia sinistra chiusa in avanti"},{en:"Merge required from all lanes",it:"Confluenza richiesta da tutte le corsie"}],correct:1,explain_en:"Lane Ends Merge Left means your current lane is about to end. Check mirrors and blind spot, signal, and merge into the left lane when safe.",explain_it:"Lane Ends Merge Left significa che la tua corsia corrente sta per finire. Controlla gli specchi e il punto cieco, segnala e confluisci nella corsia sinistra quando sicuro."},
  {cat:"signs",en:"What does a Soft Shoulder warning sign mean?",it:"Cosa significa un segnale di avvertimento Soft Shoulder?",options:[{en:"There is a comfortable rest area ahead",it:"C'e un'area di sosta comoda in avanti"},{en:"The road shoulder is unpaved and soft -- driving on it may cause loss of control",it:"La banchina stradale non e asfaltata e morbida -- guidare su di essa puo causare perdita di controllo"},{en:"The shoulder lane is open to traffic",it:"La corsia della banchina e aperta al traffico"},{en:"Road maintenance has softened the pavement",it:"La manutenzione stradale ha ammorbidito il manto stradale"}],correct:1,explain_en:"Soft Shoulder means the unpaved area beside the road cannot support a vehicle's weight. If you drive off the pavement, your vehicle may sink or tip.",explain_it:"Soft Shoulder significa che l'area non asfaltata accanto alla strada non puo sostenere il peso di un veicolo."},
  {cat:"signs",en:"What does a Dip warning sign mean?",it:"Cosa significa un segnale di avvertimento Dip?",options:[{en:"The road curves downward then rises -- reduce speed",it:"La strada curva verso il basso poi risale -- ridurre la velocita"},{en:"Road dips below water level ahead",it:"La strada scende sotto il livello dell'acqua in avanti"},{en:"Soft road surface",it:"Superficie stradale morbida"},{en:"Speed bump ahead",it:"Dosso rallentatore in avanti"}],correct:0,explain_en:"A Dip sign warns of a low spot in the road. High speeds through a dip can damage your vehicle's undercarriage. Slow down especially after rain.",explain_it:"Un segnale Dip avvisa di un punto basso nella strada. Le alte velocita attraverso un avvallamento possono danneggiare il sottoscocca del veicolo."},
  {cat:"signs",en:"What does a One Way sign with an arrow indicate?",it:"Cosa indica un segnale One Way con una freccia?",options:[{en:"You may only turn in the direction of the arrow",it:"Puoi svoltare solo nella direzione della freccia"},{en:"Traffic flows in one direction only -- the arrow shows which direction",it:"Il traffico scorre in una sola direzione -- la freccia mostra quale direzione"},{en:"Left turns prohibited",it:"Svolte sinistra vietate"},{en:"Merge into indicated lane",it:"Confluisci nella corsia indicata"}],correct:1,explain_en:"One Way signs indicate a road carries traffic in one direction only. Entering from the wrong end means facing head-on traffic.",explain_it:"I segnali One Way indicano che una strada trasporta traffico in una sola direzione. Entrare dall'estremita sbagliata significa affrontare traffico frontale."},
  {cat:"signs",en:"What does a HOV lane sign mean?",it:"Cosa significa un segnale di corsia HOV?",options:[{en:"Heavy oversized vehicles only",it:"Solo veicoli pesanti sovradimensionati"},{en:"High occupancy vehicle lane -- requires 2 or more persons",it:"Corsia per veicoli ad alta occupazione -- richiede 2 o piu persone"},{en:"Buses only",it:"Solo autobus"},{en:"Hazardous operations vehicles",it:"Veicoli per operazioni pericolose"}],correct:1,explain_en:"HOV (High Occupancy Vehicle) lanes require at least 2 occupants unless otherwise posted. They reduce congestion by encouraging carpooling.",explain_it:"Le corsie HOV richiedono almeno 2 occupanti salvo diversa indicazione. Riducono la congestione incoraggiando il carpooling."},
  {cat:"signs",en:"What does a No Outlet sign mean?",it:"Cosa significa un segnale No Outlet?",options:[{en:"No restaurants in this area",it:"Nessun ristorante in questa zona"},{en:"The road ends with no through route -- you will have to turn around",it:"La strada finisce senza percorso attraversante -- dovrai fare inversione di marcia"},{en:"Electric outlets not available",it:"Le prese elettriche non sono disponibili"},{en:"No left turns permitted",it:"Nessuna svolta sinistra consentita"}],correct:1,explain_en:"No Outlet means the road is a dead end with no connecting road. You must turn around.",explain_it:"No Outlet significa che la strada e un vicolo cieco senza strade di collegamento. Devi fare inversione di marcia."},
  {cat:"signs",en:"What does a sign showing SPEED LIMIT 45 NIGHT 35 mean?",it:"Cosa significa un segnale con SPEED LIMIT 45 NIGHT 35?",options:[{en:"45 mph maximum always, 35 mph recommended at night",it:"45 mph massimo sempre, 35 mph consigliati di notte"},{en:"45 mph during day, 35 mph legal maximum at night",it:"45 mph di giorno, 35 mph massimo legale di notte"},{en:"35 mph always on this road",it:"35 mph sempre su questa strada"},{en:"Speed limit applies only to trucks",it:"Il limite di velocita si applica solo ai camion"}],correct:1,explain_en:"When a sign shows two speeds, the lower speed is the legal maximum during nighttime hours. Both are regulatory.",explain_it:"Quando un segnale mostra due velocita, la velocita inferiore e il massimo legale durante le ore notturne. Entrambe sono normative."},
  {cat:"signs",en:"What does an advisory speed plate below a warning sign indicate?",it:"Cosa indica una targa di velocita consultiva sotto un segnale di avvertimento?",options:[{en:"The legal speed limit for that feature",it:"Il limite di velocita legale per quella caratteristica"},{en:"The recommended safe speed -- not legally enforced but unsafe to exceed",it:"La velocita sicura raccomandata -- non applicata legalmente ma pericolosa da superare"},{en:"The minimum speed required",it:"La velocita minima richiesta"},{en:"Applies only to large vehicles",it:"Si applica solo ai veicoli grandi"}],correct:1,explain_en:"Advisory speed plates suggest a safe speed for that feature. They are not legally enforceable but exceeding them significantly increases crash risk.",explain_it:"Le targhe di velocita consultiva suggeriscono una velocita sicura per quella caratteristica. Non sono legalmente applicabili ma superarle aumenta significativamente il rischio di incidente."},
  {cat:"signs",en:"What does the exit number on a green highway sign represent?",it:"Cosa rappresenta il numero di uscita su un segnale autostradale verde?",options:[{en:"The highway route number",it:"Il numero della rotta autostradale"},{en:"The exit number based on milepost location from the state border",it:"Il numero di uscita basato sulla posizione del miglio dal confine statale"},{en:"The speed limit at the exit",it:"Il limite di velocita all'uscita"},{en:"The distance to the next major city",it:"La distanza dalla prossima citta principale"}],correct:1,explain_en:"Florida exit numbers correspond to the milepost location along the highway from the state border. This helps with navigation and emergency response.",explain_it:"I numeri di uscita della Florida corrispondono alla posizione del miglio lungo l'autostrada dal confine statale."},
  {cat:"signs",en:"What does a Keep Right Except To Pass sign mean?",it:"Cosa significa un segnale Keep Right Except To Pass?",options:[{en:"You must always stay in the right lane",it:"Devi sempre rimanere nella corsia destra"},{en:"Stay in the right lane unless actively passing another vehicle",it:"Rimani nella corsia destra a meno che tu non stia attivamente sorpassando un altro veicolo"},{en:"Right lane is for slow vehicles only",it:"La corsia destra e solo per i veicoli lenti"},{en:"Passing is only allowed on the right",it:"Il sorpasso e consentito solo a destra"}],correct:1,explain_en:"Keep Right Except To Pass means use the right lane for normal driving and only move left when actively passing. After passing, return to the right lane.",explain_it:"Keep Right Except To Pass significa usare la corsia destra per la guida normale e spostarsi a sinistra solo quando si sta attivamente sorpassando."},
  {cat:"signs",en:"What does a roundabout warning sign look like?",it:"Come appare un segnale di avvertimento per le rotatorie?",options:[{en:"A red circle",it:"Un cerchio rosso"},{en:"A yellow diamond with circular arrows",it:"Un rombo giallo con frecce circolari"},{en:"A white rectangle with a circular road diagram",it:"Un rettangolo bianco con un diagramma stradale circolare"},{en:"A green circle with arrow",it:"Un cerchio verde con freccia"}],correct:1,explain_en:"Roundabout warning signs are yellow diamonds showing vehicles traveling in a circular pattern. They warn you to slow down and yield upon entering.",explain_it:"I segnali di avvertimento delle rotatorie sono rombi gialli che mostrano veicoli che viaggiano in un modello circolare."},
  {cat:"signs",en:"What does an orange diamond sign with a worker symbol mean?",it:"Cosa significa un segnale arancione a rombo con il simbolo di un lavoratore?",options:[{en:"Labor union headquarters nearby",it:"Sede sindacale nelle vicinanze"},{en:"Workers are present in the road ahead -- slow down and be prepared to stop",it:"Ci sono lavoratori sulla strada in avanti -- rallentare ed essere pronti a fermarsi"},{en:"A school construction zone",it:"Una zona di costruzione scolastica"},{en:"Road crew on lunch break",it:"Squadra stradale in pausa pranzo"}],correct:1,explain_en:"Work crew warning signs alert drivers that road workers are present ahead. Slow down, stay alert, and give workers plenty of room. Fines double in work zones.",explain_it:"I segnali di avvertimento crew di lavoro avvisano i conducenti che ci sono operai stradali in avanti. Rallentare e dare agli operai molto spazio."},
  {cat:"signs",en:"What does a sign with a tipping truck warn about?",it:"Di cosa avvisa un segnale con un camion che si inclina?",options:[{en:"Truck weigh station ahead",it:"Stazione di pesatura camion in avanti"},{en:"A sharp curve or ramp where high-profile vehicles may tip over",it:"Una curva stretta o rampa dove i veicoli alti possono ribaltarsi"},{en:"Road is slippery for trucks",it:"La strada e scivolosa per i camion"},{en:"Trucks must reduce speed by 50%",it:"I camion devono ridurre la velocita del 50%"}],correct:1,explain_en:"The rollover warning sign warns high-profile vehicles (trucks, RVs, SUVs) of a curve or ramp where rollover is a risk. Take the turn slowly.",explain_it:"Il segnale di avvertimento ribaltamento avvisa i veicoli alti di una curva o rampa dove il ribaltamento e un rischio."},
  {cat:"signs",en:"What does a Two-Way Traffic sign warn about?",it:"Di cosa avvisa un segnale di traffico bidirezionale?",options:[{en:"Traffic is allowed to flow in both directions",it:"Il traffico e consentito in entrambe le direzioni"},{en:"Two-way traffic begins -- oncoming vehicles may be in your lane",it:"Il traffico bidirezionale inizia -- i veicoli in arrivo potrebbero essere nella tua corsia"},{en:"The road divides ahead",it:"La strada si divide in avanti"},{en:"U-turns permitted here",it:"Inversioni di marcia consentite qui"}],correct:1,explain_en:"Two-way traffic signs warn that the road transitions from divided or one-way to two-way. Oncoming vehicles will now share the road.",explain_it:"I segnali di traffico bidirezionale avvisano che la strada passa da divisa o a senso unico a bidirezionale."},
  {cat:"signs",en:"What does a Flagperson Ahead sign mean?",it:"Cosa significa un segnale Flagperson Ahead?",options:[{en:"A flag store is nearby",it:"Vicino c'e un negozio di bandiere"},{en:"A flagger is directing traffic -- slow down and follow their instructions",it:"Un segnalatore sta dirigendo il traffico -- rallentare e seguire le sue istruzioni"},{en:"A school crossing guard is present",it:"E presente un vigile scolastico"},{en:"Political rally ahead",it:"Comizio politico in avanti"}],correct:1,explain_en:"Flagperson Ahead warns of a human traffic controller directing vehicles. Their hand signals and flags override normal traffic signals -- you must obey them.",explain_it:"Flagperson Ahead avvisa di un controllore del traffico umano che dirige i veicoli. I loro segnali manuali e bandiere superano i normali segnali di traffico."},
  {cat:"signs",en:"What does a Hospital sign with an H indicate?",it:"Cosa indica un segnale Hospital con una H?",options:[{en:"Hotel ahead",it:"Hotel in avanti"},{en:"A hospital is nearby -- accessible from the next exit",it:"Un ospedale e nelle vicinanze -- accessibile dalla prossima uscita"},{en:"Hazardous materials zone",it:"Zona di materiali pericolosi"},{en:"High occupancy vehicle lane",it:"Corsia per veicoli ad alta occupazione"}],correct:1,explain_en:"Blue H signs on highways indicate that a hospital is accessible from the next exit. Important to note when in an emergency situation.",explain_it:"I segnali H blu sulle autostrade indicano che un ospedale e accessibile dalla prossima uscita."},
  {cat:"signs",en:"What does a Traffic Lanes Reduced sign mean?",it:"Cosa significa un segnale Traffic Lanes Reduced?",options:[{en:"Speed is reduced in this zone",it:"La velocita e ridotta in questa zona"},{en:"The number of available travel lanes decreases ahead -- expect merging traffic",it:"Il numero di corsie di marcia disponibili diminuisce in avanti -- aspettarsi traffico in confluenza"},{en:"The road is closed entirely",it:"La strada e completamente chiusa"},{en:"No trucks permitted",it:"Nessun camion consentito"}],correct:1,explain_en:"Traffic Lanes Reduced warns of upcoming lane closures reducing from multiple lanes to fewer. Merge early and be patient.",explain_it:"Traffic Lanes Reduced avvisa che le prossime chiusure di corsie ridurranno il traffico. Confluire presto ed essere pazienti."},
  {cat:"signs",en:"What does a truck grade sign showing 6% mean?",it:"Cosa significa un segnale di pendenza per camion che mostra 6%?",options:[{en:"Maximum truck load 6 tons",it:"Carico massimo per camion 6 tonnellate"},{en:"A 6% downgrade ahead -- truck drivers must use lower gear",it:"Una discesa del 6% in avanti -- i camionisti devono usare una marcia piu bassa"},{en:"Trucks over 6 axles prohibited",it:"Camion con piu di 6 assi vietati"},{en:"6 miles until next truck stop",it:"6 miglia fino alla prossima area di sosta camion"}],correct:1,explain_en:"Percentage grade signs tell drivers the steepness of the hill. A 6% grade means 6 feet of vertical drop per 100 feet. Trucks must downshift to avoid brake fade.",explain_it:"I segnali di percentuale di pendenza indicano ai conducenti la ripidita della collina. I camionisti devono inserire una marcia piu bassa per evitare il surriscaldamento dei freni."},
  {cat:"signs",en:"What does a pennant-shaped sign on the left side of the road mean?",it:"Cosa significa un segnale a forma di pennant sul lato sinistro della strada?",options:[{en:"No parking on the left",it:"Nessun parcheggio a sinistra"},{en:"No passing zone -- do not pass in either direction",it:"Zona di divieto di sorpasso -- non sorpassare in nessuna direzione"},{en:"Left lane ends ahead",it:"La corsia sinistra finisce in avanti"},{en:"Begin passing permitted zone",it:"Inizia la zona di sorpasso consentito"}],correct:1,explain_en:"The yellow pennant No Passing Zone sign supplements the solid yellow centerline -- reinforcing that passing is prohibited in both directions.",explain_it:"Il segnale pennant giallo No Passing Zone integra la linea centrale gialla continua -- ribadendo che il sorpasso e vietato in entrambe le direzioni."},
  {cat:"signs",en:"What does a white RXR crossbuck sign at a railroad crossing mean?",it:"Cosa significa un segnale crossbuck bianco RXR a un passaggio a livello?",options:[{en:"Railroad crossing -- yield to trains",it:"Passaggio a livello -- cedere ai treni"},{en:"Road closed for repairs",it:"Strada chiusa per riparazioni"},{en:"Speed limit 10 mph",it:"Limite di velocita 10 mph"},{en:"Restricted crossing -- permit required",it:"Attraversamento limitato -- permesso richiesto"}],correct:0,explain_en:"The white X-shaped crossbuck is placed at the railroad crossing itself. You must yield to any approaching trains.",explain_it:"Il crossbuck bianco a forma di X e posizionato al passaggio a livello stesso. Devi cedere a qualsiasi treno in avvicinamento."},
  {cat:"laws",en:"What is Florida's Move Over law?",it:"Cos'e la legge Move Over della Florida?",options:[{en:"Move to the right lane when passed by faster traffic",it:"Spostarsi nella corsia destra quando si e sorpassati da traffico piu veloce"},{en:"Move over one lane or slow to 20 mph below speed limit when passing stopped emergency or road service vehicles",it:"Spostarsi di una corsia o rallentare a 20 mph sotto il limite quando si passano veicoli di emergenza o servizio stradale fermi"},{en:"Move to shoulder when emergency vehicles approach",it:"Spostarsi sulla banchina quando si avvicinano veicoli di emergenza"},{en:"Only required for police vehicles",it:"Richiesto solo per i veicoli della polizia"}],correct:1,explain_en:"Florida Move Over law: move one lane away from stopped emergency, law enforcement, sanitation, and utility vehicles with lights flashing. If you cannot move over, reduce speed to 20 mph below posted limit.",explain_it:"Legge Move Over della Florida: spostarsi di una corsia dai veicoli di emergenza, forze dell'ordine, sanificazione e servizi fermi con luci lampeggianti."},
  {cat:"laws",en:"What is the Florida law on yielding to pedestrians in a crosswalk?",it:"Qual e la legge Florida sul cedere la precedenza ai pedoni in un attraversamento pedonale?",options:[{en:"Only yield if the pedestrian is already in your lane",it:"Cedere solo se il pedone e gia nella tua corsia"},{en:"Stop and yield to pedestrians who are in or entering any part of a crosswalk",it:"Fermarsi e cedere ai pedoni che si trovano in o stanno entrando in qualsiasi parte di un attraversamento pedonale"},{en:"Pedestrians must wait for all traffic to pass",it:"I pedoni devono aspettare che tutto il traffico passi"},{en:"Only yield when a crossing guard is present",it:"Cedere solo quando e presente un vigile"}],correct:1,explain_en:"Florida law requires drivers to stop and yield to pedestrians in crosswalks. You must yield when a pedestrian is in the crosswalk or entering it.",explain_it:"La legge Florida richiede ai conducenti di fermarsi e cedere ai pedoni negli attraversamenti pedonali quando un pedone e nell'attraversamento o vi sta entrando."},
  {cat:"laws",en:"What is the Florida texting while driving law?",it:"Qual e la legge Florida sugli SMS alla guida?",options:[{en:"Legal if stopped at a red light",it:"Legale se fermo a un semaforo rosso"},{en:"A primary offense -- police can stop you solely for texting",it:"Una violazione primaria -- la polizia puo fermarti esclusivamente per inviare messaggi"},{en:"A secondary offense only",it:"Solo una violazione secondaria"},{en:"Legal for adults but not teens",it:"Legale per gli adulti ma non per i ragazzi"}],correct:1,explain_en:"Florida made texting while driving a primary offense in 2019. Officers can pull you over solely for texting. Fines start at $30 for first offense plus court costs.",explain_it:"La Florida ha reso gli SMS alla guida una violazione primaria nel 2019. Gli agenti possono fermarti esclusivamente per inviare messaggi."},
  {cat:"laws",en:"What is the Florida law about leaving a child alone in a vehicle?",it:"Qual e la legge Florida sul lasciare un bambino solo in un veicolo?",options:[{en:"Legal if the engine is off",it:"Legale se il motore e spento"},{en:"Illegal -- you may not leave a child under 6 without supervision of someone 12 or older",it:"Illegale -- non puoi lasciare un bambino sotto i 6 anni senza la supervisione di qualcuno di 12 anni o piu"},{en:"Legal for up to 5 minutes in a shaded area",it:"Legale per un massimo di 5 minuti in un'area ombreggiata"},{en:"Only illegal if the engine is running",it:"Illegale solo se il motore e acceso"}],correct:1,explain_en:"Florida law prohibits leaving a child 6 or younger unsupervised in a vehicle. In Florida's heat, a child can die in a hot car in minutes.",explain_it:"La legge Florida vieta di lasciare un bambino di 6 anni o meno non supervisionato in un veicolo. Nel caldo della Florida, un bambino puo morire in un'auto calda in pochi minuti."},
  {cat:"laws",en:"What is the Florida law on right turns at red lights?",it:"Qual e la legge Florida sulle svolte destra ai semafori rossi?",options:[{en:"Always prohibited unless a sign permits it",it:"Sempre vietato a meno che un segnale non lo permetta"},{en:"Permitted unless prohibited by sign -- must come to a complete stop first and yield to all traffic",it:"Consentito a meno che non sia vietato da segnale -- deve prima fermarsi completamente e cedere a tutto il traffico"},{en:"Always legal without stopping",it:"Sempre legale senza fermarsi"},{en:"Only at intersections with dedicated turn lanes",it:"Solo agli incroci con corsie di svolta dedicate"}],correct:1,explain_en:"Right on Red is permitted in Florida unless a No Turn on Red sign is posted. You MUST come to a complete stop first, then yield before turning.",explain_it:"La svolta destra al rosso e consentita in Florida a meno che non sia segnalato No Turn on Red. Devi prima fermarti completamente, poi cedere prima di svoltare."},
  {cat:"laws",en:"What must you do before crossing a sidewalk when exiting a driveway?",it:"Cosa devi fare prima di attraversare un marciapiede uscendo da un vialetto?",options:[{en:"Honk horn to warn pedestrians",it:"Suonare il clacson per avvisare i pedoni"},{en:"Stop before the sidewalk and yield to all pedestrians and cyclists",it:"Fermarsi prima del marciapiede e cedere a tutti i pedoni e ciclisti"},{en:"Check mirror only and proceed slowly",it:"Controllare solo lo specchio e procedere lentamente"},{en:"No special requirement",it:"Nessun requisito speciale"}],correct:1,explain_en:"When exiting a driveway over a sidewalk, you must stop before the sidewalk and yield to all pedestrians and cyclists before crossing.",explain_it:"Quando si esce da un vialetto attraverso un marciapiede, ci si deve fermare prima del marciapiede e cedere a tutti i pedoni e ciclisti prima di attraversare."},
  {cat:"laws",en:"What is the Florida law about parking near a fire hydrant?",it:"Qual e la legge Florida sul parcheggio vicino a un idrante antincendio?",options:[{en:"No parking within 10 feet of a fire hydrant",it:"Nessun parcheggio entro 10 piedi da un idrante antincendio"},{en:"No parking within 15 feet of a fire hydrant",it:"Nessun parcheggio entro 15 piedi da un idrante antincendio"},{en:"No parking within 20 feet of a fire hydrant",it:"Nessun parcheggio entro 20 piedi da un idrante antincendio"},{en:"No parking within 25 feet of a fire hydrant",it:"Nessun parcheggio entro 25 piedi da un idrante antincendio"}],correct:1,explain_en:"Florida prohibits parking within 15 feet of a fire hydrant. Emergency vehicles need unobstructed access during a fire.",explain_it:"La Florida vieta il parcheggio entro 15 piedi da un idrante antincendio. I veicoli di emergenza hanno bisogno di accesso non ostruito durante un incendio."},
  {cat:"laws",en:"What must you do when a school bus stops on an undivided road with flashing red lights?",it:"Cosa devi fare quando uno scuolabus si ferma su una strada non divisa con luci rosse lampeggianti?",options:[{en:"Continue if going in the opposite direction",it:"Continuare se si va nella direzione opposta"},{en:"ALL traffic in both directions must stop",it:"TUTTO il traffico in entrambe le direzioni deve fermarsi"},{en:"Stop only if children are crossing",it:"Fermarsi solo se i bambini stanno attraversando"},{en:"Stop for 10 seconds then proceed",it:"Fermarsi per 10 secondi poi procedere"}],correct:1,explain_en:"On undivided roads (no physical median), ALL traffic in both directions must stop for a stopped school bus with flashing red lights and extended stop arm.",explain_it:"Sulle strade non divise, TUTTO il traffico in entrambe le direzioni deve fermarsi per uno scuolabus fermo con luci rosse lampeggianti e braccio di stop esteso."},
  {cat:"laws",en:"In Florida, when must you use headlights?",it:"In Florida, quando devi usare i fari?",options:[{en:"Only at night",it:"Solo di notte"},{en:"Between sunset and sunrise AND anytime visibility is reduced to less than 1000 feet",it:"Tra il tramonto e l'alba E ogni volta che la visibilita e ridotta a meno di 1000 piedi"},{en:"Only in rain or fog",it:"Solo in caso di pioggia o nebbia"},{en:"Headlights are always optional",it:"I fari sono sempre opzionali"}],correct:1,explain_en:"Florida requires headlights from sunset to sunrise AND whenever weather conditions reduce visibility to less than 1000 feet.",explain_it:"La Florida richiede i fari dal tramonto all'alba E ogni volta che le condizioni meteorologiche riducono la visibilita a meno di 1000 piedi."},
  {cat:"laws",en:"What is the Florida minimum speed law on highways?",it:"Qual e la legge sulla velocita minima sulle autostrade Florida?",options:[{en:"No minimum speed exists",it:"Non esiste velocita minima"},{en:"You must not drive so slowly as to impede the normal flow of traffic",it:"Non devi guidare cosi lentamente da ostacolare il normale flusso del traffico"},{en:"Minimum 45 mph on all highways",it:"Minimo 45 mph su tutte le autostrade"},{en:"Minimum 55 mph on interstates",it:"Minimo 55 mph sulle autostrade interstatali"}],correct:1,explain_en:"Florida requires minimum speed compliance: you must not drive so slowly that you impede normal traffic flow.",explain_it:"La Florida richiede il rispetto della velocita minima: non devi guidare cosi lentamente da ostacolare il normale flusso del traffico."},
  {cat:"laws",en:"What is the Florida law on cell phone use for drivers under 18?",it:"Qual e la legge Florida sull'uso del cellulare per i conducenti under 18?",options:[{en:"No restriction for teens",it:"Nessuna restrizione per gli adolescenti"},{en:"All handheld phone use is prohibited for teens with learner or provisional licenses",it:"Tutto l'uso del telefono portatile e vietato per i ragazzi con patente per principianti o provvisoria"},{en:"Texting only is prohibited",it:"Solo gli SMS sono vietati"},{en:"Only prohibited in school zones",it:"Vietato solo nelle zone scolastiche"}],correct:1,explain_en:"Florida teen drivers under 18 with learner or provisional licenses are prohibited from using any handheld device while driving.",explain_it:"I giovani conducenti della Florida under 18 con patente per principianti o provvisoria hanno il divieto di usare qualsiasi dispositivo portatile durante la guida."},
  {cat:"laws",en:"What is the Florida law about following emergency vehicles?",it:"Qual e la legge Florida sul seguire i veicoli di emergenza?",options:[{en:"You may follow closely to take advantage of cleared traffic",it:"Puoi seguire da vicino per approfittare del traffico liberato"},{en:"You must not follow within 500 feet of an emergency vehicle responding to an alarm",it:"Non devi seguire entro 500 piedi da un veicolo di emergenza che risponde a un allarme"},{en:"You may follow at a normal 2-second distance",it:"Puoi seguire a una normale distanza di 2 secondi"},{en:"No restriction on following emergency vehicles",it:"Nessuna restrizione nel seguire i veicoli di emergenza"}],correct:1,explain_en:"Florida prohibits following within 500 feet of a fire truck or emergency vehicle responding to an alarm.",explain_it:"La Florida vieta di seguire entro 500 piedi da un'autopompa o veicolo di emergenza che risponde a un allarme."},
  {cat:"laws",en:"What is the penalty for a Florida speeding violation of 30 mph or more over the limit?",it:"Qual e la sanzione per una violazione di eccesso di velocita di 30 mph o piu in Florida?",options:[{en:"A $50 fine",it:"Una multa di $50"},{en:"4 points, fines over $250, and possible mandatory court appearance",it:"4 punti, multe superiori a $250 e possibile comparizione obbligatoria in tribunale"},{en:"Automatic license suspension",it:"Sospensione automatica della patente"},{en:"Only a warning for first offense",it:"Solo un avvertimento alla prima infrazione"}],correct:1,explain_en:"Speeding 30+ mph over the limit in Florida: 4 points, fines starting at $250+, possible mandatory court appearance, and 6 points if in a school zone.",explain_it:"Eccesso di velocita di 30+ mph in Florida: 4 punti, multe a partire da $250+, possibile comparizione obbligatoria in tribunale."},
  {cat:"laws",en:"What is the Florida rule on passing on the right?",it:"Qual e la regola Florida sul sorpasso a destra?",options:[{en:"Always illegal",it:"Sempre illegale"},{en:"Legal only when the passed vehicle is making a left turn or on a multi-lane road",it:"Legale solo quando il veicolo che viene sorpassato sta svoltando a sinistra o su una strada a piu corsie"},{en:"Always legal if the road is wide enough",it:"Sempre legale se la strada e abbastanza larga"},{en:"Legal only on divided highways",it:"Legale solo sulle autostrade divise"}],correct:1,explain_en:"Passing on the right is permitted when the passed vehicle is making a left turn, or on multi-lane roads where each lane moves independently.",explain_it:"Il sorpasso a destra e consentito quando il veicolo sorpassato sta svoltando a sinistra, o su strade a piu corsie dove ogni corsia si muove indipendentemente."},
  {cat:"laws",en:"What is Florida's law on wearing a seatbelt as a rear-seat passenger?",it:"Qual e la legge Florida sull'indossare la cintura di sicurezza come passeggero sul sedile posteriore?",options:[{en:"Rear seat belts are optional for adults",it:"Le cinture del sedile posteriore sono opzionali per gli adulti"},{en:"All occupants in all seats must wear a seatbelt",it:"Tutti gli occupanti in tutti i sedili devono indossare la cintura di sicurezza"},{en:"Only required for passengers under 18",it:"Richiesto solo per i passeggeri under 18"},{en:"Only required on highways",it:"Richiesto solo in autostrada"}],correct:1,explain_en:"Florida requires all vehicle occupants to wear seatbelts regardless of seating position.",explain_it:"La Florida richiede a tutti gli occupanti del veicolo di indossare le cinture di sicurezza indipendentemente dalla posizione del sedile."},
  {cat:"laws",en:"What is the Florida law on merging onto a highway?",it:"Qual e la legge Florida sulla confluenza in autostrada?",options:[{en:"Highway traffic must always yield to merging vehicles",it:"Il traffico autostradale deve sempre cedere ai veicoli che confluiscono"},{en:"Merging vehicles must yield to traffic already on the highway",it:"I veicoli che confluiscono devono cedere al traffico gia in autostrada"},{en:"Both share equal responsibility",it:"Entrambi condividono uguale responsabilita"},{en:"Only yield if there is a yield sign",it:"Cedere solo se c'e un segnale di precedenza"}],correct:1,explain_en:"Vehicles entering a highway via an on-ramp must yield to vehicles already traveling on the highway.",explain_it:"I veicoli che entrano in autostrada tramite una rampa di accesso devono cedere ai veicoli che viaggiano gia in autostrada."},
  {cat:"laws",en:"What is the Florida law on passing near a railroad crossing?",it:"Qual e la legge Florida sul sorpasso vicino a un passaggio a livello?",options:[{en:"Passing is allowed if no train is visible",it:"Il sorpasso e consentito se nessun treno e visibile"},{en:"Do not pass within 100 feet of a railroad crossing",it:"Non sorpassare entro 100 piedi da un passaggio a livello"},{en:"Passing is always allowed near railroad crossings",it:"Il sorpasso e sempre consentito vicino ai passaggi a livello"},{en:"Pass only if the crossing gates are up",it:"Sorpassare solo se le barriere del passaggio sono alzate"}],correct:1,explain_en:"Florida prohibits passing within 100 feet of a railroad crossing -- you need clear sight lines and braking distance to stop safely for a train.",explain_it:"La Florida vieta il sorpasso entro 100 piedi da un passaggio a livello."},
  {cat:"laws",en:"What is the Florida law on parking on a hill without a curb?",it:"Qual e la legge Florida sul parcheggio su una collina senza marciapiede?",options:[{en:"No special requirement",it:"Nessun requisito speciale"},{en:"Turn front wheels to the right so the vehicle rolls away from traffic if the brake fails",it:"Girare le ruote anteriori a destra in modo che il veicolo rotoli lontano dal traffico se il freno si guasta"},{en:"Turn wheels to the left",it:"Girare le ruote a sinistra"},{en:"Park only at the top of hills",it:"Parcheggiare solo in cima alle colline"}],correct:1,explain_en:"On a downhill without a curb: turn wheels to the right (toward the shoulder) so if brakes fail, the vehicle rolls off the road, not into traffic.",explain_it:"In discesa senza marciapiede: girare le ruote a destra in modo che se i freni si guastano, il veicolo rotoli fuori dalla strada."},
  {cat:"laws",en:"What is the Florida Vulnerable Road User law?",it:"Cos'e la legge Florida sul Vulnerable Road User?",options:[{en:"Applies only to children near schools",it:"Si applica solo ai bambini vicino alle scuole"},{en:"Requires extra caution and extended passing distance for pedestrians, cyclists, motorcyclists and others",it:"Richiede cautela extra e distanza di sorpasso estesa per pedoni, ciclisti, motociclisti e altri"},{en:"Bans trucks from urban areas",it:"Vieta i camion nelle aree urbane"},{en:"Prohibits passing on two-lane roads",it:"Vieta il sorpasso sulle strade a due corsie"}],correct:1,explain_en:"Florida vulnerable road user protections require drivers to exercise due care and provide adequate space when passing pedestrians, cyclists, motorcyclists, and similar users.",explain_it:"Le protezioni della Florida per gli utenti vulnerabili della strada richiedono ai conducenti di esercitare la dovuta cura e fornire spazio adeguato."},
  {cat:"laws",en:"What is the Florida law about using hazard lights when parked on the roadside?",it:"Qual e la legge Florida sull'uso delle luci di pericolo quando si e parcheggiati sul bordo della strada?",options:[{en:"Hazard lights should never be used while stopped",it:"Le luci di pericolo non devono mai essere usate mentre si e fermi"},{en:"Use hazard lights to warn approaching traffic when stopped on or near the roadway",it:"Usare le luci di pericolo per avvisare il traffico in avvicinamento quando ci si ferma sulla o vicino alla carreggiata"},{en:"Only use hazard lights in construction zones",it:"Usare le luci di pericolo solo nelle zone di costruzione"},{en:"Only at night",it:"Solo di notte"}],correct:1,explain_en:"When stopped on the shoulder or roadway, activate hazard lights to warn approaching drivers and reduce rear-end collision risk.",explain_it:"Quando ci si ferma sulla banchina o sulla carreggiata, attivare le luci di pericolo per avvisare i conducenti in avvicinamento."},
  {cat:"laws",en:"What is Florida's law on U-turns?",it:"Qual e la legge Florida sulle inversioni di marcia?",options:[{en:"Never legal in Florida",it:"Mai legale in Florida"},{en:"Permitted where not prohibited by sign and when completed safely without interfering with traffic",it:"Consentite dove non proibite da segnale e quando completate in sicurezza senza interferire con il traffico"},{en:"Only at intersections with traffic lights",it:"Solo agli incroci con semafori"},{en:"Only on roads with speed limit under 35 mph",it:"Solo su strade con limite di velocita inferiore a 35 mph"}],correct:1,explain_en:"U-turns are permitted in Florida where not prohibited by sign and when they can be completed safely. Prohibited near hills, curves, and at many intersections.",explain_it:"Le inversioni di marcia sono consentite in Florida dove non proibite da segnale e quando possono essere completate in sicurezza."},
  {cat:"laws",en:"What is the Florida law about the number of passengers in a vehicle?",it:"Qual e la legge Florida sul numero di passeggeri in un veicolo?",options:[{en:"No limit as long as everyone is comfortable",it:"Nessun limite purche tutti siano comodi"},{en:"No more passengers than the vehicle has seat belts -- each must have their own belt",it:"Non piu passeggeri di quanti il veicolo abbia cinture di sicurezza -- ognuno deve avere la propria cintura"},{en:"Up to 2 extra passengers always allowed",it:"Fino a 2 passeggeri extra sempre consentiti"},{en:"Applies only to vehicles over 10 years old",it:"Si applica solo ai veicoli con piu di 10 anni"}],correct:1,explain_en:"Every vehicle occupant must have their own seat and seat belt. Overcrowding a vehicle is illegal and creates serious safety hazards.",explain_it:"Ogni occupante del veicolo deve avere il proprio sedile e cintura di sicurezza. Sovraffollare un veicolo e illegale."},
  {cat:"laws",en:"What is the Florida law about sharing the road with horses?",it:"Qual e la legge Florida sulla condivisione della strada con i cavalli?",options:[{en:"Horses must use shoulder paths only",it:"I cavalli devono usare solo i percorsi sulla banchina"},{en:"Horse-drawn vehicles and riders have the same road rights -- pass carefully and quietly",it:"I veicoli trainati da cavalli e i cavalieri hanno gli stessi diritti stradali -- passare con attenzione e silenziosamente"},{en:"Horses must yield to all motor vehicles",it:"I cavalli devono cedere a tutti i veicoli a motore"},{en:"Motor vehicles always have right of way over horses",it:"I veicoli a motore hanno sempre la precedenza sui cavalli"}],correct:1,explain_en:"Horse-drawn vehicles and equestrians have the same rights on public roads. Pass slowly and quietly -- sudden noises can spook horses causing dangerous situations.",explain_it:"I veicoli trainati da cavalli e i cavalieri hanno gli stessi diritti sulle strade pubbliche. Passare lentamente e silenziosamente -- i rumori improvvisi possono spaventare i cavalli."},
  {cat:"laws",en:"What is the Florida law about driving with a virtual reality headset?",it:"Qual e la legge Florida sulla guida con un visore di realta virtuale?",options:[{en:"Legal if you can still see the road",it:"Legale se riesci ancora a vedere la strada"},{en:"Illegal -- any device that impairs visibility or attention while driving is prohibited",it:"Illegale -- qualsiasi dispositivo che compromette la visibilita o l'attenzione durante la guida e vietato"},{en:"Legal only on private roads",it:"Legale solo su strade private"},{en:"Not addressed by Florida law",it:"Non affrontato dalla legge Florida"}],correct:1,explain_en:"Florida traffic law prohibits operating a vehicle with any device that impairs the driver's view or interferes with driving. VR headsets are prohibited.",explain_it:"La legge del traffico della Florida vieta di guidare con qualsiasi dispositivo che comprometta la visuale del conducente o interferisca con la guida."},
  {cat:"laws",en:"What is Florida's basic speed law?",it:"Cos'e la legge di base sulla velocita della Florida?",options:[{en:"Always drive exactly at the posted limit",it:"Guidare sempre esattamente al limite segnalato"},{en:"Never drive faster than is safe for current conditions regardless of the posted limit",it:"Non guidare mai piu veloce di quanto sia sicuro per le condizioni attuali indipendentemente dal limite segnalato"},{en:"Speed limits are advisory on rural roads",it:"I limiti di velocita sono consultivi sulle strade rurali"},{en:"You may exceed limits briefly to pass",it:"Puoi superare i limiti brevemente per sorpassare"}],correct:1,explain_en:"Florida basic speed law: regardless of posted limits, you must never drive faster than is reasonable and safe for current conditions (weather, traffic, visibility).",explain_it:"Legge di base sulla velocita della Florida: indipendentemente dai limiti segnalati, non devi mai guidare piu veloce di quanto sia ragionevole e sicuro per le condizioni attuali."},
  {cat:"laws",en:"What is the Florida law on passing within an intersection?",it:"Qual e la legge Florida sul sorpasso all'interno di un incrocio?",options:[{en:"Legal if the road is wide enough",it:"Legale se la strada e abbastanza larga"},{en:"Prohibited -- do not pass within an intersection or within 100 feet of one",it:"Vietato -- non sorpassare all'interno di un incrocio o entro 100 piedi da uno"},{en:"Legal if your lane is moving faster",it:"Legale se la tua corsia si muove piu velocemente"},{en:"Only prohibited at night",it:"Vietato solo di notte"}],correct:1,explain_en:"Passing within an intersection or within 100 feet of an intersection is prohibited in Florida -- there are too many potential conflict points.",explain_it:"Il sorpasso all'interno di un incrocio o entro 100 piedi da uno e vietato in Florida -- ci sono troppi potenziali punti di conflitto."},
  {cat:"laws",en:"What is the Florida law about driving on a one-way street the wrong way?",it:"Qual e la legge Florida sulla guida nel senso sbagliato su una strada a senso unico?",options:[{en:"Legal if the street is empty",it:"Legale se la strada e vuota"},{en:"Illegal -- a serious moving violation regardless of whether other vehicles are present",it:"Illegale -- una grave violazione in movimento indipendentemente dalla presenza di altri veicoli"},{en:"Legal for short distances only",it:"Legale solo per brevi distanze"},{en:"Only illegal for commercial vehicles",it:"Illegale solo per i veicoli commerciali"}],correct:1,explain_en:"Driving the wrong way on a one-way street is a serious traffic violation in Florida regardless of whether other vehicles are present.",explain_it:"Guidare nel senso sbagliato su una strada a senso unico e una grave violazione del traffico in Florida indipendentemente dalla presenza di altri veicoli."},
  {cat:"laws",en:"What is the Florida law about using turn signals?",it:"Qual e la legge Florida sull'uso dei segnali di svolta?",options:[{en:"Signals are optional if no traffic is nearby",it:"I segnali sono opzionali se non c'e traffico nelle vicinanze"},{en:"Must signal at least 100 feet before turning or changing lanes on regular roads; 200 feet on highways",it:"Segnalare almeno 100 piedi prima di svoltare o cambiare corsia su strade normali; 200 piedi in autostrada"},{en:"Only required in school zones",it:"Richiesto solo nelle zone scolastiche"},{en:"Only required when other vehicles are present",it:"Richiesto solo quando altri veicoli sono presenti"}],correct:1,explain_en:"Florida requires signaling 100 feet before turns or lane changes on regular roads, and 200 feet on limited access highways. Failure to signal is a moving violation.",explain_it:"La Florida richiede di segnalare 100 piedi prima delle svolte o cambi di corsia su strade normali, e 200 piedi sulle autostrade."},
  {cat:"safety",en:"What is hydroplaning and how can you prevent it?",it:"Cos'e l'aquaplaning e come puoi prevenirlo?",options:[{en:"Engine failure in water -- prevent by waterproofing",it:"Guasto del motore nell'acqua -- prevenire con l'impermeabilizzazione"},{en:"Tires riding on a film of water losing road contact -- prevent with adequate tread, proper inflation, and reduced speed in rain",it:"Pneumatici che scivolano su un film d'acqua perdendo il contatto -- prevenire con battistrada adeguato, gonfiaggio corretto e velocita ridotta sotto la pioggia"},{en:"Water entering the engine -- avoid puddles",it:"Acqua che entra nel motore -- evitare le pozzanghere"},{en:"Wiper failure in heavy rain",it:"Guasto del tergicristallo in caso di pioggia intensa"}],correct:1,explain_en:"Hydroplaning: tires lose contact with road and ride on water. Prevention: adequate tread depth, proper inflation, slow down in rain, avoid standing water.",explain_it:"Aquaplaning: i pneumatici perdono il contatto con la strada e scivolano sull'acqua. Prevenzione: battistrada adeguato, gonfiaggio corretto, rallentare sotto la pioggia."},
  {cat:"safety",en:"What is the correct action if your vehicle hydroplanes?",it:"Qual e l'azione corretta se il tuo veicolo aquaplana?",options:[{en:"Brake hard to regain traction",it:"Frenare forte per recuperare la trazione"},{en:"Ease off the accelerator, hold steering straight, and let the vehicle slow until tires regain contact",it:"Togliere il piede dall'acceleratore, tenere lo sterzo dritto e lasciare che il veicolo rallenti finche i pneumatici riguadagnano il contatto"},{en:"Turn the steering wheel sharply in the direction of the skid",it:"Girare bruscamente il volante nella direzione del pattinamento"},{en:"Accelerate out of the hydroplane",it:"Accelerare per uscire dall'aquaplaning"}],correct:1,explain_en:"When hydroplaning: release the accelerator, hold steering straight, and allow the vehicle to naturally slow down until tires contact the road again.",explain_it:"Quando si aquaplana: rilasciare l'acceleratore, tenere lo sterzo dritto e lasciare che il veicolo rallenti naturalmente finche i pneumatici riguadagnano il contatto."},
  {cat:"safety",en:"What should you do if your accelerator sticks while driving?",it:"Cosa dovresti fare se il tuo acceleratore rimane bloccato durante la guida?",options:[{en:"Turn off the ignition immediately while steering",it:"Spegnere immediatamente l'accensione mentre si sterza"},{en:"Shift to neutral, apply brakes firmly, steer safely off the road, and turn off the engine",it:"Passare in folle, applicare i freni con fermezza, sterzare in sicurezza fuori dalla strada e spegnere il motore"},{en:"Pump the gas pedal to free it",it:"Pompare il pedale del gas per liberarlo"},{en:"Open the door and jump out",it:"Aprire la porta e saltare fuori"}],correct:1,explain_en:"Stuck accelerator: shift to neutral immediately (stops power), apply brakes firmly to stop, steer to safety, then turn off the engine after stopping.",explain_it:"Acceleratore bloccato: passare in folle immediatamente, applicare i freni con fermezza per fermarsi, sterzare verso la sicurezza, poi spegnere il motore dopo essersi fermati."},
  {cat:"safety",en:"What is the correct response to a tire blowout at highway speed?",it:"Qual e la risposta corretta a una foratura ad alta velocita autostradale?",options:[{en:"Brake hard and steer to the shoulder",it:"Frenare forte e sterzare verso la banchina"},{en:"Grip steering firmly, ease off gas, steer straight, let vehicle slow naturally, then guide to the shoulder",it:"Stringere fermamente lo sterzo, togliere il piede dal gas, sterzare dritto, lasciare che il veicolo rallenti naturalmente, poi guidare verso la banchina"},{en:"Accelerate through the blowout",it:"Accelerare attraverso la foratura"},{en:"Turn sharply toward the flat tire side",it:"Girare bruscamente verso il lato del pneumatico sgonfio"}],correct:1,explain_en:"Tire blowout: grip wheel firmly, do NOT brake hard, ease off gas, steer straight, let vehicle slow naturally, then guide to the shoulder.",explain_it:"Foratura: stringere fermamente il volante, NON frenare forte, togliere il piede dal gas, sterzare dritto, lasciare che il veicolo rallenti naturalmente."},
  {cat:"safety",en:"What does target fixation mean in driving?",it:"Cosa significa target fixation nella guida?",options:[{en:"Looking far ahead on the highway",it:"Guardare lontano in autostrada"},{en:"The tendency to steer toward what you are looking at -- staring at a hazard causes you to drive toward it",it:"La tendenza a sterzare verso cio che si guarda -- fissare un pericolo ti fa guidare verso di esso"},{en:"Following GPS directions too closely",it:"Seguire le indicazioni GPS troppo attentamente"},{en:"Maintaining focus on the vehicle ahead",it:"Mantenere la concentrazione sul veicolo davanti"}],correct:1,explain_en:"Target fixation: drivers unconsciously steer toward whatever they focus on. If you stare at an obstacle, you drive into it. Look where you WANT to go.",explain_it:"Target fixation: i conducenti sterzo inconsciamente verso qualsiasi cosa su cui si concentrano. Guarda dove VUOI andare, non il pericolo."},
  {cat:"safety",en:"How should you handle driving in dense fog?",it:"Come dovresti gestire la guida nella nebbia fitta?",options:[{en:"Use high beams for maximum visibility",it:"Usare gli abbaglianti per la massima visibilita"},{en:"Use low beams or fog lights, reduce speed, increase following distance, and use road markings as guides",it:"Usare luci basse o fendinebbia, ridurre la velocita, aumentare la distanza di seguimento e usare la segnaletica stradale come guida"},{en:"Follow the taillights of the car ahead closely",it:"Seguire da vicino i fari posteriori dell'auto davanti"},{en:"Use hazard lights and maintain speed",it:"Usare le luci di pericolo e mantenere la velocita"}],correct:1,explain_en:"In dense fog: use low beams (high beams reflect off fog), slow down, increase following distance, use fog lights if equipped.",explain_it:"Nella nebbia fitta: usare luci basse (gli abbaglianti si riflettono sulla nebbia), rallentare, aumentare la distanza di seguimento."},
  {cat:"safety",en:"What is the safe following distance behind a large truck?",it:"Qual e la distanza di seguimento sicura dietro a un camion grande?",options:[{en:"2 seconds -- same as for any vehicle",it:"2 secondi -- uguale a qualsiasi veicolo"},{en:"At least 4 seconds -- large trucks have long stopping distances and large blind spots",it:"Almeno 4 secondi -- i camion grandi hanno lunghe distanze di frenata e grandi punti ciechi"},{en:"One car length per 10 mph",it:"Una lunghezza auto per ogni 10 mph"},{en:"Stay very close to benefit from the slipstream",it:"Stare molto vicino per beneficiare dello scia"}],correct:1,explain_en:"Follow large trucks with at least 4 seconds of distance: they have limited rear visibility, need longer to stop, and following close means you cannot see ahead.",explain_it:"Segui i camion grandi con almeno 4 secondi di distanza: hanno visibilita posteriore limitata e hanno bisogno di piu spazio per fermarsi."},
  {cat:"safety",en:"What should you do when driving in heavy rain and wipers cannot keep up?",it:"Cosa dovresti fare quando guidi sotto pioggia intensa e i tergicristalli non riescono a stare al passo?",options:[{en:"Continue at speed with hazard lights on",it:"Continuare alla stessa velocita con le luci di pericolo accese"},{en:"Pull over to a safe location, turn on hazard lights, and wait for conditions to improve",it:"Accostare in un luogo sicuro, accendere le luci di pericolo e aspettare che le condizioni migliorino"},{en:"Follow the vehicle ahead closely",it:"Seguire da vicino il veicolo davanti"},{en:"Turn on high beams to see further",it:"Accendere gli abbaglianti per vedere piu lontano"}],correct:1,explain_en:"If rain is so heavy that wipers cannot maintain adequate visibility: pull off the road completely, turn on hazard lights, and wait for conditions to improve.",explain_it:"Se la pioggia e cosi intensa che i tergicristalli non riescono a mantenere una visibilita adeguata: accosta completamente fuori dalla strada, accendi le luci di pericolo."},
  {cat:"safety",en:"What should you do if you feel drowsy while driving?",it:"Cosa dovresti fare se ti senti assonnato durante la guida?",options:[{en:"Turn on the radio louder to stay awake",it:"Alzare il volume della radio per rimanere sveglio"},{en:"Pull over safely and rest -- no technique effectively combats drowsiness except sleep",it:"Accostare in sicurezza e riposare -- nessuna tecnica combatte efficacemente la sonnolenza tranne il sonno"},{en:"Open windows and drink coffee",it:"Aprire i finestrini e bere caffe"},{en:"Speed up to arrive faster",it:"Accelerare per arrivare piu velocemente"}],correct:1,explain_en:"Drowsy driving is as dangerous as drunk driving. Only sleep fixes it. Pull over and take a 20-minute nap or switch drivers.",explain_it:"La guida sonnolenta e pericolosa quanto la guida in stato di ebbrezza. Solo il sonno risolve il problema. Accosta e fai un pisolino di 20 minuti."},
  {cat:"safety",en:"What is the risk of overdriving your headlights?",it:"Qual e il rischio di superare i tuoi fari in velocita?",options:[{en:"Burning out headlights faster",it:"Bruciare i fari piu velocemente"},{en:"Driving faster than your headlights allow you to stop in time -- you cannot see far enough ahead to brake safely",it:"Guidare piu veloce di quanto i tuoi fari ti permettano di fermarti in tempo -- non riesci a vedere abbastanza avanti per frenare in sicurezza"},{en:"Using too much battery power",it:"Usare troppa energia della batteria"},{en:"Blinding oncoming drivers",it:"Abbagliare i conducenti in arrivo"}],correct:1,explain_en:"Overdriving headlights: your stopping distance exceeds your sight distance. At 60 mph, low beams illuminate about 200 feet but you need 250+ feet to stop.",explain_it:"Superare i fari in velocita: la distanza di frenata supera la distanza di visuale. A 60 mph, le luci basse illuminano circa 200 piedi ma hai bisogno di 250+ piedi per fermarti."},
  {cat:"safety",en:"What is the proper way to re-enter the road from the shoulder?",it:"Qual e il modo corretto per rientrare in strada dalla banchina?",options:[{en:"Signal and pull out when there is a gap in traffic",it:"Segnalare e uscire quando c'e un'apertura nel traffico"},{en:"Accelerate on the shoulder to match traffic speed, signal, check mirrors and blind spot, then merge",it:"Accelerare sulla banchina per raggiungere la velocita del traffico, segnalare, controllare gli specchi e il punto cieco, poi confluire"},{en:"Wait for a police officer to direct you back",it:"Aspettare che un agente di polizia ti diriga di nuovo"},{en:"Honk and signal simultaneously",it:"Suonare il clacson e segnalare contemporaneamente"}],correct:1,explain_en:"Re-entering from shoulder: use the shoulder to build speed matching traffic, signal, check mirrors and blind spot thoroughly, then merge when safe.",explain_it:"Rientro dalla banchina: usa la banchina per costruire velocita corrispondente al traffico, segnala, controlla accuratamente gli specchi e il punto cieco, poi confluisci quando sicuro."},
  {cat:"safety",en:"What is the proper braking technique on a road with black ice?",it:"Qual e la tecnica di frenata corretta su una strada con ghiaccio nero?",options:[{en:"Pump the brakes rapidly",it:"Pompare i freni rapidamente"},{en:"Apply brakes very gently and gradually -- hard braking on ice causes skidding",it:"Applicare i freni molto delicatamente e gradualmente -- la frenata brusca sul ghiaccio causa pattinamento"},{en:"Use the parking brake to slow down",it:"Usare il freno a mano per rallentare"},{en:"Black ice cannot be driven on -- always stop immediately",it:"Il ghiaccio nero non puo essere percorso -- fermarsi sempre immediatamente"}],correct:1,explain_en:"On ice: brake gently and gradually. Hard braking locks wheels causing skidding and loss of control. With ABS, apply steady firm pressure.",explain_it:"Sul ghiaccio: frenare delicatamente e gradualmente. La frenata brusca blocca le ruote causando pattinamento e perdita di controllo."},
  {cat:"safety",en:"What is the Florida law on motorcycle helmets?",it:"Qual e la legge Florida sui caschi per motociclette?",options:[{en:"All riders must wear helmets",it:"Tutti i motociclisti devono indossare caschi"},{en:"Riders 21+ are exempt if they have at least $10,000 in medical insurance; all riders under 21 must wear helmets",it:"I motociclisti di 21+ anni sono esentati se hanno almeno $10.000 in assicurazione medica; tutti i motociclisti under 21 devono indossare caschi"},{en:"Helmets are optional for all riders in Florida",it:"I caschi sono opzionali per tutti i motociclisti in Florida"},{en:"Only required on highways above 55 mph",it:"Richiesto solo sulle autostrade sopra i 55 mph"}],correct:1,explain_en:"Florida helmet law: riders and passengers under 21 MUST wear helmets. Riders 21+ may ride without a helmet if they carry at least $10,000 in medical benefits insurance.",explain_it:"Legge Florida sui caschi: motociclisti e passeggeri under 21 DEVONO indossare caschi. I motociclisti di 21+ anni possono guidare senza casco se hanno almeno $10.000 in assicurazione medica."},
  {cat:"safety",en:"What is the effect of carbon monoxide from a car exhaust on a driver?",it:"Qual e l'effetto del monossido di carbonio dallo scarico di un'auto su un conducente?",options:[{en:"Improves alertness at low levels",it:"Migliora la vigilanza a bassi livelli"},{en:"Causes fatigue, confusion, headache, and can be fatal -- never run engine in enclosed spaces",it:"Causa affaticamento, confusione, mal di testa e puo essere fatale -- non avviare mai il motore in spazi chiusi"},{en:"Only dangerous at very high concentrations",it:"Pericoloso solo a concentrazioni molto elevate"},{en:"Has no effect on driving ability",it:"Non ha effetti sulla capacita di guida"}],correct:1,explain_en:"Carbon monoxide is odorless and colorless -- even low levels impair driving. Never idle in a garage, tunnel, or enclosed space. A malfunctioning exhaust system can introduce CO into the cabin.",explain_it:"Il monossido di carbonio e inodore e incolore -- anche bassi livelli compromettono la guida. Non avviare mai il motore in un garage, galleria o spazio chiuso."},
  {cat:"safety",en:"What is the recommended following distance in school and construction zones?",it:"Qual e la distanza di seguimento raccomandata nelle zone scolastiche e di costruzione?",options:[{en:"Same as normal driving -- 2 seconds",it:"Uguale alla guida normale -- 2 secondi"},{en:"Increase to at least 4 seconds due to sudden stops, workers, and children entering the road",it:"Aumentare ad almeno 4 secondi a causa di soste improvvise, operai e bambini che entrano in strada"},{en:"Stop completely before these zones",it:"Fermarsi completamente prima di queste zone"},{en:"1 second is adequate at 20 mph",it:"1 secondo e adeguato a 20 mph"}],correct:1,explain_en:"In school and construction zones: increase following distance to at least 4 seconds. Children and workers may enter the road suddenly, and workers create unpredictable conditions.",explain_it:"Nelle zone scolastiche e di costruzione: aumentare la distanza di seguimento ad almeno 4 secondi. Bambini e operai possono entrare in strada improvvisamente."},
  {cat:"safety",en:"What is the best position to grip the steering wheel?",it:"Qual e la migliore posizione per stringere il volante?",options:[{en:"12 o'clock with both hands",it:"12 in punto con entrambe le mani"},{en:"9 and 3 o'clock positions provide the best control and reduce airbag injury risk",it:"Le posizioni 9 e 3 in punto forniscono il miglior controllo e riducono il rischio di lesioni da airbag"},{en:"10 and 2 o'clock is always the correct position",it:"Le posizioni 10 e 2 in punto sono sempre la posizione corretta"},{en:"One hand at 6 o'clock for relaxed driving",it:"Una mano alle 6 in punto per una guida rilassata"}],correct:1,explain_en:"Modern recommendation: 9 and 3 o'clock (or 8 and 4). This provides good control and keeps arms away from the airbag deployment zone. The old 10-and-2 can cause arm injuries during airbag deployment.",explain_it:"Raccomandazione moderna: 9 e 3 in punto (o 8 e 4). Questo fornisce un buon controllo e mantiene le braccia lontane dalla zona di esplosione dell'airbag."},
  {cat:"safety",en:"Why is it important to check your mirrors every 5-8 seconds while driving?",it:"Perche e importante controllare gli specchi ogni 5-8 secondi durante la guida?",options:[{en:"Florida law requires it",it:"La legge Florida lo richiede"},{en:"Maintains situational awareness of vehicles approaching from behind and alongside -- essential for safe decisions",it:"Mantiene la consapevolezza situazionale dei veicoli che si avvicinano da dietro e di lato -- essenziale per decisioni sicure"},{en:"To check your appearance",it:"Per controllare il tuo aspetto"},{en:"To confirm speed on the speedometer",it:"Per confermare la velocita sul tachimetro"}],correct:1,explain_en:"Regular mirror checks (every 5-8 seconds) keep your mental picture of traffic around you current. Before any lane change, braking, or turn, you need to know where surrounding vehicles are.",explain_it:"I controlli regolari degli specchi (ogni 5-8 secondi) mantengono aggiornata la tua immagine mentale del traffico intorno a te."},
  {cat:"safety",en:"What is the danger of using cruise control in rain or on wet roads?",it:"Qual e il pericolo di usare il cruise control sotto la pioggia o su strade bagnate?",options:[{en:"No danger -- cruise control works fine in rain",it:"Nessun pericolo -- il cruise control funziona bene sotto la pioggia"},{en:"Cruise control can cause hydroplaning by maintaining speed when tires lose grip -- you cannot react quickly enough",it:"Il cruise control puo causare aquaplaning mantenendo la velocita quando i pneumatici perdono aderenza -- non puoi reagire abbastanza velocemente"},{en:"Only dangerous on ice",it:"Pericoloso solo sul ghiaccio"},{en:"Cruise control automatically reduces speed in rain",it:"Il cruise control riduce automaticamente la velocita sotto la pioggia"}],correct:1,explain_en:"Cruise control in rain is dangerous: when tires hydroplane, the system tries to maintain speed by adding power, worsening the loss of control. Always disable cruise control in wet conditions.",explain_it:"Il cruise control sotto la pioggia e pericoloso: quando i pneumatici aquaplanano, il sistema cerca di mantenere la velocita aggiungendo potenza, peggiorando la perdita di controllo."},
  {cat:"safety",en:"What is the correct procedure for making a three-point turn?",it:"Qual e la procedura corretta per eseguire una svolta a tre punti?",options:[{en:"Turn wheel hard right, reverse, then straighten",it:"Girare il volante a destra forte, fare retromarcia, poi raddrizzare"},{en:"Check traffic in both directions, turn right to curb, reverse left to opposite curb, then drive forward -- only when safe",it:"Controllare il traffico in entrambe le direzioni, girare a destra verso il marciapiede, fare retromarcia a sinistra verso il marciapiede opposto, poi procedere in avanti -- solo quando sicuro"},{en:"Reverse first, then turn forward",it:"Prima fare retromarcia, poi girare in avanti"},{en:"Only perform on roads with no traffic",it:"Eseguire solo su strade senza traffico"}],correct:1,explain_en:"Three-point turn: 1) Signal right, check traffic, pull to right. 2) Shift to reverse, signal left, back to opposite side. 3) Drive forward when clear. Use only when no other option.",explain_it:"Svolta a tre punti: 1) Segnalare a destra, controllare il traffico, accostare a destra. 2) Inserire la retromarcia, segnalare a sinistra, fare retromarcia verso il lato opposto. 3) Procedere in avanti quando libero."},
  {cat:"safety",en:"What is 'space cushion' driving?",it:"Cos'e la guida con il 'space cushion'?",options:[{en:"Adding extra padding to your car seats",it:"Aggiungere imbottitura extra ai sedili dell'auto"},{en:"Maintaining adequate distance on all sides of your vehicle to give time and space to react to hazards",it:"Mantenere una distanza adeguata su tutti i lati del veicolo per dare tempo e spazio di reagire ai pericoli"},{en:"Driving in the center of your lane only",it:"Guidare solo al centro della tua corsia"},{en:"Always following the 2-second rule",it:"Seguire sempre la regola dei 2 secondi"}],correct:1,explain_en:"Space cushion: keep adequate distance ahead (2-4+ seconds), behind (manage following vehicles), and to the sides. This gives you reaction time and escape routes if something goes wrong.",explain_it:"Space cushion: mantenere una distanza adeguata davanti (2-4+ secondi), dietro (gestire i veicoli che seguono) e di lato. Questo ti da tempo di reazione e vie di fuga."},
  {cat:"alcohol",en:"At what BAC level does measurable driving impairment begin?",it:"A quale livello BAC inizia la compromissione misurabile della guida?",options:[{en:"0.08% -- the legal limit",it:"0,08% -- il limite legale"},{en:"0.02-0.05% -- measurable impairment begins below the legal limit",it:"0,02-0,05% -- la compromissione misurabile inizia sotto il limite legale"},{en:"0.15% -- the aggravated threshold",it:"0,15% -- la soglia aggravata"},{en:"0.10%",it:"0,10%"}],correct:1,explain_en:"Measurable driving impairment begins at 0.02-0.05% BAC. The legal limit of 0.08% is not a safe threshold -- impairment begins below it.",explain_it:"La compromissione misurabile della guida inizia a 0,02-0,05% BAC. Il limite legale di 0,08% non e una soglia sicura."},
  {cat:"alcohol",en:"What is the alcohol blackout phenomenon?",it:"Cos'e il fenomeno del blackout alcolico?",options:[{en:"Passing out from too much alcohol",it:"Svenire per troppo alcol"},{en:"A period of amnesia -- the person is awake and acting but unable to form new memories",it:"Un periodo di amnesia -- la persona e sveglia e agisce ma non e in grado di formare nuovi ricordi"},{en:"A brief period of unconsciousness",it:"Un breve periodo di incoscienza"},{en:"Blurred vision from alcohol",it:"Visione sfocata dall'alcol"}],correct:1,explain_en:"Alcohol blackout: the person is conscious and moving but the hippocampus is impaired -- no memory is being formed. They can drive and seem functional but have no memory of it later.",explain_it:"Blackout alcolico: la persona e cosciente e si muove ma l'ippocampo e compromesso -- nessun ricordo viene formato. Possono guidare e sembrare funzionali ma non ne hanno memoria in seguito."},
  {cat:"alcohol",en:"Which factor increases the rate of alcohol absorption into the bloodstream?",it:"Quale fattore aumenta il tasso di assorbimento dell'alcol nel flusso sanguigno?",options:[{en:"Eating a large meal before drinking",it:"Mangiare un pasto abbondante prima di bere"},{en:"Drinking on an empty stomach and mixing with carbonated beverages",it:"Bere a stomaco vuoto e mischiare con bevande gassate"},{en:"Drinking slowly over many hours",it:"Bere lentamente per molte ore"},{en:"Drinking water between alcoholic drinks",it:"Bere acqua tra le bevande alcoliche"}],correct:1,explain_en:"Empty stomach and carbonated mixers greatly accelerate alcohol absorption. Carbonation increases stomach pressure pushing alcohol into the small intestine faster.",explain_it:"Lo stomaco vuoto e i miscelatori gassati accelerano notevolmente l'assorbimento dell'alcol."},
  {cat:"alcohol",en:"What is Florida's Zero Tolerance law for drivers under 21?",it:"Cos'e la legge Zero Tolerance della Florida per i conducenti under 21?",options:[{en:"No alcohol allowed at all for under 21 drivers",it:"Nessun alcol consentito per i conducenti under 21"},{en:"BAC of 0.02% or higher results in automatic license suspension for drivers under 21",it:"Un BAC di 0,02% o superiore comporta una sospensione automatica della patente per i conducenti under 21"},{en:"Under 21 must have zero alcohol in their system",it:"I conducenti under 21 devono avere zero alcol nel sistema"},{en:"Under 21 cannot purchase alcohol",it:"I under 21 non possono acquistare alcol"}],correct:1,explain_en:"Florida Zero Tolerance: any driver under 21 with BAC 0.02%+ loses their driving privilege -- 6 months for first offense.",explain_it:"Zero Tolerance della Florida: qualsiasi conducente under 21 con BAC 0,02%+ perde il privilegio di guida -- 6 mesi per la prima infrazione."},
  {cat:"alcohol",en:"What is the effect of alcohol on peripheral vision?",it:"Qual e l'effetto dell'alcol sulla visione periferica?",options:[{en:"Improves peripheral awareness",it:"Migliora la consapevolezza periferica"},{en:"Causes tunnel vision -- reduces the field of view and ability to detect objects at the edges",it:"Causa visione a tunnel -- riduce il campo visivo e la capacita di rilevare oggetti ai margini"},{en:"No effect on peripheral vision",it:"Nessun effetto sulla visione periferica"},{en:"Only affects central vision",it:"Influisce solo sulla visione centrale"}],correct:1,explain_en:"Alcohol causes tunnel vision -- narrowing of the visual field. Peripheral vision is essential for detecting pedestrians, cyclists, and vehicles from the sides.",explain_it:"L'alcol causa la visione a tunnel -- restringimento del campo visivo. La visione periferica e essenziale per rilevare pedoni, ciclisti e veicoli dai lati."},
  {cat:"alcohol",en:"How does body weight affect BAC?",it:"Come influisce il peso corporeo sul BAC?",options:[{en:"Body weight has no effect on BAC",it:"Il peso corporeo non ha effetti sul BAC"},{en:"A lighter person will have a higher BAC than a heavier person who drank the same amount",it:"Una persona piu leggera avra un BAC piu alto di una persona piu pesante che ha bevuto la stessa quantita"},{en:"A heavier person always gets more impaired",it:"Una persona piu pesante si compromette sempre di piu"},{en:"BAC is identical for all people drinking the same amount",it:"Il BAC e identico per tutte le persone che bevono la stessa quantita"}],correct:1,explain_en:"Body weight affects BAC: a lighter person has less body water to dilute alcohol, resulting in higher BAC for the same consumption. Gender also affects BAC.",explain_it:"Il peso corporeo influisce sul BAC: una persona piu leggera ha meno acqua corporea per diluire l'alcol, risultando in un BAC piu alto."},
  {cat:"alcohol",en:"What is the role of the liver in eliminating alcohol?",it:"Qual e il ruolo del fegato nell'eliminare l'alcol?",options:[{en:"The liver eliminates alcohol instantly",it:"Il fegato elimina l'alcol istantaneamente"},{en:"The liver metabolizes approximately one standard drink per hour -- this rate cannot be increased",it:"Il fegato metabolizza circa una bevanda standard all'ora -- questo tasso non puo essere aumentato"},{en:"The liver stores alcohol until morning",it:"Il fegato immagazzina l'alcol fino al mattino"},{en:"The liver only works during sleep",it:"Il fegato funziona solo durante il sonno"}],correct:1,explain_en:"The liver metabolizes about 0.015% BAC per hour regardless of food, coffee, or exercise. For 0.15% BAC, you need about 10 hours to reach zero.",explain_it:"Il fegato metabolizza circa 0,015% BAC all'ora indipendentemente da cibo, caffe o esercizio. Per un BAC di 0,15%, ci vogliono circa 10 ore per raggiungere lo zero."},
  {cat:"alcohol",en:"What is Florida's DUI school requirement?",it:"Qual e il requisito della scuola DUI della Florida?",options:[{en:"An optional course for reduced insurance",it:"Un corso opzionale per ridurre l'assicurazione"},{en:"Mandatory substance abuse education required before license reinstatement after DUI",it:"Educazione obbligatoria sull'abuso di sostanze richiesta prima del ripristino della patente dopo un DUI"},{en:"A 1-day safety course for all drivers",it:"Un corso di sicurezza di 1 giorno per tutti i conducenti"},{en:"Only for under-21 DUI convictions",it:"Richiesto solo per le condanne DUI under-21"}],correct:1,explain_en:"Florida DUI school is mandatory before reinstatement. Level I (21 hours) for standard DUI; Level II (21+ hours with treatment) for higher BAC or repeat offense.",explain_it:"La scuola DUI Florida e obbligatoria prima del ripristino. Livello I (21 ore) per DUI standard; Livello II (21+ ore con trattamento) per BAC piu alto o infrazione ripetuta."},
  {cat:"alcohol",en:"What is the effect of even one drink on driving ability?",it:"Qual e l'effetto anche di un solo drink sulla capacita di guida?",options:[{en:"No effect with just one drink",it:"Nessun effetto con un solo drink"},{en:"Even one drink begins to affect judgment, tracking, and divided attention in measurable ways",it:"Anche un solo drink inizia a influenzare il giudizio, il tracciamento e l'attenzione divisa in modi misurabili"},{en:"Only affects driving if under 21",it:"Influisce sulla guida solo se si ha meno di 21 anni"},{en:"One drink actually improves alertness slightly",it:"Un drink in realta migliora leggermente la vigilanza"}],correct:1,explain_en:"Even one standard drink produces measurable impairment in research studies. At 0.02% BAC (roughly 1 drink): divided attention and visual functions already decline.",explain_it:"Anche una bevanda standard produce una compromissione misurabile negli studi di ricerca. A 0,02% BAC: l'attenzione divisa e le funzioni visive gia diminuiscono."},
  {cat:"alcohol",en:"What is polydrug use and why is it especially dangerous?",it:"Cos'e l'uso polidroga e perche e particolarmente pericoloso?",options:[{en:"Using two types of prescription medications",it:"Usare due tipi di farmaci da prescrizione"},{en:"Combining alcohol with other drugs -- effects multiply rather than simply add",it:"Combinare l'alcol con altre droghe -- gli effetti si moltiplicano piuttosto che sommarsi"},{en:"Taking vitamins with alcohol",it:"Assumere vitamine con l'alcol"},{en:"Using caffeine to counteract alcohol",it:"Usare la caffeina per contrastare l'alcol"}],correct:1,explain_en:"Polydrug use: alcohol combined with other substances creates multiplicative impairment. Alcohol plus sedatives, opioids, or marijuana can cause profound impairment at low doses of each.",explain_it:"Uso polidroga: l'alcol combinato con altre sostanze crea una compromissione moltiplicativa. Alcol piu sedativi, oppioidi o marijuana possono causare una compromissione profonda."},
  {cat:"alcohol",en:"What happens to a Florida DUI conviction on a driving record?",it:"Cosa succede a una condanna DUI della Florida nel casellario di guida?",options:[{en:"Removed after 3 years",it:"Rimossa dopo 3 anni"},{en:"Removed after 7 years",it:"Rimossa dopo 7 anni"},{en:"Removed after 10 years",it:"Rimossa dopo 10 anni"},{en:"DUI convictions are permanent and never removed from Florida records",it:"Le condanne DUI sono permanenti e non vengono mai rimosse dai registri Florida"}],correct:3,explain_en:"Florida DUI convictions are PERMANENT on both the criminal and driving record. They never age off regardless of time elapsed.",explain_it:"Le condanne DUI della Florida sono PERMANENTI sia nel casellario penale che in quello di guida. Non scompaiono mai indipendentemente dal tempo trascorso."},
  {cat:"alcohol",en:"What is the minimum jail time for a first DUI conviction in Florida?",it:"Qual e la pena minima di carcere per una prima condanna DUI in Florida?",options:[{en:"No mandatory jail time for first offense",it:"Nessuna detenzione obbligatoria per la prima infrazione"},{en:"Minimum 8 hours jail time for first offense",it:"Minimo 8 ore di carcere per la prima infrazione"},{en:"Minimum 24 hours",it:"Minimo 24 ore"},{en:"Minimum 30 days",it:"Minimo 30 giorni"}],correct:0,explain_en:"First DUI Florida: no mandatory minimum jail time (unless BAC 0.15%+ or minor passenger). Maximum 6 months. The court may impose other penalties like fines, community service, and probation.",explain_it:"Primo DUI Florida: nessun minimo obbligatorio di detenzione (a meno che BAC 0,15%+ o passeggero minore). Massimo 6 mesi."},
  {cat:"alcohol",en:"What is the Florida Ignition Interlock Device (IID) requirement for aggravated DUI?",it:"Qual e il requisito del dispositivo Ignition Interlock (IID) della Florida per il DUI aggravato?",options:[{en:"IID is optional for all DUI offenses",it:"Il dispositivo IID e opzionale per tutte le infrazioni DUI"},{en:"Mandatory IID for BAC 0.15%+, repeat offenders, and those with minor passengers during DUI",it:"IID obbligatorio per BAC 0,15%+, recidivi e chi aveva passeggeri minori durante il DUI"},{en:"IID only required for third DUI and above",it:"IID richiesto solo per il terzo DUI e successivi"},{en:"IID required for all DUI convictions in Florida",it:"IID richiesto per tutte le condanne DUI in Florida"}],correct:1,explain_en:"Florida mandatory IID: required for BAC 0.15%+ (minimum 6 months), second offense (minimum 1 year), third offense (minimum 2 years). The device requires a breath test before the engine will start.",explain_it:"IID obbligatorio Florida: richiesto per BAC 0,15%+ (minimo 6 mesi), seconda infrazione (minimo 1 anno), terza infrazione (minimo 2 anni)."},
  {cat:"license",en:"What is the Florida provisional license restriction for teen drivers?",it:"Qual e la restrizione della patente provvisoria Florida per i giovani conducenti?",options:[{en:"No restrictions -- same as adult license",it:"Nessuna restrizione -- uguale alla patente adulto"},{en:"No driving 11pm-6am except for work or school; maximum 1 non-family passenger under 18",it:"Nessuna guida dalle 23:00 alle 6:00 tranne che per lavoro o scuola; massimo 1 passeggero non familiare under 18"},{en:"No highway driving until 17",it:"Nessuna guida in autostrada fino a 17 anni"},{en:"Must have adult passenger at all times",it:"Deve avere un passeggero adulto in ogni momento"}],correct:1,explain_en:"Florida GDL provisional license (age 16-17): no driving 11pm-6am (exceptions: work, school, driving with parent); max 1 non-family passenger under 18 in first year.",explain_it:"Patente provvisoria GDL Florida (16-17 anni): nessuna guida dalle 23:00 alle 6:00 (eccezioni: lavoro, scuola, guida con genitore); massimo 1 passeggero non familiare under 18 nel primo anno."},
  {cat:"license",en:"How many supervised driving hours does a Florida teen need before getting a provisional license?",it:"Quante ore di guida supervisionata ha bisogno un adolescente Florida prima di ottenere una patente provvisoria?",options:[{en:"25 hours total",it:"25 ore totali"},{en:"50 hours total including 10 at night",it:"50 ore totali incluse 10 di notte"},{en:"100 hours total",it:"100 ore totali"},{en:"No minimum required",it:"Nessun minimo richiesto"}],correct:1,explain_en:"Florida GDL requires at least 50 hours of supervised driving (including 10 hours at night) with a licensed driver 21+ before a teen can apply for a provisional license.",explain_it:"Il GDL della Florida richiede almeno 50 ore di guida supervisionata (incluse 10 ore di notte) con un conducente autorizzato di 21+ anni."},
  {cat:"license",en:"What documents does Florida require for a first-time adult license?",it:"Quali documenti richiede la Florida per una prima patente adulto?",options:[{en:"Only a Social Security card",it:"Solo una tessera di previdenza sociale"},{en:"Proof of identity, Social Security number, and two proofs of Florida residential address",it:"Prova d'identita, numero di previdenza sociale e due prove di indirizzo residenziale Florida"},{en:"Just a passport",it:"Solo un passaporto"},{en:"Birth certificate only",it:"Solo certificato di nascita"}],correct:1,explain_en:"Florida REAL ID license requires: proof of identity, proof of SSN, and two documents proving Florida residency. All documents must be originals or certified copies.",explain_it:"La patente REAL ID della Florida richiede: prova d'identita, prova del numero SSN e due documenti che comprovano la residenza in Florida."},
  {cat:"license",en:"What is the Florida SR-22 certificate?",it:"Cos'e il certificato Florida SR-22?",options:[{en:"Standard registration certificate",it:"Certificato di registrazione standard"},{en:"A certificate of financial responsibility required after DUI or uninsured accidents",it:"Un certificato di responsabilita finanziaria richiesto dopo DUI o incidenti non assicurati"},{en:"A commercial vehicle permit",it:"Un permesso per veicoli commerciali"},{en:"A motorcycle safety certificate",it:"Un certificato di sicurezza per motociclette"}],correct:1,explain_en:"SR-22 is required in Florida after DUI, driving uninsured, or serious violations. Your insurer files it with FLHSMV confirming you have insurance. Must be maintained for 3 years.",explain_it:"SR-22 e richiesto in Florida dopo DUI, guida non assicurata o violazioni gravi. La tua assicurazione lo presenta al FLHSMV confermando che hai l'assicurazione."},
  {cat:"license",en:"What is the penalty for driving with a suspended license in Florida?",it:"Qual e la sanzione per la guida con patente sospesa in Florida?",options:[{en:"A non-criminal fine only",it:"Solo una multa non penale"},{en:"A second-degree misdemeanor with possible jail, additional suspension, and vehicle impoundment",it:"Un reato minore di secondo grado con possibile carcere, ulteriore sospensione e sequestro del veicolo"},{en:"Only results in a warning",it:"Comporta solo un avvertimento"},{en:"Same as driving with an expired license",it:"Uguale a guidare con una patente scaduta"}],correct:1,explain_en:"Driving with suspended license (first offense): second-degree misdemeanor -- up to 60 days jail, $500 fine, additional suspension, possible vehicle impoundment.",explain_it:"Guida con patente sospesa (prima infrazione): reato minore di secondo grado -- fino a 60 giorni di carcere, multa di $500, ulteriore sospensione, possibile sequestro del veicolo."},
  {cat:"license",en:"What is the Florida Basic Driver Improvement (BDI) course?",it:"Cos'e il corso Florida Basic Driver Improvement (BDI)?",options:[{en:"Mandatory for all new drivers",it:"Obbligatorio per tutti i nuovi conducenti"},{en:"Optional 4-hour course reducing 3 points from driving record -- available once every 12 months",it:"Corso opzionale di 4 ore che riduce 3 punti dal casellario di guida -- disponibile una volta ogni 12 mesi"},{en:"Required after any DUI conviction",it:"Richiesto dopo qualsiasi condanna DUI"},{en:"A 12-hour commercial driving course",it:"Un corso di guida commerciale di 12 ore"}],correct:1,explain_en:"BDI: 4-hour course reducing 3 points from driving record. Must elect it instead of paying the ticket. Available once per 12 months, maximum 5 times lifetime.",explain_it:"BDI: corso di 4 ore che riduce 3 punti dal casellario di guida. Deve essere scelto invece di pagare la multa. Disponibile una volta ogni 12 mesi, massimo 5 volte nella vita."},
  {cat:"license",en:"What is the difference between license suspension and revocation in Florida?",it:"Qual e la differenza tra sospensione e revoca della patente in Florida?",options:[{en:"They are the same thing",it:"Sono la stessa cosa"},{en:"Suspension is temporary with a set end date; revocation is indefinite cancellation requiring re-application",it:"La sospensione e temporanea con una data di fine fissata; la revoca e una cancellazione indefinita che richiede una nuova domanda"},{en:"Suspension is for minor violations; revocation only for DUI",it:"La sospensione e per violazioni minori; la revoca solo per DUI"},{en:"Revocation is shorter than suspension",it:"La revoca e piu breve della sospensione"}],correct:1,explain_en:"Suspension: temporary with an end date -- automatically reinstated after period if requirements met. Revocation: complete cancellation -- must reapply and possibly retest.",explain_it:"Sospensione: temporanea con una data di fine -- automaticamente ripristinata dopo il periodo. Revoca: cancellazione completa -- deve fare nuova domanda."},
  {cat:"license",en:"How many points does speeding 1-9 mph over add in Florida?",it:"Quanti punti aggiunge un eccesso di velocita di 1-9 mph in Florida?",options:[{en:"1 point",it:"1 punto"},{en:"3 points",it:"3 punti"},{en:"4 points",it:"4 punti"},{en:"6 points",it:"6 punti"}],correct:1,explain_en:"Speeding 1-9 mph over the limit in Florida: 3 points. 15-29 mph over: 4 points. 30+ mph over: 4 points (6 if in school zone).",explain_it:"Eccesso di velocita di 1-9 mph in Florida: 3 punti. 15-29 mph: 4 punti. 30+ mph: 4 punti (6 in zona scolastica)."},
  {cat:"license",en:"What is Florida's law on driving with a foreign driver's license?",it:"Qual e la legge Florida sulla guida con una patente straniera?",options:[{en:"Foreign licenses are not valid in Florida",it:"Le patenti straniere non sono valide in Florida"},{en:"Visitors may drive with a valid foreign license; residents must get a Florida license within 30 days",it:"I visitatori possono guidare con una patente straniera valida; i residenti devono ottenere una patente Florida entro 30 giorni"},{en:"Foreign license valid for 1 year from arrival",it:"Patente straniera valida per 1 anno dall'arrivo"},{en:"Only Canadian and UK licenses accepted",it:"Solo le patenti canadesi e del Regno Unito sono accettate"}],correct:1,explain_en:"Visitors to Florida may drive with a valid foreign license. Once you establish Florida residency, you must obtain a Florida license within 30 days.",explain_it:"I visitatori della Florida possono guidare con una patente straniera valida. Una volta stabilita la residenza in Florida, devi ottenere una patente Florida entro 30 giorni."},
  {cat:"license",en:"What is the Florida FR-44 certificate?",it:"Cos'e il certificato Florida FR-44?",options:[{en:"Standard liability insurance proof",it:"Prova standard di assicurazione di responsabilita"},{en:"High-limit insurance required after DUI -- needs $100,000/$300,000 BI and $50,000 PDL",it:"Assicurazione ad alto limite richiesta dopo DUI -- richiede $100.000/$300.000 BI e $50.000 PDL"},{en:"Same as SR-22 but for motorcycles",it:"Uguale a SR-22 ma per le moto"},{en:"Proof of uninsured motorist coverage",it:"Prova di copertura automobilista non assicurato"}],correct:1,explain_en:"FR-44 is required after DUI conviction in Florida. It requires much higher liability limits than standard SR-22 and must be maintained for 3 years.",explain_it:"FR-44 e richiesto dopo la condanna DUI in Florida. Richiede limiti di responsabilita molto piu alti dello standard SR-22 e deve essere mantenuto per 3 anni."},
  {cat:"license",en:"What is the Florida minimum age for a learner's permit?",it:"Qual e l'eta minima per il permesso per principianti in Florida?",options:[{en:"14 years old",it:"14 anni"},{en:"15 years old",it:"15 anni"},{en:"16 years old",it:"16 anni"},{en:"17 years old",it:"17 anni"}],correct:1,explain_en:"Florida's minimum age for a learner's license is 15 years old. The learner must hold it for at least 12 months before applying for a provisional license.",explain_it:"L'eta minima per il permesso per principianti in Florida e 15 anni. Il principiante deve tenerlo per almeno 12 mesi prima di richiedere una patente provvisoria."},
  {cat:"license",en:"What is the full unrestricted license age in Florida?",it:"Qual e l'eta per la patente completa senza restrizioni in Florida?",options:[{en:"16 years old",it:"16 anni"},{en:"17 years old",it:"17 anni"},{en:"18 years old",it:"18 anni"},{en:"21 years old",it:"21 anni"}],correct:2,explain_en:"A full, unrestricted Florida Class E license requires age 18. GDL restrictions automatically lift at age 18.",explain_it:"Una patente Florida Class E completa e senza restrizioni richiede 18 anni. Le restrizioni GDL si tolgono automaticamente a 18 anni."},
  {cat:"license",en:"What happens if a Florida driver accumulates 24 points in 36 months?",it:"Cosa succede se un conducente Florida accumula 24 punti in 36 mesi?",options:[{en:"3-month suspension",it:"Sospensione di 3 mesi"},{en:"6-month suspension",it:"Sospensione di 6 mesi"},{en:"1-year suspension",it:"Sospensione di 1 anno"},{en:"Permanent revocation",it:"Revoca permanente"}],correct:2,explain_en:"Florida point system: 12 points/12 months = 30-day suspension; 18 points/18 months = 3-month suspension; 24 points/36 months = 1-year suspension.",explain_it:"Sistema punti Florida: 12 punti/12 mesi = sospensione 30 giorni; 18 punti/18 mesi = sospensione 3 mesi; 24 punti/36 mesi = sospensione 1 anno."},

  // SESSION 6
  {cat:"signs",en:"What does a 'Do Not Enter' sign look like?",it:"Come appare un segnale 'Do Not Enter'?",options:[{en:"A red circle with a white horizontal bar",it:"Un cerchio rosso con una barra orizzontale bianca"},{en:"A red octagon",it:"Un ottagono rosso"},{en:"A yellow diamond with an X",it:"Un rombo giallo con una X"},{en:"A white square with NO ENTRY text",it:"Un quadrato bianco con testo NO ENTRY"}],correct:0,explain_en:"Do Not Enter: red circle with white horizontal bar. Seen at exit ramps and one-way streets -- entering would put you in the path of oncoming traffic.",explain_it:"Do Not Enter: cerchio rosso con barra orizzontale bianca. Visibile alle rampe di uscita e nelle strade a senso unico."},
  {cat:"signs",en:"What does a 'Wrong Way' sign mean when seen while driving?",it:"Cosa significa un segnale 'Wrong Way' durante la guida?",options:[{en:"You have taken a wrong turn",it:"Hai svoltato nel posto sbagliato"},{en:"You are driving against the flow of traffic -- stop and reverse or turn around immediately",it:"Stai guidando contro il flusso del traffico -- fermati e fai retromarcia o girati immediatamente"},{en:"The road ahead has construction",it:"La strada davanti ha lavori in corso"},{en:"A wrong-way driver is approaching",it:"Un conducente nel senso sbagliato si sta avvicinando"}],correct:1,explain_en:"Wrong Way means YOU are going the wrong direction. Stop immediately, back up or turn around. Wrong-way driving is extremely dangerous and often fatal.",explain_it:"Wrong Way significa che stai andando nella direzione sbagliata. Fermati immediatamente, fai retromarcia o girati."},
  {cat:"signs",en:"What color are guide signs on interstate highways?",it:"Di che colore sono i segnali guida sulle autostrade interstatali?",options:[{en:"White with green text",it:"Bianchi con testo verde"},{en:"Green with white text",it:"Verdi con testo bianco"},{en:"Blue with white text",it:"Blu con testo bianco"},{en:"Brown with white text",it:"Marroni con testo bianco"}],correct:1,explain_en:"Interstate guide signs are green with white text -- showing destinations, distances, and exit numbers. Blue signs indicate services; brown indicates recreation sites.",explain_it:"I segnali guida autostradali sono verdi con testo bianco -- mostrano destinazioni, distanze e numeri di uscita."},
  {cat:"signs",en:"What does a blue H sign on a highway indicate?",it:"Cosa indica un segnale H blu su un'autostrada?",options:[{en:"A rest area with handicap facilities",it:"Un'area di sosta con strutture per disabili"},{en:"A hospital is accessible from the next exit",it:"Un ospedale e accessibile dall'uscita successiva"},{en:"A hotel is ahead",it:"Un hotel e in avanti"},{en:"A hazardous materials route",it:"Un percorso per materiali pericolosi"}],correct:1,explain_en:"Blue H signs on highways direct motorists to hospitals accessible from the upcoming exit -- important in emergencies.",explain_it:"I segnali H blu sulle autostrade dirigono gli automobilisti verso gli ospedali accessibili dall'uscita successiva."},
  {cat:"signs",en:"What does a brown sign with a camping symbol indicate?",it:"Cosa indica un segnale marrone con un simbolo di campeggio?",options:[{en:"A construction work zone",it:"Una zona di lavori in corso"},{en:"A recreational area or campground nearby",it:"Un'area ricreativa o campeggio nelle vicinanze"},{en:"A national forest boundary",it:"Il confine di una foresta nazionale"},{en:"A military reservation",it:"Una riserva militare"}],correct:1,explain_en:"Brown signs indicate recreational, cultural, or scenic areas -- parks, forests, campgrounds, historic sites.",explain_it:"I segnali marroni indicano aree ricreative, culturali o panoramiche -- parchi, foreste, campeggi, siti storici."},
  {cat:"signs",en:"What does a 'Flagger Ahead' sign in a work zone mean?",it:"Cosa significa un segnale 'Flagger Ahead' in una zona di lavoro?",options:[{en:"A flag sale is ahead",it:"Una vendita di bandiere e in avanti"},{en:"A person with a flag is controlling traffic -- obey their instructions",it:"Una persona con una bandiera sta controllando il traffico -- obbedisci alle sue istruzioni"},{en:"A speed flag checkpoint is ahead",it:"Un checkpoint della bandiera di velocita e in avanti"},{en:"Construction equipment is crossing the road",it:"Attrezzature da costruzione stanno attraversando la strada"}],correct:1,explain_en:"Flagger Ahead means a flagperson is manually directing traffic through the work zone. Their instructions override traffic signals -- slow down and obey.",explain_it:"Flagger Ahead significa che un addetto alla segnalazione sta dirigendo manualmente il traffico attraverso la zona di lavoro."},
  {cat:"signs",en:"What does a 'Road Narrows' warning sign indicate?",it:"Cosa indica un segnale di avvertimento 'Road Narrows'?",options:[{en:"The road enters a tunnel",it:"La strada entra in una galleria"},{en:"The road width decreases ahead -- reduce speed",it:"La larghezza della strada diminuisce in avanti -- riduci la velocita"},{en:"Only one lane is ahead",it:"C'e solo una corsia in avanti"},{en:"The lane is a dedicated right-turn only lane",it:"La corsia e solo per svoltare a destra"}],correct:1,explain_en:"Road Narrows warns that the roadway becomes narrower ahead. Reduce speed and be alert for vehicles in oncoming lanes.",explain_it:"Road Narrows avvisa che la carreggiata si restringe in avanti. Riduci la velocita e fai attenzione ai veicoli nelle corsie in arrivo."},
  {cat:"signs",en:"What do yellow center line markings indicate on a two-lane road?",it:"Cosa indicano le linee centrali gialle su una strada a due corsie?",options:[{en:"Bike lanes on both sides",it:"Corsie ciclabili su entrambi i lati"},{en:"Separation of traffic flowing in opposite directions",it:"Separazione del traffico che scorre in direzioni opposte"},{en:"Parking is permitted on both sides",it:"Il parcheggio e consentito su entrambi i lati"},{en:"The road has four lanes",it:"La strada ha quattro corsie"}],correct:1,explain_en:"Yellow centerlines separate opposing traffic. Solid yellow = no passing. Dashed yellow = passing permitted when safe. Double solid = no passing in either direction.",explain_it:"Le linee centrali gialle separano il traffico opposto. Giallo continuo = nessun sorpasso. Giallo tratteggiato = sorpasso consentito quando sicuro."},
  {cat:"signs",en:"What does a flashing red traffic light mean?",it:"Cosa significa un semaforo rosso lampeggiante?",options:[{en:"Slow down and proceed with caution",it:"Rallenta e procedi con cautela"},{en:"Stop completely, yield, then proceed when safe -- same as a stop sign",it:"Fermati completamente, cedi il diritto di precedenza, poi procedi quando sicuro -- come un segnale di stop"},{en:"The intersection is closed",it:"L'incrocio e chiuso"},{en:"Emergency vehicles are approaching",it:"I veicoli di emergenza si stanno avvicinando"}],correct:1,explain_en:"Flashing red = treat as a stop sign. Stop completely, yield to traffic and pedestrians, then proceed when safe.",explain_it:"Rosso lampeggiante = trattalo come un segnale di stop. Fermati completamente, cedi il diritto di precedenza, poi procedi quando sicuro."},
  {cat:"signs",en:"What does a flashing yellow traffic light mean?",it:"Cosa significa un semaforo giallo lampeggiante?",options:[{en:"Stop and wait for green",it:"Fermati e aspetta il verde"},{en:"Proceed with caution -- slow down and watch for crossing traffic",it:"Procedi con cautela -- rallenta e fai attenzione al traffico trasversale"},{en:"The light is about to turn red",it:"Il semaforo sta per diventare rosso"},{en:"Construction zone -- reduce speed to 25 mph",it:"Zona di costruzione -- riduci la velocita a 25 mph"}],correct:1,explain_en:"Flashing yellow = slow down, proceed with caution. You do not have to stop but must yield if cross traffic is present.",explain_it:"Giallo lampeggiante = rallenta, procedi con cautela. Non devi fermarti ma devi cedere se c'e traffico trasversale."},
  {cat:"signs",en:"What does a 'Soft Shoulder' warning sign mean?",it:"Cosa significa un segnale di avvertimento 'Soft Shoulder'?",options:[{en:"The road has a gentle curve",it:"La strada ha una curva dolce"},{en:"The road shoulder is unpaved or unstable -- pulling off may cause loss of control",it:"La banchina stradale non e asfaltata o e instabile -- fermarsi puo causare perdita di controllo"},{en:"The shoulder is designated for bicycle use",it:"La banchina e designata per uso biciclette"},{en:"The road curves softly to the left",it:"La strada curva dolcemente a sinistra"}],correct:1,explain_en:"Soft Shoulder: the shoulder is loose gravel, dirt, or unstable -- driving onto it may cause your vehicle to sink or lose steering control.",explain_it:"Soft Shoulder: la banchina e ghiaia sciolta, terra o instabile -- guidarci sopra puo causare la perdita del controllo dello sterzo."},
  {cat:"signs",en:"What does a 'No Outlet' or 'Dead End' sign mean?",it:"Cosa significa un segnale 'No Outlet' o 'Dead End'?",options:[{en:"Parking is prohibited ahead",it:"Il parcheggio e vietato in avanti"},{en:"The road does not connect to another road -- you must return the same way",it:"La strada non si collega a un'altra strada -- devi tornare dalla stessa strada"},{en:"The road narrows to one lane",it:"La strada si restringe a una corsia"},{en:"The road crosses a waterway",it:"La strada attraversa un corso d'acqua"}],correct:1,explain_en:"No Outlet or Dead End means the road terminates without a through connection. You will have to turn around.",explain_it:"No Outlet o Dead End significa che la strada termina senza una connessione di attraversamento. Dovrai fare inversione."},
  {cat:"signs",en:"What does a Railroad Crossing crossbuck sign require?",it:"Cosa richiede il segnale crossbuck di un passaggio a livello?",options:[{en:"Stop completely at all railroad crossings",it:"Fermarsi completamente a tutti i passaggi a livello"},{en:"Yield to any train -- stop if a train is approaching or signals are active",it:"Cedere a qualsiasi treno -- fermarsi se un treno si sta avvicinando o i segnali sono attivi"},{en:"Slow to 15 mph and proceed",it:"Rallentare a 15 mph e procedere"},{en:"Sound your horn when crossing",it:"Suonare il clacson durante l'attraversamento"}],correct:1,explain_en:"The crossbuck is a yield sign at railroad crossings. If a train is approaching or signals are flashing, you MUST stop. Never race a train.",explain_it:"Il crossbuck e un segnale di precedenza ai passaggi a livello. Se un treno si sta avvicinando o i segnali lampeggiano, DEVI fermarti."},
  {cat:"signs",en:"What does a 'No U-Turn' sign look like?",it:"Come appare un segnale 'No U-Turn'?",options:[{en:"A red circle with a U-shaped arrow and diagonal slash",it:"Un cerchio rosso con una freccia a forma di U e una barra diagonale"},{en:"A yellow diamond with a curved arrow",it:"Un rombo giallo con una freccia curva"},{en:"A white rectangle with NO U-TURN text",it:"Un rettangolo bianco con testo NO U-TURN"},{en:"An orange triangle with a U arrow",it:"Un triangolo arancione con una freccia U"}],correct:0,explain_en:"No U-Turn uses the standard prohibition format: white circle with a U-turn arrow crossed by a red diagonal slash.",explain_it:"No U-Turn usa il formato standard di divieto: cerchio bianco con una freccia di inversione attraversata da una barra diagonale rossa."},
  {cat:"signs",en:"What does a HOV sign mean?",it:"Cosa significa un segnale HOV?",options:[{en:"High-speed Overtaking Vehicle lane",it:"Corsia per veicoli ad alta velocita di sorpasso"},{en:"High-Occupancy Vehicle lane -- requires minimum number of occupants (usually 2 or 3)",it:"Corsia per veicoli ad alta occupazione -- richiede un numero minimo di occupanti (di solito 2 o 3)"},{en:"Heavy Off-road Vehicle restriction",it:"Restrizione per veicoli fuoristrada pesanti"},{en:"Hazardous materials prohibition zone",it:"Zona di divieto per materiali pericolosi"}],correct:1,explain_en:"HOV (High-Occupancy Vehicle) lanes require a minimum number of occupants. The sign specifies the requirement (e.g., 2+ persons). Violating HOV rules results in a fine.",explain_it:"Le corsie HOV richiedono un numero minimo di occupanti. Il segnale specifica il requisito (es. 2+ persone)."},
  {cat:"signs",en:"What does a green arrow on a traffic signal mean?",it:"Cosa significa una freccia verde su un semaforo?",options:[{en:"Proceed straight only",it:"Procedi solo dritto"},{en:"Protected movement in that direction -- you have right of way over opposing traffic",it:"Movimento protetto in quella direzione -- hai la precedenza sul traffico opposto"},{en:"Yield before turning in that direction",it:"Cedi il diritto di precedenza prima di svoltare"},{en:"The light is about to change",it:"Il semaforo sta per cambiare"}],correct:1,explain_en:"A green arrow provides a PROTECTED movement -- opposing traffic is stopped by a red light and you may turn without yielding.",explain_it:"Una freccia verde fornisce un movimento PROTETTO -- il traffico opposto e fermato da un semaforo rosso e puoi svoltare senza cedere la precedenza."},
  {cat:"signs",en:"What does a 'Reduced Speed Ahead' sign tell you?",it:"Cosa ti dice un segnale 'Reduced Speed Ahead'?",options:[{en:"Slow down immediately -- the new limit begins at this sign",it:"Rallenta immediatamente -- il nuovo limite inizia a questo segnale"},{en:"A lower speed limit zone begins ahead -- reduce speed gradually before reaching it",it:"Una zona a velocita piu bassa inizia in avanti -- riduci la velocita gradualmente prima di raggiungerla"},{en:"Advisory speed only -- no legal requirement",it:"Solo velocita consigliata -- nessun requisito legale"},{en:"The speed limit has been permanently changed",it:"Il limite di velocita e stato modificato permanentemente"}],correct:1,explain_en:"Reduced Speed Ahead warns you to begin slowing because a lower speed limit zone is coming. The actual lower limit sign marks where the new limit takes effect.",explain_it:"Reduced Speed Ahead avvisa di iniziare a rallentare perche sta arrivando una zona a velocita piu bassa."},
  {cat:"signs",en:"What is a reversible lane and how do you know if you may use it?",it:"Cos'e una corsia reversibile e come sai se puoi usarla?",options:[{en:"A lane you may drive in either direction at any time",it:"Una corsia in cui puoi guidare in entrambe le direzioni in qualsiasi momento"},{en:"A lane that changes direction by time of day -- a green arrow overhead means you may use it; red X means it is closed to you",it:"Una corsia che cambia direzione in base all'ora del giorno -- una freccia verde sopra significa che puoi usarla; una X rossa significa che e chiusa a te"},{en:"A lane reserved for emergency vehicles",it:"Una corsia riservata ai veicoli di emergenza"},{en:"The lane is for reversing out of traffic only",it:"La corsia e solo per fare retromarcia nel traffico"}],correct:1,explain_en:"Reversible lanes change direction based on traffic demand. Green arrow overhead = you may use the lane. Red X = lane closed to you. Always check overhead signals before entering.",explain_it:"Le corsie reversibili cambiano direzione in base alla domanda di traffico. Freccia verde sopra = puoi usare la corsia. X rossa = corsia chiusa a te."},
  {cat:"signs",en:"What does a Two-Way Traffic Ahead sign warn about?",it:"Di cosa avvisa un segnale Two-Way Traffic Ahead?",options:[{en:"A lane is being added in your direction",it:"Una corsia viene aggiunta nella tua direzione"},{en:"You are leaving a one-way section and entering two-way traffic -- oncoming vehicles ahead",it:"Stai lasciando una sezione a senso unico ed entrando nel traffico bidirezionale -- veicoli in arrivo in avanti"},{en:"Two trucks are ahead on the road",it:"Due camion sono in avanti sulla strada"},{en:"The road splits into two separate roads",it:"La strada si divide in due strade separate"}],correct:1,explain_en:"Two-Way Traffic Ahead warns that you are transitioning from one-way to two-way traffic. Be prepared for vehicles coming toward you in the opposing lane.",explain_it:"Two-Way Traffic Ahead avvisa che stai passando da traffico a senso unico a bidirezionale."},
  {cat:"signs",en:"What does a Dip warning sign mean?",it:"Cosa significa un segnale di avvertimento Dip?",options:[{en:"A lane narrows ahead",it:"Una corsia si restringe in avanti"},{en:"A low area or depression in the road that could cause vehicles to bottom out",it:"Un'area bassa o depressione nella strada che potrebbe causare l'atterraggio dei veicoli"},{en:"The road dips below sea level",it:"La strada scende sotto il livello del mare"},{en:"A water crossing is ahead",it:"Un attraversamento d'acqua e in avanti"}],correct:1,explain_en:"Dip warns of a sudden dip or low spot in the road. Vehicles with low ground clearance may scrape. Slow down especially if wet.",explain_it:"Dip avvisa di un brusco avvallamento nella strada. I veicoli con bassa altezza da terra potrebbero grattare. Rallenta specialmente se bagnato."},
  {cat:"signs",en:"What does a yellow cattle crossing sign warn about?",it:"Cosa avvisa un segnale giallo di attraversamento bestiame?",options:[{en:"A farm market is ahead",it:"Un mercato agricolo e in avanti"},{en:"Cattle or livestock may be crossing or on the road",it:"Bestiame o animali potrebbero attraversare o essere in strada"},{en:"No animals allowed in this area",it:"Nessun animale consentito in questa zona"},{en:"A veterinary clinic is ahead",it:"Una clinica veterinaria e in avanti"}],correct:1,explain_en:"Cattle crossing signs warn that livestock may be on or crossing the road -- especially in rural areas. Striking an animal at speed is dangerous.",explain_it:"I segnali di attraversamento bestiame avvisano che gli animali potrebbero essere su o attraversare la strada -- specialmente nelle aree rurali."},
  {cat:"laws",en:"What is Florida's law on yielding to a funeral procession?",it:"Qual e la legge Florida sul cedere il diritto di precedenza a un corteo funebre?",options:[{en:"Funeral processions have no special right of way",it:"I cortei funebri non hanno alcun diritto di precedenza speciale"},{en:"Drivers must yield to funeral processions -- do not cut into or interfere with the procession",it:"I conducenti devono cedere il diritto di precedenza ai cortei funebri -- non tagliare o interferire con il corteo"},{en:"Only yield at intersections",it:"Cedere solo agli incroci"},{en:"Yield only if the lead vehicle has a flag",it:"Cedere solo se il veicolo di testa ha una bandiera"}],correct:1,explain_en:"Florida law requires drivers to yield to funeral processions. Do not cut into the procession or pass it. Procession vehicles may proceed through red lights as a group.",explain_it:"La legge Florida richiede ai conducenti di cedere il diritto di precedenza ai cortei funebri."},
  {cat:"laws",en:"What is Florida's law on cell phone use while driving in a school zone?",it:"Qual e la legge Florida sull'uso del cellulare durante la guida in una zona scolastica?",options:[{en:"Cell phone use is permitted if hands-free",it:"L'uso del cellulare e consentito se in modalita mani libere"},{en:"Handheld cell phone use is prohibited in school and work zones -- a primary offense",it:"L'uso del cellulare tenuto in mano e vietato nelle zone scolastiche e di lavoro -- una violazione primaria"},{en:"No special rules in school zones",it:"Nessuna regola speciale nelle zone scolastiche"},{en:"Texting is banned but calling is permitted",it:"Gli SMS sono vietati ma le chiamate sono consentite"}],correct:1,explain_en:"Florida's handheld phone ban is a PRIMARY offense in school and active work zones -- officers can pull you over just for holding your phone while driving.",explain_it:"Il divieto di telefono tenuto in mano in Florida e una violazione PRIMARIA nelle zone scolastiche e di lavoro attive."},
  {cat:"laws",en:"What is the Florida law about parking next to a fire hydrant?",it:"Qual e la legge Florida sul parcheggio accanto a un idrante antincendio?",options:[{en:"Legal for up to 15 minutes",it:"Legale fino a 15 minuti"},{en:"No parking within 15 feet of a fire hydrant at any time",it:"Nessun parcheggio entro 15 piedi da un idrante antincendio in qualsiasi momento"},{en:"No parking within 5 feet",it:"Nessun parcheggio entro 5 piedi"},{en:"Legal if hazard lights are on",it:"Legale se le luci di pericolo sono accese"}],correct:1,explain_en:"Florida prohibits parking within 15 feet of a fire hydrant at any time. This clearance ensures fire trucks can access hydrants quickly in an emergency.",explain_it:"La Florida vieta il parcheggio entro 15 piedi da un idrante antincendio in qualsiasi momento."},
  {cat:"laws",en:"What must you signal at least how many feet before turning on a regular road in Florida?",it:"Di quanti piedi prima devi segnalare su una strada normale in Florida?",options:[{en:"50 feet",it:"50 piedi"},{en:"100 feet",it:"100 piedi"},{en:"200 feet",it:"200 piedi"},{en:"300 feet",it:"300 piedi"}],correct:1,explain_en:"Florida requires turn signal use at least 100 feet before turning on regular roads, and 200 feet on limited-access highways.",explain_it:"La Florida richiede l'uso del segnale di svolta almeno 100 piedi prima di svoltare sulle strade normali e 200 piedi sulle autostrade."},
  {cat:"laws",en:"What is Florida's law about texting and driving?",it:"Qual e la legge Florida sugli SMS e la guida?",options:[{en:"Texting is legal at red lights",it:"Gli SMS sono legali ai semafori rossi"},{en:"Texting while driving is a primary offense -- officers can stop you solely for texting",it:"Gli SMS durante la guida sono una violazione primaria -- gli agenti possono fermarti solo per gli SMS"},{en:"Texting is a secondary offense",it:"Gli SMS sono una violazione secondaria"},{en:"Only prohibited for drivers under 18",it:"Vietato solo per i conducenti under 18"}],correct:1,explain_en:"As of July 2019, texting while driving is a PRIMARY offense in Florida. Applies to all drivers at all times.",explain_it:"A partire da luglio 2019, gli SMS durante la guida sono una violazione PRIMARIA in Florida."},
  {cat:"laws",en:"What does Florida Move Over Law require when passing a disabled vehicle with hazard lights?",it:"Cosa richiede la Florida Move Over Law quando si supera un veicolo in avaria con luci di pericolo?",options:[{en:"No special requirement for disabled vehicles",it:"Nessun requisito speciale per i veicoli in avaria"},{en:"Move over a lane if possible or reduce speed 20 mph below the posted limit",it:"Sposta una corsia se possibile o riduci la velocita di 20 mph sotto il limite segnalato"},{en:"Only applies to emergency vehicles",it:"Si applica solo ai veicoli di emergenza"},{en:"Slow to 25 mph and proceed",it:"Rallenta a 25 mph e procedi"}],correct:1,explain_en:"Florida's Move Over law includes disabled vehicles with hazard lights: move over a lane if safe, or reduce speed 20 mph below the posted limit.",explain_it:"La legge Move Over della Florida include i veicoli in avaria con luci di pericolo: sposta una corsia se sicuro, o riduci la velocita di 20 mph."},
  {cat:"laws",en:"What is the Florida law about leaving a child alone in a parked vehicle?",it:"Qual e la legge Florida sul lasciare un bambino da solo in un veicolo parcheggiato?",options:[{en:"Legal if the vehicle is in shade and windows are cracked",it:"Legale se il veicolo e in ombra e i finestrini sono aperti a fessura"},{en:"Illegal to leave a child under 6 alone for more than 15 minutes or in a hot vehicle",it:"Illegale lasciare un bambino sotto i 6 anni da solo per piu di 15 minuti o in un veicolo caldo"},{en:"Legal if a 12-year-old sibling is present",it:"Legale se e presente un fratello di 12 anni"},{en:"Only illegal if the engine is running",it:"Illegale solo se il motore e acceso"}],correct:1,explain_en:"Florida prohibits leaving a child under 6 alone in a vehicle for more than 15 minutes, or in dangerous heat conditions.",explain_it:"La Florida vieta di lasciare un bambino sotto i 6 anni da solo in un veicolo per piu di 15 minuti, o in condizioni di calore pericolose."},
  {cat:"laws",en:"What is Florida's law about right of way at an uncontrolled intersection?",it:"Qual e la legge Florida sulla precedenza a un incrocio non controllato?",options:[{en:"Larger vehicles always have the right of way",it:"I veicoli piu grandi hanno sempre la precedenza"},{en:"Yield to vehicles that arrived first or are on your right when arriving simultaneously",it:"Cedi ai veicoli arrivati prima o che sono alla tua destra quando si arriva contemporaneamente"},{en:"The faster vehicle has the right of way",it:"Il veicolo piu veloce ha la precedenza"},{en:"Whoever is on the main road has priority",it:"Chi e sulla strada principale ha la priorita"}],correct:1,explain_en:"At uncontrolled intersections: yield to vehicles that arrived before you. When arriving simultaneously, yield to the vehicle on your right. Always proceed cautiously.",explain_it:"Agli incroci non controllati: cedi ai veicoli arrivati prima di te. Quando si arriva contemporaneamente, cedi al veicolo alla tua destra."},
  {cat:"laws",en:"What is Florida's law on speeding in a work zone when workers are present?",it:"Qual e la legge Florida sull'eccesso di velocita in una zona di lavoro quando i lavoratori sono presenti?",options:[{en:"Same penalties as regular speeding",it:"Stesse sanzioni della normale velocita eccessiva"},{en:"Fines are doubled in active work zones with workers present",it:"Le multe sono raddoppiate nelle zone di lavoro attive con lavoratori presenti"},{en:"Only a warning for the first offense",it:"Solo un avvertimento per la prima infrazione"},{en:"Fines are tripled",it:"Le multe sono triplicate"}],correct:1,explain_en:"Florida work zone speeding fines are doubled when workers are present. Aggressive driving in work zones can result in additional charges.",explain_it:"Le multe per eccesso di velocita in zona di lavoro in Florida sono raddoppiate quando i lavoratori sono presenti."},
  {cat:"laws",en:"What is the Florida law about passing in a no-passing zone?",it:"Qual e la legge Florida sul sorpasso in una zona di divieto di sorpasso?",options:[{en:"Legal if the road is clear",it:"Legale se la strada e libera"},{en:"Illegal and a moving violation -- no-passing zones exist for safety reasons",it:"Illegale e una violazione in movimento -- le zone di divieto esistono per ragioni di sicurezza"},{en:"Legal only for motorcycles",it:"Legale solo per le moto"},{en:"Legal if the slow vehicle travels more than 10 mph under the limit",it:"Legale se il veicolo lento va a piu di 10 mph sotto il limite"}],correct:1,explain_en:"Passing in a no-passing zone is a moving violation in Florida. Violations can result in fines and points.",explain_it:"Il sorpasso in una zona di divieto di sorpasso e una violazione in movimento in Florida."},
  {cat:"laws",en:"What is Florida's law about stopping on railroad tracks?",it:"Qual e la legge Florida sul fermarsi sui binari del treno?",options:[{en:"Legal if your vehicle breaks down there",it:"Legale se il tuo veicolo si guasta li"},{en:"Never stop on railroad tracks -- wait before the tracks until you can clear them completely",it:"Non fermarsi mai sui binari del treno -- aspetta prima dei binari fino a poterli liberare completamente"},{en:"Legal to stop briefly if a train is not visible",it:"Legale fermarsi brevemente se un treno non e visibile"},{en:"Only prohibited when signals are active",it:"Vietato solo quando i segnali sono attivi"}],correct:1,explain_en:"Never stop on railroad tracks. Before crossing, ensure you can clear completely. If stuck on tracks, exit immediately and move away.",explain_it:"Non fermarsi mai sui binari del treno. Prima di attraversare, assicurati di poter liberare completamente."},
  {cat:"laws",en:"What is the Florida law about yielding when merging onto a highway?",it:"Qual e la legge Florida sul cedere quando si confluisce in autostrada?",options:[{en:"Highway traffic must move over for merging vehicles",it:"Il traffico autostradale deve spostarsi per i veicoli che confluiscono"},{en:"Merging vehicles must yield to highway traffic and match speed before merging",it:"I veicoli che confluiscono devono cedere al traffico autostradale e adeguare la velocita prima di confluire"},{en:"Both vehicles share equal responsibility",it:"Entrambi i veicoli condividono pari responsabilita"},{en:"Whoever is in the lane first has priority",it:"Chi e nella corsia per primo ha la priorita"}],correct:1,explain_en:"When merging onto a highway, you must yield to existing traffic. Use the acceleration lane to match highway speed, then merge when a safe gap appears.",explain_it:"Quando si confluisce in autostrada, devi cedere al traffico esistente. Usa la corsia di accelerazione per adeguare la velocita."},
  {cat:"laws",en:"What is Florida's rule about passing on hills and curves?",it:"Qual e la regola Florida sul sorpasso in collina e nelle curve?",options:[{en:"Passing is permitted on hills if you can see over the crest",it:"Il sorpasso e consentito in collina se puoi vedere oltre la cresta"},{en:"Passing is prohibited where you cannot see far enough ahead to pass safely",it:"Il sorpasso e vietato dove non si puo vedere abbastanza avanti per sorpassare in sicurezza"},{en:"Hills and curves have no special passing restrictions",it:"Colline e curve non hanno restrizioni speciali di sorpasso"},{en:"Curves are safe for passing if the road is wide enough",it:"Le curve sono sicure per il sorpasso se la strada e abbastanza larga"}],correct:1,explain_en:"Never pass on a hill or curve where you cannot see far enough ahead. Head-on collisions at these locations are often fatal.",explain_it:"Non sorpassare mai su una collina o curva dove non puoi vedere abbastanza avanti."},
  {cat:"laws",en:"What is the Florida law on littering from a vehicle?",it:"Qual e la legge Florida sui rifiuti gettati da un veicolo?",options:[{en:"Legal if items are biodegradable",it:"Legale se gli oggetti sono biodegradabili"},{en:"Illegal -- fines up to $1,000 plus mandatory community service for first offense",it:"Illegale -- multe fino a $1.000 piu servizio alla comunita obbligatorio per la prima infrazione"},{en:"Only illegal on interstate highways",it:"Illegale solo sulle autostrade interstatali"},{en:"A warning for first offense only",it:"Solo un avvertimento per la prima infrazione"}],correct:1,explain_en:"Florida anti-litter law: first offense up to $1,000 fine and 8 hours community service. Repeat offenses increase significantly.",explain_it:"Legge anti-rifiuti della Florida: prima infrazione fino a $1.000 di multa e 8 ore di servizio alla comunita."},
  {cat:"laws",en:"What is the Florida headlight requirement -- when must they be on?",it:"Qual e il requisito fari Florida -- quando devono essere accesi?",options:[{en:"Only at night",it:"Solo di notte"},{en:"Sunset to sunrise, in rain with wipers on, and when visibility is less than 1,000 feet",it:"Dal tramonto all'alba, in caso di pioggia con tergicristalli accesi e quando la visibilita e inferiore a 1.000 piedi"},{en:"Only when driving on highways",it:"Solo quando si guida in autostrada"},{en:"From dusk to dawn only",it:"Solo dal crepuscolo all'alba"}],correct:1,explain_en:"Florida headlight requirements: sunset to sunrise, when wipers are running due to weather, and when visibility is under 1,000 feet (fog, smoke, rain).",explain_it:"Requisiti fari Florida: dal tramonto all'alba, quando i tergicristalli funzionano a causa del meteo e quando la visibilita e inferiore a 1.000 piedi."},
  {cat:"laws",en:"What is Florida's law about double-parking?",it:"Qual e la legge Florida sul doppio parcheggio?",options:[{en:"Legal for deliveries under 5 minutes",it:"Legale per le consegne sotto i 5 minuti"},{en:"Prohibited -- parking in a traffic lane alongside parked vehicles is illegal",it:"Vietato -- parcheggiare in una corsia di traffico accanto ai veicoli parcheggiati e illegale"},{en:"Legal if hazard lights are on",it:"Legale se le luci di pericolo sono accese"},{en:"Legal only in commercial zones",it:"Legale solo nelle zone commerciali"}],correct:1,explain_en:"Double-parking is illegal in Florida. It creates traffic hazards and blocks emergency vehicle access.",explain_it:"Il doppio parcheggio e illegale in Florida. Crea pericoli per il traffico e blocca l'accesso dei veicoli di emergenza."},
  {cat:"laws",en:"What is the Florida law about parking in a bicycle lane?",it:"Qual e la legge Florida sul parcheggio in una corsia ciclabile?",options:[{en:"Permitted for up to 10 minutes",it:"Consentito fino a 10 minuti"},{en:"Prohibited -- bicycle lanes must be kept clear of parked vehicles",it:"Vietato -- le corsie ciclabili devono essere libere dai veicoli parcheggiati"},{en:"Permitted if hazard lights are on",it:"Consentito se le luci di pericolo sono accese"},{en:"Permitted for passenger drop-off only",it:"Consentito solo per lo scarico dei passeggeri"}],correct:1,explain_en:"Parking in a bicycle lane is prohibited in Florida. Cyclists depend on these lanes for safe travel.",explain_it:"Il parcheggio in una corsia ciclabile e vietato in Florida. I ciclisti dipendono da queste corsie per viaggiare in sicurezza."},
  {cat:"laws",en:"What is Florida's basic rule about right of way -- can you ever insist on it?",it:"Qual e la regola di base della Florida sul diritto di precedenza?",options:[{en:"Right of way is an absolute legal right",it:"Il diritto di precedenza e un diritto legale assoluto"},{en:"You must yield even if you have the right of way if it is necessary to prevent a crash",it:"Devi cedere anche se hai la precedenza se e necessario per prevenire un incidente"},{en:"Whoever is in the intersection first always has right of way",it:"Chi e nell'incrocio per primo ha sempre la precedenza"},{en:"Right of way only applies at controlled intersections",it:"Il diritto di precedenza si applica solo agli incroci controllati"}],correct:1,explain_en:"Right-of-way laws establish who yields to whom, but you must always yield if necessary to prevent a crash -- even if you have the legal right of way.",explain_it:"Le leggi sulla precedenza stabiliscono chi cede a chi, ma devi sempre cedere se necessario per prevenire un incidente."},
  {cat:"laws",en:"What is the Florida law about passing on the right?",it:"Qual e la legge Florida sul sorpasso a destra?",options:[{en:"Always illegal -- must pass on the left only",it:"Sempre illegale -- deve sorpassare solo a sinistra"},{en:"Permitted when the vehicle ahead is making a left turn or on a multi-lane road",it:"Consentito quando il veicolo davanti svolta a sinistra o su una strada a piu corsie"},{en:"Permitted at all times on highways",it:"Consentito in qualsiasi momento in autostrada"},{en:"Only if the vehicle ahead is 20 mph below the limit",it:"Solo se il veicolo davanti e a 20 mph sotto il limite"}],correct:1,explain_en:"Passing on the right is permitted in Florida when the vehicle ahead is turning left and you can pass safely, or on roads with multiple lanes in the same direction.",explain_it:"Il sorpasso a destra e consentito in Florida quando il veicolo davanti svolta a sinistra e puoi sorpassare in sicurezza, o su strade a piu corsie."},
  {cat:"laws",en:"What is Florida's law about unsecured cargo?",it:"Qual e la legge Florida sul carico non assicurato?",options:[{en:"Legal if cargo does not extend beyond the truck bed",it:"Legale se il carico non si estende oltre il cassone del camion"},{en:"Illegal -- operators are responsible for securing loads; spilled cargo can result in serious charges",it:"Illegale -- gli operatori sono responsabili dell'assicurazione dei carichi; il carico caduto puo comportare gravi accuse"},{en:"Only regulated for commercial vehicles",it:"Regolamentato solo per i veicoli commerciali"},{en:"Legal if speed is under 45 mph",it:"Legale se la velocita e inferiore a 45 mph"}],correct:1,explain_en:"Unsecured loads are illegal in Florida. If cargo falls and causes injury, the driver faces serious criminal charges.",explain_it:"I carichi non assicurati sono illegali in Florida. Se il carico cade e causa lesioni, il conducente affronta gravi accuse penali."},
  {cat:"laws",en:"What is Florida's law on yielding to a blind pedestrian with a white cane?",it:"Qual e la legge Florida sul cedere il diritto di precedenza a un pedone cieco con un bastone bianco?",options:[{en:"Yield only at crosswalks",it:"Cedere solo agli attraversamenti pedonali"},{en:"All vehicles must yield to a pedestrian carrying a white cane or using a guide dog at any location",it:"Tutti i veicoli devono cedere il diritto di precedenza a un pedone con un bastone bianco o un cane guida in qualsiasi luogo"},{en:"Yield only if they are in the crosswalk",it:"Cedere solo se sono nell'attraversamento"},{en:"Yield only if they have started crossing",it:"Cedere solo se hanno iniziato ad attraversare"}],correct:1,explain_en:"Florida law: all drivers must yield to pedestrians using white canes or guide dogs at all locations -- not just crosswalks.",explain_it:"Legge Florida: tutti i conducenti devono cedere il diritto di precedenza ai pedoni che usano bastoni bianchi o cani guida in qualsiasi luogo."},
  {cat:"laws",en:"What happens in Florida if the other driver in a crash has no insurance?",it:"Cosa succede in Florida se l'altro conducente in un incidente non ha assicurazione?",options:[{en:"You can sue them directly",it:"Puoi citarli direttamente"},{en:"Your own Uninsured Motorist coverage pays if you have it; PIP covers medical regardless",it:"La tua copertura per automobilisti non assicurati paga se ce l'hai; il PIP copre le spese mediche indipendentemente"},{en:"The state pays for damages",it:"Lo stato paga per i danni"},{en:"Your auto insurance never covers uninsured drivers",it:"La tua assicurazione auto non copre mai i conducenti non assicurati"}],correct:1,explain_en:"Your PIP covers medical bills regardless of fault. Uninsured Motorist (UM) coverage covers injuries caused by uninsured or underinsured drivers.",explain_it:"Il tuo PIP copre le spese mediche indipendentemente dalla colpa. La copertura UM copre le lesioni causate da conducenti non assicurati."},
  {cat:"laws",en:"What is the Florida law about parking near a stop sign?",it:"Qual e la legge Florida sul parcheggio vicino a un segnale di stop?",options:[{en:"No parking within 10 feet",it:"Nessun parcheggio entro 10 piedi"},{en:"No parking within 30 feet of a stop sign",it:"Nessun parcheggio entro 30 piedi da un segnale di stop"},{en:"Parking is legal next to stop signs unless posted otherwise",it:"Il parcheggio e legale vicino ai segnali di stop se non diversamente segnalato"},{en:"No parking within 50 feet of any intersection",it:"Nessun parcheggio entro 50 piedi da qualsiasi incrocio"}],correct:1,explain_en:"Florida prohibits parking within 30 feet of a stop sign -- keeping the sign visible and maintaining sight lines.",explain_it:"La Florida vieta il parcheggio entro 30 piedi da un segnale di stop."},
  {cat:"safety",en:"What is the recommended technique for driving in heavy fog?",it:"Qual e la tecnica raccomandata per guidare nella nebbia densa?",options:[{en:"Use high beams to see farther",it:"Usa gli abbaglianti per vedere piu lontano"},{en:"Use low beams or fog lights, slow down significantly, increase following distance",it:"Usa i fendinebbia o i fari anabbaglianti, rallenta significativamente, aumenta la distanza di seguimento"},{en:"Turn on hazard lights and maintain normal speed",it:"Accendi le luci di pericolo e mantieni la velocita normale"},{en:"Follow the taillights of the vehicle ahead closely",it:"Segui da vicino i fari posteriori del veicolo davanti"}],correct:1,explain_en:"In fog: use LOW beams (high beams reflect off fog), reduce speed, increase following distance. Never use hazard lights while moving.",explain_it:"Nella nebbia: usa i fari ANABBAGLIANTI (gli abbaglianti riflettono la nebbia), riduci la velocita, aumenta la distanza di seguimento."},
  {cat:"safety",en:"What is the correct response when you experience a front tire blowout?",it:"Qual e la risposta corretta quando si verifica uno scoppio del pneumatico anteriore?",options:[{en:"Brake hard and steer straight",it:"Frena forte e stai dritto"},{en:"Grip the wheel firmly, ease off the gas gradually, steer straight, and gently guide to the shoulder",it:"Tieni il volante fermamente, allontana gradualmente il piede dall'acceleratore, stai dritto e guida delicatamente verso la banchina"},{en:"Turn sharply in the direction the car pulls",it:"Gira bruscamente nella direzione in cui l'auto tira"},{en:"Accelerate briefly to maintain stability",it:"Accelera brevemente per mantenere la stabilita"}],correct:1,explain_en:"Front blowout: grip firmly, do NOT brake suddenly, ease off gas, steer straight, let speed reduce naturally, then steer gently to the shoulder.",explain_it:"Scoppio anteriore: tieni fermamente, NON frenare improvvisamente, allontana il piede dall'acceleratore, stai dritto, lascia che la velocita si riduca naturalmente."},
  {cat:"safety",en:"What is black ice and why is it particularly dangerous?",it:"Cos'e il ghiaccio nero e perche e particolarmente pericoloso?",options:[{en:"Ice that forms only at night",it:"Ghiaccio che si forma solo di notte"},{en:"A thin transparent layer of ice that looks like wet pavement -- nearly invisible and very slick",it:"Un sottile strato trasparente di ghiaccio che sembra asfalto bagnato -- quasi invisibile e molto scivoloso"},{en:"Black-colored road markings that become slippery when wet",it:"Marcature stradali di colore nero che diventano scivolose quando bagnate"},{en:"Ice only found on bridges",it:"Ghiaccio trovato solo sui ponti"}],correct:1,explain_en:"Black ice is thin, transparent ice that blends with the road surface. It is invisible to drivers and has almost zero traction. Most common on bridges and shaded areas.",explain_it:"Il ghiaccio nero e ghiaccio sottile e trasparente che si fonde con la superficie stradale. E invisibile ai conducenti e ha quasi zero aderenza."},
  {cat:"safety",en:"What is the correct way to brake on a slippery road with anti-lock brakes (ABS)?",it:"Qual e il modo corretto di frenare su una strada scivolosa con freni antibloccaggio ABS?",options:[{en:"Pump the brakes rapidly",it:"Pompare i freni rapidamente"},{en:"Apply firm steady pressure -- let the ABS do the pulsing; steer while braking",it:"Applica una pressione costante e ferma -- lascia che l'ABS faccia il pulsare; sterzare mentre si frena"},{en:"Apply light gentle pressure only",it:"Applica solo una pressione leggera"},{en:"Use the parking brake to supplement ABS",it:"Usa il freno a mano per integrare l'ABS"}],correct:1,explain_en:"With ABS: press and HOLD the brake pedal firmly. The system pulses automatically to prevent lockup. You can steer while braking hard.",explain_it:"Con l'ABS: premi e TIENI premuto il pedale del freno con forza. Il sistema pulsa automaticamente per prevenire il bloccaggio. Puoi sterzare mentre freni forte."},
  {cat:"safety",en:"What is hydroplaning and how do you avoid it?",it:"Cos'e l'aquaplaning e come evitarlo?",options:[{en:"When your car engine overheats in water",it:"Quando il motore della tua auto si surriscalda nell'acqua"},{en:"When a layer of water between tires and road causes loss of traction -- avoid by reducing speed in rain",it:"Quando uno strato d'acqua tra gli pneumatici e la strada causa la perdita di aderenza -- evitalo riducendo la velocita in caso di pioggia"},{en:"When windshield wipers cannot keep up with rain",it:"Quando i tergicristalli non riescono a tenere il passo con la pioggia"},{en:"When brakes lock up in standing water",it:"Quando i freni si bloccano nell'acqua stagnante"}],correct:1,explain_en:"Hydroplaning: water builds up faster than tires can displace it, lifting tires off the pavement. Avoid by reducing speed in rain and maintaining proper tire pressure and tread.",explain_it:"Aquaplaning: l'acqua si accumula piu velocemente di quanto gli pneumatici possano spostarla. Evita riducendo la velocita in caso di pioggia."},
  {cat:"safety",en:"What should you do if you experience hydroplaning?",it:"Cosa dovresti fare se sperimenti l'aquaplaning?",options:[{en:"Brake hard to stop quickly",it:"Frena forte per fermarti rapidamente"},{en:"Ease off the gas, hold the wheel straight, do not brake hard -- let the car slow naturally",it:"Allontana il piede dall'acceleratore, tieni il volante dritto, non frenare forte -- lascia che l'auto rallenti naturalmente"},{en:"Turn the wheel sharply to regain grip",it:"Gira bruscamente il volante per recuperare la presa"},{en:"Accelerate briefly to push through the water",it:"Accelera brevemente per spingere attraverso l'acqua"}],correct:1,explain_en:"If hydroplaning: gently ease off the gas, do NOT brake hard, keep steering straight, and let the car slow down naturally until tires regain contact.",explain_it:"Se in aquaplaning: allontana delicatamente il piede dall'acceleratore, NON frenare forte, tieni il volante dritto e lascia che l'auto rallenti naturalmente."},
  {cat:"safety",en:"What is the purpose of rumble strips on the highway shoulder?",it:"Qual e lo scopo delle strisce vibranti sulla banchina dell'autostrada?",options:[{en:"To slow down vehicles entering the highway",it:"Per rallentare i veicoli che entrano in autostrada"},{en:"To alert drowsy drivers who drift off the road with noise and vibration",it:"Per avvisare i conducenti assonnati che derivano fuori dalla strada con rumore e vibrazione"},{en:"To prevent flooding on the shoulder",it:"Per prevenire le inondazioni sulla banchina"},{en:"To mark the beginning of a construction zone",it:"Per segnare l'inizio di una zona di costruzione"}],correct:1,explain_en:"Shoulder rumble strips alert drowsy or inattentive drivers who drift off the road. The noise and vibration startle them back to attentiveness.",explain_it:"Le strisce vibranti della banchina avvisano i conducenti assonnati che derivano fuori dalla strada con rumore e vibrazione."},
  {cat:"safety",en:"What is target fixation in driving?",it:"Cos'e la fissazione del bersaglio nella guida?",options:[{en:"Looking too far ahead",it:"Guardare troppo lontano"},{en:"Staring at a hazard causes you to steer toward it -- look where you want to go, not at the obstacle",it:"Fissare un pericolo ti fa sterzare verso di esso -- guarda dove vuoi andare, non verso l'ostacolo"},{en:"Using cruise control on straight roads",it:"Usare il cruise control sulle strade dritte"},{en:"Driving too slowly in traffic",it:"Guidare troppo lentamente nel traffico"}],correct:1,explain_en:"Target fixation: drivers instinctively steer toward where they are looking. If you stare at an obstacle, you may steer into it. Look at your escape path instead.",explain_it:"Fissazione del bersaglio: i conducenti sterzano istintivamente verso dove stanno guardando. Guarda il tuo percorso di fuga invece."},
  {cat:"safety",en:"What is the most dangerous time of day to drive due to sun glare in Florida?",it:"Qual e il momento piu pericoloso della giornata per guidare a causa del riflesso del sole in Florida?",options:[{en:"Noon when the sun is directly overhead",it:"Mezzogiorno quando il sole e direttamente sopra"},{en:"Early morning (sunrise) and late afternoon (sunset) when the sun is low on the horizon",it:"Primo mattino (alba) e tardo pomeriggio (tramonto) quando il sole e basso sull'orizzonte"},{en:"Cloudy days with diffuse light",it:"Giorni nuvolosi con luce diffusa"},{en:"Midnight under a full moon",it:"Mezzanotte con luna piena"}],correct:1,explain_en:"Sun glare is most dangerous at sunrise and sunset when the sun is low and directly in your eyes. Use sun visors and sunglasses.",explain_it:"Il riflesso del sole e piu pericoloso all'alba e al tramonto quando il sole e basso e direttamente nei tuoi occhi."},
  {cat:"safety",en:"What is the safest following distance behind a large truck on a dry highway?",it:"Qual e la distanza di seguimento piu sicura dietro un grande camion su un'autostrada asciutta?",options:[{en:"2 seconds",it:"2 secondi"},{en:"4 seconds or more -- trucks have large blind spots and longer stopping distances",it:"4 secondi o piu -- i camion hanno grandi punti ciechi e distanze di frenata piu lunghe"},{en:"1 car length per 10 mph",it:"1 lunghezza auto per 10 mph"},{en:"Same as following a car",it:"Uguale a seguire un'auto"}],correct:1,explain_en:"Following a large truck requires at least 4 seconds: trucks stop much more slowly than cars, have massive blind spots, and tire blowouts can hit your vehicle.",explain_it:"Seguire un grande camion richiede almeno 4 secondi: i camion si fermano molto piu lentamente delle auto e hanno enormi punti ciechi."},
  {cat:"safety",en:"What is the effect of warm temperatures on tire pressure?",it:"Qual e l'effetto delle temperature calde sulla pressione degli pneumatici?",options:[{en:"Temperature has no effect on tire pressure",it:"La temperatura non ha effetti sulla pressione degli pneumatici"},{en:"Heat increases tire pressure -- check pressure in the morning before driving in Florida summer",it:"Il calore aumenta la pressione degli pneumatici -- controlla la pressione al mattino prima di guidare nell'estate Florida"},{en:"Warm temperatures reduce tire pressure",it:"Le temperature calde riducono la pressione degli pneumatici"},{en:"Tire pressure automatically adjusts to temperature",it:"La pressione degli pneumatici si regola automaticamente alla temperatura"}],correct:1,explain_en:"Tire pressure increases about 1 PSI per 10 degrees F temperature rise. In Florida summer heat, tires can become over-inflated -- check pressure when cool.",explain_it:"La pressione degli pneumatici aumenta di circa 1 PSI per ogni 10 gradi F di aumento della temperatura. Nel caldo estivo della Florida gli pneumatici possono diventare sovra-gonfiati."},
  {cat:"safety",en:"How should you adjust your driving when large trucks are nearby on the highway?",it:"Come dovresti adattare la guida quando ci sono grandi camion nelle vicinanze in autostrada?",options:[{en:"Drive close behind them to reduce wind resistance",it:"Guida vicino dietro di loro per ridurre la resistenza al vento"},{en:"Give extra space, avoid their blind spots, never cut in front, and anticipate their wide turns",it:"Dai spazio extra, evita i loro punti ciechi, non tagliare mai davanti e anticipa le loro ampie svolte"},{en:"Pass them as quickly as possible",it:"Sorpassali il piu velocemente possibile"},{en:"Stay in their blind spot for protection from wind",it:"Rimani nel loro punto cieco per proteggersi dal vento"}],correct:1,explain_en:"Around large trucks: avoid their four blind spots (No-Zones), give extra following distance, do not cut in front, and anticipate wide right turns.",explain_it:"Intorno ai grandi camion: evita i loro quattro punti ciechi, dai una distanza di seguimento extra, non tagliare mai davanti e anticipa le ampie svolte a destra."},
  {cat:"safety",en:"What is the Florida law about passengers riding in the bed of a pickup truck?",it:"Qual e la legge Florida sui passeggeri che viaggiano nel cassone di un pickup?",options:[{en:"Always legal for adults",it:"Sempre legale per gli adulti"},{en:"Passengers under 18 are prohibited from riding in an open truck bed",it:"Ai passeggeri under 18 e vietato viaggiare in un cassone del camion aperto"},{en:"Prohibited for all passengers at all times",it:"Vietato per tutti i passeggeri in qualsiasi momento"},{en:"Legal only on private property",it:"Legale solo su proprieta privata"}],correct:1,explain_en:"Florida prohibits persons under 18 from riding in the uncovered bed of a pickup truck on public roads.",explain_it:"La Florida vieta alle persone under 18 di viaggiare nel cassone scoperto di un pickup sulle strade pubbliche."},
  {cat:"alcohol",en:"What is the Florida law on purchasing alcohol for a minor?",it:"Qual e la legge Florida sull'acquisto di alcol per un minore?",options:[{en:"Legal if a parent is present",it:"Legale se e presente un genitore"},{en:"A criminal offense -- providing alcohol to minors is illegal regardless of circumstances",it:"Un reato penale -- fornire alcol ai minori e illegale indipendentemente dalle circostanze"},{en:"Legal if the minor is 17 and accompanied by an adult",it:"Legale se il minore ha 17 anni ed e accompagnato da un adulto"},{en:"Only illegal if the minor becomes intoxicated",it:"Illegale solo se il minore diventa ubriaco"}],correct:1,explain_en:"Providing alcohol to a person under 21 in Florida is a criminal offense -- second-degree misdemeanor (or first-degree if harm results).",explain_it:"Fornire alcol a una persona under 21 in Florida e un reato penale -- infrazione di secondo grado."},
  {cat:"alcohol",en:"What is the standard drink equivalence?",it:"Qual e l'equivalenza della bevanda standard?",options:[{en:"A 12 oz beer has more alcohol than a 1.5 oz shot",it:"Una birra da 12 once ha piu alcol di un bicchierino da 1,5 once"},{en:"A 12 oz regular beer, 5 oz wine, and 1.5 oz spirits each contain approximately the same alcohol",it:"Una birra normale da 12 once, 5 once di vino e 1,5 once di superalcolici contengono ciascuno approssimativamente la stessa quantita di alcol"},{en:"Wine has twice the alcohol of beer",it:"Il vino ha il doppio dell'alcol della birra"},{en:"Spirits are 4x stronger than beer by volume",it:"I superalcolici sono 4 volte piu forti della birra per volume"}],correct:1,explain_en:"One standard drink: 12 oz regular beer (5% ABV), 5 oz wine (12% ABV), or 1.5 oz spirits (40% ABV) all contain about 0.6 oz of pure alcohol.",explain_it:"Una bevanda standard: 12 once di birra normale, 5 once di vino o 1,5 once di superalcolici contengono tutte circa 0,6 once di alcol puro."},
  {cat:"alcohol",en:"How does the liver eliminate alcohol from the body?",it:"Come il fegato elimina l'alcol dall'organismo?",options:[{en:"Faster drinking means faster elimination",it:"Bere piu velocemente significa eliminazione piu veloce"},{en:"The liver eliminates alcohol at a fixed rate of about 0.015% BAC per hour",it:"Il fegato elimina l'alcol a una velocita fissa di circa 0,015% BAC all'ora"},{en:"Exercise speeds up elimination significantly",it:"L'esercizio fisico accelera significativamente l'eliminazione"},{en:"Cold water doubles the elimination rate",it:"L'acqua fredda raddoppia il tasso di eliminazione"}],correct:1,explain_en:"The liver metabolizes alcohol at about 0.015% BAC/hour -- a fixed rate. Nothing speeds this up.",explain_it:"Il fegato metabolizza l'alcol a circa 0,015% BAC/ora -- una velocita fissa. Niente accelera questo processo."},
  {cat:"alcohol",en:"What is the effect of alcohol on a driver's night vision?",it:"Qual e l'effetto dell'alcol sulla visione notturna di un conducente?",options:[{en:"Alcohol improves night vision by relaxing the eyes",it:"L'alcol migliora la visione notturna rilassando gli occhi"},{en:"Alcohol reduces the eye's ability to adapt to darkness and recover from glare",it:"L'alcol riduce la capacita dell'occhio di adattarsi all'oscurita e di riprendersi dall'abbagliamento"},{en:"Alcohol has no effect on vision",it:"L'alcol non ha effetti sulla visione"},{en:"Only affects vision above 0.10% BAC",it:"Influisce sulla visione solo sopra 0,10% BAC"}],correct:1,explain_en:"Alcohol reduces night vision: slows dark adaptation, increases glare sensitivity, and reduces peripheral vision.",explain_it:"L'alcol riduce la visione notturna: rallenta l'adattamento all'oscurita, aumenta la sensibilita all'abbagliamento e riduce la visione periferica."},
  {cat:"alcohol",en:"What is the Florida penalty for DUI with property damage?",it:"Qual e la sanzione Florida per DUI con danni materiali?",options:[{en:"Same as standard first-offense DUI",it:"Uguale al DUI standard alla prima infrazione"},{en:"A first-degree misdemeanor with potential jail, fines, and restitution",it:"Un'infrazione di primo grado con potenziale carcere, multe e restituzione"},{en:"A civil matter only",it:"Solo una questione civile"},{en:"A third-degree felony",it:"Un crimine di terzo grado"}],correct:1,explain_en:"DUI with property damage in Florida is a first-degree misdemeanor: up to 1 year jail, up to $1,000 fine, plus mandatory restitution.",explain_it:"DUI con danni materiali in Florida e un'infrazione di primo grado: fino a 1 anno di carcere, fino a $1.000 di multa, piu restituzione obbligatoria."},
  {cat:"alcohol",en:"What is Florida dram shop liability?",it:"Cos'e la responsabilita dram shop in Florida?",options:[{en:"The bartender has no legal responsibility",it:"Il barista non ha responsabilita legale"},{en:"Establishments can be liable for injuries caused by visibly intoxicated patrons they served",it:"I locali possono essere responsabili per le lesioni causate dai clienti visibilmente ubriachi che hanno servito"},{en:"Only illegal to serve if the person is under 21",it:"Illegale da servire solo se la persona ha meno di 21 anni"},{en:"No dram shop liability in Florida",it:"Nessuna responsabilita dram shop in Florida"}],correct:1,explain_en:"Florida dram shop laws: establishments can be liable for injuries caused by visibly intoxicated patrons. Serving obviously drunk people creates legal liability.",explain_it:"Le leggi dram shop della Florida: i locali possono essere responsabili per le lesioni causate dai clienti visibilmente ubriachi."},
  {cat:"alcohol",en:"What is the effect of food on alcohol absorption?",it:"Come influisce il cibo sull'assorbimento dell'alcol?",options:[{en:"Food has no effect on alcohol absorption",it:"Il cibo non ha effetti sull'assorbimento dell'alcol"},{en:"Food slows absorption delaying peak BAC but total alcohol consumed is the same",it:"Il cibo rallenta l'assorbimento ritardando il BAC di picco ma l'alcol totale e lo stesso"},{en:"Food permanently prevents alcohol from entering the bloodstream",it:"Il cibo impedisce permanentemente all'alcol di entrare nel flusso sanguigno"},{en:"High-fat foods neutralize alcohol",it:"Gli alimenti grassi neutralizzano l'alcol"}],correct:1,explain_en:"Eating slows the rate of alcohol absorption -- delaying how fast BAC rises. However, the same total alcohol will still be absorbed eventually.",explain_it:"Mangiare rallenta la velocita di assorbimento dell'alcol -- ritardando l'aumento del BAC. Tuttavia lo stesso alcol totale verra comunque assorbito."},
  {cat:"alcohol",en:"What is the Florida underage driver BAC limit?",it:"Qual e il limite BAC per i conducenti minorenni in Florida?",options:[{en:"0.08% same as adults",it:"0,08% uguale agli adulti"},{en:"0.02% -- zero tolerance for under 21",it:"0,02% -- tolleranza zero per under 21"},{en:"0.05%",it:"0,05%"},{en:"Any detectable amount",it:"Qualsiasi quantita rilevabile"}],correct:1,explain_en:"Florida zero tolerance for under 21: BAC of 0.02% or higher triggers an automatic license suspension. This is a near-zero limit.",explain_it:"Tolleranza zero della Florida per under 21: un BAC di 0,02% o superiore attiva una sospensione automatica della patente."},
  {cat:"license",en:"What is the Florida Graduated Driver License GDL program?",it:"Cos'e il programma Florida Graduated Driver License GDL?",options:[{en:"A test taken once at age 16 for a full license",it:"Un test sostenuto una volta all'eta di 16 anni per la patente completa"},{en:"A three-stage licensing system: learner at 15, restricted at 16, full license at 18",it:"Un sistema di patente in tre fasi: permesso a 15, patente con restrizioni a 16, patente completa a 18"},{en:"A program only for DUI offenders under 21",it:"Un programma solo per i trasgressori DUI under 21"},{en:"An optional safety training program for teens",it:"Un programma di formazione sulla sicurezza opzionale per i teenager"}],correct:1,explain_en:"Florida GDL: Stage 1 (Learner's at 15, held 12 months), Stage 2 (Restricted at 16, limited passengers and hours), Stage 3 (Full license at 18).",explain_it:"GDL Florida: Fase 1 (Permesso a 15 anni, tenuto 12 mesi), Fase 2 (Patente con restrizioni a 16 anni), Fase 3 (Patente completa a 18 anni)."},
  {cat:"license",en:"What is the nighttime driving restriction for a Florida provisional license holder (16-17)?",it:"Qual e la restrizione della guida notturna per un titolare di patente provvisoria Florida (16-17)?",options:[{en:"No nighttime driving allowed",it:"Nessuna guida notturna consentita"},{en:"No driving between 11 PM and 6 AM unless accompanied by a licensed adult 21 or older",it:"Nessuna guida tra le 23:00 e le 06:00 se non accompagnati da un adulto patentato di 21 anni o piu"},{en:"No driving after 9 PM",it:"Nessuna guida dopo le 21:00"},{en:"Nighttime driving allowed only within 10 miles of home",it:"Guida notturna consentita solo entro 10 miglia da casa"}],correct:1,explain_en:"Florida provisional license holders (16-17): no driving between 11 PM and 6 AM unless accompanied by a licensed driver 21 or older, or for work/school necessity.",explain_it:"Titolari di patente provvisoria Florida (16-17): nessuna guida tra le 23:00 e le 06:00 se non accompagnati da un conducente patentato di 21 anni o piu."},
  {cat:"license",en:"How many supervised driving hours are required before a Florida teen can get a restricted license?",it:"Quante ore di guida supervisionata sono richieste prima che un adolescente Florida possa ottenere la patente con restrizioni?",options:[{en:"20 hours",it:"20 ore"},{en:"50 hours total including 10 hours at night",it:"50 ore totali incluse 10 ore di notte"},{en:"30 hours total",it:"30 ore totali"},{en:"100 hours",it:"100 ore"}],correct:1,explain_en:"Florida GDL requires 50 hours of supervised driving (including 10 nighttime hours) before a teen can get a restricted license at 16.",explain_it:"Il GDL Florida richiede 50 ore di guida supervisionata (incluse 10 ore notturne) prima che un adolescente possa ottenere la patente con restrizioni a 16 anni."},
  {cat:"license",en:"What is the Florida SR-22 certificate?",it:"Cos'e il certificato Florida SR-22?",options:[{en:"Standard vehicle registration proof",it:"Prova standard di registrazione del veicolo"},{en:"A document filed by your insurer certifying you carry minimum required liability insurance -- required after certain violations",it:"Un documento depositato dalla tua assicurazione che certifica che hai la copertura minima richiesta -- richiesto dopo alcune violazioni"},{en:"The same as FR-44 insurance",it:"Uguale all'assicurazione FR-44"},{en:"A commercial vehicle insurance certificate",it:"Un certificato assicurativo per veicoli commerciali"}],correct:1,explain_en:"SR-22 is a certificate of financial responsibility required after license suspension for violations like driving without insurance. Must be maintained for 3 years.",explain_it:"SR-22 e un certificato di responsabilita finanziaria richiesto dopo la sospensione della patente per violazioni come la guida senza assicurazione."},
  {cat:"license",en:"What is a Florida hardship license and who may apply?",it:"Cos'e una patente hardship Florida e chi puo richiederla?",options:[{en:"A license with no restrictions after a DUI",it:"Una patente senza restrizioni dopo un DUI"},{en:"A limited license allowing driving to work, school, or medical appointments during a suspension",it:"Una patente limitata che consente la guida al lavoro, a scuola o agli appuntamenti medici durante una sospensione"},{en:"A license for elderly drivers with vision impairment",it:"Una patente per i conducenti anziani con problemi di visione"},{en:"A motorcycle-only license",it:"Una patente solo per moto"}],correct:1,explain_en:"A Florida hardship license allows limited driving (work, school, medical, church) during a suspension. Not available for all offenses.",explain_it:"Una patente hardship Florida consente una guida limitata (lavoro, scuola, medico, chiesa) durante una sospensione."},
  {cat:"license",en:"What happens to a Florida license after a second DUI within 5 years?",it:"Cosa succede alla patente Florida dopo un secondo DUI entro 5 anni?",options:[{en:"Same as a first DUI -- 180 day suspension",it:"Uguale al primo DUI -- sospensione di 180 giorni"},{en:"Mandatory 5-year revocation with no hardship license for the first year",it:"Revoca obbligatoria di 5 anni senza patente hardship disponibile per il primo anno"},{en:"90-day suspension only",it:"Solo sospensione di 90 giorni"},{en:"Permanent revocation",it:"Revoca permanente"}],correct:1,explain_en:"Second DUI within 5 years in Florida: mandatory 5-year license revocation. No hardship license for the first year. IID required upon reinstatement.",explain_it:"Secondo DUI entro 5 anni in Florida: revoca obbligatoria della patente di 5 anni. Nessuna patente hardship per il primo anno."},
  {cat:"license",en:"What is the Florida REAL ID requirement?",it:"Qual e il requisito REAL ID della Florida?",options:[{en:"REAL ID is optional and has no practical difference",it:"Il REAL ID e opzionale e non ha differenze pratiche"},{en:"Required for boarding domestic flights and entering federal facilities -- needs extra documentation at DHSMV",it:"Richiesto per i voli nazionali e l'accesso alle strutture federali -- necessita di documentazione extra al DHSMV"},{en:"Only required for commercial drivers",it:"Richiesto solo per i conducenti commerciali"},{en:"REAL ID requires a background check",it:"Il REAL ID richiede un controllo dei precedenti"}],correct:1,explain_en:"REAL ID: required for boarding domestic flights and entering federal buildings. Florida issues REAL ID licenses marked with a gold star -- extra documentation needed.",explain_it:"REAL ID: richiesto per i voli nazionali e l'accesso agli edifici federali. La Florida rilascia patenti REAL ID con una stella d'oro."},
  {cat:"license",en:"What must a new Florida resident do within 30 days of establishing residency?",it:"Cosa deve fare un nuovo residente Florida entro 30 giorni dall'istituzione della residenza?",options:[{en:"They can continue using their out-of-state license indefinitely",it:"Possono continuare a usare la patente di un altro stato indefinitamente"},{en:"Surrender their out-of-state license and apply for a Florida license",it:"Cedere la patente di un altro stato e richiedere la patente Florida"},{en:"Only required after 90 days of residency",it:"Richiesto solo dopo 90 giorni di residenza"},{en:"Required only when the out-of-state license expires",it:"Richiesto solo quando la patente di un altro stato scade"}],correct:1,explain_en:"New Florida residents must obtain a Florida license within 30 days. They must surrender their out-of-state license and provide proof of identity, residency, and SSN.",explain_it:"I nuovi residenti Florida devono ottenere la patente Florida entro 30 giorni. Devono cedere la patente di un altro stato e fornire prova di identita, residenza e SSN."},
  {cat:"license",en:"What is the Florida law about driving with a suspended license?",it:"Qual e la legge Florida sulla guida con una patente sospesa?",options:[{en:"A non-criminal infraction only",it:"Solo un'infrazione non penale"},{en:"First offense: a second-degree misdemeanor. Repeat offenses can escalate to felony",it:"Prima infrazione: un'infrazione di secondo grado. Le infrazioni ripetute possono aggravarsi in crimine"},{en:"Only a fine with no criminal record",it:"Solo una multa senza casellario penale"},{en:"Results only in extension of the suspension",it:"Comporta solo un prolungamento della sospensione"}],correct:1,explain_en:"Driving with a suspended license in Florida: first offense = second-degree misdemeanor (up to 60 days jail). Third offense with knowledge = third-degree felony.",explain_it:"Guidare con patente sospesa in Florida: prima infrazione = infrazione di secondo grado (fino a 60 giorni di carcere)."}
,

  // SESSION 6
  {cat:"signs",en:"What does an orange construction zone sign indicate?",it:"Cosa indica un segnale arancione di zona di costruzione?",options:[{en:"A permanent road hazard",it:"Un pericolo stradale permanente"},{en:"Temporary traffic control in a work zone -- workers and equipment may be present",it:"Controllo temporaneo del traffico in una zona di lavoro"},{en:"Detour required for all vehicles",it:"Deviazione obbligatoria per tutti i veicoli"},{en:"Reduced speed only on weekdays",it:"Velocita ridotta solo nei giorni feriali"}],correct:1,explain_en:"Orange signs indicate temporary traffic control in construction zones. Fines are doubled in these areas.",explain_it:"I segnali arancioni indicano controllo temporaneo del traffico nelle zone di costruzione. Le multe sono raddoppiate."},
  {cat:"signs",en:"What does a green highway sign indicate?",it:"Cosa indica un segnale verde autostradale?",options:[{en:"A warning of a hazard ahead",it:"Un avvertimento di un pericolo"},{en:"Guide information -- distances, destinations, and route numbers",it:"Informazioni guida -- distanze, destinazioni e numeri di percorso"},{en:"A regulatory requirement",it:"Un requisito normativo"},{en:"A service area ahead",it:"Un'area di servizio in avanti"}],correct:1,explain_en:"Green signs provide guide information: route numbers, highway names, exit distances, and destination names.",explain_it:"I segnali verdi forniscono informazioni guida: numeri di percorso, nomi delle autostrade, distanze di uscita."},
  {cat:"signs",en:"What does a blue highway sign indicate?",it:"Cosa indica un segnale blu autostradale?",options:[{en:"A state highway route",it:"Un percorso autostradale statale"},{en:"Services available -- gas, food, lodging, hospitals",it:"Servizi disponibili -- benzina, cibo, alloggio, ospedali"},{en:"Rest area speed limit",it:"Limite di velocita area di sosta"},{en:"A toll plaza ahead",it:"Un casello in avanti"}],correct:1,explain_en:"Blue signs indicate motorist services: gas, restaurants, lodging, hospitals at the next exit.",explain_it:"I segnali blu indicano servizi per automobilisti: benzina, ristoranti, alloggio, ospedali alla prossima uscita."},
  {cat:"signs",en:"What does a brown sign on a highway typically indicate?",it:"Cosa indica tipicamente un segnale marrone in autostrada?",options:[{en:"Construction zone ahead",it:"Zona di costruzione in avanti"},{en:"Recreational areas, parks, historical sites, or scenic routes",it:"Aree ricreative, parchi, siti storici o percorsi panoramici"},{en:"Weight restrictions on the road",it:"Restrizioni di peso"},{en:"Reduced speed for curves",it:"Velocita ridotta per le curve"}],correct:1,explain_en:"Brown signs indicate recreational and cultural interest areas: state parks, national forests, historical monuments, scenic byways.",explain_it:"I segnali marroni indicano aree di interesse ricreativo e culturale: parchi statali, foreste nazionali, monumenti storici."},
  {cat:"signs",en:"What does a 'Wrong Way' sign look like?",it:"Come appare un segnale 'Wrong Way'?",options:[{en:"Yellow diamond with arrows",it:"Rombo giallo con frecce"},{en:"Red rectangle with white WRONG WAY text",it:"Rettangolo rosso con testo bianco WRONG WAY"},{en:"White rectangle with black text",it:"Rettangolo bianco con testo nero"},{en:"Orange diamond with a car symbol",it:"Rombo arancione con simbolo auto"}],correct:1,explain_en:"Wrong Way signs are red rectangles with white text. Placed where drivers may enter going the wrong direction.",explain_it:"I segnali Wrong Way sono rettangoli rossi con testo bianco. Posizionati dove i conducenti possono entrare nella direzione sbagliata."},
  {cat:"signs",en:"What does a 'Do Not Enter' sign look like?",it:"Come appare un segnale 'Do Not Enter'?",options:[{en:"Red circle with white horizontal bar",it:"Cerchio rosso con barra orizzontale bianca"},{en:"Yellow diamond with an X",it:"Rombo giallo con una X"},{en:"White octagon with red text",it:"Ottagono bianco con testo rosso"},{en:"Orange rectangle with black text",it:"Rettangolo arancione con testo nero"}],correct:0,explain_en:"Do Not Enter is a red circle with a white horizontal bar. Prohibits entry at one-way streets and highway exit ramps.",explain_it:"Do Not Enter e un cerchio rosso con una barra orizzontale bianca. Vieta l'ingresso alle strade a senso unico e alle rampe di uscita."},
  {cat:"signs",en:"What is the shape of a railroad advance warning sign?",it:"Qual e la forma di un segnale di avvertimento anticipato ferroviario?",options:[{en:"Square yellow",it:"Quadrato giallo"},{en:"Round yellow with a black X and RR",it:"Rotondo giallo con una X nera e RR"},{en:"Diamond yellow with a train symbol",it:"Rombo giallo con simbolo di treno"},{en:"Red octagon",it:"Ottagono rosso"}],correct:1,explain_en:"The railroad advance warning sign is round and yellow with a black X and the letters RR. It warns that a railroad crossing is ahead.",explain_it:"Il segnale di avvertimento ferroviario anticipato e rotondo e giallo con una X nera e le lettere RR. Avvisa che un passaggio a livello e in avanti."},
  {cat:"signs",en:"What does a 'Lane Ends' sign mean?",it:"Cosa significa un segnale 'Lane Ends'?",options:[{en:"You must exit here",it:"Devi uscire qui"},{en:"Your lane ends ahead -- merge with adjacent traffic",it:"La tua corsia finisce -- confluisci con il traffico adiacente"},{en:"The highway ends",it:"L'autostrada finisce"},{en:"Right turn only from this lane",it:"Solo svolta destra da questa corsia"}],correct:1,explain_en:"Lane Ends means the lane you are in will end and you must merge into the adjacent lane.",explain_it:"Lane Ends significa che la corsia in cui ti trovi finira e devi confluire nella corsia adiacente."},
  {cat:"signs",en:"What does 'MINIMUM' under a speed limit number mean?",it:"Cosa significa 'MINIMUM' sotto un numero di limite di velocita?",options:[{en:"You must not exceed this speed",it:"Non devi superare questa velocita"},{en:"You must not drive slower than this speed except when necessary for safety",it:"Non devi guidare piu lentamente di questa velocita tranne per sicurezza"},{en:"Advisory speed for curves only",it:"Velocita consigliata solo per le curve"},{en:"School zone minimum",it:"Minimo zona scolastica"}],correct:1,explain_en:"Minimum speed signs set a legal lower limit. Driving below the posted minimum impedes traffic and is a violation.",explain_it:"I segnali di velocita minima stabiliscono un limite inferiore legale. Guidare sotto il minimo ostacola il traffico."},
  {cat:"signs",en:"What does a white diamond in a lane on the road mean?",it:"Cosa significa un rombo bianco in una corsia sulla strada?",options:[{en:"Passing allowed in this lane",it:"Sorpasso consentito in questa corsia"},{en:"A High Occupancy Vehicle (HOV) or carpool lane",it:"Una corsia HOV (carpool)"},{en:"Bicycles only",it:"Solo biciclette"},{en:"A right-turn lane",it:"Una corsia di svolta destra"}],correct:1,explain_en:"White diamonds mark an HOV (carpool) lane. Only vehicles with the minimum required number of occupants may use it during posted hours.",explain_it:"I rombi bianchi segnano una corsia HOV. Solo i veicoli con il numero minimo richiesto di occupanti possono usarla durante le ore segnalate."},
  {cat:"signs",en:"What does a 'Merge' sign indicate?",it:"Cosa indica un segnale 'Merge'?",options:[{en:"You have the right of way",it:"Hai la precedenza"},{en:"Two lanes are coming together -- yield and merge safely",it:"Due corsie si stanno unendo -- cedere e confluire in sicurezza"},{en:"The road splits into two",it:"La strada si divide in due"},{en:"Stop and wait for traffic to clear",it:"Fermarsi e aspettare"}],correct:1,explain_en:"Merge signs warn that two traffic flows are converging. Adjust speed and position to merge safely.",explain_it:"I segnali Merge avvisano che due flussi di traffico stanno convergendo. Regola velocita e posizione per confluire in sicurezza."},
  {cat:"signs",en:"What does a 'Yield' sign look like?",it:"Come appare un segnale 'Yield'?",options:[{en:"A red octagon",it:"Un ottagono rosso"},{en:"A downward-pointing red and white triangle",it:"Un triangolo rosso e bianco rivolto verso il basso"},{en:"A yellow diamond",it:"Un rombo giallo"},{en:"A white circle with red text",it:"Un cerchio bianco con testo rosso"}],correct:1,explain_en:"Yield signs are downward-pointing triangles with red border and white interior. They require slowing and giving right-of-way to conflicting traffic.",explain_it:"I segnali Yield sono triangoli rivolti verso il basso con bordo rosso. Richiedono di rallentare e cedere la precedenza."},
  {cat:"signs",en:"A sign with a truck tipping on a curve warns about what?",it:"Un segnale con un camion che si ribalta in curva avvisa di cosa?",options:[{en:"Trucks break down here frequently",it:"I camion si guastano spesso qui"},{en:"High rollover risk -- reduce speed especially in tall vehicles",it:"Alto rischio di ribaltamento -- ridurre la velocita specialmente nei veicoli alti"},{en:"Trucks must pull over here",it:"I camion devono accostare qui"},{en:"Road curves marked on both sides",it:"Le curve stradali sono segnate su entrambi i lati"}],correct:1,explain_en:"A truck-tipping sign warns of rollover risk on a sharp curve. High center-of-gravity vehicles must reduce speed significantly.",explain_it:"Un segnale di camion che si ribalta avvisa del rischio di ribaltamento. I veicoli con alto centro di gravita devono ridurre la velocita."},
  {cat:"signs",en:"What does a double yellow centerline with one solid and one dashed line mean?",it:"Cosa significa una linea centrale doppia gialla con una continua e una tratteggiata?",options:[{en:"Both directions may pass",it:"Entrambe le direzioni possono sorpassare"},{en:"Passing allowed only from the side of the dashed line",it:"Sorpasso consentito solo dal lato della linea tratteggiata"},{en:"No passing in either direction",it:"Nessun sorpasso in nessuna direzione"},{en:"Only trucks may not pass",it:"Solo i camion non possono sorpassare"}],correct:1,explain_en:"Solid yellow next to dashed yellow: if solid is on your side, no passing. If dashed is on your side, passing is permitted when safe.",explain_it:"Linea gialla continua accanto a tratteggiata: se la continua e sul tuo lato, nessun sorpasso. Se la tratteggiata e sul tuo lato, il sorpasso e consentito."},
  {cat:"signs",en:"What does 'No Stopping Any Time' mean compared to 'No Parking Any Time'?",it:"Cosa significa 'No Stopping Any Time' rispetto a 'No Parking Any Time'?",options:[{en:"They mean the same thing",it:"Significano la stessa cosa"},{en:"No Stopping prohibits even momentary stops; No Parking allows brief stops to drop off passengers",it:"No Stopping vieta le soste momentanee; No Parking consente brevi soste per far scendere passeggeri"},{en:"No Stopping only applies to trucks",it:"No Stopping si applica solo ai camion"},{en:"No Parking allows 5 minutes",it:"No Parking consente 5 minuti"}],correct:1,explain_en:"No Stopping Any Time is stricter: no stop even momentarily. No Parking allows brief stops for loading/unloading passengers only.",explain_it:"No Stopping Any Time e piu rigoroso: nessuna sosta neanche momentaneamente. No Parking consente brevi soste per carico/scarico."},
  {cat:"laws",en:"What is Florida's Move Over law?",it:"Cos'e la legge Florida Move Over?",options:[{en:"Move right when someone passes you",it:"Spostarsi a destra quando qualcuno ti sorpassa"},{en:"Move one lane over or slow 20 mph below the limit when passing stopped emergency or tow trucks with lights on",it:"Spostarsi di una corsia o rallentare a 20 mph sotto il limite quando si supera un veicolo di emergenza fermo con luci accese"},{en:"Move over for all slow vehicles",it:"Spostarsi per tutti i veicoli lenti"},{en:"Only applies to police vehicles",it:"Si applica solo ai veicoli di polizia"}],correct:1,explain_en:"Florida Move Over law: when passing a stopped emergency, sanitation, utility, or tow truck with lights on, move over one lane or reduce speed 20 mph below the posted limit.",explain_it:"Legge Move Over Florida: quando si supera un veicolo fermo di emergenza, igiene, servizi o carro attrezzi con luci accese, spostarsi di una corsia o ridurre la velocita di 20 mph."},
  {cat:"laws",en:"What is the Florida law about texting while driving?",it:"Qual e la legge Florida sull'invio di messaggi durante la guida?",options:[{en:"Legal if at a stop light",it:"Legale a un semaforo rosso"},{en:"Illegal -- texting while driving is a primary offense in Florida",it:"Illegale -- l'invio di messaggi durante la guida e un reato principale in Florida"},{en:"Only illegal for commercial drivers",it:"Illegale solo per i conducenti commerciali"},{en:"Legal for passengers to text to the driver",it:"Legale per i passeggeri inviare messaggi al conducente"}],correct:1,explain_en:"Florida made texting while driving a primary offense in 2019. In school and work zones, handheld device use is prohibited entirely.",explain_it:"La Florida ha reso l'invio di messaggi durante la guida un reato principale nel 2019. Nelle zone scolastiche e di lavoro, l'uso di dispositivi portatili e completamente vietato."},
  {cat:"laws",en:"What is the right-of-way rule for vehicles already in a roundabout?",it:"Qual e la regola di precedenza per i veicoli gia in una rotonda?",options:[{en:"Vehicles entering have the right of way",it:"I veicoli in entrata hanno la precedenza"},{en:"Vehicles already in the circle have right of way -- entering vehicles yield",it:"I veicoli gia nel cerchio hanno la precedenza -- i veicoli in entrata cedono"},{en:"The vehicle on the right has priority",it:"Il veicolo a destra ha la priorita"},{en:"No right-of-way rules in circles",it:"Nessuna regola di precedenza nelle rotonde"}],correct:1,explain_en:"At roundabouts, yield to traffic already circulating inside. Enter only when there is a safe gap. Travel counterclockwise.",explain_it:"Alle rotonde, cedere al traffico gia in circolazione. Entrare solo quando c'e uno spazio sicuro. Viaggiare in senso antiorario."},
  {cat:"laws",en:"What must Florida drivers do when approaching a funeral procession?",it:"Cosa devono fare i conducenti Florida quando si avvicinano a un corteo funebre?",options:[{en:"Honk once and proceed normally",it:"Suonare il clacson e procedere normalmente"},{en:"Yield -- it is illegal to cut through or interfere with a properly escorted funeral procession",it:"Cedere -- e illegale tagliare o interferire con un corteo funebre scortato"},{en:"Only police escorts require yielding",it:"Solo le scorte della polizia richiedono la precedenza"},{en:"Pass the procession on the right",it:"Superare il corteo a destra"}],correct:1,explain_en:"Florida law protects funeral processions. You may not interfere with or cut through a procession. Procession vehicles may follow each other through signals.",explain_it:"La legge Florida protegge i cortei funebri. Non puoi interferire o tagliare un corteo. I veicoli del corteo possono seguirsi attraverso i segnali."},
  {cat:"laws",en:"What is Florida's law about driving so slowly you impede traffic?",it:"Qual e la legge Florida sulla guida cosi lenta da ostacolare il traffico?",options:[{en:"No minimum speed on Florida roads",it:"Nessuna velocita minima"},{en:"Driving so slowly as to impede normal traffic flow is a moving violation",it:"Guidare cosi lentamente da ostacolare il normale flusso del traffico e una violazione in movimento"},{en:"Only on highways",it:"Solo in autostrada"},{en:"Legal if hazard lights are used",it:"Legale se si usano le luci di pericolo"}],correct:1,explain_en:"Florida prohibits driving so slowly as to impede normal traffic flow. Driving unreasonably slowly is a moving violation, especially on limited-access highways.",explain_it:"La Florida vieta di guidare cosi lentamente da ostacolare il normale flusso del traffico. Una violazione in movimento."},
  {cat:"laws",en:"What is the proper procedure at an all-way stop when two vehicles arrive simultaneously?",it:"Qual e la procedura corretta a uno stop totale quando due veicoli arrivano contemporaneamente?",options:[{en:"The vehicle on the left goes first",it:"Il veicolo a sinistra va per primo"},{en:"Yield to the vehicle on your right",it:"Cedere al veicolo alla tua destra"},{en:"Whoever arrived first goes first",it:"Chi e arrivato prima va per primo"},{en:"The larger vehicle goes first",it:"Il veicolo piu grande va per primo"}],correct:1,explain_en:"When two vehicles arrive simultaneously at an all-way stop, yield to the vehicle on your right.",explain_it:"Quando due veicoli arrivano contemporaneamente a uno stop totale, cedi al veicolo alla tua destra."},
  {cat:"laws",en:"What is the Florida law on making a left turn at a green light?",it:"Qual e la legge Florida sulla svolta sinistra con il verde?",options:[{en:"Left turn has absolute right of way on green",it:"La svolta sinistra ha precedenza assoluta"},{en:"May turn left on solid green but must yield to oncoming traffic and pedestrians",it:"Puoi svoltare a sinistra con il verde fisso ma devi cedere al traffico in arrivo e ai pedoni"},{en:"Left turns require a protected arrow only",it:"Le svolte sinistra richiedono solo una freccia protetta"},{en:"Left turns are prohibited on solid green",it:"Le svolte sinistra sono vietate con il verde fisso"}],correct:1,explain_en:"On a solid green, left turns are permitted but you must yield to all oncoming traffic and pedestrians. Only a green arrow gives a protected left turn.",explain_it:"Con il verde fisso, le svolte sinistra sono consentite ma devi cedere a tutto il traffico in arrivo e ai pedoni."},
  {cat:"laws",en:"What is the minimum distance for signaling before turning on a city street in Florida?",it:"Qual e la distanza minima per segnalare prima di svoltare su una strada cittadina in Florida?",options:[{en:"50 feet",it:"50 piedi"},{en:"100 feet",it:"100 piedi"},{en:"200 feet",it:"200 piedi"},{en:"300 feet",it:"300 piedi"}],correct:1,explain_en:"Florida requires signaling at least 100 feet before turning on city streets (200 feet on limited-access highways).",explain_it:"La Florida richiede di segnalare almeno 100 piedi prima di svoltare sulle strade cittadine (200 piedi sulle autostrade)."},
  {cat:"laws",en:"What is the Florida law about stopping for a school bus on a divided highway?",it:"Qual e la legge Florida sulla fermata per uno scuolabus su un'autostrada divisa?",options:[{en:"All traffic must stop on both sides",it:"Tutto il traffico deve fermarsi su entrambi i lati"},{en:"On a divided highway with a physical median, only traffic on the same side as the bus must stop",it:"Su un'autostrada divisa con mediano fisico, solo il traffico sullo stesso lato dello scuolabus deve fermarsi"},{en:"Divided highways are exempt",it:"Le autostrade divise sono esentate"},{en:"Stop only if children are visible",it:"Fermarsi solo se i bambini sono visibili"}],correct:1,explain_en:"On a divided highway with a physical barrier: only vehicles traveling in the same direction as the bus must stop. Oncoming traffic need not stop.",explain_it:"Su un'autostrada divisa con barriera fisica: solo i veicoli che viaggiano nella stessa direzione dello scuolabus devono fermarsi."},
  {cat:"laws",en:"What is the Florida law about parking near a fire hydrant?",it:"Qual e la legge Florida sul parcheggio vicino a un idrante?",options:[{en:"May park 10 feet away",it:"Si puo parcheggiare a 10 piedi"},{en:"No parking within 15 feet of a fire hydrant",it:"Nessun parcheggio entro 15 piedi da un idrante"},{en:"No parking within 20 feet",it:"Nessun parcheggio entro 20 piedi"},{en:"No restriction if the hydrant is on private property",it:"Nessuna restrizione se su proprieta privata"}],correct:1,explain_en:"Florida prohibits parking within 15 feet of a fire hydrant to ensure fire truck access in emergencies.",explain_it:"La Florida vieta il parcheggio entro 15 piedi da un idrante per garantire l'accesso dei camion dei pompieri."},
  {cat:"laws",en:"What is the Florida law on right-of-way for blind pedestrians with a white cane?",it:"Qual e la legge Florida sulla precedenza per i pedoni non vedenti con bastone bianco?",options:[{en:"Same rules as sighted pedestrians",it:"Le stesse regole dei pedoni vedenti"},{en:"Drivers must yield absolute right-of-way to persons using a white cane or guide dog",it:"I conducenti devono cedere la precedenza assoluta alle persone che usano un bastone bianco o cane guida"},{en:"Only at crosswalks with signals",it:"Solo agli attraversamenti con segnali"},{en:"The pedestrian must indicate intent to cross",it:"Il pedone deve indicare l'intenzione di attraversare"}],correct:1,explain_en:"Florida law gives absolute right-of-way to blind pedestrians using a white cane or guide dog -- at any location, not just crosswalks.",explain_it:"La legge Florida da la precedenza assoluta ai pedoni ciechi che usano un bastone bianco o cane guida -- in qualsiasi luogo."},
  {cat:"laws",en:"What is the Florida law about leaving a child under 6 alone in a vehicle?",it:"Qual e la legge Florida sul lasciare un bambino under 6 solo in un veicolo?",options:[{en:"Legal for up to 10 minutes",it:"Legale fino a 10 minuti"},{en:"Illegal for more than 15 minutes or if the engine is running",it:"Illegale per piu di 15 minuti o se il motore e acceso"},{en:"Legal if windows are down",it:"Legale se i finestrini sono abbassati"},{en:"Only illegal in extreme heat",it:"Illegale solo in calore estremo"}],correct:1,explain_en:"Florida law: children under 6 may not be left unattended in a vehicle for more than 15 minutes, or at all if the engine is running.",explain_it:"Legge Florida: i bambini under 6 non possono essere lasciati incustoditi in un veicolo per piu di 15 minuti, o per niente se il motore e acceso."},
  {cat:"laws",en:"What is Florida's law on littering from a vehicle?",it:"Qual e la legge Florida sul gettare rifiuti da un veicolo?",options:[{en:"Only illegal for commercial vehicles",it:"Illegale solo per i veicoli commerciali"},{en:"Illegal -- fines start at $100 for first offense",it:"Illegale -- le multe iniziano da $100 per la prima infrazione"},{en:"Legal for biodegradable materials",it:"Legale per i materiali biodegradabili"},{en:"Only illegal on state highways",it:"Illegale solo sulle autostrade statali"}],correct:1,explain_en:"Florida's littering law: fines start at $100 for the first offense, $200 for the second, and $500+ for subsequent violations.",explain_it:"Legge sul littering Florida: le multe iniziano da $100 per la prima infrazione, $200 per la seconda, $500+ per le successive."},
  {cat:"laws",en:"What is required when a Florida driver's address changes?",it:"Cosa e richiesto quando cambia l'indirizzo della patente Florida?",options:[{en:"Nothing until renewal",it:"Niente fino al rinnovo"},{en:"Must notify FLHSMV within 30 days",it:"Deve notificare al FLHSMV entro 30 giorni"},{en:"Must get a new license within 10 days",it:"Deve ottenere una nuova patente entro 10 giorni"},{en:"Address changes are processed only at renewal",it:"I cambi di indirizzo vengono elaborati solo al rinnovo"}],correct:1,explain_en:"Florida drivers must notify FLHSMV of an address change within 30 days. You can update online, by mail, or in person.",explain_it:"I conducenti Florida devono notificare al FLHSMV un cambio di indirizzo entro 30 giorni."},
  {cat:"laws",en:"What is Florida's law on use of high beams in fog?",it:"Qual e la legge Florida sull'uso degli abbaglianti nella nebbia?",options:[{en:"Always use high beams for maximum visibility",it:"Usare sempre gli abbaglianti"},{en:"Use low beams or fog lights -- high beams reflect off fog reducing visibility",it:"Usare anabbaglianti o fendinebbia -- gli abbaglianti riflettono nella nebbia riducendo la visibilita"},{en:"Turn off all lights in heavy fog",it:"Spegnere tutte le luci nella nebbia fitta"},{en:"High beams required in fog by Florida law",it:"Gli abbaglianti sono richiesti nella nebbia dalla legge Florida"}],correct:1,explain_en:"In fog, use low beams or fog lights. High beams reflect off water droplets and create glare that reduces your ability to see.",explain_it:"Nella nebbia, usa anabbaglianti o fendinebbia. Gli abbaglianti si riflettono sulle goccioline d'acqua e creano abbagliamento."},
  {cat:"safety",en:"What is the correct use of ABS brakes in an emergency stop?",it:"Qual e l'uso corretto dei freni ABS in una frenata di emergenza?",options:[{en:"Pump the brake pedal rapidly",it:"Pompare rapidamente il pedale del freno"},{en:"Press firmly and hold -- do not pump; ABS pumps automatically",it:"Premere con forza e tenere -- non pompare; l'ABS pompa automaticamente"},{en:"Press gently to avoid skidding",it:"Premere delicatamente per evitare lo scivolamento"},{en:"Apply parking brake simultaneously",it:"Applicare contemporaneamente il freno a mano"}],correct:1,explain_en:"With ABS: apply maximum firm pressure and hold. The system automatically pumps to prevent lockup. You can still steer while braking hard. DO NOT pump ABS.",explain_it:"Con l'ABS: applicare la massima pressione e tenere. Il sistema pompa automaticamente. Puoi ancora sterzare mentre freni forte. NON pompare l'ABS."},
  {cat:"safety",en:"What is hydroplaning and how can it be prevented?",it:"Cos'e l'aquaplaning e come puo essere prevenuto?",options:[{en:"Engine overheating",it:"Surriscaldamento del motore"},{en:"Loss of tire-road contact due to water -- prevented by reducing speed and maintaining tread depth",it:"Perdita di contatto pneumatico-strada a causa dell'acqua -- prevenuta riducendo la velocita e mantenendo il battistrada"},{en:"Tire blowout -- prevented by checking pressure",it:"Foratura -- prevenuta controllando la pressione"},{en:"Engine stalling in water",it:"Spegnimento del motore in acqua"}],correct:1,explain_en:"Hydroplaning: water builds faster than tires can channel away -- you ride on a water film losing steering and braking. Prevent by slowing in rain and maintaining 4/32+ tread.",explain_it:"Aquaplaning: l'acqua si accumula piu velocemente di quanto gli pneumatici possano canalizzarla -- si perde lo sterzo e la frenata. Prevenire rallentando nella pioggia."},
  {cat:"safety",en:"What should you do if your vehicle starts to hydroplane?",it:"Cosa dovresti fare se il tuo veicolo inizia ad aquaplanare?",options:[{en:"Brake hard immediately",it:"Frenare forte immediatamente"},{en:"Ease off gas, do not brake sharply, steer straight until tires regain contact",it:"Togliere il gas, non frenare bruscamente, sterzare dritto finche gli pneumatici non riguadagnano il contatto"},{en:"Turn the wheel sharply",it:"Girare bruscamente il volante"},{en:"Accelerate slightly to push through",it:"Accelerare leggermente"}],correct:1,explain_en:"If hydroplaning: ease off gas, hold straight, wait for tire contact to return. Braking or sharp steering while floating causes skidding.",explain_it:"In aquaplaning: togliere il gas, mantenere dritto, aspettare che il contatto torni. Frenare o sterzare bruscamente causa scivolamento."},
  {cat:"safety",en:"What should you do if a tire blows out at highway speed?",it:"Cosa dovresti fare se uno pneumatico esplode ad alta velocita?",options:[{en:"Brake hard and steer to the shoulder",it:"Frenare forte e sterzare verso la banchina"},{en:"Hold wheel firmly, ease off gas, let car slow naturally, then steer to shoulder",it:"Tenere il volante saldamente, togliere il gas, lasciare rallentare l'auto, poi sterzare verso la banchina"},{en:"Accelerate briefly to stabilize",it:"Accelerare brevemente per stabilizzare"},{en:"Turn on hazards and maintain speed",it:"Accendere le luci di pericolo e mantenere la velocita"}],correct:1,explain_en:"Tire blowout: grip steering firmly, ease off gas (don't brake hard), let car decelerate naturally, then gently steer to safety. Hard braking can cause a spin.",explain_it:"Foratura: stringi il volante, togli il gas (non frenare forte), lascia decelerare, poi sterza delicatamente verso la sicurezza."},
  {cat:"safety",en:"What is the correct procedure if your brakes fail completely?",it:"Qual e la procedura corretta se i freni si guastano completamente?",options:[{en:"Jump out of the car",it:"Saltare fuori dall'auto"},{en:"Pump brakes, downshift, use parking brake gently, find a safe escape route",it:"Pompare i freni, scalare, usare delicatamente il freno a mano, cercare una via di fuga sicura"},{en:"Turn off the engine immediately",it:"Spegnere immediatamente il motore"},{en:"Maintain lane with hazards on",it:"Mantenere la corsia con le luci di pericolo"}],correct:1,explain_en:"If brakes fail: pump repeatedly, downshift, apply parking brake gently, aim for a safe escape (uphill, guard rail, soft shoulder).",explain_it:"Se i freni si guastano: pompare ripetutamente, scalare, applicare delicatamente il freno a mano, puntare a una via di fuga sicura."},
  {cat:"safety",en:"What is the most dangerous time of day for deer-vehicle collisions?",it:"Qual e il momento piu pericoloso della giornata per le collisioni cervo-veicolo?",options:[{en:"Noon",it:"Mezzogiorno"},{en:"Dawn and dusk -- deer are most active and visibility is reduced",it:"Alba e crepuscolo -- i cervi sono piu attivi e la visibilita e ridotta"},{en:"Midnight",it:"Mezzanotte"},{en:"Early morning after sunrise",it:"Prima mattina dopo l'alba"}],correct:1,explain_en:"Dawn and dusk are peak times for deer activity -- they feed at these times. Visibility is also reduced during these transition periods.",explain_it:"Alba e crepuscolo sono i momenti di punta per l'attivita dei cervi. La visibilita e anche ridotta durante questi periodi."},
  {cat:"safety",en:"What is the correct action if your accelerator pedal sticks while driving?",it:"Qual e l'azione corretta se il pedale dell'acceleratore si blocca?",options:[{en:"Immediately turn off ignition",it:"Spegnere immediatamente il motore"},{en:"Shift to Neutral, apply brake firmly, pull off road, then turn off ignition",it:"Passare in folle, applicare il freno con forza, accostare, poi spegnere il motore"},{en:"Continue driving and use engine braking only",it:"Continuare a guidare e usare solo la frenata del motore"},{en:"Try to lift the pedal with your foot while driving",it:"Cercare di sollevare il pedale con il piede durante la guida"}],correct:1,explain_en:"Stuck accelerator: shift to Neutral, brake firmly, steer to safety, then turn off engine. Don't turn off ignition while moving -- you lose power steering and braking.",explain_it:"Acceleratore bloccato: passa in folle, frena con forza, sterza verso la sicurezza, poi spegni il motore."},
  {cat:"safety",en:"What is the danger of driving too close behind a large truck?",it:"Qual e il pericolo di guidare troppo vicino dietro a un grande camion?",options:[{en:"Trucks drive faster than cars",it:"I camion guidano piu veloce delle auto"},{en:"Reduced visibility, debris risk, underride danger if truck stops suddenly",it:"Visibilita ridotta, rischio di detriti, pericolo di incastrarsi se il camion si ferma improvvisamente"},{en:"Trucks create turbulence reducing fuel efficiency",it:"I camion creano turbolenza che riduce l'efficienza del carburante"},{en:"Only a danger with hazardous materials",it:"Un pericolo solo con materiali pericolosi"}],correct:1,explain_en:"Tailgating trucks: blind spot, debris risk, and fatal underride if the truck brakes suddenly. Stay back at least 4 seconds.",explain_it:"Seguire da vicino i camion: punto cieco, rischio di detriti e fatale incastro se il camion frena improvvisamente."},
  {cat:"safety",en:"What is the safest way to navigate a flooded road?",it:"Qual e il modo piu sicuro per navigare una strada allagata?",options:[{en:"Drive fast to get through quickly",it:"Guidare veloce per attraversare velocemente"},{en:"Turn around -- never drive through flooded roads (Turn Around Don't Drown)",it:"Girare indietro -- non guidare mai attraverso strade allagate"},{en:"Drive slowly through the center",it:"Guidare lentamente attraverso il centro"},{en:"Test the depth with your foot first",it:"Testare la profondita con il piede prima"}],correct:1,explain_en:"Turn Around Don't Drown: 6 inches of moving water can knock you down; 2 feet can sweep away a vehicle. Most flood deaths occur in vehicles.",explain_it:"Turn Around Don't Drown: 15 cm di acqua in movimento possono abbatterti; 60 cm possono spazzare via un veicolo."},
  {cat:"safety",en:"What is the correct way to merge onto a highway from an on-ramp?",it:"Qual e il modo corretto per confluire in autostrada da una rampa?",options:[{en:"Stop at the end of the ramp and wait for a gap",it:"Fermarsi alla fine della rampa e aspettare"},{en:"Use the ramp to accelerate to highway speed, signal, check mirrors and blind spots, then merge",it:"Usare la rampa per accelerare alla velocita autostradale, segnalare, controllare specchi e punti ciechi, poi confluire"},{en:"Merge immediately without checking mirrors",it:"Confluire immediatamente senza controllare gli specchi"},{en:"Wait for highway drivers to make room",it:"Aspettare che i conducenti autostradali facciano spazio"}],correct:1,explain_en:"Correct merging: use the full ramp length to match highway speed, signal early, check mirrors and blind spots, then merge smoothly.",explain_it:"Confluenza corretta: usa la lunghezza completa della rampa per raggiungere la velocita autostradale, segnala presto, controlla specchi e punti ciechi."},
  {cat:"safety",en:"What is the danger of overdriving your headlights at night?",it:"Qual e il pericolo di superare i tuoi fari di notte?",options:[{en:"It drains the car battery faster",it:"Consuma la batteria piu velocemente"},{en:"You are traveling faster than your ability to stop within the illuminated distance",it:"Stai viaggiando piu veloce della tua capacita di fermarti entro la distanza illuminata"},{en:"Headlights reduce night visibility",it:"I fari riducono la visibilita notturna"},{en:"Only a problem on curved roads",it:"Un problema solo sulle strade curve"}],correct:1,explain_en:"Overdriving headlights: if you're going faster than you can stop within the beam range, you cannot avoid an obstacle you see.",explain_it:"Superare i fari: se vai piu veloce di quanto puoi fermarti entro il raggio del fascio, non puoi evitare un ostacolo."},
  {cat:"safety",en:"What is the greatest risk on a road that just got rain after a dry period?",it:"Qual e il rischio maggiore su una strada che ha appena ricevuto pioggia dopo un periodo secco?",options:[{en:"Increased visibility from the cleaned surface",it:"Visibilita aumentata dalla superficie pulita"},{en:"Roads are most slippery at the start of rain -- oil and debris rise before being washed away",it:"Le strade sono piu scivolose all'inizio della pioggia -- olio e detriti salgono prima di essere lavati via"},{en:"Tires grip better on wet asphalt",it:"Gli pneumatici aderiscono meglio sull'asfalto bagnato"},{en:"Hydroplaning only occurs in heavy rain",it:"L'aquaplaning si verifica solo nelle piogge forti"}],correct:1,explain_en:"The first 10-30 minutes of rain are most dangerous: oil from vehicles rises to the surface making roads extremely slippery before washing away.",explain_it:"I primi 10-30 minuti di pioggia sono i piu pericolosi: l'olio dai veicoli sale in superficie rendendo le strade estremamente scivolose."},
  {cat:"safety",en:"What should you do if you become drowsy while driving on a highway?",it:"Cosa dovresti fare se diventi assonnato durante la guida?",options:[{en:"Turn up the radio and open windows",it:"Alzare la radio e aprire i finestrini"},{en:"Find a safe place to stop and rest -- drowsy driving is as dangerous as drunk driving",it:"Trovare un posto sicuro per fermarsi e riposare -- la guida assonnata e pericolosa quanto quella ubriaca"},{en:"Drink coffee and continue",it:"Bere caffe e continuare"},{en:"Speed up to reduce travel time",it:"Accelerare per ridurre il tempo di viaggio"}],correct:1,explain_en:"Drowsy driving is as impaired as drunk driving. The only real solution is sleep. Stop at a rest area for 15-20 minutes.",explain_it:"La guida assonnata e pericolosa quanto quella ubriaca. L'unica vera soluzione e il sonno. Fermati a un'area di riposo per 15-20 minuti."},
  {cat:"safety",en:"What is the main danger of highway hypnosis?",it:"Qual e il pericolo principale dell'ipnosi autostradale?",options:[{en:"Speeding without realizing it",it:"Accelerare senza rendersene conto"},{en:"A trance-like state where attention drifts from the road on monotonous drives",it:"Uno stato di trance dove l'attenzione si allontana dalla strada nelle guidate monotone"},{en:"Headlights blurring at high speed",it:"I fari che sfumano ad alta velocita"},{en:"Overconfidence in safety systems",it:"Eccesso di fiducia nei sistemi di sicurezza"}],correct:1,explain_en:"Highway hypnosis: the brain enters autopilot mode on long monotonous drives. Prevention: change eye focus, shift position, take breaks every 2 hours.",explain_it:"Ipnosi autostradale: il cervello entra in modalita pilota automatico nelle lunghe guidate monotone. Prevenzione: cambia la messa a fuoco, cambia posizione, fai pause ogni 2 ore."},
  {cat:"safety",en:"What should a driver do when cresting a hill on a two-lane road?",it:"Cosa dovrebbe fare un conducente quando raggiunge la cima di una collina su una strada a due corsie?",options:[{en:"Accelerate to get over quickly",it:"Accelerare per superarla velocemente"},{en:"Stay in your lane, reduce speed, and avoid passing -- sight distance beyond the crest is zero",it:"Restare nella corsia, ridurre la velocita, evitare di sorpassare -- la distanza visiva oltre la cima e zero"},{en:"Move to the center for better visibility",it:"Spostarsi al centro per una migliore visibilita"},{en:"Flash high beams to warn oncoming traffic",it:"Lampeggiare gli abbaglianti"}],correct:1,explain_en:"At a hill crest: stay in your lane, reduce speed, do NOT pass -- you cannot see what is on the other side.",explain_it:"In cima a una collina: resta nella corsia, riduci la velocita, NON sorpassare -- non puoi vedere cosa c'e dall'altra parte."},
  {cat:"safety",en:"What is the purpose of rumble strips on the side of a highway?",it:"Qual e lo scopo delle strisce vibranti sul lato di un'autostrada?",options:[{en:"To mark the shoulder for maintenance crews",it:"Per segnare la banchina per le squadre di manutenzione"},{en:"To alert drifting or drowsy drivers that they are leaving the travel lane",it:"Per allertare i conducenti che si allontanano o sonnolenti che stanno lasciando la corsia"},{en:"To slow vehicles entering on-ramps",it:"Per rallentare i veicoli nelle rampe"},{en:"To reduce tire wear",it:"Per ridurre l'usura degli pneumatici"}],correct:1,explain_en:"Edge rumble strips provide vibration and noise when a tire crosses them -- alerting drowsy drivers that they are drifting off the road.",explain_it:"Le strisce vibranti laterali forniscono vibrazione e rumore quando uno pneumatico le attraversa -- avvisando i conducenti sonnolenti."},
  {cat:"safety",en:"What is the recommended following distance behind a motorcycle?",it:"Qual e la distanza di seguimento raccomandata dietro a una moto?",options:[{en:"Same as any vehicle -- 2 seconds",it:"La stessa di qualsiasi veicolo -- 2 secondi"},{en:"At least 3-4 seconds -- motorcycles can stop faster",it:"Almeno 3-4 secondi -- le moto possono fermarsi piu velocemente"},{en:"1 second -- motorcycles are smaller",it:"1 secondo -- le moto sono piu piccole"},{en:"Maintain visual contact only",it:"Mantenere solo il contatto visivo"}],correct:1,explain_en:"Following a motorcycle requires MORE space -- 3-4 seconds minimum. Motorcycles stop more quickly than cars.",explain_it:"Seguire una moto richiede PIU spazio -- minimo 3-4 secondi. Le moto si fermano piu velocemente delle auto."},
  {cat:"safety",en:"What is the correct technique when driving through deep standing water?",it:"Qual e la tecnica corretta quando si guida attraverso acqua stagnante profonda?",options:[{en:"Drive fast to prevent water entry into the engine",it:"Guidare veloce per prevenire l'ingresso d'acqua nel motore"},{en:"If unavoidable, drive slowly in a low gear, test brakes afterward by applying them gently",it:"Se inevitabile, guidare lentamente in una marcia bassa, testare i freni dopo applicandoli delicatamente"},{en:"Maintain normal speed to create a bow wave",it:"Mantenere la velocita normale per creare un'onda di prua"},{en:"Turn around -- always",it:"Girare indietro -- sempre"}],correct:1,explain_en:"If you must cross standing water: slow to a crawl, use low gear, drive through the shallowest part. After crossing, gently apply brakes to dry them.",explain_it:"Se devi attraversare acqua stagnante: rallenta, usa una marcia bassa, attraversa la parte piu bassa. Dopo aver attraversato, applica delicatamente i freni per asciugarli."},
  {cat:"safety",en:"What is the effect of driving with underinflated tires on handling?",it:"Qual e l'effetto della guida con pneumatici gonfiati in modo insufficiente sulla maniabilita?",options:[{en:"Improves cornering ability",it:"Migliora la capacita di curva"},{en:"Causes poor steering response, increased tire wear on edges, and higher blowout risk at speed",it:"Causa risposta dello sterzo scadente, maggiore usura degli pneumatici sui bordi e maggiore rischio di foratura ad alta velocita"},{en:"Reduces braking distance",it:"Riduce la distanza di frenata"},{en:"Has no effect in normal conditions",it:"Non ha effetti nelle condizioni normali"}],correct:1,explain_en:"Underinflated tires: reduce fuel economy, cause premature edge wear, increase heat buildup leading to blowouts, and reduce steering responsiveness.",explain_it:"Pneumatici sottosgonfiati: riducono l'efficienza del carburante, causano usura prematura dei bordi, aumentano l'accumulo di calore portando a forature."},
  {cat:"safety",en:"What is target fixation in driving?",it:"Cos'e la fissazione del bersaglio nella guida?",options:[{en:"Focusing on the speed limit sign",it:"Concentrarsi sul segnale del limite di velocita"},{en:"The tendency to steer toward what you are looking at -- including hazards",it:"La tendenza a sterzare verso cio che si guarda -- compresi i pericoli"},{en:"Using GPS navigation to target a destination",it:"Usare la navigazione GPS per puntare a una destinazione"},{en:"Maintaining focus on the center line",it:"Mantenere la concentrazione sulla linea centrale"}],correct:1,explain_en:"Target fixation: drivers steer toward what they focus on. Look where you WANT to go, not at the obstacle -- this helps steer around it.",explain_it:"Fissazione del bersaglio: i conducenti sterzano verso cio su cui si concentrano. Guarda dove VUOI andare, non all'ostacolo."},
  {cat:"alcohol",en:"What is the role of the liver in processing alcohol?",it:"Qual e il ruolo del fegato nell'elaborazione dell'alcol?",options:[{en:"Stores alcohol for gradual release",it:"Immagazzina l'alcol per un rilascio graduale"},{en:"Metabolizes about one standard drink per hour regardless of factors",it:"Metabolizza circa un drink standard all'ora indipendentemente dai fattori"},{en:"Converts alcohol to glucose",it:"Converte l'alcol in glucosio"},{en:"Only processes alcohol after eating",it:"Elabora l'alcol solo dopo aver mangiato"}],correct:1,explain_en:"The liver metabolizes approximately one standard drink per hour. This rate cannot be sped up by exercise, food, or coffee.",explain_it:"Il fegato metabolizza circa un drink standard all'ora. Questa velocita non puo essere accelerata da esercizio, cibo o caffe."},
  {cat:"alcohol",en:"What is 'tolerance' in the context of alcohol and driving?",it:"Cos'e la 'tolleranza' nel contesto dell'alcol e della guida?",options:[{en:"The ability to hold more alcohol without vomiting",it:"La capacita di reggere piu alcol senza vomitare"},{en:"Reduced felt impairment but same physical impairment -- making experienced drinkers more dangerous",it:"Ridotta compromissione percepita ma stessa compromissione fisica -- rendendo i bevitori esperti piu pericolosi"},{en:"The legal BAC limit",it:"Il limite legale BAC"},{en:"Number of drinks before feeling drunk",it:"Il numero di drink prima di sentirsi ubriaco"}],correct:1,explain_en:"Tolerance reduces the FEELING of impairment but not the actual impairment. An experienced drinker at 0.10% doesn't feel drunk but is just as impaired.",explain_it:"La tolleranza riduce la SENSAZIONE di compromissione ma non la compromissione reale. Un bevitore esperto a 0,10% non si sente ubriaco ma e ugualmente compromesso."},
  {cat:"alcohol",en:"What is the Florida Zero Tolerance Law for drivers under 21?",it:"Qual e la Legge Zero Tolerance della Florida per i conducenti under 21?",options:[{en:"Absolutely no alcohol -- BAC must be 0.00%",it:"Assolutamente nessun alcol -- BAC deve essere 0,00%"},{en:"BAC of 0.02% or higher results in license suspension for drivers under 21",it:"Un BAC di 0,02% o superiore comporta la sospensione della patente per i conducenti under 21"},{en:"Same 0.08% limit as adults",it:"Stesso limite di 0,08% degli adulti"},{en:"Only applies to drivers under 18",it:"Si applica solo ai conducenti under 18"}],correct:1,explain_en:"Florida Zero Tolerance: drivers under 21 with BAC 0.02-0.07% lose license for 6 months. BAC 0.08%+ = full DUI prosecution.",explain_it:"Zero Tolerance Florida: conducenti under 21 con BAC 0,02-0,07% perdono la patente per 6 mesi. BAC 0,08%+ = piena accusa DUI."},
  {cat:"alcohol",en:"How does body weight affect BAC?",it:"Come influisce il peso corporeo sul BAC?",options:[{en:"Heavier people always get less drunk",it:"Le persone piu pesanti si ubriacano sempre meno"},{en:"Heavier people generally have lower BAC for the same alcohol due to greater body water volume",it:"Le persone piu pesanti hanno generalmente un BAC piu basso per lo stesso alcol a causa del maggiore volume di acqua corporea"},{en:"Body weight has no effect on BAC",it:"Il peso corporeo non ha effetti sul BAC"},{en:"Muscle mass increases BAC",it:"La massa muscolare aumenta il BAC"}],correct:1,explain_en:"Heavier people have more body water to dilute alcohol, resulting in lower BAC per drink. Body composition also matters.",explain_it:"Le persone piu pesanti hanno piu acqua corporea per diluire l'alcol, risultando in un BAC piu basso per drink."},
  {cat:"alcohol",en:"What is the effect of gender on alcohol metabolism?",it:"Qual e l'effetto del genere sul metabolismo dell'alcol?",options:[{en:"No difference between men and women",it:"Nessuna differenza tra uomini e donne"},{en:"Women generally reach higher BAC due to less body water and different enzyme levels",it:"Le donne raggiungono generalmente un BAC piu alto a causa di meno acqua corporea e diversi livelli enzimatici"},{en:"Men always have higher BAC",it:"Gli uomini hanno sempre un BAC piu alto"},{en:"Only age affects BAC, not gender",it:"Solo l'eta influisce sul BAC, non il genere"}],correct:1,explain_en:"Women have higher body fat percentage and lower body water -- alcohol is more concentrated. Women also have lower levels of alcohol dehydrogenase enzyme.",explain_it:"Le donne hanno una percentuale di grasso corporeo piu alta e meno acqua corporea -- l'alcol e piu concentrato. Hanno anche livelli piu bassi di alcol deidrogenasi."},
  {cat:"alcohol",en:"What is the effect of eating before drinking?",it:"Come influisce il mangiare prima di bere?",options:[{en:"Food prevents alcohol from entering the blood",it:"Il cibo impedisce all'alcol di entrare nel sangue"},{en:"Food slows absorption but same total alcohol is eventually absorbed -- impairment is not prevented",it:"Il cibo rallenta l'assorbimento ma lo stesso alcol totale viene eventualmente assorbito -- la compromissione non e prevenuta"},{en:"Eating after drinking reverses absorption",it:"Mangiare dopo aver bevuto inverte l'assorbimento"},{en:"High protein foods neutralize alcohol",it:"Gli alimenti proteici neutralizzano l'alcol"}],correct:1,explain_en:"Food delays alcohol absorption by slowing stomach emptying. Peak BAC is lower and delayed -- but the same total alcohol is eventually absorbed.",explain_it:"Il cibo ritarda l'assorbimento dell'alcol. Il BAC di picco e piu basso e ritardato -- ma lo stesso alcol totale viene eventualmente assorbito."},
  {cat:"alcohol",en:"What is the Florida law about operating a boat under the influence?",it:"Qual e la legge Florida sull'operare una barca sotto l'influenza?",options:[{en:"No BUI law -- alcohol is allowed on boats",it:"Non c'e legge BUI -- l'alcol e consentito sulle barche"},{en:"BUI laws mirror DUI laws -- same 0.08% BAC limit and same penalties",it:"Le leggi BUI rispecchiano le leggi DUI -- stesso limite BAC di 0,08% e stesse sanzioni"},{en:"BUI applies only to commercial vessels",it:"Il BUI si applica solo alle imbarcazioni commerciali"},{en:"BAC limit is 0.10% for boats",it:"Il limite BAC e 0,10% per le barche"}],correct:1,explain_en:"Florida BUI law: same 0.08% BAC limit as driving. Penalties include fines, imprisonment, and license suspension.",explain_it:"Legge BUI Florida: stesso limite BAC di 0,08% della guida. Le sanzioni includono multe, reclusione e sospensione della patente."},
  {cat:"alcohol",en:"How does alcohol impair a driver's risk assessment?",it:"Come compromette l'alcol la valutazione del rischio di un conducente?",options:[{en:"Alcohol makes drivers more cautious",it:"L'alcol rende i conducenti piu cauti"},{en:"Alcohol impairs judgment making drivers underestimate risks and overestimate abilities",it:"L'alcol compromette il giudizio facendo sottovalutare i rischi e sopravvalutare le proprie capacita"},{en:"Only experienced drivers' risk assessment is affected",it:"Solo i conducenti esperti sono influenzati"},{en:"Risk assessment slightly improves at low BAC",it:"La valutazione del rischio migliora leggermente a basso BAC"}],correct:1,explain_en:"Alcohol impairs judgment before motor skills. Drunk drivers feel MORE confident while being less capable -- a dangerous combination.",explain_it:"L'alcol compromette il giudizio prima delle capacita motorie. I conducenti ubriachi si sentono PIU fiduciosi mentre sono meno capaci."},
  {cat:"alcohol",en:"What is the DUI enhancement penalty for having a minor in the vehicle in Florida?",it:"Qual e la sanzione di aggravamento DUI per avere un minore nel veicolo in Florida?",options:[{en:"No enhancement for minor passengers",it:"Nessun aggravamento per i passeggeri minorenni"},{en:"Mandatory minimum $1,000 fine, mandatory IID, and possible child abuse charges",it:"Multa minima obbligatoria di $1.000, IID obbligatorio e possibili accuse di abuso su minori"},{en:"Only a warning added to the record",it:"Solo un avvertimento aggiunto al casellario"},{en:"Child endangerment charged separately -- DUI penalty unchanged",it:"Il pericolo per i bambini e accusato separatamente"}],correct:1,explain_en:"DUI with a minor in vehicle: mandatory $1,000-$2,000 fine, mandatory IID, and child abuse charges may also apply.",explain_it:"DUI con un minore nel veicolo: multa obbligatoria di $1.000-$2.000, IID obbligatorio, e possono applicarsi anche accuse di abuso su minori."},
  {cat:"alcohol",en:"What does a 'standard drink' contain?",it:"Cosa contiene un 'drink standard'?",options:[{en:"Any size glass of wine",it:"Qualsiasi bicchiere di vino"},{en:"0.6 oz (14g) of pure alcohol -- equal to 12 oz beer, 5 oz wine, or 1.5 oz spirits",it:"0,6 oz (14g) di alcol puro -- equivalente a 12 oz di birra, 5 oz di vino o 1,5 oz di superalcolici"},{en:"A drink that does not impair driving",it:"Un drink che non compromette la guida"},{en:"The maximum amount allowed before driving",it:"La quantita massima consentita prima di guidare"}],correct:1,explain_en:"A standard drink contains 0.6 oz pure alcohol. One 12oz beer = one 5oz wine = one 1.5oz shot of 80-proof spirits.",explain_it:"Un drink standard contiene 0,6 oz di alcol puro. Una birra da 12 oz = un bicchiere di vino da 5 oz = un bicchierino da 1,5 oz di superalcolici."},
  {cat:"alcohol",en:"What is the Florida Sobriety Checkpoint law?",it:"Qual e la legge Florida sui posti di blocco per la sobriety?",options:[{en:"Sobriety checkpoints are illegal in Florida",it:"I posti di blocco per la sobriety sono illegali in Florida"},{en:"Sobriety checkpoints are legal and have been upheld as constitutional",it:"I posti di blocco per la sobriety sono legali e sono stati confermati come costituzionali"},{en:"Only county sheriffs may conduct them",it:"Solo gli sceriffi di contea possono condurli"},{en:"Checkpoints require a court order for each location",it:"I posti di blocco richiedono un ordine del tribunale per ogni posizione"}],correct:1,explain_en:"Florida allows DUI sobriety checkpoints. They must be publicly announced and follow specific protocols. Courts have upheld them as constitutional.",explain_it:"La Florida consente i posti di blocco DUI. Devono essere annunciati pubblicamente e seguire protocolli specifici."},
  {cat:"alcohol",en:"What is the minimum DUI revocation period for a first offense in Florida?",it:"Qual e il periodo minimo di revoca DUI per una prima infrazione in Florida?",options:[{en:"30 days",it:"30 giorni"},{en:"90 days",it:"90 giorni"},{en:"180 days",it:"180 giorni"},{en:"1 year",it:"1 anno"}],correct:2,explain_en:"First DUI Florida: minimum 180-day license revocation. With BAC 0.15%+ or minor passenger, minimum 1 year.",explain_it:"Primo DUI Florida: revoca minima della patente di 180 giorni. Con BAC 0,15%+ o passeggero minore, minimo 1 anno."},
  {cat:"license",en:"What is the Florida FR-44 insurance certificate?",it:"Cos'e il certificato assicurativo Florida FR-44?",options:[{en:"Standard liability insurance proof",it:"Prova standard di assicurazione di responsabilita"},{en:"High-limit insurance required after DUI -- $100,000/$300,000 BI and $50,000 PDL",it:"Assicurazione ad alto limite richiesta dopo DUI -- $100.000/$300.000 BI e $50.000 PDL"},{en:"Same as SR-22 but for motorcycles",it:"Uguale a SR-22 ma per le moto"},{en:"Proof of uninsured motorist coverage",it:"Prova di copertura automobilista non assicurato"}],correct:1,explain_en:"FR-44 is required after DUI conviction in Florida. It requires much higher liability limits than standard SR-22 and must be maintained for 3 years.",explain_it:"FR-44 e richiesto dopo la condanna DUI in Florida. Richiede limiti di responsabilita molto piu alti dello standard SR-22 e deve essere mantenuto per 3 anni."},
  {cat:"license",en:"What is the Florida law about using another person's driver's license?",it:"Qual e la legge Florida sull'uso della patente di un'altra persona?",options:[{en:"Legal if the person gives permission",it:"Legale se la persona da il permesso"},{en:"A criminal offense -- using another's license is fraud",it:"Un reato penale -- usare la patente di un'altra persona e frode"},{en:"Only illegal for minors buying alcohol",it:"Illegale solo per i minori che acquistano alcol"},{en:"Legal for identification only",it:"Legale solo per l'identificazione"}],correct:1,explain_en:"Using someone else's driver's license is a criminal offense in Florida -- identity fraud. Consequences include criminal charges, suspension, and fines.",explain_it:"Usare la patente di qualcun altro e un reato penale in Florida -- frode d'identita."},
  {cat:"license",en:"What is the Florida Motorcycle Endorsement requirement?",it:"Qual e il requisito per l'approvazione moto Florida?",options:[{en:"No special endorsement needed",it:"Nessuna approvazione speciale necessaria"},{en:"Must pass a motorcycle skills test or complete an approved safety course",it:"Deve superare un test di abilita moto o completare un corso di sicurezza approvato"},{en:"Only required for motorcycles over 500cc",it:"Richiesta solo per moto superiori a 500cc"},{en:"Same as a regular Class E license",it:"Uguale a una regolare patente Class E"}],correct:1,explain_en:"To ride a motorcycle in Florida you need a Class E license with a motorcycle endorsement. Pass the BASIC RiderCourse or motorcycle skills test.",explain_it:"Per guidare una moto in Florida hai bisogno di una patente Class E con approvazione moto. Supera il BASIC RiderCourse o il test di abilita moto."},
  {cat:"license",en:"What are the GDL restrictions for a 16-17 year old in Florida?",it:"Quali sono le restrizioni GDL per un 16-17enne in Florida?",options:[{en:"No restrictions",it:"Nessuna restrizione"},{en:"No driving 11pm-6am; no more than 1 non-family passenger under 18 for first 12 months",it:"Nessuna guida 23:00-6:00; non piu di 1 passeggero non familiare under 18 per i primi 12 mesi"},{en:"No driving on highways",it:"Nessuna guida in autostrada"},{en:"Must be home by 10pm",it:"Deve essere a casa entro le 22"}],correct:1,explain_en:"Florida GDL for 16-17 year-olds: no driving 11pm-6am except work/school/emergency with documentation. First 12 months: no more than 1 non-household passenger under 18.",explain_it:"GDL Florida per 16-17 anni: nessuna guida 23:00-6:00 eccetto lavoro/scuola/emergenza. Primi 12 mesi: non piu di 1 passeggero non convivente under 18."},
  {cat:"license",en:"What is the SR-22 certificate and when is it required in Florida?",it:"Cos'e il certificato SR-22 e quando e richiesto in Florida?",options:[{en:"A safe driver reward certificate",it:"Un certificato di premio per conducente sicuro"},{en:"Proof of financial responsibility required after certain violations",it:"Prova di responsabilita finanziaria richiesta dopo determinate violazioni"},{en:"Required for all commercial drivers",it:"Richiesto per tutti i conducenti commerciali"},{en:"An optional insurance upgrade",it:"Un aggiornamento assicurativo opzionale"}],correct:1,explain_en:"SR-22 certifies to FLHSMV that you maintain minimum liability coverage. Required after certain serious violations. For DUI, Florida uses FR-44 instead.",explain_it:"SR-22 certifica al FLHSMV che si mantiene la copertura minima. Richiesto dopo determinate violazioni gravi. Per DUI, la Florida usa FR-44."},
  {cat:"license",en:"What is required to convert a foreign driver's license to a Florida license?",it:"Cosa e richiesto per convertire una patente straniera in una patente Florida?",options:[{en:"Foreign licenses are automatically valid in Florida permanently",it:"Le patenti straniere sono automaticamente valide in Florida"},{en:"Must pass knowledge and vision tests and provide proof of identity, residency, and SSN or immigration status",it:"Deve superare i test di conoscenza e visione e fornire prova di identita, residenza e SSN o stato di immigrazione"},{en:"Only a vision test is required",it:"Solo un test della visione e richiesto"},{en:"Cannot be converted -- must start from scratch",it:"Non puo essere convertita"}],correct:1,explain_en:"To convert a foreign license to Florida: pass knowledge and vision tests, provide proof of identity, SSN or immigration status, and two Florida residency proofs.",explain_it:"Per convertire una patente straniera in Florida: superare i test di conoscenza e visione, fornire prova d'identita, SSN o stato di immigrazione e due prove di residenza."},
  {cat:"license",en:"What is Florida's law on motorcycle helmet requirements?",it:"Qual e la legge Florida sui caschi per moto?",options:[{en:"Helmets required for all riders always",it:"Caschi obbligatori per tutti sempre"},{en:"Riders over 21 with at least $10,000 medical insurance may ride without a helmet",it:"I motociclisti over 21 con almeno $10.000 di assicurazione medica possono guidare senza casco"},{en:"Helmets only required at highway speeds",it:"Caschi richiesti solo alle velocita autostradali"},{en:"No helmet law in Florida",it:"Nessuna legge sul casco in Florida"}],correct:1,explain_en:"Florida helmet law: riders and passengers 21+ may ride without a helmet IF they have at least $10,000 in medical insurance. Under 21: always required.",explain_it:"Legge sul casco Florida: i motociclisti 21+ possono guidare senza casco SE hanno almeno $10.000 di assicurazione medica. Under 21: sempre obbligatori."},
  {cat:"license",en:"What is the minimum age for a Florida learner's permit?",it:"Qual e l'eta minima per il permesso per principianti Florida?",options:[{en:"14 years old",it:"14 anni"},{en:"15 years old",it:"15 anni"},{en:"16 years old",it:"16 anni"},{en:"17 years old",it:"17 anni"}],correct:1,explain_en:"Florida's minimum age for a learner's license is 15 years old.",explain_it:"L'eta minima per il permesso per principianti Florida e 15 anni."},
  {cat:"license",en:"What is the minimum age for a full unrestricted Class E license in Florida?",it:"Qual e l'eta minima per la patente Class E completa senza restrizioni?",options:[{en:"16 years old",it:"16 anni"},{en:"17 years old",it:"17 anni"},{en:"18 years old",it:"18 anni"},{en:"21 years old",it:"21 anni"}],correct:2,explain_en:"A full unrestricted Florida Class E license requires age 18. Drivers 16-17 hold a provisional license with GDL restrictions that lift at 18.",explain_it:"Una patente Florida Class E completa richiede 18 anni. I conducenti di 16-17 anni hanno una patente provvisoria con restrizioni GDL che si tolgono a 18 anni."},
  {cat:"license",en:"What documents are required to apply for a first Florida driver's license?",it:"Quali documenti sono richiesti per richiedere la prima patente Florida?",options:[{en:"A utility bill and verbal statement",it:"Una bolletta e una dichiarazione verbale"},{en:"Primary ID (birth certificate/passport), Social Security number, and two proofs of Florida residency",it:"ID principale (certificato di nascita/passaporto), numero di previdenza sociale e due prove di residenza in Florida"},{en:"Only a passport is required",it:"E richiesto solo il passaporto"},{en:"School ID and parent signature",it:"Carta d'identita scolastica e firma del genitore"}],correct:1,explain_en:"First Florida license requires: proof of identity, Social Security number, and two proofs of Florida residential address.",explain_it:"La prima patente Florida richiede: prova d'identita, numero di previdenza sociale e due prove di indirizzo residenziale in Florida."},

  // SESSION 7 SIGNS+LAWS
  {cat:"signs",en:"What does a flashing yellow traffic light mean?",it:"Cosa significa un semaforo giallo lampeggiante?",options:[{en:"Stop completely",it:"Fermarsi completamente"},{en:"Proceed with caution -- slow down and watch for cross traffic",it:"Procedere con cautela -- rallentare e fare attenzione al traffico trasversale"},{en:"Speed up before it turns red",it:"Accelerare prima che diventi rosso"},{en:"Same as a solid yellow -- prepare to stop",it:"Uguale al giallo fisso -- prepararsi a fermarsi"}],correct:1,explain_en:"A flashing yellow light means proceed with caution. Slow down, check for cross traffic, and be prepared to stop if necessary.",explain_it:"Un semaforo giallo lampeggiante significa procedere con cautela. Rallentare, controllare il traffico trasversale ed essere pronti a fermarsi."},
  {cat:"signs",en:"What does a flashing red traffic light mean?",it:"Cosa significa un semaforo rosso lampeggiante?",options:[{en:"Slow down and proceed",it:"Rallentare e procedere"},{en:"Stop completely -- treat it like a stop sign",it:"Fermarsi completamente -- trattarlo come un segnale di stop"},{en:"Only pedestrians must stop",it:"Solo i pedoni devono fermarsi"},{en:"The light is malfunctioning -- ignore it",it:"Il semaforo e in avaria -- ignorarlo"}],correct:1,explain_en:"A flashing red light has the same meaning as a stop sign: come to a complete stop, yield to cross traffic, then proceed when safe.",explain_it:"Un semaforo rosso lampeggiante ha lo stesso significato di un segnale di stop: fermarsi completamente, cedere al traffico trasversale, poi procedere."},
  {cat:"signs",en:"What does a green arrow on a traffic signal mean?",it:"Cosa significa una freccia verde su un semaforo?",options:[{en:"Proceed with caution in that direction",it:"Procedere con cautela in quella direzione"},{en:"Protected movement -- traffic in the indicated direction has the right of way with no conflicting traffic",it:"Movimento protetto -- il traffico nella direzione indicata ha la precedenza senza traffico in conflitto"},{en:"You may turn only if no pedestrians are present",it:"Puoi svoltare solo se non ci sono pedoni"},{en:"Advisory only -- yield to oncoming traffic",it:"Solo advisory -- cedere al traffico in arrivo"}],correct:1,explain_en:"A green arrow indicates a protected turn -- no conflicting traffic is permitted. You may proceed in the arrow's direction without yielding to oncoming traffic.",explain_it:"Una freccia verde indica una svolta protetta -- nessun traffico in conflitto e consentito. Puoi procedere nella direzione della freccia senza cedere."},
  {cat:"signs",en:"What does a red 'X' above a lane on an overhead sign mean?",it:"Cosa significa una 'X' rossa sopra una corsia su un segnale sopraelevato?",options:[{en:"Speed limit 10 mph in that lane",it:"Limite di velocita 10 mph in quella corsia"},{en:"That lane is closed -- do not use it",it:"Quella corsia e chiusa -- non usarla"},{en:"Toll lane only",it:"Solo corsia a pedaggio"},{en:"Lane reserved for HOV vehicles",it:"Corsia riservata ai veicoli HOV"}],correct:1,explain_en:"A red X over a lane on a variable message or overhead sign means that lane is closed. Move out of that lane immediately.",explain_it:"Una X rossa sopra una corsia su un segnale variabile o sopraelevato significa che quella corsia e chiusa. Uscire immediatamente da quella corsia."},
  {cat:"signs",en:"What does a green arrow pointing down above a lane indicate?",it:"Cosa indica una freccia verde rivolta verso il basso sopra una corsia?",options:[{en:"Merge required in this lane",it:"Confluenza richiesta in questa corsia"},{en:"This lane is open and available for use",it:"Questa corsia e aperta e disponibile per l'uso"},{en:"Trucks only in this lane",it:"Solo camion in questa corsia"},{en:"Carpool lane ahead",it:"Corsia carpool in avanti"}],correct:1,explain_en:"A downward-pointing green arrow over a lane on an overhead sign means the lane is open for travel.",explain_it:"Una freccia verde rivolta verso il basso sopra una corsia su un segnale sopraelevato significa che la corsia e aperta al traffico."},
  {cat:"signs",en:"What does a 'Reduce Speed Ahead' sign mean?",it:"Cosa significa un segnale 'Reduce Speed Ahead'?",options:[{en:"Speed limit is eliminated ahead",it:"Il limite di velocita e eliminato in avanti"},{en:"A lower speed limit zone begins ahead -- start slowing down now",it:"Una zona a limite di velocita piu basso inizia in avanti -- iniziare a rallentare ora"},{en:"Advisory only -- no legal requirement",it:"Solo advisory -- nessun requisito legale"},{en:"Only applies to trucks",it:"Si applica solo ai camion"}],correct:1,explain_en:"Reduce Speed Ahead warns that a lower posted speed limit zone is coming. Begin reducing speed before reaching the new limit sign.",explain_it:"Reduce Speed Ahead avvisa che si sta avvicinando una zona con limite di velocita piu basso. Inizia a ridurre la velocita prima di raggiungere il nuovo segnale."},
  {cat:"signs",en:"What does 'SLOWER TRAFFIC KEEP RIGHT' sign mean?",it:"Cosa significa il segnale 'SLOWER TRAFFIC KEEP RIGHT'?",options:[{en:"Slow vehicles must pull off the road",it:"I veicoli lenti devono accostare fuori dalla strada"},{en:"Vehicles moving slower than surrounding traffic must move to the right lane",it:"I veicoli che si muovono piu lentamente del traffico circostante devono spostarsi nella corsia destra"},{en:"Only applies to trucks",it:"Si applica solo ai camion"},{en:"Advisory only -- no legal requirement",it:"Solo advisory"}],correct:1,explain_en:"Slower Traffic Keep Right signs remind drivers to stay right if traveling below the prevailing traffic speed. Left lanes are for passing.",explain_it:"I segnali Slower Traffic Keep Right ricordano ai conducenti di stare a destra se viaggiano sotto la velocita del traffico prevalente."},
  {cat:"signs",en:"What does a 'Truck Route' sign indicate?",it:"Cosa indica un segnale 'Truck Route'?",options:[{en:"Trucks are prohibited on this road",it:"I camion sono vietati su questa strada"},{en:"A designated route for commercial trucks -- preferred path to avoid restricted roads",it:"Un percorso designato per i camion commerciali -- percorso preferito per evitare strade con restrizioni"},{en:"This road has extra-wide lanes for trucks",it:"Questa strada ha corsie extra-larghe per i camion"},{en:"Trucks must pay a toll here",it:"I camion devono pagare un pedaggio qui"}],correct:1,explain_en:"Truck Route signs designate roads approved for commercial truck use. Truckers should use these to avoid weight, height, or width restrictions on other roads.",explain_it:"I segnali Truck Route designano strade approvate per i camion commerciali. I camionisti dovrebbero usarle per evitare restrizioni su altre strade."},
  {cat:"signs",en:"What does a 'Road Closed' sign mean?",it:"Cosa significa un segnale 'Road Closed'?",options:[{en:"Road open to local traffic only",it:"Strada aperta solo al traffico locale"},{en:"The road ahead is completely closed -- a detour must be used",it:"La strada in avanti e completamente chiusa -- deve essere usata una deviazione"},{en:"Road temporarily closed only at night",it:"Strada temporaneamente chiusa solo di notte"},{en:"Slow to 5 mph to pass through",it:"Rallentare a 5 mph per passare"}],correct:1,explain_en:"Road Closed means the route ahead is completely blocked. Follow detour signs -- do not attempt to pass through.",explain_it:"Road Closed significa che il percorso in avanti e completamente bloccato. Seguire i segnali di deviazione -- non tentare di passare."},
  {cat:"signs",en:"What does a 'Detour' sign indicate?",it:"Cosa indica un segnale 'Detour'?",options:[{en:"An optional alternate route",it:"Un percorso alternativo opzionale"},{en:"A required alternate route because the normal road is closed or impassable",it:"Un percorso alternativo obbligatorio perche la strada normale e chiusa o impraticabile"},{en:"A scenic bypass route",it:"Un percorso panoramico"},{en:"A temporary speed zone",it:"Una zona di velocita temporanea"}],correct:1,explain_en:"Detour signs direct you to follow an alternate route because the normal road is closed. Follow the detour signs until the route rejoins the original road.",explain_it:"I segnali Detour ti indirizzano a seguire un percorso alternativo perche la strada normale e chiusa. Seguire i segnali di deviazione fino a quando il percorso si ricollega alla strada originale."},
  {cat:"signs",en:"What does a 'One Way' sign mean?",it:"Cosa significa un segnale 'One Way'?",options:[{en:"Single lane road ahead",it:"Strada a corsia singola in avanti"},{en:"Traffic flows in only one direction on this road",it:"Il traffico scorre in una sola direzione su questa strada"},{en:"Turn in the direction of the arrow only",it:"Girare solo nella direzione della freccia"},{en:"Pedestrian one-way path",it:"Percorso pedonale a senso unico"}],correct:1,explain_en:"One Way signs indicate traffic flows in a single direction. Wrong-way entry is prohibited and extremely dangerous.",explain_it:"I segnali One Way indicano che il traffico scorre in una singola direzione. L'ingresso contromano e vietato ed estremamente pericoloso."},
  {cat:"signs",en:"What does a 'Begin No Passing Zone' sign tell you?",it:"Cosa ti dice un segnale 'Begin No Passing Zone'?",options:[{en:"You may begin passing here",it:"Puoi iniziare il sorpasso qui"},{en:"Passing is now prohibited -- do not attempt to pass any vehicle",it:"Il sorpasso e ora vietato -- non tentare di sorpassare nessun veicolo"},{en:"Only trucks may not pass in this zone",it:"Solo i camion non possono sorpassare in questa zona"},{en:"The passing zone ahead ends",it:"La zona di sorpasso in avanti finisce"}],correct:1,explain_en:"Begin No Passing Zone marks the start of a zone where overtaking is prohibited. Solid yellow lines on the road reinforce this restriction.",explain_it:"Begin No Passing Zone segna l'inizio di una zona dove il sorpasso e vietato. Le linee gialle continue sulla strada rinforzano questa restrizione."},
  {cat:"signs",en:"What color are guide signs that direct drivers to hospitals, food, and fuel?",it:"Di che colore sono i segnali guida che indirizzano i conducenti a ospedali, cibo e carburante?",options:[{en:"Green",it:"Verde"},{en:"Blue",it:"Blu"},{en:"Brown",it:"Marrone"},{en:"White",it:"Bianco"}],correct:1,explain_en:"Blue signs indicate motorist services including hospitals (H), gas, food, lodging. They help travelers find essential services at upcoming exits.",explain_it:"I segnali blu indicano i servizi per automobilisti tra cui ospedali (H), benzina, cibo, alloggio."},
  {cat:"signs",en:"What do white lane markings on the road generally separate?",it:"Cosa separano generalmente le segnaletica bianca in corsia sulla strada?",options:[{en:"Opposing flows of traffic",it:"Flussi di traffico opposti"},{en:"Traffic moving in the same direction",it:"Traffico che si muove nella stessa direzione"},{en:"Bicycle lanes from car lanes",it:"Corsie ciclabili dalle corsie auto"},{en:"Turning lanes from through lanes",it:"Corsie di svolta dalle corsie diritte"}],correct:1,explain_en:"White lane markings separate traffic moving in the same direction. Yellow markings separate opposing traffic flows.",explain_it:"Le segnaletica bianca in corsia separa il traffico che si muove nella stessa direzione. La segnaletica gialla separa i flussi di traffico opposti."},
  {cat:"signs",en:"What does a solid yellow center line on your side of the road mean?",it:"Cosa significa una linea centrale gialla continua sul tuo lato della strada?",options:[{en:"Passing is permitted when clear",it:"Il sorpasso e consentito quando libero"},{en:"No passing from your side -- the solid line is on your side",it:"Nessun sorpasso dal tuo lato -- la linea continua e sul tuo lato"},{en:"Passing allowed only for emergency vehicles",it:"Sorpasso consentito solo per i veicoli di emergenza"},{en:"The road is a divided highway",it:"La strada e un'autostrada divisa"}],correct:1,explain_en:"A solid yellow line on your side prohibits passing from your direction. A dashed line on your side means passing is permitted when safe.",explain_it:"Una linea gialla continua sul tuo lato vieta il sorpasso dalla tua direzione. Una linea tratteggiata sul tuo lato significa che il sorpasso e consentito quando sicuro."},
  {cat:"signs",en:"What does a 'Hill Blocks View' sign warn you about?",it:"Cosa ti avvisa un segnale 'Hill Blocks View'?",options:[{en:"A hill causes reduced visibility -- you cannot see over it",it:"Una collina causa visibilita ridotta -- non riesci a vederci sopra"},{en:"Scenic view area ahead",it:"Area panoramica in avanti"},{en:"Road ends at the top of the hill",it:"La strada finisce in cima alla collina"},{en:"Runaway truck ramp on the hill",it:"Rampa per camion in fuga sulla collina"}],correct:0,explain_en:"Hill Blocks View warns that a hill ahead prevents you from seeing oncoming traffic. Do not attempt to pass and slow down.",explain_it:"Hill Blocks View avvisa che una collina in avanti impedisce di vedere il traffico in arrivo. Non tentare di sorpassare e rallentare."},
  {cat:"signs",en:"What is the meaning of yellow diagonal stripes painted on the road?",it:"Qual e il significato delle strisce diagonali gialle dipinte sulla strada?",options:[{en:"A bike lane begins",it:"Inizia una corsia ciclabile"},{en:"A non-drivable area -- do not drive on diagonal stripes",it:"Un'area non guidabile -- non guidare sulle strisce diagonali"},{en:"A pedestrian crossing zone",it:"Una zona di attraversamento pedonale"},{en:"A speed bump warning",it:"Un avvertimento di dosso"}],correct:1,explain_en:"Diagonal yellow stripes (channelizing markings) indicate areas you may not drive on -- typically before islands, medians, or at intersections.",explain_it:"Le strisce diagonali gialle (segnaletica di canalizzazione) indicano aree su cui non si puo guidare -- tipicamente prima delle isole, dei mediani o agli incroci."},
  {cat:"signs",en:"What does a 'Runaway Truck Ramp' sign indicate?",it:"Cosa indica un segnale 'Runaway Truck Ramp'?",options:[{en:"A truck weigh station",it:"Una stazione di pesatura camion"},{en:"An escape ramp for trucks whose brakes have failed on a downhill grade",it:"Una rampa di fuga per camion i cui freni si sono guastati in discesa"},{en:"A restricted truck route",it:"Un percorso camion ristretto"},{en:"A truck rest area",it:"Un'area di sosta camion"}],correct:1,explain_en:"Runaway truck ramps are emergency escape routes on steep downgrades for trucks with brake failure. They are filled with deep gravel or sand to stop the vehicle.",explain_it:"Le rampe di fuga per camion sono vie di fuga di emergenza nelle discese ripide per camion con guasto ai freni. Sono riempite di ghiaia profonda o sabbia per fermare il veicolo."},
  {cat:"signs",en:"What does a 'Hairpin Curve' sign tell a driver?",it:"Cosa dice a un conducente un segnale 'Hairpin Curve'?",options:[{en:"A gentle curve is ahead",it:"Una curva dolce e in avanti"},{en:"An extremely sharp U-shaped curve ahead requiring significant speed reduction",it:"Una curva a U estremamente stretta in avanti che richiede una significativa riduzione della velocita"},{en:"The road ends here",it:"La strada finisce qui"},{en:"Only motorcycles may proceed",it:"Solo le moto possono procedere"}],correct:1,explain_en:"A hairpin curve is an extremely tight bend -- nearly 180 degrees. Speed must be reduced significantly before entering. These are common in mountainous areas.",explain_it:"Una curva a gomito e una curva estremamente stretta -- quasi 180 gradi. La velocita deve essere ridotta significativamente prima di entrare."},
  {cat:"signs",en:"What does a 'Soft Shoulder' sign warn about?",it:"Cosa avvisa un segnale 'Soft Shoulder'?",options:[{en:"The shoulder is paved and safe to use",it:"La banchina e asfaltata e sicura da usare"},{en:"The road shoulder is unstable -- driving or stopping on it may cause a vehicle to sink or tip",it:"La banchina stradale e instabile -- guidare o fermarsi su di essa puo causare l'affondamento o il ribaltamento di un veicolo"},{en:"The shoulder is closed for construction",it:"La banchina e chiusa per lavori"},{en:"The road surface ahead is soft",it:"La superficie stradale in avanti e morbida"}],correct:1,explain_en:"Soft Shoulder warns that the unpaved shoulder is not firm -- it may not support vehicle weight. Driving off the pavement onto a soft shoulder can cause loss of control.",explain_it:"Soft Shoulder avvisa che la banchina non asfaltata non e solida -- potrebbe non supportare il peso del veicolo."},
  {cat:"signs",en:"What does a 'Falling Rocks' warning sign indicate?",it:"Cosa indica un segnale di avvertimento 'Falling Rocks'?",options:[{en:"A rock quarry is nearby",it:"Una cava di pietra e nelle vicinanze"},{en:"Rocks may fall or be present on the road ahead -- watch for debris",it:"Le rocce possono cadere o essere presenti sulla strada in avanti -- fare attenzione ai detriti"},{en:"The road is under construction",it:"La strada e in costruzione"},{en:"You are entering a national park",it:"Stai entrando in un parco nazionale"}],correct:1,explain_en:"Falling Rocks warning signs are common in hilly or mountainous areas. Rocks may be on the road or falling -- slow down and watch for debris.",explain_it:"I segnali di avvertimento Falling Rocks sono comuni nelle zone collinari o montuose. Le rocce possono essere sulla strada o cadere -- rallentare e fare attenzione ai detriti."},
  {cat:"signs",en:"What does a 'Road Slippery When Wet' (wavy lines) pavement marking mean?",it:"Cosa significa una segnaletica stradale 'Road Slippery When Wet' (linee ondulate)?",options:[{en:"This is a bike lane",it:"Questa e una corsia ciclabile"},{en:"The pavement surface here has reduced skid resistance when wet",it:"La superficie del manto stradale qui ha ridotta resistenza allo scivolamento quando bagnata"},{en:"Winding road ahead",it:"Strada tortuosa in avanti"},{en:"Pedestrian crossing nearby",it:"Attraversamento pedonale nelle vicinanze"}],correct:1,explain_en:"Wavy pavement markings warn of reduced skid resistance on that surface -- common on bridge approaches, steel plates, or treated pavement. Slow down when wet.",explain_it:"Le segnaletica stradale ondulata avvisa di ridotta resistenza allo scivolamento su quella superficie -- comune sugli accessi ai ponti, sulle piastre in acciaio o sul manto trattato."},
  {cat:"signs",en:"What does a 'Traffic Circles Ahead' sign tell you to do?",it:"Cosa ti dice un segnale 'Traffic Circles Ahead' di fare?",options:[{en:"Stop and yield to all traffic",it:"Fermarsi e cedere a tutto il traffico"},{en:"Prepare to enter a roundabout -- yield to circulating traffic and follow the circle",it:"Prepararsi a entrare in una rotonda -- cedere al traffico in circolazione e seguire il cerchio"},{en:"Turn around -- no through road",it:"Girare indietro -- nessuna strada di transito"},{en:"Only right turns at the circle",it:"Solo svolte destre alla rotonda"}],correct:1,explain_en:"Traffic circle ahead: reduce speed, prepare to yield to traffic already in the circle, and enter when a safe gap appears. Travel counterclockwise.",explain_it:"Rotonda in avanti: ridurre la velocita, prepararsi a cedere al traffico gia nella rotonda ed entrare quando appare uno spazio sicuro."},
  {cat:"signs",en:"What does a 'Truck Escape Ramp -- 1 Mile' sign mean for car drivers?",it:"Cosa significa un segnale 'Truck Escape Ramp -- 1 Mile' per i conducenti di auto?",options:[{en:"Merge right to make room for trucks",it:"Confluire a destra per fare spazio ai camion"},{en:"Be aware that runaway trucks may use an escape ramp ahead -- stay alert",it:"Essere consapevoli che i camion in fuga possono usare una rampa di fuga in avanti -- stare all'erta"},{en:"Car drivers must exit at this ramp",it:"I conducenti di auto devono uscire a questa rampa"},{en:"Trucks are prohibited beyond this point",it:"I camion sono vietati oltre questo punto"}],correct:1,explain_en:"Truck escape ramp signs alert all drivers. If a runaway truck is behind you on a steep grade, be aware it may suddenly turn off onto the ramp.",explain_it:"I segnali di rampa di fuga per camion avvisano tutti i conducenti. Se un camion in fuga e dietro di te in una discesa ripida, sii consapevole che potrebbe improvvisamente svoltare sulla rampa."},
  {cat:"signs",en:"What does a sign showing a school bus with flashing lights require you to do?",it:"Cosa richiede di fare un segnale che mostra uno scuolabus con luci lampeggianti?",options:[{en:"Slow to 15 mph",it:"Rallentare a 15 mph"},{en:"Stop completely and remain stopped until the stop arm retracts and bus moves",it:"Fermarsi completamente e rimanere fermi finche il braccio di stop non si ritrae e il bus non si muove"},{en:"Proceed slowly if no children are visible",it:"Procedere lentamente se non ci sono bambini visibili"},{en:"Only applicable on school days",it:"Applicabile solo nei giorni scolastici"}],correct:1,explain_en:"When a school bus has flashing red lights and its stop arm extended, ALL traffic must stop and wait until the arm retracts and the bus moves.",explain_it:"Quando uno scuolabus ha luci rosse lampeggianti e il braccio di stop esteso, TUTTO il traffico deve fermarsi e aspettare finche il braccio si ritrae e il bus si muove."},
  {cat:"laws",en:"What is the Florida law on yielding to pedestrians in a crosswalk?",it:"Qual e la legge Florida sulla precedenza ai pedoni in un attraversamento?",options:[{en:"Pedestrians must wait for traffic to clear",it:"I pedoni devono aspettare che il traffico si liberi"},{en:"Drivers must stop for pedestrians who are in or about to enter a marked or unmarked crosswalk",it:"I conducenti devono fermarsi per i pedoni che sono nell'attraversamento o stanno per entrarci"},{en:"Only at crosswalks with painted lines",it:"Solo agli attraversamenti con linee dipinte"},{en:"Yield only if the pedestrian has stepped off the curb",it:"Cedere solo se il pedone ha fatto un passo dal marciapiede"}],correct:1,explain_en:"Florida requires drivers to stop for pedestrians who are in or about to enter ANY crosswalk -- marked or unmarked. Failure to yield is a serious moving violation.",explain_it:"La Florida richiede ai conducenti di fermarsi per i pedoni che sono in o stanno per entrare in QUALSIASI attraversamento -- segnalato o meno."},
  {cat:"laws",en:"In Florida, who has the right of way at a T-intersection where one road ends?",it:"In Florida, chi ha la precedenza a un incrocio a T dove una strada finisce?",options:[{en:"The vehicle on the road that ends",it:"Il veicolo sulla strada che finisce"},{en:"Traffic on the through road -- vehicles entering from the ending road must yield",it:"Il traffico sulla strada continua -- i veicoli che entrano dalla strada che finisce devono cedere"},{en:"The first vehicle to arrive",it:"Il primo veicolo ad arrivare"},{en:"The larger vehicle",it:"Il veicolo piu grande"}],correct:1,explain_en:"At a T-intersection, traffic on the through road has the right of way. Vehicles on the road that ends must yield before entering the through road.",explain_it:"A un incrocio a T, il traffico sulla strada continua ha la precedenza. I veicoli sulla strada che finisce devono cedere prima di entrare nella strada continua."},
  {cat:"laws",en:"What is the Florida law about driving while impaired by a legal prescription drug?",it:"Qual e la legge Florida sulla guida mentre si e sotto l'effetto di un farmaco da prescrizione legale?",options:[{en:"Legal -- prescription drugs are always allowed",it:"Legale -- i farmaci da prescrizione sono sempre consentiti"},{en:"Illegal if the drug impairs driving ability -- a valid prescription is not a defense to DUI",it:"Illegale se il farmaco compromette la capacita di guida -- una prescrizione valida non e una difesa al DUI"},{en:"Only illegal if combined with alcohol",it:"Illegale solo se combinato con l'alcol"},{en:"Legal at the recommended dosage",it:"Legale al dosaggio raccomandato"}],correct:1,explain_en:"Florida DUI law covers impairment by any substance including legal prescription medications. If a drug impairs your driving, you can be charged with DUI regardless of a valid prescription.",explain_it:"La legge DUI della Florida copre la compromissione da qualsiasi sostanza inclusi i farmaci da prescrizione legali. Se un farmaco compromette la guida, puoi essere accusato di DUI."},
  {cat:"laws",en:"What is the Florida law about racing on public roads?",it:"Qual e la legge Florida sulle gare su strade pubbliche?",options:[{en:"Legal if both drivers consent",it:"Legale se entrambi i conducenti acconsentono"},{en:"Street racing is a criminal offense in Florida with mandatory license revocation",it:"Le gare in strada sono un reato penale in Florida con revoca obbligatoria della patente"},{en:"Only illegal above 100 mph",it:"Illegale solo sopra i 100 mph"},{en:"A civil violation with a $100 fine",it:"Una violazione civile con una multa di $100"}],correct:1,explain_en:"Street racing in Florida is a first-degree misdemeanor -- up to 1 year imprisonment, $1,000 fine, and 1-year license revocation for first offense. Repeat offenses are felonies.",explain_it:"Le gare in strada in Florida sono una contravvenzione di primo grado -- fino a 1 anno di prigione, multa di $1.000 e revoca della patente di 1 anno per la prima infrazione."},
  {cat:"laws",en:"What is Florida's law on the minimum age to rent a car?",it:"Qual e la legge Florida sull'eta minima per noleggiare un'auto?",options:[{en:"16 years old",it:"16 anni"},{en:"18 years old",it:"18 anni"},{en:"21 years old (most rental companies)",it:"21 anni (la maggior parte delle societa di noleggio)"},{en:"25 years old",it:"25 anni"}],correct:2,explain_en:"While Florida law allows driving at 16 with a license, most car rental companies require renters to be 21+ (some allow 18-20 with a surcharge).",explain_it:"Mentre la legge Florida consente di guidare a 16 anni con la patente, la maggior parte delle societa di noleggio richiede che i noleggiatori abbiano 21+ anni."},
  {cat:"laws",en:"What is the Florida law on right-of-way when merging from an on-ramp?",it:"Qual e la legge Florida sulla precedenza quando si confluisce da una rampa di accesso?",options:[{en:"Merging traffic always has the right of way",it:"Il traffico che confluisce ha sempre la precedenza"},{en:"Merging traffic must yield to highway traffic -- highway drivers should make room if safely possible",it:"Il traffico che confluisce deve cedere al traffico autostradale -- i conducenti autostradali dovrebbero fare spazio se possibile in sicurezza"},{en:"Highway traffic must always yield to merging traffic",it:"Il traffico autostradale deve sempre cedere al traffico che confluisce"},{en:"First to the merge point has right of way",it:"Chi arriva prima al punto di confluenza ha la precedenza"}],correct:1,explain_en:"Merging vehicles must yield to highway traffic. However, highway drivers should cooperate by adjusting speed or changing lanes when it is safe to do so.",explain_it:"I veicoli che confluiscono devono cedere al traffico autostradale. Tuttavia, i conducenti autostradali dovrebbero cooperare regolando la velocita o cambiando corsia quando sicuro."},
  {cat:"laws",en:"What is Florida's law on mopeds and scooters with engines under 50cc?",it:"Qual e la legge Florida sui motorini e scooter con motori sotto i 50cc?",options:[{en:"No license required",it:"Nessuna patente richiesta"},{en:"A valid Class E driver's license or learner's permit required -- may not ride on limited-access highways",it:"Richiesta una valida patente Class E o permesso -- non puo circolare sulle autostrade a accesso limitato"},{en:"Only a motorcycle endorsement needed",it:"E necessaria solo l'approvazione moto"},{en:"Any person over 14 may operate without a license",it:"Qualsiasi persona over 14 puo operarlo senza patente"}],correct:1,explain_en:"In Florida, mopeds (under 50cc, max 30 mph) require a valid driver's license or learner's permit. They cannot be operated on sidewalks or limited-access highways.",explain_it:"In Florida, i motorini (sotto 50cc, max 30 mph) richiedono una valida patente o permesso. Non possono essere operati su marciapiedi o autostrade a accesso limitato."},
  {cat:"laws",en:"What is the Florida law about backing a vehicle on a highway?",it:"Qual e la legge Florida sulla retromarcia in autostrada?",options:[{en:"Legal if done slowly",it:"Legale se fatto lentamente"},{en:"Illegal -- you may not back up on a limited-access highway or its ramps",it:"Illegale -- non puoi fare retromarcia su un'autostrada a accesso limitato o le sue rampe"},{en:"Legal only in emergencies",it:"Legale solo nelle emergenze"},{en:"Only prohibited for trucks",it:"Vietato solo per i camion"}],correct:1,explain_en:"Backing on a limited-access highway (interstate/freeway) or its entrance/exit ramps is illegal in Florida and extremely dangerous.",explain_it:"Fare retromarcia su un'autostrada a accesso limitato (interstatale/autostrada) o le sue rampe di entrata/uscita e illegale in Florida ed estremamente pericoloso."},
  {cat:"laws",en:"What is the Florida law about passing a stopped school bus in a school parking lot?",it:"Qual e la legge Florida sul superamento di uno scuolabus fermo in un parcheggio scolastico?",options:[{en:"Private property rules apply -- no stopping required",it:"Si applicano le regole della proprieta privata -- nessuna fermata richiesta"},{en:"Must still stop when red lights flash and stop arm is extended -- even on private property like school lots",it:"Deve comunque fermarsi quando le luci rosse lampeggiano e il braccio di stop e esteso -- anche su proprieta privata come i parcheggi scolastici"},{en:"Only stop on public roads",it:"Fermarsi solo sulle strade pubbliche"},{en:"Slow to 5 mph is sufficient",it:"Rallentare a 5 mph e sufficiente"}],correct:1,explain_en:"Florida's school bus stop law applies wherever the bus is loading/unloading students -- including school parking lots and private property.",explain_it:"La legge Florida sulla fermata degli scuolabus si applica ovunque il bus stia caricando/scaricando studenti -- inclusi i parcheggi scolastici e le proprieta private."},
  {cat:"laws",en:"What is the Florida law on vehicles yielding to transit buses re-entering traffic?",it:"Qual e la legge Florida sui veicoli che cedono agli autobus di transito che rientrano nel traffico?",options:[{en:"Buses must yield to all traffic when re-entering",it:"Gli autobus devono cedere a tutto il traffico quando rientrano"},{en:"Drivers must yield to transit buses signaling to re-enter traffic from a bus stop",it:"I conducenti devono cedere agli autobus di transito che segnalano di rientrare nel traffico da una fermata"},{en:"No law requires yielding to buses",it:"Nessuna legge richiede di cedere agli autobus"},{en:"Only yield if the bus has already moved into the lane",it:"Cedere solo se il bus si e gia spostato nella corsia"}],correct:1,explain_en:"Florida law: you must yield to transit buses signaling to pull out from a designated bus stop into traffic. The bus has the right of way when signaling to re-enter.",explain_it:"Legge Florida: devi cedere agli autobus di transito che segnalano di uscire da una fermata designata nel traffico. Il bus ha la precedenza quando segnala di rientrare."},
  {cat:"laws",en:"What is the Florida law on the use of a wireless communications device while driving in school zones?",it:"Qual e la legge Florida sull'uso di un dispositivo di comunicazione wireless durante la guida nelle zone scolastiche?",options:[{en:"Same as everywhere else -- only texting is banned",it:"Uguale a ovunque -- solo l'invio di messaggi e vietato"},{en:"All handheld wireless device use is prohibited in school and work zones -- hands-free only",it:"Tutto l'uso di dispositivi wireless portatili e vietato nelle zone scolastiche e di lavoro -- solo mani libere"},{en:"Devices must be powered off",it:"I dispositivi devono essere spenti"},{en:"Only commercial drivers restricted",it:"Solo i conducenti commerciali sono limitati"}],correct:1,explain_en:"In Florida school zones and work zones: using any handheld device is prohibited. This is a primary offense with fines of $60 (first offense) plus court costs.",explain_it:"Nelle zone scolastiche e di lavoro Florida: l'uso di qualsiasi dispositivo portatile e vietato. E un reato principale con multe di $60 (prima infrazione) piu spese giudiziarie."},
  {cat:"laws",en:"What is Florida's law about driving with a broken or inoperable speedometer?",it:"Qual e la legge Florida sulla guida con un tachimetro rotto o non funzionante?",options:[{en:"Legal -- speedometers are not required",it:"Legale -- i tachimetri non sono richiesti"},{en:"Technically a violation of vehicle equipment requirements -- speedometers must be operational",it:"Tecnicamente una violazione dei requisiti delle attrezzature del veicolo -- i tachimetri devono essere operativi"},{en:"Only an issue for commercial vehicles",it:"Solo un problema per i veicoli commerciali"},{en:"Legal if you estimate your speed carefully",it:"Legale se stimi la tua velocita con attenzione"}],correct:1,explain_en:"Florida vehicle equipment laws require speedometers to be operational. A broken speedometer is a vehicle equipment violation and can be cited during a traffic stop.",explain_it:"Le leggi sulle attrezzature dei veicoli Florida richiedono che i tachimetri siano operativi. Un tachimetro rotto e una violazione delle attrezzature del veicolo."},
  {cat:"laws",en:"What is Florida law regarding parking in a designated fire lane?",it:"Qual e la legge Florida riguardo al parcheggio in una corsia antincendio designata?",options:[{en:"Legal for 5 minutes if hazard lights are on",it:"Legale per 5 minuti se le luci di pericolo sono accese"},{en:"Illegal -- fire lanes must remain clear at all times for emergency access",it:"Illegale -- le corsie antincendio devono rimanere libere in ogni momento per l'accesso di emergenza"},{en:"Legal if the vehicle remains attended",it:"Legale se il veicolo rimane presidiato"},{en:"Only illegal if a fire truck needs access",it:"Illegale solo se un camion dei pompieri ha bisogno di accesso"}],correct:1,explain_en:"Fire lanes must always remain clear. Parking in a fire lane is illegal regardless of how long -- vehicles may be ticketed and towed immediately.",explain_it:"Le corsie antincendio devono sempre rimanere libere. Parcheggiare in una corsia antincendio e illegale indipendentemente dalla durata -- i veicoli possono essere multati e rimossi immediatamente."},
  {cat:"laws",en:"What is the Florida law on carrying a weapon in a vehicle?",it:"Qual e la legge Florida sul trasportare un'arma in un veicolo?",options:[{en:"Always prohibited in vehicles",it:"Sempre vietato nei veicoli"},{en:"Legal to have a firearm in a vehicle if securely encased -- no permit required for vehicle carry",it:"Legale avere un'arma da fuoco in un veicolo se in custodia sicura -- nessun permesso richiesto per il trasporto nel veicolo"},{en:"Only with a concealed weapons permit",it:"Solo con un permesso per armi nascoste"},{en:"Only unloaded firearms are permitted",it:"Sono consentite solo armi da fuoco scariche"}],correct:1,explain_en:"Florida law allows a firearm in a vehicle if securely encased (holster, glove box, gun case) -- no concealed carry permit required for vehicle carry. Loaded firearms on person require a permit.",explain_it:"La legge Florida consente un'arma da fuoco in un veicolo se in custodia sicura (fondina, vano portaoggetti, custodia) -- nessun permesso richiesto per il trasporto nel veicolo."},
  {cat:"laws",en:"What is required after a crash that causes injury in Florida?",it:"Cosa e richiesto dopo un incidente che causa lesioni in Florida?",options:[{en:"File an insurance claim within 30 days",it:"Presentare un reclamo assicurativo entro 30 giorni"},{en:"File a crash report (FR-300) with FLHSMV within 10 days if police did not investigate",it:"Presentare un rapporto di incidente (FR-300) al FLHSMV entro 10 giorni se la polizia non ha indagato"},{en:"Only required if damage exceeds $10,000",it:"Richiesto solo se i danni superano $10.000"},{en:"Report only to your insurance company",it:"Segnalare solo alla tua compagnia assicurativa"}],correct:1,explain_en:"Florida requires a crash report (FR-300) if the crash involved injury, death, or property damage over $500 AND was not investigated by law enforcement.",explain_it:"La Florida richiede un rapporto di incidente (FR-300) se l'incidente ha coinvolto lesioni, morte o danni materiali superiori a $500 E non e stato indagato dalle forze dell'ordine."},

  // SESSION 8 SAFETY+ALCOHOL+LICENSE
  {cat:"safety",en:"What is the proper response to a vehicle skidding sideways (oversteer)?",it:"Qual e la risposta corretta a un veicolo che va di traverso (sovrasterzo)?",options:[{en:"Brake hard and turn in the opposite direction",it:"Frenare forte e girare nella direzione opposta"},{en:"Ease off gas and steer in the direction of the skid (countersteer) to regain traction",it:"Togliere il gas e sterzare nella direzione del drift (controsterzo) per recuperare la trazione"},{en:"Accelerate to pull out of the skid",it:"Accelerare per uscire dallo scivolamento"},{en:"Apply full brakes while steering straight",it:"Applicare freno completo sterzando dritto"}],correct:1,explain_en:"Oversteer/skid: ease off gas, steer into the skid (same direction the rear is sliding). This countersteer helps the tires regain grip. Avoid hard braking during a skid.",explain_it:"Sovrasterzo/scivolamento: togli il gas, sterza nella direzione del drift. Questo controsterzo aiuta gli pneumatici a recuperare l'aderenza. Evita la frenata forte durante uno scivolamento."},
  {cat:"safety",en:"What is the correct response when your rear wheels skid on ice?",it:"Qual e la risposta corretta quando le ruote posteriori slittano sul ghiaccio?",options:[{en:"Brake hard to stop the skid",it:"Frenare forte per fermare lo slittamento"},{en:"Take your foot off the gas, steer in the direction the rear is sliding, and avoid braking",it:"Togliere il piede dall'acceleratore, sterzare nella direzione in cui il posteriore sta scivolando e evitare di frenare"},{en:"Turn sharply in the opposite direction",it:"Girare bruscamente nella direzione opposta"},{en:"Accelerate to regain traction",it:"Accelerare per recuperare la trazione"}],correct:1,explain_en:"Rear-wheel skid on ice: release gas, steer the same way the rear is sliding (don't overcorrect), avoid braking. Gentle steering corrections allow the tires to regain grip.",explain_it:"Scivolamento ruote posteriori sul ghiaccio: rilascia il gas, sterza nella stessa direzione in cui scivola il posteriore (non correggere troppo), evita di frenare."},
  {cat:"safety",en:"What is the best way to avoid backing accidents in a parking lot?",it:"Qual e il modo migliore per evitare incidenti in retromarcia in un parcheggio?",options:[{en:"Back in quickly to minimize time in reverse",it:"Fare retromarcia velocemente per minimizzare il tempo in retromarcia"},{en:"Back in slowly, check all mirrors, turn to look, and have a spotter if available",it:"Fare retromarcia lentamente, controllare tutti gli specchi, girare a guardare, e avere un assistente se disponibile"},{en:"Only use the backup camera",it:"Usare solo la telecamera posteriore"},{en:"Sound the horn continuously while backing",it:"Suonare il clacson continuamente durante la retromarcia"}],correct:1,explain_en:"Backing accidents: always back in slowly, use ALL mirrors AND physically turn to look, and if available have a spotter outside. Backup cameras supplement but don't replace physical checks.",explain_it:"Incidenti in retromarcia: fare sempre retromarcia lentamente, usare TUTTI gli specchi E girare fisicamente a guardare. Le telecamere di retromarcia integrano ma non sostituiscono i controlli fisici."},
  {cat:"safety",en:"What is the correct way to share the road with a large truck at night?",it:"Qual e il modo corretto per condividere la strada con un grande camion di notte?",options:[{en:"Always follow close to use the truck's lights as a guide",it:"Seguire sempre da vicino per usare le luci del camion come guida"},{en:"Stay out of the truck's blind spots, don't use high beams, and increase following distance",it:"Stare fuori dai punti ciechi del camion, non usare gli abbaglianti e aumentare la distanza"},{en:"Flash high beams to alert the truck driver",it:"Lampeggiare gli abbaglianti per allertare il camionista"},{en:"Pass the truck on the right at night to stay away from its headlights",it:"Superare il camion a destra di notte per stare lontano dai suoi fari"}],correct:1,explain_en:"Around trucks at night: stay out of the 4 blind spots, never use high beams (blinds the driver in mirrors), increase following distance, and pass quickly on the left.",explain_it:"Intorno ai camion di notte: stare fuori dai 4 punti ciechi, non usare mai gli abbaglianti (acceca il conducente negli specchi), aumentare la distanza, sorpassare velocemente a sinistra."},
  {cat:"safety",en:"What is the Florida law on the minimum age to ride as a bicycle passenger?",it:"Qual e la legge Florida sull'eta minima per viaggiare come passeggero in bicicletta?",options:[{en:"No age restriction",it:"Nessuna restrizione di eta"},{en:"Children under 1 year may not be carried as bicycle passengers",it:"I bambini sotto 1 anno non possono essere trasportati come passeggeri in bicicletta"},{en:"Under 4 must wear a helmet only",it:"Under 4 devono indossare solo un casco"},{en:"Under 16 may not be bicycle passengers",it:"Under 16 non possono essere passeggeri in bicicletta"}],correct:1,explain_en:"Florida: children under 1 year of age may not be carried as passengers on bicycles. All cyclists and passengers under 16 must wear helmets.",explain_it:"Florida: i bambini sotto 1 anno di eta non possono essere trasportati come passeggeri sulle biciclette. Tutti i ciclisti e i passeggeri under 16 devono indossare caschi."},
  {cat:"safety",en:"What should you do when a large truck is passing you?",it:"Cosa dovresti fare quando un grande camion ti sta sorpassando?",options:[{en:"Speed up to prevent the truck from passing",it:"Accelerare per impedire al camion di sorpassare"},{en:"Keep right, maintain steady speed, and allow extra space for the truck to merge back",it:"Mantenere a destra, mantenere una velocita costante e consentire spazio extra per il rientro del camion"},{en:"Brake to let the truck pass faster",it:"Frenare per far passare il camion piu velocemente"},{en:"Move to the left lane immediately",it:"Spostarsi immediatamente nella corsia sinistra"}],correct:1,explain_en:"When a truck is passing you: stay right, maintain steady speed (don't slow down or speed up), and leave extra space after the pass for the truck to merge back safely.",explain_it:"Quando un camion ti sorpassa: mantieni a destra, mantieni una velocita costante e lascia spazio extra dopo il sorpasso perche il camion rientri in sicurezza."},
  {cat:"safety",en:"What is the effect of carbon monoxide inside a vehicle?",it:"Qual e l'effetto del monossido di carbonio all'interno di un veicolo?",options:[{en:"Makes the driver more alert",it:"Rende il conducente piu sveglio"},{en:"Causes drowsiness, confusion, and can be fatal -- never idle in an enclosed space",it:"Causa sonnolenza, confusione e puo essere fatale -- non lasciare mai il motore acceso in uno spazio chiuso"},{en:"Has no effect in small amounts",it:"Non ha effetti in piccole quantita"},{en:"Only dangerous at cold temperatures",it:"Pericoloso solo a basse temperature"}],correct:1,explain_en:"Carbon monoxide is odorless and colorless. Even small amounts in a car can cause headache, drowsiness, and confusion -- higher concentrations are fatal. Never idle in a garage.",explain_it:"Il monossido di carbonio e inodore e incolore. Anche piccole quantita in un'auto possono causare mal di testa, sonnolenza e confusione -- concentrazioni piu alte sono fatali."},
  {cat:"safety",en:"What is the recommended minimum following distance when driving in heavy rain?",it:"Qual e la distanza minima di seguimento raccomandata quando si guida sotto pioggia intensa?",options:[{en:"2 seconds -- same as dry conditions",it:"2 secondi -- uguale alle condizioni asciutte"},{en:"At least 4-6 seconds -- double or triple the dry-weather distance",it:"Almeno 4-6 secondi -- il doppio o triplo della distanza in condizioni asciutte"},{en:"1 car length per 10 mph",it:"1 lunghezza auto per 10 mph"},{en:"Stay as close as possible to see the tail lights",it:"Stare il piu vicino possibile per vedere le luci posteriori"}],correct:1,explain_en:"In rain, double or triple your following distance (4-6 seconds minimum). Wet roads increase stopping distances significantly.",explain_it:"Nella pioggia, raddoppia o triplica la distanza di seguimento (minimo 4-6 secondi). Le strade bagnate aumentano significativamente le distanze di frenata."},
  {cat:"safety",en:"What is the danger of large trucks making wide right turns?",it:"Qual e il pericolo dei camion grandi che fanno ampie svolte destre?",options:[{en:"They turn right slowly, causing traffic delays",it:"Svoltano a destra lentamente, causando ritardi al traffico"},{en:"They may swing left first then cut right -- vehicles alongside can be squeezed",it:"Possono spostarsi prima a sinistra poi tagliare a destra -- i veicoli a fianco possono essere schiacciati"},{en:"Only dangerous for motorcycles",it:"Pericoloso solo per le moto"},{en:"No danger -- trucks have the right of way when turning",it:"Nessun pericolo -- i camion hanno la precedenza quando svoltano"}],correct:1,explain_en:"Wide right turns: large trucks may swing left before turning right to clear the curb. If you pull up on the right side of a turning truck, you can be crushed. Never pass a turning truck on the right.",explain_it:"Svolte destre ampie: i camion grandi possono spostarsi a sinistra prima di svoltare a destra per liberare il marciapiede. Se ti avvicini sul lato destro di un camion che svolta, puoi essere schiacciato."},
  {cat:"safety",en:"What should you do if you miss your highway exit?",it:"Cosa dovresti fare se manchi la tua uscita autostradale?",options:[{en:"Reverse on the highway to reach the exit",it:"Fare retromarcia in autostrada per raggiungere l'uscita"},{en:"Continue to the next exit -- never stop on the highway or back up",it:"Continuare fino alla prossima uscita -- non fermarsi mai in autostrada o fare retromarcia"},{en:"Stop on the shoulder and wait for a break in traffic",it:"Fermarsi sulla banchina e aspettare un'interruzione nel traffico"},{en:"Cross the median to return to the exit",it:"Attraversare il mediano per tornare all'uscita"}],correct:1,explain_en:"Never reverse or stop on a highway for a missed exit. Continue to the next exit and turn around. Reversing on a highway is illegal and extremely dangerous.",explain_it:"Non fare mai retromarcia o fermarsi in autostrada per un'uscita mancata. Continuare fino alla prossima uscita e girare. Fare retromarcia in autostrada e illegale ed estremamente pericoloso."},
  {cat:"safety",en:"What is the safest action when a traffic light turns green after you have been stopped?",it:"Qual e l'azione piu sicura quando un semaforo diventa verde dopo che sei stato fermo?",options:[{en:"Accelerate immediately at full speed",it:"Accelerare immediatamente a piena velocita"},{en:"Pause briefly to check for red-light runners then proceed",it:"Fare una breve pausa per controllare i passaggi con il rosso poi procedere"},{en:"Sound the horn to alert other drivers",it:"Suonare il clacson per avvisare gli altri conducenti"},{en:"Wait until all cross traffic has cleared",it:"Aspettare finche tutto il traffico trasversale si e liberato"}],correct:1,explain_en:"When your light turns green: briefly check both directions for red-light runners before accelerating -- especially at busy intersections. Most accidents from red-light running occur in the first 2 seconds of green.",explain_it:"Quando il semaforo diventa verde: controlla brevemente entrambe le direzioni per i passaggi con il rosso prima di accelerare -- specialmente agli incroci affollati."},
  {cat:"safety",en:"What is the Florida law on the use of a radar detector?",it:"Qual e la legge Florida sull'uso di un rilevatore di radar?",options:[{en:"Radar detectors are illegal in Florida",it:"I rilevatori di radar sono illegali in Florida"},{en:"Radar detectors are legal for non-commercial vehicles in Florida",it:"I rilevatori di radar sono legali per i veicoli non commerciali in Florida"},{en:"Legal only when the speed limit is above 55 mph",it:"Legale solo quando il limite di velocita e superiore a 55 mph"},{en:"Only illegal for drivers under 21",it:"Illegale solo per i conducenti under 21"}],correct:1,explain_en:"Radar detectors are legal for non-commercial passenger vehicles in Florida. However, they are illegal for commercial vehicles and in some other states.",explain_it:"I rilevatori di radar sono legali per i veicoli passeggeri non commerciali in Florida. Tuttavia, sono illegali per i veicoli commerciali e in alcuni altri stati."},
  {cat:"safety",en:"What is the proper use of the left turn lane marked with double left-turn arrows?",it:"Qual e l'uso corretto della corsia di svolta sinistra contrassegnata con doppie frecce di svolta sinistra?",options:[{en:"Two vehicles may turn side-by-side simultaneously",it:"Due veicoli possono svoltare fianco a fianco contemporaneamente"},{en:"Both lanes can turn left but each must end up in their respective destination lane",it:"Entrambe le corsie possono svoltare a sinistra ma ognuna deve finire nella rispettiva corsia di destinazione"},{en:"One lane turns, the other goes straight",it:"Una corsia svolta, l'altra va dritto"},{en:"Only buses use the left lane",it:"Solo gli autobus usano la corsia sinistra"}],correct:1,explain_en:"Dual left-turn lanes: both lanes turn left simultaneously. The inner lane must end in the inner destination lane; the outer lane in the outer destination lane. Do not switch lanes during the turn.",explain_it:"Corsie di svolta sinistra duali: entrambe le corsie svoltano a sinistra contemporaneamente. La corsia interna deve finire nella corsia di destinazione interna; la corsia esterna in quella esterna."},
  {cat:"safety",en:"What is the proper approach to driving through an intersection with a malfunctioning traffic light?",it:"Qual e l'approccio corretto per guidare attraverso un incrocio con un semaforo guasto?",options:[{en:"Proceed normally -- who was there first has the right of way",it:"Procedere normalmente -- chi era li per primo ha la precedenza"},{en:"Treat it as a four-way stop -- stop completely, yield in order of arrival, then proceed",it:"Trattarlo come uno stop a quattro vie -- fermarsi completamente, cedere in ordine di arrivo, poi procedere"},{en:"Flash your headlights and proceed",it:"Lampeggiare i fari e procedere"},{en:"Only stop if other vehicles are present",it:"Fermarsi solo se altri veicoli sono presenti"}],correct:1,explain_en:"At a non-functioning traffic signal: treat it exactly like a four-way stop. Come to a complete stop at the limit line, yield to traffic already through, take turns in order of arrival.",explain_it:"A un segnale semaforico non funzionante: trattarlo esattamente come uno stop a quattro vie. Fermarsi completamente alla linea di arresto, cedere al traffico gia attraversato, fare a turno in ordine di arrivo."},
  {cat:"safety",en:"What is the effect of distracted driving on reaction time?",it:"Qual e l'effetto della guida distratta sul tempo di reazione?",options:[{en:"No significant effect",it:"Nessun effetto significativo"},{en:"Reaction time increases significantly -- visual distraction causes drivers to miss events in 2+ seconds of travel",it:"Il tempo di reazione aumenta significativamente -- la distrazione visiva fa perdere eventi in 2+ secondi di viaggio"},{en:"Only affects elderly drivers",it:"Influisce solo sui conducenti anziani"},{en:"Slightly improves focus for experienced drivers",it:"Migliora leggermente la concentrazione per i conducenti esperti"}],correct:1,explain_en:"At 55 mph, looking at a phone for 5 seconds is like driving the length of a football field blindfolded. Distracted driving delays reaction time similar to alcohol impairment.",explain_it:"A 55 mph, guardare un telefono per 5 secondi e come percorrere la lunghezza di un campo di calcio con gli occhi bendati. La guida distratta ritarda il tempo di reazione come l'alcol."},
  {cat:"safety",en:"What is proper lane positioning for motorcycles on a highway?",it:"Qual e il corretto posizionamento in corsia per le moto in autostrada?",options:[{en:"Always ride in the center of the lane",it:"Guidare sempre al centro della corsia"},{en:"Vary position within the lane -- left, center, or right -- to maximize visibility and road condition awareness",it:"Variare la posizione all'interno della corsia -- sinistra, centro o destra -- per massimizzare la visibilita e la consapevolezza delle condizioni stradali"},{en:"Always ride on the right edge of the lane",it:"Guidare sempre sul bordo destro della corsia"},{en:"Motorcycles must share a lane with other motorcycles",it:"Le moto devono condividere una corsia con altre moto"}],correct:1,explain_en:"Motorcycle lane positioning: vary position within the lane based on visibility, road surface, and traffic. The center-left position maximizes visibility to other drivers in most situations.",explain_it:"Posizionamento in corsia per moto: variare la posizione all'interno della corsia in base a visibilita, superficie stradale e traffico. La posizione centro-sinistra massimizza la visibilita agli altri conducenti."},
  {cat:"safety",en:"What is the safest approach when driving near a bicycle lane?",it:"Qual e l'approccio piu sicuro quando si guida vicino a una corsia ciclabile?",options:[{en:"Bicycles must always yield to cars",it:"Le biciclette devono sempre cedere alle auto"},{en:"Watch for cyclists before opening doors, turning right, or crossing the bike lane",it:"Fare attenzione ai ciclisti prima di aprire le porte, svoltare a destra o attraversare la corsia ciclabile"},{en:"The bike lane is a buffer -- stay in your lane",it:"La corsia ciclabile e un buffer -- restare nella corsia"},{en:"Honk to alert cyclists before turning",it:"Suonare il clacson per avvisare i ciclisti prima di svoltare"}],correct:1,explain_en:"Near bike lanes: always check for cyclists before opening car doors (dooring), turning right across the bike lane, or merging through it. Cyclists may be moving faster than expected.",explain_it:"Vicino alle corsie ciclabili: controllare sempre i ciclisti prima di aprire le portiere, svoltare a destra attraverso la corsia ciclabile o confluire attraverso di essa."},
  {cat:"safety",en:"What is the Florida law on motorcycle lane splitting?",it:"Qual e la legge Florida sul lane splitting in moto?",options:[{en:"Legal in slow traffic",it:"Legale nel traffico lento"},{en:"Illegal -- lane splitting is prohibited in Florida",it:"Illegale -- il lane splitting e vietato in Florida"},{en:"Legal at speeds under 30 mph",it:"Legale a velocita inferiori a 30 mph"},{en:"Legal only on highways",it:"Legale solo in autostrada"}],correct:1,explain_en:"Lane splitting (riding between lanes of stopped or slow traffic) is illegal in Florida. Motorcyclists must stay within a single lane.",explain_it:"Il lane splitting (guidare tra corsie di traffico fermo o lento) e illegale in Florida. I motociclisti devono rimanere all'interno di una singola corsia."},
  {cat:"safety",en:"What is the proper way to change lanes when towing a trailer?",it:"Qual e il modo corretto per cambiare corsia quando si traina un rimorchio?",options:[{en:"Same as without a trailer",it:"Uguale a senza rimorchio"},{en:"Allow much more space, signal earlier, check wider blind spots, and make gradual moves",it:"Consentire molto piu spazio, segnalare prima, controllare i punti ciechi piu ampi e fare movimenti graduali"},{en:"Change lanes at highway speed only",it:"Cambiare corsia solo alla velocita autostradale"},{en:"Only change lanes in emergencies when towing",it:"Cambiare corsia solo nelle emergenze quando si traina"}],correct:1,explain_en:"Towing a trailer: blind spots are larger and longer, stopping distance increases, and lane changes require more space. Allow more time and distance for all maneuvers.",explain_it:"Trainare un rimorchio: i punti ciechi sono piu grandi e lunghi, la distanza di frenata aumenta e i cambi di corsia richiedono piu spazio."},
  {cat:"safety",en:"What is the purpose of a rear window defroster?",it:"Qual e lo scopo di un defroster del lunotto posteriore?",options:[{en:"Prevents the rear window from fogging only in summer",it:"Impedisce al lunotto posteriore di appannarsi solo in estate"},{en:"Clears fog or frost from the rear window to restore rearward visibility",it:"Elimina nebbia o brina dal lunotto posteriore per ripristinare la visibilita posteriore"},{en:"Improves fuel efficiency by warming the engine bay",it:"Migliora l'efficienza del carburante riscaldando il vano motore"},{en:"Only useful in temperatures below freezing",it:"Utile solo a temperature sotto lo zero"}],correct:1,explain_en:"The rear window defroster uses heated wires embedded in the glass to clear fog and frost -- restoring rear visibility. Never drive with an obscured rear window.",explain_it:"Il defroster del lunotto posteriore usa fili riscaldati incorporati nel vetro per eliminare nebbia e brina -- ripristinando la visibilita posteriore."},
  {cat:"safety",en:"What is the three-second plus rule for following distance?",it:"Cos'e la regola dei tre secondi piu per la distanza di seguimento?",options:[{en:"Leave exactly 3 car lengths behind every vehicle",it:"Lasciare esattamente 3 lunghezze auto dietro ogni veicolo"},{en:"Use 3 seconds minimum in ideal conditions and add 1 second for each hazard factor",it:"Usare minimo 3 secondi nelle condizioni ideali e aggiungere 1 secondo per ogni fattore di rischio"},{en:"Only applicable on highways above 55 mph",it:"Applicabile solo in autostrada sopra i 55 mph"},{en:"3 seconds applies only to trucks",it:"3 secondi si applica solo ai camion"}],correct:1,explain_en:"3-second rule base + 1 second each for: night driving, rain, following a truck, fatigue, or poor visibility. 4+ seconds is better than 2 in any condition.",explain_it:"Regola base di 3 secondi + 1 secondo ciascuno per: guida notturna, pioggia, seguire un camion, stanchezza o scarsa visibilita."},
  {cat:"safety",en:"How should you respond if your car goes over railroad tracks and becomes stuck?",it:"Come dovresti rispondere se la tua auto attraversa i binari ferroviari e rimane bloccata?",options:[{en:"Stay in the vehicle and call for help",it:"Rimanere nel veicolo e chiamare aiuto"},{en:"Get out immediately and move away from the tracks -- especially away from the direction of any approaching train",it:"Uscire immediatamente e allontanarsi dai binari -- specialmente dalla direzione di qualsiasi treno in avvicinamento"},{en:"Try to rock the vehicle off the tracks",it:"Cercare di dondolare il veicolo fuori dai binari"},{en:"Flag down the train to warn the engineer",it:"Fermare il treno per avvisare il macchinista"}],correct:1,explain_en:"If stuck on railroad tracks: GET OUT IMMEDIATELY. Move away from the tracks and away from the train's direction (wreckage scatters forward). Call 911 and find the emergency number posted at the crossing.",explain_it:"Se bloccato sui binari: USCIRE IMMEDIATAMENTE. Allontanarsi dai binari e dalla direzione del treno (i rottami si disperdono in avanti). Chiamare il 911."},
  {cat:"safety",en:"What is the proper way to signal when changing lanes to the right?",it:"Qual e il modo corretto di segnalare quando si cambia corsia a destra?",options:[{en:"Left turn signal",it:"Segnale di svolta sinistra"},{en:"Right turn signal activated at least 100 feet before the lane change",it:"Segnale di svolta destra attivato almeno 100 piedi prima del cambio di corsia"},{en:"Flash your hazard lights twice",it:"Lampeggiare le luci di pericolo due volte"},{en:"No signal needed on multi-lane roads",it:"Nessun segnale necessario sulle strade a piu corsie"}],correct:1,explain_en:"Signal right when changing to the right lane. Activate the turn signal at least 100 feet before the change on surface roads (200 feet on highways).",explain_it:"Segnala a destra quando cambi nella corsia destra. Attiva il segnale di svolta almeno 100 piedi prima del cambio sulle strade di superficie (200 piedi in autostrada)."},
  {cat:"safety",en:"What is the danger of 'white line fever' (highway hypnosis) on long trips?",it:"Qual e il pericolo della 'febbre della linea bianca' (ipnosi autostradale) nei viaggi lunghi?",options:[{en:"Tire wear increases on long highways",it:"L'usura degli pneumatici aumenta nelle autostrade lunghe"},{en:"The monotonous road causes the brain to enter a trance-like state where reaction time is severely impaired",it:"La strada monotona fa entrare il cervello in uno stato simile a una trance dove il tempo di reazione e gravemente compromesso"},{en:"Only affects drivers over 60",it:"Influisce solo sui conducenti over 60"},{en:"Causes engine overheating on long trips",it:"Causa il surriscaldamento del motore nei viaggi lunghi"}],correct:1,explain_en:"Highway hypnosis is a real danger on long monotonous drives. The brain reduces conscious attention to the driving task. Take breaks every 2 hours, vary eye focus, and stay alert.",explain_it:"L'ipnosi autostradale e un pericolo reale nei lunghi viaggi monotoni. Il cervello riduce l'attenzione consapevole al compito di guida. Fai pause ogni 2 ore."},
  {cat:"safety",en:"What is the proper technique for driving through a deep puddle on a road?",it:"Qual e la tecnica corretta per guidare attraverso una pozzanghera profonda sulla strada?",options:[{en:"Speed up to skim over the surface",it:"Accelerare per scivolare sulla superficie"},{en:"Reduce speed, drive through slowly in a low gear, test brakes after exiting",it:"Ridurre la velocita, attraversare lentamente in una marcia bassa, testare i freni dopo l'uscita"},{en:"Switch to 4WD before entering",it:"Passare a 4WD prima di entrare"},{en:"Use the horn to warn pedestrians",it:"Usare il clacson per avvisare i pedoni"}],correct:1,explain_en:"Through deep puddles: slow down, use a low gear, drive through the shallowest part. After exiting, apply brakes gently to dry them out and restore braking ability.",explain_it:"Attraverso pozzanghere profonde: rallenta, usa una marcia bassa, attraversa la parte piu bassa. Dopo l'uscita, applica i freni delicatamente per asciugarli e ripristinare la capacita frenante."},
  {cat:"safety",en:"What is the significance of a yellow painted curb?",it:"Qual e il significato di un marciapiede dipinto di giallo?",options:[{en:"Parking permitted for yellow vehicles",it:"Parcheggio consentito per i veicoli gialli"},{en:"No stopping or parking -- often used for loading zones or bus stops",it:"Nessuna sosta o parcheggio -- spesso usato per le zone di carico o le fermate degli autobus"},{en:"10-minute parking only",it:"Solo 10 minuti di parcheggio"},{en:"Parking for motorcycles only",it:"Parcheggio solo per le moto"}],correct:1,explain_en:"Yellow curbs indicate no stopping or parking -- typically loading zones where trucks may briefly stop to load/unload merchandise, or bus stops. Cars may not park there.",explain_it:"I marciapiedi gialli indicano nessuna sosta o parcheggio -- tipicamente zone di carico dove i camion possono brevemente fermarsi per caricare/scaricare, o fermate degli autobus."},
  {cat:"safety",en:"What is the significance of a red painted curb?",it:"Qual e il significato di un marciapiede dipinto di rosso?",options:[{en:"Fire zone -- no stopping, standing, or parking at any time",it:"Zona antincendio -- nessuna sosta, fermata o parcheggio in qualsiasi momento"},{en:"15-minute parking allowed",it:"Parcheggio di 15 minuti consentito"},{en:"Emergency vehicles only",it:"Solo veicoli di emergenza"},{en:"Parking for 5 minutes maximum",it:"Parcheggio massimo 5 minuti"}],correct:0,explain_en:"Red curbs: absolutely no stopping, standing, or parking. These are typically fire zones, fire hydrant zones, or areas that must remain clear for emergency access.",explain_it:"Marciapiedi rossi: assolutamente nessuna sosta, fermata o parcheggio. Queste sono tipicamente zone antincendio, zone idrante o aree che devono rimanere libere per l'accesso di emergenza."},
  {cat:"safety",en:"What does a white painted curb mean?",it:"Cosa significa un marciapiede dipinto di bianco?",options:[{en:"No parking at any time",it:"Nessun parcheggio in qualsiasi momento"},{en:"Passenger loading/unloading only -- usually time-limited",it:"Solo carico/scarico passeggeri -- di solito limitato nel tempo"},{en:"Parking for disabled persons",it:"Parcheggio per persone disabili"},{en:"No restrictions -- open parking",it:"Nessuna restrizione -- parcheggio aperto"}],correct:1,explain_en:"White curbs: passenger loading and unloading zone only (no parking). Drivers may stop briefly to pick up or drop off passengers.",explain_it:"Marciapiedi bianchi: zona solo carico/scarico passeggeri (nessun parcheggio). I conducenti possono fermarsi brevemente per raccogliere o lasciare i passeggeri."},
  {cat:"alcohol",en:"What is the effect of age on alcohol metabolism?",it:"Qual e l'effetto dell'eta sul metabolismo dell'alcol?",options:[{en:"Younger people process alcohol slower",it:"Le persone piu giovani elaborano l'alcol piu lentamente"},{en:"Older adults process alcohol more slowly as liver efficiency decreases with age",it:"Gli adulti piu anziani elaborano l'alcol piu lentamente man mano che l'efficienza epatica diminuisce con l'eta"},{en:"Age has no effect on metabolism",it:"L'eta non ha effetti sul metabolismo"},{en:"Teenagers metabolize alcohol twice as fast",it:"Gli adolescenti metabolizzano l'alcol due volte piu velocemente"}],correct:1,explain_en:"As people age, liver efficiency decreases and body water decreases -- the same amount of alcohol produces higher BAC and longer impairment in older adults.",explain_it:"Con l'avanzare dell'eta, l'efficienza epatica diminuisce e l'acqua corporea diminuisce -- la stessa quantita di alcol produce un BAC piu alto e una compromissione piu lunga negli adulti piu anziani."},
  {cat:"alcohol",en:"How does carbonation affect alcohol absorption?",it:"Come influisce la carbonatazione sull'assorbimento dell'alcol?",options:[{en:"Carbonated drinks slow absorption",it:"Le bevande gassate rallentano l'assorbimento"},{en:"Carbonated drinks speed alcohol absorption by opening the pyloric valve faster",it:"Le bevande gassate accelerano l'assorbimento dell'alcol aprendo la valvola pilorica piu velocemente"},{en:"Carbonation has no effect on absorption",it:"La carbonatazione non ha effetti sull'assorbimento"},{en:"Only affects BAC above 0.10%",it:"Influisce solo sul BAC sopra 0,10%"}],correct:1,explain_en:"Carbonated alcoholic drinks (champagne, mixed drinks with soda) are absorbed faster because carbonation speeds stomach emptying -- causing faster BAC rise.",explain_it:"Le bevande alcoliche gassate (champagne, drink con soda) vengono assorbite piu velocemente perche la carbonatazione accelera lo svuotamento gastrico -- causando un aumento piu rapido del BAC."},
  {cat:"alcohol",en:"What is the Florida law about purchasing alcohol for minors?",it:"Qual e la legge Florida sull'acquisto di alcol per i minori?",options:[{en:"Legal if the minor is 18+",it:"Legale se il minore ha 18+"},{en:"Illegal -- it is a criminal offense to purchase or provide alcohol to anyone under 21",it:"Illegale -- e un reato penale acquistare o fornire alcol a chiunque abbia meno di 21 anni"},{en:"Legal with parental consent",it:"Legale con il consenso dei genitori"},{en:"Only illegal in public places",it:"Illegale solo nei luoghi pubblici"}],correct:1,explain_en:"Florida law: purchasing, furnishing, or providing alcohol to anyone under 21 is a first-degree misdemeanor. Parents may be held liable for hosting underage drinking.",explain_it:"Legge Florida: acquistare, fornire o cedere alcol a chiunque abbia meno di 21 anni e una contravvenzione di primo grado."},
  {cat:"alcohol",en:"What does 'per se DUI' mean in Florida?",it:"Cosa significa 'per se DUI' in Florida?",options:[{en:"DUI requires proof of actual impairment",it:"Il DUI richiede la prova di una compromissione effettiva"},{en:"Having a BAC of 0.08% or above is sufficient for DUI conviction regardless of observed impairment",it:"Avere un BAC di 0,08% o superiore e sufficiente per la condanna DUI indipendentemente dalla compromissione osservata"},{en:"DUI only applies if you caused an accident",it:"Il DUI si applica solo se hai causato un incidente"},{en:"DUI per se applies only to commercial drivers",it:"Il DUI per se si applica solo ai conducenti commerciali"}],correct:1,explain_en:"Per se DUI: a BAC of 0.08%+ is automatically DUI regardless of driving behavior or observed impairment. No additional proof of impairment is required.",explain_it:"DUI per se: un BAC di 0,08%+ e automaticamente DUI indipendentemente dal comportamento di guida o dalla compromissione osservata."},
  {cat:"alcohol",en:"What is the approximate BAC at which most people show obvious signs of impairment?",it:"Qual e il BAC approssimativo a cui la maggior parte delle persone mostra segni evidenti di compromissione?",options:[{en:"0.02%",it:"0,02%"},{en:"0.05%",it:"0,05%"},{en:"0.10%",it:"0,10%"},{en:"0.15%",it:"0,15%"}],correct:2,explain_en:"At 0.10% BAC, most people show obvious impairment: slurred speech, coordination problems, reduced reaction time. However, impairment begins at much lower levels (0.02-0.05%).",explain_it:"A 0,10% BAC, la maggior parte delle persone mostra una compromissione evidente: parola indistinta, problemi di coordinazione, tempo di reazione ridotto. Tuttavia, la compromissione inizia a livelli molto piu bassi."},
  {cat:"alcohol",en:"What is the effect of alcohol on peripheral vision?",it:"Qual e l'effetto dell'alcol sulla visione periferica?",options:[{en:"Improves peripheral awareness",it:"Migliora la consapevolezza periferica"},{en:"Causes 'tunnel vision' -- reduces the field of view so hazards on the sides are missed",it:"Causa la 'visione a tunnel' -- riduce il campo visivo in modo che i pericoli ai lati vengano persi"},{en:"Has no effect on peripheral vision",it:"Non ha effetti sulla visione periferica"},{en:"Only affects central vision",it:"Influisce solo sulla visione centrale"}],correct:1,explain_en:"Alcohol causes tunnel vision -- reducing peripheral vision so drivers miss hazards and objects to the sides. This is especially dangerous when pedestrians or cyclists approach from the side.",explain_it:"L'alcol causa la visione a tunnel -- riducendo la visione periferica in modo che i conducenti perdano i pericoli e gli oggetti ai lati."},
  {cat:"alcohol",en:"What is the Florida law on DUI for a driver under 21 with a BAC between 0.02% and 0.07%?",it:"Qual e la legge Florida sul DUI per un conducente under 21 con BAC tra 0,02% e 0,07%?",options:[{en:"No penalty below 0.08%",it:"Nessuna sanzione sotto 0,08%"},{en:"Automatic 6-month license suspension -- Zero Tolerance law applies",it:"Sospensione automatica della patente di 6 mesi -- si applica la legge Zero Tolerance"},{en:"Only a warning is issued",it:"Viene emesso solo un avvertimento"},{en:"Same penalties as an adult DUI",it:"Le stesse sanzioni di un DUI adulto"}],correct:1,explain_en:"Florida Zero Tolerance: under-21 drivers with BAC 0.02-0.07% receive automatic 6-month license suspension. BAC 0.08%+ results in full adult DUI prosecution.",explain_it:"Zero Tolerance Florida: conducenti under 21 con BAC 0,02-0,07% ricevono una sospensione automatica della patente di 6 mesi."},
  {cat:"alcohol",en:"What is the most important single factor that affects BAC?",it:"Qual e il fattore singolo piu importante che influisce sul BAC?",options:[{en:"What you ate",it:"Cosa hai mangiato"},{en:"The total amount of alcohol consumed",it:"La quantita totale di alcol consumata"},{en:"The type of alcoholic beverage",it:"Il tipo di bevanda alcolica"},{en:"How fast you drank",it:"Con quale velocita hai bevuto"}],correct:1,explain_en:"The total amount of alcohol consumed is the primary determinant of BAC. All standard drinks contain the same amount of pure alcohol -- the type of drink doesn't matter.",explain_it:"La quantita totale di alcol consumata e il determinante principale del BAC. Tutti i drink standard contengono la stessa quantita di alcol puro -- il tipo di bevanda non conta."},
  {cat:"alcohol",en:"What is the Florida Ignition Interlock Device (IID) requirement?",it:"Qual e il requisito del dispositivo interlock di accensione (IID) della Florida?",options:[{en:"Voluntary -- only for repeat offenders",it:"Volontario -- solo per i recidivi"},{en:"Mandatory for DUI convictions with BAC 0.15%+ or with minor passenger -- for first offense; all second offenses",it:"Obbligatorio per le condanne DUI con BAC 0,15%+ o con passeggero minore -- per la prima infrazione; tutte le seconde infrazioni"},{en:"Only required for commercial vehicle DUI",it:"Richiesto solo per il DUI con veicoli commerciali"},{en:"Required for all DUI convictions without exception",it:"Richiesto per tutte le condanne DUI senza eccezioni"}],correct:1,explain_en:"Florida IID requirement: mandatory for first DUI with BAC 0.15%+ or with minor passenger. Mandatory for ALL second DUI convictions. Device prevents starting the car if alcohol is detected on breath.",explain_it:"Requisito IID Florida: obbligatorio per il primo DUI con BAC 0,15%+ o con passeggero minore. Obbligatorio per TUTTE le seconde condanne DUI."},
  {cat:"alcohol",en:"What are the signs that a driver may be under the influence of alcohol?",it:"Quali sono i segni che un conducente potrebbe essere sotto l'influenza dell'alcol?",options:[{en:"Driving too fast and staying in one lane",it:"Guidare troppo veloce e restare in una corsia"},{en:"Weaving, wide turns, straddling lanes, sudden braking, driving very slowly or erratically",it:"Serpentinamento, svolte ampie, straddling di corsie, frenata improvvisa, guida molto lenta o irregolare"},{en:"Using turn signals too frequently",it:"Usare i segnali di svolta troppo frequentemente"},{en:"Following too closely",it:"Seguire troppo da vicino"}],correct:1,explain_en:"Signs of impaired driving: weaving, drifting, wide turns, straddling lane lines, sudden speed changes, very slow driving, erratic braking. Report suspected DUI drivers to police.",explain_it:"Segni di guida compromessa: serpentinamento, deriva, svolte ampie, straddling delle linee di corsia, cambi di velocita improvvisi, guida molto lenta, frenata irregolare."},
  {cat:"license",en:"What is the Florida law about displaying a license plate?",it:"Qual e la legge Florida sull'esposizione di una targa?",options:[{en:"Only a rear plate is required",it:"E richiesta solo una targa posteriore"},{en:"One plate is required -- rear only -- and must be clearly visible and not obstructed",it:"E richiesta una targa -- solo posteriore -- e deve essere chiaramente visibile e non ostruita"},{en:"Two plates required -- front and rear",it:"Richieste due targhe -- anteriore e posteriore"},{en:"License plate can be covered if a backup camera is installed",it:"La targa puo essere coperta se e installata una telecamera di retromarcia"}],correct:1,explain_en:"Florida requires one license plate displayed on the rear of the vehicle. It must be clearly visible, properly mounted, and illuminated at night.",explain_it:"La Florida richiede una targa esposta sul retro del veicolo. Deve essere chiaramente visibile, correttamente montata e illuminata di notte."},
  {cat:"license",en:"What happens to a Florida driver who refuses a breathalyzer test for the first time?",it:"Cosa succede a un conducente Florida che rifiuta un test del respiro per la prima volta?",options:[{en:"No penalty -- refusing is always legal",it:"Nessuna sanzione -- il rifiuto e sempre legale"},{en:"Automatic 1-year license suspension regardless of whether charged with DUI",it:"Sospensione automatica della patente di 1 anno indipendentemente dal fatto che si sia accusati di DUI"},{en:"6-month suspension only if convicted of DUI",it:"Sospensione di 6 mesi solo se condannato per DUI"},{en:"A $500 fine but license is retained",it:"Una multa di $500 ma la patente viene trattenuta"}],correct:1,explain_en:"First refusal of a breath test: automatic 1-year license suspension. Second refusal is a first-degree misdemeanor with 18-month suspension. Refusing does not prevent a DUI charge.",explain_it:"Primo rifiuto del test del respiro: sospensione automatica della patente di 1 anno. Il secondo rifiuto e una contravvenzione di primo grado con sospensione di 18 mesi."},
  {cat:"license",en:"What is the Florida temporary driving permit (paper permit) and how long is it valid?",it:"Cos'e il permesso di guida temporaneo Florida (permesso cartaceo) e per quanto tempo e valido?",options:[{en:"Valid for 1 year",it:"Valido per 1 anno"},{en:"Valid for 30 days while waiting for the permanent license to arrive",it:"Valido per 30 giorni in attesa dell'arrivo della patente permanente"},{en:"Valid for 6 months",it:"Valido per 6 mesi"},{en:"Valid until the permanent license arrives",it:"Valido finche non arriva la patente permanente"}],correct:1,explain_en:"Florida issues a paper temporary permit valid for 30 days when you get or renew a license. The permanent plastic card is mailed within this period.",explain_it:"La Florida rilascia un permesso temporaneo cartaceo valido per 30 giorni quando si ottiene o rinnova una patente. La tessera plastica permanente viene spedita entro questo periodo."},
  {cat:"license",en:"What is the Florida 'Driver Improvement Program'?",it:"Cos'e il 'Driver Improvement Program' della Florida?",options:[{en:"A program to get a commercial license",it:"Un programma per ottenere una patente commerciale"},{en:"A course that can remove 3 points from a driving record -- available once in 12 months",it:"Un corso che puo rimuovere 3 punti dal casellario di guida -- disponibile una volta in 12 mesi"},{en:"Mandatory after any accident",it:"Obbligatorio dopo qualsiasi incidente"},{en:"A program for new Florida residents",it:"Un programma per i nuovi residenti Florida"}],correct:1,explain_en:"Florida's Basic Driver Improvement (BDI) course can reduce 3 points from your record. You must elect it before the court date, pay the fine, and complete the course. Available once per 12 months.",explain_it:"Il corso BDI della Florida puo ridurre 3 punti dal tuo casellario. Devi sceglierlo prima della data del tribunale, pagare la multa e completare il corso."},
  {cat:"license",en:"What does a 'D' restriction on a Florida driver's license mean?",it:"Cosa significa una restrizione 'D' sulla patente Florida?",options:[{en:"Driver must not exceed 55 mph",it:"Il conducente non deve superare i 55 mph"},{en:"Requires daylight driving only",it:"Richiede la guida solo di giorno"},{en:"Requires an automatic transmission",it:"Richiede un cambio automatico"},{en:"Requires corrective lenses",it:"Richiede lenti correttive"}],correct:1,explain_en:"A 'D' restriction on a Florida license indicates daylight driving only -- the driver is not permitted to drive after dark due to vision or other restrictions.",explain_it:"Una restrizione 'D' sulla patente Florida indica solo guida diurna -- al conducente non e consentito guidare dopo il buio a causa di visione o altre restrizioni."},
  {cat:"license",en:"What does a Florida driver's license 'CLASS E' allow?",it:"Cosa consente una patente Florida 'CLASS E'?",options:[{en:"Operation of commercial vehicles",it:"Operazione di veicoli commerciali"},{en:"Operation of non-commercial motor vehicles with GVWR under 26,001 lbs",it:"Operazione di veicoli a motore non commerciali con GVWR inferiore a 26.001 libbre"},{en:"Operation of motorcycles only",it:"Operazione di sole moto"},{en:"Operation of vehicles requiring a CDL",it:"Operazione di veicoli che richiedono un CDL"}],correct:1,explain_en:"Florida Class E license: authorizes operation of non-commercial motor vehicles with a Gross Vehicle Weight Rating under 26,001 lbs. This is the standard personal vehicle license.",explain_it:"Patente Florida Class E: autorizza l'operazione di veicoli a motore non commerciali con GVWR inferiore a 26.001 libbre. Questa e la patente standard per veicoli personali."},
  {cat:"license",en:"What is the cost penalty for a second DUI conviction in Florida?",it:"Qual e la sanzione di costo per una seconda condanna DUI in Florida?",options:[{en:"Same as first DUI",it:"Uguale al primo DUI"},{en:"$1,000-$2,000 fine plus DUI school, IID, higher insurance, and reinstatement fees",it:"Multa di $1.000-$2.000 piu scuola DUI, IID, assicurazione piu alta e spese di ripristino"},{en:"Only a $500 increase over the first DUI",it:"Solo un aumento di $500 rispetto al primo DUI"},{en:"$5,000 flat fine",it:"Multa fissa di $5.000"}],correct:1,explain_en:"Second DUI in Florida: $1,000-$2,000 fine, mandatory IID for at least 1 year, mandatory DUI school Level II, FR-44 insurance. Total cost can exceed $10,000.",explain_it:"Secondo DUI in Florida: multa di $1.000-$2.000, IID obbligatorio per almeno 1 anno, scuola DUI Livello II obbligatoria, assicurazione FR-44."},
  {cat:"license",en:"What is the Florida law on keeping a driver's license in your possession while driving?",it:"Qual e la legge Florida sul tenere la patente in possesso durante la guida?",options:[{en:"Not required -- only need proof of insurance",it:"Non richiesto -- serve solo la prova assicurativa"},{en:"Must carry the license and present it to any law enforcement officer upon request",it:"Deve portare la patente e presentarla a qualsiasi agente delle forze dell'ordine su richiesta"},{en:"Only needed when renting a vehicle",it:"Necessario solo quando si noleggia un veicolo"},{en:"Digital license on phone is sufficient",it:"La patente digitale sul telefono e sufficiente"}],correct:1,explain_en:"Florida requires drivers to have their license in their possession while driving and to present it to law enforcement upon request. Failure to do so is a noncriminal traffic infraction.",explain_it:"La Florida richiede ai conducenti di avere la patente in loro possesso durante la guida e di presentarla alle forze dell'ordine su richiesta."},
  {cat:"license",en:"What is the minimum supervision requirement for a Florida learner's license holder?",it:"Qual e il requisito minimo di supervisione per un titolare del permesso per principianti Florida?",options:[{en:"Any adult over 18 may supervise",it:"Qualsiasi adulto over 18 puo supervisionare"},{en:"Must be accompanied by a licensed driver age 21 or older sitting in the front passenger seat",it:"Deve essere accompagnato da un conducente autorizzato di 21 anni o piu seduto nel sedile anteriore passeggero"},{en:"Parent or guardian only",it:"Solo genitore o tutore"},{en:"Any licensed driver regardless of age",it:"Qualsiasi conducente autorizzato indipendentemente dall'eta"}],correct:1,explain_en:"Florida learner's license: the supervising driver must be at least 21 years old, hold a valid license, and sit in the front passenger seat. They cannot be in the back seat.",explain_it:"Permesso per principianti Florida: il conducente supervisore deve avere almeno 21 anni, avere una patente valida e sedersi nel sedile anteriore passeggero."},
  {cat:"license",en:"What are the Florida requirements to upgrade from a learner's permit to a Class E Restricted License?",it:"Quali sono i requisiti Florida per passare dal permesso per principianti alla patente Class E limitata?",options:[{en:"Turn 16 and pass a written test",it:"Compiere 16 anni e superare un test scritto"},{en:"Hold learner's license 12 months, complete 50 hours supervised driving (10 at night), have no violations for 12 months",it:"Tenere il permesso 12 mesi, completare 50 ore di guida supervisionata (10 di notte), non avere violazioni per 12 mesi"},{en:"Only need to turn 16 and wait 6 months",it:"E necessario solo compiere 16 anni e aspettare 6 mesi"},{en:"Complete 25 hours driving and turn 16",it:"Completare 25 ore di guida e compiere 16 anni"}],correct:1,explain_en:"To upgrade from learner's to restricted license: must be at least 16, hold learner's for 12 months with no violations, complete 50 hours supervised driving (10 nighttime hours).",explain_it:"Per passare dal permesso alla patente limitata: deve avere almeno 16 anni, tenere il permesso per 12 mesi senza violazioni, completare 50 ore di guida supervisionata (10 ore notturne)."},

  // SESSION 9 FINAL
  {cat:"signs",en:"What does a 'School Zone' sign with a flashing light require during flashing hours?",it:"Cosa richiede un segnale 'School Zone' con luce lampeggiante durante le ore di lampeggio?",options:[{en:"Stop completely before entering",it:"Fermarsi completamente prima di entrare"},{en:"Reduce speed to the posted school zone limit -- typically 15-20 mph",it:"Ridurre la velocita al limite segnalato della zona scolastica -- tipicamente 15-20 mph"},{en:"Sound horn once to alert children",it:"Suonare il clacson una volta per avvisare i bambini"},{en:"Only school buses must slow down",it:"Solo gli scuolabus devono rallentare"}],correct:1,explain_en:"School zones with flashing lights require all vehicles to reduce speed to the posted limit (usually 15-20 mph) whenever the light is flashing -- indicating children are present.",explain_it:"Le zone scolastiche con luci lampeggianti richiedono a tutti i veicoli di ridurre la velocita al limite segnalato (solitamente 15-20 mph) ogni volta che la luce lampeggia."},
  {cat:"signs",en:"What does a 'Hospital Zone' sign require?",it:"Cosa richiede un segnale 'Hospital Zone'?",options:[{en:"No passing in the zone",it:"Nessun sorpasso nella zona"},{en:"Reduced noise and speed -- often with a lower speed limit and restrictions on horn use",it:"Rumore e velocita ridotti -- spesso con un limite di velocita piu basso e restrizioni sull'uso del clacson"},{en:"All vehicles must stop for 3 seconds",it:"Tutti i veicoli devono fermarsi per 3 secondi"},{en:"Emergency vehicles have absolute right of way",it:"I veicoli di emergenza hanno la precedenza assoluta"}],correct:1,explain_en:"Hospital zones typically have reduced speed limits and prohibit unnecessary horn use to minimize noise for patients. Observe posted signs carefully.",explain_it:"Le zone ospedaliere hanno tipicamente limiti di velocita ridotti e vietano l'uso non necessario del clacson per minimizzare il rumore per i pazienti."},
  {cat:"signs",en:"What does a yellow and black 'X' sign on a railroad crossing mean?",it:"Cosa significa un segnale giallo e nero a forma di 'X' a un passaggio a livello?",options:[{en:"The crossing is closed permanently",it:"Il passaggio e chiuso permanentemente"},{en:"A railroad crossing is ahead -- the X shape is the advance warning crossbuck",it:"Un passaggio a livello e in avanti -- la forma X e il crossbuck di avvertimento anticipato"},{en:"A speed limit of 10 mph applies",it:"Si applica un limite di velocita di 10 mph"},{en:"Only trucks must stop here",it:"Solo i camion devono fermarsi qui"}],correct:1,explain_en:"The round yellow railroad advance warning sign with an X and RR warns drivers that a railroad crossing is ahead. Slow down, prepare to stop if a train is approaching.",explain_it:"Il segnale rotondo giallo di avvertimento ferroviario anticipato con una X e RR avvisa i conducenti che un passaggio a livello e in avanti."},
  {cat:"signs",en:"What does a 'Shared Lane Marking' (sharrow) on the road mean?",it:"Cosa significa una 'Shared Lane Marking' (sharrow) sulla strada?",options:[{en:"Parking is allowed in this lane",it:"Il parcheggio e consentito in questa corsia"},{en:"A lane shared by both motor vehicles and bicycles -- cyclists may use the full lane",it:"Una corsia condivisa sia da veicoli a motore che da biciclette -- i ciclisti possono usare l'intera corsia"},{en:"Motor vehicles must yield to cyclists",it:"I veicoli a motore devono cedere ai ciclisti"},{en:"Truck route marking",it:"Segnaletica percorso camion"}],correct:1,explain_en:"Sharrow (shared lane marking) indicates a road shared by vehicles and cyclists. Cyclists may use the full lane width. Drivers must share the lane and give cyclists at least 3 feet.",explain_it:"Sharrow indica una strada condivisa da veicoli e ciclisti. I ciclisti possono usare l'intera larghezza della corsia. I conducenti devono condividere la corsia e dare ai ciclisti almeno 3 piedi."},
  {cat:"signs",en:"What does a 'Pedestrian Hybrid Beacon' (HAWK signal) require of drivers?",it:"Cosa richiede ai conducenti un 'Pedestrian Hybrid Beacon' (segnale HAWK)?",options:[{en:"Proceed normally -- it only signals pedestrians",it:"Procedere normalmente -- segnala solo i pedoni"},{en:"Stop on red or flashing red phases and yield to pedestrians crossing",it:"Fermarsi nelle fasi di rosso o rosso lampeggiante e cedere ai pedoni che attraversano"},{en:"Only yield if pedestrians are present",it:"Cedere solo se i pedoni sono presenti"},{en:"Treat it as a yield sign always",it:"Trattarlo sempre come un segnale di resa"}],correct:1,explain_en:"HAWK signals: when dark = no action needed. Yellow = slow/prepare to stop. Solid red = stop. Flashing red = stop then proceed when pedestrians have cleared.",explain_it:"Segnali HAWK: quando spento = nessuna azione. Giallo = rallentare/prepararsi a fermarsi. Rosso fisso = fermarsi. Rosso lampeggiante = fermarsi poi procedere quando i pedoni hanno liberato."},
  {cat:"signs",en:"What does an arrow on a speed limit sign mean?",it:"Cosa significa una freccia su un segnale di limite di velocita?",options:[{en:"The speed limit applies only in the direction of the arrow",it:"Il limite di velocita si applica solo nella direzione della freccia"},{en:"Advisory speed for the upcoming curve in the direction shown",it:"Velocita consigliata per la curva imminente nella direzione mostrata"},{en:"Minimum speed requirement",it:"Requisito di velocita minima"},{en:"Speed applies to the turning lane only",it:"La velocita si applica solo alla corsia di svolta"}],correct:1,explain_en:"A speed limit sign with an arrow indicates the advisory or regulatory speed for a specific feature ahead (curve, turn, ramp) in the direction of the arrow.",explain_it:"Un segnale di limite di velocita con una freccia indica la velocita consigliata o normativa per una caratteristica specifica in avanti (curva, svolta, rampa) nella direzione della freccia."},
  {cat:"signs",en:"What does a 'Reverse Curve' sign indicate?",it:"Cosa indica un segnale 'Reverse Curve'?",options:[{en:"A U-turn is permitted",it:"E consentita un'inversione di marcia"},{en:"The road curves one way then immediately curves the opposite way -- an S-curve",it:"La strada curva in una direzione poi curva immediatamente nella direzione opposta -- una curva a S"},{en:"Go back -- road is closed",it:"Tornare indietro -- la strada e chiusa"},{en:"A detour route begins",it:"Inizia un percorso di deviazione"}],correct:1,explain_en:"A Reverse Curve sign (S-curve) warns of two consecutive curves in opposite directions. Reduce speed before the first curve and maintain it through both.",explain_it:"Un segnale Reverse Curve (curva a S) avvisa di due curve consecutive in direzioni opposte. Ridurre la velocita prima della prima curva e mantenerla attraverso entrambe."},
  {cat:"signs",en:"What does a 'Low Ground Clearance Railroad Crossing' sign mean?",it:"Cosa significa un segnale 'Low Ground Clearance Railroad Crossing'?",options:[{en:"A hill before the crossing",it:"Una collina prima del passaggio"},{en:"The crossing has an abrupt angle that may cause long or low vehicles to bottom out on the tracks",it:"Il passaggio ha un angolo brusco che puo causare il tocco del fondo nei veicoli lunghi o bassi sui binari"},{en:"The tracks are buried underground",it:"I binari sono sotterrati"},{en:"Speed bump at the crossing",it:"Dosso al passaggio"}],correct:1,explain_en:"Low Ground Clearance at a railroad crossing: the track is angled such that low-clearance vehicles (trailers, sports cars, buses) may get stuck on the rails. Approach with extreme caution.",explain_it:"Bassa altezza da terra a un passaggio a livello: il binario e inclinato in modo tale che i veicoli a bassa altezza possono rimanere bloccati sui binari."},
  {cat:"signs",en:"What does a 'Center Left Turn Lane' (two-way left turn lane) pavement marking mean?",it:"Cosa significa una segnaletica 'Center Left Turn Lane' (corsia di svolta sinistra a doppio senso)?",options:[{en:"A passing lane for all traffic",it:"Una corsia di sorpasso per tutto il traffico"},{en:"A shared lane for left-turning vehicles from both directions -- use only to turn left or enter from a side street",it:"Una corsia condivisa per i veicoli che svoltano a sinistra da entrambe le direzioni -- usare solo per svoltare a sinistra o entrare da una strada laterale"},{en:"An HOV lane for 2+ passengers",it:"Una corsia HOV per 2+ passeggeri"},{en:"A bike lane on busy roads",it:"Una corsia ciclabile sulle strade trafficate"}],correct:1,explain_en:"Two-way left turn lanes (TWLTL) are for left-turning vehicles from either direction. Do not use as a travel lane or for passing. Enter only when ready to turn.",explain_it:"Le corsie di svolta sinistra a doppio senso (TWLTL) sono per i veicoli che svoltano a sinistra da entrambe le direzioni. Non usare come corsia di marcia o per sorpassare."},
  {cat:"signs",en:"What does a green curb mean?",it:"Cosa significa un marciapiede verde?",options:[{en:"No parking restrictions",it:"Nessuna restrizione di parcheggio"},{en:"Time-limited parking -- usually 10-30 minutes maximum",it:"Parcheggio a tempo limitato -- solitamente massimo 10-30 minuti"},{en:"Parking for disabled persons",it:"Parcheggio per persone disabili"},{en:"Commercial vehicles only",it:"Solo veicoli commerciali"}],correct:1,explain_en:"Green curbs indicate time-limited parking -- typically short-duration spots (10, 15, or 30 minutes). Look for posted signs for the exact time limit.",explain_it:"I marciapiedi verdi indicano parcheggio a tempo limitato -- tipicamente posti di breve durata (10, 15 o 30 minuti). Cercare i segnali affissi per il limite di tempo esatto."},
  {cat:"signs",en:"What does a blue curb mean?",it:"Cosa significa un marciapiede blu?",options:[{en:"Time-limited parking",it:"Parcheggio a tempo limitato"},{en:"Disabled parking only -- requires valid placard or disability license plate",it:"Solo parcheggio disabili -- richiede un permesso valido o targa di disabilita"},{en:"Police vehicles only",it:"Solo veicoli di polizia"},{en:"Parking for electric vehicles",it:"Parcheggio per veicoli elettrici"}],correct:1,explain_en:"Blue curbs mark parking spaces reserved for persons with disabilities. A valid disabled placard or disability license plate is required -- violators face significant fines.",explain_it:"I marciapiedi blu segnano i parcheggi riservati alle persone con disabilita. E richiesto un permesso disabili valido o una targa di disabilita."},
  {cat:"signs",en:"What do pavement arrows in a turn lane mean?",it:"Cosa significano le frecce sulla pavimentazione in una corsia di svolta?",options:[{en:"Advisory only",it:"Solo advisory"},{en:"You must travel in the direction(s) shown -- it is a regulatory marking",it:"Devi viaggiare nella direzione/i mostrata -- e una segnaletica normativa"},{en:"Recommended path through intersection",it:"Percorso consigliato attraverso l'incrocio"},{en:"Only for buses and trucks",it:"Solo per autobus e camion"}],correct:1,explain_en:"Pavement arrows in turn lanes are regulatory -- they tell you which direction(s) you MUST go from that lane. Going straight from a turn-only lane is a violation.",explain_it:"Le frecce sulla pavimentazione nelle corsie di svolta sono normative -- ti dicono in quale direzione/i DEVI andare da quella corsia."},
  {cat:"signs",en:"What does a 'Work Zone' speed limit sign mean legally?",it:"Cosa significa legalmente un segnale di limite di velocita 'Work Zone'?",options:[{en:"Advisory only -- workers are not always present",it:"Solo advisory -- i lavoratori non sono sempre presenti"},{en:"A legally enforceable speed limit with doubled fines -- applies whether workers are present or not",it:"Un limite di velocita legalmente applicabile con multe raddoppiate -- si applica sia che i lavoratori siano presenti o meno"},{en:"Only applies when flaggers are present",it:"Si applica solo quando sono presenti i segnalatori"},{en:"Applies only to trucks",it:"Si applica solo ai camion"}],correct:1,explain_en:"Work zone speed limits are legally enforceable with doubled fines. The reduced limit applies throughout the defined work zone regardless of worker presence.",explain_it:"I limiti di velocita nelle zone di lavoro sono legalmente applicabili con multe raddoppiate. Il limite ridotto si applica in tutta la zona di lavoro definita indipendentemente dalla presenza dei lavoratori."},
  {cat:"signs",en:"What does a 'Slippery When Wet' sign with a motorcycle symbol indicate?",it:"Cosa indica un segnale 'Slippery When Wet' con simbolo moto?",options:[{en:"A motorcycle park ahead",it:"Un parcheggio moto in avanti"},{en:"The road surface is especially slippery when wet -- motorcycles and cyclists are particularly at risk",it:"La superficie stradale e particolarmente scivolosa quando bagnata -- le moto e i ciclisti sono particolarmente a rischio"},{en:"Motorcycles must stop here when raining",it:"Le moto devono fermarsi qui quando piove"},{en:"A bike lane begins",it:"Inizia una corsia ciclabile"}],correct:1,explain_en:"Slippery When Wet with a motorcycle symbol warns that the surface (often metal grates, bridge decks, or polished pavement) is especially dangerous for motorcycles in wet conditions.",explain_it:"Slippery When Wet con simbolo moto avvisa che la superficie (spesso griglie metalliche, ponti o pavimentazione lucida) e particolarmente pericolosa per le moto in condizioni bagnate."},
  {cat:"signs",en:"What does a 'Signal Ahead' sign combined with 'PREPARE TO STOP' mean?",it:"Cosa significa un segnale 'Signal Ahead' combinato con 'PREPARE TO STOP'?",options:[{en:"A railroad crossing is imminent",it:"Un passaggio a livello e imminente"},{en:"A traffic signal is ahead and based on signal timing you should be ready to stop",it:"Un semaforo e in avanti e in base alla temporizzazione del segnale dovresti essere pronto a fermarti"},{en:"Stop immediately",it:"Fermarsi immediatamente"},{en:"Speed up to catch the green light",it:"Accelerare per prendere il verde"}],correct:1,explain_en:"Signal Ahead with Prepare to Stop is used with adaptive signal systems to warn drivers the signal ahead is likely to be red when they arrive -- prepare to stop.",explain_it:"Signal Ahead con Prepare to Stop viene usato con sistemi di segnali adattativi per avvisare i conducenti che il segnale in avanti e probabile che sia rosso quando arrivano."},
  {cat:"laws",en:"What is the Florida law about driving with headphones covering both ears?",it:"Qual e la legge Florida sulla guida con le cuffie che coprono entrambe le orecchie?",options:[{en:"Always legal for all drivers",it:"Sempre legale per tutti i conducenti"},{en:"Illegal for motor vehicle drivers -- using a headset covering both ears is prohibited",it:"Illegale per i conducenti di veicoli a motore -- e vietato usare un auricolare che copre entrambe le orecchie"},{en:"Legal only on highways",it:"Legale solo in autostrada"},{en:"Only illegal for CDL holders",it:"Illegale solo per i titolari CDL"}],correct:1,explain_en:"Florida prohibits wearing a headset or earphones on both ears while operating a motor vehicle. One ear may be covered. CDL holders may not use any headset.",explain_it:"La Florida vieta di indossare cuffie o auricolari su entrambe le orecchie durante la guida di un veicolo a motore. Un orecchio puo essere coperto."},
  {cat:"laws",en:"What is the Florida law regarding driving with a pet on the driver's lap?",it:"Qual e la legge Florida riguardo alla guida con un animale domestico in grembo al conducente?",options:[{en:"Legal -- pets are allowed anywhere in the vehicle",it:"Legale -- gli animali domestici sono consentiti ovunque nel veicolo"},{en:"No specific law but could be cited for careless driving or distracted driving",it:"Nessuna legge specifica ma potrebbe essere citato per guida imprudente o guida distratta"},{en:"Legal only if the pet is under 10 pounds",it:"Legale solo se l'animale domestico pesa meno di 10 libbre"},{en:"Illegal -- all pets must be crated",it:"Illegale -- tutti gli animali domestici devono essere in un trasportino"}],correct:1,explain_en:"Florida has no specific law against pets on laps, but driving with a pet that impairs control can be cited as careless driving (a moving violation with points and fines).",explain_it:"La Florida non ha una legge specifica contro gli animali in grembo, ma guidare con un animale che compromette il controllo puo essere citato come guida imprudente."},
  {cat:"laws",en:"What is Florida's law about the driver's responsibility for passengers not wearing seatbelts?",it:"Qual e la legge Florida sulla responsabilita del conducente per i passeggeri che non indossano le cinture?",options:[{en:"Only the passenger is responsible",it:"Solo il passeggero e responsabile"},{en:"The driver is responsible for ensuring all passengers under 18 are buckled -- adult passengers are personally responsible",it:"Il conducente e responsabile di garantire che tutti i passeggeri under 18 abbiano le cinture -- i passeggeri adulti sono personalmente responsabili"},{en:"The vehicle owner is always responsible",it:"Il proprietario del veicolo e sempre responsabile"},{en:"No one is cited -- only the unbuckled person gets a warning",it:"Nessuno viene citato -- solo la persona non allacciata riceve un avvertimento"}],correct:1,explain_en:"Florida: drivers are responsible for ensuring ALL passengers under 18 are properly restrained. Adult front-seat passengers are primarily responsible for their own seatbelt use.",explain_it:"Florida: i conducenti sono responsabili di garantire che TUTTI i passeggeri under 18 siano adeguatamente trattenuti. I passeggeri adulti del sedile anteriore sono principalmente responsabili per il proprio uso della cintura."},
  {cat:"laws",en:"What is the Florida law about honking your horn at night in a residential area?",it:"Qual e la legge Florida sul suonare il clacson di notte in una zona residenziale?",options:[{en:"Always permitted if necessary for safety",it:"Sempre consentito se necessario per la sicurezza"},{en:"Excessive, unnecessary horn use at night in residential areas is prohibited as a noise violation",it:"L'uso eccessivo e non necessario del clacson di notte nelle aree residenziali e vietato come violazione del rumore"},{en:"Only prohibited between midnight and 6am",it:"Vietato solo tra mezzanotte e le 6"},{en:"Only prohibited near hospitals",it:"Vietato solo vicino agli ospedali"}],correct:1,explain_en:"Unnecessary horn use at night in residential areas violates both traffic law (horn for safety only) and noise ordinances. Use horn only when safety requires it.",explain_it:"L'uso non necessario del clacson di notte nelle aree residenziali viola sia il codice stradale (clacson solo per la sicurezza) che le ordinanze sul rumore."},
  {cat:"laws",en:"What is Florida's law on tinted windows?",it:"Qual e la legge Florida sui finestrini oscurati?",options:[{en:"No restrictions on window tinting",it:"Nessuna restrizione sull'oscuramento dei finestrini"},{en:"Front side windows must allow 28%+ light transmittance; back side and rear windows may be darker",it:"I finestrini laterali anteriori devono consentire 28%+ di trasmittanza della luce; i laterali posteriori e il lunotto possono essere piu scuri"},{en:"All windows must be clear -- no tinting permitted",it:"Tutti i finestrini devono essere trasparenti -- nessun oscuramento consentito"},{en:"Only the rear windshield may be tinted",it:"Solo il lunotto posteriore puo essere oscurato"}],correct:1,explain_en:"Florida tint law: front windshield may have a non-reflective tint on top 6 inches. Front side windows: 28%+ VLT. Rear side and back windows: 15%+ VLT. Reflectivity limits also apply.",explain_it:"Legge oscuramento Florida: parabrezza anteriore puo avere tinta non riflettente sulle 6 pollici superiori. Finestrini laterali anteriori: 28%+ VLT. Laterali posteriori e lunotto: 15%+ VLT."},
  {cat:"laws",en:"What is the Florida law on the use of studded snow tires?",it:"Qual e la legge Florida sull'uso di pneumatici da neve con borchie?",options:[{en:"Legal year-round",it:"Legale tutto l'anno"},{en:"Prohibited -- studded tires damage road surfaces and are not needed in Florida's climate",it:"Vietato -- i pneumatici con borchie danneggiano le superfici stradali e non sono necessari nel clima della Florida"},{en:"Legal only from November to March",it:"Legale solo da novembre a marzo"},{en:"Legal only for 4WD vehicles",it:"Legale solo per i veicoli 4WD"}],correct:1,explain_en:"Studded snow tires are prohibited in Florida. The state's mild climate makes them unnecessary, and they damage road surfaces.",explain_it:"I pneumatici da neve con borchie sono vietati in Florida. Il clima mite dello stato li rende non necessari e danneggiano le superfici stradali."},
  {cat:"laws",en:"What is the Florida law on the right-of-way between a vehicle and a horse-drawn carriage?",it:"Qual e la legge Florida sulla precedenza tra un veicolo e una carrozza trainata da cavalli?",options:[{en:"Vehicles always have the right of way",it:"I veicoli hanno sempre la precedenza"},{en:"Yield to horse-drawn vehicles -- horses may be startled by motor vehicles",it:"Cedere ai veicoli trainati da cavalli -- i cavalli possono essere spaventati dai veicoli a motore"},{en:"Only yield if the horse is in your lane",it:"Cedere solo se il cavallo e nella tua corsia"},{en:"No special rules apply",it:"Non si applicano regole speciali"}],correct:1,explain_en:"Florida law requires motor vehicle drivers to exercise caution around horses and horse-drawn vehicles. Yield, slow down, and avoid startling the animals with sudden noises or movements.",explain_it:"La legge Florida richiede ai conducenti di veicoli a motore di esercitare cautela intorno ai cavalli e ai veicoli trainati da cavalli. Cedere, rallentare ed evitare di spaventare gli animali."},
  {cat:"laws",en:"What must a Florida driver do at an uncontrolled railroad crossing?",it:"Cosa deve fare un conducente Florida a un passaggio a livello non controllato?",options:[{en:"Slow to 15 mph and proceed",it:"Rallentare a 15 mph e procedere"},{en:"Slow down, look both ways, and yield to any approaching train -- stop if a train is approaching",it:"Rallentare, guardare in entrambe le direzioni e cedere a qualsiasi treno in avvicinamento -- fermarsi se un treno si sta avvicinando"},{en:"Stop completely regardless of whether a train is present",it:"Fermarsi completamente indipendentemente dalla presenza di un treno"},{en:"Sound horn twice and proceed",it:"Suonare il clacson due volte e procedere"}],correct:1,explain_en:"At an uncontrolled railroad crossing: slow down, look both ways, listen for trains, and stop if a train is approaching. Never stop on the tracks.",explain_it:"A un passaggio a livello non controllato: rallentare, guardare in entrambe le direzioni, ascoltare i treni e fermarsi se un treno si sta avvicinando. Non fermarsi mai sui binari."},
  {cat:"laws",en:"What is the Florida law about driving on a limited-access highway with a learner's license?",it:"Qual e la legge Florida sulla guida su un'autostrada a accesso limitato con il permesso per principianti?",options:[{en:"Prohibited -- learner's license holders may not use interstates",it:"Vietato -- i titolari del permesso per principianti non possono usare le autostrade interstatali"},{en:"Permitted with a licensed 21+ supervisor in the passenger seat",it:"Consentito con un supervisore autorizzato 21+ nel sedile passeggero"},{en:"Only permitted at night",it:"Consentito solo di notte"},{en:"Permitted only on highways with speed limits under 55 mph",it:"Consentito solo sulle autostrade con limiti di velocita inferiori a 55 mph"}],correct:1,explain_en:"Florida learner's license holders may drive on limited-access highways (interstates) as long as a licensed driver 21+ is in the front passenger seat.",explain_it:"I titolari del permesso per principianti Florida possono guidare sulle autostrade a accesso limitato (interstatali) purche un conducente autorizzato 21+ sia nel sedile anteriore passeggero."},
  {cat:"laws",en:"What is the Florida law about following distance behind a fire truck responding to an alarm?",it:"Qual e la legge Florida sulla distanza di seguimento dietro un'autopompa che risponde a un allarme?",options:[{en:"200 feet",it:"200 piedi"},{en:"500 feet minimum",it:"Minimo 500 piedi"},{en:"100 feet",it:"100 piedi"},{en:"One city block",it:"Un isolato"}],correct:1,explain_en:"Florida law requires maintaining at least 500 feet following distance behind a fire truck that is responding to an alarm with lights and sirens.",explain_it:"La legge Florida richiede di mantenere almeno 500 piedi di distanza dietro un'autopompa che risponde a un allarme con luci e sirene."},
  {cat:"laws",en:"What is Florida's law on loading or unloading school buses?",it:"Qual e la legge Florida sul carico o scarico degli scuolabus?",options:[{en:"Only stop when the bus is directly in front of you",it:"Fermarsi solo quando il bus e direttamente davanti a te"},{en:"Stop when the bus activates red flashing lights and stop arm -- remain stopped until arm retracts and bus moves",it:"Fermarsi quando il bus attiva le luci rosse lampeggianti e il braccio di stop -- rimanere fermi finche il braccio non si ritrae e il bus non si muove"},{en:"Slow to 20 mph and proceed past the bus",it:"Rallentare a 20 mph e procedere oltre il bus"},{en:"Only stop if children are visible crossing the road",it:"Fermarsi solo se i bambini sono visibili mentre attraversano la strada"}],correct:1,explain_en:"All vehicles must stop when a school bus activates red flashing lights and the stop arm extends. Remain stopped until the arm retracts and the bus resumes movement.",explain_it:"Tutti i veicoli devono fermarsi quando uno scuolabus attiva le luci rosse lampeggianti e il braccio di stop si estende. Rimanere fermi finche il braccio non si ritrae e il bus non riprende a muoversi."},
  {cat:"laws",en:"What is the proper procedure at a traffic circle when you need to make a left turn equivalent?",it:"Qual e la procedura corretta a una rotonda quando hai bisogno di fare l'equivalente di una svolta sinistra?",options:[{en:"Enter the circle, go past the first exit, continue around and exit at the appropriate street",it:"Entrare nel cerchio, passare il primo uscita, continuare intorno e uscire alla strada appropriata"},{en:"Wait outside the circle for traffic to clear completely",it:"Aspettare fuori dal cerchio che il traffico si liberi completamente"},{en:"Signal left immediately before entering",it:"Segnalare a sinistra immediatamente prima di entrare"},{en:"Use the left lane only for left-equivalent turns",it:"Usare solo la corsia sinistra per le svolte equivalenti a sinistra"}],correct:0,explain_en:"In a roundabout, all turns are made by traveling counterclockwise around the circle. For a left turn equivalent, stay in the circle past the first exits and exit at the appropriate road.",explain_it:"In una rotonda, tutte le svolte vengono effettuate viaggiando in senso antiorario intorno al cerchio. Per l'equivalente di una svolta sinistra, rimani nel cerchio oltre le prime uscite ed esci alla strada appropriata."},
  {cat:"laws",en:"What is the Florida penalty for a second school zone speed violation?",it:"Qual e la sanzione Florida per una seconda violazione della velocita in zona scolastica?",options:[{en:"Same fine as the first",it:"Stessa multa della prima"},{en:"Doubled fines (6 points vs standard 4) and possible mandatory court appearance",it:"Multe raddoppiate (6 punti vs 4 standard) e possibile comparizione obbligatoria in tribunale"},{en:"Only a warning for the first few violations",it:"Solo un avvertimento per le prime violazioni"},{en:"$50 maximum fine",it:"Multa massima di $50"}],correct:1,explain_en:"Speeding in a school zone adds 6 points to the driving record (vs. 4 for regular speeding). Fines are doubled. Repeat violations can result in mandatory court appearance and license suspension.",explain_it:"Eccesso di velocita in una zona scolastica aggiunge 6 punti al casellario di guida (vs. 4 per l'eccesso di velocita normale). Le multe sono raddoppiate."},
  {cat:"laws",en:"What is the Florida law on the use of bicycle lanes by motor vehicles?",it:"Qual e la legge Florida sull'uso delle corsie ciclabili da parte dei veicoli a motore?",options:[{en:"Motor vehicles may use bike lanes freely",it:"I veicoli a motore possono usare liberamente le corsie ciclabili"},{en:"Motor vehicles may only enter a bike lane to turn right -- and must yield to cyclists first",it:"I veicoli a motore possono entrare in una corsia ciclabile solo per svoltare a destra -- e devono prima cedere ai ciclisti"},{en:"Motor vehicles may use bike lanes for passing",it:"I veicoli a motore possono usare le corsie ciclabili per sorpassare"},{en:"Bike lanes are legal for motorcycles only",it:"Le corsie ciclabili sono legali solo per le moto"}],correct:1,explain_en:"Motor vehicles may enter a bike lane only to make a right turn -- and must yield to cyclists in the lane before crossing. Driving in the bike lane for any other reason is illegal.",explain_it:"I veicoli a motore possono entrare in una corsia ciclabile solo per svoltare a destra -- e devono cedere ai ciclisti nella corsia prima di attraversare."},
  {cat:"laws",en:"What is the Florida law about turning left from a one-way street?",it:"Qual e la legge Florida sulla svolta sinistra da una strada a senso unico?",options:[{en:"Always prohibited from one-way streets",it:"Sempre vietata dalle strade a senso unico"},{en:"Permitted from the leftmost lane -- yield to pedestrians and any conflicting traffic",it:"Consentita dalla corsia piu a sinistra -- cedere ai pedoni e a qualsiasi traffico in conflitto"},{en:"Only permitted with a protected arrow signal",it:"Consentita solo con un segnale di freccia protetto"},{en:"Must stop and check both ways before turning",it:"Deve fermarsi e controllare in entrambe le direzioni prima di svoltare"}],correct:1,explain_en:"Turning left from a one-way street: turn from the leftmost lane onto the closest lane of the cross street. Yield to pedestrians and conflicting traffic.",explain_it:"Svoltare a sinistra da una strada a senso unico: svoltare dalla corsia piu a sinistra nella corsia piu vicina della strada trasversale. Cedere ai pedoni e al traffico in conflitto."},
  {cat:"laws",en:"What is the Florida law on parking in front of or within 20 feet of a crosswalk?",it:"Qual e la legge Florida sul parcheggio davanti o entro 20 piedi da un attraversamento pedonale?",options:[{en:"Legal if the spot is not marked no parking",it:"Legale se il posto non e segnato come divieto di parcheggio"},{en:"Prohibited -- parking within 20 feet of a crosswalk at an intersection is illegal",it:"Vietato -- il parcheggio entro 20 piedi da un attraversamento pedonale a un incrocio e illegale"},{en:"Legal for 5 minutes",it:"Legale per 5 minuti"},{en:"Only prohibited near marked crosswalks",it:"Vietato solo vicino agli attraversamenti segnati"}],correct:1,explain_en:"Florida prohibits parking within 20 feet of a crosswalk at an intersection. This ensures drivers can see pedestrians and pedestrians can see vehicles.",explain_it:"La Florida vieta il parcheggio entro 20 piedi da un attraversamento pedonale a un incrocio. Questo garantisce che i conducenti possano vedere i pedoni e i pedoni possano vedere i veicoli."},
  {cat:"laws",en:"What is the Florida law on right-of-way when two vehicles are approaching the same intersection from perpendicular roads without signals or signs?",it:"Qual e la legge Florida sulla precedenza quando due veicoli si avvicinano allo stesso incrocio da strade perpendicolari senza segnali?",options:[{en:"The vehicle on the main road has the right of way",it:"Il veicolo sulla strada principale ha la precedenza"},{en:"Yield to the vehicle on your right",it:"Cedere al veicolo alla tua destra"},{en:"Both vehicles must stop and yield to each other",it:"Entrambi i veicoli devono fermarsi e cedere l'uno all'altro"},{en:"The vehicle moving faster has the right of way",it:"Il veicolo piu veloce ha la precedenza"}],correct:1,explain_en:"At uncontrolled intersections with no signs or signals: yield to the vehicle on your right. This is the fundamental right-of-way tie-breaking rule.",explain_it:"Agli incroci non controllati senza segnali: cedere al veicolo alla tua destra. Questa e la regola fondamentale di spareggio della precedenza."},
  {cat:"laws",en:"What is the Florida law about driving the wrong way after missing a highway exit?",it:"Qual e la legge Florida sulla guida contromano dopo aver mancato un'uscita autostradale?",options:[{en:"Legal if done quickly",it:"Legale se fatto velocemente"},{en:"Illegal -- continue to the next exit; never back up or drive against traffic on a highway",it:"Illegale -- continuare alla prossima uscita; non fare mai retromarcia o guidare contromano in autostrada"},{en:"Legal if the highway is empty",it:"Legale se l'autostrada e vuota"},{en:"Permitted with hazard lights on",it:"Consentito con le luci di pericolo accese"}],correct:1,explain_en:"Never back up on a highway or use an entrance ramp as an exit. Continue to the next exit and turn around. Wrong-way driving is one of the most dangerous and illegal acts on the road.",explain_it:"Non fare mai retromarcia in autostrada o usare una rampa di accesso come uscita. Continuare alla prossima uscita e girare. La guida contromano e uno degli atti piu pericolosi e illegali sulla strada."},
  {cat:"laws",en:"What is the Florida law on transporting hazardous materials?",it:"Qual e la legge Florida sul trasporto di materiali pericolosi?",options:[{en:"No special requirements for personal vehicles",it:"Nessun requisito speciale per i veicoli personali"},{en:"Requires a CDL with hazmat endorsement -- vehicles must display proper placards and follow specific routes",it:"Richiede un CDL con approvazione hazmat -- i veicoli devono esporre le tabelle appropriate e seguire percorsi specifici"},{en:"Only applies to out-of-state shipments",it:"Si applica solo alle spedizioni fuori stato"},{en:"Any driver with a valid license may transport hazmat",it:"Qualsiasi conducente con una patente valida puo trasportare hazmat"}],correct:1,explain_en:"Transporting hazardous materials commercially requires a CDL with hazmat endorsement, proper placards on the vehicle, specific routing rules, and compliance with federal FMCSA regulations.",explain_it:"Il trasporto commerciale di materiali pericolosi richiede un CDL con approvazione hazmat, tabelle appropriate sul veicolo, regole di percorso specifiche e conformita alle normative federali FMCSA."},
  {cat:"alcohol",en:"What is the approximate time for a healthy adult liver to process one standard drink?",it:"Qual e il tempo approssimativo per un fegato adulto sano per elaborare un drink standard?",options:[{en:"15 minutes",it:"15 minuti"},{en:"About 1 hour",it:"Circa 1 ora"},{en:"30 minutes",it:"30 minuti"},{en:"2 hours",it:"2 ore"}],correct:1,explain_en:"A healthy adult liver processes approximately one standard drink (0.6 oz pure alcohol) per hour. This rate is relatively constant and cannot be accelerated.",explain_it:"Un fegato adulto sano elabora circa un drink standard (17 ml di alcol puro) all'ora. Questa velocita e relativamente costante e non puo essere accelerata."},
  {cat:"alcohol",en:"What is the legal consequence in Florida of a third DUI conviction within 10 years?",it:"Qual e la conseguenza legale in Florida di una terza condanna DUI entro 10 anni?",options:[{en:"Same as a second DUI",it:"Uguale al secondo DUI"},{en:"A third-degree felony with up to 5 years in prison and 10-year license revocation",it:"Un crimine di terzo grado con fino a 5 anni di prigione e revoca della patente di 10 anni"},{en:"Mandatory life in prison",it:"Prigione a vita obbligatoria"},{en:"Only a $2,000 fine and community service",it:"Solo una multa di $2.000 e servizio alla comunita"}],correct:1,explain_en:"Third DUI within 10 years in Florida: third-degree felony, up to $5,000 fine, up to 5 years prison, mandatory 10-year license revocation.",explain_it:"Terzo DUI entro 10 anni in Florida: crimine di terzo grado, fino a $5.000 di multa, fino a 5 anni di prigione, revoca obbligatoria della patente di 10 anni."},
  {cat:"alcohol",en:"What is the effect of alcohol on night vision?",it:"Qual e l'effetto dell'alcol sulla visione notturna?",options:[{en:"Improves night vision",it:"Migliora la visione notturna"},{en:"Impairs night vision by reducing the eye's ability to adapt to darkness and glare",it:"Compromette la visione notturna riducendo la capacita dell'occhio di adattarsi all'oscurita e all'abbagliamento"},{en:"No effect on night vision",it:"Nessun effetto sulla visione notturna"},{en:"Only affects night vision above 0.15% BAC",it:"Influisce sulla visione notturna solo sopra 0,15% BAC"}],correct:1,explain_en:"Alcohol impairs night vision: reduces ability to adapt to darkness, increases glare sensitivity, and shrinks the visual field. Night driving while impaired is especially dangerous.",explain_it:"L'alcol compromette la visione notturna: riduce la capacita di adattarsi all'oscurita, aumenta la sensibilita all'abbagliamento e riduce il campo visivo."},
  {cat:"alcohol",en:"What is the Florida law about alcohol at public beaches and parks?",it:"Qual e la legge Florida sull'alcol nelle spiagge e nei parchi pubblici?",options:[{en:"Always legal on all Florida beaches",it:"Sempre legale su tutte le spiagge Florida"},{en:"Varies by county and local ordinance -- some areas prohibit alcohol on public beaches and parks",it:"Varia per contea e ordinanza locale -- alcune aree vietano l'alcol nelle spiagge e nei parchi pubblici"},{en:"Only prohibited at night",it:"Vietato solo di notte"},{en:"Legal everywhere in Florida under state law",it:"Legale ovunque in Florida in base alla legge statale"}],correct:1,explain_en:"Florida has no statewide law on beach alcohol. Individual counties (Escambia, Okaloosa, etc.) and municipalities set their own rules -- some prohibit alcohol on public beaches entirely.",explain_it:"La Florida non ha una legge statale sull'alcol in spiaggia. Le singole contee e i comuni stabiliscono le proprie regole -- alcune vietano completamente l'alcol nelle spiagge pubbliche."},
  {cat:"alcohol",en:"What is the role of blood alcohol concentration in determining DUI in Florida?",it:"Qual e il ruolo della concentrazione di alcol nel sangue nel determinare il DUI in Florida?",options:[{en:"BAC is irrelevant -- only field sobriety tests matter",it:"Il BAC e irrilevante -- contano solo i test di sobriety sul campo"},{en:"BAC of 0.08%+ is per se DUI; below 0.08% you can still be charged if impairment is observed",it:"BAC di 0,08%+ e per se DUI; sotto 0,08% puoi comunque essere accusato se viene osservata una compromissione"},{en:"BAC must be 0.10%+ for a DUI charge",it:"Il BAC deve essere 0,10%+ per un'accusa DUI"},{en:"Only field sobriety performance determines DUI",it:"Solo le prestazioni ai test di sobriety sul campo determinano il DUI"}],correct:1,explain_en:"Florida DUI: BAC 0.08%+ is per se DUI (no other evidence needed). Below 0.08%, you can still be charged if law enforcement observes impairment affecting normal faculties.",explain_it:"DUI Florida: BAC 0,08%+ e per se DUI (nessun'altra prova necessaria). Sotto 0,08%, puoi comunque essere accusato se le forze dell'ordine osservano una compromissione che influisce sulle normali facolta."},
  {cat:"alcohol",en:"What is the Florida law about selling alcohol to a visibly intoxicated person?",it:"Qual e la legge Florida sulla vendita di alcol a una persona visibilmente ubriaca?",options:[{en:"Legal -- the customer is responsible for their own intake",it:"Legale -- il cliente e responsabile del proprio consumo"},{en:"Illegal -- selling to a visibly intoxicated person is a violation for the establishment",it:"Illegale -- vendere a una persona visibilmente ubriaca e una violazione per l'esercizio"},{en:"Legal if the customer signs a waiver",it:"Legale se il cliente firma una rinuncia"},{en:"Only illegal after midnight",it:"Illegale solo dopo mezzanotte"}],correct:1,explain_en:"Florida Dram Shop law: establishments and their employees are prohibited from serving alcohol to visibly intoxicated persons. Violations can result in license revocation and civil liability.",explain_it:"Legge Dram Shop Florida: gli esercizi e i loro dipendenti non possono servire alcol alle persone visibilmente ubriache. Le violazioni possono comportare la revoca della licenza e la responsabilita civile."},
  {cat:"alcohol",en:"What are the mandatory minimum jail sentences for DUI in Florida?",it:"Quali sono le pene detentive minime obbligatorie per il DUI in Florida?",options:[{en:"No mandatory jail for any DUI",it:"Nessun carcere obbligatorio per nessun DUI"},{en:"First DUI: no mandatory jail. Second within 5 years: 10 days mandatory. Third within 10 years: 30 days mandatory.",it:"Primo DUI: nessun carcere obbligatorio. Secondo entro 5 anni: 10 giorni obbligatori. Terzo entro 10 anni: 30 giorni obbligatori."},{en:"All DUI convictions carry 30-day minimum",it:"Tutte le condanne DUI prevedono un minimo di 30 giorni"},{en:"Only DUI with injury carries mandatory jail",it:"Solo il DUI con lesioni prevede il carcere obbligatorio"}],correct:1,explain_en:"Florida DUI mandatory minimums: 1st offense = no mandatory jail (up to 6 months); 2nd within 5 years = 10 days mandatory; 3rd within 10 years = 30 days mandatory.",explain_it:"Minimi obbligatori DUI Florida: 1a infrazione = nessun carcere obbligatorio (fino a 6 mesi); 2a entro 5 anni = 10 giorni obbligatori; 3a entro 10 anni = 30 giorni obbligatori."},
  {cat:"alcohol",en:"How does fatigue interact with alcohol impairment?",it:"Come interagisce la stanchezza con la compromissione da alcol?",options:[{en:"Fatigue counteracts alcohol effects",it:"La stanchezza contrasta gli effetti dell'alcol"},{en:"Fatigue compounds alcohol impairment -- even small amounts of alcohol combined with fatigue cause dangerous impairment",it:"La stanchezza aggrava la compromissione da alcol -- anche piccole quantita di alcol combinate con la stanchezza causano una pericolosa compromissione"},{en:"Fatigue has no interaction with alcohol",it:"La stanchezza non ha interazione con l'alcol"},{en:"Alcohol reduces fatigue and therefore is safe when tired",it:"L'alcol riduce la stanchezza e quindi e sicuro quando si e stanchi"}],correct:1,explain_en:"Fatigue and alcohol are multiplicative: even a small amount of alcohol combined with sleep deprivation produces impairment far greater than either alone. Never drink before driving when fatigued.",explain_it:"Stanchezza e alcol sono moltiplicativi: anche una piccola quantita di alcol combinata con privazione del sonno produce una compromissione molto maggiore di ciascuno da solo."},
  {cat:"alcohol",en:"What is the Florida administrative license suspension (ALS) vs. criminal DUI suspension?",it:"Qual e la differenza tra la sospensione amministrativa della patente (ALS) e la sospensione DUI penale in Florida?",options:[{en:"They are the same",it:"Sono la stessa cosa"},{en:"ALS is imposed immediately by FLHSMV for BAC 0.08%+ or refusal; criminal suspension follows conviction -- both can apply",it:"ALS viene imposta immediatamente da FLHSMV per BAC 0,08%+ o rifiuto; la sospensione penale segue la condanna -- entrambe possono applicarsi"},{en:"Only ALS applies -- no criminal suspension",it:"Si applica solo ALS -- nessuna sospensione penale"},{en:"Criminal suspension cancels ALS",it:"La sospensione penale annulla l'ALS"}],correct:1,explain_en:"Florida has two DUI suspension tracks: ALS (administrative) is automatic upon arrest for 0.08%+ or refusal. Criminal suspension follows conviction. A person may face both.",explain_it:"La Florida ha due percorsi di sospensione DUI: ALS (amministrativa) e automatica all'arresto per 0,08%+ o rifiuto. La sospensione penale segue la condanna. Una persona puo affrontare entrambe."},
  {cat:"alcohol",en:"What is Florida's law on 'actual physical control' of a vehicle while intoxicated?",it:"Qual e la legge Florida sul 'controllo fisico effettivo' di un veicolo mentre si e ubriachi?",options:[{en:"Only applies when the vehicle is moving",it:"Si applica solo quando il veicolo e in movimento"},{en:"Being intoxicated in a parked car with the keys accessible constitutes DUI in Florida",it:"Essere ubriachi in un'auto parcheggiata con le chiavi accessibili costituisce DUI in Florida"},{en:"Only applies to running vehicles",it:"Si applica solo ai veicoli in funzione"},{en:"Sleeping in a parked car is never DUI",it:"Dormire in un'auto parcheggiata non e mai DUI"}],correct:1,explain_en:"Florida DUI includes 'actual physical control' -- being in the driver's seat with keys accessible (on ignition, in lap, or in hand) while intoxicated can result in DUI even if the car is parked.",explain_it:"Il DUI Florida include il 'controllo fisico effettivo' -- essere nel sedile del conducente con le chiavi accessibili mentre si e ubriachi puo comportare il DUI anche se l'auto e parcheggiata."},
  {cat:"license",en:"What is the Florida law on restricted licenses for medical conditions?",it:"Qual e la legge Florida sulle patenti con restrizioni per condizioni mediche?",options:[{en:"Medical conditions do not affect license status",it:"Le condizioni mediche non influiscono sullo stato della patente"},{en:"FLHSMV may impose restrictions (daylight only, limited distance, automatic transmission) based on medical review",it:"FLHSMV puo imporre restrizioni (solo diurno, distanza limitata, cambio automatico) in base alla revisione medica"},{en:"Only applies to drivers over 75",it:"Si applica solo ai conducenti over 75"},{en:"Drivers with medical conditions must surrender their license",it:"I conducenti con condizioni mediche devono consegnare la patente"}],correct:1,explain_en:"Florida FLHSMV may place medical restrictions on a license (daylight only, limited mileage, specific vehicle requirements) based on a physician's medical review if driving safety is a concern.",explain_it:"Florida FLHSMV puo imporre restrizioni mediche sulla patente (solo diurno, chilometraggio limitato, requisiti specifici del veicolo) in base alla revisione medica di un medico."},
  {cat:"license",en:"What is the Florida E6 endorsement on a driver's license?",it:"Cos'e l'approvazione E6 sulla patente Florida?",options:[{en:"Emergency vehicle operator certification",it:"Certificazione di operatore di veicolo di emergenza"},{en:"There is no E6 endorsement -- Florida uses letter restrictions not endorsements for Class E",it:"Non c'e approvazione E6 -- la Florida usa restrizioni alfabetiche non approvazioni per la Class E"},{en:"Authorization to drive commercial vehicles",it:"Autorizzazione a guidare veicoli commerciali"},{en:"Electric vehicle operator certification",it:"Certificazione di operatore di veicolo elettrico"}],correct:1,explain_en:"Florida Class E licenses use letter-coded restrictions (A through Z) indicating conditions of licensure -- not numbered endorsements. Endorsements (motorcycle, CDL) are separate.",explain_it:"Le patenti Florida Class E usano restrizioni codificate con lettere (da A a Z) che indicano le condizioni della licenza -- non approvazioni numerate. Le approvazioni (moto, CDL) sono separate."},
  {cat:"license",en:"What is the Florida law on the validity of an out-of-state driver's license for new residents?",it:"Qual e la legge Florida sulla validita di una patente fuori stato per i nuovi residenti?",options:[{en:"Out-of-state licenses remain valid indefinitely",it:"Le patenti fuori stato rimangono valide indefinitamente"},{en:"New Florida residents must obtain a Florida license within 30 days of establishing residency",it:"I nuovi residenti Florida devono ottenere una patente Florida entro 30 giorni dall'stabilimento della residenza"},{en:"Out-of-state licenses must be exchanged within 90 days",it:"Le patenti fuori stato devono essere scambiate entro 90 giorni"},{en:"Must convert within 6 months",it:"Deve essere convertita entro 6 mesi"}],correct:1,explain_en:"New Florida residents must obtain a Florida driver's license within 30 days of establishing residency. Visitors may drive on a valid out-of-state license.",explain_it:"I nuovi residenti Florida devono ottenere una patente Florida entro 30 giorni dall'stabilimento della residenza. I visitatori possono guidare con una patente fuori stato valida."},
  {cat:"license",en:"What is the REAL ID requirement on a Florida driver's license?",it:"Qual e il requisito REAL ID sulla patente Florida?",options:[{en:"All Florida licenses are automatically REAL ID compliant",it:"Tutte le patenti Florida sono automaticamente conformi al REAL ID"},{en:"Drivers may choose a REAL ID compliant license (star symbol) or a standard license -- REAL ID required for federal purposes like boarding flights",it:"I conducenti possono scegliere una patente conforme al REAL ID (simbolo stella) o una patente standard -- REAL ID richiesto per scopi federali come l'imbarco su voli"},{en:"REAL ID is only for commercial drivers",it:"REAL ID e solo per i conducenti commerciali"},{en:"REAL ID is optional and has no practical difference",it:"REAL ID e opzionale e non ha differenze pratiche"}],correct:1,explain_en:"Florida offers REAL ID compliant licenses (marked with a star). You need REAL ID or a passport for federal purposes including boarding domestic flights and entering federal buildings.",explain_it:"La Florida offre patenti conformi al REAL ID (contrassegnate con una stella). Hai bisogno del REAL ID o di un passaporto per scopi federali incluso l'imbarco su voli nazionali."},
  {cat:"license",en:"What is the Florida law on driving with a foreign license from a non-reciprocal country?",it:"Qual e la legge Florida sulla guida con una patente straniera da un paese non reciproco?",options:[{en:"Foreign licenses from any country are always valid in Florida",it:"Le patenti straniere di qualsiasi paese sono sempre valide in Florida"},{en:"Visitors may drive in Florida on a valid foreign license for up to 1 year -- after that a Florida license is required if residing in Florida",it:"I visitatori possono guidare in Florida con una patente straniera valida fino a 1 anno -- dopo di che e richiesta una patente Florida se si risiede in Florida"},{en:"Foreign licenses are never valid in Florida",it:"Le patenti straniere non sono mai valide in Florida"},{en:"Require an International Driving Permit to drive in Florida",it:"Richiedono un Permesso di Guida Internazionale per guidare in Florida"}],correct:1,explain_en:"Visitors to Florida may drive on a valid foreign license. However, once you establish Florida residency, you must obtain a Florida license within 30 days. An IDP is recommended but not legally required.",explain_it:"I visitatori della Florida possono guidare con una patente straniera valida. Tuttavia, una volta stabilita la residenza Florida, devi ottenere una patente Florida entro 30 giorni."},
  {cat:"license",en:"What is the Florida law about using a license from another state when applying for a Florida license?",it:"Qual e la legge Florida sull'uso di una patente di un altro stato quando si richiede la patente Florida?",options:[{en:"Must retake all tests from scratch",it:"Deve ripetere tutti i test da zero"},{en:"May be able to waive the skills test if you hold a valid out-of-state license -- knowledge and vision tests still required",it:"Potrebbe essere in grado di rinunciare al test di abilita se si possiede una patente valida fuori stato -- test di conoscenza e visione ancora richiesti"},{en:"Out-of-state license automatically converts to Florida",it:"La patente fuori stato si converte automaticamente in Florida"},{en:"Must wait 6 months in Florida before applying",it:"Deve aspettare 6 mesi in Florida prima di fare domanda"}],correct:1,explain_en:"With a valid out-of-state license, Florida may waive the driving skills test but still requires knowledge test, vision test, and proof of identity and residency documents.",explain_it:"Con una patente valida fuori stato, la Florida puo rinunciare al test di guida ma richiede ancora il test di conoscenza, il test della visione e i documenti di identita e residenza."},
  {cat:"license",en:"What is the minimum vision requirement for a Florida Class E license?",it:"Qual e il requisito minimo di visione per una patente Florida Class E?",options:[{en:"20/20 in both eyes",it:"20/20 in entrambi gli occhi"},{en:"20/70 or better in at least one eye (with correction if needed)",it:"20/70 o migliore in almeno un occhio (con correzione se necessaria)"},{en:"20/40 in both eyes",it:"20/40 in entrambi gli occhi"},{en:"20/200 corrected",it:"20/200 corretto"}],correct:1,explain_en:"Florida minimum vision for Class E: 20/70 or better in at least one eye (with corrective lenses if normally worn). Significantly impaired vision results in license restriction or denial.",explain_it:"Visione minima Florida per Class E: 20/70 o migliore in almeno un occhio (con lenti correttive se normalmente indossate)."},
  {cat:"license",en:"What is the Florida law about driving while a license revocation is in effect?",it:"Qual e la legge Florida sulla guida mentre e in vigore una revoca della patente?",options:[{en:"A civil infraction only",it:"Solo un'infrazione civile"},{en:"A second-degree misdemeanor for first offense -- third offense within 5 years is a felony",it:"Una contravvenzione di secondo grado per la prima infrazione -- la terza infrazione entro 5 anni e un crimine"},{en:"No criminal penalty -- just extends the revocation",it:"Nessuna sanzione penale -- si estende solo la revoca"},{en:"Same as driving with a suspended license",it:"Uguale alla guida con la patente sospesa"}],correct:1,explain_en:"Driving while revoked is more serious than driving while suspended in Florida. First offense: second-degree misdemeanor. Three within 5 years: third-degree felony (Habitual Traffic Offender).",explain_it:"Guidare mentre si e revocati e piu grave che guidare mentre si e sospesi in Florida. Prima infrazione: contravvenzione di secondo grado. Tre entro 5 anni: crimine di terzo grado (HTO)."},
  {cat:"license",en:"What is the TLSAE (Traffic Law and Substance Abuse Education) course requirement?",it:"Qual e il requisito del corso TLSAE (Traffic Law and Substance Abuse Education)?",options:[{en:"Required only after a DUI conviction",it:"Richiesto solo dopo una condanna DUI"},{en:"Required for all first-time Florida license applicants 18 years and older before receiving a license",it:"Richiesto per tutti i richiedenti la prima patente Florida di 18 anni e piu prima di ricevere la patente"},{en:"An optional course for license discounts",it:"Un corso opzionale per sconti sulla patente"},{en:"Required for commercial license applicants only",it:"Richiesto solo per i richiedenti la patente commerciale"}],correct:1,explain_en:"TLSAE (also called DATA) is mandatory for all first-time license applicants 18+ in Florida. The 4-hour course covers traffic laws and the dangers of substance abuse while driving.",explain_it:"TLSAE (noto anche come DATA) e obbligatorio per tutti i richiedenti la prima patente di 18+ anni in Florida. Il corso di 4 ore copre le leggi del traffico e i pericoli dell'abuso di sostanze durante la guida."},
  {cat:"license",en:"What is the Florida law on reporting a change of name on a driver's license?",it:"Qual e la legge Florida sulla segnalazione di un cambio di nome sulla patente?",options:[{en:"Not required -- use your old name until renewal",it:"Non richiesto -- usa il vecchio nome fino al rinnovo"},{en:"Must update license within 30 days of a legal name change",it:"Deve aggiornare la patente entro 30 giorni da un cambio legale di nome"},{en:"Only required at the next renewal",it:"Richiesto solo al prossimo rinnovo"},{en:"Name changes do not affect a driver's license",it:"I cambi di nome non influiscono sulla patente"}],correct:1,explain_en:"Florida requires updating the driver's license within 30 days of a legal name change (marriage, divorce, court order). Bring legal documentation to a FLHSMV office.",explain_it:"La Florida richiede l'aggiornamento della patente entro 30 giorni da un cambio legale di nome (matrimonio, divorzio, ordine del tribunale). Portare documentazione legale a un ufficio FLHSMV."},

  // SESSION 10 FINAL PUSH
  {cat:"signs",en:"What does a fluorescent yellow-green sign indicate?",it:"Cosa indica un segnale giallo-verde fluorescente?",options:[{en:"A construction zone",it:"Una zona di costruzione"},{en:"A pedestrian, bicycle, or school warning -- these colors are highly visible",it:"Un avvertimento per pedoni, biciclette o scuola -- questi colori sono molto visibili"},{en:"A temporary speed limit",it:"Un limite di velocita temporaneo"},{en:"An advisory speed near parks",it:"Una velocita consigliata vicino ai parchi"}],correct:1,explain_en:"Fluorescent yellow-green is used for pedestrian crossing, bicycle crossing, and school area warning signs -- this high-visibility color improves detection in low-light conditions.",explain_it:"Il giallo-verde fluorescente e usato per i segnali di avvertimento di attraversamento pedonale, ciclabile e scolastico -- questo colore ad alta visibilita migliora il rilevamento in condizioni di scarsa luce."},
  {cat:"signs",en:"What does 'PHOTO ENFORCED' under a speed limit sign mean?",it:"Cosa significa 'PHOTO ENFORCED' sotto un segnale di limite di velocita?",options:[{en:"Speed cameras may capture violators for citation",it:"Le telecamere di velocita possono catturare i trasgressori per la multa"},{en:"Only warning purposes -- no actual enforcement",it:"Solo scopi di avvertimento -- nessuna applicazione effettiva"},{en:"Cameras record only for accident investigation",it:"Le telecamere registrano solo per l'indagine sugli incidenti"},{en:"Cameras are inactive",it:"Le telecamere sono inattive"}],correct:0,explain_en:"Photo Enforced means automated cameras may photograph vehicles speeding or running red lights -- citations can be mailed to the registered owner.",explain_it:"Photo Enforced significa che le telecamere automatizzate possono fotografare i veicoli che eccedono la velocita o passano col rosso -- le multe possono essere spedite al proprietario registrato."},
  {cat:"signs",en:"What does a 'Pedestrian Push Button' at a crosswalk signal indicate?",it:"Cosa indica un 'Pedestrian Push Button' a un segnale di attraversamento?",options:[{en:"Ring the bell to stop traffic",it:"Suonare il campanello per fermare il traffico"},{en:"Press to activate the pedestrian signal phase -- drivers must yield when the WALK signal shows",it:"Premere per attivare la fase del segnale pedonale -- i conducenti devono cedere quando appare il segnale WALK"},{en:"Only for cyclists",it:"Solo per i ciclisti"},{en:"Press to report a malfunction",it:"Premere per segnalare un malfunzionamento"}],correct:1,explain_en:"Pedestrian push buttons activate the WALK signal. Drivers must always yield to pedestrians who have a WALK signal, even if the driver's light is green.",explain_it:"I pulsanti pedonali attivano il segnale WALK. I conducenti devono sempre cedere ai pedoni che hanno un segnale WALK, anche se il semaforo del conducente e verde."},
  {cat:"signs",en:"What does a 'Keep Clear' box marking in an intersection mean?",it:"Cosa significa una segnaletica 'Keep Clear' a scatola in un incrocio?",options:[{en:"Clear your car of debris before driving",it:"Pulire l'auto dai detriti prima di guidare"},{en:"Do not stop in this box even if traffic is heavy -- you must be able to clear the intersection",it:"Non fermarsi in questo riquadro anche se il traffico e intenso -- devi essere in grado di liberare l'incrocio"},{en:"Emergency vehicles only may stop here",it:"Solo i veicoli di emergenza possono fermarsi qui"},{en:"Clear your lane before turning",it:"Liberare la corsia prima di svoltare"}],correct:1,explain_en:"Yellow 'Keep Clear' or cross-hatched boxes at intersections: do not enter or stop in the box unless you can completely clear it. Blocking an intersection is illegal.",explain_it:"I riquadri gialli 'Keep Clear' o tratteggiati agli incroci: non entrare o fermarsi nel riquadro a meno che non si possa liberarlo completamente. Bloccare un incrocio e illegale."},
  {cat:"signs",en:"What does a sign reading 'NEXT EXIT 23 MILES' tell a driver?",it:"Cosa dice a un conducente un segnale che recita 'NEXT EXIT 23 MILES'?",options:[{en:"A toll booth is 23 miles ahead",it:"Un casello e a 23 miglia in avanti"},{en:"The next opportunity to exit the highway is 23 miles ahead -- plan accordingly",it:"La prossima opportunita di uscire dall'autostrada e a 23 miglia in avanti -- pianificare di conseguenza"},{en:"Speed limit changes at 23 miles",it:"Il limite di velocita cambia a 23 miglia"},{en:"A rest area is 23 miles ahead",it:"Un'area di sosta e a 23 miglia in avanti"}],correct:1,explain_en:"'Next Exit X Miles' informs drivers they won't have another exit opportunity for that distance -- important for fuel, restroom, and navigation planning.",explain_it:"'Next Exit X Miles' informa i conducenti che non avranno un'altra opportunita di uscita per quella distanza -- importante per la pianificazione del carburante, del bagno e della navigazione."},
  {cat:"signs",en:"What does a 'Truck Weight Station' sign require commercial vehicle drivers to do?",it:"Cosa richiede ai conducenti di veicoli commerciali un segnale 'Truck Weight Station'?",options:[{en:"Slow to 45 mph past the station",it:"Rallentare a 45 mph oltre la stazione"},{en:"All vehicles with commercial plates or weight over the specified limit must exit and be weighed",it:"Tutti i veicoli con targhe commerciali o peso superiore al limite specificato devono uscire ed essere pesati"},{en:"Only semi-trucks must stop",it:"Solo i semi-camion devono fermarsi"},{en:"Yield to entering trucks",it:"Cedere ai camion in entrata"}],correct:1,explain_en:"Weigh stations are mandatory stops for commercial vehicles meeting certain criteria. A 'CLOSED' light means you may bypass it; 'OPEN' means all applicable vehicles must exit.",explain_it:"Le stazioni di pesatura sono soste obbligatorie per i veicoli commerciali che soddisfano determinati criteri. Una luce 'CLOSED' significa che puoi bypassarla; 'OPEN' significa che tutti i veicoli applicabili devono uscire."},
  {cat:"signs",en:"What does the marking 'ONLY' in a turn lane mean?",it:"Cosa significa la segnaletica 'ONLY' in una corsia di svolta?",options:[{en:"Advisory -- you may proceed straight if clear",it:"Advisory -- puoi procedere dritto se libero"},{en:"Mandatory -- vehicles in this lane MUST turn in the indicated direction",it:"Obbligatorio -- i veicoli in questa corsia DEVONO svoltare nella direzione indicata"},{en:"Only buses may use this lane",it:"Solo gli autobus possono usare questa corsia"},{en:"Only during peak hours",it:"Solo durante le ore di punta"}],correct:1,explain_en:"ONLY in a turn lane (combined with an arrow) is mandatory. You must turn in the indicated direction -- going straight from a turn-only lane is a traffic violation.",explain_it:"ONLY in una corsia di svolta (combinato con una freccia) e obbligatorio. Devi svoltare nella direzione indicata -- andare dritto da una corsia solo svolta e una violazione del traffico."},
  {cat:"signs",en:"What does the 'AHEAD' on a 'DIVIDED HIGHWAY ENDS AHEAD' sign mean for drivers?",it:"Cosa significa 'AHEAD' su un segnale 'DIVIDED HIGHWAY ENDS AHEAD' per i conducenti?",options:[{en:"You are currently on a divided highway",it:"Sei attualmente su un'autostrada divisa"},{en:"The divided roadway ends soon -- prepare for two-way traffic and possible head-on hazard",it:"La carreggiata divisa finisce presto -- prepararsi per il traffico bidirezionale e possibile pericolo frontale"},{en:"Move to the left lane immediately",it:"Spostarsi immediatamente nella corsia sinistra"},{en:"Speed limit increases ahead",it:"Il limite di velocita aumenta in avanti"}],correct:1,explain_en:"Divided Highway Ends Ahead: prepare for opposing traffic on the same road. Move right, reduce speed, and be alert for vehicles coming toward you.",explain_it:"Divided Highway Ends Ahead: prepararsi per il traffico opposto sulla stessa strada. Spostarsi a destra, ridurre la velocita ed essere vigili per i veicoli che vengono verso di te."},
  {cat:"signs",en:"What does a sign with a bicycle and the word 'LANE' inside a painted box mean?",it:"Cosa significa un segnale con una bicicletta e la parola 'LANE' all'interno di un riquadro dipinto?",options:[{en:"Bicycles must stop here",it:"Le biciclette devono fermarsi qui"},{en:"A designated bicycle lane -- motor vehicles must not block or drive in it except to turn",it:"Una corsia ciclabile designata -- i veicoli a motore non devono bloccarla o guidarci eccetto per svoltare"},{en:"A lane shared equally by bikes and cars",it:"Una corsia condivisa equamente da bici e auto"},{en:"Optional path for cyclists",it:"Percorso opzionale per i ciclisti"}],correct:1,explain_en:"A marked bicycle lane is reserved for cyclists. Motor vehicles may enter only to make a right turn -- yielding to cyclists first. Parking in a bike lane is prohibited.",explain_it:"Una corsia ciclabile segnata e riservata ai ciclisti. I veicoli a motore possono entrare solo per svoltare a destra -- cedendo prima ai ciclisti. Parcheggiare in una corsia ciclabile e vietato."},
  {cat:"signs",en:"What does a 'Clearance Bar' hanging above a road or in a structure mean?",it:"Cosa significa una 'Clearance Bar' appesa sopra una strada o in una struttura?",options:[{en:"An obstacle course for trucks",it:"Un percorso a ostacoli per camion"},{en:"The maximum height of vehicles that may pass -- if your vehicle touches the bar you are too tall",it:"L'altezza massima dei veicoli che possono passare -- se il tuo veicolo tocca la barra sei troppo alto"},{en:"A speed deterrent for the area",it:"Un deterrente della velocita per la zona"},{en:"A wind measurement device",it:"Un dispositivo di misurazione del vento"}],correct:1,explain_en:"Clearance bars are physical height markers hung before tunnels, garages, or low bridges. If your vehicle would touch it, you must find an alternate route.",explain_it:"Le barre di altezza sono indicatori fisici di altezza appesi prima di gallerie, garage o ponti bassi. Se il tuo veicolo le toccherebbe, devi trovare un percorso alternativo."},
  {cat:"signs",en:"What is the purpose of 'STOP HERE ON RED' in addition to a stop line?",it:"Qual e lo scopo di 'STOP HERE ON RED' in aggiunta a una linea di stop?",options:[{en:"Marks where pedestrians should cross",it:"Segna dove i pedoni dovrebbero attraversare"},{en:"Indicates the required stopping position when the signal is red -- not at the signal head itself",it:"Indica la posizione di arresto richiesta quando il segnale e rosso -- non al segnale stesso"},{en:"Advisory only -- you may stop anywhere",it:"Solo advisory -- puoi fermarti ovunque"},{en:"Used only at railroad crossings",it:"Usato solo ai passaggi a livello"}],correct:1,explain_en:"Stop Here on Red marks the required stop position -- at or before the line, not past it into the crosswalk or intersection. Stopping past this line is a violation.",explain_it:"Stop Here on Red segna la posizione di arresto richiesta -- alla linea o prima di essa, non oltre nell'attraversamento o nell'incrocio."},
  {cat:"signs",en:"What does a 'Slow Moving Vehicle' orange triangle on the back of a vehicle mean?",it:"Cosa significa un triangolo arancione 'Slow Moving Vehicle' sul retro di un veicolo?",options:[{en:"The vehicle is in the wrong lane",it:"Il veicolo e nella corsia sbagliata"},{en:"The vehicle travels at 25 mph or less -- expect slow speeds and give plenty of following distance",it:"Il veicolo viaggia a 25 mph o meno -- aspettarsi velocita lente e dare ampia distanza di seguimento"},{en:"Emergency vehicle warning",it:"Avvertimento veicolo di emergenza"},{en:"Construction equipment -- stop and wait",it:"Attrezzatura da costruzione -- fermarsi e aspettare"}],correct:1,explain_en:"The orange reflective triangle identifies a slow-moving vehicle (farm equipment, tractors, horse-drawn vehicles) traveling at 25 mph or less. Slow down and follow at a safe distance.",explain_it:"Il triangolo arancione riflettente identifica un veicolo a bassa velocita (attrezzatura agricola, trattori, veicoli trainati da cavalli) che viaggia a 25 mph o meno."},
  {cat:"signs",en:"What does a 'Speed Limit Applies to ALL Vehicles' sign mean in a work zone?",it:"Cosa significa un segnale 'Speed Limit Applies to ALL Vehicles' in una zona di lavoro?",options:[{en:"Only cars must comply",it:"Solo le auto devono conformarsi"},{en:"The reduced speed limit applies to every vehicle type including trucks and motorcycles -- no exceptions",it:"Il limite di velocita ridotto si applica a ogni tipo di veicolo inclusi camion e moto -- nessuna eccezione"},{en:"Trucks may travel 5 mph over the limit",it:"I camion possono viaggiare a 5 mph oltre il limite"},{en:"Only commercial vehicles must follow the posted limit",it:"Solo i veicoli commerciali devono seguire il limite segnalato"}],correct:1,explain_en:"Work zone speed limits apply to ALL vehicles without exception. Large trucks, motorcycles, and emergency vehicles (unless responding) must comply with the reduced limit.",explain_it:"I limiti di velocita nelle zone di lavoro si applicano a TUTTI i veicoli senza eccezione. I camion grandi, le moto e i veicoli di emergenza (a meno che non stiano rispondendo) devono conformarsi al limite ridotto."},
  {cat:"signs",en:"What does a 'Night Speed Limit' sign mean?",it:"Cosa significa un segnale 'Night Speed Limit'?",options:[{en:"The speed limit only applies at night",it:"Il limite di velocita si applica solo di notte"},{en:"A lower speed limit applies during nighttime hours -- typically posted where visibility at night is reduced",it:"Si applica un limite di velocita piu basso durante le ore notturne -- tipicamente segnalato dove la visibilita notturna e ridotta"},{en:"No speed limit applies during daytime",it:"Nessun limite di velocita si applica durante il giorno"},{en:"Night Speed signs are advisory only",it:"I segnali Night Speed sono solo advisory"}],correct:1,explain_en:"Night Speed Limit signs post a lower speed limit for nighttime hours due to reduced visibility. The lower limit is legally enforceable during the specified hours.",explain_it:"I segnali Night Speed Limit segnalano un limite di velocita piu basso per le ore notturne a causa della visibilita ridotta."},
  {cat:"signs",en:"What does a 'No Outlet' sign mean?",it:"Cosa significa un segnale 'No Outlet'?",options:[{en:"No electrical outlets in this area",it:"Nessuna presa elettrica in questa zona"},{en:"The road is a dead end -- there is no through street and you must return the same way",it:"La strada e senza uscita -- non c'e una strada di transito e devi tornare nello stesso modo"},{en:"No left turn ahead",it:"Nessuna svolta sinistra in avanti"},{en:"Gas station closed",it:"Stazione di servizio chiusa"}],correct:1,explain_en:"No Outlet means the road network ahead has no through connection -- it is a dead end area. You will need to turn around and exit the same way you entered.",explain_it:"No Outlet significa che la rete stradale in avanti non ha connessione di transito -- e un'area senza uscita. Dovrai girare e uscire nello stesso modo in cui sei entrato."},
  {cat:"safety",en:"What is the difference between a 'controlled' and 'uncontrolled' skid?",it:"Qual e la differenza tra uno scivolamento 'controllato' e 'incontrollato'?",options:[{en:"No practical difference",it:"Nessuna differenza pratica"},{en:"A controlled skid is intentional or managed with steering/brake inputs; uncontrolled is a random loss of traction",it:"Uno scivolamento controllato e intenzionale o gestito con input di sterzo/freno; incontrollato e una perdita casuale di trazione"},{en:"Only occurs on ice",it:"Si verifica solo sul ghiaccio"},{en:"Controlled skids are legal; uncontrolled are illegal",it:"Gli scivolamenti controllati sono legali; quelli incontrollati sono illegali"}],correct:1,explain_en:"A controlled skid is managed by a skilled driver using deliberate brake, throttle, and steering inputs. An uncontrolled skid is unexpected loss of traction requiring immediate corrective action.",explain_it:"Uno scivolamento controllato e gestito da un conducente esperto usando input deliberati di freno, acceleratore e sterzo. Uno incontrollato e una perdita inaspettata di trazione."},
  {cat:"safety",en:"What is the Florida law on the minimum age to ride without a bicycle helmet?",it:"Qual e la legge Florida sull'eta minima per andare in bicicletta senza casco?",options:[{en:"All cyclists must wear helmets",it:"Tutti i ciclisti devono indossare caschi"},{en:"Cyclists and passengers under 16 must wear helmets -- over 16 is optional",it:"I ciclisti e i passeggeri under 16 devono indossare caschi -- over 16 e opzionale"},{en:"Helmets required only on roads with speed limits above 35 mph",it:"Caschi richiesti solo sulle strade con limiti superiori a 35 mph"},{en:"No helmet law for cyclists in Florida",it:"Nessuna legge sul casco per i ciclisti in Florida"}],correct:1,explain_en:"Florida bicycle helmet law: all cyclists and passengers under 16 years old must wear an approved helmet. Riders 16 and older are not legally required to wear a helmet.",explain_it:"Legge sul casco bicicletta Florida: tutti i ciclisti e i passeggeri under 16 anni devono indossare un casco approvato. I ciclisti di 16 anni e oltre non sono legalmente obbligati."},
  {cat:"safety",en:"What is the primary cause of most fatal crashes at intersections?",it:"Qual e la causa principale della maggior parte degli incidenti mortali agli incroci?",options:[{en:"Weather conditions",it:"Condizioni meteorologiche"},{en:"Failure to yield right of way -- drivers not checking before entering the intersection",it:"Mancata precedenza -- conducenti che non controllano prima di entrare nell'incrocio"},{en:"Speeding through the intersection",it:"Eccesso di velocita attraverso l'incrocio"},{en:"Distracted pedestrians",it:"Pedoni distratti"}],correct:1,explain_en:"Most fatal intersection crashes are caused by failure to yield. Drivers run red lights, fail to check cross traffic, or misjudge speeds -- entering intersections without proper clearance.",explain_it:"La maggior parte degli incidenti mortali agli incroci e causata dalla mancata precedenza. I conducenti passano col rosso, non controllano il traffico trasversale o valutano male le velocita."},
  {cat:"safety",en:"What is the safest way to enter a traffic lane from a parked position?",it:"Qual e il modo piu sicuro per entrare in una corsia di traffico da una posizione parcheggiata?",options:[{en:"Pull out quickly to minimize time merging",it:"Uscire velocemente per minimizzare il tempo di confluenza"},{en:"Check mirrors, signal, shoulder check, wait for a safe gap, then gradually accelerate to traffic speed",it:"Controllare gli specchi, segnalare, controllare la spalla, aspettare uno spazio sicuro, poi accelerare gradualmente alla velocita del traffico"},{en:"Turn on hazard lights and pull out",it:"Accendere le luci di pericolo e uscire"},{en:"Honk to alert other drivers then pull out",it:"Suonare il clacson per avvisare gli altri conducenti poi uscire"}],correct:1,explain_en:"Pulling out from a parked position: check mirrors, signal, shoulder-check blind spot, wait for a safe gap in traffic, then smoothly accelerate to match traffic speed.",explain_it:"Uscire da una posizione parcheggiata: controlla gli specchi, segnala, controlla il punto cieco con la spalla, aspetta uno spazio sicuro, poi accelera fluidamente per raggiungere la velocita del traffico."},
  {cat:"safety",en:"What is the safest action when a school bus is stopped ahead with flashing amber lights (not yet red)?",it:"Qual e l'azione piu sicura quando uno scuolabus e fermo davanti con luci gialle lampeggianti (non ancora rosse)?",options:[{en:"Maintain current speed",it:"Mantenere la velocita attuale"},{en:"Slow down and prepare to stop -- amber lights mean the bus is about to stop and activate red lights",it:"Rallentare e prepararsi a fermarsi -- le luci gialle significano che il bus sta per fermarsi e attivare le luci rosse"},{en:"Pass the bus quickly before it stops",it:"Superare il bus velocemente prima che si fermi"},{en:"Move to the left lane and pass",it:"Spostarsi nella corsia sinistra e sorpassare"}],correct:1,explain_en:"Amber (yellow) flashing lights on a school bus are a warning: the bus is about to stop. Slow down, prepare to stop, and never attempt to pass when amber lights are on.",explain_it:"Le luci gialle lampeggianti su uno scuolabus sono un avvertimento: il bus sta per fermarsi. Rallentare, prepararsi a fermarsi e non tentare mai di sorpassare quando le luci gialle sono accese."},
  {cat:"safety",en:"What is the proper way to handle road rage from another driver?",it:"Qual e il modo corretto per gestire la rabbia stradale di un altro conducente?",options:[{en:"Respond assertively to teach them a lesson",it:"Rispondere assertivamente per dargli una lezione"},{en:"Avoid eye contact, do not respond, create distance, and if threatened call 911",it:"Evitare il contatto visivo, non rispondere, creare distanza e se minacciati chiamare il 911"},{en:"Block their vehicle to prevent them from passing",it:"Bloccare il loro veicolo per impedirgli di passare"},{en:"Match their driving behavior",it:"Corrispondere al loro comportamento di guida"}],correct:1,explain_en:"Road rage: don't engage, avoid eye contact, create space, do not make gestures, and if followed or threatened drive to a police station and call 911.",explain_it:"Rabbia stradale: non impegnarsi, evitare il contatto visivo, creare spazio, non fare gesti e se seguiti o minacciati andare a un commissariato di polizia e chiamare il 911."},
  {cat:"safety",en:"What is the safest driving technique in heavy traffic that repeatedly speeds up and slows down?",it:"Qual e la tecnica di guida piu sicura nel traffico intenso che accelera e decelera ripetutamente?",options:[{en:"Follow as close as possible to minimize gaps",it:"Seguire il piu vicino possibile per minimizzare i gap"},{en:"Maintain a larger following distance and drive at a smooth constant speed to avoid unnecessary braking",it:"Mantenere una distanza di seguimento maggiore e guidare a velocita costante e fluida per evitare frenate non necessarie"},{en:"Use the shoulder to bypass slow traffic",it:"Usare la banchina per bypassare il traffico lento"},{en:"Constantly change lanes to find the fastest lane",it:"Cambiare continuamente corsia per trovare la corsia piu veloce"}],correct:1,explain_en:"In stop-and-go traffic: maintain larger following distance (5+ seconds) and coast/decelerate smoothly rather than repeatedly braking. This reduces crashes, fuel use, and fatigue.",explain_it:"Nel traffico stop-and-go: mantenere una distanza di seguimento maggiore (5+ secondi) e decelerare fluidamente piuttosto che frenare ripetutamente."},
  {cat:"safety",en:"What are the dangers of driving near large trucks during strong crosswinds?",it:"Quali sono i pericoli di guidare vicino a grandi camion durante forti venti trasversali?",options:[{en:"No special danger -- trucks protect smaller vehicles from wind",it:"Nessun pericolo speciale -- i camion proteggono i veicoli piu piccoli dal vento"},{en:"The aerodynamic turbulence from trucks plus crosswinds can push smaller vehicles off course",it:"La turbolenza aerodinamica dei camion piu i venti trasversali possono spingere i veicoli piu piccoli fuori rotta"},{en:"Only dangerous for motorcycles",it:"Pericoloso solo per le moto"},{en:"Trucks slow down in crosswinds -- no danger",it:"I camion rallentano nei venti trasversali -- nessun pericolo"}],correct:1,explain_en:"During crosswinds, both passing and being passed by large trucks is dangerous -- turbulence from the truck plus the crosswind can suddenly push a smaller vehicle sideways.",explain_it:"Durante i venti trasversali, sia sorpassare che essere sorpassati da grandi camion e pericoloso -- la turbolenza del camion piu il vento trasversale puo improvvisamente spingere lateralmente un veicolo piu piccolo."},
  {cat:"safety",en:"What is the purpose of 'rumble strips' on the center line of a two-lane highway?",it:"Qual e lo scopo delle 'strisce vibranti' sulla linea centrale di un'autostrada a due corsie?",options:[{en:"To mark the speed limit zone",it:"Per segnare la zona del limite di velocita"},{en:"To alert drivers who are drifting into oncoming traffic -- centerline rumble strips prevent head-on crashes",it:"Per allertare i conducenti che si spostano nel traffico in arrivo -- le strisce vibranti sulla linea centrale prevengono gli incidenti frontali"},{en:"To indicate a passing zone ends",it:"Per indicare la fine di una zona di sorpasso"},{en:"To alert drivers of an upcoming railroad crossing",it:"Per allertare i conducenti di un imminente passaggio a livello"}],correct:1,explain_en:"Centerline rumble strips vibrate and create noise when a tire crosses the center line -- alerting drifting or drowsy drivers before they enter oncoming traffic.",explain_it:"Le strisce vibranti sulla linea centrale vibrano e creano rumore quando uno pneumatico attraversa la linea centrale -- allertando i conducenti in deriva o sonnolenti prima che entrino nel traffico in arrivo."},
  {cat:"safety",en:"What is the most effective way to prevent backing accidents in parking lots?",it:"Qual e il modo piu efficace per prevenire gli incidenti in retromarcia nei parcheggi?",options:[{en:"Back in slowly using only the backup camera",it:"Fare retromarcia lentamente usando solo la telecamera posteriore"},{en:"Back into parking spaces when arriving so you can pull forward when leaving -- forward-facing departure is safer",it:"Fare retromarcia entrando nel parcheggio all'arrivo in modo da poter uscire in avanti -- l'uscita in avanti e piu sicura"},{en:"Use hazard lights when backing",it:"Usare le luci di pericolo quando si fa retromarcia"},{en:"Sound horn while backing to warn pedestrians",it:"Suonare il clacson durante la retromarcia per avvisare i pedoni"}],correct:1,explain_en:"Back into parking spots when arriving (backing in) so you pull forward when leaving. Forward-facing departure gives you much better visibility of pedestrians and vehicles.",explain_it:"Fare retromarcia entrando nel parcheggio all'arrivo in modo da uscire in avanti. L'uscita in avanti offre una visibilita molto migliore su pedoni e veicoli."},
  {cat:"safety",en:"What should you do if you are involved in a hit-and-run crash as the victim?",it:"Cosa dovresti fare se sei vittima di un incidente con fuga?",options:[{en:"Chase the other vehicle to get their plate number",it:"Inseguire l'altro veicolo per ottenere il numero di targa"},{en:"Call 911, note the direction of travel and any vehicle description, stay at the scene, and document the damage",it:"Chiamare il 911, annotare la direzione di viaggio e qualsiasi descrizione del veicolo, rimanere sulla scena e documentare i danni"},{en:"Handle it through insurance only -- no need to involve police",it:"Gestirlo solo tramite l'assicurazione -- non e necessario coinvolgere la polizia"},{en:"Move your vehicle to a safe location first, then call insurance",it:"Spostare prima il veicolo in un luogo sicuro, poi chiamare l'assicurazione"}],correct:1,explain_en:"Hit and run victim: do NOT chase the other vehicle (dangerous). Call 911, document the scene, note vehicle description/direction/partial plate if seen, and cooperate with police.",explain_it:"Vittima di incidente con fuga: NON inseguire l'altro veicolo (pericoloso). Chiamare il 911, documentare la scena, annotare la descrizione del veicolo/direzione/targa parziale se visto."},
  {cat:"safety",en:"What is the safest lane to use on a highway when entering or exiting a rest area?",it:"Qual e la corsia piu sicura da usare in autostrada quando si entra o esce da un'area di sosta?",options:[{en:"Left lane -- it's fastest",it:"Corsia sinistra -- e la piu veloce"},{en:"Right lane -- rest areas always enter and exit on the right side",it:"Corsia destra -- le aree di sosta entrano ed escono sempre sul lato destro"},{en:"Center lane -- most stable",it:"Corsia centrale -- la piu stabile"},{en:"Any lane -- rest area ramps use both sides",it:"Qualsiasi corsia -- le rampe delle aree di sosta usano entrambi i lati"}],correct:1,explain_en:"Rest areas in Florida (and nationally) always enter and exit on the right side. Move to the right lane well before the exit to safely enter the rest area at reduced speed.",explain_it:"Le aree di sosta in Florida (e a livello nazionale) entrano ed escono sempre sul lato destro. Spostarsi nella corsia destra ben prima dell'uscita per entrare in sicurezza nell'area di sosta."},
  {cat:"safety",en:"What is the correct response when a vehicle in front of you suddenly stops on a highway?",it:"Qual e la risposta corretta quando un veicolo davanti a te si ferma improvvisamente in autostrada?",options:[{en:"Brake hard and hope for the best",it:"Frenare forte e sperare per il meglio"},{en:"Apply maximum braking, honk, and check adjacent lanes for an escape route",it:"Applicare la frenata massima, suonare il clacson e controllare le corsie adiacenti per una via di fuga"},{en:"Swerve immediately to the left",it:"Sterzare immediatamente a sinistra"},{en:"Use the parking brake for faster stopping",it:"Usare il freno a mano per una frenata piu veloce"}],correct:1,explain_en:"Sudden stop ahead: brake hard (ABS will pump automatically), sound horn to warn others, and assess adjacent lanes for an escape route if braking alone won't prevent a crash.",explain_it:"Stop improvviso in avanti: frena forte (l'ABS pompera automaticamente), suona il clacson per avvisare gli altri e valuta le corsie adiacenti per una via di fuga se la sola frenata non previene l'incidente."},
  {cat:"safety",en:"What does 'defensive space' around your vehicle mean?",it:"Cosa significa 'spazio difensivo' intorno al tuo veicolo?",options:[{en:"Armor plating on the vehicle",it:"Corazza blindata sul veicolo"},{en:"Maintaining adequate space on all sides of your vehicle to allow reaction time and escape routes",it:"Mantenere uno spazio adeguato su tutti i lati del tuo veicolo per consentire tempo di reazione e vie di fuga"},{en:"Driving in the center of the road",it:"Guidare al centro della strada"},{en:"Following at exactly 2 seconds",it:"Seguire esattamente a 2 secondi"}],correct:1,explain_en:"Defensive space: manage the space ahead, behind, and to the sides of your vehicle. This 'cushion of safety' gives you time to react and room to maneuver in emergencies.",explain_it:"Spazio difensivo: gestire lo spazio davanti, dietro e ai lati del tuo veicolo. Questo 'cuscino di sicurezza' ti da il tempo di reagire e spazio per manovrare nelle emergenze."},
  {cat:"safety",en:"What is the correct way to turn your wheels when parked facing downhill next to a curb?",it:"Qual e il modo corretto di girare le ruote quando si e parcheggiati in discesa vicino a un marciapiede?",options:[{en:"Turn wheels away from the curb (to the left on the right side)",it:"Girare le ruote lontano dal marciapiede (a sinistra sul lato destro)"},{en:"Turn wheels toward the curb (to the right) so the car rolls into the curb if the brakes fail",it:"Girare le ruote verso il marciapiede (a destra) in modo che l'auto rotoli verso il marciapiede se i freni si guastano"},{en:"Keep wheels straight",it:"Mantenere le ruote dritte"},{en:"Angle does not matter when parked on hills",it:"L'angolo non importa quando si e parcheggiati sulle colline"}],correct:1,explain_en:"Downhill with a curb: turn wheels TO the curb (right). If the car rolls, it contacts the curb and stops. Uphill: turn wheels AWAY from the curb. No curb (either direction): turn toward the road edge.",explain_it:"In discesa con marciapiede: girare le ruote VERSO il marciapiede (destra). Se l'auto rotola, tocca il marciapiede e si ferma. In salita: girare le ruote LONTANO dal marciapiede."},
  {cat:"safety",en:"What is the significance of a flashing yellow 'X' over a lane?",it:"Qual e il significato di una 'X' gialla lampeggiante sopra una corsia?",options:[{en:"The lane is open to all traffic",it:"La corsia e aperta a tutto il traffico"},{en:"Prepare to exit the lane -- the lane will close soon; move to an adjacent open lane",it:"Prepararsi a uscire dalla corsia -- la corsia chiudera presto; spostarsi in una corsia aperta adiacente"},{en:"Lane is reserved for HOV vehicles",it:"La corsia e riservata ai veicoli HOV"},{en:"Speed limit increase in this lane",it:"Aumento del limite di velocita in questa corsia"}],correct:1,explain_en:"A flashing yellow X is a warning that the lane will close soon -- begin moving to an open lane (green arrow) immediately. A steady red X means the lane is closed now.",explain_it:"Una X gialla lampeggiante e un avvertimento che la corsia chiudera presto -- inizia a spostarti in una corsia aperta (freccia verde) immediatamente."},
  {cat:"safety",en:"When can a driver legally park in a handicapped space without a placard?",it:"Quando puo un conducente parcheggiare legalmente in uno spazio disabili senza un permesso?",options:[{en:"When running a quick errand",it:"Quando si fa una commissione veloce"},{en:"Never -- there are no legal exceptions for parking in a disabled space without a valid permit",it:"Mai -- non ci sono eccezioni legali per il parcheggio in uno spazio disabili senza un permesso valido"},{en:"When dropping off a passenger",it:"Quando si fa scendere un passeggero"},{en:"When all other spaces are full",it:"Quando tutti gli altri posti sono pieni"}],correct:1,explain_en:"There are absolutely no exceptions -- disabled parking spaces require a valid placard or disability plate at all times. Fines start at $250 in Florida.",explain_it:"Non ci sono assolutamente eccezioni -- i parcheggi disabili richiedono un permesso valido o una targa di disabilita in ogni momento. Le multe iniziano da $250 in Florida."},
  {cat:"safety",en:"What is 'gap acceptance' when turning left at an uncontrolled intersection?",it:"Cos'e l'accettazione del gap quando si svolta a sinistra a un incrocio non controllato?",options:[{en:"Judging whether a gap in traffic is large enough to complete the turn safely",it:"Valutare se un gap nel traffico e abbastanza grande da completare la svolta in sicurezza"},{en:"Counting the seconds between vehicles",it:"Contare i secondi tra i veicoli"},{en:"Using the horn to create a gap",it:"Usare il clacson per creare un gap"},{en:"Waiting until all traffic stops",it:"Aspettare finche tutto il traffico si ferma"}],correct:0,explain_en:"Gap acceptance: judging whether the space between approaching vehicles is large enough to complete your intended turn or merge safely. Most left-turn crashes occur from poor gap acceptance.",explain_it:"Accettazione del gap: valutare se lo spazio tra i veicoli in avvicinamento e abbastanza grande da completare la svolta o confluire in sicurezza. La maggior parte degli incidenti di svolta sinistra si verifica da una scarsa accettazione del gap."},
  {cat:"alcohol",en:"What is 'passive alcohol sensing' used at some DUI checkpoints?",it:"Cos'e il 'rilevamento passivo dell'alcol' usato in alcuni posti di blocco DUI?",options:[{en:"Officers guessing BAC from behavior",it:"Agenti che indovinano il BAC dal comportamento"},{en:"A device that detects alcohol in the air around the driver's window without requiring a breath test",it:"Un dispositivo che rileva l'alcol nell'aria intorno al finestrino del conducente senza richiedere un test del respiro"},{en:"Blood tests taken passively while the driver is unconscious",it:"Esami del sangue effettuati passivamente mentre il conducente e incosciente"},{en:"Observing the car for alcohol containers",it:"Osservare l'auto per contenitori di alcol"}],correct:1,explain_en:"Passive alcohol sensors (PAS) detect ethanol vapors in the ambient air near the driver -- no cooperation required. A positive reading justifies requesting a sobriety test.",explain_it:"I sensori passivi di alcol (PAS) rilevano i vapori di etanolo nell'aria vicino al conducente -- non e richiesta cooperazione. Una lettura positiva giustifica la richiesta di un test di sobriety."},
  {cat:"alcohol",en:"What is the 'one drink per hour' rule and what are its limitations?",it:"Qual e la regola 'un drink all'ora' e quali sono i suoi limiti?",options:[{en:"An exact formula -- one drink per hour guarantees you stay below 0.08%",it:"Una formula esatta -- un drink all'ora garantisce di rimanere sotto 0,08%"},{en:"A rough guideline only -- actual BAC varies by weight, gender, food intake, and individual metabolism",it:"Solo una linea guida approssimativa -- il BAC effettivo varia per peso, genere, apporto calorico e metabolismo individuale"},{en:"Only applies to beer -- wine is absorbed faster",it:"Si applica solo alla birra -- il vino viene assorbito piu velocemente"},{en:"Guarantees legal driving as long as total drinks divided by hours is under 1",it:"Garantisce la guida legale finche le bevande totali divise per le ore sono sotto 1"}],correct:1,explain_en:"'One drink per hour' is a rough average -- actual metabolism varies significantly by body weight, gender, food intake, health, and individual factors. Never rely on a formula to determine if you're safe to drive.",explain_it:"'Un drink all'ora' e una media approssimativa -- il metabolismo effettivo varia significativamente per peso corporeo, genere, apporto calorico, salute e fattori individuali."},
  {cat:"alcohol",en:"What happens to a Florida driver's license immediately upon arrest for DUI?",it:"Cosa succede alla patente Florida immediatamente all'arresto per DUI?",options:[{en:"Nothing until convicted",it:"Niente fino alla condanna"},{en:"It is confiscated and a 10-day temporary driving permit is issued -- administrative suspension begins after 10 days",it:"Viene confiscata e viene rilasciato un permesso di guida temporaneo di 10 giorni -- la sospensione amministrativa inizia dopo 10 giorni"},{en:"Immediately voided with no temporary permit",it:"Immediatamente annullata senza permesso temporaneo"},{en:"Suspended for 30 days pending outcome",it:"Sospesa per 30 giorni in attesa dell'esito"}],correct:1,explain_en:"Upon DUI arrest in Florida: license is taken, a yellow temporary driving permit valid for 10 days is issued. If you don't request a formal review hearing within 10 days, the administrative suspension begins automatically.",explain_it:"All'arresto DUI in Florida: la patente viene ritirata, viene rilasciato un permesso di guida temporaneo giallo valido per 10 giorni. Se non si richiede un'udienza formale entro 10 giorni, la sospensione amministrativa inizia automaticamente."},
  {cat:"alcohol",en:"What is the best decision a person can make after drinking to ensure they don't drive impaired?",it:"Qual e la migliore decisione che una persona puo prendere dopo aver bevuto per garantire di non guidare in stato di compromissione?",options:[{en:"Drink coffee and wait 30 minutes",it:"Bere caffe e aspettare 30 minuti"},{en:"Designate a sober driver before drinking, use a rideshare, or stay where you are until sober",it:"Designare un guidatore sobrio prima di bere, usare un rideshare o rimanere dove si e finche sobri"},{en:"Eat a large meal after drinking",it:"Mangiare un pasto abbondante dopo aver bevuto"},{en:"Take a nap for 1 hour then drive",it:"Fare un pisolino di 1 ora poi guidare"}],correct:1,explain_en:"The only safe options: designate a sober driver in advance, use Uber/Lyft/taxi, stay overnight, or call someone. There is no reliable shortcut to sobriety -- only time works.",explain_it:"Le uniche opzioni sicure: designare un conducente sobrio in anticipo, usare Uber/Lyft/taxi, dormire sul posto o chiamare qualcuno. Non c'e una scorciatoia affidabile alla sobriety -- solo il tempo funziona."},
  {cat:"alcohol",en:"What does 'DUI per se' mean in practice for a driver who seems sober?",it:"Cosa significa 'DUI per se' in pratica per un conducente che sembra sobrio?",options:[{en:"They cannot be charged if they appear sober",it:"Non possono essere accusati se sembrano sobri"},{en:"A BAC of 0.08%+ is automatic DUI regardless of how sober the driver appears or acts",it:"Un BAC di 0,08%+ e DUI automatico indipendentemente da quanto sobrio appare o agisce il conducente"},{en:"Per se only applies at BAC above 0.15%",it:"Per se si applica solo sopra 0,15% BAC"},{en:"Only applies if the driver caused an accident",it:"Si applica solo se il conducente ha causato un incidente"}],correct:1,explain_en:"Per se DUI means the BAC alone is sufficient for conviction -- regardless of driving behavior, appearance, or field sobriety performance. 0.08%+ = DUI, no further proof of impairment needed.",explain_it:"DUI per se significa che il solo BAC e sufficiente per la condanna -- indipendentemente dal comportamento di guida, dall'aspetto o dalle prestazioni ai test di sobriety."},
  {cat:"license",en:"What is the Florida law on driving with a learner's permit on an interstate highway?",it:"Qual e la legge Florida sulla guida con il permesso per principianti su un'autostrada interstatale?",options:[{en:"Prohibited on all limited access highways",it:"Vietato su tutte le autostrade a accesso limitato"},{en:"Permitted as long as a licensed driver 21+ is supervising from the passenger seat",it:"Consentito purche un conducente autorizzato 21+ stia supervisionando dal sedile passeggero"},{en:"Only permitted on highways with speed limits under 55 mph",it:"Consentito solo sulle autostrade con limiti di velocita inferiori a 55 mph"},{en:"Permitted only on expressways, not interstates",it:"Consentito solo sulle superstrade, non sulle autostrade interstatali"}],correct:1,explain_en:"Florida learner's permit holders may drive on any road including limited-access highways (interstates) provided a licensed 21+ driver occupies the front passenger seat.",explain_it:"I titolari del permesso Florida possono guidare su qualsiasi strada incluse le autostrade a accesso limitato (interstatali) purche un conducente autorizzato 21+ occupi il sedile anteriore passeggero."},
  {cat:"license",en:"How long must a new Florida resident wait before they can get a Florida license if they hold a valid out-of-state license?",it:"Quanto tempo deve aspettare un nuovo residente Florida prima di poter ottenere una patente Florida se ha una patente valida fuori stato?",options:[{en:"6 months",it:"6 mesi"},{en:"No waiting period -- apply within 30 days of establishing residency",it:"Nessun periodo di attesa -- fare domanda entro 30 giorni dall'stabilimento della residenza"},{en:"90 days",it:"90 giorni"},{en:"Must complete 6 months of Florida driving first",it:"Deve completare prima 6 mesi di guida in Florida"}],correct:1,explain_en:"New Florida residents with a valid out-of-state license should apply for a Florida license within 30 days. There is no waiting period -- just bring required documents.",explain_it:"I nuovi residenti Florida con una patente valida fuori stato dovrebbero fare domanda per una patente Florida entro 30 giorni. Non c'e periodo di attesa -- basta portare i documenti richiesti."},
  {cat:"license",en:"What is the Florida law about expired driver's licenses?",it:"Qual e la legge Florida sulle patenti scadute?",options:[{en:"A 6-month grace period is automatic",it:"E automatico un periodo di grazia di 6 mesi"},{en:"Driving with an expired license is a noncriminal traffic infraction -- renew before expiration",it:"Guidare con una patente scaduta e un'infrazione del traffico non penale -- rinnovare prima della scadenza"},{en:"An expired license is still valid for 1 year",it:"Una patente scaduta e ancora valida per 1 anno"},{en:"Expired licenses are treated the same as having no license",it:"Le patenti scadute sono trattate come non avere la patente"}],correct:1,explain_en:"Driving with an expired license in Florida is a noncriminal infraction. However, significantly expired licenses (years overdue) may be treated more seriously. Renew on time.",explain_it:"Guidare con una patente scaduta in Florida e un'infrazione non penale. Tuttavia, le patenti scadute da molto tempo possono essere trattate in modo piu serio."},
  {cat:"license",en:"What is the Florida law on allowing an unlicensed person to drive your vehicle?",it:"Qual e la legge Florida sull'autorizzare una persona senza patente a guidare il tuo veicolo?",options:[{en:"No law against it if you trust them",it:"Nessuna legge contro se ti fidi di loro"},{en:"Illegal -- the vehicle owner can face criminal liability for allowing an unlicensed person to drive",it:"Illegale -- il proprietario del veicolo puo affrontare responsabilita penale per aver consentito a una persona senza patente di guidare"},{en:"Only illegal if an accident occurs",it:"Illegale solo se si verifica un incidente"},{en:"Legal for licensed drivers to allow their minor children to drive on private property",it:"Legale per i conducenti autorizzati consentire ai figli minorenni di guidare su proprieta privata"}],correct:1,explain_en:"Knowingly allowing an unlicensed person to drive your vehicle in Florida is a criminal offense. The vehicle owner can face misdemeanor charges and civil liability for any resulting damages.",explain_it:"Consentire consapevolmente a una persona senza patente di guidare il tuo veicolo in Florida e un reato penale. Il proprietario del veicolo puo affrontare accuse per contravvenzione e responsabilita civile."},
  {cat:"license",en:"What is the Florida law about transferring vehicle ownership and the certificate of title?",it:"Qual e la legge Florida sul trasferimento della proprieta del veicolo e il certificato di titolo?",options:[{en:"Title transfer must occur within 90 days",it:"Il trasferimento del titolo deve avvenire entro 90 giorni"},{en:"Title must be transferred within 30 days of purchase -- seller must sign the back and buyer applies at tax collector",it:"Il titolo deve essere trasferito entro 30 giorni dall'acquisto -- il venditore deve firmare il retro e l'acquirente fa domanda al tax collector"},{en:"Title transfer is optional for vehicles over 10 years old",it:"Il trasferimento del titolo e opzionale per i veicoli di oltre 10 anni"},{en:"Buyer and seller can delay transfer indefinitely",it:"Acquirente e venditore possono ritardare il trasferimento indefinitamente"}],correct:1,explain_en:"Florida requires title transfer within 30 days of a vehicle sale. The seller signs the title, the buyer takes it to the county tax collector's office to register in their name.",explain_it:"La Florida richiede il trasferimento del titolo entro 30 giorni dalla vendita di un veicolo. Il venditore firma il titolo, l'acquirente lo porta all'ufficio del tax collector della contea per registrarlo a proprio nome."},

  // SESSION 11
  {cat:"laws",en:"What is the Florida law about parking on a sidewalk?",it:"Qual e la legge Florida sul parcheggio sul marciapiede?",options:[{en:"Legal if the vehicle does not block pedestrians",it:"Legale se il veicolo non blocca i pedoni"},{en:"Illegal -- no vehicle may be parked, stopped, or driven on a sidewalk",it:"Illegale -- nessun veicolo puo essere parcheggiato, fermato o guidato sul marciapiede"},{en:"Legal for motorcycles only",it:"Legale solo per le moto"},{en:"Legal for less than 5 minutes",it:"Legale per meno di 5 minuti"}],correct:1,explain_en:"Parking or driving on a sidewalk is prohibited in Florida. Sidewalks are for pedestrian use. Violators may be ticketed and vehicles towed.",explain_it:"Parcheggiare o guidare sul marciapiede e vietato in Florida. I marciapiedi sono per uso pedonale. I trasgressori possono essere multati e i veicoli rimossi."},
  {cat:"laws",en:"What is Florida's law on the speed limit in an alley?",it:"Qual e la legge Florida sul limite di velocita in un vicolo?",options:[{en:"Same as the adjacent street",it:"Uguale alla strada adiacente"},{en:"10 mph maximum in an alley",it:"Massimo 10 mph in un vicolo"},{en:"15 mph maximum",it:"Massimo 15 mph"},{en:"No posted speed limit required in alleys",it:"Nessun limite di velocita segnalato richiesto nei vicoli"}],correct:1,explain_en:"Florida sets a maximum speed of 10 mph in alleys. This protects pedestrians and vehicles in the tight confines of alleys.",explain_it:"La Florida stabilisce una velocita massima di 10 mph nei vicoli. Questo protegge pedoni e veicoli nei confini angusti dei vicoli."},
  {cat:"laws",en:"What is the Florida law on driving with an open container of alcohol in the vehicle?",it:"Qual e la legge Florida sulla guida con un contenitore aperto di alcol nel veicolo?",options:[{en:"Legal if the driver is not drinking",it:"Legale se il conducente non beve"},{en:"Illegal -- no open containers in the passenger area of a vehicle, regardless of who has it",it:"Illegale -- nessun contenitore aperto nell'area passeggeri del veicolo, indipendentemente da chi ce l'ha"},{en:"Legal for passengers in the back seat only",it:"Legale solo per i passeggeri nel sedile posteriore"},{en:"Only illegal for the driver",it:"Illegale solo per il conducente"}],correct:1,explain_en:"Florida open container law: no open alcohol containers in the passenger area of a vehicle -- driver or passenger. Exceptions: limousines, buses, motorhomes where the living area is separate.",explain_it:"Legge sul contenitore aperto Florida: nessun contenitore di alcol aperto nell'area passeggeri -- conducente o passeggero. Eccezioni: limousine, autobus, camper dove l'area soggiorno e separata."},
  {cat:"laws",en:"What is the minimum liability insurance required for a Florida personal vehicle?",it:"Qual e l'assicurazione di responsabilita minima richiesta per un veicolo personale Florida?",options:[{en:"$10,000 bodily injury / $20,000 per accident",it:"$10.000 lesioni personali / $20.000 per incidente"},{en:"$10,000 Personal Injury Protection (PIP) and $10,000 Property Damage Liability (PDL)",it:"$10.000 Personal Injury Protection (PIP) e $10.000 Property Damage Liability (PDL)"},{en:"$25,000/$50,000/$10,000",it:"$25.000/$50.000/$10.000"},{en:"$100,000 combined single limit",it:"$100.000 limite singolo combinato"}],correct:1,explain_en:"Florida minimum insurance: $10,000 PIP (personal injury protection -- covers your own injuries) and $10,000 PDL (property damage liability). Florida is a no-fault state.",explain_it:"Assicurazione minima Florida: $10.000 PIP (personal injury protection -- copre le proprie lesioni) e $10.000 PDL (property damage liability). La Florida e uno stato no-fault."},
  {cat:"laws",en:"What does Florida's no-fault insurance system mean for drivers?",it:"Cosa significa il sistema assicurativo no-fault della Florida per i conducenti?",options:[{en:"No one is ever at fault in an accident",it:"Nessuno ha mai torto in un incidente"},{en:"Your own PIP insurance pays for your injuries regardless of who caused the crash",it:"La tua assicurazione PIP paga le tue lesioni indipendentemente da chi ha causato l'incidente"},{en:"Drivers cannot sue each other after an accident",it:"I conducenti non possono fare causa l'uno all'altro dopo un incidente"},{en:"Insurance companies pay equal amounts regardless of fault",it:"Le compagnie assicurative pagano importi uguali indipendentemente dalla colpa"}],correct:1,explain_en:"Florida no-fault: your PIP pays your medical bills up to $10,000 regardless of who caused the crash. This reduces litigation for minor accidents. You can still sue for serious injuries.",explain_it:"Florida no-fault: il tuo PIP paga le tue spese mediche fino a $10.000 indipendentemente da chi ha causato l'incidente. Puoi comunque fare causa per lesioni gravi."},
  {cat:"laws",en:"What must a Florida driver do when involved in a crash with an unattended vehicle?",it:"Cosa deve fare un conducente Florida quando e coinvolto in un incidente con un veicolo incustodito?",options:[{en:"Drive away if no one saw the crash",it:"Andarsene se nessuno ha visto l'incidente"},{en:"Stop, find the owner OR leave written notice with name, address, and vehicle registration in a visible place",it:"Fermarsi, trovare il proprietario O lasciare una nota scritta con nome, indirizzo e registrazione del veicolo in un posto visibile"},{en:"Call 911 and wait -- no action needed",it:"Chiamare il 911 e aspettare -- nessuna azione necessaria"},{en:"Only required if damage exceeds $1,000",it:"Richiesto solo se i danni superano $1.000"}],correct:1,explain_en:"Hit an unattended vehicle: stop, locate the owner if possible, or leave a written note in a conspicuous place with your name, address, and vehicle registration number.",explain_it:"Colpisci un veicolo incustodito: fermati, localizza il proprietario se possibile, o lascia una nota scritta in un posto ben visibile con il tuo nome, indirizzo e numero di registrazione."},
  {cat:"laws",en:"What is the Florida law about using hazard lights while driving?",it:"Qual e la legge Florida sull'uso delle luci di pericolo durante la guida?",options:[{en:"Always legal to use for any reason",it:"Sempre legale da usare per qualsiasi motivo"},{en:"Permitted while stopped or when a vehicle is a hazard; generally not permitted while moving except in funeral processions or emergency situations",it:"Consentito mentre si e fermi o quando un veicolo e un pericolo; generalmente non consentito mentre si e in movimento eccetto nei cortei funebri o situazioni di emergenza"},{en:"Must use hazard lights any time it rains",it:"Devi usare le luci di pericolo ogni volta che piove"},{en:"Only for disabled vehicles -- never while driving",it:"Solo per veicoli in avaria -- mai durante la guida"}],correct:1,explain_en:"Florida: hazard lights are for stopped vehicles or hazard situations. Using them while driving in rain is actually illegal in Florida -- they confuse other drivers about your direction.",explain_it:"Florida: le luci di pericolo sono per i veicoli fermi o situazioni di pericolo. Usarle durante la guida nella pioggia e in realta illegale in Florida -- confondono gli altri conducenti sulla tua direzione."},
  {cat:"laws",en:"What is the Florida law about parking within 50 feet of a railroad crossing?",it:"Qual e la legge Florida sul parcheggio entro 50 piedi da un passaggio a livello?",options:[{en:"No restriction near railroad crossings",it:"Nessuna restrizione vicino ai passaggi a livello"},{en:"No parking within 50 feet of the nearest rail of a railroad crossing",it:"Nessun parcheggio entro 50 piedi dal binario piu vicino di un passaggio a livello"},{en:"No parking within 100 feet",it:"Nessun parcheggio entro 100 piedi"},{en:"Only commercial vehicles restricted",it:"Solo i veicoli commerciali sono limitati"}],correct:1,explain_en:"Florida prohibits parking within 50 feet of the nearest rail at a railroad crossing. This keeps the approach clear for trains and prevents sight-line obstructions.",explain_it:"La Florida vieta il parcheggio entro 50 piedi dal binario piu vicino a un passaggio a livello. Questo mantiene libera l'area di avvicinamento per i treni."},
  {cat:"laws",en:"What is the Florida law about U-turns in a business district?",it:"Qual e la legge Florida sulle inversioni di marcia in un distretto commerciale?",options:[{en:"Always prohibited in business districts",it:"Sempre vietate nei distretti commerciali"},{en:"Permitted only at intersections where a signal or officer authorizes it and it can be done safely",it:"Consentite solo agli incroci dove un segnale o un agente le autorizza e possono essere effettuate in sicurezza"},{en:"Legal anywhere with a clear view of 500 feet",it:"Legale ovunque con visibilita di 500 piedi"},{en:"Only prohibited near schools",it:"Vietato solo vicino alle scuole"}],correct:1,explain_en:"In a business district, U-turns are only permitted at intersections controlled by a signal or officer, and only when safe. Signs prohibiting U-turns must be obeyed.",explain_it:"In un distretto commerciale, le inversioni di marcia sono consentite solo agli incroci controllati da un segnale o agente, e solo quando sicuro."},
  {cat:"laws",en:"What is the Florida law about turning right on red when there is a 'No Turn on Red' sign?",it:"Qual e la legge Florida sulla svolta destra con il rosso quando c'e un segnale 'No Turn on Red'?",options:[{en:"May still turn if no traffic is present",it:"Puoi comunque svoltare se non c'e traffico"},{en:"Absolutely prohibited -- the sign overrides the general right-on-red permission",it:"Assolutamente vietato -- il segnale sovrascrive la generale autorizzazione svolta-destra-col-rosso"},{en:"Only prohibited during school hours",it:"Vietato solo durante le ore scolastiche"},{en:"Allowed after a complete stop",it:"Consentito dopo un arresto completo"}],correct:1,explain_en:"A 'No Turn on Red' sign absolutely prohibits turning right on red at that location -- regardless of traffic conditions. This is a regulatory sign and must be obeyed.",explain_it:"Un segnale 'No Turn on Red' vieta assolutamente di svoltare a destra con il rosso in quel luogo -- indipendentemente dalle condizioni del traffico."},
  {cat:"laws",en:"What is Florida's implied consent law?",it:"Cos'e la legge sul consenso implicito della Florida?",options:[{en:"Drivers consent to random vehicle searches",it:"I conducenti acconsentono alle perquisizioni casuali dei veicoli"},{en:"By driving on Florida roads, drivers implicitly consent to chemical testing (breath, blood, urine) if lawfully arrested for DUI",it:"Guidando sulle strade Florida, i conducenti acconsentono implicitamente ai test chimici (respiro, sangue, urina) se legalmente arrestati per DUI"},{en:"Consent to wear a seatbelt at all times",it:"Consenso a indossare la cintura di sicurezza in ogni momento"},{en:"Consent to roadside sobriety tests only",it:"Consenso solo ai test di sobriety sul ciglio della strada"}],correct:1,explain_en:"Florida implied consent: operating a vehicle implies consent to lawful DUI testing (breath/blood/urine). Refusal results in automatic license suspension and can be used against you in court.",explain_it:"Consenso implicito Florida: guidare un veicolo implica il consenso ai test DUI legali (respiro/sangue/urina). Il rifiuto comporta la sospensione automatica della patente."},
  {cat:"laws",en:"What is the Florida law about the speed limit on a residential street with no posted signs?",it:"Qual e la legge Florida sul limite di velocita in una strada residenziale senza segnali affissi?",options:[{en:"25 mph",it:"25 mph"},{en:"30 mph",it:"30 mph"},{en:"35 mph",it:"35 mph"},{en:"20 mph",it:"20 mph"}],correct:1,explain_en:"Florida's default speed limit on a residential road or street without a posted sign is 30 mph. School zones have lower limits. Always look for posted signs that may change this.",explain_it:"Il limite di velocita predefinito della Florida su una strada residenziale senza segnale affisso e 30 mph. Le zone scolastiche hanno limiti piu bassi."},
  {cat:"laws",en:"What is the Florida law about speed limits on interstate highways?",it:"Qual e la legge Florida sui limiti di velocita sulle autostrade interstatali?",options:[{en:"65 mph everywhere",it:"65 mph ovunque"},{en:"70 mph on rural interstates, 65 mph on urban interstates (unless otherwise posted)",it:"70 mph sulle autostrade rurali, 65 mph sulle urbane (salvo diversa indicazione)"},{en:"55 mph statewide",it:"55 mph in tutto lo stato"},{en:"75 mph on rural, 70 mph on urban",it:"75 mph rurali, 70 mph urbane"}],correct:1,explain_en:"Florida interstate speed limits: 70 mph on rural interstates, 65 mph on urban interstates. Posted signs may set different limits. Always obey the posted sign.",explain_it:"Limiti di velocita autostrade interstatali Florida: 70 mph sulle interstatali rurali, 65 mph sulle urbane. I segnali affissi possono stabilire limiti diversi."},
  {cat:"laws",en:"What is the Florida law on the speed limit on a two-lane rural road?",it:"Qual e la legge Florida sul limite di velocita su una strada rurale a due corsie?",options:[{en:"55 mph",it:"55 mph"},{en:"60 mph",it:"60 mph"},{en:"65 mph",it:"65 mph"},{en:"Determined solely by posted signs",it:"Determinato esclusivamente dai segnali affissi"}],correct:0,explain_en:"Florida's default speed limit on two-lane rural roads is 55 mph unless otherwise posted. Always look for posted signs that may modify this limit.",explain_it:"Il limite di velocita predefinito della Florida sulle strade rurali a due corsie e 55 mph salvo diversa indicazione. Cerca sempre i segnali affissi."},
  {cat:"laws",en:"When must Florida drivers use headlights?",it:"Quando devono usare i fari i conducenti Florida?",options:[{en:"Only at night",it:"Solo di notte"},{en:"From sunset to sunrise and when visibility is reduced to less than 1,000 feet (including rain)",it:"Dal tramonto all'alba e quando la visibilita e ridotta a meno di 1.000 piedi (inclusa la pioggia)"},{en:"Only in rain and fog",it:"Solo nella pioggia e nella nebbia"},{en:"Whenever on a highway",it:"Ogni volta che si e in autostrada"}],correct:1,explain_en:"Florida headlight law: required from sunset to sunrise AND whenever windshield wipers are in use (rain), OR when visibility is less than 1,000 feet. If wipers are on, lights must be on.",explain_it:"Legge fari Florida: obbligatori dal tramonto all'alba E quando i tergicristalli sono in uso (pioggia), O quando la visibilita e inferiore a 1.000 piedi."},
  {cat:"laws",en:"What is the Florida law about passing on the right on a one-lane road?",it:"Qual e la legge Florida sul sorpasso a destra su una strada a una corsia?",options:[{en:"Always legal if done quickly",it:"Sempre legale se fatto velocemente"},{en:"Never permitted on a single-lane road -- passing on the shoulder is illegal",it:"Mai consentito su una strada a corsia singola -- il sorpasso sulla banchina e illegale"},{en:"Legal if the other vehicle is stopped",it:"Legale se l'altro veicolo e fermo"},{en:"Legal if you signal first",it:"Legale se segnali prima"}],correct:1,explain_en:"Passing on the shoulder (right side of the road) is illegal in Florida. On a single-lane road, you may not pass at all unless there is a legal passing zone.",explain_it:"Il sorpasso sulla banchina (lato destro della strada) e illegale in Florida. Su una strada a corsia singola, non puoi sorpassare affatto a meno che non ci sia una zona di sorpasso legale."},
  {cat:"laws",en:"What is the Florida law about the maximum speed when passing a school bus loading or unloading children?",it:"Qual e la legge Florida sulla velocita massima quando si supera uno scuolabus che carica o scarica bambini?",options:[{en:"5 mph",it:"5 mph"},{en:"There is no speed to pass -- you must be completely stopped",it:"Non c'e velocita per superare -- devi essere completamente fermo"},{en:"20 mph",it:"20 mph"},{en:"10 mph",it:"10 mph"}],correct:1,explain_en:"You must be fully stopped when a school bus has its red lights flashing and stop arm extended. There is no legal passing speed -- passing is completely prohibited.",explain_it:"Devi essere completamente fermo quando uno scuolabus ha le luci rosse lampeggianti e il braccio di stop esteso. Non c'e velocita legale di sorpasso -- il sorpasso e completamente vietato."},
  {cat:"laws",en:"What is the Florida law regarding bicycles riding on the road?",it:"Qual e la legge Florida riguardo alle biciclette che circolano sulla strada?",options:[{en:"Bicycles must always use the sidewalk",it:"Le biciclette devono sempre usare il marciapiede"},{en:"Bicycles have the same rights and duties as motor vehicles when riding on the road",it:"Le biciclette hanno gli stessi diritti e doveri dei veicoli a motore quando circolano sulla strada"},{en:"Bicycles must yield to all motor vehicles",it:"Le biciclette devono cedere a tutti i veicoli a motore"},{en:"Bicycles are prohibited on roads with speed limits above 35 mph",it:"Le biciclette sono vietate sulle strade con limiti superiori a 35 mph"}],correct:1,explain_en:"Florida law: bicycles on roads have the same rights and duties as motor vehicles. Cyclists must obey all traffic laws, signals, and signs. Drivers must give cyclists at least 3 feet when passing.",explain_it:"Legge Florida: le biciclette sulle strade hanno gli stessi diritti e doveri dei veicoli a motore. I ciclisti devono rispettare tutte le leggi del traffico. I conducenti devono dare ai ciclisti almeno 3 piedi."},
  {cat:"laws",en:"What is the Florida 3-foot law for cyclists?",it:"Qual e la legge Florida dei 3 piedi per i ciclisti?",options:[{en:"Cyclists must stay 3 feet from the curb",it:"I ciclisti devono stare a 3 piedi dal marciapiede"},{en:"Drivers must leave at least 3 feet of space when passing a bicycle",it:"I conducenti devono lasciare almeno 3 piedi di spazio quando superano una bicicletta"},{en:"Cyclists must maintain 3 feet from parked cars to avoid dooring",it:"I ciclisti devono mantenere 3 piedi dalle auto parcheggiate per evitare l'apertura delle porte"},{en:"Bicycles must be at least 3 feet from pedestrians",it:"Le biciclette devono essere almeno a 3 piedi dai pedoni"}],correct:1,explain_en:"Florida's 3-foot law: when passing a bicycle, motor vehicle drivers must provide at least 3 feet of clearance. If 3 feet is not possible in the lane, the driver must change lanes to pass.",explain_it:"Legge dei 3 piedi Florida: quando superano una bicicletta, i conducenti di veicoli a motore devono fornire almeno 3 piedi di spazio. Se non e possibile, il conducente deve cambiare corsia."},
  {cat:"laws",en:"What must a Florida driver do when their turn signal light burns out?",it:"Cosa deve fare un conducente Florida quando la spia del segnale di svolta si brucia?",options:[{en:"May continue driving -- no law requires turn signals",it:"Puo continuare a guidare -- nessuna legge richiede i segnali di svolta"},{en:"Must use hand signals until repaired -- equipment violations can result in a citation",it:"Deve usare segnali a mano fino alla riparazione -- le violazioni delle attrezzature possono risultare in una multa"},{en:"Must stop driving immediately",it:"Deve smettere di guidare immediatamente"},{en:"Only an issue during a vehicle inspection",it:"Solo un problema durante un'ispezione del veicolo"}],correct:1,explain_en:"If a turn signal is burned out, Florida drivers may use hand signals until the equipment is repaired. Driving with inoperable required equipment can result in a citation.",explain_it:"Se un segnale di svolta e bruciato, i conducenti Florida possono usare segnali a mano fino alla riparazione. Guidare con attrezzature obbligatorie non funzionanti puo risultare in una multa."},
  {cat:"laws",en:"What is the correct hand signal for slowing down or stopping?",it:"Qual e il segnale a mano corretto per rallentare o fermarsi?",options:[{en:"Left arm extended straight out",it:"Braccio sinistro teso in fuori"},{en:"Left arm extended downward at an angle (hand pointing down)",it:"Braccio sinistro esteso verso il basso a un angolo (mano rivolta verso il basso)"},{en:"Right arm waved out the window",it:"Braccio destro agitato fuori dal finestrino"},{en:"Left arm extended upward",it:"Braccio sinistro esteso verso l'alto"}],correct:1,explain_en:"Hand signal for stopping/slowing: left arm extended out the window and bent downward at the elbow, hand pointing toward the ground.",explain_it:"Segnale a mano per fermarsi/rallentare: braccio sinistro esteso fuori dal finestrino e piegato verso il basso al gomito, mano rivolta verso il basso."},
  {cat:"laws",en:"What is the correct hand signal for a left turn?",it:"Qual e il segnale a mano corretto per una svolta sinistra?",options:[{en:"Left arm extended upward",it:"Braccio sinistro esteso verso l'alto"},{en:"Left arm extended straight out horizontally",it:"Braccio sinistro esteso orizzontalmente in fuori"},{en:"Left arm extended downward",it:"Braccio sinistro esteso verso il basso"},{en:"Right arm waved out window",it:"Braccio destro agitato fuori dal finestrino"}],correct:1,explain_en:"Hand signal for left turn: left arm extended straight out horizontally through the window. This mirrors the direction of the intended turn.",explain_it:"Segnale a mano per svolta sinistra: braccio sinistro esteso orizzontalmente in fuori. Questo rispecchia la direzione della svolta prevista."},
  {cat:"laws",en:"What is the correct hand signal for a right turn?",it:"Qual e il segnale a mano corretto per una svolta destra?",options:[{en:"Right arm extended out the right window",it:"Braccio destro esteso fuori dal finestrino destro"},{en:"Left arm bent upward at the elbow (forearm vertical, hand pointing up)",it:"Braccio sinistro piegato verso l'alto al gomito (avambraccio verticale, mano rivolta verso l'alto)"},{en:"Left arm extended horizontally",it:"Braccio sinistro esteso orizzontalmente"},{en:"Flash the brake lights twice",it:"Lampeggiare i freni due volte"}],correct:1,explain_en:"Hand signal for right turn: left arm out the window, bent upward 90 degrees at the elbow with the hand pointing up. This indicates turning right.",explain_it:"Segnale a mano per svolta destra: braccio sinistro fuori dal finestrino, piegato verso l'alto a 90 gradi al gomito con la mano rivolta verso l'alto."},
  {cat:"laws",en:"What Florida points are assigned for a reckless driving conviction?",it:"Quanti punti Florida vengono assegnati per una condanna per guida spericolata?",options:[{en:"3 points",it:"3 punti"},{en:"4 points",it:"4 punti"},{en:"6 points",it:"6 punti"},{en:"12 points",it:"12 punti"}],correct:2,explain_en:"Reckless driving conviction in Florida adds 4 points to the driving record. More serious violations (leaving scene with injury, passing stopped school bus) add more points.",explain_it:"Una condanna per guida spericolata in Florida aggiunge 4 punti al casellario di guida. Le violazioni piu gravi aggiungono piu punti."},
  {cat:"laws",en:"What is the Florida law about careless driving?",it:"Qual e la legge Florida sulla guida imprudente?",options:[{en:"Same as reckless driving",it:"Uguale alla guida spericolata"},{en:"Driving in a manner that fails to exercise due care -- a civil traffic infraction",it:"Guidare in modo che non esercita la dovuta cura -- un'infrazione del traffico civile"},{en:"Only applies if an accident occurs",it:"Si applica solo se si verifica un incidente"},{en:"No specific law -- just common negligence rules",it:"Nessuna legge specifica -- solo regole di negligenza comune"}],correct:1,explain_en:"Florida careless driving: failure to drive with reasonable care or in a manner that endangers persons or property. It's a civil infraction (not criminal) -- carries 3 points and a fine.",explain_it:"Guida imprudente Florida: mancanza di guida con ragionevole cura o in modo che mette in pericolo persone o proprieta. E un'infrazione civile (non penale) -- comporta 3 punti e una multa."},
  {cat:"laws",en:"What is the Florida law on the right-of-way when a vehicle enters from an alley?",it:"Qual e la legge Florida sulla precedenza quando un veicolo entra da un vicolo?",options:[{en:"The vehicle in the alley has the right of way",it:"Il veicolo nel vicolo ha la precedenza"},{en:"Must stop and yield to all pedestrians and vehicle traffic before emerging from an alley",it:"Deve fermarsi e cedere a tutti i pedoni e al traffico prima di uscire da un vicolo"},{en:"Yield only to vehicles -- pedestrians must watch out",it:"Cedere solo ai veicoli -- i pedoni devono fare attenzione"},{en:"First vehicle to the alley entrance has priority",it:"Il primo veicolo all'ingresso del vicolo ha la priorita"}],correct:1,explain_en:"When emerging from an alley, driveway, or building: stop before the sidewalk, yield to all pedestrians on the sidewalk, then yield to all street traffic before proceeding.",explain_it:"Quando si emerge da un vicolo, vialetto o edificio: fermarsi prima del marciapiede, cedere a tutti i pedoni sul marciapiede, poi cedere a tutto il traffico stradale prima di procedere."},
  {cat:"laws",en:"What is the Florida law on minimum following distance behind a fire truck that is NOT on an emergency call?",it:"Qual e la legge Florida sulla distanza minima di seguimento dietro un'autopompa che NON e in una chiamata di emergenza?",options:[{en:"No minimum -- follow at normal distance",it:"Nessun minimo -- seguire a distanza normale"},{en:"500 feet minimum even when not on a call",it:"Minimo 500 piedi anche quando non e in chiamata"},{en:"100 feet minimum",it:"Minimo 100 piedi"},{en:"200 feet minimum",it:"Minimo 200 piedi"}],correct:1,explain_en:"Florida law requires maintaining at least 500 feet behind any fire truck regardless of whether it is on an emergency call. This clears the path for potential rapid departures.",explain_it:"La legge Florida richiede di mantenere almeno 500 piedi dietro qualsiasi autopompa indipendentemente dal fatto che sia in una chiamata di emergenza."},
  {cat:"laws",en:"What is the Florida law on maximum speed in a school zone?",it:"Qual e la legge Florida sulla velocita massima in una zona scolastica?",options:[{en:"25 mph always",it:"25 mph sempre"},{en:"15 mph when the flashing light is active or children are present",it:"15 mph quando la luce lampeggiante e attiva o i bambini sono presenti"},{en:"20 mph on all school days",it:"20 mph in tutti i giorni scolastici"},{en:"The same as the adjacent road",it:"Uguale alla strada adiacente"}],correct:1,explain_en:"Florida school zone speed limit: 15 mph when the zone's warning lights are flashing or when children are present. Outside of these times, the normal road speed limit applies.",explain_it:"Limite di velocita zona scolastica Florida: 15 mph quando le luci di avvertimento della zona lampeggiano o quando i bambini sono presenti."},
  {cat:"laws",en:"What is the Florida law about the use of vehicle headlights on a clear day?",it:"Qual e la legge Florida sull'uso dei fari del veicolo in una giornata serena?",options:[{en:"Always required -- day or night",it:"Sempre obbligatori -- giorno o notte"},{en:"Only required from sunset to sunrise and in low-visibility conditions such as rain",it:"Obbligatori solo dal tramonto all'alba e in condizioni di scarsa visibilita come la pioggia"},{en:"Required from 30 minutes before sunset",it:"Obbligatori da 30 minuti prima del tramonto"},{en:"Optional at all times during daylight hours",it:"Opzionali in ogni momento durante le ore diurne"}],correct:1,explain_en:"Florida requires headlights from sunset to sunrise and whenever visibility is impaired (rain, fog, etc.). On a clear day with good visibility, headlights are not legally required -- though daytime running lights are beneficial.",explain_it:"La Florida richiede i fari dal tramonto all'alba e ogni volta che la visibilita e ridotta (pioggia, nebbia, ecc.). In una giornata serena con buona visibilita, i fari non sono legalmente obbligatori."},
  {cat:"safety",en:"What is the proper technique for making a three-point turn on a narrow road?",it:"Qual e la tecnica corretta per fare un'inversione in tre punti su una strada stretta?",options:[{en:"Do it quickly to minimize time blocking traffic",it:"Farlo velocemente per minimizzare il tempo di blocco del traffico"},{en:"Check for traffic both ways, signal, turn fully in one direction, reverse, then complete the turn -- use mirrors throughout",it:"Controllare il traffico in entrambe le direzioni, segnalare, svoltare completamente in una direzione, fare retromarcia, poi completare la svolta -- usare gli specchi durante"},{en:"Only perform three-point turns on one-way streets",it:"Effettuare inversioni in tre punti solo sulle strade a senso unico"},{en:"Use the driveway of the nearest house",it:"Usare il vialetto della casa piu vicina"}],correct:1,explain_en:"Three-point turn: check traffic in both directions, signal, turn hard right to the curb, reverse left while checking mirrors, then complete the forward turn. Only use when no driveways or intersections are available.",explain_it:"Inversione in tre punti: controlla il traffico in entrambe le direzioni, segnala, svolta a destra verso il marciapiede, fai retromarcia a sinistra controllando gli specchi, poi completa la svolta in avanti."},
  {cat:"safety",en:"What is the correct way to position your hands on the steering wheel for maximum control?",it:"Qual e il modo corretto di posizionare le mani sul volante per il massimo controllo?",options:[{en:"12 and 6 o'clock",it:"12 e 6 in punto"},{en:"9 and 3 o'clock (or 8 and 4) -- keeps hands away from the airbag deployment zone",it:"9 e 3 in punto (o 8 e 4) -- mantiene le mani lontane dalla zona di attivazione dell'airbag"},{en:"10 and 2 o'clock -- the traditional position",it:"10 e 2 in punto -- la posizione tradizionale"},{en:"One hand at 12 o'clock",it:"Una mano alle 12 in punto"}],correct:1,explain_en:"Modern recommendation: 9-and-3 or 8-and-4. This keeps hands away from the airbag deployment zone (upper half of wheel), provides good leverage, and reduces injury risk if the airbag deploys.",explain_it:"Raccomandazione moderna: 9 e 3 o 8 e 4. Questo mantiene le mani lontane dalla zona di attivazione dell'airbag (met\u00e0 superiore del volante), fornisce buona leva e riduce il rischio di lesioni."},
  {cat:"safety",en:"What is the safest action if a pedestrian steps into the road unexpectedly?",it:"Qual e l'azione piu sicura se un pedone entra inaspettatamente nella strada?",options:[{en:"Swerve around them and honk",it:"Sterzare intorno a loro e suonare il clacson"},{en:"Brake as hard as safely possible and swerve only if braking alone will not avoid the collision",it:"Frenare il piu forte possibile in sicurezza e sterzare solo se la sola frenata non evita la collisione"},{en:"Honk loud and maintain speed",it:"Suonare il clacson forte e mantenere la velocita"},{en:"Swerve immediately without braking",it:"Sterzare immediatamente senza frenare"}],correct:1,explain_en:"Sudden pedestrian in road: brake hard first (maximum deceleration), then steer around only if braking won't stop you in time. Swerving without braking may cause you to miss them but hit something else.",explain_it:"Pedone improvviso in strada: frena forte prima (decelerazione massima), poi sterza intorno solo se la frenata non ti ferma in tempo."},
  {cat:"safety",en:"What is the danger of using cruise control in rain or on slippery roads?",it:"Qual e il pericolo dell'uso del cruise control nella pioggia o su strade scivolose?",options:[{en:"Cruise control improves fuel efficiency in rain",it:"Il cruise control migliora l'efficienza del carburante nella pioggia"},{en:"If the car hydroplanes, cruise control may maintain or increase speed -- causing loss of control",it:"Se l'auto acquaplana, il cruise control puo mantenere o aumentare la velocita -- causando perdita di controllo"},{en:"No danger -- cruise control works the same in all conditions",it:"Nessun pericolo -- il cruise control funziona allo stesso modo in tutte le condizioni"},{en:"Cruise control automatically reduces speed in rain",it:"Il cruise control riduce automaticamente la velocita nella pioggia"}],correct:1,explain_en:"Cruise control in wet conditions: if you hydroplane, the system tries to maintain speed -- potentially accelerating the vehicle. Always disengage cruise control in rain, snow, or slippery conditions.",explain_it:"Cruise control in condizioni umide: se aquaplani, il sistema cerca di mantenere la velocita -- potenzialmente accelerando il veicolo. Disattivare sempre il cruise control nella pioggia o sulle strade scivolose."},
  {cat:"safety",en:"What is the minimum required stopping distance at 55 mph on dry pavement for an average car?",it:"Qual e la distanza minima di frenata richiesta a 55 mph sull'asfalto asciutto per un'auto media?",options:[{en:"About 50 feet",it:"Circa 50 piedi"},{en:"About 180-200 feet (including reaction distance)",it:"Circa 180-200 piedi (inclusa la distanza di reazione)"},{en:"About 500 feet",it:"Circa 500 piedi"},{en:"About 100 feet",it:"Circa 100 piedi"}],correct:1,explain_en:"At 55 mph: reaction distance is ~60 feet (1 second) + braking distance ~145 feet = total ~200 feet on dry pavement. Wet roads or worn tires can double this.",explain_it:"A 55 mph: distanza di reazione ~60 piedi (1 secondo) + distanza di frenata ~145 piedi = totale ~200 piedi sull'asfalto asciutto. Strade bagnate o pneumatici usurati possono raddoppiare questo."},
  {cat:"safety",en:"What is the correct way to handle a 'road rage' incident where another driver follows you?",it:"Qual e il modo corretto per gestire un incidente di 'rabbia stradale' in cui un altro conducente ti segue?",options:[{en:"Stop your car to confront them",it:"Fermare l'auto per affrontarli"},{en:"Drive to a populated public place or police station -- do not go home",it:"Andare in un luogo pubblico affollato o commissariato di polizia -- non andare a casa"},{en:"Speed away to lose them",it:"Accelerare per seminarli"},{en:"Pull over on the highway shoulder",it:"Accostare sulla banchina dell'autostrada"}],correct:1,explain_en:"If followed by an aggressive driver: drive to a police station, fire station, or busy public place. Do NOT go home. Call 911. Never confront the other driver.",explain_it:"Se seguito da un conducente aggressivo: andare a un commissariato di polizia, caserma dei pompieri o luogo pubblico affollato. NON andare a casa. Chiamare il 911."},
  {cat:"safety",en:"What is the importance of adjusting your mirrors before driving?",it:"Qual e l'importanza di regolare gli specchi prima di guidare?",options:[{en:"Mirrors are only needed on highways",it:"Gli specchi sono necessari solo in autostrada"},{en:"Properly adjusted mirrors minimize blind spots and reduce the need to turn your head for routine checks",it:"Gli specchi correttamente regolati minimizzano i punti ciechi e riducono la necessita di girare la testa per i controlli di routine"},{en:"Mirrors replaced looking over the shoulder completely",it:"Gli specchi sostituiscono completamente il guardare oltre la spalla"},{en:"Mirror adjustment is only needed when sharing a vehicle",it:"La regolazione degli specchi e necessaria solo quando si condivide un veicolo"}],correct:1,explain_en:"Properly adjusted mirrors: side mirrors should show minimal car body; rearview mirror centered on rear window. This minimizes blind spots -- but shoulder checks are still required for lane changes.",explain_it:"Specchi correttamente regolati: gli specchi laterali dovrebbero mostrare il minimo della carrozzeria; lo specchietto retrovisore centrato sul lunotto. Questo minimizza i punti ciechi."},
  {cat:"safety",en:"What is the proper lane for an emergency vehicle to pass through a congested area?",it:"Qual e la corsia corretta per un veicolo di emergenza per passare attraverso un'area congestionata?",options:[{en:"The center of the road -- between lanes",it:"Il centro della strada -- tra le corsie"},{en:"All drivers must pull to the right and stop -- creating a clear path on the left side",it:"Tutti i conducenti devono accostare a destra e fermarsi -- creando un percorso libero sul lato sinistro"},{en:"Emergency vehicles use the shoulder only",it:"I veicoli di emergenza usano solo la banchina"},{en:"Drivers should pull to the left",it:"I conducenti dovrebbero accostare a sinistra"}],correct:1,explain_en:"When an emergency vehicle approaches: pull to the right edge of the road and stop. This clears the left side (and center) for the emergency vehicle to pass -- even on a one-way street.",explain_it:"Quando si avvicina un veicolo di emergenza: accosta al bordo destro della strada e fermati. Questo libera il lato sinistro per il veicolo di emergenza."},
  {cat:"safety",en:"How does increasing speed affect stopping distance?",it:"Come influisce l'aumento della velocita sulla distanza di frenata?",options:[{en:"Stopping distance increases linearly with speed",it:"La distanza di frenata aumenta linearmente con la velocita"},{en:"Stopping distance increases exponentially -- doubling speed quadruples stopping distance",it:"La distanza di frenata aumenta esponenzialmente -- raddoppiare la velocita quadruplica la distanza di frenata"},{en:"Stopping distance is constant regardless of speed",it:"La distanza di frenata e costante indipendentemente dalla velocita"},{en:"Stopping distance doubles with each 10 mph increase",it:"La distanza di frenata raddoppia con ogni aumento di 10 mph"}],correct:1,explain_en:"Stopping distance is proportional to the square of speed. Double the speed = 4x the stopping distance. At 60 mph you need 4x more stopping distance than at 30 mph.",explain_it:"La distanza di frenata e proporzionale al quadrato della velocita. Raddoppiare la velocita = 4 volte la distanza di frenata. A 60 mph hai bisogno di 4 volte piu distanza che a 30 mph."},
  {cat:"safety",en:"What is the correct action when driving through a construction zone with workers present?",it:"Qual e l'azione corretta quando si guida attraverso una zona di costruzione con lavoratori presenti?",options:[{en:"Maintain normal speed -- workers are protected by barriers",it:"Mantenere la velocita normale -- i lavoratori sono protetti dalle barriere"},{en:"Reduce speed to the posted limit, increase following distance, and stay alert for workers and equipment",it:"Ridurre la velocita al limite segnalato, aumentare la distanza e restare vigili per lavoratori e attrezzature"},{en:"Drive in the center to avoid edge obstacles",it:"Guidare al centro per evitare gli ostacoli ai bordi"},{en:"Only trucks need to slow down in work zones",it:"Solo i camion devono rallentare nelle zone di lavoro"}],correct:1,explain_en:"In work zones with workers present: follow the reduced speed limit strictly, increase following distance, watch for workers and slow-moving equipment, and avoid distractions.",explain_it:"Nelle zone di lavoro con lavoratori presenti: rispettare rigorosamente il limite di velocita ridotto, aumentare la distanza, fare attenzione ai lavoratori e alle attrezzature a bassa velocita."},
  {cat:"safety",en:"What is Florida's law on child passenger safety seats for children under 4?",it:"Qual e la legge Florida sui seggiolini per bambini per i bambini sotto i 4 anni?",options:[{en:"Recommended but not required",it:"Raccomandato ma non obbligatorio"},{en:"Must be secured in a crash-tested, federally approved child restraint device",it:"Devono essere assicurati in un dispositivo di ritenuta per bambini testato per gli urti e approvato federalmente"},{en:"May sit in an adult lap with a seatbelt",it:"Possono sedersi in grembo a un adulto con una cintura di sicurezza"},{en:"Required only on highways",it:"Obbligatorio solo in autostrada"}],correct:1,explain_en:"Florida law: children under 4 must be secured in a federally approved child restraint device (car seat or booster seat appropriate for their size). Rear-facing preferred for infants.",explain_it:"Legge Florida: i bambini under 4 devono essere assicurati in un dispositivo di ritenuta approvato federalmente. Sedile rivolto verso il retro preferito per i neonati."},
  {cat:"safety",en:"What is the correct action if your vehicle breaks down on the highway?",it:"Qual e l'azione corretta se il tuo veicolo si guasta in autostrada?",options:[{en:"Stay in the vehicle in the travel lane with hazard lights on",it:"Rimanere nel veicolo nella corsia di marcia con le luci di pericolo accese"},{en:"Move to the right shoulder, turn on hazard lights, exit carefully, stay away from traffic, and call for help",it:"Spostarsi alla banchina destra, accendere le luci di pericolo, uscire con cautela, stare lontano dal traffico e chiamare aiuto"},{en:"Stand behind the vehicle to warn traffic",it:"Stare dietro il veicolo per avvisare il traffico"},{en:"Set up flares directly behind the vehicle",it:"Posizionare i segnali direttamente dietro il veicolo"}],correct:1,explain_en:"Breakdown on highway: move fully onto the right shoulder, turn on hazard lights, exit from the passenger side away from traffic, move well away from the road, and call for assistance.",explain_it:"Guasto in autostrada: spostarsi completamente sulla banchina destra, accendere le luci di pericolo, uscire dal lato passeggero lontano dal traffico, allontanarsi dalla strada e chiamare assistenza."},
  {cat:"safety",en:"What is the effect of worn shock absorbers on vehicle safety?",it:"Qual e l'effetto degli ammortizzatori usurati sulla sicurezza del veicolo?",options:[{en:"No effect -- only affects ride comfort",it:"Nessun effetto -- influisce solo sul comfort di guida"},{en:"Reduces tire-to-road contact on bumps, increasing stopping distance and reducing steering control",it:"Riduce il contatto pneumatico-strada sui dossi, aumentando la distanza di frenata e riducendo il controllo dello sterzo"},{en:"Improves braking by reducing weight transfer",it:"Migliora la frenata riducendo il trasferimento di peso"},{en:"Only significant for trucks and SUVs",it:"Significativo solo per camion e SUV"}],correct:1,explain_en:"Worn shocks/struts: tires bounce on rough roads, reducing road contact. This increases stopping distance, reduces cornering stability, and can cause unpredictable handling -- a real safety hazard.",explain_it:"Ammortizzatori usurati: gli pneumatici rimbalzano sulle strade sconnesse, riducendo il contatto stradale. Questo aumenta la distanza di frenata e riduce la stabilita in curva."},
  {cat:"safety",en:"What is the proper way to drive through a sharp curve on a mountain road?",it:"Qual e il modo corretto di guidare attraverso una curva stretta su una strada di montagna?",options:[{en:"Brake through the curve for maximum control",it:"Frenare attraverso la curva per il massimo controllo"},{en:"Brake before the curve, then gently accelerate through it -- weight is more stable this way",it:"Frenare prima della curva, poi accelerare delicatamente attraverso -- il peso e piu stabile in questo modo"},{en:"Shift to a higher gear for better engine braking",it:"Passare a una marcia piu alta per una migliore frenata del motore"},{en:"Maintain constant speed through the curve",it:"Mantenere la velocita costante attraverso la curva"}],correct:1,explain_en:"Cornering technique: brake before the curve (when going straight), then gently accelerate through the corner. Braking in a turn shifts weight and reduces traction -- potentially causing understeer or oversteer.",explain_it:"Tecnica in curva: frena prima della curva (quando sei in rettilineo), poi accelera delicatamente attraverso la curva. Frenare in curva sposta il peso e riduce la trazione."},
  {cat:"safety",en:"What is the best strategy for long-distance highway driving to avoid fatigue?",it:"Qual e la migliore strategia per la guida in autostrada a lungo raggio per evitare la stanchezza?",options:[{en:"Drive through without stopping to arrive sooner",it:"Guidare senza fermarsi per arrivare prima"},{en:"Take a break every 2 hours or 100 miles -- get out and walk, avoid heavy meals, stay hydrated",it:"Fare una pausa ogni 2 ore o 100 miglia -- scendere e camminare, evitare pasti pesanti, mantenersi idratati"},{en:"Drink energy drinks every hour",it:"Bere bevande energetiche ogni ora"},{en:"Turn up the radio and open windows",it:"Alzare la radio e aprire i finestrini"}],correct:1,explain_en:"To combat driving fatigue: stop every 2 hours or 100 miles, get out and move, avoid heavy meals (cause drowsiness), stay hydrated, and travel during your normal waking hours.",explain_it:"Per combattere la stanchezza alla guida: fermarsi ogni 2 ore o 100 miglia, scendere e muoversi, evitare pasti pesanti (causano sonnolenza), mantenersi idratati."},
  {cat:"safety",en:"What is the Florida law on wearing a seatbelt in a pickup truck?",it:"Qual e la legge Florida sull'indossare la cintura di sicurezza in un pickup?",options:[{en:"Seatbelts optional in pickups",it:"Cinture opzionali nei pickup"},{en:"All occupants in pickup trucks must wear seatbelts -- same as any other vehicle",it:"Tutti gli occupanti dei pickup devono indossare le cinture -- uguale a qualsiasi altro veicolo"},{en:"Only the driver needs a seatbelt",it:"Solo il conducente ha bisogno della cintura"},{en:"Only for passengers under 18",it:"Solo per i passeggeri under 18"}],correct:1,explain_en:"Florida seatbelt law applies to all vehicles including pickup trucks. All occupants (driver and passengers) in pickup trucks must be properly buckled.",explain_it:"La legge sulle cinture Florida si applica a tutti i veicoli inclusi i pickup. Tutti gli occupanti (conducente e passeggeri) dei pickup devono essere correttamente allacciati."},
  {cat:"safety",en:"What is the proper technique for entering a parking space between two vehicles?",it:"Qual e la tecnica corretta per entrare in un parcheggio tra due veicoli?",options:[{en:"Drive straight in at normal speed",it:"Entrare dritto alla velocita normale"},{en:"Approach slowly, align carefully, signal your intent, and use mirrors to avoid the adjacent vehicles",it:"Avvicinarsi lentamente, allinearsi con cura, segnalare l'intenzione e usare gli specchi per evitare i veicoli adiacenti"},{en:"Always reverse into parking spaces",it:"Sempre fare retromarcia nei parcheggi"},{en:"Position the front bumper at the line then proceed",it:"Posizionare il paraurti anteriore alla linea poi procedere"}],correct:1,explain_en:"Parking between vehicles: slow approach, signal, use mirrors to judge clearance on both sides, and align carefully. If in doubt, back in for better visibility on exit.",explain_it:"Parcheggio tra veicoli: avvicinamento lento, segnalare, usare gli specchi per valutare lo spazio libero su entrambi i lati e allinearsi con cura."},
  {cat:"safety",en:"What is the most common cause of accidents at intersections in Florida?",it:"Qual e la causa piu comune di incidenti agli incroci in Florida?",options:[{en:"Speed too high for conditions",it:"Velocita troppo alta per le condizioni"},{en:"Failure to obey traffic controls -- running red lights and stop signs",it:"Mancato rispetto dei controlli del traffico -- passare col rosso e i segnali di stop"},{en:"Distracted pedestrians",it:"Pedoni distratti"},{en:"Poor road surface design",it:"Scarsa progettazione della superficie stradale"}],correct:1,explain_en:"The leading cause of intersection accidents is failure to obey traffic controls: running red lights, blowing through stop signs, and failing to yield. These account for the majority of intersection fatalities.",explain_it:"La causa principale degli incidenti agli incroci e il mancato rispetto dei controlli del traffico: passare col rosso, ignorare i segnali di stop e non cedere la precedenza."},
  {cat:"safety",en:"What is the significance of a solid yellow line painted on the road edge (fog line)?",it:"Qual e il significato di una linea gialla continua dipinta sul bordo della strada (linea della nebbia)?",options:[{en:"Indicates a no-parking zone",it:"Indica una zona di divieto di parcheggio"},{en:"Marks the right edge of the road -- used as a guide in low visibility conditions",it:"Segna il bordo destro della strada -- usata come guida nelle condizioni di scarsa visibilita"},{en:"Indicates a bicycle lane boundary",it:"Indica il confine di una corsia ciclabile"},{en:"Marks the center of a one-way road",it:"Segna il centro di una strada a senso unico"}],correct:1,explain_en:"A yellow solid edge line (fog line) marks the right edge of the roadway. In fog, rain, or darkness, it guides drivers and prevents them from drifting off the road edge.",explain_it:"Una linea di bordo gialla continua (linea della nebbia) segna il bordo destro della carreggiata. Nella nebbia, pioggia o oscurita, guida i conducenti e impedisce loro di scivolare fuori dal bordo."},
  {cat:"safety",en:"What is the Florida law on carrying unsecured cargo in a pickup truck bed?",it:"Qual e la legge Florida sul trasporto di carico non assicurato nel cassone di un pickup?",options:[{en:"Legal -- truck beds are designed for open cargo",it:"Legale -- i cassoni dei camion sono progettati per il carico aperto"},{en:"Illegal if the cargo is likely to fall -- must be covered or secured",it:"Illegale se il carico e probabile che cada -- deve essere coperto o assicurato"},{en:"Only illegal on highways",it:"Illegale solo in autostrada"},{en:"Legal if the load does not exceed the bed dimensions",it:"Legale se il carico non supera le dimensioni del cassone"}],correct:1,explain_en:"Florida law: cargo that falls from a vehicle is the driver's responsibility. Unsecured loads that fall and cause an accident result in criminal charges. All cargo must be secured or covered.",explain_it:"Legge Florida: il carico che cade da un veicolo e responsabilita del conducente. I carichi non assicurati che cadono e causano un incidente comportano accuse penali."},
  {cat:"alcohol",en:"What is the effect of alcohol on a driver's ability to judge distances?",it:"Qual e l'effetto dell'alcol sulla capacita del conducente di valutare le distanze?",options:[{en:"Improves depth perception",it:"Migliora la percezione della profondita"},{en:"Impairs depth perception and distance judgment -- making drivers misjudge gaps and following distances",it:"Compromette la percezione della profondita e la valutazione delle distanze -- facendo valutare male i gap e le distanze di seguimento"},{en:"Only affects lateral movement judgment",it:"Influisce solo sulla valutazione del movimento laterale"},{en:"No effect on depth perception",it:"Nessun effetto sulla percezione della profondita"}],correct:1,explain_en:"Alcohol impairs depth perception and distance estimation. Drunk drivers misjudge how far away vehicles are, underestimate closing speeds, and make poor gap acceptance decisions.",explain_it:"L'alcol compromette la percezione della profondita e la stima delle distanze. I conducenti ubriachi valutano male la distanza dei veicoli, sottovalutano le velocita di avvicinamento."},
  {cat:"alcohol",en:"What are field sobriety tests and who administers them?",it:"Cosa sono i test di sobriety sul campo e chi li somministra?",options:[{en:"Breathalyzer tests at the police station",it:"Test del respiro alla stazione di polizia"},{en:"Standardized physical performance tests administered by law enforcement at the roadside to assess impairment",it:"Test standardizzati di performance fisica somministrati dalle forze dell'ordine sul ciglio della strada per valutare la compromissione"},{en:"Self-administered tests available at bars",it:"Test autosomministrati disponibili nei bar"},{en:"Medical tests only available at hospitals",it:"Test medici disponibili solo negli ospedali"}],correct:1,explain_en:"Standardized Field Sobriety Tests (SFST): Walk-and-Turn, One-Leg Stand, and Horizontal Gaze Nystagmus. Administered by trained officers at the roadside. Results are used as evidence in DUI cases.",explain_it:"Test standardizzati di sobriety sul campo (SFST): Walk-and-Turn, One-Leg Stand e Horizontal Gaze Nystagmus. Somministrati da agenti addestrati sul ciglio della strada."},
  {cat:"alcohol",en:"What is the effect of alcohol on a driver's reaction time at 0.05% BAC?",it:"Qual e l'effetto dell'alcol sul tempo di reazione di un conducente a 0,05% BAC?",options:[{en:"No measurable effect below 0.08%",it:"Nessun effetto misurabile sotto 0,08%"},{en:"Reaction time is already noticeably slowed -- impairment begins well below the legal limit",it:"Il tempo di reazione e gia notevolmente rallentato -- la compromissione inizia ben al di sotto del limite legale"},{en:"Reaction time actually improves slightly at low BAC",it:"Il tempo di reazione migliora leggermente a basso BAC"},{en:"Only affects reaction to unexpected events, not normal driving",it:"Influisce solo sulla reazione agli eventi inaspettati, non sulla guida normale"}],correct:1,explain_en:"Impairment begins at the first drink. At 0.05% BAC, reaction time is measurably slower, judgment is impaired, and coordination is reduced. The 0.08% limit is not the point where impairment begins.",explain_it:"La compromissione inizia al primo drink. A 0,05% BAC, il tempo di reazione e misurabilmente piu lento, il giudizio e compromesso e la coordinazione e ridotta."},
  {cat:"alcohol",en:"What does 'DUI with serious bodily injury' mean in Florida?",it:"Cosa significa 'DUI con gravi lesioni personali' in Florida?",options:[{en:"A civil violation with higher fines",it:"Una violazione civile con multe piu alte"},{en:"A third-degree felony with up to 5 years imprisonment and $5,000 fine",it:"Un crimine di terzo grado con fino a 5 anni di reclusione e multa di $5.000"},{en:"Same penalties as standard DUI",it:"Stesse sanzioni del DUI standard"},{en:"Only applies if the injury was permanent",it:"Si applica solo se la lesione era permanente"}],correct:1,explain_en:"DUI with serious bodily injury in Florida is a third-degree felony: up to 5 years prison, up to $5,000 fine, and restitution to the victim. This is a significant criminal charge.",explain_it:"DUI con gravi lesioni personali in Florida e un crimine di terzo grado: fino a 5 anni di prigione, multa fino a $5.000 e risarcimento alla vittima."},
  {cat:"alcohol",en:"What is the Florida law on DUI involving death (DUI manslaughter)?",it:"Qual e la legge Florida sul DUI che coinvolge la morte (omicidio DUI)?",options:[{en:"A misdemeanor with up to 1 year in jail",it:"Una contravvenzione con fino a 1 anno di carcere"},{en:"DUI manslaughter is a second-degree felony with up to 15 years in prison",it:"L'omicidio DUI e un crimine di secondo grado con fino a 15 anni di prigione"},{en:"Same as vehicular homicide",it:"Uguale all'omicidio colposo con veicolo"},{en:"A first-degree misdemeanor",it:"Una contravvenzione di primo grado"}],correct:1,explain_en:"DUI manslaughter in Florida: second-degree felony, up to 15 years prison, up to $10,000 fine, and permanent license revocation. If the driver left the scene: first-degree felony up to 30 years.",explain_it:"Omicidio DUI in Florida: crimine di secondo grado, fino a 15 anni di prigione, multa fino a $10.000 e revoca permanente della patente."},
  {cat:"alcohol",en:"What is the Florida law on 'Habitual DUI Offender' status?",it:"Qual e la legge Florida sullo status di 'Habitual DUI Offender'?",options:[{en:"After 5 DUI convictions",it:"Dopo 5 condanne DUI"},{en:"Three DUI convictions result in permanent license revocation -- driving after permanent revocation is a felony",it:"Tre condanne DUI comportano la revoca permanente della patente -- guidare dopo la revoca permanente e un crimine"},{en:"There is no habitual DUI status in Florida",it:"Non c'e uno status DUI abituale in Florida"},{en:"After 2 DUI convictions within 5 years",it:"Dopo 2 condanne DUI entro 5 anni"}],correct:1,explain_en:"Three DUI convictions in Florida result in permanent license revocation. After 10 years, one may apply for reinstatement. Driving while permanently revoked is a felony.",explain_it:"Tre condanne DUI in Florida comportano la revoca permanente della patente. Dopo 10 anni, si puo fare domanda di reintegro. Guidare mentre si e permanentemente revocati e un crimine."},
  {cat:"alcohol",en:"How does alcohol impair divided attention (multitasking)?",it:"Come compromette l'alcol l'attenzione divisa (multitasking)?",options:[{en:"Alcohol helps focus on one task at a time",it:"L'alcol aiuta a concentrarsi su un compito alla volta"},{en:"Alcohol impairs the ability to process multiple inputs simultaneously -- making driving tasks much harder",it:"L'alcol compromette la capacita di elaborare piu input simultaneamente -- rendendo i compiti di guida molto piu difficili"},{en:"Divided attention is unaffected by alcohol",it:"L'attenzione divisa non e influenzata dall'alcol"},{en:"Only reaction time is affected, not multitasking",it:"Solo il tempo di reazione e influenzato, non il multitasking"}],correct:1,explain_en:"Driving requires constant multitasking (steering, braking, watching for hazards, reading signs, etc.). Alcohol's most damaging effect is impairing divided attention -- making each individual task harder.",explain_it:"La guida richiede un costante multitasking. L'effetto piu dannoso dell'alcol e compromettere l'attenzione divisa -- rendendo ogni singolo compito piu difficile."},
  {cat:"alcohol",en:"What is the Florida law on designated driver programs?",it:"Qual e la legge Florida sui programmi di guidatore designato?",options:[{en:"No legal status -- just a social practice",it:"Nessuno status legale -- solo una pratica sociale"},{en:"While not legally mandated, designated driver programs are encouraged -- some establishments offer free non-alcoholic drinks to designated drivers",it:"Sebbene non siano legalmente obbligatori, i programmi di guidatore designato sono incoraggiati -- alcuni esercizi offrono bevande analcoliche gratuite ai guidatori designati"},{en:"Required by law for groups of 4+ people drinking",it:"Richiesto dalla legge per gruppi di 4+ persone che bevono"},{en:"Designated drivers are legally immune from DUI charges",it:"I guidatori designati sono legalmente immuni dalle accuse DUI"}],correct:1,explain_en:"Designated driver programs are voluntary in Florida. Many bars and restaurants encourage them. The designated driver is NOT immune from DUI -- they must remain completely sober.",explain_it:"I programmi di guidatore designato sono volontari in Florida. Molti bar e ristoranti li incoraggiano. Il guidatore designato NON e immune dal DUI -- deve rimanere completamente sobrio."},
  {cat:"alcohol",en:"What happens to your BAC after you stop drinking?",it:"Cosa succede al tuo BAC dopo che smetti di bere?",options:[{en:"Drops immediately to zero",it:"Scende immediatamente a zero"},{en:"Continues to rise for a period (20-40 minutes) as alcohol already consumed is still being absorbed, then gradually falls",it:"Continua a salire per un periodo (20-40 minuti) man mano che l'alcol gia consumato viene ancora assorbito, poi scende gradualmente"},{en:"Drops at exactly 0.015% per hour",it:"Scende esattamente del 0,015% all'ora"},{en:"Drops immediately then levels off",it:"Scende immediatamente poi si stabilizza"}],correct:1,explain_en:"After your last drink, BAC may continue rising for 20-40 minutes as alcohol in the stomach continues being absorbed. Then it drops as the liver metabolizes it -- roughly 0.015% per hour.",explain_it:"Dopo l'ultimo drink, il BAC puo continuare a salire per 20-40 minuti man mano che l'alcol nello stomaco continua ad essere assorbito. Poi scende man mano che il fegato lo metabolizza."},
  {cat:"alcohol",en:"What is the Florida law on DUI for a commercial driver (CDL holder)?",it:"Qual e la legge Florida sul DUI per un conducente commerciale (titolare CDL)?",options:[{en:"Same 0.08% limit as regular drivers",it:"Stesso limite di 0,08% dei conducenti regolari"},{en:"0.04% BAC limit while operating a commercial vehicle -- disqualification for first offense",it:"Limite BAC di 0,04% durante l'operazione di un veicolo commerciale -- squalifica per la prima infrazione"},{en:"0.06% BAC limit for commercial drivers",it:"Limite BAC di 0,06% per i conducenti commerciali"},{en:"No alcohol permitted -- 0.00% limit",it:"Nessun alcol consentito -- limite 0,00%"}],correct:1,explain_en:"CDL holders: 0.04% BAC limit while driving a commercial vehicle. First offense = 1-year CDL disqualification. Carrying hazmat at the time = 3-year disqualification. Second offense = lifetime CDL disqualification.",explain_it:"Titolari CDL: limite BAC di 0,04% durante la guida di un veicolo commerciale. Prima infrazione = 1 anno di squalifica CDL. Seconda infrazione = squalifica CDL a vita."},
  {cat:"alcohol",en:"What is the legal definition of 'impairment' under Florida DUI law?",it:"Qual e la definizione legale di 'compromissione' ai sensi della legge DUI della Florida?",options:[{en:"Only when BAC is 0.08% or higher",it:"Solo quando il BAC e 0,08% o superiore"},{en:"When normal faculties are impaired -- including vision, hearing, coordination, balance, or reaction time -- by any substance",it:"Quando le normali facolta sono compromesse -- incluse visione, udito, coordinazione, equilibrio o tempo di reazione -- da qualsiasi sostanza"},{en:"Only when the driver causes an accident",it:"Solo quando il conducente causa un incidente"},{en:"When the driver admits to feeling drunk",it:"Quando il conducente ammette di sentirsi ubriaco"}],correct:1,explain_en:"Florida DUI: 'impairment' = the substance affected normal faculties -- the ability to see clearly, hear normally, walk, talk, judge distances, etc. This can occur below 0.08% BAC.",explain_it:"DUI Florida: 'compromissione' = la sostanza ha influenzato le normali facolta -- la capacita di vedere chiaramente, sentire normalmente, camminare, parlare, valutare le distanze, ecc."},
  {cat:"alcohol",en:"What does 'reasonable suspicion' mean for a Florida DUI traffic stop?",it:"Cosa significa 'sospetto ragionevole' per un fermo DUI Florida?",options:[{en:"The officer must have proof of DUI before stopping",it:"L'agente deve avere la prova del DUI prima di fermare"},{en:"The officer needs only an articulable reason to believe a traffic violation occurred -- DUI investigation follows if indicators are observed",it:"L'agente ha bisogno solo di una ragione articolabile per credere che si sia verificata una violazione del traffico -- l'indagine DUI segue se vengono osservati indicatori"},{en:"Random stops are permitted without any reason",it:"Le fermate casuali sono consentite senza alcuna ragione"},{en:"Only applies at DUI checkpoints",it:"Si applica solo ai posti di blocco DUI"}],correct:1,explain_en:"For a traffic stop: police need reasonable suspicion of a traffic violation (weaving, running a red light, etc.). If DUI indicators are observed during the stop (odor, slurred speech), investigation proceeds.",explain_it:"Per un fermo del traffico: la polizia ha bisogno di sospetto ragionevole di una violazione (serpentinamento, passaggio col rosso, ecc.). Se vengono osservati indicatori DUI durante il fermo, l'indagine procede."},
  {cat:"alcohol",en:"How does the 'ignition interlock device' work?",it:"Come funziona il 'dispositivo interlock di accensione'?",options:[{en:"It prevents the car from going above 35 mph",it:"Impedisce all'auto di superare i 35 mph"},{en:"Requires the driver to blow into a breathalyzer before the car will start -- the car won't start if alcohol is detected",it:"Richiede al conducente di soffiare in un etilometro prima che l'auto si avvii -- l'auto non si avvia se viene rilevato alcol"},{en:"Tracks the vehicle's location via GPS",it:"Tiene traccia della posizione del veicolo tramite GPS"},{en:"Sends alerts to the DMV when driving erratically",it:"Invia avvisi al DMV quando si guida in modo erratico"}],correct:1,explain_en:"IID (Ignition Interlock Device): driver must blow into a breath sensor before starting. If BAC exceeds threshold (~0.02%), the car won't start. Rolling retests required while driving to prevent someone else from blowing.",explain_it:"IID: il conducente deve soffiare in un sensore del respiro prima di avviare. Se il BAC supera la soglia (~0,02%), l'auto non si avvia. Sono richiesti test ripetuti durante la guida."},
  {cat:"alcohol",en:"What happens at a Florida DUI checkpoint if a driver appears sober?",it:"Cosa succede a un posto di blocco DUI Florida se un conducente appare sobrio?",options:[{en:"All drivers must take a breathalyzer",it:"Tutti i conducenti devono fare un etilometro"},{en:"If no indicators of impairment are observed, the driver is waved through after a brief interaction",it:"Se non vengono osservati indicatori di compromissione, il conducente viene fatto passare dopo una breve interazione"},{en:"All drivers must show proof they haven't been drinking",it:"Tutti i conducenti devono mostrare la prova che non hanno bevuto"},{en:"Random drivers are selected for testing regardless of indicators",it:"I conducenti casuali sono selezionati per i test indipendentemente dagli indicatori"}],correct:1,explain_en:"At a sobriety checkpoint: officers use neutral criteria to stop vehicles, check license/registration, and briefly observe the driver. If no impairment indicators, the driver is released within seconds.",explain_it:"A un posto di blocco: gli agenti usano criteri neutri per fermare i veicoli, controllare la patente/registrazione e osservare brevemente il conducente. Se non ci sono indicatori di compromissione, il conducente viene rilasciato in pochi secondi."},
  {cat:"alcohol",en:"What is the effect of alcohol on the sense of balance and coordination?",it:"Qual e l'effetto dell'alcol sul senso dell'equilibrio e la coordinazione?",options:[{en:"No effect on balance until very high BAC",it:"Nessun effetto sull'equilibrio fino a un BAC molto alto"},{en:"Impairs the cerebellum -- the brain region controlling balance, coordination, and fine motor skills",it:"Compromette il cervelletto -- la regione cerebrale che controlla equilibrio, coordinazione e abilita motorie fini"},{en:"Improves balance by relaxing muscles",it:"Migliora l'equilibrio rilassando i muscoli"},{en:"Only affects gross motor skills",it:"Influisce solo sulle abilita motorie grossolane"}],correct:1,explain_en:"Alcohol affects the cerebellum first -- causing coordination problems, unsteady gait, poor fine motor control, and impaired balance. This is why field sobriety tests include balance and coordination tasks.",explain_it:"L'alcol colpisce prima il cervelletto -- causando problemi di coordinazione, andatura instabile, scarso controllo motorio fine e equilibrio compromesso."},
  {cat:"alcohol",en:"What is the Florida law on alcohol consumption by a passenger in a vehicle?",it:"Qual e la legge Florida sul consumo di alcol da parte di un passeggero in un veicolo?",options:[{en:"Legal for passengers at any time",it:"Legale per i passeggeri in qualsiasi momento"},{en:"Illegal -- open container law prohibits consumption in the passenger area regardless of who is drinking",it:"Illegale -- la legge sul contenitore aperto vieta il consumo nell'area passeggeri indipendentemente da chi beve"},{en:"Legal for passengers over 21 in the back seat",it:"Legale per i passeggeri over 21 nel sedile posteriore"},{en:"Legal if the driver is not drinking",it:"Legale se il conducente non beve"}],correct:1,explain_en:"Florida open container: no consuming alcohol in the passenger compartment of any vehicle -- driver or passenger. The container must be sealed and in the trunk or other non-passenger area.",explain_it:"Contenitore aperto Florida: nessun consumo di alcol nell'abitacolo di qualsiasi veicolo -- conducente o passeggero."},
  {cat:"alcohol",en:"What does 'blood alcohol concentration' actually measure?",it:"Cosa misura effettivamente la 'concentrazione di alcol nel sangue'?",options:[{en:"The amount of alcohol in the stomach",it:"La quantita di alcol nello stomaco"},{en:"The grams of alcohol per 100 milliliters of blood -- expressed as a percentage",it:"I grammi di alcol per 100 millilitri di sangue -- espressi come percentuale"},{en:"The volume of alcohol consumed",it:"Il volume di alcol consumato"},{en:"The time since the last drink",it:"Il tempo dall'ultimo drink"}],correct:1,explain_en:"BAC = grams of pure alcohol per 100 mL of blood. 0.08% BAC = 0.08 grams per 100 mL. This is measured via breath (Breathalyzer uses the ratio of alcohol in breath to blood), blood draw, or urine.",explain_it:"BAC = grammi di alcol puro per 100 mL di sangue. 0,08% BAC = 0,08 grammi per 100 mL. Viene misurato tramite respiro (etilometro), prelievo di sangue o urina."},
  {cat:"license",en:"What is the Florida law about the 'organ donor' designation on a driver's license?",it:"Qual e la legge Florida sulla designazione 'donatore di organi' sulla patente?",options:[{en:"The designation can be overridden by family members",it:"La designazione puo essere sostituta dai familiari"},{en:"The donor designation on a license is legally binding -- family members cannot override the decision",it:"La designazione del donatore sulla patente e legalmente vincolante -- i familiari non possono annullare la decisione"},{en:"The designation expires with the license",it:"La designazione scade con la patente"},{en:"Only valid if notarized",it:"Valida solo se notarizzata"}],correct:1,explain_en:"Florida organ donor designation: once registered (shown by heart symbol on license), the decision is legally binding in most circumstances. Family input may be considered but cannot legally override a documented decision.",explain_it:"Designazione donatore di organi Florida: una volta registrata (mostrata dal simbolo a cuore sulla patente), la decisione e legalmente vincolante nella maggior parte delle circostanze."},
  {cat:"license",en:"What does the 'not for REAL ID purposes' notation on a Florida license mean?",it:"Cosa significa la notazione 'not for REAL ID purposes' su una patente Florida?",options:[{en:"The license is expired",it:"La patente e scaduta"},{en:"This license cannot be used for federal identification purposes such as boarding flights or entering federal buildings",it:"Questa patente non puo essere usata per scopi di identificazione federale come l'imbarco su voli o l'ingresso in edifici federali"},{en:"The license was issued to a non-citizen",it:"La patente e stata rilasciata a un non cittadino"},{en:"The license has restrictions",it:"La patente ha restrizioni"}],correct:1,explain_en:"A non-REAL ID Florida license cannot be used for federal identification purposes (boarding domestic flights, entering secure federal facilities). A passport or REAL ID compliant license is needed for those purposes.",explain_it:"Una patente Florida non-REAL ID non puo essere usata per scopi di identificazione federale (imbarco su voli nazionali, ingresso in strutture federali sicure)."},
  {cat:"license",en:"What is the Florida law on renting a vehicle with a learner's permit?",it:"Qual e la legge Florida sul noleggio di un veicolo con il permesso per principianti?",options:[{en:"May rent with parental consent",it:"Puo noleggiare con il consenso dei genitori"},{en:"Cannot rent -- rental companies require a full driver's license",it:"Non puo noleggiare -- le societa di noleggio richiedono una patente completa"},{en:"May rent motorcycles only",it:"Puo noleggiare solo moto"},{en:"May rent with supervisor present",it:"Puo noleggiare con supervisore presente"}],correct:1,explain_en:"Rental car companies require a full driver's license (not a learner's permit) to rent a vehicle. Most also require renters to be 21+ and have a credit card.",explain_it:"Le societa di noleggio auto richiedono una patente completa (non un permesso per principianti) per noleggiare un veicolo."},
  {cat:"license",en:"What is the difference between license 'suspension' and 'revocation' in Florida?",it:"Qual e la differenza tra 'sospensione' e 'revoca' della patente in Florida?",options:[{en:"They mean the same thing",it:"Significano la stessa cosa"},{en:"Suspension is temporary -- driving privilege is withdrawn for a set period; revocation means the license is cancelled and must be reapplied for",it:"La sospensione e temporanea -- il privilegio di guida viene ritirato per un periodo stabilito; la revoca significa che la patente viene annullata e deve essere richiesta di nuovo"},{en:"Revocation is less serious than suspension",it:"La revoca e meno grave della sospensione"},{en:"Suspension requires a court order; revocation is administrative",it:"La sospensione richiede un ordine del tribunale; la revoca e amministrativa"}],correct:1,explain_en:"Suspension = temporary removal of driving privilege for a defined period. Revocation = cancellation of the license -- the person must reapply and meet all requirements to get a new license after the revocation period.",explain_it:"Sospensione = rimozione temporanea del privilegio di guida per un periodo definito. Revoca = cancellazione della patente -- la persona deve fare domanda di nuovo e soddisfare tutti i requisiti."},
  {cat:"license",en:"What is the Florida law about the minimum number of supervised driving hours for a learner's permit holder?",it:"Qual e la legge Florida sul numero minimo di ore di guida supervisionata per un titolare del permesso per principianti?",options:[{en:"25 hours total",it:"25 ore totali"},{en:"50 hours total (10 of which must be at night) before upgrading to a Restricted License",it:"50 ore totali (di cui 10 di notte) prima di passare alla patente limitata"},{en:"30 hours total",it:"30 ore totali"},{en:"No minimum hours required",it:"Nessuna ora minima richiesta"}],correct:1,explain_en:"Florida requires 50 hours of supervised driving (with a licensed 21+ driver), including 10 hours at night, before a 16-17 year old can upgrade to a Restricted (provisional) license.",explain_it:"La Florida richiede 50 ore di guida supervisionata (con un conducente autorizzato 21+), di cui 10 ore di notte, prima che un 16-17enne possa passare alla patente limitata (provvisoria)."},
  {cat:"license",en:"What is the Florida law on the validity period of a standard Class E license?",it:"Qual e la legge Florida sul periodo di validita di una patente standard Class E?",options:[{en:"4 years",it:"4 anni"},{en:"8 years for drivers under 80; must be renewed in person after age 79",it:"8 anni per i conducenti under 80; deve essere rinnovata di persona dopo i 79 anni"},{en:"5 years for all ages",it:"5 anni per tutte le eta"},{en:"6 years, renewed every birthday",it:"6 anni, rinnovata ogni compleanno"}],correct:1,explain_en:"Florida standard license: valid for 8 years (expires on your birthday). Drivers over 79 must renew every 6 years in person. REAL ID licenses have the same validity as standard licenses.",explain_it:"Patente standard Florida: valida per 8 anni (scade il tuo compleanno). I conducenti over 79 devono rinnovare ogni 6 anni di persona."},
  {cat:"license",en:"What points are assigned for passing a stopped school bus in Florida?",it:"Quanti punti vengono assegnati per il sorpasso di uno scuolabus fermo in Florida?",options:[{en:"3 points",it:"3 punti"},{en:"4 points",it:"4 punti"},{en:"6 points",it:"6 punti"},{en:"12 points -- automatic suspension",it:"12 punti -- sospensione automatica"}],correct:2,explain_en:"Passing a stopped school bus with flashing lights in Florida: 4 points on your license. Combined with the fine, this is one of the more serious moving violations in Florida.",explain_it:"Superare uno scuolabus fermo con luci lampeggianti in Florida: 4 punti sulla patente. Combinato con la multa, questa e una delle violazioni in movimento piu gravi in Florida."},
  {cat:"license",en:"What is the Florida law about providing false information when applying for a driver's license?",it:"Qual e la legge Florida sulla fornitura di informazioni false quando si richiede una patente?",options:[{en:"A civil infraction with a $50 fine",it:"Un'infrazione civile con una multa di $50"},{en:"A criminal offense -- fraudulent application for a license is a misdemeanor or felony",it:"Un reato penale -- la domanda fraudolenta di una patente e una contravvenzione o crimine"},{en:"Only results in the application being rejected",it:"Comporta solo il rifiuto della domanda"},{en:"Legal if the misrepresentation was minor",it:"Legale se l'inesattezza era minore"}],correct:1,explain_en:"Providing false information on a license application in Florida is a criminal offense. This includes false address, identity, or eligibility information. Penalties can include imprisonment.",explain_it:"Fornire informazioni false su una domanda di patente in Florida e un reato penale. Questo include indirizzo falso, identita o informazioni di idoneita false."},
  {cat:"license",en:"What is the Florida law about using a cell phone while holding a learner's permit?",it:"Qual e la legge Florida sull'uso del cellulare con il permesso per principianti?",options:[{en:"Same rules as adult drivers",it:"Le stesse regole dei conducenti adulti"},{en:"Prohibited from using any wireless communication device while driving with a learner's permit",it:"Vietato usare qualsiasi dispositivo di comunicazione wireless durante la guida con il permesso per principianti"},{en:"Hands-free only permitted",it:"Consentito solo mani libere"},{en:"Only prohibited at night",it:"Vietato solo di notte"}],correct:1,explain_en:"Florida learner's permit holders are completely prohibited from using any wireless communication device while driving -- no calls, texts, or any other device use, even hands-free.",explain_it:"I titolari del permesso per principianti Florida sono completamente vietati dall'usare qualsiasi dispositivo di comunicazione wireless durante la guida -- nessuna chiamata, messaggio o qualsiasi altro uso del dispositivo."},
  {cat:"license",en:"What is the Florida law about allowing a passenger with a learner's permit to drive?",it:"Qual e la legge Florida sull'autorizzare un passeggero con il permesso per principianti a guidare?",options:[{en:"Legal if the car owner consents",it:"Legale se il proprietario dell'auto acconsente"},{en:"The supervising licensed driver is legally responsible for ensuring the permit holder complies with all restrictions",it:"Il conducente autorizzato supervisore e legalmente responsabile di garantire che il titolare del permesso rispetti tutte le restrizioni"},{en:"No special responsibility for the supervising driver",it:"Nessuna responsabilita speciale per il conducente supervisore"},{en:"Supervising driver must be a family member",it:"Il conducente supervisore deve essere un familiare"}],correct:1,explain_en:"The supervising licensed driver assumes responsibility for ensuring the permit holder follows all legal restrictions. If violations occur, both the permit holder and supervisor may face consequences.",explain_it:"Il conducente autorizzato supervisore assume la responsabilita di garantire che il titolare del permesso segua tutte le restrizioni legali."},
  {cat:"license",en:"What is the Florida law about commercial driver license (CDL) medical certificates?",it:"Qual e la legge Florida sui certificati medici della patente commerciale (CDL)?",options:[{en:"Medical certificate not required for CDL",it:"Certificato medico non richiesto per CDL"},{en:"CDL holders must have a current medical examiner's certificate -- physical examination required periodically",it:"I titolari CDL devono avere un certificato dell'esaminatore medico corrente -- esame fisico richiesto periodicamente"},{en:"Medical certificate only required for hazmat transport",it:"Certificato medico richiesto solo per il trasporto hazmat"},{en:"Self-certification is sufficient",it:"L'autocertificazione e sufficiente"}],correct:1,explain_en:"CDL holders must maintain a current medical examiner's certificate (DOT physical). The certificate is typically valid for 2 years for healthy drivers. Certain conditions require more frequent exams.",explain_it:"I titolari CDL devono mantenere un certificato medico corrente (esame fisico DOT). Il certificato e tipicamente valido per 2 anni per i conducenti sani."},
  {cat:"license",en:"What is the Florida 'Habitual Traffic Offender' (HTO) designation?",it:"Qual e la designazione Florida 'Habitual Traffic Offender' (HTO)?",options:[{en:"Any driver with 3 or more accidents",it:"Qualsiasi conducente con 3 o piu incidenti"},{en:"A driver who accumulates 3 convictions for major violations OR 15 total convictions within 5 years -- results in 5-year revocation",it:"Un conducente che accumula 3 condanne per violazioni maggiori O 15 condanne totali entro 5 anni -- comporta revoca di 5 anni"},{en:"A driver with more than 12 points in one year",it:"Un conducente con piu di 12 punti in un anno"},{en:"A driver with 2 DUI convictions",it:"Un conducente con 2 condanne DUI"}],correct:1,explain_en:"Florida Habitual Traffic Offender: 3 major violations (DUI, driving while revoked, vehicular homicide, etc.) OR 15 total convictions within 5 years = mandatory 5-year license revocation.",explain_it:"Habitual Traffic Offender Florida: 3 violazioni maggiori (DUI, guida mentre revocato, omicidio colposo, ecc.) O 15 condanne totali entro 5 anni = revoca obbligatoria della patente di 5 anni."},
  {cat:"license",en:"What is the fee for reinstatement of a suspended Florida driver's license?",it:"Qual e la tariffa per il reintegro di una patente Florida sospesa?",options:[{en:"$10 flat fee",it:"Tariffa fissa di $10"},{en:"Varies by violation type -- typically $45 to $75 for standard suspensions, higher for serious violations",it:"Varia in base al tipo di violazione -- tipicamente $45-$75 per le sospensioni standard, piu alta per le violazioni gravi"},{en:"$500 for all suspensions",it:"$500 per tutte le sospensioni"},{en:"No fee -- just complete the suspension period",it:"Nessuna tariffa -- basta completare il periodo di sospensione"}],correct:1,explain_en:"Florida reinstatement fees vary by violation type: $45-$75 for standard suspensions, up to $75-$150+ for serious violations. DUI reinstatement has additional requirements beyond just paying a fee.",explain_it:"Le tariffe di reintegro Florida variano per tipo di violazione: $45-$75 per le sospensioni standard, fino a $75-$150+ per le violazioni gravi."},
  {cat:"license",en:"What is the Florida law on passenger restrictions for a 16-17 year old with a Restricted License during the first 12 months?",it:"Qual e la legge Florida sulle restrizioni per i passeggeri per un 16-17enne con patente limitata durante i primi 12 mesi?",options:[{en:"No passengers allowed",it:"Nessun passeggero consentito"},{en:"No more than 1 non-household member passenger under 18 (unless immediate family) during first 12 months",it:"Non piu di 1 passeggero non convivente under 18 (salvo familiari immediati) durante i primi 12 mesi"},{en:"2 passengers under 18 are permitted",it:"2 passeggeri under 18 sono consentiti"},{en:"Only family members may be passengers at any time",it:"Solo i familiari possono essere passeggeri in qualsiasi momento"}],correct:1,explain_en:"Florida GDL Restricted License (16-17, first 12 months): max 1 non-household passenger under 18 in the vehicle. Immediate family members exempt. Exception for work/school with documentation.",explain_it:"Patente limitata GDL Florida (16-17, primi 12 mesi): max 1 passeggero non convivente under 18 nel veicolo. Familiari immediati esenti."},
  {cat:"license",en:"When can a Florida 17-year-old upgrade from a Restricted License to an unrestricted license?",it:"Quando puo un 17enne Florida passare da una patente limitata a una senza restrizioni?",options:[{en:"After holding restricted license 6 months with no violations",it:"Dopo aver tenuto la patente limitata 6 mesi senza violazioni"},{en:"At age 18 -- the restricted license automatically becomes unrestricted on the driver's 18th birthday",it:"A 18 anni -- la patente limitata diventa automaticamente senza restrizioni al 18\u00b0 compleanno del conducente"},{en:"After passing an advanced driving test",it:"Dopo aver superato un test di guida avanzato"},{en:"After 24 months with the restricted license",it:"Dopo 24 mesi con la patente limitata"}],correct:1,explain_en:"Florida GDL: the Restricted License restrictions automatically lift at age 18. No test or application required -- the existing license becomes unrestricted when the driver turns 18.",explain_it:"GDL Florida: le restrizioni della patente limitata si tolgono automaticamente a 18 anni. Nessun test o domanda richiesta -- la patente esistente diventa senza restrizioni quando il conducente compie 18 anni."},
  {cat:"license",en:"What is the Florida law about having a driver's license from another country and getting pulled over?",it:"Qual e la legge Florida sull'avere una patente di un altro paese ed essere fermati dalla polizia?",options:[{en:"Foreign licenses are never accepted by Florida police",it:"Le patenti straniere non sono mai accettate dalla polizia Florida"},{en:"A valid foreign license is acceptable for visitors -- police will accept it as proof of driving authority",it:"Una patente straniera valida e accettabile per i visitatori -- la polizia la accettera come prova dell'autorizzazione alla guida"},{en:"Must have an International Driving Permit (IDP) to be accepted",it:"Deve avere un Permesso di Guida Internazionale (IDP) per essere accettata"},{en:"Foreign licenses are only valid for 30 days in Florida",it:"Le patenti straniere sono valide solo 30 giorni in Florida"}],correct:1,explain_en:"Florida accepts valid foreign licenses for visitors. An IDP is recommended as a translation aid but is not legally required. If you are a resident (established domicile), you must get a Florida license within 30 days.",explain_it:"La Florida accetta patenti straniere valide per i visitatori. Un IDP e raccomandato come aiuto alla traduzione ma non e legalmente richiesto."},
  {cat:"license",en:"What is Florida's law on the minimum age to apply for a learner's license?",it:"Qual e la legge Florida sull'eta minima per richiedere il permesso per principianti?",options:[{en:"14 years old",it:"14 anni"},{en:"15 years old",it:"15 anni"},{en:"16 years old",it:"16 anni"},{en:"17 years old",it:"17 anni"}],correct:1,explain_en:"Florida minimum age for a learner's license (learner's permit) is 15 years old. The applicant must pass a knowledge test and vision screening.",explain_it:"L'eta minima Florida per il permesso per principianti e 15 anni. Il richiedente deve superare un test di conoscenza e uno screening della visione."},
  {cat:"license",en:"What is the Florida law on the maximum points before an automatic license suspension?",it:"Qual e la legge Florida sul numero massimo di punti prima della sospensione automatica della patente?",options:[{en:"10 points in any period",it:"10 punti in qualsiasi periodo"},{en:"12 points in 12 months, 18 in 18 months, or 24 in 36 months each trigger suspensions",it:"12 punti in 12 mesi, 18 in 18 mesi, o 24 in 36 mesi ognuno attiva sospensioni"},{en:"20 points in any 12-month period",it:"20 punti in qualsiasi periodo di 12 mesi"},{en:"15 points at any time",it:"15 punti in qualsiasi momento"}],correct:1,explain_en:"Florida point suspension thresholds: 12 points/12 months = 30-day suspension; 18 points/18 months = 3-month suspension; 24 points/36 months = 1-year suspension.",explain_it:"Soglie di sospensione punti Florida: 12 punti/12 mesi = sospensione 30 giorni; 18 punti/18 mesi = sospensione 3 mesi; 24 punti/36 mesi = sospensione 1 anno."},
  {cat:"license",en:"What is the Florida law about the 'administrative hearing' option after a DUI arrest?",it:"Qual e la legge Florida sull'opzione 'udienza amministrativa' dopo un arresto DUI?",options:[{en:"No hearing option -- suspension is automatic",it:"Nessuna opzione di udienza -- la sospensione e automatica"},{en:"Must request a formal hearing within 10 days of arrest to challenge the administrative license suspension",it:"Deve richiedere un'udienza formale entro 10 giorni dall'arresto per contestare la sospensione amministrativa della patente"},{en:"30 days to request a hearing",it:"30 giorni per richiedere un'udienza"},{en:"Hearing requests are automatic",it:"Le richieste di udienza sono automatiche"}],correct:1,explain_en:"After a DUI arrest in Florida: you have 10 days to request a formal review hearing to challenge the ALS (administrative license suspension). Miss the 10-day window and the suspension is automatic.",explain_it:"Dopo un arresto DUI in Florida: hai 10 giorni per richiedere un'udienza formale di revisione per contestare la sospensione amministrativa. Perdere la finestra di 10 giorni e la sospensione e automatica."},
  {cat:"license",en:"What is the Florida law about 'hardship licenses' during a DUI suspension?",it:"Qual e la legge Florida sulle 'patenti di necessita' durante una sospensione DUI?",options:[{en:"Not available for DUI suspensions",it:"Non disponibile per le sospensioni DUI"},{en:"Available for first DUI after serving a mandatory period -- allows driving to work, school, or medical appointments",it:"Disponibile per il primo DUI dopo aver scontato un periodo obbligatorio -- consente di guidare al lavoro, a scuola o agli appuntamenti medici"},{en:"Available immediately upon request",it:"Disponibile immediatamente su richiesta"},{en:"Only for commercial drivers",it:"Solo per i conducenti commerciali"}],correct:1,explain_en:"Florida hardship (business purposes only) license: available after serving the mandatory suspension period for a first DUI. Requires enrollment in DUI school and restricted driving to essential activities.",explain_it:"Patente di necessita Florida: disponibile dopo aver scontato il periodo di sospensione obbligatorio per il primo DUI. Richiede l'iscrizione alla scuola DUI e la guida limitata alle attivita essenziali."},

  // SESSION 12 FINAL
  {cat:"signs",en:"What does a 'Divided Highway Begins' sign mean?",it:"Cosa significa un segnale 'Divided Highway Begins'?",options:[{en:"The road is narrowing",it:"La strada si sta restringendo"},{en:"The road ahead is divided by a median -- keep right of the divider",it:"La strada in avanti e divisa da un mediano -- mantenersi a destra del divisore"},{en:"The road ends and splits into two separate roads",it:"La strada finisce e si divide in due strade separate"},{en:"A two-way left turn lane begins",it:"Inizia una corsia di svolta sinistra a doppio senso"}],correct:1,explain_en:"Divided Highway Begins: a physical median or barrier will separate opposing traffic ahead. Stay to the right of the center divider -- head-on crashes are a serious risk if you cross it.",explain_it:"Divided Highway Begins: un mediano fisico o barriera separera il traffico opposto in avanti. Mantenersi a destra del divisore centrale."},
  {cat:"signs",en:"What does a 'Yield Ahead' sign tell a driver?",it:"Cosa dice a un conducente un segnale 'Yield Ahead'?",options:[{en:"Yield immediately",it:"Cedere immediatamente"},{en:"A yield sign is ahead -- begin slowing to be ready to yield to conflicting traffic",it:"Un segnale di resa e in avanti -- iniziare a rallentare per essere pronti a cedere al traffico in conflitto"},{en:"Speed up to pass before reaching the yield",it:"Accelerare per passare prima di raggiungere la resa"},{en:"The road ahead merges",it:"La strada in avanti si unisce"}],correct:1,explain_en:"Yield Ahead warns that a yield sign or situation is coming. Begin reducing speed so you can smoothly yield to conflicting traffic when you reach the sign.",explain_it:"Yield Ahead avvisa che si sta avvicinando un segnale di resa. Iniziare a ridurre la velocita per cedere fluidamente al traffico in conflitto quando si raggiunge il segnale."},
  {cat:"signs",en:"What does an orange 'ROAD CLOSED LOCAL TRAFFIC ONLY' sign mean?",it:"Cosa significa un segnale arancione 'ROAD CLOSED LOCAL TRAFFIC ONLY'?",options:[{en:"The road is fully closed to all traffic",it:"La strada e completamente chiusa a tutto il traffico"},{en:"Through traffic must use an alternate route -- only vehicles accessing local properties may proceed",it:"Il traffico di transito deve usare un percorso alternativo -- solo i veicoli che accedono a proprieta locali possono procedere"},{en:"Only trucks are restricted",it:"Solo i camion sono limitati"},{en:"The road is closed at night only",it:"La strada e chiusa solo di notte"}],correct:1,explain_en:"Road Closed Local Traffic Only: through traffic must detour. Only vehicles whose destination is on that road (residents, deliveries) may proceed. This is common during construction.",explain_it:"Road Closed Local Traffic Only: il traffico di transito deve fare una deviazione. Solo i veicoli la cui destinazione e su quella strada possono procedere."},
  {cat:"signs",en:"What does a 'No Pedestrian Crossing' sign look like?",it:"Come appare un segnale 'No Pedestrian Crossing'?",options:[{en:"A green circle with a walking figure",it:"Un cerchio verde con una figura che cammina"},{en:"A white circle or rectangle with a walking figure crossed by a red slash",it:"Un cerchio o rettangolo bianco con una figura che cammina attraversata da una barra rossa"},{en:"A red octagon with P",it:"Un ottagono rosso con P"},{en:"A yellow diamond with a walking figure",it:"Un rombo giallo con una figura che cammina"}],correct:1,explain_en:"No Pedestrian Crossing uses the standard prohibition format: the action (pedestrian walking) crossed by a red prohibition slash. It prohibits crossing at that location.",explain_it:"No Pedestrian Crossing usa il formato standard di divieto: l'azione (pedone che cammina) attraversata da una barra di divieto rossa."},
  {cat:"signs",en:"What does a 'No Bicycles' sign indicate?",it:"Cosa indica un segnale 'No Bicycles'?",options:[{en:"Bicycles must yield to pedestrians",it:"Le biciclette devono cedere ai pedoni"},{en:"Bicycles are prohibited on this road, path, or facility",it:"Le biciclette sono vietate su questa strada, percorso o struttura"},{en:"A bicycle rack is not available",it:"Un portabiciclette non e disponibile"},{en:"Motorized bicycles only are permitted",it:"Solo biciclette motorizzate sono consentite"}],correct:1,explain_en:"A No Bicycles sign prohibits cycling in that area -- typically on high-speed roads, some pedestrian-only paths, or inside certain facilities. Cyclists must find an alternate route.",explain_it:"Un segnale No Bicycles vieta il ciclismo in quell'area -- tipicamente su strade ad alta velocita, alcuni percorsi solo pedonali o all'interno di determinate strutture."},
  {cat:"signs",en:"What color and shape is a U.S. Route sign?",it:"Che colore e forma ha un segnale di percorso U.S.?",options:[{en:"Green rectangle",it:"Rettangolo verde"},{en:"White shield shape with black route number",it:"Forma a scudo bianca con numero di percorso nero"},{en:"Blue circle with route number",it:"Cerchio blu con numero di percorso"},{en:"Red pentagon",it:"Pentagono rosso"}],correct:1,explain_en:"U.S. Route signs are white shield-shaped markers with black numbers. They identify numbered U.S. highways as part of the national highway system.",explain_it:"I segnali di percorso U.S. sono marker a forma di scudo bianchi con numeri neri. Identificano le autostrade U.S. numerate come parte del sistema autostradale nazionale."},
  {cat:"signs",en:"What shape and color is an Interstate Highway sign?",it:"Che forma e colore ha un segnale di autostrada interstatale?",options:[{en:"Green rectangle",it:"Rettangolo verde"},{en:"Blue shield with red top and white route number",it:"Scudo blu con sommita rossa e numero di percorso bianco"},{en:"White pentagon",it:"Pentagono bianco"},{en:"Green and white shield",it:"Scudo verde e bianco"}],correct:1,explain_en:"Interstate Highway signs are blue shields with a red top banner and white route number. They are part of the federal highway system and indicate limited-access divided highways.",explain_it:"I segnali di autostrada interstatale sono scudi blu con un banner superiore rosso e numero di percorso bianco."},
  {cat:"signs",en:"What does a 'No Trucks' sign indicate?",it:"Cosa indica un segnale 'No Trucks'?",options:[{en:"Trucks must pay a toll",it:"I camion devono pagare un pedaggio"},{en:"Commercial trucks are prohibited on this road -- usually due to weight, height, or width restrictions",it:"I camion commerciali sono vietati su questa strada -- solitamente a causa di restrizioni di peso, altezza o larghezza"},{en:"Trucks must use the right lane only",it:"I camion devono usare solo la corsia destra"},{en:"Trucks must stop at the weigh station ahead",it:"I camion devono fermarsi alla stazione di pesatura in avanti"}],correct:1,explain_en:"No Trucks signs prohibit commercial truck traffic from that road -- commonly due to weight limits, low clearance bridges, or neighborhood protection ordinances.",explain_it:"I segnali No Trucks vietano il traffico dei camion commerciali da quella strada -- comunemente a causa di limiti di peso, ponti a bassa altezza o ordinanze di protezione del quartiere."},
  {cat:"signs",en:"What does a 'Steep Grade' (percentage) sign warn drivers about?",it:"Cosa avvisa i conducenti un segnale 'Steep Grade' (percentuale)?",options:[{en:"Road quality rating",it:"Valutazione della qualita stradale"},{en:"The road has a significant incline or decline -- the percentage indicates rise or fall per 100 feet",it:"La strada ha una notevole inclinazione o discesa -- la percentuale indica salita o discesa per 100 piedi"},{en:"Speed limit on the grade",it:"Limite di velocita sulla pendenza"},{en:"The road is under construction at this grade",it:"La strada e in costruzione a questa pendenza"}],correct:1,explain_en:"Steep grade signs (e.g., '8% grade'): 8 feet of rise/fall per 100 feet of road. Trucks must use low gears on downgrades; all vehicles should check brakes and reduce speed.",explain_it:"Segnali di pendenza ripida (es. '8% grade'): 8 piedi di salita/discesa per 100 piedi di strada. I camion devono usare marce basse nelle discese."},
  {cat:"signs",en:"What does a 'Traffic Signal Ahead' warning sign mean for a driver approaching at highway speed?",it:"Cosa significa un segnale di avvertimento 'Traffic Signal Ahead' per un conducente che si avvicina a velocita autostradale?",options:[{en:"Maintain speed -- signals are timed for highway speeds",it:"Mantenere la velocita -- i segnali sono sincronizzati per le velocita autostradali"},{en:"Reduce speed and be prepared to stop -- a signal is ahead that may be red",it:"Ridurre la velocita e prepararsi a fermarsi -- un segnale e in avanti che potrebbe essere rosso"},{en:"Move to the right lane only",it:"Spostarsi solo nella corsia destra"},{en:"Advisory only -- no legal requirement to slow",it:"Solo advisory -- nessun requisito legale per rallentare"}],correct:1,explain_en:"Traffic Signal Ahead: prepare to encounter a signal, reduce speed appropriately, and be ready to stop. Posted because the signal may not be expected at that location (e.g., end of a highway segment).",explain_it:"Traffic Signal Ahead: prepararsi a incontrare un segnale, ridurre la velocita e essere pronti a fermarsi."},
  {cat:"signs",en:"What does a 'Ped Xing' (pedestrian crossing) sign require of drivers?",it:"Cosa richiede ai conducenti un segnale 'Ped Xing' (attraversamento pedonale)?",options:[{en:"No requirement -- pedestrians must yield to vehicles",it:"Nessun requisito -- i pedoni devono cedere ai veicoli"},{en:"Watch for pedestrians crossing and be prepared to yield or stop",it:"Fare attenzione ai pedoni che attraversano e essere pronti a cedere o fermarsi"},{en:"Sound horn to warn pedestrians",it:"Suonare il clacson per avvisare i pedoni"},{en:"Only applicable during daylight hours",it:"Applicabile solo durante le ore diurne"}],correct:1,explain_en:"Pedestrian Crossing signs warn of areas where pedestrians frequently cross. Drivers must watch for pedestrians and be prepared to yield -- especially near schools, parks, and residential areas.",explain_it:"I segnali di attraversamento pedonale avvisano di aree dove i pedoni attraversano frequentemente. I conducenti devono fare attenzione e essere pronti a cedere."},
  {cat:"signs",en:"What does a 'Bicycle Crossing' sign indicate?",it:"Cosa indica un segnale 'Bicycle Crossing'?",options:[{en:"A dedicated bike lane begins",it:"Inizia una corsia ciclabile dedicata"},{en:"An area where cyclists frequently cross the road -- drivers should watch for bicycles",it:"Un'area dove i ciclisti attraversano frequentemente la strada -- i conducenti dovrebbero fare attenzione alle biciclette"},{en:"Bicycles are prohibited from crossing here",it:"Le biciclette sono vietate dall'attraversare qui"},{en:"A bicycle rental station ahead",it:"Una stazione di noleggio biciclette in avanti"}],correct:1,explain_en:"Bicycle Crossing signs (often fluorescent yellow-green) warn drivers that cyclists frequently cross at this location. Reduce speed and watch for bicycles entering the roadway.",explain_it:"I segnali di attraversamento ciclabile (spesso giallo-verde fluorescente) avvisano i conducenti che i ciclisti attraversano frequentemente in questo punto."},
  {cat:"signs",en:"What does 'END SCHOOL ZONE' sign mean?",it:"Cosa significa un segnale 'END SCHOOL ZONE'?",options:[{en:"School speed limits now apply",it:"Si applicano ora i limiti di velocita scolastici"},{en:"The school speed limit zone has ended -- normal speed limits resume",it:"La zona del limite di velocita scolastico e terminata -- riprendono i normali limiti di velocita"},{en:"School is closed for the day",it:"La scuola e chiusa per la giornata"},{en:"No more school buses on this road",it:"Nessun altro scuolabus su questa strada"}],correct:1,explain_en:"End School Zone marks the boundary where the school zone speed restrictions end. Once past this sign, normal speed limits apply -- but remain alert for children in the area.",explain_it:"End School Zone segna il confine dove terminano le restrizioni di velocita della zona scolastica. Una volta passato questo segnale, si applicano i normali limiti di velocita."},
  {cat:"signs",en:"What does the word 'STOP' painted on the road surface indicate?",it:"Cosa indica la parola 'STOP' dipinta sulla superficie stradale?",options:[{en:"An advisory to slow down",it:"Un advisory per rallentare"},{en:"A stop line or position -- you must stop here at a stop sign or red signal",it:"Una linea o posizione di stop -- devi fermarti qui a un segnale di stop o semaforo rosso"},{en:"Parking prohibited",it:"Parcheggio vietato"},{en:"For pedestrians only",it:"Solo per i pedoni"}],correct:1,explain_en:"STOP on the road surface marks the stopping position at an intersection with a stop sign or signal. You must stop with the front of your vehicle at or before this marking.",explain_it:"STOP sulla superficie stradale segna la posizione di arresto a un incrocio con segnale di stop o semaforo. Devi fermarti con il fronte del tuo veicolo a o prima di questa segnaletica."},
  {cat:"signs",en:"What does 'KEEP LEFT' mean when posted at a fork or island?",it:"Cosa significa 'KEEP LEFT' quando affisso a un bivio o isola?",options:[{en:"Always stay in the left lane",it:"Stare sempre nella corsia sinistra"},{en:"Pass the obstacle on the left side -- the island or median must be passed on your left",it:"Superare l'ostacolo sul lato sinistro -- l'isola o il mediano deve essere superato alla tua sinistra"},{en:"Yield to traffic on the left",it:"Cedere al traffico a sinistra"},{en:"Left lane is faster -- use it",it:"La corsia sinistra e piu veloce -- usala"}],correct:1,explain_en:"Keep Left signs at an island or obstruction mean pass on the LEFT side of the island. This is less common in the U.S. but used at specific road configurations.",explain_it:"I segnali Keep Left a un'isola o ostacolo significano passare sul lato SINISTRO dell'isola."},
  {cat:"signs",en:"What does an advance warning sign for a sharp curve (hairpin) typically recommend?",it:"Cosa raccomanda tipicamente un segnale di avvertimento anticipato per una curva stretta (gomito)?",options:[{en:"Stop before the curve",it:"Fermarsi prima della curva"},{en:"An advisory speed well below the posted limit -- significantly reduce speed before entering",it:"Una velocita consigliata ben al di sotto del limite segnalato -- ridurre significativamente la velocita prima di entrare"},{en:"Increase speed to maintain momentum through the curve",it:"Aumentare la velocita per mantenere lo slancio attraverso la curva"},{en:"Only applicable for trucks",it:"Applicabile solo ai camion"}],correct:1,explain_en:"Sharp curve advance warnings include an advisory speed plate (yellow, e.g., '15 MPH'). This is the recommended maximum speed to safely navigate the curve -- not a legal limit but ignoring it risks loss of control.",explain_it:"Gli avvertimenti anticipati di curve strette includono una targa di velocita consigliata (gialla, es. '15 MPH'). Questa e la velocita massima raccomandata per navigare la curva in sicurezza."},
  {cat:"signs",en:"What does a 'Divided Highway' warning sign look like?",it:"Come appare un segnale di avvertimento 'Divided Highway'?",options:[{en:"White rectangle with median symbol",it:"Rettangolo bianco con simbolo mediano"},{en:"Yellow diamond showing two arrows diverging from a center line (road splits)",it:"Rombo giallo che mostra due frecce che divergono da una linea centrale (la strada si divide)"},{en:"Blue sign with direction arrows",it:"Segnale blu con frecce direzionali"},{en:"Green rectangle with split road symbol",it:"Rettangolo verde con simbolo di strada divisa"}],correct:1,explain_en:"Divided Highway Begins: yellow diamond with two arrows diverging (road splits into divided highway). Divided Highway Ends: arrows converging (road returns to undivided). Both are black on yellow diamonds.",explain_it:"Divided Highway Begins: rombo giallo con due frecce che divergono. Divided Highway Ends: frecce convergenti. Entrambi sono neri su rombi gialli."},
  {cat:"signs",en:"What does a fluorescent orange sign typically indicate?",it:"Cosa indica tipicamente un segnale arancione fluorescente?",options:[{en:"A scenic area",it:"Un'area panoramica"},{en:"A temporary traffic control device or work zone sign -- requires reduced speed and heightened caution",it:"Un dispositivo temporaneo di controllo del traffico o segnale di zona di lavoro -- richiede velocita ridotta e maggiore cautela"},{en:"A permanent road hazard",it:"Un pericolo stradale permanente"},{en:"A tourist attraction nearby",it:"Un'attrazione turistica nelle vicinanze"}],correct:1,explain_en:"Orange is the color of temporary traffic control. Orange signs in work zones are legally enforceable with doubled fines. They indicate construction activity, detours, or temporary speed limits.",explain_it:"L'arancione e il colore del controllo temporaneo del traffico. I segnali arancioni nelle zone di lavoro sono legalmente applicabili con multe raddoppiate."},
  {cat:"signs",en:"What does a circular sign with a red border generally indicate in international road sign conventions?",it:"Cosa indica generalmente un segnale circolare con bordo rosso nelle convenzioni internazionali dei segnali stradali?",options:[{en:"A warning of a hazard ahead",it:"Un avvertimento di un pericolo in avanti"},{en:"A prohibition or restriction -- you must not do what is shown",it:"Un divieto o restrizione -- non devi fare quello che e mostrato"},{en:"A required action",it:"Un'azione obbligatoria"},{en:"An informational sign",it:"Un segnale informativo"}],correct:1,explain_en:"In international conventions (used in Europe and most of the world): circular signs with red borders are prohibitory (No Entry, No Parking, Speed Limit, No U-Turn). The U.S. uses some of these formats.",explain_it:"Nelle convenzioni internazionali: i segnali circolari con bordi rossi sono proibitivi (No Entry, No Parking, Limite di Velocita, No U-Turn)."},
  {cat:"signs",en:"What does 'SPEED LIMIT 35 NIGHT' indicate?",it:"Cosa indica 'SPEED LIMIT 35 NIGHT'?",options:[{en:"Maximum speed is 35 mph for the next 35 minutes",it:"La velocita massima e 35 mph per i prossimi 35 minuti"},{en:"A lower speed limit applies during nighttime hours due to reduced visibility or pedestrian activity",it:"Si applica un limite di velocita piu basso durante le ore notturne a causa della visibilita ridotta o dell'attivita pedonale"},{en:"Daytime speed is unlimited",it:"La velocita diurna e illimitata"},{en:"Advisory only at night",it:"Solo advisory di notte"}],correct:1,explain_en:"Night speed limits are lower legally enforceable limits that apply only during nighttime hours -- typically near resorts, entertainment districts, or areas with night pedestrian activity.",explain_it:"I limiti di velocita notturni sono limiti legalmente applicabili piu bassi che si applicano solo durante le ore notturne."},
  {cat:"signs",en:"What does a 'No Parking Between Signs' indication (two signs with arrows pointing toward each other) mean?",it:"Cosa significa un'indicazione 'No Parking Between Signs' (due segnali con frecce che si puntano l'una verso l'altra)?",options:[{en:"No parking at either sign location",it:"Nessun parcheggio in nessuna delle due posizioni dei segnali"},{en:"No parking in the entire zone between the two signs",it:"Nessun parcheggio nell'intera zona tra i due segnali"},{en:"Parking permitted only between the signs",it:"Parcheggio consentito solo tra i segnali"},{en:"No parking on alternating days between signs",it:"Nessun parcheggio nei giorni alterni tra i segnali"}],correct:1,explain_en:"When two No Parking signs face each other with arrows, no parking is permitted in the entire stretch of road between them -- the prohibition covers the whole zone, not just the sign locations.",explain_it:"Quando due segnali No Parking si affrontano con frecce, nessun parcheggio e consentito in tutto il tratto di strada tra loro."},
  {cat:"laws",en:"What is the Florida law on the speed limit near schools during non-school hours?",it:"Qual e la legge Florida sul limite di velocita vicino alle scuole durante le ore non scolastiche?",options:[{en:"15 mph at all times near schools",it:"15 mph in ogni momento vicino alle scuole"},{en:"Normal posted speed limit when no school zone warning lights are flashing and no children are present",it:"Normale limite di velocita segnalato quando le luci di avvertimento della zona scolastica non lampeggiano e nessun bambino e presente"},{en:"25 mph during all weekday hours",it:"25 mph durante tutte le ore feriali"},{en:"School zone limits apply 24 hours a day, 7 days a week",it:"I limiti della zona scolastica si applicano 24 ore su 24, 7 giorni su 7"}],correct:1,explain_en:"Florida school zone limits apply ONLY when: (1) warning lights are flashing, OR (2) children are present. At other times, the normal road speed limit applies.",explain_it:"I limiti della zona scolastica Florida si applicano SOLO quando: (1) le luci di avvertimento lampeggiano, O (2) i bambini sono presenti. Negli altri momenti, si applica il normale limite di velocita."},
  {cat:"laws",en:"What is the Florida law about driving on a road marked with a 'Dead End' sign?",it:"Qual e la legge Florida sulla guida su una strada contrassegnata con un segnale 'Dead End'?",options:[{en:"Prohibited -- dead end roads are for residents only",it:"Vietato -- le strade senza uscita sono solo per i residenti"},{en:"Legal to enter but you must be able to turn around safely -- there is no through road",it:"Legale entrare ma devi essere in grado di girare in sicurezza -- non c'e strada di transito"},{en:"Only emergency vehicles may use dead end roads",it:"Solo i veicoli di emergenza possono usare le strade senza uscita"},{en:"Dead end roads are always private property",it:"Le strade senza uscita sono sempre proprieta privata"}],correct:1,explain_en:"Dead end roads are public or private -- either way, there is no through connection. You must turn around. They are legal to enter but require planning for your exit.",explain_it:"Le strade senza uscita sono pubbliche o private -- in ogni caso, non c'e connessione di transito. Devi girare. Sono legali da entrare ma richiedono pianificazione per l'uscita."},
  {cat:"laws",en:"What is the Florida law on honking when passing another vehicle?",it:"Qual e la legge Florida sul suonare il clacson quando si supera un altro veicolo?",options:[{en:"Required before passing on a two-lane road",it:"Obbligatorio prima di sorpassare su una strada a due corsie"},{en:"Not required -- horn is for safety warnings, not passing notifications",it:"Non obbligatorio -- il clacson e per gli avvertimenti di sicurezza, non per le notifiche di sorpasso"},{en:"Required at night when passing",it:"Obbligatorio di notte quando si supera"},{en:"Prohibited while passing to avoid startling the other driver",it:"Vietato durante il sorpasso per evitare di spaventare l'altro conducente"}],correct:1,explain_en:"Florida does not require honking when passing. The horn should be used only when necessary to give a safety warning. Unnecessary horn use is prohibited in many areas.",explain_it:"La Florida non richiede di suonare il clacson quando si sorpassa. Il clacson dovrebbe essere usato solo quando necessario per dare un avvertimento di sicurezza."},
  {cat:"laws",en:"What is the Florida law about the proper disposal of used motor oil?",it:"Qual e la legge Florida sullo smaltimento corretto dell'olio motore usato?",options:[{en:"May be poured down storm drains",it:"Puo essere versato negli scarichi pluviali"},{en:"Must be recycled or brought to a designated disposal facility -- dumping is illegal",it:"Deve essere riciclato o portato a una struttura di smaltimento designata -- lo smaltimento abusivo e illegale"},{en:"May be used as a dust suppressant on dirt roads",it:"Puo essere usato come soppressore di polvere sulle strade sterrate"},{en:"No regulation on used oil disposal",it:"Nessun regolamento sullo smaltimento dell'olio usato"}],correct:1,explain_en:"Improper disposal of used motor oil is illegal in Florida. One quart can contaminate one million gallons of groundwater. Bring it to auto parts stores, service stations, or recycling centers.",explain_it:"Lo smaltimento improprio dell'olio motore usato e illegale in Florida. Un quarto di gallone puo contaminare un milione di galloni di acque sotterranee."},
  {cat:"laws",en:"What is the Florida law on minimum headlight distance (how far they must illuminate)?",it:"Qual e la legge Florida sulla distanza minima dei fari (quanto lontano devono illuminare)?",options:[{en:"100 feet at low beams, 200 at high",it:"100 piedi con anabbaglianti, 200 con abbaglianti"},{en:"Low beams: 150 feet; high beams: 500 feet",it:"Anabbaglianti: 150 piedi; Abbaglianti: 500 piedi"},{en:"200 feet for both",it:"200 piedi per entrambi"},{en:"50 feet low beams, 300 high beams",it:"50 piedi anabbaglianti, 300 abbaglianti"}],correct:1,explain_en:"Florida requires headlights to illuminate objects at least 150 feet ahead on low beams, 500 feet on high beams. If an oncoming vehicle is within 500 feet, switch to low beams.",explain_it:"La Florida richiede che i fari illuminino oggetti ad almeno 150 piedi con gli anabbaglianti, 500 piedi con gli abbaglianti. Se un veicolo in arrivo e entro 500 piedi, passare agli anabbaglianti."},
  {cat:"laws",en:"When must Florida drivers dim their headlights to low beams?",it:"Quando devono i conducenti Florida abbassare i fari agli anabbaglianti?",options:[{en:"Only when entering a city",it:"Solo quando si entra in una citta"},{en:"Within 500 feet of an oncoming vehicle and within 300 feet when following another vehicle",it:"Entro 500 piedi di un veicolo in arrivo e entro 300 piedi quando si segue un altro veicolo"},{en:"Any time another vehicle is visible",it:"Ogni volta che un altro veicolo e visibile"},{en:"Only in urban areas",it:"Solo nelle aree urbane"}],correct:1,explain_en:"Florida: dim high beams to low beams within 500 feet of oncoming traffic and within 300 feet when following another vehicle. High beams into a driver's mirrors can temporarily blind them.",explain_it:"Florida: abbassare gli abbaglianti agli anabbaglianti entro 500 piedi del traffico in arrivo e entro 300 piedi quando si segue un altro veicolo."},
  {cat:"laws",en:"What is Florida's law on attaching a trailer to a vehicle?",it:"Qual e la legge Florida sul collegamento di un rimorchio a un veicolo?",options:[{en:"No legal requirements for trailers",it:"Nessun requisito legale per i rimorchi"},{en:"Must be properly connected with safety chains, working lights, and properly functioning brakes on heavier trailers",it:"Deve essere collegato correttamente con catene di sicurezza, luci funzionanti e freni funzionanti correttamente sui rimorchi piu pesanti"},{en:"Only semi-trailers need safety chains",it:"Solo i semi-rimorchi necessitano di catene di sicurezza"},{en:"Trailers do not need brake lights",it:"I rimorchi non necessitano di luci di stop"}],correct:1,explain_en:"Florida trailer requirements: safety chains, all required lights (tail, brake, turn), and trailer brakes are required on trailers over a certain weight. The trailer must be properly registered and licensed.",explain_it:"Requisiti del rimorchio Florida: catene di sicurezza, tutte le luci richieste (coda, stop, svolta) e i freni del rimorchio sono richiesti sui rimorchi oltre un certo peso."},
  {cat:"laws",en:"What is the Florida law on vehicles that must yield when entering a street from private property?",it:"Qual e la legge Florida sui veicoli che devono cedere quando entrano in una strada da proprieta privata?",options:[{en:"Traffic on the street yields to entering vehicles",it:"Il traffico sulla strada cede ai veicoli in entrata"},{en:"The vehicle entering from private property must yield to all traffic and pedestrians on the street",it:"Il veicolo che entra da proprieta privata deve cedere a tutto il traffico e i pedoni sulla strada"},{en:"Right of way determined by vehicle size",it:"La precedenza e determinata dalla dimensione del veicolo"},{en:"First to arrive at the intersection has priority",it:"Chi arriva per primo all'incrocio ha la priorita"}],correct:1,explain_en:"Vehicles entering a public road from private property (driveway, parking lot, gas station) must yield to ALL pedestrians and ALL vehicles already on the public road.",explain_it:"I veicoli che entrano in una strada pubblica da proprieta privata devono cedere a TUTTI i pedoni e TUTTI i veicoli gia sulla strada pubblica."},
  {cat:"laws",en:"What is the Florida law about driving in reverse (backing up) on a public road?",it:"Qual e la legge Florida sulla guida in retromarcia (retromarcia) su una strada pubblica?",options:[{en:"Always legal for short distances",it:"Sempre legale per brevi distanze"},{en:"Allowed only as necessary for safety -- you may not reverse for a significant distance or use an entrance ramp as an exit",it:"Consentita solo se necessario per la sicurezza -- non puoi fare retromarcia per una distanza significativa o usare una rampa di accesso come uscita"},{en:"Prohibited on all public roads",it:"Vietata su tutte le strade pubbliche"},{en:"Legal only at speeds under 5 mph",it:"Legale solo a velocita inferiori a 5 mph"}],correct:1,explain_en:"Reversing is only permitted when necessary and safe. You cannot reverse for extended distances on public roads. Reversing on a limited-access highway or using a ramp the wrong way is always illegal.",explain_it:"La retromarcia e consentita solo quando necessaria e sicura. Non puoi fare retromarcia per distanze estese su strade pubbliche."},
  {cat:"laws",en:"What is Florida's law on truck access to residential areas?",it:"Qual e la legge Florida sull'accesso dei camion alle aree residenziali?",options:[{en:"Trucks may use any public road",it:"I camion possono usare qualsiasi strada pubblica"},{en:"Local ordinances may restrict trucks from residential streets -- trucks should follow designated truck routes",it:"Le ordinanze locali possono limitare i camion dalle strade residenziali -- i camion dovrebbero seguire i percorsi designati"},{en:"Only semi-trucks are restricted from residential areas",it:"Solo i semi-camion sono limitati dalle aree residenziali"},{en:"Trucks may use residential streets only between 9am and 5pm",it:"I camion possono usare le strade residenziali solo tra le 9 e le 17"}],correct:1,explain_en:"Florida allows local governments to restrict truck traffic on residential streets. Trucks should use designated truck routes where available and comply with local weight and time restrictions.",explain_it:"La Florida consente ai governi locali di limitare il traffico dei camion sulle strade residenziali. I camion dovrebbero usare i percorsi designati dove disponibili."},
  {cat:"laws",en:"What is the Florida law about the use of tow trucks on private property?",it:"Qual e la legge Florida sull'uso dei carri attrezzi su proprieta privata?",options:[{en:"Property owners can tow any vehicle at any time",it:"I proprietari di proprieta possono rimorchiare qualsiasi veicolo in qualsiasi momento"},{en:"Vehicles may be towed from private property if properly posted signs warn of unauthorized vehicle removal",it:"I veicoli possono essere rimossi dalla proprieta privata se i segnali correttamente affissi avvisano della rimozione dei veicoli non autorizzati"},{en:"Property owners must wait 24 hours before towing",it:"I proprietari di proprieta devono aspettare 24 ore prima di rimorchiare"},{en:"Only police can authorize towing from private property",it:"Solo la polizia puo autorizzare il rimorchio dalla proprieta privata"}],correct:1,explain_en:"Florida private property towing: legal if signs are posted meeting specific requirements (size, placement, tow company contact). The property owner must follow Florida Statute 715.07 or face penalties.",explain_it:"Rimorchio su proprieta privata Florida: legale se i segnali sono affissi soddisfacendo requisiti specifici. Il proprietario deve seguire lo Statuto Florida 715.07."},
  {cat:"laws",en:"What is the Florida law on vehicle insurance when driving another person's car?",it:"Qual e la legge Florida sull'assicurazione del veicolo quando si guida l'auto di un'altra persona?",options:[{en:"Your own insurance always follows you as the driver",it:"La tua assicurazione ti segue sempre come conducente"},{en:"In Florida, insurance follows the vehicle -- the car owner's insurance is primary",it:"In Florida, l'assicurazione segue il veicolo -- l'assicurazione del proprietario dell'auto e primaria"},{en:"Both policies share equal responsibility",it:"Entrambe le polizze condividono uguale responsabilita"},{en:"Neither policy covers accidents in a borrowed car",it:"Nessuna delle due polizze copre gli incidenti in un'auto in prestito"}],correct:1,explain_en:"In Florida, insurance follows the vehicle (not the driver). If you borrow someone's car and crash, their insurance is primary. Your own insurance may serve as secondary coverage.",explain_it:"In Florida, l'assicurazione segue il veicolo (non il conducente). Se prendi in prestito l'auto di qualcuno e hai un incidente, la loro assicurazione e primaria."},
  {cat:"laws",en:"What is the proper action when a police officer directs you to do something different from what a traffic sign requires?",it:"Qual e l'azione corretta quando un agente di polizia ti dice di fare qualcosa di diverso da quello che richiede un segnale stradale?",options:[{en:"Follow the traffic sign -- it is the law",it:"Seguire il segnale stradale -- e la legge"},{en:"Obey the officer -- a police officer's directions override traffic signs and signals",it:"Obbedire all'agente -- le indicazioni di un agente di polizia sovrascrivono i segnali stradali"},{en:"Stop and wait for clarification",it:"Fermarsi e aspettare chiarimenti"},{en:"Follow whichever is safer in your judgment",it:"Seguire quello che e piu sicuro a tuo giudizio"}],correct:1,explain_en:"Police officers directing traffic have authority that overrides traffic signs and signals. Always obey a police officer's hand signals or instructions, even if they contradict posted signs.",explain_it:"Gli agenti di polizia che dirigono il traffico hanno un'autorit\u00e0 che sovrascrive i segnali stradali. Obbedire sempre alle indicazioni di un agente di polizia, anche se contraddicono i segnali affissi."},
  {cat:"laws",en:"What is the Florida law on parking within 15 feet of a fire station driveway?",it:"Qual e la legge Florida sul parcheggio entro 15 piedi dal vialetto di una caserma dei pompieri?",options:[{en:"Legal if the fire station appears closed",it:"Legale se la caserma dei pompieri sembra chiusa"},{en:"No parking within 15 feet of a fire station driveway on the same side of the road",it:"Nessun parcheggio entro 15 piedi dal vialetto di una caserma dei pompieri sullo stesso lato della strada"},{en:"No restriction near fire stations",it:"Nessuna restrizione vicino alle caserme dei pompieri"},{en:"Only restricted when emergency vehicles are present",it:"Solo limitato quando sono presenti veicoli di emergenza"}],correct:1,explain_en:"Florida prohibits parking within 15 feet of a fire station driveway entrance on the same side of the road. This ensures rapid emergency vehicle exit.",explain_it:"La Florida vieta il parcheggio entro 15 piedi dall'ingresso del vialetto di una caserma dei pompieri sullo stesso lato della strada."},
  {cat:"laws",en:"What is Florida's law regarding vehicle modifications that affect safety equipment?",it:"Qual e la legge Florida riguardo alle modifiche dei veicoli che influiscono sulle attrezzature di sicurezza?",options:[{en:"Any modification is legal with owner's consent",it:"Qualsiasi modifica e legale con il consenso del proprietario"},{en:"Modifications that disable or circumvent required safety equipment (airbags, seatbelts, required lights) are illegal",it:"Le modifiche che disabilitano o aggirano le attrezzature di sicurezza richieste (airbag, cinture di sicurezza, luci richieste) sono illegali"},{en:"Safety equipment modifications only illegal for vehicles under warranty",it:"Le modifiche alle attrezzature di sicurezza sono illegali solo per i veicoli in garanzia"},{en:"Only federal law applies to vehicle modifications",it:"Solo la legge federale si applica alle modifiche dei veicoli"}],correct:1,explain_en:"Disabling safety equipment (airbags, seatbelts, headlights, brake lights) is illegal. Vehicles must meet federal and state safety standards. Equipment violations can result in citations.",explain_it:"Disabilitare le attrezzature di sicurezza (airbag, cinture, fari, luci di stop) e illegale. I veicoli devono soddisfare gli standard di sicurezza federali e statali."},
  {cat:"laws",en:"What is the Florida law on maximum speed in an unposted business district?",it:"Qual e la legge Florida sulla velocita massima in un distretto commerciale senza segnaletica?",options:[{en:"35 mph",it:"35 mph"},{en:"30 mph",it:"30 mph"},{en:"25 mph",it:"25 mph"},{en:"45 mph",it:"45 mph"}],correct:1,explain_en:"Florida's default speed limit in an unposted business or residential district is 30 mph. Posted signs may set different limits. On limited-access highways the limit is higher.",explain_it:"Il limite di velocita predefinito della Florida in un distretto commerciale o residenziale senza segnaletica e 30 mph."},
  {cat:"laws",en:"What is the Florida law about driving while fatigued?",it:"Qual e la legge Florida sulla guida in stato di stanchezza?",options:[{en:"No law against fatigued driving",it:"Nessuna legge contro la guida stanca"},{en:"Driving while fatigued to the point of impairment can result in reckless or careless driving charges",it:"Guidare in stato di stanchezza al punto di compromissione puo comportare accuse di guida spericolata o imprudente"},{en:"Only applicable to commercial drivers",it:"Applicabile solo ai conducenti commerciali"},{en:"Legal if the driver feels they can manage",it:"Legale se il conducente sente di poter gestire"}],correct:1,explain_en:"While Florida has no specific 'drowsy driving' law, severely fatigued drivers can be charged with reckless or careless driving -- especially if they cause a crash. Prevention is the best policy.",explain_it:"Sebbene la Florida non abbia una legge specifica sulla 'guida assonnata', i conducenti gravemente stanchi possono essere accusati di guida spericolata o imprudente."},
  {cat:"laws",en:"What is the Florida law on the use of studded chains on tires?",it:"Qual e la legge Florida sull'uso di catene con borchie sugli pneumatici?",options:[{en:"Legal whenever conditions warrant",it:"Legale ogni volta che le condizioni lo richiedono"},{en:"Metal chains and studded tires are prohibited in Florida as road conditions do not require them",it:"Le catene metalliche e i pneumatici con borchie sono vietati in Florida poiche le condizioni stradali non le richiedono"},{en:"Legal only for 4WD vehicles",it:"Legale solo per i veicoli 4WD"},{en:"Legal from December through February",it:"Legale da dicembre a febbraio"}],correct:1,explain_en:"Florida prohibits studded tires and metal tire chains on paved roads. Florida's climate does not require them, and they damage road surfaces.",explain_it:"La Florida vieta pneumatici con borchie e catene metalliche sulle strade asfaltate. Il clima Florida non le richiede e danneggiano le superfici stradali."},
  {cat:"laws",en:"What is the Florida law on cell phone use for drivers under 18?",it:"Qual e la legge Florida sull'uso del cellulare per i conducenti under 18?",options:[{en:"Same rules as adult drivers",it:"Le stesse regole dei conducenti adulti"},{en:"Learner's permit and restricted license holders under 18 may not use any wireless device while driving",it:"I titolari del permesso per principianti e della patente limitata under 18 non possono usare nessun dispositivo wireless durante la guida"},{en:"Hands-free only for under 18",it:"Solo mani libere per under 18"},{en:"Prohibited only in school zones",it:"Vietato solo nelle zone scolastiche"}],correct:1,explain_en:"Florida GDL: permit holders and restricted license holders under 18 are completely prohibited from using any wireless communications device while driving -- even hands-free.",explain_it:"GDL Florida: i titolari del permesso e della patente limitata under 18 sono completamente vietati dall'usare qualsiasi dispositivo di comunicazione wireless durante la guida."},
  {cat:"safety",en:"What is the proper following distance when driving in fog?",it:"Qual e la distanza di seguimento corretta quando si guida nella nebbia?",options:[{en:"2 seconds -- same as normal",it:"2 secondi -- uguale al normale"},{en:"Increase distance significantly -- use tail lights ahead to gauge distance and drive at a speed where you can stop in the visible distance",it:"Aumentare la distanza significativamente -- usare le luci posteriori davanti per valutare la distanza e guidare a una velocita dove puoi fermarti nella distanza visibile"},{en:"Drive closer to follow the tail lights ahead",it:"Guidare piu vicino per seguire le luci posteriori davanti"},{en:"Pull over and wait for fog to clear",it:"Accostare e aspettare che la nebbia si diradi"}],correct:1,explain_en:"In fog: increase following distance dramatically, use low beams or fog lights, reduce speed to match visibility (stop in the visible distance), and watch for stopped vehicles.",explain_it:"Nella nebbia: aumentare significativamente la distanza, usare anabbaglianti o fendinebbia, ridurre la velocita per corrispondere alla visibilita e fare attenzione ai veicoli fermi."},
  {cat:"safety",en:"What is the safest approach to an intersection with poor visibility due to parked vehicles?",it:"Qual e l'approccio piu sicuro a un incrocio con scarsa visibilita a causa di veicoli parcheggiati?",options:[{en:"Drive through quickly to minimize exposure time",it:"Attraversare velocemente per minimizzare il tempo di esposizione"},{en:"Slow significantly, creep into the intersection to gain visibility, and be prepared to stop",it:"Rallentare significativamente, avanzare lentamente nell'incrocio per guadagnare visibilita ed essere pronti a fermarsi"},{en:"Sound horn and proceed",it:"Suonare il clacson e procedere"},{en:"Only applicable at uncontrolled intersections",it:"Applicabile solo agli incroci non controllati"}],correct:1,explain_en:"At an intersection where parked vehicles block your sightlines: slow to a near-stop, ease forward slowly to gain visibility, and stop if cross-traffic appears. Never rush through a blind intersection.",explain_it:"A un incrocio dove i veicoli parcheggiati bloccano le linee visive: rallentare quasi a fermarsi, avanzare lentamente per guadagnare visibilita e fermarsi se appare traffico trasversale."},
  {cat:"safety",en:"What is the safest position for a driver's seat adjustment?",it:"Qual e la posizione piu sicura per la regolazione del sedile del conducente?",options:[{en:"As far back as possible from the steering wheel",it:"Il piu lontano possibile dal volante"},{en:"Close enough to reach all controls comfortably -- at least 10-12 inches from the steering wheel airbag",it:"Abbastanza vicino per raggiungere comodamente tutti i controlli -- almeno 10-12 pollici dall'airbag del volante"},{en:"Reclining is safest for long drives",it:"L'inclinazione e piu sicura per i viaggi lunghi"},{en:"Seat position doesn't affect safety",it:"La posizione del sedile non influisce sulla sicurezza"}],correct:1,explain_en:"Correct seat position: close enough to reach pedals/controls comfortably, but at least 10-12 inches from steering wheel (airbag deployment). Upright position (not reclined) for seatbelt effectiveness.",explain_it:"Posizione corretta del sedile: abbastanza vicino per raggiungere pedale/controlli comodamente, ma almeno 10-12 pollici dal volante. Posizione eretta (non reclinata) per l'efficacia della cintura."},
  {cat:"safety",en:"What is the correct action when you realize you are driving the wrong way on a one-way street?",it:"Qual e l'azione corretta quando ti rendi conto che stai guidando contromano su una strada a senso unico?",options:[{en:"Flash headlights and maintain lane",it:"Lampeggiare i fari e mantenere la corsia"},{en:"Stop safely, turn on hazard lights, back out carefully or turn around at the nearest opportunity",it:"Fermarsi in sicurezza, accendere le luci di pericolo, fare retromarcia con attenzione o girare alla prima opportunita"},{en:"Continue to the next intersection and turn",it:"Continuare all'incrocio successivo e svoltare"},{en:"Pull to the right lane and proceed slowly",it:"Spostarsi nella corsia destra e procedere lentamente"}],correct:1,explain_en:"Wrong way on one-way street: stop immediately, activate hazard lights, then carefully reverse or make a U-turn when safe. Do not continue driving the wrong way -- risk of head-on collision.",explain_it:"Contromano su strada a senso unico: fermarsi immediatamente, attivare le luci di pericolo, poi fare retromarcia o un'inversione con cautela quando sicuro."},
  {cat:"safety",en:"What is the proper way to stop for a railroad crossing when required?",it:"Qual e il modo corretto di fermarsi a un passaggio a livello quando richiesto?",options:[{en:"Stop with your front bumper on the tracks",it:"Fermarsi con il paraurti anteriore sui binari"},{en:"Stop at least 15 feet from the nearest rail -- never stop on the tracks",it:"Fermarsi ad almeno 15 piedi dal binario piu vicino -- non fermarsi mai sui binari"},{en:"Stop alongside the crossing gates",it:"Fermarsi accanto alle sbarre del passaggio"},{en:"Stop 5 feet from the gate arm",it:"Fermarsi a 5 piedi dal braccio della sbarra"}],correct:1,explain_en:"At a railroad crossing stop: stop at least 15 feet from the nearest rail. Never stop on the tracks -- a stuck vehicle is extremely dangerous. Wait until the train completely passes before proceeding.",explain_it:"Alla fermata del passaggio a livello: fermarsi ad almeno 15 piedi dal binario piu vicino. Non fermarsi mai sui binari -- un veicolo bloccato e estremamente pericoloso."},
  {cat:"safety",en:"What is the Florida law on wearing a seatbelt for rear-seat passengers over 18?",it:"Qual e la legge Florida sull'indossare la cintura di sicurezza per i passeggeri del sedile posteriore over 18?",options:[{en:"Always required",it:"Sempre obbligatorio"},{en:"Required under secondary enforcement -- police can cite for it only if stopped for another violation",it:"Richiesto nell'ambito dell'applicazione secondaria -- la polizia puo multare per questo solo se fermati per un'altra violazione"},{en:"Not required for adults in the back seat",it:"Non richiesto per gli adulti nel sedile posteriore"},{en:"Required only on highways",it:"Richiesto solo in autostrada"}],correct:1,explain_en:"Florida seatbelt: front seat passengers 18+ have primary enforcement (can be stopped just for not buckling). Rear seat adults 18+: secondary enforcement (cited only if stopped for another reason).",explain_it:"Cintura Florida: i passeggeri del sedile anteriore 18+ hanno applicazione primaria. Gli adulti del sedile posteriore 18+: applicazione secondaria (citati solo se fermati per un altro motivo)."},
  {cat:"safety",en:"What is the safest way to approach a blind intersection (no sightlines)?",it:"Qual e il modo piu sicuro per avvicinarsi a un incrocio cieco (nessuna linea visiva)?",options:[{en:"Accelerate through to minimize exposure time",it:"Accelerare attraverso per minimizzare il tempo di esposizione"},{en:"Come to a full stop, edge forward to gain visibility, look both ways carefully, then proceed when clear",it:"Fermarsi completamente, avanzare lentamente per guadagnare visibilita, guardare attentamente in entrambe le direzioni, poi procedere quando libero"},{en:"Sound horn repeatedly before entering",it:"Suonare ripetutamente il clacson prima di entrare"},{en:"Only stop if a sign requires it",it:"Fermarsi solo se un segnale lo richiede"}],correct:1,explain_en:"Blind intersection: full stop, slowly inch forward past obstructions to gain sightlines, check both ways thoroughly, and proceed only when you can verify it is clear.",explain_it:"Incrocio cieco: arresto completo, avanzare lentamente oltre gli ostacoli per guadagnare linee visive, controllare attentamente in entrambe le direzioni e procedere solo quando puoi verificare che sia libero."},
  {cat:"safety",en:"What is the Florida law on the minimum distance to pass a bicycle?",it:"Qual e la legge Florida sulla distanza minima per superare una bicicletta?",options:[{en:"1 foot minimum",it:"Minimo 1 piede"},{en:"3 feet minimum clearance between the vehicle and the bicycle",it:"Minimo 3 piedi di spazio tra il veicolo e la bicicletta"},{en:"5 feet minimum",it:"Minimo 5 piedi"},{en:"Same as passing any vehicle",it:"Uguale al sorpasso di qualsiasi veicolo"}],correct:1,explain_en:"Florida's 3-foot law: when passing a cyclist, motor vehicles must maintain at least 3 feet of clearance. If the lane is too narrow, the driver must change lanes or wait for a safe opportunity to pass.",explain_it:"Legge dei 3 piedi Florida: quando si supera un ciclista, i veicoli a motore devono mantenere almeno 3 piedi di spazio. Se la corsia e troppo stretta, il conducente deve cambiare corsia."},
  {cat:"safety",en:"What is the Florida requirement for school bus emergency exits?",it:"Qual e il requisito Florida per le uscite di emergenza degli scuolabus?",options:[{en:"Not regulated -- varies by manufacturer",it:"Non regolamentato -- varia per produttore"},{en:"Required to be clearly marked, operable, and not blocked -- students must know how to use them",it:"Devono essere chiaramente segnalate, funzionanti e non bloccate -- gli studenti devono sapere come usarle"},{en:"Only rear doors are required as emergency exits",it:"Solo le porte posteriori sono richieste come uscite di emergenza"},{en:"Emergency exits only required on buses over 40 passengers",it:"Uscite di emergenza richieste solo sui bus con piu di 40 passeggeri"}],correct:1,explain_en:"School buses must have functioning emergency exits (rear door, roof hatch, window exits). They must be clearly marked, not blocked, and students must receive training on their use.",explain_it:"Gli scuolabus devono avere uscite di emergenza funzionanti (porta posteriore, portello sul tetto, uscite dai finestrini). Devono essere chiaramente segnalate e gli studenti devono ricevere formazione sul loro utilizzo."},
  {cat:"safety",en:"What is the safest action when another driver is following you too closely (tailgating)?",it:"Qual e l'azione piu sicura quando un altro conducente ti segue troppo da vicino (tailgating)?",options:[{en:"Brake hard to force them to back off",it:"Frenare forte per costringerli a retrocedere"},{en:"Move to the right and let them pass -- do not engage with the tailgater",it:"Spostarsi a destra e lasciarli passare -- non interagire con chi ti segue troppo da vicino"},{en:"Speed up to create more distance",it:"Accelerare per creare piu distanza"},{en:"Flash your brake lights to warn them",it:"Lampeggiare le luci di stop per avvisarli"}],correct:1,explain_en:"When tailgated: don't brake check, don't speed up. Move right and let them pass. Increase your own following distance to create more stopping room. Don't engage with aggressive drivers.",explain_it:"Quando sei tallonato: non frenare bruscamente, non accelerare. Spostati a destra e lasciali passare. Aumenta la tua distanza di seguimento per creare piu spazio di frenata."},
  {cat:"alcohol",en:"What is the approximate BAC after 2 standard drinks in 1 hour for a 150-lb person?",it:"Qual e il BAC approssimativo dopo 2 drink standard in 1 ora per una persona di 150 libbre?",options:[{en:"0.00%",it:"0,00%"},{en:"Approximately 0.04-0.05%",it:"Circa 0,04-0,05%"},{en:"0.08% or above",it:"0,08% o superiore"},{en:"0.01%",it:"0,01%"}],correct:1,explain_en:"For a 150-lb person: 2 drinks in 1 hour yields roughly 0.04-0.05% BAC after liver processing begins. This is below 0.08% but already causes measurable impairment of judgment and reaction time.",explain_it:"Per una persona di 150 libbre: 2 drink in 1 ora producono circa 0,04-0,05% BAC dopo l'inizio dell'elaborazione epatica. Questo e sotto 0,08% ma causa gia una compromissione misurabile."},
  {cat:"alcohol",en:"What is the Florida law on alcohol sales hours?",it:"Qual e la legge Florida sugli orari di vendita dell'alcol?",options:[{en:"24 hours a day statewide",it:"24 ore al giorno in tutto lo stato"},{en:"Set by each county -- no uniform statewide hours; typically 7am to 2am but varies",it:"Stabilito da ogni contea -- nessun orario uniforme statale; tipicamente dalle 7 alle 2, ma varia"},{en:"Only between noon and midnight everywhere",it:"Solo tra mezzogiorno e mezzanotte ovunque"},{en:"No restrictions on alcohol sales hours",it:"Nessuna restrizione sugli orari di vendita dell'alcol"}],correct:1,explain_en:"Florida alcohol sales hours are determined by counties and municipalities. Common hours are 7am-2am but some areas allow 24-hour sales (e.g., Key West). Local ordinances control the specifics.",explain_it:"Gli orari di vendita dell'alcol in Florida sono determinati dalle contee e dai comuni. Gli orari comuni sono dalle 7 alle 2, ma alcune aree consentono vendite 24 ore su 24."},
  {cat:"alcohol",en:"What is the effect of alcohol on coordination and fine motor skills?",it:"Qual e l'effetto dell'alcol sulla coordinazione e le abilita motorie fini?",options:[{en:"Improves fluid coordination",it:"Migliora la coordinazione fluida"},{en:"Impairs fine motor control needed for steering, braking, and accelerating smoothly",it:"Compromette il controllo motorio fine necessario per sterzare, frenare e accelerare fluidamente"},{en:"Only affects gross motor skills like walking",it:"Influisce solo sulle abilita motorie grossolane come camminare"},{en:"No effect on motor control until 0.15% BAC",it:"Nessun effetto sul controllo motorio fino a 0,15% BAC"}],correct:1,explain_en:"Alcohol impairs fine motor control starting at the first drink. Smooth steering inputs, precise braking, and clutch/throttle coordination all degrade. This is why driving is so dangerous when impaired.",explain_it:"L'alcol compromette il controllo motorio fine dal primo drink. Gli input di sterzo fluidi, la frenata precisa e la coordinazione frizione/acceleratore si degradano tutti."},
  {cat:"alcohol",en:"What is the Florida law on consuming alcohol while driving?",it:"Qual e la legge Florida sul consumo di alcol durante la guida?",options:[{en:"Legal for drivers over 21 in small amounts",it:"Legale per i conducenti over 21 in piccole quantita"},{en:"Illegal -- consuming alcohol while operating a vehicle is always prohibited",it:"Illegale -- consumare alcol durante la guida di un veicolo e sempre vietato"},{en:"Legal if the BAC stays below 0.08%",it:"Legale se il BAC rimane sotto 0,08%"},{en:"Only illegal in school zones",it:"Illegale solo nelle zone scolastiche"}],correct:1,explain_en:"Consuming alcohol while driving is always illegal in Florida -- regardless of the amount or resulting BAC. The open container law also prohibits alcohol in the passenger compartment.",explain_it:"Consumare alcol durante la guida e sempre illegale in Florida -- indipendentemente dalla quantita o dal BAC risultante."},
  {cat:"alcohol",en:"What is 'impaired driving' vs 'drunk driving' under Florida law?",it:"Qual e la differenza tra 'guida compromessa' e 'guida ubriaca' secondo la legge Florida?",options:[{en:"They are identical terms",it:"Sono termini identici"},{en:"Drunk driving implies BAC 0.08%+; impaired driving includes any level of impairment from any substance affecting normal faculties",it:"Guida ubriaca implica BAC 0,08%+; guida compromessa include qualsiasi livello di compromissione da qualsiasi sostanza che influisce sulle normali facolta"},{en:"Impaired driving is always a less serious charge",it:"La guida compromessa e sempre un'accusa meno grave"},{en:"Only prescription drugs cause 'impaired driving'; alcohol causes 'drunk driving'",it:"Solo i farmaci da prescrizione causano 'guida compromessa'; l'alcol causa 'guida ubriaca'"}],correct:1,explain_en:"Florida DUI covers BOTH: (1) per se DUI (BAC 0.08%+) and (2) impaired DUI (driving with normal faculties impaired by any substance -- alcohol, prescription drugs, illegal drugs, or combination).",explain_it:"Il DUI Florida copre ENTRAMBI: (1) DUI per se (BAC 0,08%+) e (2) DUI compromesso (guidare con le normali facolta compromesse da qualsiasi sostanza -- alcol, farmaci, droghe illegali o combinazione)."},
  {cat:"alcohol",en:"What is the relationship between number of drinks and BAC for two people of the same weight but different genders?",it:"Qual e la relazione tra numero di drink e BAC per due persone dello stesso peso ma di genere diverso?",options:[{en:"BAC will be identical",it:"Il BAC sara identico"},{en:"The female will generally have a higher BAC than the male from the same drinks",it:"La femmina avra generalmente un BAC piu alto del maschio dagli stessi drink"},{en:"The male will have a higher BAC",it:"Il maschio avra un BAC piu alto"},{en:"Gender has no effect if weight is equal",it:"Il genere non ha effetto se il peso e uguale"}],correct:1,explain_en:"Equal weight, same drinks: women typically have higher BAC due to lower total body water percentage and less alcohol dehydrogenase enzyme. At the same weight, women experience more impairment per drink.",explain_it:"Stesso peso, stessi drink: le donne hanno tipicamente un BAC piu alto a causa della minore percentuale di acqua corporea totale e della minore alcol deidrogenasi."},
  {cat:"alcohol",en:"What is the Florida law about alcohol and minors in a vehicle?",it:"Qual e la legge Florida sull'alcol e i minori in un veicolo?",options:[{en:"Alcohol is only prohibited if the minor is drinking",it:"L'alcol e vietato solo se il minore beve"},{en:"It is illegal to transport a minor while impaired by alcohol -- enhances DUI penalties",it:"E illegale trasportare un minore mentre si e sotto l'influenza dell'alcol -- aumenta le sanzioni DUI"},{en:"Only applies if the minor is under 6",it:"Si applica solo se il minore ha meno di 6 anni"},{en:"No special law for minors in vehicles with alcohol",it:"Nessuna legge speciale per i minori nei veicoli con alcol"}],correct:1,explain_en:"DUI with a minor passenger in Florida triggers mandatory enhancements: higher fines ($1,000-$2,000), mandatory IID, and possible child neglect/abuse charges in addition to standard DUI penalties.",explain_it:"DUI con un passeggero minore in Florida attiva aggravamenti obbligatori: multe piu alte ($1.000-$2.000), IID obbligatorio e possibili accuse di abbandono/abuso di minori."},
  {cat:"alcohol",en:"How many points on the BAC scale equal one standard drink consumed per hour?",it:"Quanti punti sulla scala BAC corrispondono a un drink standard consumato all'ora?",options:[{en:"0.08% per drink",it:"0,08% per drink"},{en:"Approximately 0.015% per drink per hour -- but this varies significantly by weight, gender, and metabolism",it:"Circa 0,015% per drink all'ora -- ma questo varia significativamente per peso, genere e metabolismo"},{en:"Exactly 0.02% per drink",it:"Esattamente 0,02% per drink"},{en:"0.03% per drink regardless of weight",it:"0,03% per drink indipendentemente dal peso"}],correct:1,explain_en:"A rough average: BAC increases approximately 0.015-0.025% per standard drink, then decreases ~0.015% per hour as the liver processes it. Actual values vary widely by individual factors.",explain_it:"Una media approssimativa: il BAC aumenta di circa 0,015-0,025% per drink standard, poi diminuisce ~0,015% all'ora man mano che il fegato lo elabora. I valori reali variano ampiamente."},
  {cat:"alcohol",en:"What is the maximum allowable BAC for a school bus driver in Florida?",it:"Qual e il BAC massimo consentito per un conducente di scuolabus in Florida?",options:[{en:"0.08% -- same as regular drivers",it:"0,08% -- uguale ai conducenti regolari"},{en:"0.04% -- same as other CDL drivers",it:"0,04% -- uguale agli altri conducenti CDL"},{en:"0.02% -- stricter than regular CDL",it:"0,02% -- piu rigoroso del CDL normale"},{en:"0.00% -- zero tolerance",it:"0,00% -- zero tolleranza"}],correct:1,explain_en:"School bus drivers hold CDLs and are subject to the 0.04% CDL limit while driving. Pre-employment and random drug/alcohol testing is also required for school bus operators.",explain_it:"I conducenti di scuolabus hanno CDL e sono soggetti al limite CDL di 0,04% durante la guida. Sono richiesti anche test antidroga/alcol pre-assunzione e casuali."},
  {cat:"alcohol",en:"What does research show about the relationship between alcohol and crash risk?",it:"Cosa mostra la ricerca sulla relazione tra alcol e rischio di incidenti?",options:[{en:"Crash risk only increases above 0.08% BAC",it:"Il rischio di incidenti aumenta solo sopra 0,08% BAC"},{en:"Crash risk doubles at 0.05% BAC and is 7x higher at 0.08% compared to a sober driver",it:"Il rischio di incidenti raddoppia a 0,05% BAC ed e 7 volte piu alto a 0,08% rispetto a un conducente sobrio"},{en:"Alcohol actually improves alertness at low doses",it:"L'alcol migliora effettivamente la vigilanza a basse dosi"},{en:"Crash risk only increases for inexperienced drinkers",it:"Il rischio di incidenti aumenta solo per i bevitori inesperti"}],correct:1,explain_en:"Research shows: at 0.05% BAC crash risk is 2x sober; at 0.08% crash risk is approximately 7x sober; at 0.15% crash risk is 25x sober. There is NO safe BAC for driving.",explain_it:"La ricerca mostra: a 0,05% BAC il rischio di incidenti e 2 volte quello sobrio; a 0,08% e circa 7 volte; a 0,15% e 25 volte. NON c'e BAC sicuro per guidare."},
  {cat:"license",en:"What is the Florida law on the minimum age to drive a golf cart on public roads?",it:"Qual e la legge Florida sull'eta minima per guidare un golf cart sulle strade pubbliche?",options:[{en:"14 years old with parental supervision",it:"14 anni con supervisione dei genitori"},{en:"14 years old in designated areas; a valid driver's license needed to operate on streets with speed limits above 25 mph",it:"14 anni nelle aree designate; patente valida necessaria per operare su strade con limiti superiori a 25 mph"},{en:"18 years old",it:"18 anni"},{en:"No age restriction for golf carts",it:"Nessuna restrizione di eta per i golf cart"}],correct:1,explain_en:"Florida golf cart law: minimum age 14 in areas designated for golf cart use. On roads with posted speed limits above 25 mph, a valid driver's license is required regardless of age.",explain_it:"Legge golf cart Florida: eta minima 14 anni nelle aree designate per l'uso del golf cart. Sulle strade con limiti superiori a 25 mph, e richiesta una patente valida indipendentemente dall'eta."},
  {cat:"license",en:"What does a Florida 'E' restriction on a driver's license mean?",it:"Cosa significa una restrizione 'E' Florida su una patente?",options:[{en:"Emergency use only",it:"Solo uso di emergenza"},{en:"Must have corrective lenses (glasses or contacts) while driving",it:"Deve avere lenti correttive (occhiali o contatti) durante la guida"},{en:"Employment driving only",it:"Solo guida per lavoro"},{en:"Engine displacement limit",it:"Limite di cilindrata del motore"}],correct:1,explain_en:"An 'E' restriction on a Florida license means the driver must wear corrective lenses (glasses or contact lenses) at all times while driving. Driving without them is a violation.",explain_it:"Una restrizione 'E' su una patente Florida significa che il conducente deve indossare lenti correttive (occhiali o lenti a contatto) in ogni momento durante la guida."},
  {cat:"license",en:"What is the Florida law about supervising a learner's permit holder while using a cell phone?",it:"Qual e la legge Florida sulla supervisione di un titolare del permesso per principianti mentre si usa il cellulare?",options:[{en:"Supervisors may use phones while supervising",it:"I supervisori possono usare i telefoni durante la supervisione"},{en:"The supervising driver should not be distracted and should focus entirely on supervising the permit holder",it:"Il conducente supervisore non dovrebbe essere distratto e dovrebbe concentrarsi interamente sulla supervisione del titolare del permesso"},{en:"Only texting is prohibited for supervisors",it:"Solo l'invio di messaggi e vietato per i supervisori"},{en:"No restriction on supervisor phone use",it:"Nessuna restrizione sull'uso del telefono del supervisore"}],correct:1,explain_en:"While not explicitly prohibited, supervisors of permit holders should not use phones or be distracted -- they are legally responsible for the permit holder's safe operation of the vehicle.",explain_it:"Sebbene non sia esplicitamente vietato, i supervisori dei titolari del permesso non dovrebbero usare i telefoni o essere distratti -- sono legalmente responsabili del funzionamento sicuro del veicolo."},
  {cat:"license",en:"What is the Florida 'First Time Driver' (DATA) course?",it:"Cos'e il corso Florida 'First Time Driver' (DATA)?",options:[{en:"An optional advanced driving course",it:"Un corso avanzato di guida opzionale"},{en:"A mandatory 4-hour course covering traffic law and substance abuse required before first-time applicants 18+ get a license",it:"Un corso obbligatorio di 4 ore su leggi del traffico e abuso di sostanze richiesto prima che i richiedenti per la prima volta 18+ ottengano la patente"},{en:"A defensive driving course for license renewal",it:"Un corso di guida difensiva per il rinnovo della patente"},{en:"Required only after a DUI conviction",it:"Richiesto solo dopo una condanna DUI"}],correct:1,explain_en:"DATA (Drug Awareness and Traffic Awareness) / TLSAE: mandatory 4-hour online or in-person course for all first-time license applicants age 18+. Covers traffic laws and dangers of substance-impaired driving.",explain_it:"DATA/TLSAE: corso obbligatorio di 4 ore per tutti i richiedenti la prima patente di 18+ anni. Copre le leggi del traffico e i pericoli della guida sotto l'influenza di sostanze."},
  {cat:"license",en:"What is the Florida law about obtaining a license after a medical condition that caused a license surrender?",it:"Qual e la legge Florida sull'ottenimento della patente dopo una condizione medica che ha causato la restituzione della patente?",options:[{en:"Must start the process from scratch including written test",it:"Deve ricominciare il processo da zero incluso il test scritto"},{en:"Must provide medical clearance from a physician and FLHSMV medical review may require examination or driving test",it:"Deve fornire l'autorizzazione medica di un medico e la revisione medica FLHSMV puo richiedere una visita o un test di guida"},{en:"Automatic reinstatement after 6 months",it:"Reintegro automatico dopo 6 mesi"},{en:"Medical conditions permanently bar re-licensure",it:"Le condizioni mediche vietano permanentemente il rilicenziamento"}],correct:1,explain_en:"After a medical surrender: provide physician clearance and FLHSMV medical review. Depending on the condition, FLHSMV may require additional medical exams or a behind-the-wheel evaluation before reinstating.",explain_it:"Dopo una restituzione medica: fornire l'autorizzazione del medico e la revisione medica FLHSMV. A seconda della condizione, FLHSMV puo richiedere ulteriori esami medici o una valutazione alla guida."},
  {cat:"license",en:"What is the Florida law on operating an electric bicycle (e-bike)?",it:"Qual e la legge Florida sull'operazione di una bicicletta elettrica (e-bike)?",options:[{en:"Requires a driver's license and registration",it:"Richiede una patente e una registrazione"},{en:"Class 1 and Class 2 e-bikes (under 20 mph assist) do not require a license, registration, or insurance",it:"Le e-bike di Classe 1 e Classe 2 (assistenza sotto 20 mph) non richiedono patente, registrazione o assicurazione"},{en:"Must be registered like a motorcycle",it:"Deve essere registrata come una moto"},{en:"Only Class 1 e-bikes permitted on bike lanes",it:"Solo le e-bike di Classe 1 sono consentite nelle corsie ciclabili"}],correct:1,explain_en:"Florida e-bike law: Class 1 (pedal assist up to 20mph) and Class 2 (throttle up to 20mph) e-bikes are treated like regular bicycles -- no license, registration, or insurance required. Riders under 16 must wear helmets.",explain_it:"Legge e-bike Florida: le e-bike di Classe 1 (assistenza al pedale fino a 20 mph) e Classe 2 (acceleratore fino a 20 mph) sono trattate come biciclette regolari -- nessuna patente, registrazione o assicurazione richiesta."},
  {cat:"license",en:"What is the Florida law about the 'Restricted' license curfew during the second 12 months?",it:"Qual e la legge Florida sul coprifuoco della patente 'limitata' durante i secondi 12 mesi?",options:[{en:"No curfew in second 12 months",it:"Nessun coprifuoco nei secondi 12 mesi"},{en:"Curfew extends to 1am in the second year (vs midnight in the first)",it:"Il coprifuoco si estende all'1 nei secondi 12 mesi (vs mezzanotte nel primo)"},{en:"No change -- same 11pm curfew continues",it:"Nessun cambiamento -- lo stesso coprifuoco delle 23 continua"},{en:"Curfew is completely removed after 12 months",it:"Il coprifuoco viene completamente rimosso dopo 12 mesi"}],correct:0,explain_en:"Florida GDL: during both the first and second 12-month periods, the nighttime curfew is 11pm-6am. The passenger restriction (1 non-household under 18) lifts after the first 12 months.",explain_it:"GDL Florida: durante entrambi i primi e secondi periodi di 12 mesi, il coprifuoco notturno e 23:00-6:00. La restrizione per i passeggeri (1 non convivente under 18) si toglie dopo i primi 12 mesi."},
  {cat:"license",en:"What is the Florida 'E-Ticket' system?",it:"Cos'e il sistema Florida 'E-Ticket'?",options:[{en:"Online ticket purchasing for events",it:"Acquisto di biglietti online per eventi"},{en:"Electronic traffic citations issued by law enforcement -- eliminating paper tickets",it:"Citazioni del traffico elettroniche emesse dalle forze dell'ordine -- eliminando i biglietti cartacei"},{en:"Online vehicle registration renewal system",it:"Sistema di rinnovo online della registrazione del veicolo"},{en:"Electronic license plates",it:"Targhe elettroniche"}],correct:1,explain_en:"Florida's e-Ticket system allows law enforcement to issue electronic traffic citations. The ticket is transmitted to the court electronically and mailed to the violator's registered address.",explain_it:"Il sistema e-Ticket della Florida consente alle forze dell'ordine di emettere citazioni del traffico elettroniche. La citazione viene trasmessa elettronicamente al tribunale."},
  {cat:"license",en:"What is the Florida law on renewing a driver's license by mail or online?",it:"Qual e la legge Florida sul rinnovo della patente per posta o online?",options:[{en:"Must always renew in person",it:"Deve sempre rinnovare di persona"},{en:"Online and mail renewals are permitted for eligible drivers -- those without address changes and meeting vision requirements",it:"I rinnovi online e per posta sono consentiti per i conducenti idonei -- quelli senza cambiamenti di indirizzo e che soddisfano i requisiti visivi"},{en:"Mail renewals only for drivers over 65",it:"Rinnovi per posta solo per i conducenti over 65"},{en:"Online renewal available but in-person vision test still required",it:"Rinnovo online disponibile ma il test della visione di persona e ancora richiesto"}],correct:1,explain_en:"Florida allows online and mail license renewals for eligible drivers (no required in-person vision test change, no address update needed, etc.). Drivers over 79 must renew in person.",explain_it:"La Florida consente i rinnovi della patente online e per posta per i conducenti idonei. I conducenti over 79 devono rinnovare di persona."},
  {cat:"license",en:"What is the Florida law on displaying proof of insurance when stopped by police?",it:"Qual e la legge Florida sulla visualizzazione della prova assicurativa quando si e fermati dalla polizia?",options:[{en:"Required only if you have been in an accident",it:"Richiesto solo se si e stati in un incidente"},{en:"Must be able to provide proof of required insurance upon request by law enforcement",it:"Deve essere in grado di fornire la prova dell'assicurazione richiesta su richiesta delle forze dell'ordine"},{en:"Insurance card is recommended but not legally required",it:"La tessera assicurativa e raccomandata ma non legalmente richiesta"},{en:"Only required for commercial vehicles",it:"Richiesto solo per i veicoli commerciali"}],correct:1,explain_en:"Florida drivers must carry proof of PIP and PDL insurance in the vehicle and present it to law enforcement upon request. Driving without required insurance is a serious violation.",explain_it:"I conducenti Florida devono portare la prova dell'assicurazione PIP e PDL nel veicolo e presentarla alle forze dell'ordine su richiesta."},

  // SESSION 13 COMPLETION
  {cat:"laws",en:"What is the maximum fine for a first-time speeding violation of 10 mph over the limit in Florida?",it:"Qual e la multa massima per una prima violazione della velocita di 10 mph oltre il limite in Florida?",options:[{en:"$25",it:"$25"},{en:"Varies by county -- approximately $125-$165 for 10 mph over",it:"Varia per contea -- circa $125-$165 per 10 mph oltre"},{en:"$500 minimum",it:"Minimo $500"},{en:"$1,000 for any speeding violation",it:"$1.000 per qualsiasi violazione della velocita"}],correct:1,explain_en:"Florida speeding fines vary by county and school/construction zone status. For 10 mph over in a regular zone, expect approximately $125-$165. Work zone and school zone fines are doubled.",explain_it:"Le multe per eccesso di velocita in Florida variano per contea e stato di zona scolastica/di lavoro. Per 10 mph oltre in una zona normale, aspettarsi circa $125-$165."},
  {cat:"laws",en:"In Florida, what is the proper action when approaching an intersection where the traffic light is out?",it:"In Florida, qual e l'azione corretta quando ci si avvicina a un incrocio dove il semaforo e spento?",options:[{en:"The vehicle traveling the main road has the right of way",it:"Il veicolo che percorre la strada principale ha la precedenza"},{en:"Treat as a four-way stop -- stop completely, yield in order of arrival",it:"Trattarlo come uno stop a quattro vie -- fermarsi completamente, cedere in ordine di arrivo"},{en:"Slow to 10 mph and proceed",it:"Rallentare a 10 mph e procedere"},{en:"Proceed normally -- only signals that are red require stopping",it:"Procedere normalmente -- solo i segnali rossi richiedono la fermata"}],correct:1,explain_en:"Florida law: when a traffic light is completely dark (not functioning), treat the intersection as an all-way stop. Stop completely, then yield to vehicles in order of arrival.",explain_it:"Legge Florida: quando un semaforo e completamente spento, trattare l'incrocio come uno stop a quattro vie. Fermarsi completamente, poi cedere ai veicoli in ordine di arrivo."},
  {cat:"safety",en:"What is the Florida law on the use of headlights when windshield wipers are in use?",it:"Qual e la legge Florida sull'uso dei fari quando i tergicristalli sono in uso?",options:[{en:"Optional -- wipers and lights are independent",it:"Opzionale -- tergicristalli e luci sono indipendenti"},{en:"Required -- if wipers are on due to rain or fog, headlights must also be on",it:"Obbligatorio -- se i tergicristalli sono accesi a causa di pioggia o nebbia, anche i fari devono essere accesi"},{en:"Only for intermittent wiper speed",it:"Solo per la velocita intermittente dei tergicristalli"},{en:"Only required if visibility is below 500 feet",it:"Richiesto solo se la visibilita e inferiore a 500 piedi"}],correct:1,explain_en:"Florida law: if your windshield wipers are on due to rain or weather, you MUST also have your headlights on. This is a primary offense -- police can stop you solely for wipers-on but no lights.",explain_it:"Legge Florida: se i tergicristalli sono accesi a causa di pioggia o condizioni atmosferiche, devi ANCHE avere i fari accesi. E un reato principale."},
  {cat:"alcohol",en:"What is the Florida law about participating in a DUI diversion program?",it:"Qual e la legge Florida sulla partecipazione a un programma di diversione DUI?",options:[{en:"Available to all DUI offenders",it:"Disponibile per tutti i trasgressori DUI"},{en:"Available in some counties for first-time offenders -- completion may result in reduced or dismissed charges",it:"Disponibile in alcune contee per i recidivi primari -- il completamento puo comportare accuse ridotte o respinte"},{en:"Not available in Florida",it:"Non disponibile in Florida"},{en:"Only for offenders under 21",it:"Solo per i trasgressori under 21"}],correct:1,explain_en:"Some Florida counties offer DUI diversion programs for first-time, low-BAC offenders with no prior record. Successful completion may result in charge reduction or dismissal, but the arrest remains.",explain_it:"Alcune contee Florida offrono programmi di diversione DUI per i trasgressori primari con BAC basso e nessun precedente. Il completamento con successo puo comportare la riduzione o il respingimento delle accuse."},
  {cat:"license",en:"What is the Florida law on receiving a traffic ticket in another state?",it:"Qual e la legge Florida sul ricevere una multa del traffico in un altro stato?",options:[{en:"Out-of-state tickets do not affect Florida license",it:"Le multe fuori stato non influiscono sulla patente Florida"},{en:"Florida participates in the Driver License Compact -- out-of-state convictions are reported and may affect your Florida record",it:"La Florida partecipa al Driver License Compact -- le condanne fuori stato vengono segnalate e possono influire sul tuo casellario Florida"},{en:"Only serious violations from other states are reported",it:"Solo le violazioni gravi di altri stati vengono segnalate"},{en:"Tickets from neighboring states only",it:"Solo le multe degli stati vicini"}],correct:1,explain_en:"Florida participates in the Driver License Compact and Non-Resident Violator Compact. Traffic convictions from participating states are reported to FLHSMV and can add points to your Florida record.",explain_it:"La Florida partecipa al Driver License Compact. Le condanne del traffico dagli stati partecipanti vengono segnalate al FLHSMV e possono aggiungere punti al tuo casellario Florida."},
  {cat:"signs",en:"What does a 'Warning: Photo Enforced Intersection' sign mean?",it:"Cosa significa un segnale 'Warning: Photo Enforced Intersection'?",options:[{en:"Cameras record accidents only",it:"Le telecamere registrano solo gli incidenti"},{en:"Automated cameras monitor the intersection and may photograph red-light violators for citations",it:"Le telecamere automatizzate monitorano l'incrocio e possono fotografare i trasgressori del rosso per le citazioni"},{en:"Speed cameras are active",it:"Le telecamere di velocita sono attive"},{en:"Police are always present",it:"La polizia e sempre presente"}],correct:1,explain_en:"Photo-enforced intersections use automated cameras to capture red-light runners. Citations (with photos of the violation) are mailed to the registered vehicle owner.",explain_it:"Gli incroci con foto enforcement usano telecamere automatizzate per catturare chi passa col rosso. Le citazioni (con foto della violazione) vengono spedite al proprietario registrato del veicolo."},
  {cat:"safety",en:"What is the first thing you should do after a minor vehicle crash with no injuries?",it:"Qual e la prima cosa da fare dopo un piccolo incidente senza feriti?",options:[{en:"Leave the scene immediately if damage is minor",it:"Lasciare la scena immediatamente se i danni sono lievi"},{en:"Check for injuries, move vehicles if safe, turn on hazard lights, exchange information, and call police if required",it:"Controllare i feriti, spostare i veicoli se sicuro, accendere le luci di pericolo, scambiare informazioni e chiamare la polizia se richiesto"},{en:"Call your insurance first before doing anything else",it:"Chiamare prima l'assicurazione prima di fare qualsiasi altra cosa"},{en:"Take photos and leave without exchanging information if the other driver agrees",it:"Scattare foto e andarsene senza scambiare informazioni se l'altro conducente e d'accordo"}],correct:1,explain_en:"After a crash: check for injuries first. If safe to do so, move vehicles out of traffic. Turn on hazard lights. Exchange information (name, contact, insurance, license). Call police if injuries or significant damage.",explain_it:"Dopo un incidente: prima controlla i feriti. Se sicuro, sposta i veicoli dal traffico. Accendi le luci di pericolo. Scambia informazioni. Chiama la polizia se ci sono feriti o danni significativi."},
  {cat:"laws",en:"What is Florida's law on the minimum following distance behind a motorcycle?",it:"Qual e la legge Florida sulla distanza minima di seguimento dietro a una moto?",options:[{en:"Same as any vehicle -- 2 seconds",it:"Uguale a qualsiasi veicolo -- 2 secondi"},{en:"At least 2 seconds but 3-4 recommended -- motorcycles can stop faster and need the protection of following distance",it:"Almeno 2 secondi ma 3-4 raccomandati -- le moto possono fermarsi piu velocemente e necessitano della protezione della distanza"},{en:"1 second because motorcycles are smaller",it:"1 secondo perche le moto sono piu piccole"},{en:"Only 1 car length needed",it:"E necessaria solo 1 lunghezza auto"}],correct:1,explain_en:"Florida requires a 2-second following distance minimum but recommends 3-4 seconds behind motorcycles. Motorcycles stop faster than cars and are harder to see -- they need the buffer.",explain_it:"La Florida richiede una distanza minima di 2 secondi ma raccomanda 3-4 secondi dietro le moto. Le moto si fermano piu velocemente delle auto e sono piu difficili da vedere."},
  {cat:"alcohol",en:"What is the Florida law on DUI record expungement?",it:"Qual e la legge Florida sull'espunzione del casellario DUI?",options:[{en:"DUI can be expunged after 10 years",it:"Il DUI puo essere espunto dopo 10 anni"},{en:"DUI convictions in Florida cannot be expunged or sealed -- they are permanent on the driving record",it:"Le condanne DUI in Florida non possono essere espunte o sigillate -- sono permanenti nel casellario di guida"},{en:"DUI can be expunged for first-time offenders after 5 years",it:"Il DUI puo essere espunto per i recidivi primari dopo 5 anni"},{en:"DUI can be sealed but not expunged",it:"Il DUI puo essere sigillato ma non espunto"}],correct:1,explain_en:"Florida DUI convictions cannot be expunged or sealed from the driving record. They remain permanently. DUI charges that were dismissed (not convicted) may be eligible for sealing/expungement.",explain_it:"Le condanne DUI in Florida non possono essere espunte o sigillate dal casellario di guida. Rimangono permanentemente."},
  {cat:"license",en:"What happens to a Florida CDL if the holder gets a DUI in a personal vehicle?",it:"Cosa succede a un CDL Florida se il titolare ottiene un DUI in un veicolo personale?",options:[{en:"Only the personal license is affected",it:"Solo la patente personale e influenzata"},{en:"First DUI in any vehicle results in 1-year CDL disqualification; second = lifetime disqualification",it:"Il primo DUI in qualsiasi veicolo comporta 1 anno di squalifica CDL; il secondo = squalifica a vita"},{en:"CDL is unaffected by personal vehicle DUI",it:"Il CDL non e influenzato dal DUI del veicolo personale"},{en:"CDL suspended only if driving commercially at the time",it:"CDL sospeso solo se si stava guidando commercialmente al momento"}],correct:1,explain_en:"A DUI conviction in ANY vehicle -- personal or commercial -- results in CDL disqualification: 1 year for first offense, lifetime for second offense. Commercial driving career can end with one DUI.",explain_it:"Una condanna DUI in QUALSIASI veicolo -- personale o commerciale -- comporta la squalifica CDL: 1 anno per la prima infrazione, a vita per la seconda."},
  {cat:"signs",en:"What does a 'Keep Right Except to Pass' sign on a highway mean?",it:"Cosa significa un segnale 'Keep Right Except to Pass' in autostrada?",options:[{en:"Only right lane is legal for travel",it:"Solo la corsia destra e legale per viaggiare"},{en:"Drive in the right lane normally -- only use left lanes to pass slower traffic, then return right",it:"Guidare normalmente nella corsia destra -- usare le corsie sinistre solo per superare il traffico piu lento, poi tornare a destra"},{en:"Right turn required at next intersection",it:"Svolta destra obbligatoria al prossimo incrocio"},{en:"Only trucks must keep right",it:"Solo i camion devono stare a destra"}],correct:1,explain_en:"Keep Right Except to Pass: use the right lane(s) for normal driving. Move left only to pass, then return right. Camping in the left lane impedes traffic and is a moving violation in Florida.",explain_it:"Keep Right Except to Pass: usare le corsie destre per la guida normale. Spostarsi a sinistra solo per sorpassare, poi tornare a destra. Stazionare nella corsia sinistra ostacola il traffico."},
  {cat:"laws",en:"What is the Florida law on right-of-way when a driver and pedestrian are both trying to cross the same point?",it:"Qual e la legge Florida sulla precedenza quando un conducente e un pedone stanno entrambi cercando di attraversare lo stesso punto?",options:[{en:"The driver always has the right of way",it:"Il conducente ha sempre la precedenza"},{en:"Pedestrians always have the right of way in or entering a crosswalk -- drivers must yield",it:"I pedoni hanno sempre la precedenza nell'attraversamento o entrando -- i conducenti devono cedere"},{en:"Whoever gets there first has the right of way",it:"Chi arriva prima ha la precedenza"},{en:"The vehicle has the right of way because it is larger",it:"Il veicolo ha la precedenza perche e piu grande"}],correct:1,explain_en:"Florida law: drivers must yield to pedestrians who are in a crosswalk or about to enter one. Pedestrians have the right of way in these situations -- failure to yield is a serious moving violation.",explain_it:"Legge Florida: i conducenti devono cedere ai pedoni che sono in un attraversamento o stanno per entrarci. I pedoni hanno la precedenza in queste situazioni."},
  {cat:"safety",en:"What is the effect of sun glare on driving safety?",it:"Qual e l'effetto dell'abbagliamento del sole sulla sicurezza alla guida?",options:[{en:"No significant effect on experienced drivers",it:"Nessun effetto significativo sui conducenti esperti"},{en:"Temporarily blinds the driver, eliminates ability to see traffic signals and hazards -- reduce speed and increase following distance",it:"Acceca temporaneamente il conducente, elimina la capacita di vedere segnali del traffico e pericoli -- ridurre la velocita e aumentare la distanza"},{en:"Only affects drivers without sunglasses",it:"Influisce solo sui conducenti senza occhiali da sole"},{en:"More dangerous at dawn than dusk",it:"Piu pericoloso all'alba che al crepuscolo"}],correct:1,explain_en:"Sun glare can completely eliminate forward visibility -- making traffic signals, stopped vehicles, and pedestrians invisible. Always reduce speed and increase following distance when driving into the sun.",explain_it:"L'abbagliamento del sole puo eliminare completamente la visibilita frontale -- rendendo invisibili i segnali del traffico, i veicoli fermi e i pedoni."},
  {cat:"alcohol",en:"What is the minimum required waiting period to apply for CDL reinstatement after a lifetime disqualification?",it:"Qual e il periodo minimo di attesa obbligatorio per richiedere il reintegro del CDL dopo una squalifica a vita?",options:[{en:"10 years",it:"10 anni"},{en:"There is no reinstatement for a lifetime CDL disqualification -- it is permanent",it:"Non c'e reintegro per una squalifica CDL a vita -- e permanente"},{en:"5 years with treatment program completion",it:"5 anni con completamento del programma di trattamento"},{en:"20 years with perfect driving record",it:"20 anni con casellario di guida perfetto"}],correct:1,explain_en:"A lifetime CDL disqualification is permanent with very limited exceptions. A second DUI or refusal conviction ends a commercial driving career. There is no standard reinstatement pathway.",explain_it:"Una squalifica CDL a vita e permanente con eccezioni molto limitate. Una seconda condanna DUI o di rifiuto termina una carriera di guida commerciale."},
  {cat:"license",en:"What does the Florida driver's license exam consist of for a first-time applicant?",it:"Di cosa consiste l'esame della patente Florida per un richiedente per la prima volta?",options:[{en:"Only a written test",it:"Solo un test scritto"},{en:"A knowledge (written) test, a vision screening, and a driving skills test",it:"Un test di conoscenza (scritto), uno screening della visione e un test di abilita di guida"},{en:"Only a vision test and driving test",it:"Solo un test della visione e un test di guida"},{en:"Only the driving skills test if transferring from another state",it:"Solo il test di abilita di guida se si trasferisce da un altro stato"}],correct:1,explain_en:"First-time Florida license applicants must pass: (1) knowledge test (50 questions, 80% passing), (2) vision screening (20/40 or corrected), and (3) driving skills test. Out-of-state transfers may waive the driving test.",explain_it:"I richiedenti della prima patente Florida devono superare: (1) test di conoscenza (50 domande, 80% per passare), (2) screening della visione e (3) test di abilita di guida."},

];
